export const recipes=[{"id":1,"servings":4,"tipType":"pasta","pairingsType":"pasta","nutrition":{"cal":784,"prot":33,"carb":76,"fat":38,"fib":3},"origin":{"ar":"إيطاليا","en":"Italy","ro":"Italia"},"name":{"ar":"سباغيتي كاربونارا","en":"Spaghetti Carbonara","ro":"Spaghete Carbonara"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"ingredients":{"ar":["400غ سباغيتي","200غ غوانشالي (أو بانشيتا)، مقطّع مكعبات 1 سم","4 صفار بيضات كبيرة + بيضة كاملة","80غ بيكورينو رومانو مبشور ناعم","40غ بارميجيانو ريجيانو مبشور ناعم","1 ملعقة صغيرة فلفل أسود مطحون طازجاً","ملح بحر ناعم لماء الطبخ"],"en":["400g spaghetti","200g guanciale (or pancetta), cut into 1cm cubes","4 large egg yolks + 1 whole egg","80g Pecorino Romano, finely grated","40g Parmigiano Reggiano, finely grated","1 tsp freshly cracked black pepper","Fine sea salt for pasta water"],"ro":["400g spaghete","200g guanciale (sau pancetta), tăiat cuburi de 1 cm","4 gălbenușuri de ou mari + 1 ou întreg","80g Pecorino Romano, ras fin","40g Parmigiano Reggiano, ras fin","1 linguriță piper negru proaspăt măcinat","Sare de mare fină pentru apa de fiert"]},"howIsMade":{"ar":"أوصل 4 لترات ماء إلى الغليان القوي، أضف ملحاً وافراً حتى يصبح طعمه لذيذاً كالماء البحري الخفيف، ثم أنضج السباغيتي لمدة أقل بدقيقتين من الوقت المكتوب على العبوة — ستكمل نضجها في الصلصة. في الوقت ذاته، ضع الغوانشالي في مقلاة واسعة بارئة على نار متوسطة-منخفضة ودع الدهن يذوب ببطء 8–10 دقائق حتى يصبح ذهبياً والأطراف مقرمشة؛ البدء من المقلاة الباردة يمنع الاحتراق ويستخلص أقصى نكهة. أثناء ذلك، اخفق صفار البيض مع البيضة الكاملة والجبنتين وكمية سخية من الفلفل الأسود المطحون خشناً حتى تحصل على عجينة كثيفة كريمية شاحبة — هذه هي الصلصة. قبيل التصفية مباشرةً، انزع 250 مل على الأقل من ماء الطبخ العكر وأبقه قريباً؛ النشا المذاب هو ما يجعل الإيمولسيون الناعم ممكناً. ارفع المقلاة مع الغوانشالي عن النار تماماً — هذه الخطوة غير قابلة للتفاوض — ثم أضف السباغيتي المصفاة بخارها لا يزال يتصاعد مباشرةً في المقلاة وقلّب 30 ثانية ليمتص كل خيط الدهن المُذاب. صب كريمة البيض فوق المعكرونة، ثم أضف ماء الطبخ بكميات صغيرة مع التقليب والطي المستمر؛ الحرارة المتبقية تحوّل البيض إلى صلصة ناعمة لامعة — توقف عن إضافة الماء حين تغطي الصلصة المعكرونة دون أن تتجمع في القاع. تذوّق واضبط الملح — الغوانشالي والبيكورينو مالحان أصلاً — وأضف قليلاً من الماء إن تماسكت الصلصة عند التقديم. قدّمها فوراً في أطباق دافئة، أنهِها بجبن بيكورينو مبشور إضافي وعدة لفات سخية من طاحونة الفلفل.","en":"Bring 4 litres of water to a rolling boil, salt it generously until it tastes pleasantly of the sea, then cook the spaghetti for 2 minutes less than the packet's al dente time — it will finish in the sauce. Meanwhile, place the guanciale in a cold, wide pan over medium-low heat and let the fat render slowly for 8–10 minutes until it turns golden and the edges crisp; starting from cold prevents burning and draws out maximum flavour. While the guanciale renders, beat the egg yolks and whole egg with both cheeses and a generous amount of coarsely cracked pepper until you have a thick, pale, creamy paste — this is the sauce. Just before draining, scoop out at least 250 ml of the cloudy pasta water and keep it within reach; the dissolved starch is what makes a smooth emulsion possible. Take the guanciale pan completely off the heat — this step is non-negotiable — then add the drained, steaming spaghetti directly into it and toss for 30 seconds so every strand absorbs the rendered fat. Pour the egg cream over the pasta, then add pasta water a small splash at a time, tossing and folding constantly; the residual heat sets the egg into a smooth, glossy sauce — stop adding water when the sauce coats the pasta without pooling. Taste and adjust salt — the guanciale and Pecorino are already salty — then add a little more pasta water if the sauce tightens as you plate. Serve immediately in warm bowls, finish with an extra shaving of Pecorino and several confident turns of the pepper mill."}},{"id":2,"origin":{"ar":"رومانيا","en":"Romania","ro":"România"},"name":{"ar":"شوربة الكرشة","en":"Tripe Soup","ro":"Ciorbă de burtă"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"soup","pairingsType":"soup","nutrition":{"cal":320,"prot":27,"carb":8,"fat":20,"fib":1},"ingredients":{"ar":["800غ كرشة بقرية مسلوقة مسبقاً، مقطّعة شرائح 5×1 سم","2 جزرة متوسطة (نحو 200غ)","1 جذر بقدونس","1 قطعة كرفس جذر (نحو 150غ)","1 بصلة كبيرة","4 فصوص ثوم مهروسة","3 صفار بيض كبير","300مل كريمة حامضة دسمة (20٪ على الأقل)","3 ملاعق كبيرة خل النبيذ الأبيض","ملح وفلفل أبيض حسب الذوق","أوراق اللفّة الطازجة (اختياري)"],"en":["800g pre-cleaned beef tripe, cut into 5×1 cm strips","2 medium carrots (about 200g)","1 parsley root","1 piece celeriac (about 150g)","1 large onion","4 garlic cloves, crushed","3 large eggs, yolks only","300ml full-fat sour cream (min. 20%)","3 tbsp white wine vinegar","salt and white pepper to taste","fresh lovage leaves (optional)"],"ro":["800g burtă de vită (precurățată și fiartă), tăiată fâșii de 5×1 cm","2 morcovi medii (aprox. 200g)","1 rădăcină de pătrunjel","1 bucată țelină rădăcină (aprox. 150g)","1 ceapă mare","4 căței de usturoi, pisați","3 ouă mari, gălbenușurile separate","300ml smântână grasă (min. 20%)","3 linguri oțet de vin alb","sare și piper alb după gust","frunze de leuștean proaspăt (opțional)"]},"howIsMade":{"ar":"إذا لم تكن الكرشة مُعالجة مسبقاً، ادلكها بملح خشن تحت ماء بارد جارٍ واشطفها 3–4 مرات. اسلق الكرشة في ماء مملح على نار هادئة 2–3 ساعات حتى تلين (أو 40–50 دقيقة في قدر الضغط). صفّها وقطّعها شرائح 5×1 سم. اسلق الجزر وجذر البقدونس والكرفس والبصل في 2 لتر ماء مملح 40 دقيقة ثم أزل الخضار. أضف شرائح الكرشة للمرق واطبخ 15 دقيقة. اخفق صفار البيض مع الكريمة الحامضة حتى يتجانسا. دفّئ الخليط: أضف ملاعق من المرق الساخن تدريجياً للكريمة مع الخفق المستمر قبل صبّه في القدر — يمنع التجبّن. أضف الثوم المهروس والخل والملح والفلفل الأبيض. لا تعِد الغليان بعد الإضافة. قدّم ساخناً جداً.","en":"If tripe is not pre-cleaned, rub thoroughly with coarse salt under cold running water and rinse 3–4 times. Boil tripe in salted water for 2–3 hours on low heat until easily pierced with a fork — or 40–50 minutes in a pressure cooker. Drain and cut into 5×1 cm strips. Simmer carrots, parsley root, celeriac, and onion in 2L salted water for 40 minutes, then discard the vegetables (or blend and return for a thicker soup). Add the tripe strips to the broth and simmer 15 minutes. Whisk egg yolks with sour cream until smooth. Temper the mixture: ladle several spoonfuls of hot broth into the cream gradually, whisking constantly before pouring it back into the pot — this prevents curdling. Stir in crushed garlic, vinegar, salt, and white pepper. Do not boil again after adding the liaison — it will curdle. Serve piping hot with chilli and garlic sauce on the side."}},{"id":3,"servings":6,"tipType":"def","pairingsType":"def","nutrition":{"cal":770,"prot":21,"carb":27,"fat":62,"fib":1},"origin":{"ar":"فرنسا","en":"France","ro":"Franța"},"name":{"ar":"كيش لورين","en":"Quiche Lorraine","ro":"Quiche Lorraine"},"category":{"ar":"فطور","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"ar":["200 غ عجينة قصيرة (ورقة واحدة)، محرومة مسبقاً","200 غ لحم خنزير مدخن أو بيكون مدخن مقطّع مكعبات","3 بيضات كبيرة","300 مل كريمة مزدوجة (35% دهون على الأقل)","60 غ جبن غرويار مبروش ناعم","ربع ملعقة صغيرة جوزة الطيب مبروشة طازجة","ملح وفلفل أبيض حسب الرغبة","زبدة لتشحيم القالب"],"en":["200g shortcrust pastry (1 sheet), blind-baked","200g smoked lardons or diced smoked bacon","3 large eggs","300ml double cream (min. 35% fat)","60g Gruyère cheese, finely grated","1/4 tsp freshly grated nutmeg","salt and white pepper to taste","butter for greasing"],"ro":["200g aluat scurt (1 foaie), copt în alb","200g lardon afumat sau bacon afumat, tocat cuburi","3 ouă mari","300ml smântână grasă (min. 35%)","60g Gruyère, ras fin","1/4 linguriță nucșoară rasă proaspăt","sare și piper alb după gust","unt pentru uns forma"]},"howIsMade":{"ar":"افرد العجينة وبطّن قالب تارت 23سم مع الضغط على الحواف. ضعه في الثلاجة 20 دقيقة. اخبزه بلا حشوة على 180°C: غطّ بورق خبز واملأ بالحبوب، اخبز 15 دقيقة؛ أزل الحبوب والورق واخبز 5 دقائق إضافية حتى يصبح ذهبياً فاتحاً. في الأثناء، اقلِ اللحم المدخن في مقلاة جافة حتى يذهب دهنه ويصبح ذهبياً، نحو 5 دقائق؛ صفّه. اخفق البيض والكريمة وجوز الطيب والملح والفلفل الأبيض. وزّع اللحم على قاع القالب، اسكب خليط البيض وارش الغرويار فوقه. اخبز 25–30 دقيقة على 180°C حتى يتماسك — يجب أن يترنح المركز قليلاً. دعه يبرد 10 دقائق قبل التقطيع.","en":"Roll out the pastry and line a 23cm tart tin, pressing firmly into the edges. Chill 20 minutes. Blind-bake at 180°C: line with baking paper, fill with baking beans, bake 15 minutes; remove beans and paper and bake a further 5 minutes until pale golden. Meanwhile, cook the lardons in a dry pan until golden and the fat is rendered, about 5 minutes; drain on paper. Whisk together eggs, cream, nutmeg, salt and white pepper. Scatter the lardons evenly over the base, pour the egg mixture over, and sprinkle with Gruyère. Bake 25–30 minutes at 180°C until just set — the centre should tremble slightly when you shake the tin. Cool 10 minutes before slicing. A true Quiche Lorraine contains no onion or vegetables, only lardons and the classic custard."}},{"id":4,"origin":{"ar":"إسبانيا","en":"Spain","ro":"Spania"},"name":{"ar":"جازباتشو","en":"Gazpacho","ro":"Gazpacho"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"veg","nutrition":{"cal":260,"prot":4,"carb":24,"fat":16,"fib":3},"ingredients":{"ar":["800غ طماطم ناضجة (سان مارزانو أو إيطالية) مقطّعة خشناً","فليفلة حمراء واحدة (نحو 200غ) منزوعة البذور ومقطّعة","خيارة متوسطة (نحو 200غ) مقشّرة ومقطّعة","فصّا ثوم","100غ خبز أبيض من يوم سابق بلا قشرة","60مل زيت زيتون بكر ممتاز","2 ملعقة كبيرة خل النبيذ الأحمر","1 ملعقة صغيرة ملح ناعم","200مل ماء بارد"],"en":["800g ripe tomatoes (San Marzano or plum), roughly chopped","1 red bell pepper (about 200g), deseeded and chopped","1 medium cucumber (about 200g), peeled and chopped","2 garlic cloves","100g day-old white bread, crusts removed","60ml extra-virgin olive oil","2 tbsp red wine vinegar","1 tsp fine salt","200ml cold water"],"ro":["800g roșii coapte (San Marzano sau roșii de câmp), tăiate cuburi","1 ardei gras roșu (aprox. 200g), curățat de semințe și tocat","1 castravete mediu (aprox. 200g), curățat și tocat","2 căței de usturoi","100g pâine albă veche de o zi, fără coajă","60ml ulei de măsline extravirgin","2 linguri oțet de vin roșu","1 linguriță sare fină","200ml apă rece"]},"howIsMade":{"ar":"قطّع الخبز ونقعه في 200مل ماء بارد 10 دقائق. ضع الطماطم والفليفلة والخيار والثوم في الخلاط واخلط دقيقة واحدة على السرعة القصوى. أضف الخبز المنقوع مع مائه والخل والملح واخلط مجدداً. مع تشغيل الخلاط أضف زيت الزيتون في خيط رفيع — الاستحلاب هو ما يمنح القوام الحريري. تحقّق من الملح والخل. اصفِ عبر منخل ناعم للحصول على قوام أملس أو اتركه خشناً. برّد في الثلاجة ساعتين على الأقل — الغازباتشو عند 6–8°C أكثر نكهة بكثير من درجة حرارة الغرفة. قدّمه في أطباق مبرّدة مع رشّة زيت زيتون فوقه.","en":"Tear the bread into pieces and soak in 200ml cold water for 10 minutes. Put tomatoes, pepper, cucumber, and garlic into a blender and blitz for 1 minute on high. Add the soaked bread along with its soaking water, vinegar, and salt; blitz again. With the motor running, pour olive oil in a thin stream — this emulsification gives the soup its silky texture. Taste and adjust salt and vinegar. Pass through a fine-mesh sieve for a smoother result, or leave it rustic. Chill at least 2 hours — gazpacho at 6–8°C is vastly more flavourful than at room temperature. Serve in chilled bowls with a drizzle of olive oil on top."}},{"id":5,"origin":{"ar":"اليابان","en":"Japan","ro":"Japonia"},"name":{"ar":"سوشي","en":"Sushi","ro":"Sushi"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"japanese","nutrition":{"cal":430,"prot":15,"carb":51,"fat":14,"fib":3},"ingredients":{"ar":["كوبان أرز ياباني بحبة قصيرة للسوشي","2½ كوب ماء","60مل خل الأرز","1 ملعقة كبيرة سكر","1 ملعقة صغيرة ملح","4 أوراق نوري (20×18 سم)","200غ شرائح سمك سلمون بجودة ساشيمي مقطّعة رفيعة","أفوكادو ناضج واحد مقطّع شرائح","½ خيارة صغيرة مقطّعة شرائح دقيقة","صلصة الصويا للتقديم","واسابي وزنجبيل مخلّل (غاري) للتقديم"],"en":["2 cups Japanese short-grain sushi rice","2½ cups water","60ml rice vinegar","1 tbsp sugar","1 tsp salt","4 nori sheets (20×18 cm)","200g sashimi-grade salmon fillet, thinly sliced","1 ripe avocado, sliced","½ small cucumber, julienned","soy sauce to serve","wasabi and pickled ginger (gari) to serve"],"ro":["2 căni orez japonez pentru sushi (bob scurt)","2½ căni apă","60ml oțet de orez","1 lingură zahăr","1 linguriță sare","4 foi nori (20×18 cm)","200g file de somon sashimi-grade, feliat subțire","1 avocado copt, feliat","½ castravete mic, julienizat","sos de soia pentru servire","wasabi și ghimbir murat (gari) pentru servire"]},"howIsMade":{"ar":"اطبخ الأرز: اشطفه بماء بارد حتى يصفو (4–5 مرات). أغلِ الأرز مع 2½ كوب ماء، غطِّه، اطبخ على أضعف نار 12 دقيقة، أرِّحه 10 دقائق بعيداً عن النار. أذِب الخل والسكر والملح في وعاء صغير. انشر الأرز على صينية كبيرة وأضف التتبيلة بحركات تقطيع — لا تقلّب دائرياً وإلا سيصبح الأرز لزجاً. غطِّه بقطعة قماش مبللة واتركه يبرد لدرجة حرارة الغرفة. ضع النوري بجانبه اللامع لأسفل على الحصيرة. وزّع الأرز على ¾ من النوري (3 سم فارغة عند الحافة البعيدة). رتّب السلمون والأفوكادو والخيار في صف. لفّ بإحكام وأغلق بحبات أرز. قطّع بسكين حادة مبللة قليلاً إلى 8 قطع. قدّم مع صلصة الصويا والواسابي والغاري.","en":"Cook the rice: rinse under cold water until the water runs clear (4–5 washes). Bring rice and 2½ cups water to a boil, cover, reduce to lowest heat for 12 minutes, then rest off heat 10 minutes. Dissolve vinegar, sugar, and salt in a small bowl. Spread cooked rice onto a large tray and fold the dressing in using a wooden paddle with cutting motions — do not stir in circles or the rice turns mushy. Cover with a damp cloth and cool to room temperature (not fridge). Lay a nori sheet shiny-side down on the bamboo mat. Spread seasoned rice over ¾ of the nori (leaving a 3 cm gap at the far edge). Arrange salmon, avocado, and cucumber along the near edge in a single row. Roll firmly from the near edge, pressing as you go; seal the bare nori with a few rice grains. Slice with a sharp, lightly wet knife into 8 rounds. Serve at once with soy sauce, wasabi, and pickled ginger."}},{"id":7,"servings":4,"tipType":"meat","pairingsType":"meat","nutrition":{"cal":775,"prot":40,"carb":39,"fat":49,"fib":1},"origin":{"ar":"الولايات المتحدة","en":"USA","ro":"SUA"},"name":{"ar":"تشيز برجر","en":"Cheeseburger","ro":"Cheeseburger"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["500 غ لحم بقري مفروم (80% خالٍ من الدهون، 20% دهون)","4 خبز بريوش مقسّم ومحمّص","4 شرائح جبن شيدر أمريكي","2 طماطم ناضجة مقطّعة شرائح سميكة","4 أوراق خس آيسبرغ","1 بصلة متوسطة مقطّعة حلقات رفيعة","2 ملعقة كبيرة صلصة برجر (مايونيز وكاتشب وخردل ومخلل مفروم)","ملح وفلفل أسود مطحون طازج"],"en":["500g ground beef (80% lean, 20% fat)","4 brioche buns, halved and toasted","4 slices American cheddar","2 ripe tomatoes, thickly sliced","4 large iceberg lettuce leaves","1 medium onion, thinly sliced into rings","2 tbsp burger sauce (mayo, ketchup, mustard, diced pickles)","salt and freshly ground black pepper"],"ro":["500g carne de vită tocată (80% carne / 20% grăsime)","4 chifle brioche, tăiate și prăjite","4 felii cheddar american","2 roșii coapte, tăiate felii groase","4 frunze de salată iceberg","1 ceapă medie, tăiată rondele subțiri","2 linguri sos de burger (maioneză, ketchup, muștar, castraveți murați tocați)","sare și piper negru proaspăt măcinat"]},"howIsMade":{"ar":"تبّل اللحم المفروم بالملح والفلفل وقسّمه إلى أربع كرات وزن كل منها 125 غ. سخّن مقلاة من الحديد الزهر على نار عالية جداً حتى يبدأ الدخان بالصعود. اضغط كل كرة مباشرةً على المقلاة بملعقة صلبة — تقنية السماش تُكوّن قشرة مقرمشة في 90 ثانية. اقلب الكفتة، ضع شريحة من الجبن وغطّ 30 ثانية حتى يذوب. احمص الخبز من الجانب المقطوع دقيقة واحدة. رتّب: خبز سفلي، صلصة برجر، خس، طماطم، شريحة بالجبن المذاب، حلقات بصل، خبز علوي. قدّم فوراً.","en":"Season the ground beef with salt and pepper and divide into four 125g balls. Heat a cast-iron skillet over high heat until smoking. Press each ball flat on the pan with a firm spatula — the smash technique creates a crisp, lacy crust in about 90 seconds. Flip, add a slice of cheddar, and cover for 30 seconds to melt. Toast the buns cut-side down for 1 minute. Assemble: bottom bun, burger sauce, lettuce, tomato, patty with melted cheese, onion rings, top bun. Serve immediately — the crust fades fast."}},{"id":8,"servings":4,"tipType":"meat","pairingsType":"meat","nutrition":{"cal":390,"prot":26,"carb":32,"fat":18,"fib":4},"origin":{"ar":"المكسيك","en":"Mexico","ro":"Mexic"},"name":{"ar":"تاكو","en":"Tacos","ro":"Tacos"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["500 غ لحم بقري مفروم (80% خالٍ من الدهون)","8 خبز تورتيلا صغيرة من الذرة (15سم)","1 ملعقة صغيرة كمون مطحون","1 ملعقة صغيرة بابريكا مدخنة","2 طماطم ناضجة مفرومة ناعماً (لصلصة البيكو دي غايو)","1 بصلة بيضاء صغيرة مفرومة ناعماً","كزبرة طازجة وشرائح ليمون أخضر وصلصة وكريمة حامضة للتقديم","ملح وفلفل أسود"],"en":["500g ground beef (80% lean)","8 small corn tortillas (15cm)","1 tsp ground cumin","1 tsp smoked paprika","2 ripe tomatoes, finely diced (for pico de gallo)","1 small white onion, finely diced","fresh cilantro, lime wedges, salsa, and sour cream for serving","salt and black pepper"],"ro":["500g carne de vită tocată (80% carne)","8 tortilla mici din porumb (15cm)","1 linguriță chimion măcinat","1 linguriță boia afumată","2 roșii coapte, tocate mărunt (pico de gallo)","1 ceapă albă mică, tocată mărunt","coriandru proaspăt, felii de lime, sos salsa și smântână pentru servit","sare și piper negru"]},"howIsMade":{"ar":"حمّر اللحم المفروم في مقلاة جافة على نار عالية مع تفتيته — لا تحرك كثيراً في البداية لتتشكل قشرة. صفّ الدهن الزائد. أضف الكمون والبابريكا والملح والفلفل؛ اطبخ دقيقتين إضافيتين. سخّن التورتيلا: امسكها فوق لهب الغاز 15 ثانية لكل وجه حتى تتورم وتحترق خفيفاً، أو حمّصها جافة في مقلاة ساخنة. لصلصة البيكو دي غايو: اخلط الطماطم والبصل مع رشة ملح وعصير الليمون. ضع تورتيلتين فوق بعضهما لكل تاكو. أضف اللحم المتبّل، البيكو دي غايو، الكزبرة، عصير الليمون، والصلصة أو الكريمة الحامضة.","en":"Brown the ground beef in a dry skillet over high heat, breaking it into fine crumbles — do not stir too much at first so the meat develops colour. Drain excess fat. Add cumin, paprika, salt and pepper; cook 2 more minutes. Warm the corn tortillas: hold them directly over a gas flame for 15 seconds per side until they blister and char lightly, or dry-toast in a hot pan. For quick pico de gallo: toss diced tomato with diced onion, a pinch of salt, and a squeeze of lime. Double-stack two tortillas per taco to prevent splitting. Spoon on the seasoned beef, then top with pico de gallo, cilantro leaves, a squeeze of lime, and salsa or sour cream to taste."}},{"id":9,"servings":4,"tipType":"meat","pairingsType":"meat","nutrition":{"cal":375,"prot":23,"carb":11,"fat":19,"fib":3},"origin":{"ar":"الهند","en":"India","ro":"India"},"name":{"ar":"دجاج بالكاري","en":"Chicken Curry","ro":"Curry de pui"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["800غ أفخاذ وأرجل دجاج بالعظم بدون جلد","بصلتان كبيرتان (نحو 350غ)، مقطّعتان ناعماً","400غ طماطم مهروسة معلّبة","1 ملعقة كبيرة معجون زنجبيل (قطعة 3 سم)","1 ملعقة كبيرة معجون ثوم (5 فصوص)","3 ملاعق كبيرة زيت عباد الشمس","1 ملعقة صغيرة بذور كمون","2 ملعقة صغيرة كزبرة مطحونة","1 ملعقة صغيرة غارام ماسالا","½ ملعقة صغيرة كركم","1 ملعقة صغيرة فلفل كشميري (أو بابريكا خفيفة)","200مل زبادي كامل الدسم مخفوق","ملح حسب الرغبة","أوراق كزبرة طازجة للتقديم"],"en":["800g bone-in chicken thighs and drumsticks, skin removed","2 large onions (about 350g), finely diced","400g canned crushed tomatoes","1 tbsp ginger paste (from a 3cm piece)","1 tbsp garlic paste (from 5 cloves)","3 tbsp sunflower oil","1 tsp cumin seeds","2 tsp ground coriander","1 tsp garam masala","½ tsp turmeric","1 tsp Kashmiri chili powder (or mild paprika)","200ml full-fat yogurt, whisked","Salt to taste","Fresh coriander leaves to finish"],"ro":["800g pulpe de pui cu os, fără piele","2 cepe mari (aprox. 350g), tăiate mărunt","400g roșii tocate din conservă","1 lingură pastă de ghimbir (bucată de 3 cm)","1 lingură pastă de usturoi (5 căței)","3 linguri ulei de floarea-soarelui","1 linguriță semințe de chimen","2 lingurițe coriandru măcinat","1 linguriță garam masala","½ linguriță turmeric","1 linguriță praf de ardei Kashmiri (sau boia dulce)","200ml iaurt gras, bătut","Sare după gust","Frunze de coriandru proaspăt pentru finisare"]},"howIsMade":{"ar":"سخّن الزيت في قدر ذو قاع سميك على نار متوسطة-عالية. أضف بذور الكمون ودعها تطقطق 30 ثانية. أضف البصل واقلِه مع التقليب المستمر 15–18 دقيقة حتى يصبح ذهبي عميق — هذا الكرمل يبني قاعدة النكهة. أضف معجون الزنجبيل والثوم؛ اطبخ 2 دقيقتين. أضف الكزبرة والكركم والفلفل الكشميري؛ اقلب دقيقة. اسكب الطماطم واطبخ على نار متوسطة مع التقليب 10 دقائق حتى ينفصل الزيت للجانبين. أضف الدجاج وغلّفه بالماسالا واقلِه 5 دقائق. ارفع عن النار وأضف الزبادي المخفوق ملعقة تلو ملعقة. أعده لنار متوسطة-منخفضة، غطِّه واتركه يتهنّد 25–30 دقيقة حتى تنفصل اللحمة عن العظم. أضف الغارام ماسالا وعدّل الملح وأنهِ بالكزبرة الطازجة. قدّم مع أرز بسمتي أو خبز نان.","en":"Heat oil in a heavy-bottomed pot over medium-high heat. Add cumin seeds and let sizzle 30 seconds. Add diced onions and fry, stirring often, for 15–18 minutes until deep golden — this caramelisation builds the flavour base. Stir in ginger and garlic paste; cook 2 minutes until the raw smell disappears. Add ground coriander, turmeric, and Kashmiri chili; stir 1 minute. Pour in crushed tomatoes and cook over medium heat, stirring often, for 10 minutes until the oil separates to the sides. Add chicken pieces, coat in masala, and sear 5 minutes. Remove from heat; stir in whisked yogurt one tablespoon at a time to prevent curdling. Return to medium-low heat, cover, and simmer 25–30 minutes until the chicken falls easily from the bone. Stir in garam masala, adjust salt, finish with fresh coriander. Serve with basmati rice or naan."}},{"id":10,"servings":4,"tipType":"def","pairingsType":"veg","nutrition":{"cal":215,"prot":4,"carb":19,"fat":13,"fib":4},"origin":{"ar":"فرنسا","en":"France","ro":"Franța"},"name":{"ar":"راتاتوي","en":"Ratatouille","ro":"Ratatouille"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["1 باذنجانة متوسطة (نحو 300غ) مقطّعة مكعبات 2سم","2 كوسة متوسطة (نحو 400غ) مقطّعة شرائح 2سم","1 فلفل أحمر بدون بذور ومقطّع","1 فلفل أصفر بدون بذور ومقطّع","4 طماطم بندورة ناضجة (نحو 400غ) مفرومة خشناً","1 بصلة كبيرة مقطّعة","4 فصوص ثوم مقطّعة شرائح رفيعة","4 ملاعق كبيرة زيت زيتون بكر ممتاز","1 ملعقة صغيرة أعشاب بروفانس مجففة","ملح وفلفل أسود حسب الرغبة"],"en":["1 medium aubergine (about 300g), cut into 2cm cubes","2 medium courgettes (about 400g), cut into 2cm rounds","1 red bell pepper, deseeded and diced","1 yellow bell pepper, deseeded and diced","4 ripe plum tomatoes (about 400g), roughly chopped","1 large onion, diced","4 garlic cloves, thinly sliced","4 tbsp extra-virgin olive oil","1 tsp dried herbes de Provence","salt and black pepper to taste"],"ro":["1 vânătă medie (aprox. 300g), cuburi de 2cm","2 dovlecei medii (aprox. 400g), rondele de 2cm","1 ardei gras roșu, curățat și tocat","1 ardei gras galben, curățat și tocat","4 roșii prune coapte (aprox. 400g), tocate grosier","1 ceapă mare, tocată","4 căței de usturoi, feliați subțire","4 linguri ulei de măsline extravirgin","1 linguriță herbes de Provence uscate","sare și piper negru după gust"]},"howIsMade":{"ar":"رشّ القليل من الملح على مكعبات الباذنجان واتركها 15 دقيقة لإزالة المرارة، ثم جففها. سخّن ملعقة كبيرة زيت في مقلاة واسعة على نار متوسطة-عالية. اقلِ الباذنجان حتى يصبح ذهبياً خفيفاً، نحو 5 دقائق؛ أخرجه وضعه جانباً. كرر مع الكوسة (3 دقائق) ثم الفلفل (4 دقائق). في نفس المقلاة، سخّن باقي الزيت وحمّر البصل 5 دقائق. أضف الثوم ودقيقة واحدة. أضف الطماطم والأعشاب؛ اطبخ 10 دقائق حتى تتفتت الطماطم. أعد جميع الخضروات، قلّب برفق، تبّل واترك يتبخّر على نار خفيفة دون غطاء 15-20 دقيقة. قدّمه دافئاً أو في درجة حرارة الغرفة.","en":"Lightly salt the aubergine cubes and set aside for 15 minutes to draw out bitterness, then pat dry. Heat 1 tbsp oil in a wide pan over medium-high heat. Saute the aubergine until lightly golden, about 5 minutes; remove and set aside. Saute the courgettes 3 minutes, then the peppers 4 minutes; remove each in turn. In the same pan, heat the remaining oil and sweat the onion until soft and translucent, 5 minutes. Add garlic and cook 1 minute. Add the tomatoes and herbes de Provence; cook 10 minutes until the tomatoes collapse into a sauce. Return all vegetables, stir gently, season with salt and pepper, and simmer uncovered 15–20 minutes until everything is tender and fragrant. Serve warm or at room temperature — ratatouille tastes even better the next day."}},{"id":11,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ar":"اليونان","en":"Greece","ro":"Grecia"},"name":{"ar":"سوفلاكي","en":"Souvlaki","ro":"Souvlaki"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["700 غرام كتف خنزير مقطعة مكعبات 3 سم","3 ملاعق كبيرة زيت زيتون بكر ممتاز","عصير ليمونة واحدة","3 فصوص ثوم مهروسة","2 ملعقة صغيرة زعتر يوناني مجفف","1 ملعقة صغيرة زعتر مجفف","ملح وفلفل أسود مطحون طازج","أسياخ خشبية أو معدنية"],"en":["700g pork shoulder, cut into 3cm cubes","3 tbsp extra-virgin olive oil","juice of 1 lemon","3 garlic cloves, crushed","2 tsp dried Greek oregano","1 tsp dried thyme","salt and freshly ground black pepper","wooden or metal skewers"],"ro":["700g ceafă de porc, tăiată cuburi de 3 cm","3 linguri ulei de măsline extravirgin","sucul de la 1 lămâie","3 căței de usturoi, zdrobiți","2 linguriță oregano grecesc uscat","1 linguriță cimbru uscat","sare și piper negru proaspăt măcinat","frigărui de lemn sau metal"]},"howIsMade":{"ar":"اخلط زيت الزيتون وعصير الليمون والثوم المهروس والزعتر في وعاء. أضف مكعبات الخنزير واخلطها جيداً، غطها وضعها في الثلاجة لمدة ساعة على الأقل، ويُفضل طوال الليل. إذا استخدمت أسياخاً خشبية، انقعها في الماء 30 دقيقة. انظم 5-6 مكعبات على كل سيخ مع ترك مسافات صغيرة. اشوِ على نار عالية (الفحم مثالي) 8-10 دقائق، مع التقليب كل دقيقتين حتى يتحول الخارج للون الذهبي وتخرج العصائر صافية. قدمها فوراً في خبز البيتا الدافئ مع التزاتزيكي والطماطم والبصل الأحمر.","en":"Combine olive oil, lemon juice, crushed garlic, oregano and thyme in a bowl. Add the pork cubes, toss to coat thoroughly, cover and refrigerate for at least 1 hour — overnight is better. If using wooden skewers, soak them in water for 30 minutes. Thread 5-6 cubes per skewer, leaving small gaps between pieces. Grill over high heat (charcoal is ideal) for 8-10 minutes total, turning every 2 minutes, until the outside is charred and the juices run clear. The meat should be firm but not dry — pull it at 70°C internal. Serve immediately in warm pita with tzatziki, sliced tomatoes and red onion."},"nutrition":{"cal":420,"prot":35,"carb":3,"fat":29,"fib":0}},{"id":12,"origin":{"ar":"الهند","en":"India","ro":"India"},"name":{"ar":"دال","en":"Dhal","ro":"Dhal"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"veg","ingredients":{"ar":["300غ عدس أحمر مجفّف (ماسور دال)","2 ملعقة كبيرة سمن (أو زيت نباتي)","بصلة كبيرة مفرومة ناعماً","4 فصوص ثوم مفروم","2 سم زنجبيل طازج مبشور","400غ طماطم مقطّعة معلّبة (أو 3 طماطم طازجة كبيرة)","1 ملعقة صغيرة كركم مطحون","1 ملعقة صغيرة كمون مطحون","1 ملعقة صغيرة كزبرة مطحونة","½ ملعقة صغيرة غارام ماسالا","½ ملعقة صغيرة فلفل أحمر مطحون","400مل حليب جوز الهند (أو ماء)","ملح حسب الذوق","كزبرة طازجة وأسافين ليمون للتقديم"],"en":["300g dried red lentils (masoor dal)","2 tbsp ghee (or vegetable oil)","1 large onion, finely chopped","4 garlic cloves, minced","2 cm fresh ginger, grated","400g canned chopped tomatoes (or 3 large fresh tomatoes)","1 tsp ground turmeric","1 tsp ground cumin","1 tsp ground coriander","½ tsp garam masala","½ tsp ground red chilli","400ml coconut milk (or water)","salt to taste","fresh coriander and lemon wedges to serve"],"ro":["300g linte roșie uscată (masoor dal)","2 linguri ghee (sau ulei vegetal)","1 ceapă mare, tocată fin","4 căței de usturoi, tocați","2 cm ghimbir proaspăt, ras","400g roșii din conservă, tăiate cuburi (sau 3 roșii mari proaspete)","1 linguriță turmeric măcinat","1 linguriță chimen măcinat","1 linguriță coriandru măcinat","½ linguriță garam masala","½ linguriță ardei iute roșu măcinat","400ml lapte de nucă de cocos (sau apă)","sare după gust","coriandru proaspăt și felii de lămâie pentru servire"]},"howIsMade":{"ar":"اشطف العدس الأحمر بماء بارد 3–4 مرات حتى يصفو الماء. في قدر واسع ذوّب السمن على نار متوسطة. أضف البصل وقلّبه باستمرار 10–12 دقيقة حتى يذهب ذهبياً طرياً — لا تتخطّ هذه الخطوة، القاعدة المكرملة هي أساس النكهة. أضف الثوم والزنجبيل واقلِ دقيقة. أضف الكركم والكمون والكزبرة والفلفل الأحمر وحرّك 30 ثانية حتى تفوح الرائحة. أضف الطماطم واطبخ 3–4 دقائق. أضف العدس المصفّى وحليب جوز الهند (أو الماء)، اطبخ على نار هادئة مكشوفاً 20–25 دقيقة مع التقليب أحياناً حتى يذوب العدس ويصبح الدال كريمياً. أضف الغارام ماسالا وتحقّق من الملح. قدّم مع الأرز أو الخبز الهندي وكزبرة طازجة وعصير ليمون.","en":"Rinse the red lentils under cold water 3–4 times until the water runs clear. In a large pan melt ghee over medium heat. Add the onion and cook, stirring often, for 10–12 minutes until golden and soft — do not skip this step, the caramelised base is the backbone of flavour. Add garlic and ginger, fry 1 minute. Add turmeric, cumin, coriander, and red chilli, stir 30 seconds until fragrant. Add tomatoes, simmer 3–4 minutes until slightly thickened. Add the rinsed lentils and coconut milk (or water), reduce to a gentle simmer and cook uncovered for 20–25 minutes, stirring occasionally, until lentils collapse and the dhal is thick and creamy. Stir in garam masala and adjust salt. Thin with a little hot water if needed. Serve with rice or naan, topped with fresh coriander and a squeeze of lemon."},"nutrition":{"cal":490,"prot":21,"carb":56,"fat":19,"fib":13}},{"id":13,"timeMins":{"total":20,"active":20},"servings":4,"tipType":"def","pairingsType":"veg","origin":{"ar":"المكسيك","en":"Mexico","ro":"Mexic"},"name":{"ar":"جواكامولي","en":"Guacamole","ro":"Guacamole"},"category":{"ar":"وجبة خفيفة","en":"Snack","ro":"Gustare"},"ingredients":{"ar":["3 أفوكادو هاس ناضجة","عصير 2 حبة ليمون أخضر (نحو 3 ملاعق كبيرة)","1 بصلة حمراء صغيرة مفرومة ناعماً","2 طماطم روما ناضجة بدون بذور ومقطّعة","1 فلفل خالابينو صغير مفروم ناعماً (بدون بذور للحدة الخفيفة)","15 غ كزبرة طازجة مقطّعة خشناً","نصف ملعقة صغيرة ملح بحري ناعم حسب الرغبة"],"en":["3 ripe Hass avocados","juice of 2 limes (about 3 tbsp)","1 small red onion, finely diced","2 ripe Roma tomatoes, deseeded and diced","1 small jalapeño, finely chopped (seeds removed for mild heat)","15g fresh cilantro, roughly chopped","1/2 tsp fine sea salt, plus more to taste"],"ro":["3 avocado Hass coapte","sucul a 2 lime (aprox. 3 linguri)","1 ceapă roșie mică, tocată mărunt","2 roșii Roma coapte, curățate de semințe și tocate","1 ardei jalapeno mic, tocat fin (fără semințe pentru mai puțin iute)","15g coriandru proaspăt, tocat grosier","1/2 linguriță sare fină de mare"]},"howIsMade":{"ar":"قسّم الأفوكادو إلى نصفين، أخرج النواة وأخرج اللب بملعقة. أضف عصير الليمون فوراً — الحمض يبطّئ الأكسدة. اهرس بشوكة حسب الملمس المرغوب: خشن أو ناعم. أضف البصل والطماطم والخالابينو والكزبرة. تبّل بالملح. تذوّق واضبط الليمون والملح. للحفظ، اضغط ورق التغليف مباشرةً على السطح لإزالة الهواء — عصير الليمون يحمي أكثر بكثير من النواة. قدّم في غضون ساعتين.","en":"Halve and stone the avocados. Scoop the flesh into a bowl and add the lime juice immediately — the acid slows browning. Mash with a fork to your preferred texture: very chunky or almost smooth. Fold in the diced onion, tomato, jalapeño, and cilantro. Season with salt. Taste and adjust lime and salt. To store, press cling film directly onto the surface of the guacamole to exclude air — the lime juice prevents browning far better than the avocado stone. Serve within 2 hours for best colour and flavour."},"nutrition":{"cal":200,"prot":3,"carb":13,"fat":17,"fib":9}},{"id":14,"servings":4,"tipType":"soup","pairingsType":"soup","origin":{"ar":"روسيا","en":"Russia","ro":"Rusia"},"name":{"ar":"بورشت","en":"Borscht","ro":"Bors"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"ingredients":{"ar":["500غ شمندر خام، مقشور ومبشور خشن","300غ ملفوف أبيض مقطّع رفيع","300غ بطاطس صلبة، مقطّعة مكعبات 2 سم","جزرتان متوسطتان، مقطّعتان شرائح","بصلة كبيرة، مقطّعة","3 فصوص ثوم مفرومة","2 ملعقة كبيرة معجون طماطم","1.5 لتر مرق لحم بقري أو خضار","2 ملعقة كبيرة زيت عباد الشمس","1 ملعقة كبيرة خل تفاح (لتثبيت اللون الأحمر)","ملح وفلفل أسود حسب الرغبة","كريمة حامضة وشبت طازج للتقديم"],"en":["500g raw beetroot, peeled and coarsely grated","300g white cabbage, thinly shredded","300g waxy potatoes, cut into 2cm cubes","2 medium carrots, julienned","1 large onion, diced","3 garlic cloves, minced","2 tbsp tomato paste","1.5 litres beef or vegetable broth","2 tbsp sunflower oil","1 tbsp apple cider vinegar (to fix the deep red colour)","Salt and black pepper to taste","Sour cream and fresh dill to serve"],"ro":["500g sfeclă roșie crudă, curățată și rasă grosier","300g varză albă, feliată subțire","300g cartofi waxy, cuburi de 2 cm","2 morcovi medii, julien","1 ceapă mare, tocată","3 căței de usturoi, tocați","2 linguri pastă de roșii","1,5 litri supă de vită sau legume","2 linguri ulei de floarea-soarelui","1 lingură oțet de mere (pentru culoare vie)","Sare și piper după gust","Smântână și mărar proaspăt pentru servire"]},"howIsMade":{"ar":"سخّن الزيت على نار متوسطة، أضف البصل والجزر واقلِهما 7–8 دقائق حتى يلينا. أضف معجون الطماطم والثوم؛ اقلب دقيقتين. أضف الشمندر المبشور والخل؛ اطبخ 5 دقائق — الخل يثبّت اللون الأحمر الغامق. صب المرق الساخن وأضف البطاطس. أغلِ ثم خفّف النار واتركه يتهنّد 15 دقيقة. أضف الملفوف واتركه 10 دقائق حتى يلين قليلاً. اضبط الملح والفلفل وأضف الخل إذا احتجت لحموضة. قدّمه في أطباق عميقة مع الكريمة الحامضة والشبت الطازج.","en":"Heat oil over medium heat, add onion and carrots, and sauté 7–8 minutes until softened. Stir in tomato paste and garlic; cook 2 minutes. Add the grated beetroot and apple cider vinegar; cook 5 minutes — the vinegar fixes the deep red colour. Pour in the hot broth and add potatoes. Bring to a boil, reduce heat and simmer 15 minutes. Add shredded cabbage and simmer another 10 minutes until the cabbage is just tender and the potatoes are soft but not falling apart. Taste for salt, add pepper and extra vinegar if the soup needs brightness. Ladle into deep bowls and top with a generous spoonful of sour cream and fresh chopped dill."},"nutrition":{"cal":260,"prot":5,"carb":28,"fat":9,"fib":7}},{"id":15,"servings":4,"tipType":"dessert","pairingsType":"dessert","origin":{"ar":"الولايات المتحدة","en":"USA","ro":"SUA"},"name":{"ar":"فطائر أمريكية","en":"Pancakes","ro":"Clătite americane"},"category":{"ar":"فطور","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"ar":["200 غرام دقيق أبيض","2 ملعقة صغيرة بيكنج بودر","1 ملعقة كبيرة سكر","نصف ملعقة صغيرة ملح","240 مل حليب كامل الدسم","2 بيضة كبيرة","30 غرام زبدة مذابة، وزيادة للمقلاة","1 ملعقة صغيرة خلاصة الفانيليا"],"en":["200g plain flour","2 tsp baking powder","1 tbsp sugar","1/2 tsp salt","240ml whole milk","2 large eggs","30g melted butter, plus extra for the pan","1 tsp vanilla extract"],"ro":["200g făină albă","2 linguriță praf de copt","1 lingură zahăr","1/2 linguriță sare","240ml lapte integral","2 ouă mari","30g unt topit, plus extra pentru tigaie","1 linguriță extract de vanilie"]},"howIsMade":{"ar":"في وعاء كبير، اخلط الدقيق والبيكنج بودر والسكر والملح. في وعاء آخر، اخفق الحليب والبيض والزبدة المذابة والفانيليا. صب المكونات السائلة على الجافة واخلطها برفق بالملعقة — كتل صغيرة طبيعية ومرغوبة؛ الخلط الزائد يطور الغلوتين ويجعل الفطائر مطاطية. اترك العجين يرتاح 5 دقائق. سخن مقلاة غير لاصقة على نار متوسطة، ادهنها بزبدة وامسح الزيادة. صب ملعقة كبيرة (حوالي 80مل) لكل فطيرة. اطهُ 2-3 دقائق حتى تظهر فقاعات على السطح وتجف الحواف. اقلبها واطهُ دقيقة إلى دقيقتين. قدمها فوراً مع شراب القيقب والزبدة والفاكهة الطازجة.","en":"In a large bowl, whisk together flour, baking powder, sugar and salt. In a second bowl, whisk milk, eggs, melted butter and vanilla. Pour the wet ingredients into the dry and fold gently with a spatula — a few lumps are fine and even desirable; over-mixing develops gluten and makes the pancakes tough. Rest the batter 5 minutes: the baking powder bubbles will rise to the surface. Heat a non-stick pan over medium heat, add a small knob of butter and wipe away the excess. Pour one ladle (about 80ml) of batter per pancake. Cook 2-3 minutes until bubbles break on the surface and the edges look set and dry. Flip and cook 1-2 minutes more until golden on the underside. Serve immediately — pancakes deflate as they cool. Top with real maple syrup, fresh butter and seasonal fruit."},"nutrition":{"cal":340,"prot":10,"carb":45,"fat":13,"fib":1}},{"id":16,"servings":4,"tipType":"def","pairingsType":"fish","origin":{"ar":"تايلاند","en":"Thailand","ro":"Thailanda"},"name":{"ar":"باد تاي","en":"Pad Thai","ro":"Pad Thai"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["200غ نودلز أرز مسطح جاف (ينقع 30 دقيقة)","200غ جمبري نيء، مقشور ومنظف","بيضتان","2 ملعقة كبيرة معجون التمر الهندي","2 ملعقة كبيرة صلصة سمك","1 ملعقة كبيرة صلصة محار","1 ملعقة صغيرة سكر نخيل","2 ملعقة كبيرة زيت خفيف","2 فص ثوم مفروم","1 كراث مقطع رقيقاً","100غ براعم فول الصويا","3 بصل أخضر مقطع 3سم","3 ملاعق كبيرة فول سوداني محمص مكسر","1 ليمون أخضر أسافير","فلفل مجفف حسب الذوق"],"en":["200g dried flat rice noodles (soaked 30 min)","200g raw medium prawns, peeled and deveined","2 eggs","2 tbsp tamarind paste","2 tbsp fish sauce","1 tbsp oyster sauce","1 tsp palm sugar or brown sugar","2 tbsp neutral oil","2 cloves garlic, minced","1 shallot, thinly sliced","100g bean sprouts","3 spring onions, cut into 3cm pieces","3 tbsp roasted peanuts, roughly crushed","1 lime, cut into wedges","Dried chili flakes to serve"],"ro":["200g tăiței lat de orez (înmuiați 30 min)","200g creveți cruzi, curățați","2 ouă","2 linguri pastă de tamarind","2 linguri sos de pește","1 lingură sos de stridii","1 linguriță zahăr de palmier","2 linguri ulei neutru","2 căței de usturoi, tocați","1 șalotă, feliată","100g germeni de fasole","3 cepe verzi, tăiate 3cm","3 linguri alune prăjite, zdrobite","1 lime, pentru servire","Fulgi de ardei iute, după gust"]},"howIsMade":{"ar":"انقع النودلز في الماء البارد 30 دقيقة ثم صفّها. اخلط معجون التمر الهندي وصلصة السمك وصلصة المحار والسكر في وعاء صغير لتحضير الصوص. سخّن الزيت في المقلاة على نار عالية جداً حتى يبدأ بالتدخين الخفيف؛ اقلِ الثوم والكراث 30 ثانية، أضف الجمبري واطبخه دقيقتين حتى يصبح ورديّاً. ادفع كل شيء جانباً، أضف البيض واخفقه خفيفاً 30 ثانية ثم اجمعه مع الجمبري. أضف النودلز المصفّاة وصبّ الصوص؛ قلّب باستمرار دقيقتين–3 دقائق حتى تمتص النودلز الصوص وتبدأ بالتكرمل على الحواف. ارفع عن النار، أضف البراعم والبصل الأخضر؛ قدّم فوراً مع الفول السوداني المكسر وأسفين ليمون أخضر وفلفل مجفف.","en":"Soak rice noodles in cold water for 30 minutes, then drain. Mix tamarind paste, fish sauce, oyster sauce and sugar in a small bowl to make the sauce. Heat oil in a wok over very high heat until just smoking; fry garlic and shallot for 30 seconds, add prawns and cook 2 minutes until just pink. Push everything to the side, crack in eggs and scramble lightly for 30 seconds, then toss everything together. Add drained noodles and pour the sauce over; toss constantly for 2–3 minutes until the noodles absorb the sauce and begin to caramelise at the edges. Remove from heat, fold in bean sprouts and spring onions; serve immediately topped with crushed peanuts, a lime wedge and chili flakes to taste."},"nutrition":{"cal":380,"prot":18,"carb":40,"fat":13,"fib":2}},{"id":17,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ar":"ألمانيا","en":"Germany","ro":"Germania"},"name":{"ar":"شنيتزل","en":"Schnitzel","ro":"Schnitzel"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"ingredients":{"ar":["4 شرائح لحم خنزير بدون عظم (نحو 150 غ كل منها) منزّعة الشحم","80 غ دقيق عادي متبّل بالملح والفلفل","2 بيضة كبيرة مخفوقة","150 غ بقسماط جاف ناعم","200 مل زيت خفيف (عباد الشمس أو الكانولا) للقلي","1 ليمونة مقطّعة أنصافاً للتقديم","ملح وفلفل أبيض"],"en":["4 boneless pork loin chops (about 150g each), trimmed","80g plain flour, seasoned with salt and pepper","2 large eggs, beaten","150g fine dry breadcrumbs (Semmelbrösel)","200ml neutral oil (sunflower or rapeseed) for frying","1 lemon, cut into wedges for serving","salt and white pepper"],"ro":["4 cotlete de porc din spată (aprox. 150g fiecare), dezosate și degresate","80g făină simplă, condimentată cu sare și piper","2 ouă mari, bătute","150g pesmet fin uscat (Semmelbrösel)","200ml ulei neutru (floarea-soarelui sau rapiță) pentru prăjit","1 lămâie, tăiată fâșii pentru servit","sare și piper alb"]},"howIsMade":{"ar":"ضع كل شريحة بين طبقتين من ورق التغليف واضربها بمطرقة اللحم أو الشوبك حتى يتساوى سمكها عند 4–5 ملم — النحافة المتساوية هي السمة الأساسية للشنيتزل الأصيل. جففها ثم تبّل بالملح والفلفل الأبيض. أعد ثلاثة أطباق ضحلة: دقيق متبّل وبيض مخفوق وبقسماط. غطّ كل شريحة بالدقيق (انفض الزائد)، اغمسها بالبيض، ثم اضغط بثبات على البقسماط دون ضغط مفرط — يجب أن تبقى مسامية لتتشقق وتتحمص في الزيت الحار. صبّ الزيت في مقلاة واسعة بعمق 1سم وسخّنه إلى 170–180°C. اقلِ 2–3 دقائق لكل وجه حتى يصبح ذهبياً داكناً ومقرمشاً. صفّه على رف سلكي ولا تضعه على منشفة ورقية أبداً. قدّمه فوراً مع شرائح الليمون.","en":"Place each pork chop between two sheets of cling film and beat with a meat mallet or rolling pin until evenly 4–5mm thick — the thin, even cut is the defining feature of a proper schnitzel. Pat dry and season with salt and white pepper. Set up three shallow dishes: seasoned flour, beaten eggs, breadcrumbs. Coat each schnitzel in flour (shake off the excess), dip in egg, then press firmly into breadcrumbs to coat evenly — do not press the crumb down too hard; it should stay airy so it puffs and blisters in hot oil. Pour oil into a wide pan to a depth of 1cm and heat to 170–180°C. Fry 2–3 minutes per side until deep golden and crisp. Drain on a wire rack — never on paper towel, which traps steam and kills the crust. Serve immediately with lemon wedges."},"nutrition":{"cal":570,"prot":45,"carb":15,"fat":35,"fib":1}},{"id":18,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ar":"البرازيل","en":"Brazil","ro":"Brazilia"},"name":{"ar":"فيجوادا","en":"Feijoada","ro":"Feijoada"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["400 غرام فاصولياء سوداء مجففة، منقوعة طوال الليل","400 غرام ضلوع خنزير مدخنة","200 غرام شوريثو أو سجق مدخن مقطع شرائح","200 غرام لحم مقدد مدخن مقطع مكعبات","1 بصلة كبيرة مفرومة","4 فصوص ثوم مفروم","ورقتا غار","3 ملاعق كبيرة زيت زيتون","ملح وفلفل وبهار حسب الذوق"],"en":["400g dried black beans, soaked overnight","400g smoked pork ribs","200g chourico or smoked sausage, sliced","200g smoked bacon, diced","1 large onion, chopped","4 garlic cloves, minced","2 bay leaves","3 tbsp olive oil","salt, pepper and chilli flakes to taste"],"ro":["400g fasole neagră uscată, înmuiată 12 ore","400g coaste de porc afumate","200g chouriço sau cârnați afumați, feliați","200g bacon afumat, tăiat cuburi","1 ceapă mare, tocată","4 căței de usturoi, tocați","2 foi de dafin","3 linguri ulei de măsline","sare, piper și fulgi de ardei iute după gust"]},"howIsMade":{"ar":"صفّ الفاصولياء المنقوعة وضعها في قدر كبير مع ماء بارد يغطيها بـ5 سم. أضف الضلوع المدخنة وأوراق الغار. أضف للغليان ثم اطبخ على نار متوسطة ساعة مع إزالة الرغوة. أثناء ذلك، قلي البصل في الزيت 8 دقائق، أضف الثوم واطبخ دقيقتين. أضف الشوريثو واللحم المقدد وحمّرهما 5 دقائق. انقل كل شيء إلى القدر مع الفاصولياء واخلط جيداً واطبخ على نار هادئة 45-60 دقيقة حتى تصبح الفاصولياء طرية والمرق سميكاً. اسحق بعض الفاصولياء على جانب القدر لتكثيف المرق. اضبط الملح والفلفل. قدمها مع أرز أبيض وشرائح البرتقال والفاروفا.","en":"Drain the soaked beans and place in a large pot with fresh cold water to cover by 5cm. Add the smoked ribs and bay leaves. Bring to a boil, then simmer over medium heat for 1 hour, skimming any foam. Meanwhile, heat olive oil in a skillet, saute onion 8 minutes until soft and golden, add garlic and cook 2 minutes more. Add chourico and bacon, brown for 5 minutes. Transfer everything to the bean pot, stir well and simmer on low heat for 45-60 minutes until the beans are completely tender and the broth has thickened. Crush a handful of beans against the pot side with a wooden spoon — this thickens the stew naturally. Adjust salt and pepper. Serve in deep bowls with white rice, fresh orange slices and farofa (toasted manioc flour)."},"nutrition":{"cal":620,"prot":38,"carb":45,"fat":32,"fib":14}},{"id":19,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ar":"الصين","en":"China","ro":"China"},"name":{"ar":"دجاج كونغ باو","en":"Kung Pao Chicken","ro":"Pui Gong Bao"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["500غ صدر دجاج، مقطّع مكعبات 2 سم","100غ فول سوداني محمص بدون ملح","8–10 فلفل حار صيني مجفّف","4 بصل أخضر، مقطّع قطع 3 سم","3 فصوص ثوم مقطّعة شرائح رفيعة","قطعة زنجبيل 2 سم مقطّعة شرائح","2 ملعقة كبيرة زيت فلفل سيشوان أو زيت عباد الشمس","تتبيلة: 1 ملعقة كبيرة صلصة صويا، 1 ملعقة صغيرة نشا الذرة، 1 ملعقة صغيرة زيت السمسم","صلصة: 2 ملعقة كبيرة صلصة صويا، 1 ملعقة كبيرة خل الأرز الأسود، 1 ملعقة كبيرة سكر، 1 ملعقة صغيرة نشا، 2 ملعقة كبيرة ماء"],"en":["500g chicken breast, cut into 2cm cubes","100g unsalted roasted peanuts","8–10 dried Chinese chili peppers (Sichuan or similar)","4 spring onions, cut into 3cm pieces","3 garlic cloves, thinly sliced","2cm piece of ginger, thinly sliced","2 tbsp Sichuan chili oil or sunflower oil","Marinade: 1 tbsp soy sauce, 1 tsp cornstarch, 1 tsp sesame oil","Sauce: 2 tbsp soy sauce, 1 tbsp black rice vinegar (Chinkiang), 1 tbsp sugar, 1 tsp cornstarch, 2 tbsp water"],"ro":["500g piept de pui, tăiat cuburi de 2 cm","100g arahide prăjite nesărate","8–10 ardei iuți uscați chinezești (chili Sichuan)","4 cepe verzi, tăiate bucăți de 3 cm","3 căței de usturoi, feliați subțire","1 bucată ghimbir de 2 cm, feliată subțire","2 linguri ulei cu ardei Sichuan sau ulei de floarea-soarelui","Marinată: 1 lingură sos de soia, 1 linguriță amidon de porumb, 1 linguriță ulei de susan","Sos: 2 linguri sos de soia, 1 lingură oțet de orez negru (Chinkiang), 1 lingură zahăr, 1 linguriță amidon de porumb, 2 linguri apă"]},"howIsMade":{"ar":"تبّل الدجاج بمكونات التتبيلة واتركه 15 دقيقة. اخلط مكونات الصلصة في وعاء صغير. سخّن الووك على أعلى نار حتى يدخّن؛ أضف الزيت واقلِ الفلفل المجفّف 30 ثانية حتى يتلوّن. أضف الدجاج واحمرّه 3–4 دقائق دون تحريك حتى يذهب؛ اقلبه واطبخ دقيقتين أخريين. أضف الثوم والزنجبيل والجزء الأبيض من البصل الأخضر؛ اقلِ دقيقة. صب الصلصة وحرّك بقوة دقيقة حتى تتكثّف. أضف الفول السوداني والجزء الأخضر من البصل؛ قلّب 30 ثانية. قدّم فوراً مع أرز الياسمين.","en":"Toss chicken with marinade ingredients and leave for 15 minutes. Combine sauce ingredients in a small bowl. Heat wok over highest heat until smoking; add oil and fry dried chilis and Sichuan peppercorns 30 seconds until darkened but not black — they should smell toasted, not burnt. Add chicken pieces and sear 3–4 minutes without stirring, until golden on one side; toss and cook 2 more minutes. Add garlic, ginger, and the white parts of the spring onion; stir-fry 1 minute. Pour in the sauce, toss vigorously for 1 minute until thickened and clinging to the chicken. Throw in peanuts and green spring onion tops; toss 30 seconds. Serve immediately with jasmine rice."},"nutrition":{"cal":400,"prot":32,"carb":11,"fat":22,"fib":2}},{"id":20,"servings":4,"tipType":"fish","pairingsType":"fish","origin":{"ar":"المملكة المتحدة","en":"United Kingdom","ro":"Marea Britanie"},"name":{"ar":"سمك وبطاطا","en":"Fish and Chips","ro":"Fish and Chips"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["4 شرائح قد أو هادوك (حوالي 180غ لكل منها)، بدون جلد","1 كغ بطاطس دقيقية القوام، مقطّعة بطاطا سميكة","زيت نباتي للقلي العميق (حوالي 2 لتر)","العجينة: 180غ دقيق عادي + إضافي للتقليب","1 ملعقة صغيرة بيكنج باودر","1 ملعقة صغيرة ملح ناعم","300مل بيرة باردة جداً (لاغر أو بيل إيل)","ملح وخل الشعير للتقديم"],"en":["4 cod or haddock fillets (about 180g each), skin removed","1kg floury potatoes (Maris Piper or King Edward), cut into thick chips","Vegetable oil for deep-frying (about 2 litres)","Batter: 180g plain flour, plus extra for dusting","1 tsp baking powder","1 tsp fine salt","300ml ice-cold lager or pale ale","Salt and malt vinegar to serve"],"ro":["4 fileuri de cod sau haddock (aprox. 180g fiecare), fără piele","1 kg cartofi floury (Maris Piper sau King Edward), tăiați bețe groase","Ulei vegetal pentru prăjit (aprox. 2 litri)","Pentru aluat: 180g făină tip 550 + extra pentru tăvălit","1 linguriță praf de copt","1 linguriță sare fină","300ml bere blondă rece (lager sau ale)","Sare și oțet de malt pentru servire"]},"howIsMade":{"ar":"اقلِ البطاطا على مرحلتين: اقلِها أولاً عند 140°م 8 دقائق حتى تلين دون تلوين؛ صفّيها وبرّدها على شبكة. اعجن العجينة بخلط الدقيق والبيكنج باودر والملح، ثم أضف البيرة الباردة تدريجياً حتى قوام الكريمة الكثيفة — لا تعجن كثيراً. جفّف شرائح السمك جيداً بورق المطبخ. سخّن الزيت إلى 185°م. لفّ كل شريحة بالدقيق الإضافي وانفض الزائد، اغمسها في العجينة واتركها تقطر ثوانٍ. اقلِها 6–8 دقائق — في المنتصف صب زيتاً ساخناً من الأعلى — حتى تصبح العجينة ذهبية مقرمشة. صفّيها على ورق. ارفع حرارة الزيت إلى 200°م وأعد قلي البطاطا 3–4 دقائق حتى تصبح ذهبية مقرمشة. قدّم فوراً مع الملح وخل الشعير.","en":"Cook chips in two stages: fry at 140°C for 8 minutes until soft but not coloured; drain and cool on a rack. Make the batter by whisking flour, baking powder, and salt together, then gradually whisk in ice-cold beer until the consistency of double cream — do not overmix. Pat fish fillets completely dry with paper towels. Heat oil to 185°C. Dust each fillet in the extra flour, shake off excess, dip into batter and let it drip for a few seconds. Fry 6–8 minutes — halfway through, spoon hot oil over the top for even crisping — until the batter is deep golden and crunchy. Drain on paper. Raise oil to 200°C and fry chips a second time for 3–4 minutes until golden and crisp all over. Serve immediately with salt and malt vinegar."},"nutrition":{"cal":850,"prot":35,"carb":85,"fat":42,"fib":5}},{"id":21,"origin":{"ar":"فيتنام","en":"Vietnam","ro":"Vietnam"},"name":{"ar":"فو","en":"Pho","ro":"Pho"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","timeMins":{"total":225,"active":75},"pairingsType":"def","ingredients":{"ar":["400غ شعيرية أرز جافة (بانه فو، عرض 5مم)","500غ صدر أو كنب بقري (للمرق)","1 كغ عظام بقرية (نخاع أو مفصل)","2 بصلة متوسطة مقسومة إلى نصفين","5 سم زنجبيل طازج مشقوق طولياً","3 بهارات يانسون نجمي","عود قرفة (5 سم)","3 قرنفلات","2 ملعقة كبيرة صلصة السمك (نووك مام)","1 ملعقة صغيرة سكر","ملح حسب الذوق","200غ براعم فاصوليا طازجة","كزبرة طازجة وريحان تايلاندي","2 فلفل أحمر حار مقطّع دوائر (على المائدة)","2 ليمون حامض مربّعات (على المائدة)","صلصة هويسن وسريراتشا (على المائدة)"],"en":["400g dried rice noodles (banh pho, 5mm width)","500g beef brisket or flank (for the broth)","1kg beef bones (marrow or knuckle)","2 medium onions, halved","5 cm fresh ginger, halved lengthways","3 star anise","1 cinnamon stick (5 cm)","3 cloves","2 tbsp fish sauce (nuoc mam)","1 tsp sugar","salt to taste","200g fresh bean sprouts","fresh coriander and Thai basil","2 red chillies, sliced (at the table)","2 limes, quartered (at the table)","hoisin sauce and sriracha (at the table)"],"ro":["400g tăiței de orez (banh pho, lățime 5mm), uscați","500g piept de vită sau flacără (pentru supă)","1kg oase de vită (măduvă sau coadă)","2 cepe medii, înjumătățite","5 cm ghimbir proaspăt, înjumătățit","3 anasoane stelate","1 baton de scorțișoară (5 cm)","3 cuișoare","2 linguri sos de pește (nuoc mam)","1 linguriță zahăr","sare după gust","200g muguri de soia proaspeți","coriandru proaspăt și busuioc thai","2 ardei iuți roșii, feliați (la masă)","2 lămâi verzi, tăiate în sferturi (la masă)","sos hoisin și sos sriracha (la masă)"]},"howIsMade":{"ar":"اسلق العظام في ماء مغلي 5 دقائق، اسكب الماء واشطفها جيداً — هذا يزيل الشوائب ويحافظ على صفاء المرق. حمّر نصفي البصل والزنجبيل مباشرةً على لهب الغاز أو تحت الشواية حتى تسودّ حوافها قليلاً (2–3 دقائق لكل وجه) — هذا يمنح المرق لونه الذهبي وعمقه. امرأ قدراً كبيراً بـ3 لتر ماء بارد، أضف العظام والصدر والبصل والزنجبيل المحمّر واليانسون النجمي والقرفة والقرنفل. أغلِ ثم خفّف النار وطبخ مكشوفاً 3 ساعات مع إزالة الشحم دورياً. أخرج صدر اللحم بعد ساعة ونصف، دعه يبرد ثم قطّعه رفيعاً. صفِّ المرق عبر منخل ناعم وتبّله بصلصة السمك والسكر والملح. نقّع الشعيرية في ماء بارد 20 دقيقة، اسلقها 30 ثانية وصفّها. وزّعها على أطباق، صبّ المرق المغلي فوقها وضع اللحم. قدّم مع البراعم والكزبرة والريحان والفلفل والليمون والصلصات.","en":"Blanch beef bones in boiling water for 5 minutes, discard water, rinse well — this removes impurities and keeps the broth clear. Char the onion halves and ginger directly over a gas flame or under the grill until lightly blackened on the edges (2–3 minutes per side) — this gives the broth its golden colour and depth. Fill a large pot with 3L cold water, add bones, brisket, charred onion, ginger, star anise, cinnamon, and cloves. Bring to a boil, reduce to a bare simmer, cook uncovered for 3 hours, skimming fat periodically. Remove the brisket after 1½ hours, let cool, slice thinly. Strain broth through a fine sieve, season with fish sauce, sugar, and salt. Soak noodles in cold water 20 minutes, boil 30 seconds, drain. Divide noodles into bowls, ladle boiling broth over, add meat slices. Serve with bean sprouts, coriander, basil, chilli, lime, and sauces at the table."},"nutrition":{"cal":380,"prot":28,"carb":42,"fat":10,"fib":2}},{"id":22,"origin":{"ar":"إسبانيا","en":"Spain","ro":"Spania"},"name":{"ar":"باييلا","en":"Paella","ro":"Paella"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"fish","ingredients":{"ar":["300غ أرز بومبا (أو أرز بحبة قصيرة)","400غ أفخاذ دجاج منزوعة العظم مقطّعة قطعاً","300غ جمبري نيء (بقشره أو مقشّر)","400غ بلح البحر منظّف ومزال خيطه","بصلة كبيرة مفرومة ناعماً","4 فصوص ثوم مفروم","فليفلة حمراء مقطّعة مكعبات","400غ طماطم معلّبة مهروسة","½ ملعقة صغيرة خيوط زعفران (منقوعة في 2 ملعقة كبيرة ماء دافئ)","1 ملعقة صغيرة بابريكا مدخّنة (بيمينتون دي لا فيرا)","800مل مرق دجاج دافئ","3 ملاعق كبيرة زيت زيتون","ملح وفلفل أسود حسب الذوق","بقدونس طازج وأسافين ليمون للتقديم"],"en":["300g bomba rice (or short-grain rice)","400g boneless chicken thighs, cut into pieces","300g raw prawns (shell-on or peeled)","400g mussels, scrubbed and debearded","1 large onion, finely chopped","4 garlic cloves, minced","1 red bell pepper, diced","400g canned crushed tomatoes","½ tsp saffron threads (soaked in 2 tbsp warm water)","1 tsp smoked paprika (pimentón de la Vera)","800ml warm chicken stock","3 tbsp olive oil","salt and black pepper to taste","fresh parsley and lemon wedges to serve"],"ro":["300g orez bomba (sau orez cu bob scurt)","400g pulpe de pui dezosate, tăiate în bucăți","300g creveți crudi (cu coajă sau fără)","400g midii, spălate și curățate","1 ceapă mare, tocată","4 căței de usturoi, tocați","1 ardei gras roșu, tăiat cuburi","400g roșii din conservă, concasate","½ linguriță șofran (înmuiat în 2 linguri apă caldă)","1 linguriță boia de ardei afumată (pimentón de la Vera)","800ml fond de pui cald","3 linguri ulei de măsline","sare și piper negru după gust","pătrunjel proaspăt și felii de lămâie pentru servire"]},"howIsMade":{"ar":"انقع الزعفران في 2 ملعقة كبيرة ماء دافئ; سخّن الزيت في مقلاة باييلا (أو مقلاة واسعة مستوية) على نار متوسطة-عالية. تبّل الدجاج وحمّره 4–5 دقائق من كل وجه حتى يصبح ذهبياً؛ ارفعه جانباً; في نفس المقلاة اقلِ البصل 5 دقائق، أضف الثوم والفليفلة وقلّبهما 3 دقائق. أضف الطماطم والبابريكا المدخّنة واطبخ 3–4 دقائق حتى يتكثّف — هذا هو السوفريتو، روح الباييلا; أضف الأرز وحرّكه دقيقة واحدة. اسكب المرق الدافئ مع الزعفران بالتساوي; أعد الدجاج للمقلاة. اضبط النار على المتوسطة ولا تحرّك بعد الآن — لا يُحرّك قط بعد إضافة المرق; اطبخ مكشوفاً 10 دقائق. رتّب الجمبري والبلح فوقه مع ضغط خفيف; اطبخ 8–10 دقائق أخرى حتى يتحوّل الجمبري إلى اللون الوردي وينفتح البلح. للسوكارات ارفع النار آخر دقيقتين; أرِّح 5 دقائق; زيّن بالبقدونس وقدّم مع ليمون.","en":"Soak saffron in 2 tbsp warm water; heat olive oil in a paella pan (or wide shallow pan) over medium-high heat. Season chicken, sear 4–5 minutes per side until deeply golden; remove and set aside; in the same pan fry onion 5 minutes, add garlic and red pepper, cook 3 more minutes. Add crushed tomatoes and smoked paprika, cook 3–4 minutes until thickened — this is the sofrito, the soul of the paella; add the rice, stir 1 minute to toast lightly. Pour in the warm stock with the saffron and its soaking water, spread evenly; return the chicken. Adjust to medium heat and do not stir again — never stir paella once the stock is added; cook uncovered for 10 minutes. Place prawns and mussels on top, pressing gently into the rice; cook 8–10 minutes more until prawns are pink and mussels open (discard any that stay shut). For socarrat (the coveted crispy bottom crust), raise to high heat the last 2 minutes — listen for a light crackling; rest 5 minutes; garnish with parsley and serve with lemon wedges."},"nutrition":{"cal":520,"prot":32,"carb":58,"fat":16,"fib":3}},{"id":23,"servings":4,"tipType":"def","pairingsType":"korean","origin":{"ar":"كوريا الجنوبية","en":"South Korea","ro":"Coreea de Sud"},"name":{"ar":"بيبيمباب","en":"Bibimbap","ro":"Bibimbap"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"ingredients":{"ar":["كوبان أرز بحبة قصيرة","200غ لحم بقري (سيرلوين)، مقطّع رقيقاً عكس الألياف","كوسا متوسطة مقطّعة شرائح","جزرة متوسطة مقطّعة شرائح","200غ سبانخ صغير","100غ براعم فول الصويا","4 فطر شيتاكي بلا سيقان","4 بيضات","4 ملاعق كبيرة غوتشوجانغ","3 ملاعق كبيرة زيت السمسم","2 ملعقة كبيرة صلصة الصويا","1 ملعقة صغيرة سكر","3 فصوص ثوم مفرومة","بذور سمسم للتزيين"],"en":["2 cups short-grain white rice","200g beef sirloin, thinly sliced against the grain","1 medium courgette, julienned","1 medium carrot, julienned","200g baby spinach","100g bean sprouts","4 shiitake mushrooms, stems removed","4 eggs","4 tbsp gochujang (Korean chili paste)","3 tbsp sesame oil","2 tbsp soy sauce","1 tsp sugar","3 cloves garlic, minced","Sesame seeds to garnish"],"ro":["2 căni orez cu bob scurt","200g vită (antricot), felii subțiri","1 dovlecel mediu, julien","1 morcov mediu, julien","200g spanac baby","100g germeni de fasole","4 ciuperci shiitake, fără codiță","4 ouă","4 linguri gochujang (pastă de ardei coreean)","3 linguri ulei de susan","2 linguri sos de soia","1 linguriță zahăr","3 căței de usturoi, tocați","Semințe de susan, pentru decor"]},"howIsMade":{"ar":"اطبخ الأرز في 2.5 كوب ماء: اتركه يغلي، غطِّه واطبخه على أضعف نار 12 دقيقة، ثم أبقِه مغطى 10 دقائق. تبّل اللحم بملعقة كبيرة صلصة صويا، ملعقة كبيرة زيت سمسم، ملعقة صغيرة سكر ونصف الثوم لمدة 15 دقيقة. اسلق السبانخ 30 ثانية في ماء مملح، اعصره جيداً، وتبّله بملعقة صغيرة زيت سمسم وملح؛ اقلِ براعم فول الصويا دقيقتين مع الثوم والملح؛ اقلِ الجزر والكوسا كل منهما منفرداً دقيقتين مع رشة زيت سمسم. احمرّ اللحم المتبّل على نار عالية 3–4 دقائق حتى يتكرمل؛ اقلِ الشيتاكي دقيقتين مع رشة صلصة صويا؛ اقلِ البيض على شكل عيون بزيت السمسم. وزّع الأرز على 4 أوعية، رتّب الخضار واللحم في أقسام، ضع بيضة في المنتصف، أضف ملعقة كبيرة غوتشوجانغ لكل وعاء، ورشّ زيت سمسم وبذور سمسم — اخلط كل شيء جيداً قبل الأكل.","en":"Cook rice in 2.5 cups water: bring to a boil, cover and simmer on the lowest heat for 12 minutes, then rest off the heat for 10 minutes. Marinate beef with 1 tbsp soy sauce, 1 tbsp sesame oil, 1 tsp sugar and half the garlic for 15 minutes. Blanch spinach 30 seconds in boiling salted water, squeeze dry, season with 1 tsp sesame oil and salt; sauté bean sprouts 2 minutes with garlic and salt; stir-fry carrot and courgette separately for 2 minutes each with a drizzle of sesame oil. Sear marinated beef over high heat 3–4 minutes until caramelised; slice shiitake and sauté 2 minutes with a splash of soy sauce; fry eggs sunny-side up in sesame oil. Divide rice among 4 bowls, arrange vegetables and beef in sections, place an egg in the centre, add 1 tbsp gochujang per bowl, drizzle with sesame oil and scatter sesame seeds — mix everything together before eating."},"nutrition":{"cal":450,"prot":22,"carb":65,"fat":12,"fib":5}},{"id":24,"servings":4,"tipType":"def","pairingsType":"veg","origin":{"ar":"سوريا","en":"Syria","ro":"Siria"},"name":{"ar":"حمص","en":"Hummus","ro":"Hummus"},"category":{"ar":"وجبة خفيفة","en":"Snack","ro":"Gustare"},"ingredients":{"ar":["400 غ حمص مسلوق (علبة واحدة)، منزوع القشرة","80 غ طحينة جيدة الجودة، محرّكة جيداً","عصير 2 حبة ليمون (نحو 4 ملاعق كبيرة)","2 فص ثوم مبروش","نصف ملعقة صغيرة ملح ناعم","3–5 ملاعق كبيرة ماء مثلوج","2 ملعقة كبيرة زيت زيتون بكر ممتاز للتقديم"],"en":["400g (1 can) cooked chickpeas, skins removed","80g tahini (good quality, stirred well)","juice of 2 lemons (about 4 tbsp)","2 garlic cloves, grated","1/2 tsp fine salt","3–5 tbsp ice-cold water","2 tbsp extra-virgin olive oil for finishing"],"ro":["400g năut gătit (1 conservă), coaja îndepărtată","80g pastă de susan (tahini de calitate, bine amestecată)","sucul a 2 lămâi (aprox. 4 linguri)","2 căței de usturoi, rași","1/2 linguriță sare fină","3–5 linguri apă rece cu gheață","2 linguri ulei de măsline extravirgin pentru finalizare"]},"howIsMade":{"ar":"للحصول على أناعم حمص، نزّع قشرة حبات الحمص بالضغط بلطف على كل حبة — خطوة صغيرة تصنع فرقاً كبيراً. في معالج الطعام، اخلط الطحينة وعصير الليمون وحدهما دقيقة كاملة حتى يصبحا فاتح اللون وكريمي القوام. أضف الثوم والملح؛ اخلط 30 ثانية. أضف الحمص ومعالجة دقيقة. مع تشغيل الجهاز، أضف الماء المثلوج ملعقة ملعقة — الماء البارد يهوّي الحمص ويجعله أخف. معالجة 3–5 دقائق كليًا مع كشط الجوانب حتى يصبح ناعماً تماماً. تذوّق واضبط الليمون والملح. افرده في وعاء، رشّ زيت الزيتون وأضف البابريكا أو السماق.","en":"For the smoothest hummus, pop the skins off the chickpeas by gently squeezing each one — a small step that makes a big difference. In a food processor, blitz tahini and lemon juice alone for 1 minute until pale and creamy. Add garlic and salt; blitz 30 seconds. Add the chickpeas and process 1 minute. With the machine running, drizzle in ice-cold water tablespoon by tablespoon — the cold water aerates and lightens the hummus. Process 3–5 minutes total, scraping down the sides, until completely smooth. Taste and adjust lemon and salt. Spread in a bowl, drizzle with olive oil, and finish with smoked paprika or sumac. Keeps refrigerated up to 5 days."},"nutrition":{"cal":220,"prot":8,"carb":22,"fat":12,"fib":6}},{"id":25,"servings":4,"tipType":"def","pairingsType":"veg","origin":{"ar":"لبنان","en":"Lebanon","ro":"Liban"},"name":{"ar":"تبولة","en":"Tabbouleh","ro":"Tabbouleh"},"category":{"ar":"سلطة","en":"Salad","ro":"Salate"},"ingredients":{"ar":["200 غرام بقدونس مسطح، الأوراق فقط، مفرومة ناعماً","50 غرام برغل ناعم، منقوع 20 دقيقة في ماء بارد ثم معصور جيداً","3 طماطم ناضجة (حوالي 300 غرام)، مقطعة مكعبات صغيرة","4 بصل أخضر، مقطع ناعماً","20 غرام أوراق نعناع طازج، مفرومة ناعماً","عصير ليمونتين (حوالي 80 مل)","4 ملاعق كبيرة زيت زيتون بكر ممتاز، ملح وفلفل أسود حسب الذوق"],"en":["200g flat-leaf parsley, leaves only, finely chopped","50g fine bulgur wheat, soaked in cold water 20 min then squeezed dry","3 ripe tomatoes (about 300g), finely diced","4 spring onions, finely sliced","20g fresh mint leaves, finely chopped","juice of 2 lemons (about 80ml)","4 tbsp extra-virgin olive oil, salt and black pepper to taste"],"ro":["200g pătrunjel plat, frunze tocate mărunt","50g bulgur fin, înmuiat 20 min în apă rece, stors bine","3 roșii coapte (cca 300g), tăiate cuburi mici","4 cepe verzi, tocate fin","20g frunze de mentă proaspătă, tocate mărunt","sucul de la 2 lămâi (cca 80ml)","4 linguri ulei de măsline extravirgin, sare și piper negru după gust"]},"howIsMade":{"ar":"انقع البرغل في ماء بارد 20 دقيقة، ثم صفّه واعصره جيداً بيديك — يجب أن يكون جافاً. افرم البقدونس ناعماً قدر الإمكان؛ التبولة الأصيلة سلطة أعشاب، وليست سلطة حبوب. اخلط البقدونس والنعناع والبصل الأخضر والطماطم والبرغل في وعاء كبير. أضف عصير الليمون وزيت الزيتون، اخلط جيداً واترك 10 دقائق ليستريح. اضبط الملح والفلفل. قدّمها في درجة حرارة الغرفة.","en":"Soak the bulgur in cold water for 20 minutes, then drain and squeeze out as much water as possible with your hands — it should be dry, not wet. Chop the parsley as finely as you can; authentic tabbouleh is herb-forward, not grain-forward. Combine parsley, mint, spring onions, tomatoes and squeezed bulgur in a large bowl. Add lemon juice and olive oil, toss well and let rest 10 minutes — the lemon juice continues to soften the bulgur and blooms the herbs. Adjust salt and pepper. Serve at room temperature. True tabbouleh is a parsley salad with bulgur, not a bulgur salad with a little parsley."},"nutrition":{"cal":180,"prot":4,"carb":20,"fat":10,"fib":4}},{"id":26,"servings":4,"tipType":"pasta","pairingsType":"pasta","origin":{"ar":"إيطاليا","en":"Italy","ro":"Italia"},"name":{"ar":"ريزوتو","en":"Risotto","ro":"Risotto"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["320 غ أرز أربوريو أو كارنارولي","1 كراث كبير أو بصلة صغيرة مفرومة ناعماً","50 غ زبدة غير مملحة مقسّمة","100 مل نبيذ أبيض جاف","1,2 لتر مرق دافئ من الدجاج أو الخضار","40 غ جبن بارميجانو ريجانو مبروش طازج","1 ملعقة كبيرة زيت زيتون بكر ممتاز","ملح وفلفل أبيض حسب الرغبة"],"en":["320g Arborio or Carnaroli rice","1 large shallot or small onion, finely diced","50g unsalted butter, divided","100ml dry white wine","1.2L warm chicken or vegetable stock","40g Parmigiano-Reggiano, freshly grated","1 tbsp extra-virgin olive oil","salt and white pepper to taste"],"ro":["320g orez Arborio sau Carnaroli","1 șalotă sau ceapă mică, tocată fin","50g unt nesărat, împărțit","100ml vin alb sec","1,2L supă caldă de pui sau legume","40g Parmigiano-Reggiano, ras proaspăt","1 lingură ulei de măsline extravirgin","sare și piper alb după gust"]},"howIsMade":{"ar":"أبق المرق دافئاً على نار هادئة طوال فترة الطهي — إضافة المرق البارد تقطع الطهي وتدمر القوام الكريمي. سخّن الزيت ونصف الزبدة في مقلاة واسعة ثقيلة على نار متوسطة. حمّر الكراث حتى يلين، 3 دقائق. أضف الأرز وحمّصه مع التحريك دقيقتين حتى تصبح الحبات شفافة قليلاً من الأطراف. صبّ النبيذ وحرّك حتى يُمتص كلياً. أضف المرق الدافئ مغرفة مغرفة، محرّكاً باستمرار ومنتظراً الامتصاص التام قبل كل مغرفة جديدة — هذه الخطوة الأساسية تستغرق 16–18 دقيقة. يجب أن يكون الأرز al dente. أبعد عن النار وأضف الزبدة الباردة المتبقية والجبن بقوة (تسمى هذه mantecatura). ارح دقيقة وقدّم فوراً في أوعية دافئة.","en":"Keep the stock warm over low heat throughout cooking — adding cold stock stops the cooking and ruins the creaminess. Heat oil and half the butter in a wide, heavy pan over medium heat. Sweat the shallot until soft, 3 minutes. Add the rice and toast, stirring, for 2 minutes until grains are slightly translucent at the edges. Pour in the wine and stir until completely absorbed. Add warm stock one ladleful at a time, stirring constantly and waiting for each ladleful to be absorbed before adding the next — this is the essential step and takes 16–18 minutes. The rice should be al dente with a creamy coating. Off the heat, beat in the remaining cold butter and the Parmigiano vigorously — the fat emulsifies into the starches creating a glossy sauce (this is called mantecatura). Rest 1 minute, then serve immediately in warm bowls."}},{"id":27,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ar":"السويد","en":"Sweden","ro":"Suedia"},"name":{"ar":"كرات اللحم السويدية","en":"Swedish Meatballs","ro":"Chifteluțe suedeze"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"ingredients":{"ar":["500 غ لحم مفروم مشترك من الخنزير والبقر (50/50)","1 بصلة متوسطة مبروشة","1 شريحة خبز أبيض بدون قشرة منقوعة في 3 ملاعق كبيرة حليب","1 بيضة كبيرة","ربع ملعقة صغيرة بهار مطحون","ربع ملعقة صغيرة جوز الطيب مبروش طازج","2 ملعقة كبيرة زبدة للقلي","250 مل مرق لحم بقري","150 مل كريمة مزدوجة"],"en":["500g mixed ground pork and beef (50/50)","1 medium onion, grated","1 slice white bread, crusts removed, soaked in 3 tbsp milk","1 large egg","1/4 tsp ground allspice","1/4 tsp freshly grated nutmeg","2 tbsp butter for frying","250ml beef stock","150ml double cream"],"ro":["500g carne tocată amestecată porc și vită (50/50)","1 ceapă medie, rasă","1 felie de pâine albă fără coajă, înmuiată în 3 linguri lapte","1 ou mare","1/4 linguriță ienibahar măcinat","1/4 linguriță nucșoară rasă","2 linguri unt pentru prăjit","250ml supă de vită","150ml smântână pentru frișcă"]},"howIsMade":{"ar":"اعصر الخبز المنقوع للتخلص من الحليب الزائد، ثم اخلطه مع اللحم المفروم والبصل المبروش (معصور)، والبيضة، والبهار، وجوز الطيب، والملح والفلفل. اعجن جيداً لكن لا تفرط — الإفراط يجعل الكرات قاسية. بيدين مبللتين، شكّل كرات بحجم 3سم (20–24 حبة). أذّب الزبدة في مقلاة واسعة على نار متوسطة. اقلِ الكرات على دفعات، مع التدوير برفق لتلتوي جميع الجوانب، 6–8 دقائق لكل دفعة. أخرجها وضعها جانباً. في نفس المقلاة، أضف مرق اللحم مع كشط القاع، واترك يغلي. أضف الكريمة واطبخ 5 دقائق حتى يتكثف قليلاً. أعد الكرات إلى الصوص واطبخ 5 دقائق أخرى على نار خفيفة. قدّم مع مربى التوت البري والبطاطا المسلوقة أو المهروسة والخيار المخلل.","en":"Squeeze the soaked bread to remove excess milk, then mix with the ground meat, grated onion (squeeze out excess liquid), egg, allspice, nutmeg, salt and pepper. Mix well but do not overwork — overworking makes the meatballs tough. With wet hands, roll into balls about 3cm in diameter, yielding about 20–24 meatballs. Melt butter in a wide skillet over medium heat. Fry the meatballs in batches, rolling gently to brown all sides evenly, 6–8 minutes per batch. Remove and set aside. In the same pan, stir in the beef stock, scraping up the fond, and bring to a simmer. Add the cream and simmer 5 minutes until slightly thickened. Return the meatballs to the sauce and cook on low heat 5 more minutes. Serve with lingonberry jam, boiled or mashed potatoes, and pickled cucumber."}},{"id":28,"servings":4,"tipType":"meat","timeMins":{"total":720,"active":75},"pairingsType":"japanese","origin":{"ar":"اليابان","en":"Japan","ro":"Japonia"},"name":{"ar":"رامن ياباني كلاسيكي","en":"Classic Japanese Ramen","ro":"Ramen clasic japonez"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"ingredients":{"ar":["4 حصص من نودلز الرامين الطازجة أو المجففة (نحو 400 غ إجمالاً)","1 لتر مرق دجاج أو عظام خنزير","100 مل صلصة صويا (حسب الرغبة)","2 ملعقة كبيرة ميرين","200 غ بطن خنزير أو كتف مقطّع شرائح رفيعة (تشاشو)","4 بيضات مسلوقة ناعمة منقوعة طوال الليل في صويا وميرين","2 ورقة نوري (أعشاب بحرية مجففة) مقطوعة لنصفين","4 ملاعق كبيرة براعم الخيزران (مينما)","2 بصل أخضر مقطّع شرائح رفيعة","1 ملعقة كبيرة زيت سمسم"],"en":["4 portions fresh or dried ramen noodles (about 400g total)","1L chicken or pork bone broth","100ml soy sauce (or to taste)","2 tbsp mirin","200g pork belly or shoulder, thinly sliced (chashu)","4 soft-boiled eggs (marinated overnight in soy sauce and mirin)","2 sheets nori (dried seaweed), halved","4 tbsp bamboo shoots (menma)","2 spring onions, thinly sliced","1 tbsp sesame oil"],"ro":["4 porții tăiței ramen proaspeți sau uscați (aprox. 400g total)","1L supă de pui sau os de porc","100ml sos de soia (sau după gust)","2 linguri mirin","200g burtă de porc sau pulpă, feliată subțire (chashu)","4 ouă fierte moi (marinate în soia și mirin peste noapte)","2 foi nori (alge uscate), tăiate în jumătate","4 linguri mlădițe de bambus (menma)","2 cepe verzi, feliați subțire","1 lingură ulei de susan"]},"howIsMade":{"ar":"اخلط المرق مع صلصة الصويا والميرين؛ اتركه يغلي 10 دقائق وتذوّق — يجب أن يكون المرق عميق النكهة وخفيف الملوحة مع لمسة حلاوة. بيض الرامين (يفضّل التحضير ليلاً): اسلق البيض 6 دقائق و30 ثانية بالضبط، أدخله فوراً في ماء مثلوج، قشّره وانقعه ليلة كاملة في 3 ملاعق كبيرة صويا، 2 ملعقة كبيرة ميرين، و50 مل ماء. التشاشو: لفّ بطن الخنزير باحكام، ربطه بخيط ومطبخه في صويا وميرين وساكي وسكر على نار هادئة ساعتين. شرّحه بعد التبريد. اسلق النودلز وفق التعليمات (عادةً 2–3 دقائق)، صفّها في أوعية دافئة. صبّ المرق الساخن فوقها. ضع 2–3 شرائح تشاشو، بيضة رامين مقطوعة للنصف، قطعة نوري واقفة، براعم خيزران، بصلاً أخضر وقطرة زيت سمسم. قدّم فوراً.","en":"Combine the broth with soy sauce and mirin; simmer 10 minutes and taste — the broth should be deeply savoury, slightly salty, with a hint of sweetness. Ramen eggs (best made the night before): boil eggs for exactly 6 minutes 30 seconds, shock in ice water, peel, and marinate overnight in 3 tbsp soy sauce, 2 tbsp mirin, and 50ml water. Chashu pork: roll pork belly tightly, tie with kitchen string, and braise in soy sauce, mirin, sake, and sugar over a gentle simmer for 2 hours until tender. Slice when cool. Cook noodles per package directions (usually 2–3 minutes), drain, and portion into warmed bowls. Ladle hot broth over. Top with 2–3 slices of chashu pork, a halved ramen egg, a piece of nori standing upright, bamboo shoots, spring onions, and a drop of sesame oil. Serve immediately."}},{"id":29,"servings":4,"tipType":"meat","pairingsType":"latin","origin":{"ar":"الأرجنتين","en":"Argentina","ro":"Argentina"},"name":{"ar":"إمباناداس","en":"Empanadas","ro":"Empanadas"},"category":{"ar":"وجبة خفيفة","en":"Snack","ro":"Gustare"},"ingredients":{"ar":["400 غرام دقيق أبيض","100 غرام شحم الخنزير أو زبدة باردة مقطعة","150 مل ماء دافئ","1 ملعقة صغيرة ملح","300 غرام لحم بقري مفروم","1 بصلة متوسطة مفرومة ناعماً","2 بيضة مسلوقة مفرومة","12 زيتونة خضراء منزوعة النواة ومقطعة","1 ملعقة صغيرة كمون مطحون","1 ملعقة صغيرة فلفل حلو"],"en":["400g plain flour","100g lard or cold butter, diced","150ml warm water","1 tsp salt","300g ground beef","1 medium onion, finely chopped","2 hard-boiled eggs, chopped","12 green olives, pitted and sliced","1 tsp ground cumin","1 tsp sweet paprika"],"ro":["400g făină albă","100g untură sau unt rece, cuburi","150ml apă caldă","1 linguriță sare","300g carne de vită tocată","1 ceapă medie, tocată fin","2 ouă fierte tari, tăiate","12 măsline verzi, fără sâmburi și tăiate","1 linguriță chimen măcinat","1 linguriță boia dulce"]},"howIsMade":{"ar":"تحضير العجين: اخلط الدقيق والملح، افرك الشحم أو الزبدة الباردة بأطراف الأصابع حتى تتكون فتات، ثم أضف الماء الدافئ تدريجياً واعجن 5 دقائق حتى تصبح عجيناً ناعماً ومرناً. غلف واترك ليرتاح 30 دقيقة. للحشوة، قلي البصل 8 دقائق، أضف اللحم المفروم واطبخ 10 دقائق على نار متوسطة مع التفتيت الجيد. تبّل بالكمون والفلفل الحلو والملح والفلفل. اترك يبرد تماماً ثم أضف البيض المفروم والزيتون. افرد العجين بسماكة 3مم وقطّع دوائر 12 سم. ضع ملعقة كبيرة من الحشوة في المنتصف، برطب الحواف، أطوِ على شكل هلال واختم بحافة ملتوية. اخبز على 200 درجة مئوية 20-25 دقيقة حتى يتحول للذهبي، أو اقلي في زيت ساخن 180 درجة 3-4 دقائق من كل جانب.","en":"Make the dough: combine flour and salt, rub in the lard or cold butter with your fingertips until the mixture resembles breadcrumbs, then add warm water gradually and knead 5 minutes to a smooth, elastic dough. Wrap and rest 30 minutes. For the filling, saute onion in a little oil for 8 minutes, add ground beef and cook 10 minutes over medium heat, breaking it up well. Season with cumin, paprika, salt and pepper. Cool completely, then fold in the chopped boiled eggs and olives. Roll dough to 3mm thick and cut 12cm circles. Place a tablespoon of filling in the centre, moisten the edges, fold into a half-moon and seal with a twisted rope border (repulge). Bake at 200 degrees C for 20-25 minutes until golden, or deep-fry at 180 degrees C for 3-4 minutes per side."}},{"id":30,"servings":4,"tipType":"def","pairingsType":"mediterranean","origin":{"ar":"اليونان","en":"Greece","ro":"Grecia"},"name":{"ar":"تزاتزيكي","en":"Tzatziki","ro":"Tzatziki"},"category":{"ar":"وجبة خفيفة","en":"Snack","ro":"Gustare"},"ingredients":{"ar":["500 غرام زبادي يوناني كامل الدسم (مصفى طوال الليل إن أمكن)","1 خيارة كبيرة (حوالي 300 غرام)، مبشورة ومعصورة جيداً","2 فص ثوم مبشور ناعماً","2 ملعقة كبيرة زيت زيتون بكر ممتاز، وقليل للتقديم","1 ملعقة كبيرة شبت طازج مفروم ناعماً","عصير نصف ليمونة","ملح ناعم حسب الذوق"],"en":["500g full-fat Greek yogurt (strained overnight if possible)","1 large cucumber (about 300g), grated and well squeezed","2 garlic cloves, finely grated","2 tbsp extra-virgin olive oil, plus a drizzle to serve","1 tbsp fresh dill, finely chopped","juice of half a lemon","fine sea salt to taste"],"ro":["500g iaurt grecesc integral (scurs peste noapte dacă e posibil)","1 castravete mare (cca 300g), ras și bine stors","2 căței de usturoi, rași fin","2 linguri ulei de măsline extravirgin, plus un pic pentru servit","1 lingură mărar proaspăt, tocat mărunt","sucul de la jumătate de lămâie","sare fină după gust"]},"howIsMade":{"ar":"أهم خطوة: ابشر الخيار واضعه في منشفة نظيفة أو مصفاة. رشّ قليلاً من الملح واترك 10 دقائق ثم اعصره بقوة — سيفقد الخيار تقريباً نصف وزنه ماءً. الرطوبة الزائدة هي ما يجعل التزاتزيكي مائياً. اخلط الزبادي مع الخيار المعصور جيداً والثوم المبشور وزيت الزيتون وعصير الليمون والشبت. اضبط الملح. غطِّ وضع في الثلاجة 30 دقيقة على الأقل. قدّمه مع رذاذ زيت الزيتون والشبت الطازج مع خبز البيتا الدافئ.","en":"The most important step: grate the cucumber on the coarse side of a box grater and place in a clean tea towel or colander. Sprinkle with a little salt, leave 10 minutes, then squeeze out hard — the cucumber will shed almost half its weight in water. Excess moisture is what makes tzatziki watery and weak. Combine the yogurt with the well-squeezed cucumber, grated garlic, olive oil, lemon juice and dill. Taste and adjust salt. Cover and refrigerate at least 30 minutes before serving — the flavours deepen as it rests. Serve drizzled with olive oil and a few fresh dill sprigs, alongside warm pita bread or souvlaki."}},{"id":31,"servings":4,"tipType":"soup","pairingsType":"french","origin":{"ar":"فرنسا","en":"France","ro":"Franța"},"name":{"ar":"حساء البصل الفرنسي","en":"French Onion Soup","ro":"Supă de ceapă franțuzească"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"ingredients":{"ar":["1 كغم بصل أصفر مقطع شرائح رفيعة","60 غرام زبدة غير مملحة","1 ملعقة كبيرة دقيق","200 مل نبيذ أبيض جاف","1.2 لتر مرق لحم بقري جيد","4 شرائح سميكة من الباجيت محمصة","150 غرام جبن غرويير مبشور","ملح وفلفل أسود وأغصان زعتر طازج"],"en":["1kg yellow onions, thinly sliced","60g unsalted butter","1 tbsp plain flour","200ml dry white wine","1.2 litres good beef stock","4 thick slices baguette, toasted","150g Gruyere, grated","salt, black pepper and fresh thyme sprigs"],"ro":["1kg ceapă galbenă, tăiată julienne","60g unt nesărat","1 lingură făină","200ml vin alb sec","1,2 litri supă bună de vită","4 felii groase de baghetă, prăjite","150g Gruyère, ras","sare, piper negru și crenguțe de cimbru proaspăt"]},"howIsMade":{"ar":"أذب الزبدة في قدر سميك القاع على نار منخفضة متوسطة. أضف البصل مع رشة ملح واطبخ 45-60 دقيقة مع التحريك كل 5 دقائق — الصبر هو السر هنا. يجب أن يتحول البصل للون الكراميل. أضف الزعتر والدقيق وحرّك دقيقة. صب النبيذ واتركه يفور 3 دقائق. أضف المرق وأوصله للغليان الخفيف واطبخ 20 دقيقة. اضبط الملح والفلفل. صب في أطباق تحتمل الفرن، ضع شريحة باجيت محمصة في كل طبق، غطها بالجبن واشوِ 3-4 دقائق حتى يفور الجبن ويتحول للذهبي. قدّم فوراً.","en":"Melt the butter in a heavy-bottomed pot over medium-low heat. Add the onions with a pinch of salt and cook for 45-60 minutes, stirring every 5 minutes — patience is everything here. The onions must turn the colour of caramel, not burnt. Add a splash of water whenever they stick. Add the thyme and flour, stir for 1 minute. Pour in the wine and let it bubble for 3 minutes. Add the beef stock, bring to a simmer and cook 20 minutes. Taste and adjust salt and pepper. Ladle into oven-safe bowls, float a slice of toasted baguette in each, pile on the Gruyere and grill (broil) for 3-4 minutes until the cheese is bubbling and golden brown. Serve immediately — the cheese will set as it cools."}},{"id":32,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ar":"المجر","en":"Hungary","ro":"Ungaria"},"name":{"ar":"جولاش","en":"Goulash","ro":"Gulaș"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["700 غرام كتف بقري أو ساق مقطعة مكعبات 3 سم","400 غرام بطاطس شمعية مقشورة ومقطعة","2 بصلة كبيرة مفرومة ناعماً","2 فليفلة حمراء مقطعة مكعبات","3 ملاعق كبيرة بابريكا حلوة مجرية","400 غرام طماطم مقطعة معلبة","1 لتر مرق لحم بقري","3 ملاعق كبيرة شحم الخنزير أو زيت نباتي","2 ملعقة صغيرة بذور كراوية، ملح وفلفل أسود حسب الذوق"],"en":["700g beef chuck or shin, cut into 3cm cubes","400g waxy potatoes, peeled and diced","2 large onions, finely chopped","2 red bell peppers, diced","3 tbsp sweet Hungarian paprika","400g canned chopped tomatoes","1 litre beef stock","3 tbsp lard or vegetable oil","2 tsp caraway seeds, salt and black pepper to taste"],"ro":["700g carne de vită (spată sau greabăn), cuburi de 3 cm","400g cartofi cerosi, curățați și tăiați cuburi","2 cepe mari, tocate mărunt","2 ardei grași roșii, tăiați cuburi","3 linguri boia ungurească dulce","400g roșii tocate la conservă","1 litru supă de vită","3 linguri untură sau ulei vegetal","2 linguriță semințe de chimen, sare și piper negru după gust"]},"howIsMade":{"ar":"جفف مكعبات اللحم وتبّلها. سخن الشحم في قدر ثقيل على نار عالية وحمّر اللحم على دفعات — لا تحرك كثيراً لتتكون قشرة، وليس لحماً مطبوخاً بالبخار. أزل اللحم وضعه جانباً. خفف النار للمتوسطة وقلّي البصل 10 دقائق. أضف البابريكا وحرّك دقيقة — لا تحرقها وإلا ستصبح مرة. أضف الفليفلة والطماطم والكراوية والمرق. أعد اللحم وأوصله للغليان ثم غطّ واطبخ على نار هادئة 60-75 دقيقة. أضف البطاطس واطبخ 25 دقيقة أخرى. اضبط الملح. قدّمها في أطباق عميقة مع خبز مقرمش.","en":"Pat the beef cubes dry and season with salt and pepper. Heat the lard or oil in a heavy pot over high heat and brown the meat in batches — do not stir too much; you want a crust, not steamed meat. Remove and set aside. Reduce heat to medium, add the onions and cook 10 minutes. Add the paprika and stir for 1 minute — do not let it burn or it turns bitter. Add the peppers, tomatoes, caraway seeds and beef stock. Return the beef, bring to a boil, cover and simmer on low heat for 60-75 minutes. Add the potatoes and simmer 25 more minutes until tender and the beef flakes easily under pressure. Taste and adjust salt. Serve in deep bowls with crusty bread to mop up the rich broth."}},{"id":33,"servings":4,"tipType":"def","pairingsType":"middle-eastern","origin":{"ar":"مصر","en":"Egypt","ro":"Egipt"},"name":{"ar":"كشري","en":"Koshari","ro":"Koshari"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"ingredients":{"ar":["200 غرام أرز طويل الحبة","200 غرام عدس أخضر","150 غرام مكرونة صغيرة (شعيرية أو دقة)","400 غرام حمص معلب مصفى","800 غرام طماطم مهروسة معلبة","3 بصلات كبيرة (2 للصلصة، 1 للتبسيل المقرمش)","4 ملاعق كبيرة زيت نباتي","3 فصوص ثوم مفرومة، ملح وكمون وخل حسب الذوق"],"en":["200g long-grain white rice","200g green lentils","150g small macaroni or ditalini","400g canned chickpeas, drained","800g canned crushed tomatoes","3 large onions (2 for sauce, 1 for crispy topping)","4 tbsp vegetable oil","3 garlic cloves, minced, salt, cumin and vinegar to taste"],"ro":["200g orez cu bob lung","200g linte verde","150g macaroane mici sau ditalini","400g năut la conservă, scurs","800g roșii tocate la conservă","3 cepe mari (2 pentru sos, 1 pentru topping crocant)","4 linguri ulei vegetal","3 căței de usturoi, tocați, sare, chimen și oțet după gust"]},"howIsMade":{"ar":"اسلق العدس في ماء بدون ملح 20 دقيقة حتى يكون متماسكاً وصفّه. اسلق الأرز بالماء المملح 15 دقيقة. اسلق المكرونة حتى تكون متماسكة وصفّها. قطّع البصلة الثالثة حلقات رفيعة وقلّيها في الزيت على نار عالية 15-20 دقيقة مع التحريك المتكرر حتى تصبح ذهبية مقرمشة. صفّها على ورق مطبخ. في نفس الزيت، قلّي البصل المفروم المتبقي 10 دقائق، أضف الثوم والكمون والطماطم المعلبة ورشة خل وملح. اطبخ الصلصة 20-25 دقيقة حتى تتكثف. أضف الحمص 5 دقائق. اخلط العدس مع الأرز. قدّم في طبقات مع الحلقات المقرمشة فوقها.","en":"Cook the lentils in unsalted water for 20 minutes until al dente, then drain. Cook the rice in salted water for 15 minutes. Cook the pasta al dente and drain. Slice the third onion into thin rings and fry in oil over medium-high heat for 15-20 minutes, stirring often, until deep golden brown and crispy — this is the prized topping. Drain on paper towels. In the same oil, saute the remaining chopped onions 10 minutes, add garlic, cumin, canned tomatoes, a splash of vinegar and salt. Simmer the sauce 20-25 minutes until thick. Add the chickpeas and simmer 5 more minutes. Mix lentils into the rice. To serve, layer rice-lentil mixture, pasta, tomato-chickpea sauce, and top with the crispy onion rings. Koshari is eaten at room temperature."}},{"id":35,"servings":8,"tipType":"dessert","pairingsType":"dessert","origin":{"ar":"تركيا","en":"Turkey","ro":"Turcia"},"name":{"ar":"بقلاوة","en":"Baklava","ro":"Baklava"},"category":{"ar":"تحلية","en":"Dessert","ro":"Desert"},"ingredients":{"ar":["500 غرام أوراق عجينة فيلو مذابة","200 غرام زبدة غير مملحة مذابة","200 غرام جوز مفروم ناعماً","100 غرام فستق مفروم ناعماً","1 ملعقة صغيرة قرفة مطحونة","300 غرام سكر","200 مل ماء","2 ملعقة كبيرة عسل مع 1 ملعقة كبيرة عصير ليمون"],"en":["500g phyllo pastry sheets, thawed","200g unsalted butter, melted","200g walnuts, finely chopped","100g pistachios, finely chopped","1 tsp ground cinnamon","300g sugar","200ml water","2 tbsp honey plus 1 tbsp lemon juice"],"ro":["500g foi de plăcintă (phyllo), dezghețate","200g unt nesărat, topit","200g nuci, tocate mărunt","100g fistic, tocat mărunt","1 linguriță scorțișoară măcinată","300g zahăr","200ml apă","2 linguri miere plus 1 lingură suc de lămâie"]},"howIsMade":{"ar":"حضّر الشراب أولاً: أذب السكر في الماء، غلّه 5 دقائق، أضف العسل وعصير الليمون واغله 5 دقائق أخرى; دعه يبرد تماماً — يجب أن يكون الشراب بارداً حين يُسكب على البقلاوة الساخنة. اخلط الجوز مع الفستق والقرفة; ادهن صينية 33x23 سم بالزبدة. ضع 8 أوراق فيلو مع دهن كل ورقة بالزبدة; رشّ طبقة سخية من الجوز. غطِّ بـ4 أوراق مدهونة ثم طبقة أخرى; كرّر حتى تنتهي المكسرات وأنهِ بـ8 أوراق. قطّع إلى معينات قبل الخبز; اخبز على 160 درجة 45-50 دقيقة حتى يصبح ذهبياً. حال خروجه من الفرن صب الشراب البارد; اترك 2-3 ساعات قبل التقديم.","en":"Make the syrup first: dissolve sugar in water, boil 5 minutes, add honey and lemon juice, boil 5 more minutes; leave to cool completely — the syrup must be cold when poured over hot baklava. Mix the walnuts with pistachios and cinnamon; grease a 33x23cm baking tray with melted butter. Layer 8 phyllo sheets, brushing each with butter; scatter a generous layer of nut mixture. Cover with 4 buttered phyllo sheets, then another nut layer; repeat until the nuts are used up, finishing with 8 buttered phyllo sheets. Cut into diamonds or squares before baking; bake at 160 degrees C for 45-50 minutes until pale golden. The moment it comes out of the oven, pour the cold syrup all over — the temperature contrast helps the baklava absorb every drop; leave to rest 2-3 hours before serving."}},{"id":36,"servings":4,"tipType":"meat","pairingsType":"mexican","origin":{"ar":"المكسيك","en":"Mexico","ro":"Mexic"},"name":{"ar":"تشيلي كون كارني","en":"Chili con carne","ro":"Chili con carne"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["500 غرام لحم بقري مفروم (دهون لا تقل عن 20%)","400 غرام فاصولياء حمراء معلبة مصفاة","400 غرام طماطم مقطعة معلبة","2 بصلة كبيرة مقطعة","3 فصوص ثوم مفروم","2 ملعقة كبيرة معجون شيبوتلي أو 2 فلفل شيبوتلي مجفف","1 ملعقة كبيرة كمون مطحون و1 ملعقة كبيرة بابريكا مدخنة","2 ملعقة كبيرة زيت نباتي","ملح وفلفل أسود"],"en":["500g beef mince (min. 20% fat)","400g canned red kidney beans, drained","400g canned chopped tomatoes","2 large onions, chopped","3 garlic cloves, minced","2 tbsp chipotle paste or 2 dried chipotle chillies, rehydrated","1 tbsp ground cumin and 1 tbsp smoked paprika","2 tbsp vegetable oil","salt and black pepper"],"ro":["500g carne de vită tocată (min. 20% grăsime)","400g fasole roșie kidney la conservă, scursă","400g roșii tocate la conservă","2 cepe mari, tocate","3 căței de usturoi, tocați","2 linguri pastă de chipotle sau 2 ardei iuți uscați","1 lingură chimen măcinat și 1 lingură boia afumată","2 linguri ulei vegetal","sare și piper negru"]},"howIsMade":{"ar":"سخّن الزيت في قدر كبير على نار عالية. حمّر اللحم المفروم على دفعتين مع التفتيت الجيد — تريد قطعاً صغيرة مكرملة لا كتلة رمادية. أزل اللحم وفي نفس الزيت قلّي البصل 8 دقائق. أضف الثوم والكمون والبابريكا المدخنة وحرّك دقيقة. أضف معجون الشيبوتلي والطماطم والفاصولياء واللحم و200 مل ماء. أوصله للغليان ثم خفف النار وغطّ جزئياً واطبخ 45-60 دقيقة. إن كان سائلاً جداً أزل الغطاء الـ15 دقيقة الأخيرة. اضبط الملح. قدّمه بالكريمة الحامضة والجبن المبشور والهالابينيو والكزبرة الطازجة.","en":"Heat the oil in a large pot over high heat. Brown the mince in two batches, breaking it up well — you want small caramelised pieces, not a grey steamed mass. Remove the meat and in the same oil, saute the onion for 8 minutes. Add garlic, cumin and smoked paprika, stir for 1 minute. Add chipotle paste, canned tomatoes, drained beans, the browned meat and 200ml water. Bring to a boil, reduce to low, partially cover and simmer 45-60 minutes, stirring occasionally. Chili should be thick, not watery — uncover for the last 15 minutes if too thin. Taste and adjust salt. Serve in bowls with sour cream, grated cheddar, sliced jalapeños, fresh coriander and tortilla chips."}},{"id":37,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ar":"الصين","en":"China","ro":"China"},"name":{"ar":"دجاج حلو وحامض","en":"Sweet and Sour Chicken","ro":"Pui dulce-acrișor"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["500 غرام صدر دجاج مقطع 3 سم","1 ملعقة كبيرة نشا ذرة للتغليف","200 غرام قطع اناناس معلب مع حفظ العصير","1 فليفلة حمراء و1 خضراء مقطعة مكعبات","1 بصلة صغيرة مقطعة مكعبات","3 ملاعق كبيرة خل الارز","2 ملعقة كبيرة سكر و2 صلصة صويا و1 كاتشب","2 ملعقة كبيرة زيت نباتي و1 ملعقة صغيرة زيت سمسم"],"en":["500g chicken breast, cut into 3cm pieces","1 tbsp cornstarch (for coating)","200g canned pineapple chunks, juice reserved","1 red and 1 green bell pepper, diced","1 small onion, diced","3 tbsp rice vinegar","2 tbsp sugar, 2 tbsp soy sauce, 1 tbsp ketchup","2 tbsp vegetable oil plus 1 tsp sesame oil"],"ro":["500g piept de pui, tăiat cuburi de 3 cm","1 lingură amidon de porumb (pentru acoperire)","200g bucăți de ananas la conservă, sucul rezervat","1 ardei roșu și 1 ardei verde, tăiați cuburi","1 ceapă mică, tăiată cuburi","3 linguri oțet de orez","2 linguri zahăr, 2 linguri sos de soia, 1 lingură ketchup","2 linguri ulei vegetal plus 1 linguriță ulei de susan"]},"howIsMade":{"ar":"حضّر الصلصة اولاً: اخلط خل الارز والسكر وصلصة الصويا والكاتشب و3 ملاعق من عصير الاناناس. قلّب قطع الدجاج في النشا ونفض الزائد. سخّن الزيت في المقلاة الصينية على نار عالية. اقلي الدجاج على دفعات 4-5 دقائق حتى يصبح مقرمشاً ذهبياً. ضعه جانباً. في نفس المقلاة اضف قليل زيت وقلّي البصل دقيقتين، اضف الفليفلة وقلّي دقيقتين على نار عالية. اضف الاناناس والصلصة واتركها تغلي 1-2 دقيقة حتى تتكثف وتلمع. اعد الدجاج وقلّب الكل. اضف زيت السمسم. قدّم فوراً مع الارز المطبوخ بالبخار.","en":"Make the sauce first: mix rice vinegar, sugar, soy sauce, ketchup and 3 tbsp of the pineapple juice. Toss the chicken pieces in cornstarch and shake off excess. Heat vegetable oil in a wok or large skillet over high heat. Fry the chicken in batches for 4-5 minutes until crisp and golden — do not crowd the pan. Set aside. In the same wok, add a little more oil and stir-fry the onion 2 minutes, add the peppers and cook 2 more minutes on high — they should stay crisp. Add the pineapple, pour in the sauce and bubble for 1-2 minutes until thick and glossy. Return the chicken and toss everything together. Finish with sesame oil. Serve immediately over steamed rice."}},{"id":38,"servings":8,"tipType":"dessert","pairingsType":"dessert","origin":{"ar":"أستراليا","en":"Australia","ro":"Australia"},"name":{"ar":"بافلوفا","en":"Pavlova","ro":"Pavlova"},"category":{"ar":"تحلية","en":"Dessert","ro":"Desert"},"ingredients":{"ar":["4 بياض بيضة كبيرة، بدرجة حرارة الغرفة","220 غ سكر ناعم","2 ملعقة صغيرة نشا الذرة","1 ملعقة صغيرة خل النبيذ الابيض","1 ملعقة صغيرة مستخلص الفانيليا","300 مل كريمة للخفق (35% دهون)","200 غ فراولة طازجة مشرحة","2 فاكهة الباشن، اللب"],"en":["4 large egg whites, room temperature","220g caster sugar","2 tsp cornstarch","1 tsp white wine vinegar","1 tsp vanilla extract","300ml double cream, for whipping","200g fresh strawberries, sliced","2 passion fruits, pulp scooped"],"ro":["4 albușuri mari, la temperatura camerei","220g zahăr fin (caster sugar)","2 lingurițe amidon de porumb","1 linguriță oțet de vin alb","1 linguriță extract de vanilie","300ml smântână pentru frișcă (min. 35% grăsime)","200g căpșuni proaspete, feliate","2 fructe ale pasiunii, pulpă"]},"howIsMade":{"ar":"سخن الفرن على 120 درجة مئوية وارسم دائرة قطرها 22 سم على ورق الخبز. اخفق بياض البيض مع رشة ملح حتى تتشكل قمم ناعمة. اضف السكر ملعقة ملعقة مع الخفق الجيد — يستغرق 8-10 دقائق حتى يصبح المرينغ لامعا وصلبا بلا حبيبات سكر. اضف النشا والخل والفانيليا بلطف بملعقة مطاط. ضع المرينغ على الدائرة مع رفع الحواف قليلا. اخبز 90 دقيقة حتى تجف القشرة وتصبح كريمية اللون. اطفئ الفرن واترك البافلوفا لتبرد داخله مع فتح الباب قليلا لمدة ساعتين على الاقل. قبل التقديم اخفق الكريمة وانشرها فوق المرينغ وزين بالفراولة ولب الباشن.","en":"Preheat oven to 120°C and trace a 22cm circle on baking paper. Whisk egg whites with a pinch of salt to soft peaks. Add caster sugar one tablespoon at a time, whisking well after each addition — takes 8-10 minutes until the meringue is glossy, stiff, and has no sugar grains when rubbed between fingers. Fold in cornstarch, vinegar, and vanilla with a spatula. Mound the meringue onto the paper circle, building the sides slightly higher than the centre. Bake 90 minutes — the shell should be dry and faintly cream-coloured. Turn off oven and leave the pavlova to cool completely inside with the door ajar, at least 2 hours. Just before serving, whip cream to soft peaks and spread over the meringue. Top with strawberries and passion fruit pulp."}},{"id":39,"servings":4,"tipType":"def","pairingsType":"def","origin":{"ar":"كندا","en":"Canada","ro":"Canada"},"name":{"ar":"بوتين","en":"Poutine","ro":"Poutine"},"category":{"ar":"وجبة خفيفة","en":"Snack","ro":"Gustare"},"ingredients":{"ar":["800 غ بطاطا راسيت او مشابهة، مقشرة","150 غ جبن كيرد طازج، بدرجة حرارة الغرفة","2 ملعقة كبيرة زبدة غير مملحة","2 ملعقة كبيرة دقيق","500 مل مرقة لحم بقري ساخنة","1 ملعقة صغيرة صلصة وورشيستر","زيت نباتي للقلي","ملح وفلفل اسود"],"en":["800g Russet or Maris Piper potatoes, peeled","150g fresh cheese curds, room temperature","2 tbsp unsalted butter","2 tbsp plain flour","500ml beef stock, hot","1 tsp Worcestershire sauce","vegetable oil for frying","salt and black pepper"],"ro":["800g cartofi Russet sau Desiree, curatati","150g cas proaspat (cheese curds), la temperatura camerei","2 linguri unt nesarat","2 linguri făină alba","500ml supa de vita, fierbinte","1 lingurita sos Worcestershire","ulei vegetal pentru prajit","sare si piper negru"]},"howIsMade":{"ar":"قطع البطاطا الى عصي بسمك 1 سم وانقعها في ماء بارد 30 دقيقة لازالة النشا — هذا يجعلها مقرمشة. جففها جيدا. القلي الاول: سخن الزيت الى 150 درجة وقلي 5-6 دقائق حتى تنضج بدون لون. صفي واتركيها ترتاح 10 دقائق. القلي الثاني: سخن الى 190 درجة وقلي 3-4 دقائق حتى تصبح ذهبية ومقرمشة جدا. تبل فورا بالملح. للصلصة: اذب الزبدة على نار متوسطة، اضف الدقيق واطبخ دقيقتين مع التحريك. اضف المرقة الساخنة تدريجيا مع الخفق حتى تتكثف 3-4 دقائق. اضف الوورشيستر وتبل. ضع البطاطا الساخنة في وعاء عميق، انثر الجبن بدرجة حرارة الغرفة فوقها وصب الصلصة الساخنة فورا.","en":"Cut potatoes into 1cm batons and soak in cold water for 30 minutes to remove starch — this is what makes them crispy. Dry thoroughly. First fry: heat oil to 150°C and fry potatoes 5-6 minutes until cooked through but without colour. Drain and rest 10 minutes. Second fry: heat oil to 190°C and fry 3-4 minutes until golden and very crispy. Season immediately with salt. For the gravy: melt butter over medium heat, add flour and cook 2 minutes stirring — it should turn pale golden. Add hot stock gradually, whisking constantly until thickened, 3-4 minutes. Add Worcestershire, season. Pile hot fries into a deep bowl, scatter room-temperature cheese curds over, and immediately pour the hot gravy on top — the heat partially melts the curds while keeping their signature squeak."}},{"id":40,"servings":4,"tipType":"def","pairingsType":"def","origin":{"ar":"بولندا","en":"Poland","ro":"Polonia"},"name":{"ar":"بيروجي","en":"Pierogi","ro":"Pierogi"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cina"},"ingredients":{"ar":["300 غ دقيق ابيض بالاضافة للرش","1 بيضة كبيرة و150 مل ماء دافئ (للعجينة)","500 غ بطاطا دقيقة مسلوقة ومهروسة","200 غ جبن طازج (تواروغ) او قريش جاف","2 بصلة متوسطة مفرومة ناعما","40 غ زبدة بلا ملح","100 غ قطع بيكون مدخن","ملح وفلفل ابيض وبصل اخضر طازج للتقديم"],"en":["300g plain flour, plus extra for dusting","1 large egg plus 150ml warm water (for dough)","500g floury potatoes, boiled and mashed","200g farmer's cheese (twarog) or dry cottage cheese","2 medium onions, finely diced","40g unsalted butter","100g smoked bacon lardons","salt, white pepper and fresh chives to serve"],"ro":["300g făină alba, plus extra pentru intins","1 ou mare plus 150ml apa calda (pentru aluat)","500g cartofi fainosi, fierti si zdrobiti","200g branza de vaci (twarog) sau branza proaspata","2 cepe medii, taiate marunt","40g unt nesarat","100g bacon afumat, taiat cubulete","sare, piper alb si ceapa verde proaspata pentru servit"]},"howIsMade":{"ar":"اخلط الدقيق مع البيضة والماء الدافئ، اعجن 5 دقائق حتى تحصل على عجينة ناعمة ومرنة، غطها واتركها ترتاح 30 دقيقة. اسلق البطاطا حتى تطرى ثم اهرسها مع الجبن والملح والفلفل الابيض. في مقلاة، قلي نصف البصل في الزبدة حتى يذهب (10 دقائق)، اضفه للحشوة. افرد العجينة لسمك 3 ملم، قطع دوائر قطرها 8 سم. ضع ملعقة صغيرة من الحشوة على كل دائرة، اطوها واضغط الحواف باحكام. اسلق في ماء مملح 3-4 دقائق حتى تطفو. في هذا الوقت قلي البيكون حتى يقرمش واضف باقي البصل. قلي البيروجي المسلوق في الزبدة 2-3 دقائق من كل جهة. قدمه مع البيكون والبصل والقشطة الحامضة.","en":"Mix flour with egg and warm water, knead 5 minutes to a smooth, elastic dough, cover and rest 30 minutes. Boil potatoes until tender, mash with farmer's cheese, salt and white pepper. In a pan, fry half the onion in butter until golden (10 min), stir into filling. Roll dough to 3mm, cut 8cm circles. Place a teaspoon of filling on each disc, fold in half and seal the edges firmly by pressing with fingers or a fork. Boil in salted water 3-4 minutes — they float when done. Meanwhile, fry bacon until crisp, add remaining onion and brown. Pan-fry the boiled pierogi in butter 2-3 minutes per side until golden patches appear. Serve with bacon, fried onion and sour cream."}},{"id":41,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ar":"إندونيسيا","en":"Indonesia","ro":"Indonezia"},"name":{"ar":"ناسي جورينج","en":"Nasi Goreng","ro":"Nasi Goreng"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["4 أكواب من أرز الياسمين المطبوخ من اليوم السابق","300 غ من فخذة الدجاج منزوعة العظم، مقطعة إلى مكعبات بحجم 1 سم","4 بيضات","4 كراث، مقطعة شرائح رفيعة","4 فصوص ثوم، مفروم","2 فلفل أحمر حار صغير، مقطع شرائح رفيعة","2 ملعقة كبيرة كيجاب مانيس (صلصة صويا حلوة)","1 ملعقة كبيرة صلصة صويا","1 ملعقة صغيرة معجون الجمبري (تيراسي)، محمص","3 ملاعق كبيرة زيت نباتي","ملح وفلفل أبيض حسب الذوق","شرائح خيار وكراث مقلي للتقديم"],"en":["4 cups day-old cooked jasmine rice","300 g boneless chicken thigh, cut into 1 cm cubes","4 eggs","4 shallots, thinly sliced","4 garlic cloves, minced","2 red bird's eye chillies, thinly sliced","2 tbsp kecap manis (sweet soy sauce)","1 tbsp soy sauce","1 tsp shrimp paste (terasi), toasted","3 tbsp vegetable oil","salt and white pepper to taste","cucumber slices and fried shallots to serve"],"ro":["4 căni orez jasmin fiert în ziua precedentă","300 g pulpă de pui dezosată, tăiată cubulețe de 1 cm","4 ouă","4 eșalote, feliate subțire","4 căței de usturoi, tocați","2 ardei iuți roșii, feliați subțire","2 linguri kecap manis (sos de soia dulce)","1 lingură sos de soia","1 linguriță pastă de creveți (terasi), prăjită","3 linguri ulei vegetal","sare și piper alb după gust","felii de castravete și eșalote prăjite pentru servire"]},"howIsMade":{"ar":"فتّت الأرز البارد بيديك لفصل الكتل. سخّن ملعقة كبيرة من الزيت في مقلاة الووك على حرارة عالية حتى يدخن. أضف الدجاج واقلِه 3–4 دقائق حتى ينضج ويصبح ذهبياً؛ ارفعه وضعه جانباً. أضف ملعقتين الزيت المتبقيتين. أضف الكراث واقلِه دقيقتين حتى يطرأ. أضف الثوم والفلفل الحار ومعجون الجمبري واقلِه دقيقة واحدة حتى يفوح الأريج. أضف الأرز وافرده في طبقة منتظمة واتركه دقيقة دون تحريك ليتكوّن قليل من القشرة، ثم اقلبه بقوة 2–3 دقائق. أعد الدجاج إلى الووك وأضف الكيجاب مانيس وصلصة الصويا وقلّب ليتغطى الكل. أضف الملح والفلفل الأبيض. ادفع الأرز جانباً واكسر البيض في الووك وقلّبه قليلاً ثم ادمجه مع الأرز واطهه دقيقة حتى ينعقد. قدّم في أطباق مع شرائح الخيار والكراث المقلي.","en":"Break up the cold rice with your hands to separate any clumps. Heat 1 tbsp of oil in a wok over high heat until smoking. Add the chicken cubes and stir-fry for 3–4 minutes until cooked through and lightly golden; remove and set aside. Add the remaining 2 tbsp of oil to the wok. Add the shallots and stir-fry for 2 minutes until softened. Add the garlic, chilli, and shrimp paste and stir-fry for 1 minute until fragrant. Add the rice, spread into an even layer, and leave untouched for 1 minute to form a slight crust, then toss vigorously for 2–3 minutes. Return the chicken, add the kecap manis and soy sauce, and toss to coat evenly. Season with salt and white pepper. Push the rice to the side, crack in the eggs, scramble briefly, then fold into the rice and cook for 1 minute until just set. Serve in bowls topped with cucumber slices and fried shallots."}},{"id":42,"servings":4,"tipType":"def","pairingsType":"def","origin":{"ar":"سويسرا","en":"Switzerland","ro":"Elveția"},"name":{"ar":"فوندو","en":"Fondue","ro":"Fondue"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["400 غ من جبن غرويير، مبشور خشن","200 غ من جبن إيمنتال، مبشور خشن","1 فص ثوم، مقسّم إلى نصفين","300 مل من النبيذ الأبيض الجاف (فاندان أو شاسيلاس)","1 ملعقة كبيرة نشا ذرة","2 ملعقة كبيرة كيرش (كونياك الكرز)","رشة من جوزة الطيب المبشورة طازجاً","فلفل أسود مطحون طازجاً حسب الذوق","1 باغيت كبير مقرمش (حوالي 500 غ)، مقطع إلى مكعبات 2 سم","مخللات صغيرة وبطاطا جديدة مسلوقة للتقديم"],"en":["400 g Gruyère, coarsely grated","200 g Emmental, coarsely grated","1 garlic clove, halved","300 ml dry white wine (Fendant or Chasselas)","1 tbsp cornstarch","2 tbsp kirsch (cherry brandy)","a pinch of freshly grated nutmeg","freshly ground black pepper to taste","1 large crusty baguette (about 500 g), cut into 2 cm cubes","cornichons and boiled new potatoes to serve"],"ro":["400 g Gruyère, ras grosier","200 g Emmental, ras grosier","1 cățel de usturoi, tăiat pe jumătate","300 ml vin alb sec (Fendant sau Chasselas)","1 lingură amidon de porumb","2 linguri kirsch (rachiu de cireșe)","un praf de nucșoară rasă proaspăt","piper negru proaspăt măcinat după gust","1 baghetă mare crocantă (cca. 500 g), tăiată cubulețe de 2 cm","cornișoni și cartofi noi fierți pentru servire"]},"howIsMade":{"ar":"افرك داخل إناء الفوندو بالوجه المقطوع لفص الثوم؛ تخلّص من الثوم. صبّ النبيذ في الإناء وسخّنه على نار متوسطة حتى ما دون الغليان. اخلط الجبن المبشور مع نشا الذرة حتى يتغطى بشكل منتظم. أضف الجبن إلى النبيذ الدافئ في ثلاث مراحل، مع التحريك بحركة الرقم ثمانية بعد كل إضافة حتى يذوب الجبن تماماً ويصبح ناعماً، حوالي 8–10 دقائق في المجموع. أضف الكيرش وجوزة الطيب والفلفل الأسود؛ يجب أن يكون الفوندو سميكاً بما يكفي لتغليف الملعقة. ضع الإناء على موقد الفوندو على نار خفيفة للحفاظ على فوران هادئ. انقر مكعبات الخبز على أسياخ الفوندو وأدرها في الجبن واصلاً إلى قاع الإناء لمنع تشكّل القشرة. قدّم مع المخللات والبطاطا الصغيرة المسلوقة.","en":"Rub the inside of a fondue pot with the cut sides of the garlic clove; discard the garlic. Pour the wine into the pot and heat over medium heat until just below simmering. Toss the grated Gruyère and Emmental with the cornstarch until evenly coated. Add the cheese to the warm wine in three batches, stirring in a figure-eight motion after each addition until fully melted and smooth, about 8–10 minutes total. Stir in the kirsch, nutmeg, and a grind of black pepper; the fondue should be thick enough to coat a spoon. Place the pot over a fondue burner set to low to keep it gently bubbling. Spear bread cubes on fondue forks and swirl into the cheese, reaching the bottom of the pot to prevent a crust from forming. Serve with cornichons and boiled new potatoes."}},{"id":43,"servings":4,"tipType":"fish","pairingsType":"middle-eastern","origin":{"ar":"العراق","en":"Iraq","ro":"Irak"},"name":{"ar":"مسقوف","en":"Masgouf","ro":"Masgouf"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["1 سمكة كاملة (شبوط أو قاروص)، حوالي 1.5 كغ، مُنظّفة","4 ملاعق كبيرة زيت زيتون","1 ملعقة صغيرة ملح","1 ملعقة صغيرة كركم مطحون","1 ملعقة صغيرة كمون مطحون","2 حبتا طماطم، مقطعتان خشناً","1 ليمونة، مقطعة شرائح","4 فصوص ثوم، مفروم","1 بصلة صغيرة، مقطعة خشناً","2 ملعقة كبيرة معجون طماطم","فلفل أسود مطحون طازجاً حسب الذوق","4 أرغفة خبز رقيق للتقديم","بصل مقطع وطماطم ومخللات للتقديم"],"en":["1 whole carp or sea bass (about 1.5 kg), gutted and cleaned","4 tbsp olive oil","1 tsp salt","1 tsp ground turmeric","1 tsp ground cumin","2 tomatoes, roughly chopped","1 lemon, sliced","4 garlic cloves, minced","1 small onion, roughly chopped","2 tbsp tomato paste","freshly ground black pepper to taste","4 flatbreads to serve","sliced onion, tomato, and pickles to serve"],"ro":["1 crap sau biban întreg (cca. 1,5 kg), curățat și eviscerat","4 linguri ulei de măsline","1 linguriță sare","1 linguriță turmeric măcinat","1 linguriță chimen măcinat","2 roșii, tăiate grosier","1 lămâie, feliată","4 căței de usturoi, tocați","1 ceapă mică, tocată grosier","2 linguri pastă de roșii","piper negru proaspăt măcinat după gust","4 pâini plate pentru servire","ceapă feliată, roșii și murături pentru servire"]},"howIsMade":{"ar":"باستخدام سكين حادة، أجرِ شقاً عميقاً على طول العمود الفقري لفرد السمكة مسطحة. اعمل شرطات قطرية في اللحم كل 4 سنتيمترات. امزج زيت الزيتون والكركم والكمون والملح والفلفل وافرك الخليط في اللحم والتجويف. اتركها تتبّل 20 دقيقة. في هذه الأثناء، امزج الطماطم والبصل والثوم وشرائح الليمون ومعجون الطماطم لصنع صلصة الدهن. انظم السمكة على سيخين طويلين لتثبيتها. اشوها فوق الجمر المتّقد (ليس اللهب المباشر) من 30–40 دقيقة: اللحم نحو الأسفل لأول 20 دقيقة حتى يصبح أبيضاً ويتفصّل عن العظم، ثم الجلد نحو الأسفل لمدة 10–15 دقيقة حتى يصبح مقرمشاً. ادهن بالصلصة كل 5 دقائق. قدّمها فوراً مع الخبز الرقيق والبصل المقطع والطماطم والمخللات.","en":"Using a sharp knife, make a deep cut along the backbone to butterfly the fish open flat. Score the flesh diagonally every 4 cm. Mix the olive oil, turmeric, cumin, salt, and pepper; rub all over the flesh and inside the cavity. Leave to marinate for 20 minutes at room temperature. Meanwhile, combine the tomatoes, onion, garlic, lemon slices, and tomato paste to make the basting sauce. Thread the fish onto two long skewers (or use a fish grill basket) to hold it flat. Grill over glowing wood embers or charcoal (not open flames) for 30–40 minutes: flesh side down for the first 20 minutes until the flesh is opaque and pulls away from the bone, then skin side down for 10–15 minutes until the skin is crisp. Baste with the sauce every 5 minutes. Serve immediately with flatbread, sliced onion, tomato, and pickles."}},{"id":44,"servings":4,"tipType":"def","pairingsType":"middle-eastern","origin":{"ar":"إسرائيل","en":"Israel","ro":"Israel"},"name":{"ar":"شكشوكة","en":"Shakshuka","ro":"Shakshuka"},"category":{"ar":"فطور","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"ar":["2 ملعقة كبيرة زيت زيتون","1 بصلة كبيرة، مقطعة ناعماً","1 فلفل أحمر حلو، مقطع ناعماً","4 فصوص ثوم، مفروم","1 ملعقة صغيرة كمون مطحون","1 ملعقة صغيرة فليفلة حلوة","½ ملعقة صغيرة فليفلة مدخنة","¼ ملعقة صغيرة رقائق الفلفل الحار","2 علبة طماطم مهروسة (400 غ لكل علبة)","1 ملعقة صغيرة سكر","ملح وفلفل أسود مطحون طازجاً حسب الذوق","6 بيضات","حفنة صغيرة من البقدونس الطازج أو الكزبرة، مقطعة خشناً","خبز مقرمش أو خبز بيتا للتقديم"],"en":["2 tbsp olive oil","1 large onion, finely diced","1 red bell pepper, finely diced","4 garlic cloves, minced","1 tsp ground cumin","1 tsp sweet paprika","½ tsp smoked paprika","¼ tsp chilli flakes","2 x 400 g cans crushed tomatoes","1 tsp sugar","salt and freshly ground black pepper to taste","6 eggs","a small handful of fresh flat-leaf parsley or coriander, roughly chopped","crusty bread or pita to serve"],"ro":["2 linguri ulei de măsline","1 ceapă mare, tăiată mărunt","1 ardei kapia roșu, tăiat mărunt","4 căței de usturoi, tocați","1 linguriță chimen măcinat","1 linguriță boia dulce","½ linguriță boia afumată","¼ linguriță fulgi de ardei iute","2 x 400 g roșii zdrobite la conservă","1 linguriță zahăr","sare și piper negru proaspăt măcinat după gust","6 ouă","o mână de frunze de pătrunjel sau coriandru, tocate grosier","pâine crocantă sau pita pentru servire"]},"howIsMade":{"ar":"سخّن زيت الزيتون في مقلاة عميقة وواسعة على نار متوسطة. أضف البصل والفلفل الأحمر واطبخ مع التحريك من حين لآخر لمدة 8 دقائق حتى يلين ويتلوّن. أضف الثوم والكمون والفليفلتين ورقائق الفلفل الحار وحرّك دقيقة حتى يفوح الأريج. صبّ الطماطم وأضف السكر وتبّل بسخاء. اطهُ على نار هادئة 10 دقائق حتى يتكاثف الصلصة. اصنع 6 حفرات بالملعقة. اكسر بيضة في كل حفرة وغطّ المقلاة واطهُ 8–10 دقائق حتى ينعقد البياض ويظل الصفار طرياً. رشّ البقدونس أو الكزبرة وقدّم فوراً مع الخبز المقرمش أو الخبز العربي.","en":"Heat the olive oil in a wide, deep frying pan over medium heat. Add the onion and red pepper and cook, stirring occasionally, for 8 minutes until softened and beginning to colour. Add the garlic, cumin, sweet paprika, smoked paprika, and chilli flakes and stir for 1 minute until fragrant. Pour in the crushed tomatoes, add the sugar, and season generously with salt and pepper. Simmer for 10 minutes, stirring occasionally, until the sauce thickens and deepens in colour. Make 6 wells in the sauce with a spoon. Crack one egg into each well, then cover the pan with a lid and cook for 8–10 minutes until the whites are just set but the yolks are still runny. Scatter the parsley or coriander over the top and serve immediately from the pan with crusty bread or pita."}},{"id":45,"servings":4,"tipType":"soup","pairingsType":"soup","origin":{"ar":"فنلندا","en":"Finland","ro":"Finlanda"},"name":{"ar":"حساء السلمون","en":"Salmon Soup","ro":"Lohikeitto"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"ingredients":{"ar":["600 غ فيليه سمك السلمون الطازج، منزوع الجلد، مقطع قطعاً 3 سم","500 غ بطاطا صلبة اللب (شارلوت أو مشابهة)، مقشرة، مكعبات 2 سم","1 كراث كبير، الجزء الأبيض والأخضر الفاتح، مقطع حلقات رقيقة","2 جزرة متوسطة، مقشرة ومقطعة شرائح 5 مم","1 لتر مرق سمك جيد","200 مل كريمة للطهي","ورقة غار","5 حبات بهار حلو كاملة","1 ملعقة صغيرة ملح ناعم، يزاد حسب الذوق","¼ ملعقة صغيرة فلفل أبيض مطحون","حزمة كبيرة شبت طازج (نحو 30 غ)، مقطعة خشناً"],"en":["600 g fresh salmon fillet, skin removed, cut into 3 cm chunks","500 g waxy potatoes (Charlotte or similar), peeled and cut into 2 cm cubes","1 large leek, white and pale-green parts, thinly sliced into rings","2 medium carrots, peeled and sliced 5 mm thick","1 litre good-quality fish stock","200 ml double cream","1 bay leaf","5 whole allspice berries","1 tsp fine sea salt, plus more to taste","¼ tsp ground white pepper","1 large bunch fresh dill (about 30 g), roughly chopped"],"ro":["600 g file de somon proaspăt, fără piele, tăiat cuburi de 3 cm","500 g cartofi cu pulpă fermă (Charlotte sau similari), curățați, cuburi de 2 cm","1 praz mare, partea albă și verde deschis, tăiat rondele subțiri","2 morcovi medii, curățați, rondele de 5 mm","1 litru supă de pește bine aromatizată","200 ml smântână dulce pentru gătit","1 frunză de dafin","5 boabe de ienibahar","1 linguriță sare fină, plus după gust","¼ linguriță piper alb măcinat","1 mănunchi mare de mărar proaspăt (cca 30 g), tocat grosier"]},"howIsMade":{"ar":"صبّ مرق السمك في قدر كبيرة وأضئ على نار متوسطة حتى يرتجف قليلاً. أضف البطاطا والجزر والكراث وورقة الغار وحبات البهار الحلو. اطهُ على نار خفيفة 12–15 دقيقة حتى تنضج البطاطا عند غرز سكين فيها. خفّض النار إلى أدنى درجة — يجب أن يرتجف المرق دون أن يغلي. أضف قطع السلمون واطهُ 4–5 دقائق حتى يصبح السمك أبيض لاجلياً ويتفتت بسهولة. أضف الكريمة وسخّن دقيقتين دون غليان. اضبط الملح والفلفل الأبيض. أخرج ورقة الغار وحبات البهار. صبّ في أطباق دافئة وضع فوق كل حصة شبتاً طازجاً وفيراً. قدّمه مع خبز الجاودار الأسود.","en":"Pour the fish stock into a large pot and bring to a gentle simmer over medium heat. Add the potatoes, carrots, leek, bay leaf, and allspice berries. Cook at a gentle simmer for 12–15 minutes until the potatoes are just tender when pierced with a knife. Lower the heat so the stock barely trembles — do not boil. Add the salmon chunks and cook for 4–5 minutes until the fish is just opaque and flakes easily when nudged. Stir in the cream and heat for 2 minutes without letting it boil. Season with salt and white pepper. Remove the bay leaf and allspice berries. Ladle into warmed bowls and heap each portion with a generous amount of fresh dill. Serve with dark rye bread alongside."}},{"id":46,"servings":4,"tipType":"meat","timeMins":{"total":300,"active":60},"pairingsType":"middle-eastern","origin":{"ar":"إيران","en":"Iran","ro":"Iran"},"name":{"ar":"غورمه سبزي","en":"Ghormeh Sabzi","ro":"Ghormeh Sabzi"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["700 غ كتف ضأن بلا عظم (أو لحم بقري للطهي البطيء)، مقطع مكعبات 4 سم","200 غ فاصوليا حمراء جافة، منقوعة ليلة وصافية (أو 400 غ معلبة مصفاة)","1 بصلة كبيرة، مقطعة ناعماً","80 غ أوراق الحلبة الطازجة (أو 3 ملاعق كبيرة حلبة مجففة / كاسوري ميتهي)","100 غ بقدونس طازج ذو أوراق مسطحة، مفروم ناعماً","80 غ كزبرة طازجة، مفرومة ناعماً","50 غ سبانخ طازجة، مفرومة ناعماً","4 ليمون فارسي مجفف (ليمو عماني)، محفور بالشواية","1 ملعقة صغيرة كركم مطحون","½ ملعقة صغيرة فلفل أسود مطحون","1 ملعقة صغيرة ملح ناعم، يزاد حسب الذوق","3 ملاعق كبيرة زيت نباتي، مقسمة"],"en":["700 g boneless lamb shoulder (or beef chuck), cut into 4 cm cubes","200 g dried red kidney beans, soaked overnight and drained (or 400 g canned, drained)","1 large onion, finely diced","80 g fresh fenugreek leaves (or 3 tbsp dried fenugreek / kasuri methi)","100 g fresh flat-leaf parsley, finely chopped","80 g fresh coriander (cilantro), finely chopped","50 g fresh spinach, finely chopped","4 dried Persian limes (limoo amani), pierced with a skewer","1 tsp ground turmeric","½ tsp ground black pepper","1 tsp fine sea salt, plus more to taste","3 tbsp vegetable oil, divided"],"ro":["700 g carne de miel fără os (spată) sau vită pentru tocăniță, tăiată cuburi de 4 cm","200 g fasole boabe roșie uscată, hidratată peste noapte și scursă (sau 400 g la conservă, scursă)","1 ceapă mare, tăiată mărunt","80 g frunze proaspete de schinduf (sau 3 linguri schinduf uscat / kasoori methi)","100 g pătrunjel frunze plate proaspăt, tocat mărunt","80 g coriandru proaspăt, tocat mărunt","50 g spanac proaspăt, tocat mărunt","4 lămâi persane uscate (limoo amani), înțepate cu un frigărui","1 linguriță turmeric măcinat","½ linguriță piper negru măcinat","1 linguriță sare fină, plus după gust","3 linguri ulei vegetal, separat"]},"howIsMade":{"ar":"سخّن 1 ملعقة كبيرة زيت في قدر ثقيلة على نار عالية; حمّر اللحم على دفعتين 3–4 دقائق لكل دفعة من جميع الجهات حتى يتحول بني داكن. أخرجه وضعه جانباً; في القدر ذاتها، اقلِ البصل على نار متوسطة 8 دقائق حتى يذهب. أضف الكركم والفلفل وقلّب دقيقة; أعد اللحم مع الفاصوليا المصفاة والليمون المحفور. صب ماء يغطيها بالكاد; أوصل للغليان وانزع الرغوة ثم خفّض النار لأدنى درجة. في الوقت ذاته، في بقية الزيت في مقلاة واسعة على نار عالية، قلّي جميع الأعشاب (الحلبة والبقدونس والكزبرة والسبانخ) 15–20 دقيقة مع التحريك المستمر حتى تصبح خضراء داكناً جداً وتتبخر كل الرطوبة — هذه الخطوة الحاسمة تصنع الطعم المميز للطبق; أضف الأعشاب المقلية إلى المرق. اضبط الملح; غطِّ واطهُ على أهدأ نار لمدة 2–2.5 ساعة (فاصوليا جافة) أو 1.5 ساعة (معلبة) مع التحريك أحياناً حتى يتفتت اللحم; قدّم فوق أرز بسمتي.","en":"Heat 1 tbsp oil in a large heavy pot over medium-high heat; brown the meat in two batches, 3–4 minutes per batch, until deep brown on all sides. Remove and set aside; in the same pot, cook the onion over medium heat for 8 minutes until golden. Add the turmeric and black pepper; stir for 1 minute; return the meat to the pot. Add the drained kidney beans and pierced dried limes; pour over just enough water to barely cover. Bring to the boil, skim the foam, then reduce to the lowest possible simmer; meanwhile, heat the remaining 2 tbsp oil in a large frying pan over medium-high heat. Add all the herbs (fenugreek, parsley, coriander, spinach) and stir-fry for 15–20 minutes, until the herbs turn very dark green and all moisture has fully evaporated — this step is critical and builds the stew's characteristic deep flavour; stir the fried herbs into the stew. Season with salt; cover and simmer on the lowest heat for 2–2.5 hours (if using dried beans) or 1.5 hours (canned beans), stirring occasionally, until the meat is very tender and pulls apart easily. The stew should be thick and deeply coloured; serve over steamed basmati rice."}},{"id":47,"servings":4,"tipType":"fish","pairingsType":"fish","origin":{"ar":"البرتغال","en":"Portugal","ro":"Portugalia"},"name":{"ar":"باكالهاو أ براس","en":"Bacalhau à Brás","ro":"Bacalhau à Brás"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["500 غ سمك قد مملح منقوع 24–48 ساعة ومفتت","600 غ بطاطس متماسكة مقشرة ومقطعة شرائح رفيعة","6 بيضات كبيرة مخفوقة قليلاً","بصلتان بيضاوان متوسطتان مقطعتان شرائح رفيعة","4 ملاعق كبيرة زيت زيتون بكر ممتاز","3 فصوص ثوم مقطعة شرائح","حفنة صغيرة بقدونس طازج مقطعة خشناً","80 غ زيتون أسود منزوع النوى","ملح وفلفل أبيض"],"en":["500g salted cod (bacalhau), soaked 24–48h in cold water and shredded into flakes","600g waxy potatoes, peeled and cut into very thin matchstick strips","6 large eggs, lightly beaten","2 medium white onions, thinly sliced","4 tbsp extra-virgin olive oil","3 garlic cloves, thinly sliced","Small bunch of fresh flat-leaf parsley, roughly chopped","80g black olives, pitted, to serve","Salt and white pepper to taste"],"ro":["500g cod sărat (bacalhau), înmuiat 24–48h și desfăcut în fâșii","600g cartofi cerați, curățați și tăiați în bețișoare foarte subțiri","6 ouă mari, ușor bătute","2 cepe medii albe, tăiate felii subțiri","4 linguri ulei de măsline extravirgin","3 căței de usturoi, tăiați felii subțiri","Legătură mică de pătrunjel proaspăt, tocat grosier","80g măsline negre, fără sâmburi","Sare și piper alb"]},"howIsMade":{"ar":"انقع قطع سمك القد في الماء البارد، غيّر الماء أربع مرات خلال 24–48 ساعة حتى يصبح المذاق لطيفاً مالحاً; اصفِ وجفّف. قطّع البطاطس شرائح رفيعة جداً; في 2 سم من الزيت على 170°C، اقلِ شرائح البطاطس على دفعات 3–4 دقائق حتى تذهب ذهبياً فاتحاً. صفّها على ورق وتخلص من الزيت; امسح المقلاة. سخّن زيت الزيتون على نار متوسطة-منخفضة ولطّف البصل والثوم 12–15 دقيقة مع التقليب المستمر; أضف القد وحرّك دقيقتين. أضف البطاطس وقلّب برفق; صبّ البيض المخفوق بالفلفل الأبيض. حرّك باستمرار بطيّات واسعة وبطيئة 2–3 دقائق على نار هادئة — يجب أن يتشكّل البيض في طيات ناعمة وكريمية; ارفع عن النار بينما البيض لا يزال شبه نيء. تذوّق الملح; رشّ البقدونس وقدّم مع الزيتون الأسود.","en":"Soak the shredded cod in cold water, changing the water four times over 24–48 hours until a small piece tastes pleasantly savoury rather than sharp; drain and pat dry. Cut potatoes into very thin matchstick strips; heat 2cm of neutral oil in a deep frying pan to 170°C and fry the potato strips in batches for 3–4 minutes until pale golden; drain on paper. Discard the frying oil and wipe the pan; heat olive oil over medium-low heat and cook the onion and garlic, stirring often, for 12–15 minutes until very soft and lightly golden. Add the cod flakes and stir for 2 minutes until warmed through; tip in the potato strips and toss once. Pour in the beaten eggs seasoned with white pepper; stir continuously over low heat with slow, wide folds for 2–3 minutes — the eggs should set in soft, creamy layers, never dry or granular. Remove from heat while the eggs still look slightly underdone; residual heat finishes the dish; taste for salt before adding any — the cod may already hold enough; scatter with parsley and serve straight from the pan with black olives alongside."}},{"id":48,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ar":"الفلبين","en":"Philippines","ro":"Filipine"},"name":{"ar":"أدوبو","en":"Adobo","ro":"Adobo"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["1.2 كغ أفخاذ وأرجل دجاج كاملة بالعظم والجلد (أو 1 كغ بطن خنزير مقطع مكعبات 4 سم)","6 فصوص ثوم، مسحوقة","125 مل خل قصب أو خل نبيذ أبيض","80 مل صلصة صويا","3 أوراق غار","1 ملعقة صغيرة حبوب فلفل أسود كاملة","80 مل ماء","2 ملعقة كبيرة زيت نباتي"],"en":["1.2 kg chicken thighs and drumsticks, bone-in skin-on (or 1 kg pork belly cut into 4 cm cubes)","6 garlic cloves, crushed","125 ml cane vinegar or white wine vinegar","80 ml soy sauce","3 bay leaves","1 tsp whole black peppercorns","80 ml water","2 tbsp vegetable oil"],"ro":["1,2 kg pulpe și tobe de pui (cu os, cu piele) sau 1 kg burtă de porc tăiată cuburi de 4 cm","6 căței de usturoi, zdrobiți","125 ml oțet de trestie sau oțet alb de vin","80 ml sos de soia","3 frunze de dafin","1 linguriță boabe de piper negru","80 ml apă","2 linguri ulei vegetal"]},"howIsMade":{"ar":"اجمع الدجاج (أو الخنزير) والثوم والخل وصلصة الصويا وأوراق الغار وحبات الفلفل والماء في قدر كبيرة. انقعه 30 دقيقة في درجة حرارة الغرفة. أضرم النار المتوسطة-العالية وأوصل للغليان دون تحريك. بعد الغليان خفّض النار، غطِّ واطهُ 30 دقيقة (دجاج) أو 45 دقيقة (خنزير) حتى ينضج اللحم. اكشف الغطاء وارفع النار للمتوسطة. استمر في الطهي وقلّب اللحم أحياناً 15–20 دقيقة حتى يتكاثف الصوص إلى طلاء لامع يغطي ظهر الملعقة. في مقلاة منفصلة سخّن الزيت على نار عالية. ضع القطع بالجلد لأسفل واقلها 3–4 دقائق حتى يصبح الجلد ذهبياً ومقرمشاً. أعدها للصوص وقلّبها. أخرج أوراق الغار. قدّم على أرز أبيض.","en":"Combine the chicken (or pork), garlic, vinegar, soy sauce, bay leaves, peppercorns, and water in a large pot. Marinate for 30 minutes at room temperature. Bring to the boil over medium-high heat without stirring. Once boiling, reduce heat to low, cover, and simmer for 30 minutes (chicken) or 45 minutes (pork) until the meat is tender. Uncover and increase heat to medium. Continue simmering, turning the meat occasionally, for 15–20 minutes until the sauce reduces to a glossy, thick glaze that coats the back of a spoon. In a separate pan, heat the oil over high heat. Add the cooked pieces skin-side down and fry for 3–4 minutes until the skin is golden brown and crisp. Return to the sauce and toss to coat. Discard bay leaves. Serve over steamed white rice."}},{"id":49,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ar":"جامايكا","en":"Jamaica","ro":"Jamaica"},"name":{"ar":"دجاج جيرك","en":"Jerk Chicken","ro":"Jerk Chicken"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["1.5 كغ أفخاذ وأرجل دجاج بالجلد مع شقوق عميقة","6 بصيلات خضراء مقطعة خشناً","3 فلفل سكوتش بونيت أو هابانيرو منزوع البذور","5 فصوص ثوم","قطعة 2 سم زنجبيل طازج مقشر","2 ملعقة كبيرة صويا غامقة","2 ملعقة كبيرة سكر بني","1 ملعقة كبيرة فلفل حلو مطحون","1 ملعقة صغيرة زعتر مجفف","½ ملعقة صغيرة قرفة مطحونة","½ ملعقة صغيرة فلفل أسود","2 ملعقة كبيرة زيت نباتي","عصير ليمونتين خضراوتين مع شرائح للتقديم"],"en":["1.5kg chicken thighs and drumsticks, skin-on, scored deeply with a knife","6 spring onions, roughly chopped","3 Scotch bonnet chilies or habaneros, seeds removed for moderate heat","5 garlic cloves","2cm piece fresh ginger, peeled","2 tbsp dark soy sauce","2 tbsp brown sugar","1 tbsp ground allspice","1 tsp dried thyme","½ tsp ground cinnamon","½ tsp black pepper","2 tbsp vegetable oil","Juice of 2 limes, plus wedges to serve"],"ro":["1,5 kg pulpe și copane de pui, cu piele, crestați adânc","6 fire ceapă verde, tăiate grosier","3 ardei Scotch bonnet (sau habanero), semințele îndepărtate","5 căței de usturoi","Bucată de 2cm ghimbir proaspăt, curățat","2 linguri sos de soia închis la culoare","2 linguri zahăr brun","1 lingură ienibahar măcinat","1 linguriță cimbru uscat","½ linguriță scorțișoară măcinată","½ linguriță piper negru","2 linguri ulei vegetal","Suc de la 2 lămi verzi, plus felii pentru servire"]},"howIsMade":{"ar":"امزج البصل الأخضر والفلفل الحار والثوم والزنجبيل والصويا والسكر والفلفل الحلو والزعتر والقرفة والفلفل الأسود والزيت وعصير الليمون في الخلاط حتى تتشكل عجينة خشنة. اشقق كل قطعة دجاج عميقاً حتى العظم — لا تعمل طريقة جيرك إلا إذا اخترق التتبيل داخل اللحم. دهّن بالعجينة واضغطها داخل كل شق. دع الدجاج يتبل في الثلاجة 4 ساعات على الأقل، ومن الأفضل طوال الليل. أخرجه قبل 30 دقيقة من الطهي. على الفحم: اشوِ على حرارة متوسطة-عالية 35–45 دقيقة، مع التقليب كل 10 دقائق. في الفرن: 200°C على رف فوق صينية 40 دقيقة ثم 5 دقائق تحت الشواية. أرح 5 دقائق. قدّم مع الأرز والبازلاء والموز المقلي.","en":"Blend spring onions, Scotch bonnets, garlic, ginger, soy sauce, brown sugar, allspice, thyme, cinnamon, black pepper, oil, and lime juice in a food processor until a rough paste forms. Score the chicken pieces deeply down to the bone — jerk only works if the marinade penetrates inside the meat. Rub the paste all over and into every cut. Cover and marinate in the refrigerator for at least 4 hours, ideally overnight. Remove from the fridge 30 minutes before cooking. To grill over charcoal: cook over medium-hot coals for 35–45 minutes, turning every 10 minutes, until the juices run clear and the exterior is deeply charred in places. To oven-roast: place on a rack over a baking tray at 200°C for 40 minutes, then finish under a hot grill for 5 minutes to char the skin. Allspice is the defining spice — do not substitute with mixed spice. Rest 5 minutes before serving. Serve with rice and peas, fried plantain, and lime wedges."}},{"id":50,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ar":"إثيوبيا","en":"Ethiopia","ro":"Etiopia"},"name":{"ar":"دورو وات","en":"Doro Wat","ro":"Doro Wat"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["1.2 كغ قطع دجاج (فخاذ وأرجل بالعظم)","3 ملاعق كبيرة عصير ليمون","4 بصلات كبيرة (نحو 800 غ)، مفرومة ناعماً جداً","80 غ نيتر كيبي (الزبدة الإثيوبية المتبلة) أو زبدة مصفاة","6 فصوص ثوم، مفرومة ناعماً","2 ملعقة كبيرة زنجبيل طازج مبشور ناعماً (قطعة نحو 3 سم)","4 ملاعق كبيرة مزيج بهارات بربري","1 ملعقة صغيرة هيل مطحون","½ ملعقة صغيرة حلبة مطحونة","250 مل ماء أو مرق دجاج","4 بيضات مسلوقة صلبة، مقشرة ومحزوزة بالشوكة من جميع الجهات","ملح حسب الذوق"],"en":["1.2 kg chicken pieces (thighs and drumsticks, bone-in)","3 tbsp lemon juice","4 large onions (about 800 g), very finely diced","80 g niter kibbeh (Ethiopian spiced butter) or clarified butter","6 garlic cloves, minced","2 tbsp fresh ginger, finely grated (about 3 cm piece)","4 tbsp berbere spice blend","1 tsp ground cardamom","½ tsp ground fenugreek","250 ml water or chicken stock","4 hard-boiled eggs, shelled and scored all over with a fork","salt to taste"],"ro":["1,2 kg piese de pui (pulpe și tobe cu os)","3 linguri suc de lămâie","4 cepe mari (cca 800 g), tăiate mărunt fin","80 g unt etiopian niter kibbeh (sau unt clarificat)","6 căței de usturoi, tocați mărunt","2 linguri ghimbir proaspăt ras (cca 3 cm bucată)","4 linguri amestec de condimente berbere","1 linguriță cardamom măcinat","½ linguriță schinduf măcinat","250 ml apă sau supă de pui","4 ouă fierte tari, curățate, înțepate cu furculița","sare după gust"]},"howIsMade":{"ar":"اثقب الدجاج بالشوكة من جميع الجهات وافركه بعصير الليمون; ضع البصل المفروم ناعماً في قدر ثقيلة كبيرة على نار خفيفة بدون زيت أو دهن. اطهُ مع التحريك كثيراً 25–30 دقيقة حتى يصبح البصل طرياً جداً وذهبياً داكناً يفوح منه رائحة الكراميل — هذا التحمير الجاف الطويل هو أساس نكهة الطبق; أضف النيتر كيبي وقلّب. أضف الثوم والزنجبيل والبربري والهيل والحلبة; اطهُ 5 دقائق مع التحريك المستمر حتى تتفتح البهارات ويتحول الزبد إلى أحمر-برتقالي غامق. أضف قطع الدجاج وقلّب لتغطيها كلها; اطهُ 5 دقائق مع التقليب حتى يتحول الدجاج من جميع الجهات. صبّ الماء أو المرق; أوصل للغليان ثم خفّض لأدنى نار. غطِّ واطهُ 40–45 دقيقة مع تقليب الدجاج في المنتصف حتى يتفتت; احزّ البيض واوضعه في الصلصة. اطهُ مكشوفاً 10 دقائق أخرى حتى يتلون البيض بالأحمر; اضبط الملح; قدّم على إنجيرا أو أرز.","en":"Prick the chicken all over with a fork and rub with lemon juice; put the finely diced onions into a large heavy pot over low heat with no oil or fat. Cook, stirring often, for 25–30 minutes until the onions are very soft, deep golden-brown, and smell caramel-like — this long dry fry builds the stew's flavour base; add the niter kibbeh and stir to coat. Add the garlic, ginger, berbere, cardamom, and fenugreek; cook for 5 minutes, stirring constantly, until the spices bloom and the butter turns deep red-orange. Add the chicken pieces and turn to coat completely; cook 5 minutes, turning, until sealed on all sides. Pour in the water or stock; bring to the boil, then reduce to the lowest simmer. Cover and cook for 40–45 minutes, turning the chicken halfway through, until the meat is very tender and nearly falling off the bone; score the eggs all over with a fork and nestle them into the sauce. Simmer uncovered for 10 more minutes until the eggs are stained red from the sauce and the sauce has thickened; season with salt; serve on injera flatbread or steamed rice."}},{"id":51,"servings":4,"tipType":"meat","pairingsType":"middle-eastern","origin":{"ar":"سوريا","en":"Syria","ro":"Siria"},"name":{"ar":"كبة","en":"Kibbeh","ro":"Kibbeh"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["العجينة: 300 غ برغل ناعم (#1)، مغسول ومصفى جيداً","400 غ لحم ضأن (أو بقري) خالٍ من الدهن، مفروم ومبرد","1 بصلة متوسطة، مبشورة ناعماً","1 ملعقة صغيرة بهار حلو مطحون","1 ملعقة صغيرة قرفة مطحونة","1 ملعقة صغيرة ملح ناعم","½ ملعقة صغيرة فلفل أسود مطحون","الحشوة: 300 غ لحم ضأن (أو بقري) مفروم","1 بصلة متوسطة، مقطعة ناعماً","80 غ صنوبر (أو كاجو)","1 ملعقة صغيرة بهار حلو مطحون","½ ملعقة صغيرة قرفة مطحونة","1 ملعقة كبيرة زيت نباتي","زيت نباتي للقلي العميق (نحو 1 لتر)"],"en":["Shell: 300 g fine bulgur wheat (#1 grade), rinsed and drained","400 g very lean lamb (or beef) mince, chilled","1 medium onion, finely grated","1 tsp ground allspice","1 tsp ground cinnamon","1 tsp fine salt","½ tsp ground black pepper","Filling: 300 g lamb (or beef) mince","1 medium onion, finely diced","80 g pine nuts (or cashews)","1 tsp ground allspice","½ tsp ground cinnamon","1 tbsp vegetable oil","Vegetable oil for deep-frying (about 1 litre)"],"ro":["Coajă: 300 g bulgur fin (#1), clătit și scurs bine","400 g carne de miel sau vită slabă, tocată fin și răcită","1 ceapă medie, rasă sau blenderizată","1 linguriță condiment allspice (ienibahar măcinat)","1 linguriță scorțișoară măcinată","1 linguriță sare fină","½ linguriță piper negru măcinat","Umplutură: 300 g carne de miel sau vită tocată","1 ceapă medie, tăiată mărunt","80 g nuci de pin (sau nuci caju)","1 linguriță allspice","½ linguriță scorțișoară","1 lingură ulei vegetal","Ulei vegetal pentru prăjit adânc (cca 1 litru)"]},"howIsMade":{"ar":"انقع البرغل في الماء البارد 15 دقيقة، صفّه وعصره جيداً باليدين; اخلطه في معالج الطعام مع اللحم المبرد والبصل المبشور والبهار والقرفة والملح والفلفل. شغّل 3–4 دقائق مضيفاً ملاعق من الماء البارد إذا احتجت حتى تحصل على عجينة صلبة متجانسة; ضعها في الثلاجة 30 دقيقة. الحشوة: سخّن الزيت على نار متوسطة; اقلِ البصل 5 دقائق حتى يلين. أضف اللحم ورمّره 6–8 دقائق مع التكسير; أضف البهار والقرفة والفلفل والصنوبر وقلّب دقيقتين. دعه يبرد; التشكيل: بلّل يديك بالماء البارد. خذ 60 غ عجين وشكّلها حول إصبعك السبابة كطوربيد مجوف بجدران 5 مم; احشُها بملعقة كبيرة من الحشوة. أغلق الطرف المفتوح بإحكام في شكل رأس مدبب; كرر العملية. ضع في الثلاجة 30 دقيقة; القلي: سخّن الزيت إلى 175 درجة. اقلِ في دفعات 4–5 قطع 4–5 دقائق مع التقليب اللطيف حتى تتحول لذهبية من جميع الجهات; صفّها على ورق; قدّم دافئاً مع لبن أو صلصة ثوم وخبز بيتا.","en":"Soak the bulgur in cold water for 15 minutes, then drain and squeeze out all moisture firmly with your hands; combine with the chilled lean mince, grated onion, allspice, cinnamon, salt, and pepper in a food processor. Process for 3–4 minutes, adding ice water a tablespoon at a time if needed, until you have a smooth, stiff dough; refrigerate for 30 minutes. Make the filling: heat the oil over medium heat; cook the onion for 5 minutes until soft. Add the mince and brown, breaking it up, for 6–8 minutes; stir in allspice, cinnamon, pepper, and pine nuts; cook 2 minutes. Cool completely; shape: wet your hands with cold water. Take a 60 g piece of dough and mould it around your index finger into a hollow torpedo shape with 5 mm thick walls; fill the hollow with about 1 tablespoon of filling. Pinch the open end firmly to seal it into a pointed torpedo; repeat with the remaining dough and filling. Refrigerate for at least 30 minutes; fry: heat oil to 175°C. Fry in batches of 4–5 for 4–5 minutes, turning gently, until deep golden brown all over; drain on paper; serve warm with yoghurt or garlic sauce and pita bread."}},{"id":52,"servings":4,"tipType":"veg","pairingsType":"veg","origin":{"ar":"هولندا","en":"Netherlands","ro":"Olanda"},"name":{"ar":"ستامبوت","en":"Stamppot","ro":"Stamppot"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["1 كغ من البطاطا الطحينية (مثل ماريس بايبر)، مقشورة ومقطعة إلى أرباع","400 غ من اللفت الكرنبي المجعد (بوركنكول)، مع إزالة السيقان الصلبة وتقطيع الأوراق خشنًا","400 غ من النقانق المدخنة (روكورست) أو البراتفورست","80 غ من الزبدة غير المملحة، مقطعة مكعبات","100 مل من الحليب الكامل الدسم، دافئ","1/4 ملعقة صغيرة من جوزة الطيب المبشورة طازجًا","1 1/2 ملعقة صغيرة من الملح البحري الناعم، مقسمة","1/2 ملعقة صغيرة من الفلفل الأسود المطحون طازجًا"],"en":["1 kg floury potatoes (such as Maris Piper or Russet), peeled and quartered","400 g curly kale (boerenkool), tough stems removed, leaves roughly chopped","400 g smoked pork sausage (rookworst) or bratwurst","80 g unsalted butter, cut into cubes","100 ml whole milk, warmed","1/4 tsp freshly grated nutmeg","1 1/2 tsp fine sea salt, divided","1/2 tsp freshly ground black pepper"],"ro":["1 kg cartofi făinoși (tip Maris Piper sau Russet), curățați și tăiați în sferturi","400 g varză creață (boerenkool), tulpini dure îndepărtate, frunze tocate grosier","400 g cârnați afumați din porc (rookworst) sau bratwurst","80 g unt nesărat, tăiat cubulețe","100 ml lapte integral, încălzit","1/4 linguriță nucșoară proaspăt rasă","1 1/2 linguriță sare fină de mare, împărțită","1/2 linguriță piper negru proaspăt măcinat"]},"howIsMade":{"ar":"احضر قدرًا كبيرًا من الماء مع ملعقة صغيرة من الملح إلى الغليان، أضف البطاطا واطهها 18-20 دقيقة حتى تصبح طرية تمامًا عند وخزها بسكين. بينما تُطهى البطاطا، احضر قدرًا آخر من الماء المملح إلى الغليان، أضف اللفت وابيضه 5-6 دقائق حتى يذبل ويطرى؛ صفيه جيدًا واعصر الماء الزائد وقطعه خشنًا. ضع النقانق المدخنة في مقلاة وأضف ماءً كافيًا لتغطيتها وأغلها على نار متوسطة 20 دقيقة حتى تسخن تمامًا — أو اقلها في كمية قليلة من الزيت على نار متوسطة 8-10 دقائق مع التقليب في المنتصف حتى تتحمر من جميع الجهات. صفي البطاطا وأعدها إلى القدر الساخن على نار خفيفة 1-2 دقيقة مع تحريك القدر لتجفيفها بالبخار ومنع الهريس المائي. أضف الزبدة والحليب الدافئ وهرس بشدة باستخدام مهرس البطاطا حتى تحصل على هريس ناعم وكريمي. أضف اللفت المصفى وتبل بالملح المتبقي والفلفل الأسود وجوزة الطيب وقلب حتى يتجانس المزيج. قدمه فورًا في أطباق عميقة مع شرائح النقانق فوقه.","en":"Bring a large pot of water with 1 tsp salt to the boil, add the potatoes, and cook for 18-20 minutes until completely tender when pierced with a knife. While the potatoes cook, bring a separate pot of salted water to the boil, add the kale, and blanch for 5-6 minutes until wilted and tender; drain well, squeeze out excess water, and chop roughly. Place the smoked sausage in a pan, add enough water to just cover, and simmer over medium heat for 20 minutes until heated through — or pan-fry in a little oil over medium heat for 8-10 minutes, turning halfway, until browned on all sides. Drain the potatoes and return them to the hot pot over low heat for 1-2 minutes, shaking the pot to steam-dry them and prevent a watery mash. Add the butter and warm milk and mash vigorously with a potato masher until smooth and creamy. Fold in the drained kale, season with the remaining salt, black pepper, and nutmeg, and stir until evenly combined. Serve immediately in deep bowls with the sliced sausage on top."}},{"id":53,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ar":"نيوزيلندا","en":"New Zealand","ro":"Noua Zeelandă"},"name":{"ar":"هانغي","en":"Hangi","ro":"Hangi"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["600 غ من لحم الضأن مع العظم (كتف أو ضلوع)، مقطع إلى قطع 4 سم","4 أفخاذ دجاج (حوالي 600 غ إجمالًا) مع الجلد","500 غ من البطاطا الصماء، مقشورة ومقسمة إلى نصفين","300 غ من كومارا (بطاطا حلوة برتقالية)، مقشورة ومقطعة مكعبات 4 سم","300 غ من قرع الفراشة، مقشور ومقطع مكعبات 4 سم","ربع رأس ملفوف السافوا (حوالي 300 غ)، مقطع إلى 4 أجزاء","3 ملاعق كبيرة زيت نباتي","1 1/2 ملعقة صغيرة ملح ناعم","1/2 ملعقة صغيرة فلفل أسود مطحون"],"en":["600 g bone-in lamb shoulder or ribs, cut into 4 cm pieces","4 chicken drumsticks (about 600 g total), skin-on","500 g waxy potatoes, peeled and halved","300 g kumara (orange sweet potato), peeled and cut into 4 cm cubes","300 g butternut pumpkin, peeled and cut into 4 cm cubes","1/4 head savoy cabbage (about 300 g), cut into 4 wedges","3 tbsp vegetable oil","1 1/2 tsp fine salt","1/2 tsp ground black pepper"],"ro":["600 g carne de miel cu os (spată sau coaste), tăiată în bucăți de 4 cm","4 pulpe inferioare de pui (cca 600 g total), cu os și piele","500 g cartofi waxy, curățați și tăiați în jumătăți","300 g kumara (batată portocalie), curățată și tăiată cubulețe de 4 cm","300 g dovleac butternut, curățat și tăiat cubulețe de 4 cm","1/4 dintr-un cap de varză Savoy (cca 300 g), tăiată în 4 sferturi","3 linguri ulei vegetal","1 1/2 linguriță sare fină","1/2 linguriță piper negru măcinat"]},"howIsMade":{"ar":"سخن الفرن على 180 درجة مئوية (160 درجة بالمروحة). تبّل لحم الضأن والدجاج جيدًا بالملح والفلفل. سخن الزيت في قدر كبير مناسب للفرن على نار عالية وحمّر قطع الضأن 3-4 دقائق من كل جانب حتى تتلون بعمق، ثم انقلها إلى طبق. في نفس القدر، اقلِ أرجل الدجاج من جانب الجلد 4-5 دقائق حتى يصبح الجلد ذهبيًا ومقرمشًا، ثم ضعها جانبًا. رتب جميع اللحوم المحمّرة في القدر وضع البطاطا والكومارا والقرع وأرباع الملفوف بإحكام بين القطع. أضف 200 مل من الماء ثم أغلق القدر بإحكام شديد بطبقة مزدوجة من الرقاقة المعدنية مضغوطة على الحواف، ثم ضع الغطاء. اطبخ في الفرن ساعتين حتى يصبح لحم الضأن طريًا تمامًا وينفصل عن العظم بسهولة، وتصبح جميع الخضار طرية عند ثقبها بشوكة — إن لم تكن جاهزة، أعد التغطية واطبخ 30 دقيقة أخرى. أزل الغطاء والرقاقة المعدنية، ارفع حرارة الفرن إلى 220 درجة، واشوِ دون تغطية 15 دقيقة حتى يصبح الجلد مقرمشًا. ارح 10 دقائق ثم انقل كل شيء إلى طبق كبير وصب عليه العصائر المتجمعة قبل التقديم.","en":"Heat the oven to 180°C (160°C fan). Season the lamb and chicken all over with salt and pepper. Heat the oil in a large flameproof casserole over high heat and brown the lamb pieces for 3-4 minutes per side until deeply coloured, then transfer to a plate. In the same pot, brown the chicken drumsticks skin-side down for 4-5 minutes until the skin is golden and crisp, then set aside. Arrange all the browned meat in the casserole and tuck the potatoes, kumara, pumpkin, and cabbage wedges snugly around and between the pieces. Pour in 200 ml of water, then seal the casserole very tightly with a double layer of foil pressed against the rim and put the lid on. Cook in the oven for 2 hours until the lamb is completely tender and pulls away from the bone easily, and all the vegetables are soft when pierced with a fork — if not quite done, cover again and cook for 30 minutes more. Remove the lid and foil, raise the oven to 220°C, and roast uncovered for 15 minutes until the skin crisps. Rest for 10 minutes before transferring everything to a large platter and spooning the collected juices over the top."}},{"id":54,"servings":4,"tipType":"fish","pairingsType":"fish","origin":{"ar":"بلجيكا","en":"Belgium","ro":"Belgia"},"name":{"ar":"بلح البحر مع البطاطس المقلية","en":"Moules-frites","ro":"Moules-frites"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["2 كغ بلح بحر طازج حي مدعوك ومنزوع الخيط","800 غ بطاطس دقيقية مقشرة ومقطعة عصي سميكة","50 غ زبدة غير مملحة","4 كراث مقطع ناعماً","4 فصوص ثوم مقطعة شرائح رفيعة","200 مل نبيذ أبيض جاف","2 ساق كرفس مقطعتان شرائح رفيعة","حفنة صغيرة بقدونس طازج مقطع ناعماً","زيت نباتي أو دهن بقري للقلي","ملح وفلفل أسود"],"en":["2kg fresh live mussels, scrubbed and beards removed","800g floury potatoes, peeled and cut into thick batons","50g unsalted butter","4 shallots, finely diced","4 garlic cloves, thinly sliced","200ml dry white wine","2 celery stalks, finely sliced","Small bunch of fresh parsley, finely chopped","Vegetable oil or beef dripping, for deep-frying","Salt and black pepper"],"ro":["2 kg midii proaspete vii, curățate și cu beard-ul îndepărtat","800g cartofi făinoși, curățați și tăiați bețe groase","50g unt nesărat","4 șalote, tocate mărunt","4 căței de usturoi, felii subțiri","200ml vin alb sec","2 tulpini de țelină, feliate subțire","Legătură mică de pătrunjel proaspăt, tocat mărunt","Ulei vegetal sau grăsime de vită, pentru prăjit","Sare și piper negru"]},"howIsMade":{"ar":"للبطاطا: قطّعها عصياً سميكة وانقعها في ماء بارد 30 دقيقة، ثم اصفِ وجفّف جيداً; الأولى قلي على 140°C لمدة 6–8 دقائق حتى تنضج دون اكتساب اللون؛ صفّها وبرّدها كلياً. اقرع كل صدفة مفتوحة على المنضدة — تخلص مما لا يُغلق; أذب الزبدة في إناء ثقيل على نار متوسطة-عالية. أضف الكراث والكرفس واطبخ 3 دقائق; أضف الثوم واطبخ دقيقة. صبّ النبيذ الأبيض وأحضره للغليان، أضف بلح البحر وأغلق الغطاء محكماً; اطبخ بالبخار 4–5 دقائق مع هز الإناء مرة أو مرتين حتى تنفتح القذائف. تخلص من المغلقة; أضف البقدونس وتبّل المرق. ارفع حرارة الزيت إلى 190°C واقلِ عصي البطاطا المسبقة الطهي على دفعات 2–3 دقائق حتى تذهب ذهبية ومقرمشة; صفّها وملّحها فوراً; قدّم بلح البحر في مرقه مع البطاطا جانباً.","en":"For the frites: cut potatoes into thick batons and soak in cold water for 30 minutes to remove surface starch, then drain and dry thoroughly; first fry at 140°C for 6–8 minutes until cooked through but uncoloured; drain and cool completely. Tap each open mussel on the counter — discard any that do not close; melt butter in a large heavy pot over medium-high heat. Add shallots and celery and cook for 3 minutes until softened; add garlic and cook for 1 minute. Pour in the white wine, bring to a boil, then add the mussels and cover tightly; steam for 4–5 minutes, shaking the pot once or twice, until the shells have opened wide. Discard any that remain shut; stir in most of the parsley and season the broth. Raise the frying oil to 190°C and fry the blanched batons in batches for 2–3 minutes until golden and very crisp; drain and season immediately with salt; serve the mussels in wide bowls in their broth, the frites alongside, with the remaining parsley and mayonnaise on the side."}},{"id":55,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ar":"اليونان","en":"Greece","ro":"Grecia"},"name":{"ar":"مسقعة","en":"Moussaka","ro":"Moussaka"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["حبتان كبيرتان من الباذنجان (حوالي 1 كغ إجمالاً)، شرائح بسماكة 1 سم","500 غ لحم ضأن مفروم (أو لحم بقر مفروم)","1 بصلة كبيرة، مفرومة ناعماً","3 فصوص ثوم، مفرومة","400 غ طماطم مفرومة معلبة (علبة واحدة)","2 ملعقة كبيرة معجون طماطم","100 مل نبيذ أحمر","1 ملعقة صغيرة أوريغانو مجفف","1/2 ملعقة صغيرة قرفة مطحونة","60 غ زبدة (للبشاميل)","60 غ دقيق أبيض (للبشاميل)","700 مل حليب دافئ","2 صفار بيض","80 غ جبن كيفالوتيري مبشور (أو بارميزان)","3 ملاعق كبيرة زيت زيتون","ملح وفلفل أسود مطحون طازج"],"en":["2 large eggplants (about 1 kg total), sliced 1 cm thick","500 g lamb mince (or beef mince)","1 large onion, finely diced","3 garlic cloves, minced","400 g chopped tomatoes (1 can)","2 tbsp tomato paste","100 ml red wine","1 tsp dried oregano","1/2 tsp ground cinnamon","60 g butter (for the bechamel)","60 g plain flour (for the bechamel)","700 ml warm milk","2 egg yolks","80 g grated kefalotyri (or parmesan)","3 tbsp olive oil","Salt and freshly ground black pepper"],"ro":["2 vinete mari (aproximativ 1 kg in total), feliate de 1 cm grosime","500 g carne tocata de miel (sau de vita)","1 ceapa mare, tocata marunt","3 căței de usturoi, zdrobiti","400 g rosii tocate in conserva (1 conserva)","2 linguri pasta de rosii","100 ml vin rosu","1 lingurita oregano uscat","1/2 lingurita scortisoara macinata","60 g unt (pentru bechamel)","60 g făină alba (pentru bechamel)","700 ml lapte cald","2 galbenusuri de ou","80 g kefalotyri ras (sau parmezan)","3 linguri ulei de masline","Sare si piper negru proaspat macinat"]},"howIsMade":{"ar":"قطّع حبتين كبيرتين من الباذنجان إلى شرائح بسماكة 1 سم، رشّها بالملح بسخاء واتركها في مصفاة لمدة 30 دقيقة لتُخرج ماءها المرّ؛ جفّفها بمناديل ورقية. ادهن الشرائح بزيت الزيتون واشوها في الفرن على حرارة 200 درجة لمدة 20-25 دقيقة مع قلبها مرة واحدة حتى تذهب وتنضج. في مقلاة واسعة سخّن 2 ملعقة كبيرة زيت على نار متوسطة-عالية وحمّر 500 غرام لحم ضأن مفروم مع بصلة مفرومة و3 فصوص ثوم لمدة 8-10 دقائق، ثم أضف 100 مل نبيذ أحمر واتركه يتبخر. أضف 400 غرام طماطم مفرومة و2 ملعقة كبيرة معجون طماطم ونصف ملعقة صغيرة قرفة و1 ملعقة صغيرة أوريغانو؛ اطبخ على نار هادئة 20 دقيقة حتى يثخن المزيج ولا يبقى سائل على الأطراف. للبشاميل أذب 60 غرام زبدة في قدر، أضف 60 غرام دقيق واطبخ 2 دقيقة حتى يصبح ذهبياً، ثم أضف تدريجياً 700 مل حليب دافئ مع التحريك المستمر حتى يثخن؛ ارفع عن النار واتركه يبرد 30 ثانية ثم اخفق 2 صفار بيض مع 80 غرام جبن كيفالوتيري أو بارميزان مبشور. في صينية فرن 30x20 سم رتّب طبقة من الباذنجان، نصف صلصة اللحم، طبقة أخرى من الباذنجان، باقي الصلصة، ثم اسكب البشاميل فوقها وسوّها بملعقة. اخبزها على حرارة 180 درجة لمدة 40-45 دقيقة حتى يصبح الوجه ذهبياً عميقاً وتغلي الصلصة على الأطراف. اترك المسقعة ترتاح 15-20 دقيقة قبل تقطيعها؛ هذه الخطوة غير قابلة للتفاوض حتى تتماسك الطبقات وتحافظ القطع على شكلها.","en":"Slice 2 large eggplants into 1 cm rounds, salt them generously and let them sit in a colander for 30 minutes to draw out the bitter water; pat dry with paper towels. Brush the slices with olive oil and roast at 200 C for 20-25 minutes, turning once, until golden and tender. In a wide pan heat 2 tbsp oil over medium-high and brown 500 g minced lamb with one chopped onion and 3 garlic cloves for 8-10 minutes, then deglaze with 100 ml red wine and let it reduce. Add 400 g chopped tomatoes, 2 tbsp tomato paste, half a tsp cinnamon and 1 tsp oregano; simmer 20 minutes until thick and no excess liquid pools at the edge. For the bechamel melt 60 g butter in a saucepan, whisk in 60 g flour and cook 2 minutes until blond, then gradually add 700 ml warm milk whisking constantly until thick; off the heat, let it cool 30 seconds and beat in 2 egg yolks with 80 g grated kefalotyri or parmesan. In a 30x20 cm baking dish layer half the eggplant, all the lamb sauce, the remaining eggplant, then pour the bechamel on top and level it with a spatula. Bake at 180 C for 40-45 minutes until the top is deeply golden and the sauce bubbles at the edges. Rest the moussaka for 15-20 minutes before cutting; this step is non-negotiable so the layers set and the slices hold their shape."},"timeMins":{"total":105,"active":35}},{"id":56,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ar":"جمهورية التشيك","en":"Czech Republic","ro":"Republica Cehă"},"name":{"ar":"سفيتشكوفا","en":"Svíčková","ro":"Svíčková"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["1.2 كغ من لحم بقري (ورك أو فخذ علوي)","100 غ من لحم مقدد مدخن، شرائح رفيعة للتشحيم (اختياري)","30 غ من الزبدة","1 ملعقة كبيرة من زيت محايد","1 بصلة كبيرة، مكعبات","2 جزرة كبيرة، مكعبات","1 جذر جزر أبيض، مكعبات","150 غ من جذر الكرفس، مكعبات","2 ورقتا غار","6 حبات بهار حلو","10 حبات فلفل أسود","قشر نصف ليمونة","1 ملعقة كبيرة من خردل ديجون","2 ملعقتان كبيرتان من معجون الطماطم","200 مل من نبيذ أبيض جاف","500 مل من مرق لحم البقر","200 مل من قشدة ثقيلة (33% دسم)","1 ملعقة كبيرة من الطحين (اختياري، للتكثيف)","1 ملعقة صغيرة من السكر","عصير نصف ليمونة","ملح، حسب الرغبة","للتقديم: كريمة مخفوقة، مربى التوت البري، شريحة ليمون، كنيدليكي"],"en":["1.2 kg beef sirloin (top round or topside)","100 g smoked bacon, cut in thin strips for larding (optional)","30 g butter","1 tbsp neutral oil","1 large onion, diced","2 large carrots, diced","1 parsnip, diced","150 g celeriac, diced","2 bay leaves","6 allspice berries","10 black peppercorns","Zest of 1/2 lemon","1 tbsp Dijon mustard","2 tbsp tomato paste","200 ml dry white wine","500 ml beef stock","200 ml heavy cream (33% fat)","1 tbsp plain flour (optional, for thickening)","1 tsp sugar","Juice of 1/2 lemon","Salt, to taste","To serve: whipped cream, cranberry compote, lemon slice, knedliky"],"ro":["1,2 kg mușchi de vită (vrabia sau pulpă top)","100 g bacon afumat, tăiat fâșii subțiri pentru lardonare (opțional)","30 g unt","1 lingură ulei neutru","1 ceapă mare, tăiată cuburi","2 morcovi mari, tăiați cuburi","1 rădăcină de păstârnac, tăiată cuburi","150 g țelină rădăcină, tăiată cuburi","2 foi de dafin","6 boabe de ienibahar","10 boabe de piper negru","Coaja de la 1/2 lămâie","1 lingură de muștar Dijon","2 linguri de pastă de roșii","200 ml vin alb sec","500 ml supă de vită","200 ml smântână grasă (33% grăsime)","1 lingură de făină albă (opțional, pentru îngroșare)","1 linguriță de zahăr","Zeama de la 1/2 lămâie","Sare, după gust","Pentru servire: frișcă bătută, dulceață de merișoare, felie de lămâie, knedlíky"]},"howIsMade":{"ar":"اشحم لحم البقر (1.2 كغ) بشرائح رقيقة من اللحم المقدد المدخن، أو اربطه بإحكام بخيط المطبخ؛ تبّله بسخاء بالملح والفلفل المطحون طازجًا من جميع الجهات. سخّن 30 غ من الزبدة و1 ملعقة كبيرة من الزيت في قدر هولندي ثقيل على نار متوسطة عالية واشوِ اللحم من كل جانب 8-10 دقائق حتى تتشكل قشرة بنية عميقة، ثم انقله إلى طبق. في القدر نفسه حمّر الميربوا (1 جزرة كبيرة، 1 جذر بقدونس، 150 غ من جذر الكرفس، 1 بصلة كبيرة، كلها مكعبات) 10-12 دقيقة حتى تتكرمل عند الحواف؛ أضف 2 ورقتي غار، 6 حبات بهار، 10 حبات فلفل أسود، قشر نصف ليمونة و1 ملعقة كبيرة من الخردل. أضف 2 ملعقتين كبيرتين من معجون الطماطم واطبخه دقيقتين حتى يصبح أغمق لونًا، ثم أزل الالتصاق ب200 مل من النبيذ الأبيض الجاف و500 مل من مرق اللحم، مع كشط القاع، وأعد اللحم فوق الخضار. غطّ واطهُ في الفرن عند 160°م لمدة 1.5-2 ساعة، مع تقليب اللحم كل 30 دقيقة، حتى تدخل الشوكة بلا مقاومة. انقل اللحم إلى لوح وغطّه برقاقة الألمنيوم ليرتاح؛ اهرس سائل الطهي مع الخضار بخلاط يدوي حتى يصبح ناعمًا ومرّر الصلصة عبر مصفاة ناعمة إلى القدر. أضف 200 مل من القشدة الثقيلة وعند الحاجة 1 ملعقة كبيرة من الطحين المذاب في قليل من الماء البارد؛ اطهُ على نار هادئة 5 دقائق حتى تغطي الصلصة ظهر الملعقة بلمعان، ثم اضبط النكهة بالملح و1 ملعقة صغيرة من السكر ورشة من عصير الليمون لموازنة الحلو-الحامض. قطّع اللحم عكس الألياف إلى شرائح بسماكة 1 سم، اسكب الصلصة الدافئة فوقه وزيّنه بملعقة من الكريمة المخفوقة ومربى التوت البري وشريحة ليمون؛ قدّمه مع كنيدليكي (زلابية الخبز).","en":"Lard the beef sirloin (1.2 kg) with thin strips of smoked bacon, or truss it tightly with kitchen twine; season generously with salt and freshly ground pepper on all sides. Heat 30 g butter and 1 tbsp oil in a heavy Dutch oven over medium-high and sear the beef on every side for 8-10 minutes until a deep brown crust forms, then transfer to a plate. In the same pot brown the mirepoix (1 large carrot, 1 parsnip, 150 g celeriac, 1 large onion, all diced) for 10-12 minutes until caramelised at the edges; add 2 bay leaves, 6 allspice berries, 10 whole black peppercorns, the zest of half a lemon and 1 tbsp mustard. Stir in 2 tbsp tomato paste and cook 2 minutes until it darkens, then deglaze with 200 ml dry white wine and 500 ml beef stock, scraping the bottom, and nestle the beef back in on top of the vegetables. Cover and braise at 160°C for 1.5 to 2 hours, turning the beef every 30 minutes, until a fork slides in with no resistance. Lift the beef onto a board and tent with foil to rest; blend the cooking liquid and vegetables with a stick blender until smooth and pass the sauce through a fine sieve back into the pot. Stir in 200 ml heavy cream and, if needed, 1 tbsp flour slaked in a little cold water; simmer 5 minutes until the sauce coats the back of a spoon glossily, then adjust with salt, 1 tsp sugar and a squeeze of lemon to balance the sweet-sour. Slice the beef against the grain into 1 cm slices, ladle the warm sauce over the top and garnish with a spoon of whipped cream, cranberry compote and a lemon slice; serve with houskove knedliky (bread dumplings)."}},{"id":57,"servings":4,"tipType":"meat","timeMins":{"total":195,"active":45},"pairingsType":"meat","origin":{"ar":"النرويج","en":"Norway","ro":"Norvegia"},"name":{"ar":"فاركال","en":"Fårikål","ro":"Fårikål"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["1.2 كغ من لحم الضأن مع العظم (كتف أو رقبة)، مقطع إلى قطع 5 سم","1.2 كغ من الملفوف الأبيض (رأس كبير تقريبًا)، منزوع القلب، مقطع إلى 8 أوتاد سميكة","1 ملعقة كبيرة حبات فلفل أسود كاملة","600 مل ماء بارد","1 1/2 ملعقة صغيرة ملح ناعم"],"en":["1.2 kg bone-in lamb shoulder or neck, cut into 5 cm pieces","1.2 kg white cabbage (about 1 large head), cored and cut into 8 thick wedges","1 tbsp whole black peppercorns","600 ml cold water","1 1/2 tsp fine salt"],"ro":["1,2 kg carne de miel cu os (spata sau gat), taiata in bucati de 5 cm","1,2 kg varza alba (1 cap mare), miezul indepartat, taiata in 8 sferturi groase","1 lingura boabe intregi de piper negru","600 ml apa rece","1 1/2 lingurita sare fina"]},"howIsMade":{"ar":"تبّل قطع الضأن من جميع الجهات بملعقة صغيرة من الملح. رتب نصف أوتاد الملفوف في طبقة متساوية على قاع قدر كبير وثقيل. ضع قطع الضأن فوقها وانثر حبات الفلفل وباقي الملح (نصف ملعقة صغيرة)، ثم رتب الملفوف المتبقي فوق ذلك. صب الماء البارد برفق على الجدار الداخلي للقدر دون التحريك. أغلق بإحكام وأحضره لغليان خفيف على نار متوسطة لنحو 8-10 دقائق. اخفض الحرارة للحد الأدنى واتركه يغلي برفق دون تحريك من ساعتين إلى ساعتين ونصف حتى يصبح لحم الضأن طريًا تمامًا وينفصل عن العظم، وينهار الملفوف ويمتص عصارة اللحم. بعد ساعتين تحقق أن اللحم ينفصل دون مقاومة والمرق غني وعطر — إن لم يكن جاهزًا بعد، أعد الغطاء واطبخ 30 دقيقة اضافية. تذوق واضبط الملح. اغرف في اطباق عميقة مع المرق مع التاكد من احتواء كل حصة على اللحم والملفوف.","en":"Season the lamb pieces all over with 1 tsp of the salt. Arrange half the cabbage wedges in an even layer at the bottom of a large, heavy pot. Lay the lamb pieces on top, scatter over the peppercorns and the remaining 1/2 tsp salt, then arrange the remaining cabbage on top. Pour the cold water carefully down the inside wall of the pot — do not stir. Cover tightly and bring to a gentle boil over medium heat, about 8-10 minutes. Reduce the heat to the lowest possible simmer and cook undisturbed for 2 to 2.5 hours until the lamb is completely tender and falls off the bone, and the cabbage has collapsed and fully absorbed the meat juices. After 2 hours check that the lamb pulls away from the bone with no resistance and the broth is rich and fragrant — if not quite done, cover and simmer for 30 minutes more. Taste and adjust salt. Ladle into deep bowls with the broth, ensuring each serving has both lamb and cabbage."}},{"id":58,"servings":4,"tipType":"veg","pairingsType":"middle-eastern","origin":{"ar":"السودان","en":"Sudan","ro":"Sudan"},"name":{"ar":"فول مدمس","en":"Ful Medames","ro":"Ful Medames"},"category":{"ar":"فطور","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"ar":["400 غ من الفول المجفف الصغير، منقوع طوال الليل في الماء البارد (أو 800 غ من الفول المعلب، مغسول ومصفى)","4 فصوص ثوم، مفرومة ناعمًا","60 مل من عصير الليمون الطازج (نحو ليمونة كبيرة)، ويزاد حسب الذوق","4 ملاعق كبيرة زيت زيتون بكر ممتاز، مقسمة","1 ملعقة صغيرة كمون مطحون","1/2 ملعقة صغيرة كزبرة مطحونة","1/2 ملعقة صغيرة ملح بحري ناعم، ويزاد حسب الذوق","1/4 ملعقة صغيرة فلفل حار مطحون أو بابريكا حارة","طماطمتان متوسطتان ناضجتان (نحو 250 غ)، مقطعتان ناعمًا","1 بصلة حمراء صغيرة (نحو 100 غ)، مقطعة ناعمًا","20 غ بقدونس أوراق مسطحة، أوراقه مقطعة خشنًا"],"en":["400 g dried small fava beans, soaked overnight in cold water (or 800 g canned fava beans, rinsed and drained)","4 garlic cloves, finely minced","60 ml fresh lemon juice (about 1 large lemon), plus more to taste","4 tbsp extra-virgin olive oil, divided","1 tsp ground cumin","1/2 tsp ground coriander","1/2 tsp fine sea salt, plus more to taste","1/4 tsp cayenne pepper or hot paprika","2 medium ripe tomatoes (about 250 g), finely diced","1 small red onion (about 100 g), finely diced","20 g flat-leaf parsley, leaves roughly chopped"],"ro":["400 g fasole fava uscata, inmuiata peste noapte in apa rece (sau 800 g fasole fava la conserva, clatita si scursa)","4 căței de usturoi, tocati marunt","60 ml suc proaspat de lamaie (cca 1 lamaie mare), plus dupa gust","4 linguri ulei de masline extravirgin, impartit","1 lingurita chimen macinat","1/2 lingurita coriandru macinat","1/2 lingurita sare fina de mare, plus dupa gust","1/4 lingurita ardei iute macinat sau boia picanta","2 rosii mijlocii coapte (cca 250 g), taiate marunt","1 ceapa rosie mica (cca 100 g), taiata marunt","20 g patrunjel plat, frunzele tocate grosier"]},"howIsMade":{"ar":"إذا كنت تستخدم الفول المجفف، صفّه وغطّه بماء بارد طازج بارتفاع 4-5 سم؛ أحضره للغليان واطبخه على نار هادئة 1.5 إلى 2 ساعة حتى يصبح ناعمًا تمامًا عند الضغط عليه بين الأصابع؛ صفّه محتفظًا بـ 100 مل من ماء الطبخ. إذا كنت تستخدم الفول المعلب، اغسله وصفّه واستخدم 100 مل ماء كسائل. أعد الفول إلى الوعاء على نار خفيفة وأضف الثوم وعصير الليمون و3 ملاعق كبيرة من زيت الزيتون والكمون والكزبرة والملح والفلفل الحار. اطبخ 3-4 دقائق مع هرس نحو نصف الفول بشوكة لتحصل على قوام كريمي لكن خشن جزئيًا، مضيفًا السائل المحفوظ رشًا رشًا إن كان ثقيلًا جدًا. تذوق واضبط الليمون والملح والبهارات — يجب أن يكون الفول لاذعًا ومتبلًا جيدًا. قسّمه في صحون ضحلة وانثر الطماطم المقطعة والبصل الأحمر والبقدونس فوقه. ارشش الملعقة الكبيرة المتبقية من زيت الزيتون فوق كل وجبة وقدّم فورًا مع خبز البيتا الدافئ.","en":"If using dried beans, drain the soaked beans and cover with fresh cold water by 4-5 cm; bring to the boil and simmer for 1.5 to 2 hours until the beans are completely soft when pressed between fingers, then drain, reserving 100 ml of cooking liquid. If using canned beans, rinse, drain, and use 100 ml of water as the liquid. Return the beans to the pot over low heat and add the garlic, lemon juice, 3 tbsp of the olive oil, cumin, coriander, salt, and cayenne. Cook for 3-4 minutes, mashing about half the beans with a fork to create a creamy, partly chunky texture, adding reserved cooking liquid a splash at a time if too thick. Taste and adjust lemon, salt, and spice — the ful should be tangy and warmly spiced. Divide into shallow bowls and scatter the diced tomatoes, red onion, and parsley over the top. Drizzle the remaining 1 tbsp olive oil over each serving and serve immediately with warm pita bread."}},{"id":59,"servings":4,"tipType":"fish","timeMins":{"total":50,"active":40},"pairingsType":"mediterranean","origin":{"ar":"كرواتيا","en":"Croatia","ro":"Croația"},"name":{"ar":"تشرني ريجوت","en":"Crni Rizot","ro":"Crni Rižot"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["500 غ كاليماري طازج أو مُذاب، منظف، مع الاحتفاظ بـ 2-3 أكياس حبر","300 غ أرز أربوريو أو كارناولي","1 بصلة متوسطة (نحو 150 غ)، مفرومة ناعمًا","3 فصوص ثوم، مفرومة ناعمًا","100 مل نبيذ أبيض دالماتي جاف (أو Pošip)","1 لتر مرق سمك دافئ (أو ماء مع 1 مكعب مرق سمك)","60 مل زيت زيتون بكر ممتاز","30 غ زبدة باردة، مقطعة مكعبات","2 ملعقة كبيرة بقدونس طازج، مفروم","1/2 ليمونة، العصير فقط","1 ملعقة صغيرة ملح بحري ناعم","1/2 ملعقة صغيرة فلفل أسود مطحون"],"en":["500 g fresh or thawed squid, cleaned, with 2-3 ink sacs reserved","300 g arborio or carnaroli rice","1 medium onion (about 150 g), finely chopped","3 garlic cloves, finely minced","100 ml dry Dalmatian white wine (or Pošip)","1 litre warm fish stock (or water with 1 fish stock cube)","60 ml extra-virgin olive oil","30 g cold butter, cubed","2 tbsp fresh parsley, chopped","1/2 lemon, juice only","1 tsp fine sea salt","1/2 tsp ground black pepper"],"ro":["500 g calmari proaspeti sau decongelati, curatati, cu 2-3 saculeti de cerneala separati","300 g orez arborio sau carnaroli","1 ceapa medie (cca 150 g), tocata marunt","3 căței de usturoi, tocati marunt","100 ml vin alb sec dalmatian (sau Pošip)","1 litru fond de peste cald (sau apa cu 1 cub de fond de peste)","60 ml ulei de masline extravirgin","30 g unt rece, taiat cubulete","2 linguri patrunjel proaspat, tocat","1/2 lamaie, doar zeama","1 lingurita sare fina de mare","1/2 lingurita piper negru macinat"]},"howIsMade":{"ar":"نظف الكاليماري بعناية: أخرج أكياس الحبر سليمة إلى وعاء صغير مع قليل من الماء، ثم قطع الأجسام إلى حلقات 1 سم وقسم المجسات نصفين. في مقلاة واسعة وثقيلة، سخن 4 ملاعق كبيرة زيت زيتون على نار متوسطة وقلب البصل 4-5 دقائق حتى يلين، ثم أضف الثوم لدقيقة أخرى. أضف حلقات الكاليماري والمجسات، قلب 2-3 دقائق حتى تصبح معتمة، ثم أضف النبيذ واتركه يتبخر تمامًا (نحو دقيقتين). أضف الأرز وقلب لدقيقة ليغطى بالدهن، ثم ابدأ بإضافة مرق السمك الساخن مغرفة تلو الأخرى، مع التقليب المستمر لمدة 16-18 دقيقة إجمالًا. في منتصف الطهي، اكسر أكياس الحبر في المرق المتبقي وأضفه — يتحول الريزوتو إلى أسود عميق فورًا ويكتسب عمقًا بحريًا قويًا. عندما يصبح الأرز al dente وكريميًا مع بقاء قليل من المرق، أطفئ النار وأضف الزبدة الباردة والملعقتين الكبيرتين المتبقيتين من زيت الزيتون وعصير الليمون والبقدونس. قلب بقوة 30 ثانية للمنتيكاتورا، غطِ واتركه يرتاح دقيقتين. قدمه فورًا في أطباق عميقة مع المزيد من البقدونس فوقه وشريحة ليمون بجانبه.","en":"Clean the squid carefully: lift out the ink sacs intact into a small bowl with a splash of water, then cut the bodies into 1 cm rings and halve the tentacles. In a wide heavy pan, heat 4 tbsp olive oil over medium heat and sauté the onion for 4-5 minutes until soft, then add the garlic for 1 minute more. Add the squid rings and tentacles, sauté for 2-3 minutes until just opaque, then pour in the wine and let it evaporate completely (about 2 minutes). Add the rice and stir for 1 minute to coat with fat, then begin adding the hot fish stock one ladle at a time, stirring constantly for 16-18 minutes total. Halfway through, break the ink sacs into the remaining stock and pour it in — the risotto turns deep jet black instantly and gains a profound oceanic depth. When the rice is al dente and creamy with a little stock still pooling, kill the heat and add the cold butter, the remaining 2 tbsp olive oil, the lemon juice, and the parsley. Stir vigorously for 30 seconds for the mantecatura, then cover and rest for 2 minutes. Serve immediately in shallow bowls with extra parsley on top and a wedge of lemon alongside."}},{"id":60,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ar":"منغوليا","en":"Mongolia","ro":"Mongolia"},"name":{"ar":"بوز","en":"Buuz","ro":"Buuz"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["العجينة: 300 غ دقيق أبيض مع إضافي للتبطين","150 مل ماء دافئ (نحو 50 درجة)","1/2 ملعقة صغيرة ملح ناعم","الحشوة: 400 غ لحم ضأن مفروم (أو نصف ضأن ونصف بقري)","1 بصلة متوسطة (نحو 150 غ)، مفرومة ناعمًا","3 فصوص ثوم، مفرومة ناعمًا","2 ملاعق كبيرة زيت عباد الشمس","1 ملعقة صغيرة كمون مطحون","1 ملعقة صغيرة ملح بحري ناعم","1/2 ملعقة صغيرة فلفل أسود مطحون","50 مل ماء بارد"],"en":["Dough: 300 g all-purpose flour, plus extra for dusting","150 ml warm water (about 50 C)","1/2 tsp fine salt","Filling: 400 g ground lamb (or half lamb, half beef)","1 medium onion (about 150 g), finely diced","3 garlic cloves, finely minced","2 tbsp sunflower oil","1 tsp ground cumin","1 tsp fine sea salt","1/2 tsp ground black pepper","50 ml cold water"],"ro":["Aluat: 300 g făină alba, plus extra pentru intins","150 ml apa calda (cca 50 C)","1/2 lingurita sare fina","Umplutura: 400 g carne de miel tocata (sau amestec miel-vita)","1 ceapa medie (cca 150 g), taiata marunt","3 căței de usturoi, tocati marunt","2 linguri ulei de floarea-soarelui","1 lingurita chimen macinat","1 lingurita sare fina de mare","1/2 lingurita piper negru macinat","50 ml apa rece"]},"howIsMade":{"ar":"اعجن العجينة: اخلط الدقيق مع الملح، أضف الماء الدافئ واعجن 5-6 دقائق حتى تصبح ناعمة ومرنة. غطها بقماش رطب واتركها ترتاح 30 دقيقة. اعمل الحشوة: اخلط اللحم المفروم والبصل والثوم والزيت والكمون والملح والفلفل والماء البارد في وعاء وامزج جيدًا باليدين حتى يتجانس المزيج ويصبح لزجًا قليلًا. قسم العجينة إلى 20-24 قطعة متساوية (نحو 20 غ كل منها) وافرد كل قطعة في دائرة رفيعة نحو 10 سم مع ترك المنتصف اسمك قليلًا من الحواف. ضع ملعقة كبيرة ممتلئة (نحو 25 غ) من الحشوة في مركز كل دائرة. ارفع الحواف حول الحشوة واطوِها معًا من الأعلى تاركًا ثقبًا صغيرًا للبخار في المنتصف. بطن سلة البخار بورق الزبدة وارتب الحبوب في طبقة واحدة بمسافة 2 سم بين كل منها. أحضر الماء في مقلاة وسيعة للغليان الشديد وضع السلة فوقها وابخر 20-22 دقيقة حتى تنضج العجينة تمامًا وتتوقف الحشوة عن كونها وردية. قدم فورًا.","en":"Make the dough: mix flour and salt, pour in the warm water, and knead for 5-6 minutes until smooth and elastic. Cover with a damp cloth and rest for 30 minutes. Make the filling: combine the lamb, onion, garlic, oil, cumin, salt, pepper, and cold water in a bowl and mix well with your hands until evenly combined and slightly sticky. Divide the dough into 20-24 equal pieces (about 20 g each) and roll each into a thin round about 10 cm across, keeping the centre slightly thicker than the edges. Place 1 heaped tablespoon (about 25 g) of filling in the centre of each round. Lift the edges up around the filling and pleat them together at the top, leaving a small steam hole in the centre — the classic Mongolian shape. Line a bamboo steamer with parchment paper or cabbage leaves and arrange the buuz in a single layer with 2 cm between each. Fill a wok or wide pot with water and bring to a rolling boil; set the steamer basket over the boiling water and steam for 20-22 minutes until the dough is cooked through and the filling is no longer pink inside. Serve immediately."}},{"id":61,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ar":"باكستان","en":"Pakistan","ro":"Pakistan"},"name":{"ar":"برياني","en":"Biryani","ro":"Biryani"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["800 غ أفخاذ دجاج منزوعة العظم (أو كتف ضأن)، مقطعة قطعاً كبيرة، مع العظم إن أمكن","200 غ لبن زبادي كامل الدسم، مخفوق","2 ملعقة كبيرة معجون زنجبيل وثوم","1 ملعقة صغيرة جرام ماسالا","1 ملعقة صغيرة فلفل حار مطحون","1/2 ملعقة صغيرة كركم","1 ملعقة صغيرة ملح","3 ملاعق كبيرة حليب دافئ + رشة خيوط زعفران","400 غ أرز بسمتي","2.5 لتر ماء (لسلق الأرز جزئياً)","4 ملاعق كبيرة سمن","4 حبات هيل أخضر","2 حبة هيل أسود","1 عود قرفة","6 حبات قرنفل","2 ورقة غار","2 بصلة كبيرة، مقطعة شرائح رفيعة","2 حبة طماطم متوسطة، مبشورة","2 ملعقة كبيرة نعناع طازج مفروم","2 ملعقة كبيرة كزبرة طازجة مفرومة","1 ملعقة كبيرة سمن إضافي، مذاب (للتنقيط)","للتقديم: رايتا زبادي باردة، شرائح ليمون"],"en":["800g boneless chicken thighs (or lamb shoulder), cut into large pieces, bone-in if possible","200g plain whole-milk yoghurt, whisked","2 tbsp ginger-garlic paste","1 tsp garam masala","1 tsp chilli powder","1/2 tsp turmeric","1 tsp salt","3 tbsp warm milk + a pinch of saffron threads","400g basmati rice","2.5 litres water (for par-boiling the rice)","4 tbsp ghee","4 green cardamom pods","2 black cardamom pods","1 cinnamon stick","6 cloves","2 bay leaves","2 large onions, thinly sliced","2 medium tomatoes, grated","2 tbsp chopped fresh mint","2 tbsp chopped fresh coriander","1 tbsp extra ghee, melted (to drizzle)","To serve: cold yoghurt raita, lemon wedges"],"ro":["800 g pulpe de pui dezosate (sau spata de miel), taiate cuburi mari, cu os daca este posibil","200 g iaurt gras de vaca, batut","2 linguri pasta de ghimbir-usturoi","1 lingurita garam masala","1 lingurita pudra de chili","1/2 lingurita turmeric","1 lingurita sare","3 linguri lapte cald + un varf de fire de sofran","400 g orez basmati","2,5 l apa (pentru fierberea partiala a orezului)","4 linguri ghee","4 capsule cardamom verde","2 capsule cardamom negru","1 bat de scortisoara","6 cuișoare","2 foi de dafin","2 cepe mari, taiate solzi subtiri","2 rosii medii, rase","2 linguri menta proaspata, tocata","2 linguri coriandru proaspat, tocat","1 lingura ghee suplimentar, topit (pentru stropit)","Pentru servit: raita de iaurt rece, felii de lamaie"]},"howIsMade":{"ar":"اخلط 800 غ دجاج (أو لحم ضأن) مع 200 غ لبن زبادي مخفوق، 2 ملعقة كبيرة معجون زنجبيل وثوم، 1 ملعقة صغيرة جرام ماسالا، 1 ملعقة صغيرة فلفل حار مطحون، 1/2 ملعقة صغيرة كركم، 1 ملعقة صغيرة ملح ورشة خيوط زعفران منقوعة في 3 ملاعق كبيرة حليب دافئ؛ غطّ واترك التتبيلة ساعة على الأقل، ويفضل 4 ساعات في الثلاجة. أذب 4 ملاعق كبيرة سمن أو زيت في قدر ثقيل القاع على نار متوسطة؛ حين يلمع، أضف 4 حبات هيل أخضر، 2 حبة هيل أسود، 1 عود قرفة، 4 قرنفل و1 ورقة غار، واتركها تتفتح 30 ثانية حتى تطقطق برفق. أضف 2 بصلة كبيرة مقطعة شرائح رفيعة وحمّرها 12-15 دقيقة مع التحريك المتكرر حتى تصبح بنية داكنة ومقرمشة؛ ارفع نصفها على ورق مطبخ للتزيين واترك الباقي في القدر مع الزيت المعطر. أنزل اللحم المتبل إلى القدر مع 2 حبة طماطم مبشورة واطبخه 8-10 دقائق على نار متوسطة مع التحريك حتى ينفصل اللبن ويظهر الزيت على الأطراف؛ خفف النار وغطّ القدر واطبخ 15 دقيقة إضافية حتى يقارب اللحم النضج ويبقى الصلصة كثيفة. في هذه الأثناء اغسل 400 غ أرز بسمتي حتى يصبح الماء صافياً وانقعه 30 دقيقة؛ اغلِ 2.5 لتر ماء مع 2 ملعقة صغيرة ملح، 3 حبات هيل، 1 عود قرفة و2 ورقة غار، أضف الأرز وبضع قطرات زيت واطبخ 5-6 دقائق بالضبط حتى تصل الحبات إلى 70% من النضج — لا تزال صلبة في القلب؛ صفِّه فوراً. وزّع نصف الأرز المصفى فوق مسالا اللحم، رشّ نصف البصل المقلي و2 ملعقة كبيرة نعناع مفروم و2 ملعقة كبيرة كزبرة، ثم غطِّ بالأرز المتبقي؛ نقّط 4 ملاعق كبيرة حليب دافئ بالزعفران و2 ملعقة كبيرة سمن مذاب، وأنهِ بباقي البصل والنعناع والكزبرة. أغلق القدر بغطاء محكم (أو غطِّ بورق ألمنيوم واضغط الغطاء فوقه)، ضعه على أهدأ نار ممكنة، ويفضل فوق ناشر حرارة أو صاج حديدي، واطبخ على الدم 25 دقيقة دون رفع الغطاء — البخار المحتبس يكمل الأرز واللحم في وقت واحد. أطفئ النار واترك القدر المغلق يستريح 10 دقائق؛ افتح، فكّك الأرز برفق من الجانب إلى الداخل لتختلط طبقات اللحم والأرز، وقدّم فوراً مع رايتا زبادي بارد وشرائح ليمون.","en":"Mix 800 g chicken (or lamb) with 200 g whisked yoghurt, 2 tbsp ginger-garlic paste, 1 tsp garam masala, 1 tsp chilli powder, 1/2 tsp turmeric, 1 tsp salt and a pinch of saffron threads soaked in 3 tbsp warm milk; cover and marinate at least 1 hour, ideally 4 hours in the fridge. Melt 4 tbsp ghee or oil in a heavy-bottomed pot over medium heat; when it shimmers, add 4 green cardamom pods, 2 black cardamom pods, 1 cinnamon stick, 4 cloves and 1 bay leaf and let them bloom for 30 seconds until they crackle lightly. Add 2 large onions sliced thin and fry for 12-15 minutes, stirring often, until deep brown and crisp; lift out half onto kitchen paper for garnish and leave the rest in the pot with the aromatic oil. Slide the marinated meat into the pot with 2 grated tomatoes and cook 8-10 minutes over medium heat, stirring until the yoghurt breaks and the oil rises to the edges; lower the heat and simmer covered another 15 minutes until the meat is almost tender but the sauce stays thick. Meanwhile rinse 400 g basmati rice until the water runs clear and soak for 30 minutes; bring 2.5 litres of water to the boil with 2 tsp salt, 3 cardamom pods, 1 cinnamon stick and 2 bay leaves, slip in the rice with a few drops of oil and cook for exactly 5-6 minutes until the grains are 70% done — still firm in the centre; drain at once. Spread half of the drained rice over the meat masala, scatter half of the fried onions, 2 tbsp chopped mint and 2 tbsp coriander, then layer the remaining rice on top; drizzle with 4 tbsp warm saffron milk and 2 tbsp melted ghee, and finish with the remaining onions, mint and coriander. Seal the pot with a tight lid (or cover with foil and press the lid down), set it on the lowest possible flame, ideally over a heat diffuser or a cast-iron tava, and dum cook for 25 minutes without lifting the lid — the trapped steam finishes the rice and meat together. Turn off the heat and let the sealed pot rest for 10 minutes; open, gently fluff from the side inwards to fold the meat and rice layers, and serve straight away with cold yoghurt raita and lemon wedges."},"timeMins":{"total":105,"active":50}},{"id":62,"servings":4,"tipType":"def","pairingsType":"middle-eastern","origin":{"ar":"تونس","en":"Tunisia","ro":"Tunisia"},"name":{"ar":"بريك","en":"Brik","ro":"Brik"},"category":{"ar":"وجبة خفيفة","en":"Snack","ro":"Gustare"},"ingredients":{"ar":["4 أوراق من عجينة البريك (أو ملسوقة/وارقة)، نحو 30 سم قطرًا (أو أوراق لفائف الربيع كبديل)","4 بيضات كبيرة (واحدة لكل بريك)","160 غ تونة معلبة بزيت الزيتون، مصفاة جيدًا","1 بصلة صغيرة (نحو 80 غ)، مفرومة ناعمًا","3 ملاعق كبيرة كبر صغير، مغسول ومقطع خشنًا","20 غ بقدونس ورق مسطح، مفروم ناعمًا","1/2 ملعقة صغيرة كمون مطحون","1/2 ملعقة صغيرة ملح بحري ناعم","1/4 ملعقة صغيرة فلفل حار مطحون أو معجون هريسة","500 مل زيت نباتي للقلي العميق","1 ليمونة مقطعة إلى 4 أجزاء للتقديم"],"en":["4 sheets of brik pastry (or malsouka/ouarka), about 30 cm in diameter (or spring roll wrappers as substitute)","4 large eggs (1 per brik)","160 g canned tuna in olive oil, well drained","1 small onion (about 80 g), finely diced","3 tbsp small capers, rinsed and roughly chopped","20 g flat-leaf parsley, finely chopped","1/2 tsp ground cumin","1/2 tsp fine sea salt","1/4 tsp cayenne pepper or harissa paste","500 ml vegetable oil for deep-frying","1 lemon, cut into 4 wedges, to serve"],"ro":["4 foi de brik (sau malsouka/ouarka), cca 30 cm diametru (sau foi de spring roll ca substitut)","4 oua mari (1 pe brik)","160 g ton la conserva in ulei de masline, bine scurs","1 ceapa mica (cca 80 g), taiata marunt","3 linguri capere mici, clatite si tocate grosier","20 g patrunjel plat, tocat marunt","1/2 lingurita chimen macinat","1/2 lingurita sare fina de mare","1/4 lingurita ardei iute macinat sau harissa","500 ml ulei vegetal pentru prajit adanc","1 lamaie, taiata in 4, pentru servire"]},"howIsMade":{"ar":"اخلط التونة المصفاة والبصل والكبر والبقدونس والكمون والملح والفلفل الحار في وعاء لتحضير الحشوة. صب الزيت النباتي في مقلاة عميقة واسعة حتى عمق 3-4 سم وسخنه إلى 175 درجة. افرد ورقة بريك على سطح نظيف وضع ربع حشوة التونة على النصف السفلي مع عمل تجويف صغير في الوسط. اكسر بيضة في التجويف. بسرعة، اطو الورقة إلى النصف لتشكل هلالًا واضغط الحواف بإحكام لإغلاقها ومنع البيضة من الخروج. انزلق بريك بحذر في الزيت الساخن واقله 1.5-2 دقيقة من كل جهة حتى يتحول لذهبي عميق ومقرمش، مع تقليب مرة واحدة بملعقة مفلطحة واسعة. ارفعه بملعقة مثقبة وجففه على ورق المطبخ 30 ثانية. قدم فورًا -- يجب أن يكون الصفار سائلًا إلى شبه متماسك والعجين مقرمشًا. اعصر شريحة ليمون فوقه.","en":"Combine the drained tuna, onion, capers, parsley, cumin, salt, and cayenne in a bowl and mix well to make the filling. Pour the vegetable oil into a deep, wide pan to a depth of 3-4 cm and heat to 175°C. Lay a brik pastry sheet flat on a clean surface and spoon a quarter of the tuna filling onto the lower half, creating a slight hollow in the centre. Crack 1 egg into the hollow. Working quickly, fold the pastry in half to form a half-moon, pressing the edges firmly together to seal and prevent the egg from escaping. Carefully slide the brik into the hot oil and fry for 1.5-2 minutes per side until deep golden and crisp all over, flipping once with a wide spatula. Lift out with a slotted spoon and drain on paper towels for 30 seconds. Serve immediately — the yolk should be runny to lightly set and the pastry crackling crisp. Squeeze a lemon wedge over the top."}},{"id":63,"servings":4,"tipType":"def","pairingsType":"def","origin":{"ar":"جورجيا","en":"Georgia","ro":"Georgia"},"name":{"ar":"خاتشابوري","en":"Khachapuri","ro":"Khachapuri"},"category":{"ar":"فطور","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"ar":["500 غ دقيق أبيض للأغراض العامة، مع القليل للتغطية","7 غ خميرة فورية (كيس واحد)","1 ملعقة صغيرة سكر","1 ملعقة صغيرة ملح ناعم","250 مل ماء دافئ (حوالي 40 درجة مئوية)","2 ملعقة كبيرة زيت زيتون","400 غ جبن سولوغوني أو موزاريلا، مبشور خشن","200 غ جبن فيتا، مفتت","4 بيضات كبيرة (1 لكل خاتشابوري)","40 غ زبدة غير مملحة، مقطعة إلى 4 قطع متساوية"],"en":["500 g plain flour (all-purpose), plus extra for dusting","7 g instant yeast (1 sachet)","1 tsp caster sugar","1 tsp fine sea salt","250 ml warm water (about 40°C / 105°F)","2 tbsp olive oil","400 g sulguni or mozzarella, coarsely grated","200 g feta cheese, crumbled","4 large eggs (1 per khachapuri)","40 g unsalted butter, cut into 4 equal pieces"],"ro":["500 g făină albă, plus extra pentru pudrare","7 g drojdie instant (1 plic)","1 linguriță zahăr","1 linguriță sare fină de mare","250 ml apă caldă (aproximativ 40°C)","2 linguri ulei de măsline","400 g suluguni sau mozzarella, ras grosier","200 g brânză feta, sfărâmată","4 ouă mari (câte 1 pentru fiecare khachapuri)","40 g unt nesărat, tăiat în 4 bucăți egale"]},"howIsMade":{"ar":"اخلط الدقيق والخميرة والسكر والملح في وعاء كبير، أضف الماء الدافئ وزيت الزيتون واعجن المكونات معاً، ثم اعجن على سطح مرشوش بالقليل من الدقيق لمدة 8-10 دقائق حتى يصبح العجين ناعماً ولزجاً قليلاً. شكّل كرة وضعها في وعاء مدهون بالزيت، غطِّها بقماش مبلل واتركها في مكان دافئ لمدة ساعة حتى يتضاعف حجمها. أثناء تخمر العجين، اخلط الجبن المبشور (سولوغوني أو موزاريلا) مع جبن الفيتا المفتت في وعاء؛ سخّن الفرن إلى 250 درجة مع وضع صينية ثقيلة أو حجر بيتزا بداخله. قسّم العجين المتخمر إلى 4 أجزاء متساوية وافرد كل جزء على سطح مرشوش بالدقيق على شكل بيضاوي بأبعاد تقريبية 25 x 15 سم. طوِ الحواف الطويلة للداخل بمقدار 3 سم ولفّها لتشكيل حافة مرتفعة، ثم اضغط طرفي القصير معاً بإحكام لتشكيل قارب. ضع القوارب على ورق زبدة، واملأ كل تجويف بالكامل بربع خليط الجبن، وانقلها إلى الصينية الساخنة واخبزها 12-14 دقيقة حتى تصبح القشرة ذهبية ويفور الجبن ويتحمر قليلاً. أخرج من الفرن، اصنع تجويفاً صغيراً في وسط كل حشوة، اكسر بيضة واحدة في كل تجويف وأعد للفرن لمدة 3-4 دقائق حتى يتماسك البياض ويبقى الصفار سائلاً. ضع قطعة زبدة على كل بيضة وقدّم فوراً — اقطع شرائح من حافة الخبز وامتصها في الجبن المذاب والصفار.","en":"Mix the flour, yeast, sugar, and salt in a large bowl, add the warm water and olive oil and stir to a rough dough, then knead on a lightly floured surface for 8-10 minutes until smooth and slightly tacky. Shape into a ball, place in an oiled bowl, cover with a damp cloth, and leave in a warm place for 1 hour until doubled in size. While the dough rises, mix the grated sulguni (or mozzarella) and crumbled feta together in a bowl; heat the oven to 250°C (230°C fan) with a heavy baking tray or pizza stone inside. Divide the risen dough into 4 equal pieces and roll each on a lightly floured surface into an oval about 25 x 15 cm. Fold the long edges inward by 3 cm and roll them up into a thick raised border, then pinch both short ends firmly together to form a boat shape. Arrange the boats on baking parchment, fill each cavity completely with a quarter of the cheese mixture, then slide onto the hot tray and bake for 12-14 minutes until the crust is golden and the cheese is bubbling and lightly browned. Remove from the oven, press a small hollow in the centre of each cheese filling, crack 1 egg into each hollow, and return to the oven for 3-4 minutes until the white is just set but the yolk remains runny. Place a piece of butter on top of each egg and serve immediately — tear strips of the border and dip into the melted cheese and yolk."}},{"id":64,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ar":"جنوب أفريقيا","en":"South Africa","ro":"Africa de Sud"},"name":{"ar":"بوبوتي","en":"Bobotie","ro":"Bobotie"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["750 غ لحم بقري أو ضأن مفروم قليل الدهون","2 بصلة متوسطة (حوالي 300 غ)، مفرومة ناعماً","2 شريحة خبز أبيض (حوالي 60 غ)، بدون قشور","125 مل حليب كامل الدسم، مقسم","2 بيضة كبيرة","50 غ زبيب سلطانة","30 غ مشمش مجفف (حوالي 6 حبات)، مفروم ناعماً","2 ملعقة كبيرة مربى مشمش أو صلصة تشتني حلوة","2 ملعقة كبيرة مسحوق كاري خفيف","1 ملعقة صغيرة كركم مطحون","2 ملعقة كبيرة زيت نباتي","1 ملعقة صغيرة ملح ناعم","1/2 ملعقة صغيرة فلفل أسود مطحون","4 أوراق غار طازجة أو مجففة"],"en":["750 g lean beef or lamb mince","2 medium onions (about 300 g total), finely diced","2 slices white bread (about 60 g), crusts removed","125 ml whole milk, divided","2 large eggs","50 g sultanas (golden raisins)","30 g dried apricots (about 6), finely chopped","2 tbsp apricot jam or sweet chutney","2 tbsp mild curry powder","1 tsp ground turmeric","2 tbsp vegetable oil","1 tsp fine sea salt","1/2 tsp ground black pepper","4 fresh or dried bay leaves"],"ro":["750 g carne tocată de vită sau miel, slabă","2 cepe medii (aproximativ 300 g), fin tocate","2 felii pâine albă (aproximativ 60 g), fără coajă","125 ml lapte integral, împărțit","2 ouă mari","50 g stafide galbene (sultane)","30 g caise uscate (aproximativ 6 bucăți), fin tocate","2 linguri gem de caise sau chutney dulce-picant","2 linguri pudră de curry blând","1 linguriță turmeric măcinat","2 linguri ulei vegetal","1 linguriță sare fină de mare","1/2 linguriță piper negru măcinat","4 foi de dafin proaspete sau uscate"]},"howIsMade":{"ar":"انقع الخبز في 60 مل من الحليب لمدة 5 دقائق، ثم اعصره وفتته في وعاء صغير. سخّن الزيت في مقلاة كبيرة على نار متوسطة-عالية، أضف البصل واطهه مع التقليب 8-10 دقائق حتى يلين ويصبح ذهبي اللون. أضف الكاري والكركم وقلّب دقيقة حتى تفوح الرائحة، ثم أضف اللحم المفروم واطهه 8-10 دقائق مع تفتيته حتى يتحمر وتتبخر السوائل. ارفع عن النار واخلط الخبز المنقوع والزبيب والمشمش والمربى والملح والفلفل حتى يتجانس الخليط. سخّن الفرن إلى 180 درجة ودهن طبق خبز متوسط (حوالي 25 x 20 سم) بالزيت قليلاً. انقل خليط اللحم إلى الطبق، اضغطه في طبقة منتظمة واغرز أوراق الغار في السطح. اخفق البيض مع 65 مل الحليب المتبقي ورشة ملح حتى يصبح ناعماً، ثم صبّه بالتساوي فوق اللحم. اخبز 35-40 دقيقة حتى يتماسك الغطاء الكريمي ويصبح ذهبي اللون دون اهتزاز في المركز. ارحه 5 دقائق ثم قدّمه مع الأرز الأصفر والشتني.","en":"Soak the bread in 60 ml of the milk for 5 minutes, then squeeze out the excess liquid and crumble into a small bowl. Heat the oil in a large frying pan over medium-high heat, add the onions and cook, stirring, for 8-10 minutes until soft and golden. Add the curry powder and turmeric and stir for 1 minute until fragrant, then add the mince and cook for 8-10 minutes, breaking up any lumps, until browned and all liquid has evaporated. Remove from the heat and mix in the soaked bread, sultanas, dried apricots, apricot jam, salt, and pepper until evenly combined. Heat the oven to 180°C (160°C fan) and lightly grease a medium baking dish (about 25 x 20 cm). Transfer the meat mixture into the dish, press it into an even layer, and tuck the bay leaves into the surface. Beat the eggs with the remaining 65 ml milk and a pinch of salt until smooth, then pour evenly over the meat. Bake for 35-40 minutes until the custard topping is set and golden brown with no wobble in the centre. Rest for 5 minutes before serving with yellow rice, chutney, and sambals."}},{"id":65,"servings":4,"tipType":"fish","pairingsType":"latin","origin":{"ar":"بيرو","en":"Peru","ro":"Peru"},"name":{"ar":"سيفيتشي","en":"Ceviche","ro":"Ceviche"},"category":{"ar":"وجبة خفيفة","en":"Snack","ro":"Gustare"},"ingredients":{"ar":["700 غ شرائح سمك أبيض طازج جداً (قاروص، موسى، أو هلبوت)، منزوع الجلد والعظام","180 مل عصير ليمون أخضر طازج (حوالي 8-10 ليمونات)، أكثر حسب الذوق","1 بصلة حمراء صغيرة (حوالي 150 غ)، مقطعة نصف حلقات رفيعة","1-2 فلفل أجي أماريو أو 1 خال من البذور ومفروم ناعماً","1 فص ثوم، مبشور ناعماً","1 ملعقة صغيرة زنجبيل طازج (نحو 1 سم)، مبشور ناعماً","30 غ كزبرة طازجة، أوراق وسيقان رفيعة، مفرومة خشناً","1 ملعقة صغيرة ملح ناعم","1/4 ملعقة صغيرة فلفل أبيض مطحون","2 كوز ذرة، مسلوق ومقطع قطعاً بطول 5 سم","2 بطاطا حلوة صغيرة (حوالي 400 غ)، مسلوقة حتى النضج، مقشرة ومقطعة شرائح"],"en":["700 g very fresh white fish fillets (sea bass, sole, or halibut), skin and bones removed","180 ml fresh lime juice (about 8-10 limes), plus more to taste","1 small red onion (about 150 g), halved and thinly sliced into half-moons","1-2 ají amarillo chillies or 1 jalapeño, deseeded and finely diced","1 garlic clove, finely grated","1 tsp fresh ginger (about 1 cm piece), finely grated","30 g fresh coriander (cilantro), leaves and fine stems, roughly chopped","1 tsp fine sea salt","1/4 tsp ground white pepper","2 ears of corn, boiled and cut into 5 cm rounds","2 small sweet potatoes (about 400 g), boiled until tender, peeled and sliced"],"ro":["700 g file de pește alb foarte proaspăt (biban de mare, limbă sau halibut), fără piele și oase","180 ml suc proaspăt de lime (aproximativ 8-10 lime-uri), plus extra după gust","1 ceapă roșie mică (aproximativ 150 g), tăiată felii subțiri în jumătate de lună","1-2 ardei ají amarillo sau 1 jalapeño, fără semințe, fin tocați","1 căței de usturoi, fin ras","1 linguriță ghimbir proaspăt (aproximativ 1 cm), fin ras","30 g coriandru proaspăt, frunze și tulpini subțiri, grosier tocat","1 linguriță sare fină de mare","1/4 linguriță piper alb măcinat","2 știuleți de porumb, fierți și tăiați în rondele de 5 cm","2 cartofi dulci mici (aproximativ 400 g), fierți, curățați și feliați"]},"howIsMade":{"ar":"جفّف السمك بمناشف ورقية وقطّعه مكعبات بحجم 2 سم مع إزالة أي عظام متبقية، ثم ضعه في وعاء غير تفاعلي (زجاج أو خزف). تبّله بالملح والفلفل الأبيض واخلطه. أضف البصل الأحمر والفلفل والثوم والزنجبيل واخلط بلطف. صبّ عصير الليمون — يجب أن يغطي السمك تقريباً — ثم اخلط برفق واضغط على السمك لإغراقه قدر الإمكان. غطِّ الوعاء وضعه في الثلاجة 10-15 دقيقة مع تقليب مرة في المنتصف، حتى يصبح خارج كل مكعب معتماً وثابتاً قليلاً عند اللمس بينما يبقى المركز شفافاً قليلاً — الأسلوب البيروفي الكلاسيكي. اضبط الملح وعصير الليمون حسب الذوق. اخلط معظم الكزبرة مع الاحتفاظ ببعضها للتزيين. قدّم فوراً في أطباق باردة مع أسطوانات الذرة وشرائح البطاطا الحلوة، ورش الكزبرة المتبقية فوقه.","en":"Pat the fish dry with paper towels and cut into 2 cm cubes, removing any remaining pin bones, then place in a non-reactive bowl (glass or ceramic). Season with the salt and white pepper and toss to coat. Add the red onion, chilli, garlic, and ginger and mix gently. Pour over the lime juice — it should nearly cover the fish — then stir gently and press the fish down to submerge it as much as possible. Cover and refrigerate for 10-15 minutes, stirring once halfway through, until the outside of each cube is opaque and just firm to the touch while the very centre remains slightly translucent — the classic Peruvian style, not fully cooked through. Taste and adjust salt and lime juice. Stir in most of the coriander, reserving a little for garnish. Serve immediately in chilled bowls alongside the corn rounds and sweet potato slices, with the remaining coriander scattered over the top."}},{"id":66,"servings":8,"tipType":"korean","pairingsType":"korean","origin":{"ar":"كوريا الجنوبية","en":"South Korea","ro":"Coreea de Sud"},"name":{"ar":"كيمتشي","en":"Kimchi","ro":"Kimchi"},"category":{"ar":"طبق جانبي","en":"Side dish","ro":"Garnitură"},"ingredients":{"ar":["1 كرنب صيني كبير (نحو 2 كيلو)","3 ملاعق كبيرة ملح بحر غير معالج باليود","4 ملاعق كبيرة غوتشوغارو (رقائق فلفل كوري أحمر)","5 فصوص ثوم مفرومة ناعماً","1 ملعقة صغيرة زنجبيل طازج مبشور","1 ملعقة كبيرة صلصة سمك (أو صويا للنباتيين)","1 ملعقة صغيرة سكر","6 بصل أخضر مقطع 3سم","1 جزرة متوسطة مقطعة شرائح"],"en":["1 large napa cabbage (about 2 kg)","3 tbsp sea salt (non-iodised)","4 tbsp gochugaru (Korean red pepper flakes)","5 cloves garlic, finely minced","1 tsp fresh ginger, grated","1 tbsp fish sauce (or soy sauce for vegan)","1 tsp sugar","6 spring onions, cut into 3cm pieces","1 medium carrot, julienned"],"ro":["1 varză napa mare (aprox. 2 kg)","3 linguri sare de mare (fără iod)","4 linguri gochugaru (fulgi de ardei coreean)","5 căței de usturoi, tocați mărunt","1 linguriță ghimbir proaspăt, ras","1 lingură sos de pește (sau sos de soia pentru variantă vegană)","1 linguriță zahăr","6 cepe verzi, tăiate în bucăți de 3 cm","1 morcov mediu, julien"]},"howIsMade":{"ar":"قطّع الكرنب الصيني طولياً إلى أرباع ثم عرضياً إلى قطع 5سم. رشّه بالملح واعجنه باليدين 2–3 دقائق، اتركه 1–2 ساعة مع التقليب من حين لآخر حتى يذبل ويطلق الماء. اشطفه 2–3 مرات بالماء البارد، صفّه واعصره جيداً؛ يجب أن يكون مالحاً بلذة. اخلط غوتشوغارو والثوم والزنجبيل وصلصة السمك والسكر في وعاء؛ أضف البصل الأخضر والجزر. أضف الكرنب المصفّى إلى العجينة واخلطهما بيديك (البسي قفازات) حتى تُغطّى كل قطعة بالعجينة الحمراء. اضغط بإحكام في جرات نظيفة سعة 1 لتر مع ترك 3–4سم من الفراغ؛ اتركه على درجة حرارة الغرفة 1–2 يومان ثم ضعه في الثلاجة — يصبح جاهزاً بعد 3–5 أيام.","en":"Quarter the napa cabbage lengthwise, then cut crosswise into 5cm pieces. Toss with sea salt and massage 2–3 minutes, let sit 1–2 hours turning occasionally until the cabbage has wilted and released water. Rinse the cabbage thoroughly in cold water 2–3 times, drain and squeeze firmly to remove excess moisture; it should taste pleasantly salty — rinse once more if too salty. Mix gochugaru, garlic, ginger, fish sauce and sugar in a bowl; add spring onions and carrot. Add drained cabbage to the paste and mix thoroughly with your hands (wear gloves) — every piece should be evenly coated in red paste. Pack tightly into clean 1-litre jars, press down firmly to eliminate air pockets, leaving 3–4 cm of headspace; leave at room temperature for 1–2 days, then refrigerate — kimchi is ready in 3–5 days and best after 1 week."}},{"id":67,"servings":4,"tipType":"meat","timeMins":{"total":285,"active":60},"pairingsType":"vietnamese","origin":{"ar":"فيتنام","en":"Vietnam","ro":"Vietnam"},"name":{"ar":"بان مي","en":"Banh Mi","ro":"Banh Mi"},"category":{"ar":"وجبة خفيفة","en":"Snack","ro":"Gustare"},"ingredients":{"ar":["4 أرغفة باجيت صغيرة (نحو 20 سم كل منها)، مقطوعة بالطول","400 غ لحم خنزير مشوي أو صدر دجاج، مقطع شرائح رفيعة (نحو 5 مم)","2 ملعقة كبيرة صلصة الصويا","1 ملعقة كبيرة صلصة السمك","1 ملعقة صغيرة زيت السمسم + 1 ملعقة صغيرة سكر + 1/4 ملعقة صغيرة فلفل أسود (تتبيلة)","2 جزرة متوسطة (حوالي 200 غ)، مقشرة ومقطعة عيدان رفيعة (جولييان)","100 غ فجل دايكون، مقشر ومقطع جولييان (أو جزر إضافي)","3 ملعقة كبيرة خل أرز","1 ملعقة كبيرة سكر + 1/2 ملعقة صغيرة ملح ناعم (للتخليل)","60 غ باتيه كبد دجاج","4 ملعقة كبيرة مايونيز","1 خيارة كبيرة، مقطعة عصي رفيعة","2 فلفل خال أو فلفل أحمر حار، مقطع حلقات رفيعة","20 غ كزبرة طازجة، أغصان"],"en":["4 small baguettes or demi-baguettes (about 20 cm each), halved lengthwise","400 g pork tenderloin, thinly sliced (about 5 mm)","2 tbsp soy sauce","1 tbsp fish sauce","1 tsp sesame oil + 1 tsp sugar + 1/4 tsp black pepper (marinade)","2 medium carrots (about 200 g), peeled and julienned","100 g daikon, peeled and julienned (or extra carrot)","3 tbsp rice vinegar","1 tbsp sugar + 1/2 tsp fine salt (for pickling)","60 g chicken liver pâté","4 tbsp mayonnaise","1 large cucumber, cut into thin batons","2 jalapeños or red chillies, thinly sliced","20 g fresh coriander, sprigs"],"ro":["4 baghetele mici (de circa 20 cm), tăiate pe lungime","400 g mușchi de porc, tăiat felii subțiri (circa 5 mm)","2 linguri sos de soia","1 lingură sos de pește","1 linguriță ulei de susan + 1 linguriță zahăr + 1/4 linguriță piper negru (pentru marinadă)","2 morcovi medii (aproximativ 200 g), curățați și tăiați julienne","100 g daikon (ridiche asiatică), curățat și juliennat (sau morcov în plus)","3 linguri oțet de orez","1 lingură zahăr + 1/2 linguriță sare (pentru murat)","60 g pate de ficat de pui","4 linguri maioneză","1 castravete mare, tăiat bețe subțiri","2 jalapeño sau ardei roșii, tăiați rondele","20 g coriandru proaspăt, crenguțe"]},"howIsMade":{"ar":"اخلط الجزر والدايكون مع خل الأرز والسكر والملح، قلّب جيداً واتركه يتخلل 20 دقيقة على الأقل (أو حتى 4 ساعات في الثلاجة) حتى يلين قليلاً مع الاحتفاظ بالقرمشة. اخلط صلصة الصويا وصلصة السمك وزيت السمسم والسكر والفلفل الأسود في وعاء، أضف شرائح اللحم وقلّب لتتبّل؛ اتركه 15-20 دقيقة في درجة حرارة الغرفة. سخّن مقلاة ثقيلة على نار عالية حتى يتصاعد الدخان، أضف اللحم في طبقة واحدة على دفعتين أو ثلاث واطهه دقيقة إلى دقيقتين من كل جانب حتى يتكرمل ويصبح ذهبياً. سخّن الأرغفة في فرن 200 درجة مدة 4-5 دقائق حتى تتقرمش القشرة. ادهن جوانب الخبز المقطوعة بسخاء بالباتيه والمايونيز. ضع شرائح اللحم الدافئة، الجزر والدايكون المخلل المصفى، عيدان الخيار، حلقات الخال، وأغصاناً سخية من الكزبرة. اضغط برفق وقدّم فوراً.","en":"Combine the carrots and daikon with the rice vinegar, sugar, and salt, toss well, and leave to pickle for at least 20 minutes (or up to 4 hours in the fridge) until slightly softened but still crunchy. Mix the soy sauce, fish sauce, sesame oil, sugar, and black pepper in a bowl, add the sliced pork, and toss to coat; marinate for 15-20 minutes at room temperature. Heat a heavy frying pan or griddle over high heat until smoking, add the pork in a single layer in 2-3 batches, and cook for 1-2 minutes per side until caramelised and golden brown at the edges. Toast the baguettes in a 200°C oven for 4-5 minutes until the crust is crisp. Spread the cut sides generously with pâté and mayonnaise. Layer in the warm pork slices, the drained pickled carrots and daikon, cucumber batons, jalapeño slices, and generous sprigs of coriander. Press gently and serve immediately."}},{"id":68,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ar":"إندونيسيا","en":"Indonesia","ro":"Indonezia"},"name":{"ar":"ساتيه","en":"Satay","ro":"Satay"},"category":{"ar":"وجبة خفيفة","en":"Snack","ro":"Gustare"},"ingredients":{"ar":["700 غ أفخاذ دجاج منزوعة العظم والجلد، مقطعة مكعبات 2 سم","3 ملعقة كبيرة صلصة الصويا","2 ملعقة كبيرة حليب جوز الهند","1 ملعقة كبيرة سكر بني فاتح","2 ملعقة صغيرة كزبرة مطحونة","1 ملعقة صغيرة كمون مطحون","1 ملعقة صغيرة كركم مطحون","2 فص ثوم، مبشور ناعماً","1 عود ليمون حشيش (لمون غراس)، الجزء الأبيض، مفروم ناعماً","200 غ زبدة فول سوداني ناعمة","200 مل حليب جوز الهند (للصلصة)","2 ملعقة كبيرة كيجاب مانيس (صلصة صويا حلوة)","1 ملعقة كبيرة عصير ليمون أخضر","1 ملعقة صغيرة سمبال أويليك أو سيراشا","20 أسياخ بامبو، منقوعة في ماء بارد 30 دقيقة"],"en":["700 g boneless skinless chicken thighs, cut into 2 cm cubes","3 tbsp soy sauce","2 tbsp coconut milk","1 tbsp light brown sugar","2 tsp ground coriander","1 tsp ground cumin","1 tsp ground turmeric","2 garlic cloves, finely grated","1 lemongrass stalk, pale part only, finely minced","200 g smooth peanut butter","200 ml coconut milk (for sauce)","2 tbsp kecap manis (sweet soy sauce)","1 tbsp lime juice","1 tsp sambal oelek or sriracha","20 bamboo skewers, soaked in cold water for 30 minutes"],"ro":["700 g pulpe de pui dezosate și fără piele, tăiate cubulețe de 2 cm","3 linguri sos de soia","2 linguri lapte de cocos","1 lingură zahăr brun pal","2 lingurițe coriandru măcinat","1 linguriță chimen măcinat","1 linguriță turmeric măcinat","2 căței de usturoi, fin rași","1 tulpină lemongrass, partea palidă, fin tocată","200 g unt de arahide cremos","200 ml lapte de cocos (pentru sos)","2 linguri kecap manis (sos de soia dulce)","1 lingură suc de lime","1 linguriță sambal oelek sau sriracha","20 bețișoare de bambus, înmuiate în apă rece 30 de minute"]},"howIsMade":{"ar":"اخلط صلصة الصويا وحليب جوز الهند والسكر البني والكزبرة والكمون والكركم والثوم وليمون الحشيش في وعاء لعمل التتبيلة. أضف مكعبات الدجاج وقلّب لتتبّل؛ اتركها تتبّل 30 دقيقة على الأقل في درجة حرارة الغرفة أو حتى 4 ساعات في الثلاجة. اعمل صلصة الفول السوداني: اخلط زبدة الفول السوداني وحليب جوز الهند وكيجاب مانيس وعصير الليمون والسمبال في قدر صغير على نار خفيفة مع التقليب 3-4 دقائق حتى يصبح ناعماً وحريرياً؛ أضف ماء إذا كان كثيفاً جداً. اغرز 4-5 قطع دجاج في كل سيخ مبلل بإحكام. سخّن شواية فحم أو مقلاة شواء من الحديد الزهر على نار عالية وادهنها بقليل من الزيت. اشوِ الأسياخ 3-4 دقائق من كل جانب مع القلب مرة واحدة حتى يتفحّم الدجاج في بعض الأماكن ويُسحب بسهولة من السيخ — يجب أن تبلغ درجة الحرارة الداخلية 75 درجة. قدّم فوراً مع صلصة الفول السوداني الدافئة وشرائح الخيار.","en":"Mix the soy sauce, coconut milk, brown sugar, ground coriander, cumin, turmeric, garlic, and lemongrass in a bowl to make the marinade. Add the chicken cubes, toss to coat, and marinate for at least 30 minutes at room temperature or up to 4 hours in the refrigerator. Make the peanut sauce: combine the peanut butter, coconut milk, kecap manis, lime juice, and sambal in a small saucepan over low heat and stir for 3-4 minutes until smooth and silky; thin with a splash of water if too thick. Thread 4-5 chicken pieces onto each soaked skewer, pressing them close together. Heat a charcoal grill, cast-iron griddle, or grill pan over high heat and brush lightly with oil. Grill the skewers for 3-4 minutes per side, turning once, until deeply charred in spots and the chicken pulls away from the skewer easily — internal temperature should reach 75°C. Serve immediately with the warm peanut sauce for dipping and sliced cucumber alongside."}},{"id":69,"servings":4,"tipType":"def","pairingsType":"soup","origin":{"ar":"ماليزيا","en":"Malaysia","ro":"Malaysia"},"name":{"ar":"لاكسا","en":"Laksa","ro":"Laksa"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"ingredients":{"ar":["3 ملعقة كبيرة معجون لاكسا (أو معجون كاري أحمر مع ملعقة صغيرة معجون الروبيان)","2 ملعقة كبيرة زيت نباتي","800 مل حليب جوز الهند (2 علبة × 400 مل)","600 مل مرق دجاج أو ماء","2 ملعقة كبيرة صلصة السمك","1 ملعقة صغيرة سكر","400 غ روبيان نيء متوسط الحجم، مقشر ومنزوع الخيط","200 غ توفو صلب، مصفى ومقطع مكعبات 2 سم","200 غ براعم فاصوليا الصويا الطازجة","200 غ شعيرية أرز، منقوعة في ماء مغلي 3 دقائق ومصفاة","4 بيضات كبيرة، مسلوقة (7 دقائق)، مقشرة ومقسومة نصفين","100 غ فاصوليا خضراء، مقطوعة ومقسومة نصفين","2 ليمون أخضر، مقطع أوتاداً","20 غ كزبرة طازجة، الأوراق فقط","2 بصلة خضراء، مقطعة رفيعاً"],"en":["3 tbsp laksa paste (or red curry paste with 1 tsp shrimp paste added)","2 tbsp vegetable oil","800 ml coconut milk (2 x 400 ml cans)","600 ml chicken stock or water","2 tbsp fish sauce","1 tsp sugar","400 g raw medium prawns, peeled and deveined","200 g firm tofu, drained and cut into 2 cm cubes","200 g fresh bean sprouts","200 g rice vermicelli noodles, soaked in boiling water 3 minutes and drained","4 large eggs, hard-boiled (7 minutes), peeled and halved","100 g green beans, trimmed and halved","2 limes, cut into wedges","20 g fresh coriander, leaves only","2 spring onions, thinly sliced"],"ro":["3 linguri pastă laksa (sau pastă de curry roșu cu 1 linguriță pastă de creveți)","2 linguri ulei vegetal","800 ml lapte de cocos (2 conserve de 400 ml)","600 ml supă de pui sau apă","2 linguri sos de pește","1 linguriță zahăr","400 g creveți cruzi medii, curățați și devenați","200 g tofu ferm, scurs și tăiat cuburi de 2 cm","200 g muguri de soia proaspeți","200 g vermicelli de orez, înmuiați în apă clocotită 3 minute și scurși","4 ouă mari, fierte tari (7 minute), decojite și tăiate jumătate","100 g fasole verde, curățată și tăiată în jumătăți","2 lime, tăiate felii","20 g coriandru proaspăt, frunze","2 cepe verzi, feliate subțire"]},"howIsMade":{"ar":"انقع شعيرية الأرز في الماء المغلي 3 دقائق، صفِّها واشطفها بماء بارد وضعها جانباً. اسلق البيض 7 دقائق، برّده في ماء مثلج، قشّره واقسمه نصفين. سخّن الزيت في مقلاة واسعة أو وعاء كبير على نار متوسطة، أضف معجون اللاكسا واقله مع التقليب المستمر 2-3 دقائق حتى تفوح الرائحة ويبدأ الزيت بالانفصال. أضف حليب جوز الهند ومرق الدجاج وأوصله إلى غليان هادئ. أضف صلصة السمك والسكر وتذوق — يجب أن يكون المرق غنياً ومالحاً قليلاً. أضف الفاصوليا الخضراء واطهها 3 دقائق، ثم أضف الروبيان والتوفو واطهها 2-3 دقائق حتى يتحول الروبيان للون الوردي. وزّع الشعيرية على 4 أطباق عميقة وصبّ المرق الساخن مع الروبيان والتوفو والفاصوليا فوقها. زيّن كل طبق ببراعم الصويا ونصفي البيضة والبصل الأخضر والكزبرة. قدّم فوراً مع أوتاد الليمون الأخضر.","en":"Soak the rice vermicelli in boiling water for 3 minutes, drain, rinse under cold water, and set aside. Hard-boil the eggs for 7 minutes, cool in iced water, peel, and halve. Heat the oil in a large wok or saucepan over medium heat, add the laksa paste, and fry, stirring constantly, for 2-3 minutes until fragrant and the oil begins to separate. Pour in the coconut milk and chicken stock and bring to a steady simmer. Add the fish sauce and sugar, taste, and adjust — the broth should be rich and slightly salty. Add the green beans and cook for 3 minutes, then add the prawns and tofu and cook for 2-3 minutes until the prawns are pink and just cooked through. Divide the noodles between 4 deep bowls and ladle the hot broth with prawns, tofu, and beans on top. Finish each bowl with bean sprouts, 2 halved eggs, spring onions, and coriander. Serve immediately with lime wedges on the side."}},{"id":70,"servings":4,"tipType":"def","pairingsType":"mexican","origin":{"ar":"السلفادور","en":"El Salvador","ro":"El Salvador"},"name":{"ar":"ببوسا","en":"Pupusa","ro":"Pupusa"},"category":{"ar":"وجبة خفيفة","en":"Snack","ro":"Gustare"},"ingredients":{"ar":["400 غ دقيق ماسا هارينا (دقيق الذرة المعالج بالنيكستمال، مثل Maseca)، مع القليل إضافي","350 مل ماء دافئ (حوالي 40 درجة)، والمزيد عند الحاجة","1 ملعقة صغيرة ملح ناعم","200 غ فاصوليا سوداء أو بينتو معلبة ومهروسة، دافئة","200 غ جبن كيسيو كيسيو أو موزاريلا، مبشور خشن","2 ملعقة كبيرة زيت نباتي (للطهي)","300 غ ملفوف أبيض (نحو ربع رأس)، مقطع ناعماً جداً","1 جزرة صغيرة (نحو 80 غ)، مقشرة ومبشورة خشن","نصف بصلة بيضاء صغيرة (نحو 60 غ)، مقطعة رفيعاً","100 مل خل التفاح أو الخل الأبيض","100 مل ماء (للكورتيدو)","1 ملعقة صغيرة ملح + 1 ملعقة صغيرة سكر (للكورتيدو)","نصف ملعقة صغيرة زعتر مجفف","200 مل صلصة طماطم للتقديم"],"en":["400 g masa harina (nixtamalized corn flour, such as Maseca), plus extra","350 ml warm water (about 40°C), plus more if needed","1 tsp fine sea salt","200 g canned refried black or pinto beans, warmed","200 g queso quesillo or mozzarella, coarsely grated","2 tbsp vegetable oil (for cooking)","300 g white cabbage (about 1/4 head), very finely shredded","1 small carrot (about 80 g), peeled and coarsely grated","1/2 small white onion (about 60 g), thinly sliced","100 ml apple cider vinegar or white vinegar","100 ml water (for curtido)","1 tsp fine salt + 1 tsp sugar (for curtido)","1/2 tsp dried oregano","200 ml tomato salsa, to serve"],"ro":["400 g masa harina (făină de porumb nixtamalizată, ex. Maseca), plus extra","350 ml apă caldă (circa 40°C), plus dacă e nevoie","1 linguriță sare fină de mare","200 g fasole neagră sau pinto refulată (din conservă, încălzită)","200 g queso quesillo sau mozzarella, ras grosier","2 linguri ulei vegetal (pentru prăjit)","300 g varză albă (aprox. 1/4 căpățână), fin feliată","1 morcov mic (aprox. 80 g), curățat și ras","1/2 ceapă albă mică (aprox. 60 g), felii subțiri","100 ml oțet de mere sau oțet alb","100 ml apă (pentru curtido)","1 linguriță sare fină + 1 linguriță zahăr (pentru curtido)","1/2 linguriță oregano uscat","200 ml salsa de roșii pentru servit"]},"howIsMade":{"ar":"حضّر الكورتيدو أولاً: اخلط الملفوف والجزر والبصل في وعاء، امزج الخل والماء والملح والسكر والزعتر، صبّ على الخضار وقلّب جيداً، واتركه يتخلل 30 دقيقة على الأقل (أو في الثلاجة طوال الليل). حضّر العجينة: اخلط ماسا هارينا والملح في وعاء كبير، أضف الماء الدافئ تدريجياً واعجن بيديك حتى تتشكل عجينة ناعمة ومرنة — يجب أن تتماسك دون تشقق؛ أضف ملعقة ماء في كل مرة عند الحاجة. اخلط الفاصوليا المهروسة والجبن المبشور لعمل الحشوة. قسّم العجينة إلى 8 كرات متساوية (نحو 90 غ كل منها). اضغط على كرة في راحة يدك المبللة لتشكيل قرص قطره نحو 12 سم، ضع ملعقتين كبيرتين من الحشوة في المركز، ثم اطوِ الحواف فوق الحشوة وضغطها جيداً لإغلاقها؛ أعد تسطيحها بلطف لتصبح قرصاً بسمك 1 سم وقطر 12 سم، مسدوداً أي شقوق. سخّن صينية ثقيلة أو مقلاة حديد زهر على نار متوسطة-عالية ودهنها بالزيت. اطهِ البوبوسا على دفعات 3-4 دقائق لكل جانب حتى تظهر بقع ذهبية داكنة ولا تلتصق العجينة عند اللمس. قدّم ساخناً مع الكورتيدو فوقه والصلصة جانبه.","en":"Make the curtido first: combine the cabbage, carrot, and onion in a bowl, mix the vinegar, water, salt, sugar, and oregano, pour over the vegetables, toss well, and set aside to pickle for at least 30 minutes (or overnight in the fridge). Make the dough: combine the masa harina and salt in a large bowl, pour in the warm water gradually, and mix with your hands until a smooth, pliable dough forms — it should hold together without cracking; add a tablespoon of water at a time if needed. Mix the refried beans and grated cheese together to make the filling. Divide the dough into 8 equal balls (about 90 g each). Press a ball flat in your damp palm into a disc about 12 cm across, place 2 heaped tablespoons of filling in the centre, then fold the edges up over the filling and pinch firmly to seal; gently re-flatten into a disc about 1 cm thick and 12 cm wide, patching any cracks. Heat a heavy griddle or cast-iron skillet over medium-high heat and brush with oil. Cook the pupusas in batches for 3-4 minutes per side until dark golden-brown patches appear and the dough feels dry rather than tacky. Serve hot with the curtido piled on top and salsa alongside."}},{"id":72,"servings":4,"tipType":"fish","pairingsType":"vietnamese","origin":{"ar":"كمبوديا","en":"Cambodia","ro":"Cambodgia"},"name":{"ar":"آموك","en":"Amok","ro":"Amok"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["600 غ شرائح سمك أبيض (تيلابيا، سنيبر، أو سمك السلور)، منزوع الجلد، مقطع قطعاً بحجم 3 سم","400 مل حليب جوز الهند (1 علبة 400 مل)","2 بيضتان كبيرتان، مخفوقتان قليلاً","3 ملعقة كبيرة صلصة السمك","1 ملعقة صغيرة سكر","2 عود ليمون حشيش، الجزء الأبيض فقط، مفروم ناعماً جداً","3 فصوص ثوم، مفرومة ناعماً","3 كراث (نحو 100 غ)، مفروم ناعماً","1 ملعقة صغيرة معجون الجاوى (أو 1 سم جاوى طازج مبشور)","1/2 ملعقة صغيرة كركم مطحون","1/2 ملعقة صغيرة رقائق فلفل حار أو فلفل أحمر طازج مفروم ناعماً","4 أوراق ليمون كافير، منزوعة السيقان، مقطعة رفيعاً جداً","4 مربعات كبيرة من أوراق الموز (30 x 30 سم)، تُليّن فوق اللهب، أو 4 أطباق فردية","20 غ أوراق ريحان طازج أو ريحان تايلاندي للتزيين"],"en":["600 g white fish fillets (tilapia, snapper, or catfish), skin removed, cut into 3 cm pieces","400 ml coconut milk (1 x 400 ml can)","2 large eggs, lightly beaten","3 tbsp fish sauce","1 tsp caster sugar","2 lemongrass stalks, pale parts only, very finely minced","3 garlic cloves, finely minced","3 shallots (about 100 g), finely minced","1 tsp galangal paste (or 1 cm fresh galangal, grated)","1/2 tsp ground turmeric","1/2 tsp dried chilli flakes or 1 fresh red chilli, finely sliced","4 kaffir lime leaves, stems removed, very finely shredded","4 large banana leaf squares (30 x 30 cm), softened over a flame, or 4 ramekins","20 g fresh basil or Thai basil leaves, to garnish"],"ro":["600 g file de pește alb (tilapia, biban sau somn), fără piele, tăiat bucăți de 3 cm","400 ml lapte de cocos (1 conservă de 400 ml)","2 ouă mari, ușor bătute","3 linguri sos de pește","1 linguriță zahăr","2 tulpini lemongrass, doar partea palidă, fin tocate","3 căței de usturoi, fin tocați","3 șalote (aproximativ 100 g), fin tocate","1 linguriță pastă de galangal (sau 1 cm galangal proaspăt, ras)","1/2 linguriță turmeric măcinat","1/2 linguriță fulgi de ardei iute uscat sau 1 ardei roșu, fin tocat","4 frunze de kaffir lime, cotoare îndepărtate, fin feliate","4 pătrate mari de frunze de bananier (30 x 30 cm), înmuiate, sau ramekine","20 g frunze de busuioc proaspăt sau busuioc thai, pentru garnitură"]},"howIsMade":{"ar":"اهرس أو الخلط ليمون الحشيش والثوم والكراث والجاوى والكركم والفلفل حتى تتشكل معجونة ناعمة. في وعاء كبير، اخفق حليب جوز الهند والبيض المخفوق وصلصة السمك والسكر حتى تمتزج. أضف معجون البهارات ونصف أوراق الليمون كافير المقطعة. أضف قطع السمك وقلّب برفق لتتبّل؛ اتركها 15 دقيقة. ليّن مربعات أوراق الموز فوق لهب الغاز أو في ماء ساخن 30 ثانية حتى تلين. اطوِ كل واحدة على شكل كوب بعرض 12 سم وعمق 4 سم وثبّتها بعود أسنان. وزّع خليط السمك بالتساوي على 4 أكواب من أوراق الموز، مملوءة بثلثيها، وانثر أوراق الليمون كافير المتبقية فوقها. ضع الأكواب في قدر بخار من الخيزران فوق ماء مغلٍ، غطِّها جيداً، وابخّرها 18-20 دقيقة حتى يتماسك الآموك ولا يسيل عند إمالة الكوب برفق وتصبح السطح ثابتاً قليلاً. زيّن بأوراق الريحان وقدّم فوراً مع أرز الياسمين المبخّر.","en":"Pound or blend the lemongrass, garlic, shallots, galangal, turmeric, and chilli into a smooth paste. In a large bowl, whisk together the coconut milk, beaten eggs, fish sauce, and sugar until combined. Stir in the spice paste and half the shredded kaffir lime leaves. Add the fish pieces and fold gently to coat; marinate for 15 minutes. Soften the banana leaf squares over a gas flame or in hot water for 30 seconds until pliable. Fold each into a cup shape about 12 cm across and 4 cm deep, securing with a toothpick. Divide the fish mixture evenly among the 4 banana leaf cups, filling each about two-thirds full, then scatter the remaining kaffir lime leaves on top. Set the cups in a bamboo steamer over boiling water, cover tightly, and steam for 18-20 minutes until the amok is just set — no longer liquid when the cup is gently tilted — and the top is slightly firm to the touch. Garnish with fresh basil leaves and serve immediately with steamed jasmine rice."}},{"id":73,"servings":4,"tipType":"meat","pairingsType":"indian","origin":{"ar":"نيبال","en":"Nepal","ro":"Nepal"},"name":{"ar":"مومو","en":"Momo","ro":"Momo"},"category":{"ar":"وجبة خفيفة","en":"Snack","ro":"Gustare"},"ingredients":{"ar":["300 غ من الدقيق الأبيض، بالإضافة إلى كمية إضافية للرش","150 مل ماء دافئ","500 غ لحم دجاج أو خنزير مفروم","1 بصلة متوسطة (حوالي 120 غ)، مفرومة ناعمة جداً","3 فصوص ثوم، مفرومة ناعماً","1 ملعقة كبيرة زنجبيل طازج (حوالي 2 سم)، مبشور ناعم","30 غ كزبرة طازجة، مفرومة ناعماً","1 ملعقة صغيرة كمون مطحون","1/2 ملعقة صغيرة كزبرة مطحونة","1/4 ملعقة صغيرة كركم","1 ملعقة صغيرة ملح ناعم، مقسّمة","4 طماطم متوسطة (حوالي 400 غ)، مقطوعة نصفين","2 فلفل أحمر مجفف أو 1/2 ملعقة صغيرة من رقائق الفلفل الحار","1 ملعقة كبيرة زيت نباتي"],"en":["300 g plain flour (all-purpose), plus extra for dusting","150 ml warm water","500 g ground chicken or pork","1 medium onion (about 120 g), very finely diced","3 garlic cloves, finely minced","1 tbsp fresh ginger (about 2 cm piece), finely grated","30 g fresh coriander (cilantro), finely chopped","1 tsp ground cumin","1/2 tsp ground coriander","1/4 tsp ground turmeric","1 tsp fine sea salt, divided","4 medium tomatoes (about 400 g), halved","2 dried red chillies or 1/2 tsp chilli flakes","1 tbsp vegetable oil"],"ro":["300 g făină albă (tip 550), plus extra pentru pudrat","150 ml apă caldă","500 g carne tocată de pui sau porc","1 ceapă medie (circa 120 g), tocată mărunt","3 căței de usturoi, tocați mărunt","1 lingură ghimbir proaspăt (circa 2 cm), ras fin","30 g coriandru proaspăt, tocat mărunt","1 linguriță chimen măcinat","1/2 linguriță coriandru măcinat","1/4 linguriță turmeric","1 linguriță sare fină, împărțită","4 roșii medii (circa 400 g), tăiate în jumătăți","2 ardei iuți uscați sau 1/2 linguriță fulgi de ardei iute","1 lingură ulei vegetal"]},"howIsMade":{"ar":"اخلطي الدقيق ونصف ملعقة صغيرة من الملح، أضيفي الماء الدافئ تدريجياً واعجني لمدة 5-6 دقائق حتى تتكون عجينة ملساء ومتماسكة وغير لاصقة؛ غطيها بقماش مبلل واتركيها ترتاح 30 دقيقة. في وعاء آخر، اخلطي اللحم المفروم والبصل والثوم والزنجبيل والكزبرة والكمون والكزبرة المطحونة والكركم ونصف ملعقة صغيرة الملح المتبقية والزيت جيداً؛ ثم ضعيها في الثلاجة 15 دقيقة. لتحضير الصلصة، حمّصي نصفي الطماطم والفلفل المجفف في مقلاة جافة على نار عالية 4-5 دقائق حتى يلينا ويحترقا قليلاً، ثم اخلطيهما مع الثوم والملح حتى تتكون صلصة ناعمة. قسّمي العجينة إلى 24 قطعة متساوية (حوالي 15 غ لكل منها) وافردي كل قطعة إلى دائرة رفيعة بقطر 8 سم. ضعي ملعقة صغيرة مكدسة من الحشوة في المنتصف، اجمعي الحواف بطيات متداخلة صغيرة وأحكمي الإغلاق من الأعلى. رتبي المومو على ورق زبدة مدهون قليلاً في طنجرة البخار مع ترك مسافة سنتيمتر على الأقل بينها. اطبخيها على البخار 12-15 دقيقة حتى تصبح قشرتها شبه شفافة وترتد للشكل الأصلي عند الضغط عليها برفق. قدّميها فوراً مع صلصة الطماطم والفلفل الحار.","en":"Combine flour and 1/2 tsp of the salt in a bowl, then add warm water a little at a time, mixing until a rough dough forms; knead for 5-6 minutes until smooth, firm, and no longer sticky, then cover with a damp cloth and rest for 30 minutes. In a separate bowl, mix the ground meat, onion, garlic, ginger, coriander leaves, cumin, ground coriander, turmeric, the remaining 1/2 tsp salt, and oil until well combined; refrigerate for 15 minutes to let the flavours meld. Meanwhile, make the dipping sauce: char the tomato halves and dried chillies in a dry heavy skillet over high heat for 4-5 minutes until softened and blackened in spots, then blend with the garlic and remaining salt until smooth. Divide the rested dough into 24 equal pieces (about 15 g each) and roll each into a thin round about 8 cm across. Place a heaped teaspoon of filling in the centre of each round, then gather the edges and pleat them together with small overlapping folds, pinching firmly at the top to seal. Line a bamboo or metal steamer with lightly oiled parchment paper and arrange the momo at least 1 cm apart. Set over a pot of vigorously boiling water, cover tightly, and steam for 12-15 minutes until the wrappers turn translucent and a gently pressed momo springs back without feeling doughy inside. Serve immediately with the tomato-chilli sauce."}},{"id":74,"servings":4,"tipType":"soup","pairingsType":"soup","origin":{"ar":"الإكوادور","en":"Ecuador","ro":"Ecuador"},"name":{"ar":"إينسيبولادو","en":"Encebollado","ro":"Encebollado"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"ingredients":{"ar":["700 غ تونة طازجة أو 2 علبة تونة في الماء (400 غ في المجموع)، مصفاة","600 غ كسافا (يوكا)، مقشرة ومقطعة إلى قطع بحجم 4 سم","1 بصلة حمراء كبيرة (حوالي 200 غ)، مقطعة إلى أنصاف حلقات رفيعة","4 طماطم متوسطة (حوالي 400 غ)، مفرومة خشناً","4 فصوص ثوم، مفرومة خشناً","1 ملعقة صغيرة كمون مطحون","1 ملعقة صغيرة معجون أشيوتي أو 1/2 ملعقة صغيرة فلفل حلو","1.5 لتر مرق سمك أو ماء","3 ملاعق كبيرة عصير ليمون (حوالي 2 حبة)","2 ملعقة كبيرة زيت نباتي","1 ملعقة صغيرة ملح ناعم","30 غ كزبرة طازجة، مقسمة — نصفها للطهي ونصفها للتقديم","1 فلفل هالابينيو أو أجي، منزوع البذور، مقطع شرائح رفيعة","2 بصل أخضر، مقطع شرائح رفيعة (للتزيين)"],"en":["700 g fresh tuna or 2 cans tuna in water (400 g total), drained","600 g cassava (yuca), peeled and cut into 4 cm chunks","1 large red onion (about 200 g), thinly sliced into half-moons","4 medium tomatoes (about 400 g), roughly chopped","4 garlic cloves, roughly chopped","1 tsp ground cumin","1 tsp achiote paste or 1/2 tsp sweet paprika","1.5 litres fish stock or water","3 tbsp fresh lime juice (about 2 limes)","2 tbsp vegetable oil","1 tsp fine sea salt","30 g fresh coriander (cilantro), divided — half to cook, half to garnish","1 jalapeño or aji pepper, deseeded and finely sliced","2 spring onions, thinly sliced (to garnish)"],"ro":["700 g ton proaspăt sau 2 conserve ton în apă (400 g total), scurse","600 g yuca (manioc), curățată și tăiată bucăți de 4 cm","1 ceapă roșie mare (circa 200 g), tăiată în felii subțiri","4 roșii medii (circa 400 g), tăiate grosier","4 căței de usturoi, tăiați grosier","1 linguriță chimen măcinat","1 linguriță pastă de achiote sau 1/2 linguriță paprika dulce","1,5 litri supă de pește sau apă","3 linguri zeamă de lămâie verde (circa 2 lămâi)","2 linguri ulei vegetal","1 linguriță sare fină","30 g coriandru proaspăt, împărțit — jumătate pentru gătit, jumătate pentru servit","1 jalapeno sau ardei iute, fără semințe, feliat subțire","2 fire ceapă verde, tăiate subțire (pentru decor)"]},"howIsMade":{"ar":"سخّني الزيت في قدر كبير على نار متوسطة، أضيفي البصل والثوم والطماطم والهالابينيو والكمون واطبخيها 8-10 دقائق مع التحريك من حين لآخر، حتى يلين البصل جداً وتتحول الطماطم إلى صلصة سميكة. أضيفي معجون الأشيوتي واطبخي دقيقة واحدة حتى يصبح الزيت برتقالياً داكناً. صبّي مرق السمك وأحضريه للغليان، ثم أضيفي الكسافا واطبخيها 20-25 دقيقة حتى تنضج تماماً وتبدأ في التفتت من الأطراف. إن كنتِ تستخدمين تونة طازجة، سلقيها في ماء مملح خفيفاً على نار هادئة 5-6 دقائق حتى تنضج، ثم اتركيها تبرد قليلاً وقطعيها إلى قطع كبيرة. أضيفي التونة المقطعة (أو تونة العلبة المصفاة) ونصف الكزبرة وعصير الليمون إلى القدر؛ اتركيها تغلي على نار هادئة 3-4 دقائق لتتداخل النكهات. اضبطي الملح، ثم صبّي الحساء في أطباق عميقة. رشّي الكزبرة المتبقية والبصل الأخضر فوقها وقدّميها مع التوستاداس أو رقائق الموز.","en":"Heat the oil in a large pot over medium heat, add the onion, garlic, tomatoes, jalapeño, and cumin, and cook for 8-10 minutes, stirring occasionally, until the onion is very soft and the tomatoes have broken down into a thick paste. Stir in the achiote paste and cook for 1 minute until the oil turns a deep orange. Pour in the stock, bring to a boil, then add the cassava and cook for 20-25 minutes until completely tender and just beginning to break apart at the edges. If using fresh tuna, poach the steaks in lightly salted simmering water for 5-6 minutes until just cooked through, cool slightly, and flake into large chunks. Add the flaked tuna (or drained canned tuna), half the coriander, and the lime juice to the pot; simmer for 3-4 minutes to marry the flavours. Season with salt to taste, then ladle the soup into deep bowls. Top with the remaining coriander and spring onions, and serve with tostadas or plantain chips on the side."}},{"id":75,"servings":4,"tipType":"soup","pairingsType":"middle-eastern","origin":{"ar":"المغرب","en":"Morocco","ro":"Maroc"},"name":{"ar":"حريرة","en":"Harira","ro":"Harira"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"ingredients":{"ar":["400 غ كتف الخروف، مقطعة إلى قطع بحجم 3 سم","400 غ حمص معلب (1 علبة 400 غ)، مصفى ومغسول","150 غ عدس أخضر أو بني، مغسول","4 طماطم متوسطة (حوالي 400 غ)، مفرومة خشناً","1 بصلة كبيرة (حوالي 200 غ)، مفرومة ناعمة جداً","3 سيقان كرفس مع أوراقها (حوالي 150 غ)، مقطعة رفيعة","3 فصوص ثوم، مفرومة ناعماً","1 ملعقة صغيرة كمون مطحون","1 ملعقة صغيرة قرفة + 1 ملعقة صغيرة زنجبيل مطحون","1/2 ملعقة صغيرة كركم + 1 ملعقة صغيرة ملح ناعم","2 ملعقة كبيرة زيت الزيتون","1.5 لتر ماء أو مرق الخروف","60 غ شعيرية رفيعة، مكسورة إلى قطع بطول 2 سم","30 غ كزبرة طازجة وبقدونس مفلطح، مفرومان خشناً"],"en":["400 g lamb shoulder, cut into 3 cm chunks","400 g canned chickpeas (1 x 400 g can), rinsed and drained","150 g green or brown lentils, rinsed","4 medium tomatoes (about 400 g), roughly chopped","1 large onion (about 200 g), finely diced","3 celery stalks with leaves (about 150 g), finely sliced","3 garlic cloves, finely minced","1 tsp ground cumin","1 tsp ground cinnamon + 1 tsp ground ginger","1/2 tsp ground turmeric + 1 tsp fine sea salt","2 tbsp olive oil","1.5 litres water or lamb stock","60 g thin vermicelli, broken into 2 cm pieces","30 g fresh coriander and flat-leaf parsley, roughly chopped"],"ro":["400 g spata de miel, taiata bucati de 3 cm","400 g naut fiert (1 cutie 400 g), scurs si clatit","150 g linte verde sau bruna, clatita","4 rosii medii (circa 400 g), taiate grosier","1 ceapa mare (circa 200 g), tocata marunt","3 tulpini de telina cu frunze (circa 150 g), feliate subtire","3 căței de usturoi, tocati marunt","1 lingurita chimen macinat","1 lingurita scortisoara + 1 lingurita ghimbir macinat","1/2 lingurita turmeric + 1 lingurita sare fina","2 linguri ulei de masline","1,5 litri apa sau supa de miel","60 g vermicelli subtire, rupt in bucati de 2 cm","30 g coriandru proaspat si patrunjel plat, tocat grosier"]},"howIsMade":{"ar":"سخّني الزيت في قدر كبير على نار عالية، أضيفي قطع الخروف واقليها 4-5 دقائق مع التقليب حتى تتحمر من جميع الجهات. أضيفي البصل والكرفس والثوم وأطبخيها 5 دقائق حتى تلين. أضيفي الكمون والقرفة والزنجبيل والكركم والملح واقليها دقيقة واحدة حتى تفوح الرائحة. أضيفي الطماطم والحمص والعدس وصبّي الماء أو المرق؛ أحضريها للغليان وانزعي الرغوة. خففي النار وغطّي القدر جزئياً واتركيه يغلي على نار هادئة 45-50 دقيقة حتى يلين الخروف وينهار العدس في المرق مكثّفاً إياه قليلاً. أضيفي الشعيرية واطبخيها 5-6 دقائق حتى تنضج. ارفعي عن النار وأضيفي الكزبرة والبقدونس واعصري عصير الليمون حسب الرغبة. صبّي في أطباق وقدّمي فوراً مع الخبز والتمر.","en":"Heat the oil in a large pot over medium-high heat, add the lamb chunks and sear for 4-5 minutes, turning occasionally, until browned on all sides. Add the onion, celery, and garlic and cook for 5 minutes until softened. Stir in the cumin, cinnamon, ginger, turmeric, and salt and cook for 1 minute until fragrant. Add the tomatoes, chickpeas, and lentils, pour in the water or stock, and bring to a boil; skim any foam from the surface. Reduce the heat to low, cover partially, and simmer for 45-50 minutes until the lamb is tender and the lentils have dissolved into the broth, thickening it slightly. Stir in the vermicelli and cook for 5-6 minutes until tender. Remove from the heat, stir in the coriander and parsley, and squeeze in lemon juice to taste. Ladle into bowls and serve immediately with crusty bread and dates."}},{"id":76,"servings":4,"tipType":"veg","pairingsType":"veg","origin":{"ar":"جورجيا","en":"Georgia","ro":"Georgia"},"name":{"ar":"لوبيو","en":"Lobio","ro":"Lobio"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["500 غ فاصوليا حمراء مجففة (أو 2 علبة 400 غ، مغسولة)","1 بصلة كبيرة (حوالي 200 غ)، مفرومة ناعمة جداً","4 فصوص ثوم، مفرومة ناعماً","100 غ من أنصاف الجوز، مطحونة ناعماً أو مفرومة جداً","1 ملعقة صغيرة كزبرة مطحونة","1/2 ملعقة صغيرة حلبة مطحونة (أوتشو سونيلي)","1/2 ملعقة صغيرة قرفة","1/2 ملعقة صغيرة رقائق الفلفل الحار أو 1 فلفل حار صغير منزوع البذور ومفروم","2 ملعقة كبيرة خل النبيذ الأبيض أو الأحمر","3 ملعقة كبيرة زيت نباتي","1 ملعقة صغيرة ملح ناعم","30 غ كزبرة طازجة، مفرومة ناعماً","4 ملاعق كبيرة بذور الرمان (حوالي 1/2 رمانة)","4 بصل أخضر، مقطع شرائح رفيعة"],"en":["500 g dried red kidney beans (or 2 x 400 g cans, rinsed)","1 large onion (about 200 g), finely diced","4 garlic cloves, finely minced","100 g walnut halves, finely ground or very finely chopped","1 tsp ground coriander","1/2 tsp ground fenugreek (utsho suneli)","1/2 tsp ground cinnamon","1/2 tsp dried chilli flakes or 1 small red chilli, deseeded and minced","2 tbsp white wine vinegar or red wine vinegar","3 tbsp vegetable oil","1 tsp fine sea salt","30 g fresh coriander (cilantro), finely chopped","4 tbsp pomegranate seeds (about 1/2 pomegranate)","4 spring onions, thinly sliced"],"ro":["500 g fasole rosie uscata (sau 2 x 400 g conserve, clatite)","1 ceapa mare (circa 200 g), tocata marunt","4 căței de usturoi, tocati marunt","100 g miez de nuca, macinat fin sau tocat marunt","1 lingurita coriandru macinat","1/2 lingurita schinduf macinat (utsho suneli)","1/2 lingurita scortisoara","1/2 lingurita fulgi de ardei iute sau 1 ardei iute mic, fara seminte, tocat","2 linguri otet alb sau de vin rosu","3 linguri ulei vegetal","1 lingurita sare fina","30 g coriandru proaspat, tocat marunt","4 linguri boabe de rodie (circa 1/2 rodie)","4 fire ceapa verde, taiate subtire"]},"howIsMade":{"ar":"إن كنتِ تستخدمين الفاصوليا المجففة، انقعيها في ماء بارد طوال الليل، صفّيها، وضعيها في قدر كبير مع ماء بارد جديد، أحضريها للغليان، انزعي الرغوة واتركيها تغلي على نار هادئة 45-60 دقيقة حتى تنضج تماماً وتبدأ في التفتت، مع سائل طهي أحمر داكن وسميك. سخّني الزيت في مقلاة على نار متوسطة، أضيفي البصل واطبخيه 10-12 دقيقة مع التقليب من حين لآخر حتى يصبح ذهبياً داكناً وطرياً جداً. أضيفي الثوم والكزبرة المطحونة والحلبة والقرفة والفلفل الحار واطبخي دقيقتين حتى تفوح الرائحة. أضيفي مزيج البصل والجوز المطحون والخل إلى الفاصوليا وأتركيها تغلي على نار خفيفة 10 دقائق مع التقليب، حتى تتداخل النكهات وتصبح الفاصوليا طرية جداً مع صلصة سميكة — سحّقي بعض الحبات على جانب القدر للتكثيف. اضبطي الملح والخل. ارفعي عن النار وأضيفي نصف الكزبرة الطازجة. ضعي في طبق وزيّني بالبصل الأخضر وبذور الرمان والكزبرة المتبقية. قدّمي دافئاً مع الخبز.","en":"If using dried beans, soak them overnight in cold water, then drain, cover with fresh cold water in a large pot, bring to a boil, skim any foam, and simmer for 45-60 minutes until completely tender and starting to break apart, with a thick dark-red cooking liquid. Heat the oil in a frying pan over medium heat, add the onion and cook for 10-12 minutes, stirring occasionally, until deep golden and very soft. Add the garlic, ground coriander, fenugreek, cinnamon, and chilli and cook for 2 minutes until fragrant. Stir the onion mixture, ground walnuts, and vinegar into the cooked beans and simmer over low heat for 10 minutes, stirring occasionally, until the flavours meld and the beans are very soft with a thick sauce — mash a few beans against the side of the pot to help thicken. Season with salt and more vinegar to taste. Remove from the heat and stir in half the fresh coriander. Transfer to a shallow dish and top with the spring onions, pomegranate seeds, and remaining coriander. Serve warm with flatbread."}},{"id":77,"servings":4,"tipType":"meat","pairingsType":"middle-eastern","origin":{"ar":"الجزائر","en":"Algeria","ro":"Algeria"},"name":{"ar":"شخشوخة","en":"Chakhchoukha","ro":"Chakhchoukha"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"ingredients":{"ar":["600 غ كتف الخروف بالعظم أو رقبة، مقطعة إلى قطع بحجم 4 سم","400 غ حمص معلب (1 علبة 400 غ)، مصفى ومغسول","4 طماطم متوسطة (حوالي 400 غ)، مفرومة خشناً","2 بصلة متوسطة (حوالي 300 غ)، مفرومة ناعمة جداً","4 فصوص ثوم، مفرومة ناعماً","2 ملعقة كبيرة زيت نباتي","1 ملعقة صغيرة كمون مطحون","1 ملعقة صغيرة كزبرة مطحونة","1 ملعقة صغيرة فلفل أحمر حلو","1/2 ملعقة صغيرة قرفة + 1/2 ملعقة صغيرة فلفل أسود مطحون","1 ملعقة صغيرة ملح ناعم","600 مل ماء أو مرق الخروف","4 أوراق كبيرة من الرقاق (الخبز الجزائري) أو تورتيلا كبيرة ممزقة إلى قطع 5 سم","30 غ كزبرة طازجة وبقدونس مفلطح، مفرومان خشناً (للتزيين)"],"en":["600 g bone-in lamb shoulder or neck, cut into 4 cm pieces","400 g canned chickpeas (1 x 400 g can), rinsed and drained","4 medium tomatoes (about 400 g), roughly chopped","2 medium onions (about 300 g), finely diced","4 garlic cloves, finely minced","2 tbsp vegetable oil","1 tsp ground cumin","1 tsp ground coriander","1 tsp sweet paprika","1/2 tsp ground cinnamon + 1/2 tsp ground black pepper","1 tsp fine sea salt","600 ml water or lamb stock","4 large sheets of rougag (Algerian flatbread) or large tortillas, torn into 5 cm pieces","30 g fresh coriander and flat-leaf parsley, roughly chopped (to garnish)"],"ro":["600 g spata de miel cu os sau gat, taiata bucati de 4 cm","400 g naut fiert (1 cutie 400 g), scurs si clatit","4 rosii medii (circa 400 g), taiate grosier","2 cepe medii (circa 300 g), tocate marunt","4 căței de usturoi, tocati marunt","2 linguri ulei vegetal","1 lingurita chimen macinat","1 lingurita coriandru macinat","1 lingurita boia dulce","1/2 lingurita scortisoara + 1/2 lingurita piper negru","1 lingurita sare fina","600 ml apa sau supa de miel","4 foi mari de rougag (lipie algeriana) sau 4 tortilla mari, rupte bucati de 5 cm","30 g coriandru proaspat si patrunjel plat, tocat grosier (pentru decor)"]},"howIsMade":{"ar":"سخّني الزيت في قدر كبير ثقيل على نار عالية، أضيفي قطع الخروف على دفعات واقليها 4-5 دقائق حتى تتحمر من جميع الجهات. أضيفي البصل والثوم وأطبخيها 5 دقائق حتى تلين وتصبح ذهبية. أضيفي الكمون والكزبرة والفلفل الأحمر والقرفة والملح والفلفل الأسود واطبخي دقيقة واحدة حتى تفوح رائحة البهارات. أضيفي الطماطم واطبخيها 8-10 دقائق مع التقليب حتى تتحول إلى صلصة سميكة. صبّي الماء أو المرق، أضيفي الحمص وأحضري للغليان؛ خففي النار، غطّي القدر واتركيه يغلي على نار هادئة 50-60 دقيقة حتى يلين الخروف تماماً ويتفتت عن العظم. وزّعي قطع الخبز المسطح في قاع طبق تقديم كبير وصبّي فوقها اللحم الساخن والصلصة، مع ضغط الخبز برفق ليمتص السائل ويلين. زيّني بالكزبرة الطازجة والبقدونس وقدّمي فوراً.","en":"Heat the oil in a large heavy pot over medium-high heat, add the lamb in batches and sear for 4-5 minutes until browned on all sides. Add the onion and garlic and cook for 5 minutes until softened and golden. Stir in the cumin, coriander, paprika, cinnamon, salt, and pepper and cook for 1 minute until the spices smell toasted. Add the tomatoes and cook for 8-10 minutes, stirring occasionally, until they break down into a thick sauce. Pour in the water or stock, add the chickpeas, and bring to a boil; reduce the heat to low, cover, and simmer for 50-60 minutes until the lamb is completely tender and falling off the bone. Scatter the torn flatbread pieces over the bottom of a large serving dish and ladle the hot meat and sauce generously on top, pressing the bread down gently so it absorbs the liquid and softens — it should be soaked through but not dissolving. Garnish with the fresh coriander and parsley and serve immediately."}},{"id":78,"servings":4,"tipType":"meat","timeMins":{"total":330,"active":60},"pairingsType":"meat","origin":{"ar":"إندونيسيا","en":"Indonesia","ro":"Indonezia"},"name":{"ar":"رندنج","en":"Rendang","ro":"Rendang"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["1 كغ من لحم البقر (الكتف أو الصدر)، مقطع إلى مكعبات بحجم 5 سم","800 مل حليب جوز الهند كامل الدسم (2 x 400 مل)","5 بصل أخضر صغير (حوالي 150 غ)، مفروم خشناً","4 فصوص ثوم، مفرومة خشناً","2 ملعقة كبيرة زنجبيل طازج (حوالي 3 سم)، مفروم خشناً","1 ملعقة كبيرة جالنجال طازج (حوالي 2 سم) أو 1 ملعقة صغيرة معجون جالنجال","3 سيقان عشب الليمون، الأجزاء الفاتحة، مقطعة خشناً","4-6 فلفل أحمر مجفف، منقوع في الماء الدافئ 15 دقيقة، مصفى","4 أوراق كافير ليم، العرق الأوسط مزال، مقطعة ناعمة جداً","1 ملعقة صغيرة كركم مطحون","1 ملعقة صغيرة كزبرة مطحونة","1 ملعقة صغيرة كمون مطحون","1 ملعقة صغيرة ملح ناعم","1 ملعقة كبيرة زيت نباتي"],"en":["1 kg beef chuck or brisket, cut into 5 cm cubes","800 ml full-fat coconut milk (2 x 400 ml cans)","5 shallots (about 150 g), roughly chopped","4 garlic cloves, roughly chopped","2 tbsp fresh ginger (about 3 cm piece), roughly chopped","1 tbsp fresh galangal (about 2 cm) or 1 tsp galangal paste","3 lemongrass stalks, pale parts only, roughly sliced","4-6 dried red chillies, soaked in warm water 15 minutes and drained","4 kaffir lime leaves, stems removed, very finely shredded","1 tsp ground turmeric","1 tsp ground coriander","1 tsp ground cumin","1 tsp fine sea salt","1 tbsp vegetable oil"],"ro":["1 kg muschi de vita sau piept, taiat cuburi de 5 cm","800 ml lapte de cocos integral (2 x 400 ml)","5 esalote (circa 150 g), taiate grosier","4 căței de usturoi, tăiați grosier","2 linguri ghimbir proaspat (circa 3 cm), taiat grosier","1 lingura galangal proaspat (circa 2 cm) sau 1 lingurita pasta galangal","3 tulpini de lemongrass, partile palide, feliate grosier","4-6 ardei iuti rosii uscati, înmuiați in apa calda 15 minute, scursi","4 frunze de kafir lime, coada indepartata, maruntite fin","1 lingurita turmeric macinat","1 lingurita coriandru macinat","1 lingurita chimen macinat","1 lingurita sare fina","1 lingura ulei vegetal"]},"howIsMade":{"ar":"اخلطي البصل الأخضر والثوم والزنجبيل والجالنجال والليمون الحشيش والفلفل المنقوع مع 2 ملعقة كبيرة من حليب جوز الهند حتى تحصلي على معجون ناعم تماماً — نحو دقيقتين. سخّني الزيت في قدر كبير ثقيل على نار متوسطة، أضيفي معجون البهارات واطبخيه 5-6 دقائق مع التقليب المستمر حتى يصبح ذهبياً داكناً ويزول الرائحة النيئة. أضيفي مكعبات البقر وقلبيها لتغطيتها بالمعجون؛ اطبخيها 3-4 دقائق حتى تتلون قليلاً. صبّي بقية حليب جوز الهند، أضيفي أوراق كافير ليم والكركم والكزبرة والكمون والملح وأخلطي. أحضري للغليان ثم خففي النار وأتركيها تغلي مكشوفة لمدة ساعة ونصف مع التقليب كل 15-20 دقيقة حتى يتكاثف حليب جوز الهند ويأخذ لوناً بنياً فاتحاً. استمري في الطهي مع التقليب بشكل أكثر تكراراً كل 5-10 دقائق لمدة 30-45 دقيقة أخرى حتى تتبخر الصلصة تقريباً ويتمازج الزيت؛ سيبدأ اللحم بالقلي في دهنه الخاص ويتحول إلى اللون البني الداكن. قدّمي مع الأرز الأبيض المطبوخ على البخار.","en":"Blend the shallots, garlic, ginger, galangal, lemongrass, and soaked chillies with 2 tbsp of the coconut milk until completely smooth — about 2 minutes in a food processor. Heat the oil in a large heavy pot over medium heat, add the spice paste and cook for 5-6 minutes, stirring constantly, until deep golden and the raw smell has gone. Add the beef cubes and stir to coat with the paste; cook for 3-4 minutes until lightly coloured. Pour in the remaining coconut milk, add the kaffir lime leaves, turmeric, coriander, cumin, and salt, and stir to combine. Bring to a boil, then reduce to medium-low and simmer uncovered for 1.5 hours, stirring every 15-20 minutes, until the coconut milk thickens significantly and turns light brown. Continue cooking, stirring more frequently (every 5-10 minutes), for another 30-45 minutes as the sauce reduces to almost nothing and the oil splits from the coconut; the beef will begin to fry in its own fat and turn deep mahogany brown — this is when rendang is ready. Serve with steamed white rice."}},{"id":79,"servings":4,"tipType":"fish","timeMins":{"total":4380,"active":45},"pairingsType":"fish","origin":{"ar":"السويد","en":"Sweden","ro":"Suedia"},"name":{"ar":"غرافلاكس","en":"Gravlax","ro":"Gravlax"},"category":{"ar":"وجبة خفيفة","en":"Snack","ro":"Gustare"},"ingredients":{"ar":["600 غ من شرائح السلمون مع الجلد، منزوعة الشوك","3 ملاعق كبيرة من الملح البحري الخشن","2 ملعقة كبيرة سكر","1 ملعقة صغيرة من حبوب الفلفل الأبيض، مطحونة خشناً","60 غ من الشبت الطازج (1 حزمة كبيرة)، مفروم خشناً","2 ملعقة كبيرة من الأكوافيت أو الفودكا (اختياري)"],"en":["600 g salmon fillet, skin-on and pin-boned","3 tbsp coarse sea salt","2 tbsp caster sugar","1 tsp white peppercorns, coarsely crushed","60 g fresh dill (1 large bunch), roughly chopped","2 tbsp aquavit or vodka (optional)"],"ro":["600 g file de somon cu piele, cu oasele îndepărtate","3 linguri sare grunjoasă de mare","2 linguri zahăr tos","1 linguriță boabe de piper alb, zdrobite grosier","60 g mărar proaspăt (1 legătură mare), tocat grosier","2 linguri aquavit sau vodcă (opțional)"]},"howIsMade":{"ar":"اخلط الملح الخشن والسكر وحبوب الفلفل المطحونة في وعاء صغير. ضع السلمون بجانب الجلد للأسفل على قطعة كبيرة من غلاف التغليف؛ اضغط نصف الشبت بالتساوي على اللحم، وزّع خليط التمليح بالتساوي فوقه، ورشّ الأكوافيت إن كنت تستخدمه، ثم غطِّ بالشبت المتبقي. لفّ بإحكام بالغلاف وضعه في طبق عميق مع وضع طبق ثقيل فوقه لضغط السمكة. ضعه في الثلاجة من 48 إلى 72 ساعة، مع قلب الطرد كل 12 ساعة أثناء التمليح — ستتجمع المحلول في الطبق. أزل الغلاف، اشطف تحت الماء البارد وجفّف بمناشف الورق. قطّع بشرائح رفيعة جداً بشكل مائل بسكين مرن وقدّم على خبز الجاودار الداكن مع صلصة الخردل والشبت.","en":"Mix the coarse salt, sugar, and crushed peppercorns in a small bowl. Lay the salmon skin-side down on a large piece of cling film; press half the dill evenly over the flesh, spread the cure uniformly over the top, drizzle with aquavit if using, then cover with the remaining dill. Wrap tightly in the cling film and place in a deep dish, setting a heavy plate on top to press the fish. Refrigerate for 48-72 hours, turning the parcel every 12 hours as it cures — brine will pool in the dish. Unwrap, rinse under cold water, and pat dry with paper towels. Slice very thinly on the diagonal with a sharp flexible knife and serve on dark rye bread with a mustard-dill sauce."}},{"id":80,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ar":"بلجيكا","en":"Belgium","ro":"Belgia"},"name":{"ar":"ستوففليس","en":"Stoofvlees","ro":"Stoofvlees"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["1 كغ من لحم البقر للطهي ببطء (كتف أو صدر)، مقطّع مكعبات 4 سم","330 مل من البيرة البلجيكية الداكنة (Leffe Brune أو ما يشابهها)","500 غ من البصل (نحو 3 متوسطات)، مقطّع شرائح رفيعة","2 ملعقة كبيرة من خردل ديجون","شريحتان سميكتان (نحو 80 غ) من الخبز البني القديم، بدون قشرة","2 ملعقة كبيرة من الزيت النباتي","ورقتا غار","3 أغصان من الزعتر الطازج","1 ملعقة كبيرة سكر بني","1 ملعقة كبيرة خل نبيذ أحمر","1 ملعقة صغيرة ملح ناعم","نصف ملعقة صغيرة فلفل أسود مطحون"],"en":["1 kg beef stew meat (chuck or brisket), cut into 4 cm cubes","330 ml dark Belgian ale (Leffe Brune or similar)","500 g onions (about 3 medium), thinly sliced","2 tbsp Dijon mustard","2 thick slices (about 80 g) stale brown bread, crusts removed","2 tbsp neutral oil","2 bay leaves","3 fresh thyme sprigs","1 tbsp brown sugar","1 tbsp red wine vinegar","1 tsp fine salt","1/2 tsp ground black pepper"],"ro":["1 kg carne de vită pentru tocăniță (capac sau piept), tăiată cuburi de 4 cm","330 ml bere belgiană brună (Leffe Brune sau similară)","500 g ceapă (circa 3 medii), feliată subțire","2 linguri muștar Dijon","2 felii groase (circa 80 g) pâine brună veche, fără coajă","2 linguri ulei neutru","2 foi de dafin","3 crenguțe de cimbru proaspăt","1 lingură zahăr brun","1 lingură oțet de vin roșu","1 linguriță sare fină","1/2 linguriță piper negru măcinat"]},"howIsMade":{"ar":"تبّل اللحم بالملح والفلفل. سخّن الزيت في قدر كبير وثقيل على نار متوسطة عالية واقلِ اللحم على دفعات 3-4 دقائق لكل جانب حتى يصبح ذهبياً عميقاً؛ ثم انقله إلى طبق. خفّض الحرارة، أضف البصل إلى نفس القدر واطهُه 12-15 دقيقة مع التحريك أحياناً حتى يصبح طرياً وذهبياً. أعد اللحم إلى القدر، أضف أوراق الغار والزعتر، وصبّ البيرة — يجب أن تغطي اللحم تقريباً. ادهن وجهاً واحداً من كل شريحة خبز بالخردل بسخاء وضعها بجهة الخردل للأسفل فوق الحساء؛ سيذوب الخبز ويكثّف الصلصة. أضف السكر البني والخل، أحضر إلى غليان خفيف، غطّ بغطاء مفتوح قليلاً واطبخ على نار هادئة لمدة ساعتين مع التحريك كل 30 دقيقة حتى يصبح اللحم طرياً جداً. أزل الغطاء في آخر 20-30 دقيقة لتقليل الصلصة إلى مرق داكن لامع يلتصق بظهر الملعقة؛ أزل الغار والزعتر وقدّم مع البطاطا المقلية أو البيوريه.","en":"Season the beef with salt and pepper. Heat the oil in a large heavy casserole over medium-high and brown the beef in batches for 3-4 minutes per side until deeply golden; transfer to a plate. Reduce heat to medium, add the onions to the same pot and cook for 12-15 minutes, stirring occasionally, until soft and golden. Return the beef to the pot, tuck in the bay leaves and thyme, and pour in the beer — it should nearly cover the meat. Spread one side of each bread slice thickly with mustard and lay them mustard-side down on top of the stew; the bread will dissolve and thicken the sauce. Stir in the brown sugar and vinegar, bring to a gentle simmer, cover with the lid slightly ajar, and cook over low heat for 2 hours, stirring every 30 minutes, until the beef is very tender. Remove the lid for the final 20-30 minutes to reduce the sauce to a glossy dark gravy that coats the back of a spoon; discard the bay leaves and thyme and serve with frites or mashed potato."}},{"id":81,"servings":4,"tipType":"soup","pairingsType":"soup","origin":{"ar":"مولدوفا","en":"Moldova","ro":"Moldova"},"name":{"ar":"زياما","en":"Zeama","ro":"Zeamă"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"ingredients":{"ar":["1 كغ من قطع الدجاج مع العظم (أفخاذ وأرجل)","2 جزرة متوسطة (نحو 200 غ)، مقشّرة ومقطّعة إلى نصفين","1 بصلة متوسطة، مقطّعة إلى نصفين","2 ساق كرفس مع الأوراق","150 غ شعيرية بيض رفيعة","200 مل بورش أو 4 ملاعق كبيرة من عصير الليمون الطازج","حزمة صغيرة من اللوفيج الطازج (نحو 15 غ)، مفروم خشناً، أو بقدونس","1 ملعقة صغيرة ملح ناعم","نصف ملعقة صغيرة فلفل أبيض"],"en":["1 kg bone-in chicken pieces (legs and thighs)","2 medium carrots (about 200 g), peeled and halved","1 medium onion, halved","2 celery stalks with leaves","150 g thin egg noodles","200 ml borș (fermented wheat bran liquid) or 4 tbsp fresh lemon juice","1 small bunch fresh lovage (about 15 g), roughly chopped, or flat-leaf parsley","1 tsp fine salt","1/2 tsp white pepper"],"ro":["1 kg bucăți de pui cu os (pulpe și coapse)","2 morcovi medii (circa 200 g), curățați și tăiați în jumătate","1 ceapă medie, tăiată în jumătate","2 tulpini de țelină cu frunze","150 g tăiței subțiri de ou","200 ml borș sau 4 linguri suc proaspăt de lămâie","1 legătură mică leuștean proaspăt (circa 15 g), tocat grosier, sau pătrunjel","1 linguriță sare fină","1/2 linguriță piper alb"]},"howIsMade":{"ar":"ضع الدجاج في قدر كبير، غطّه بلترين من الماء البارد وأحضره إلى الغليان على نار متوسطة عالية؛ انزع الرغوة التي تطفو على السطح خلال أول 5-10 دقائق حتى يصبح المرق صافياً. أضف الجزر والبصل والكرفس، اخفض الحرارة إلى متوسطة منخفضة، غطّ جزئياً واترك ينضج 45-50 دقيقة حتى ينضج الدجاج تماماً ويبدأ في الانفصال عن العظام. أخرج الدجاج والخضار؛ تخلص من البصل، اقطع الجزر دوائر وفتّ الدجاج إلى قطع صغيرة مع نزع الجلد والعظام. أعد الدجاج المفتوت ودوائر الجزر إلى القدر وأعده إلى الغليان الخفيف على نار متوسطة. أضف الشعيرية واطبخ 5-7 دقائق (أو حسب تعليمات العبوة) حتى تنضج. صبّ البورش أو عصير الليمون، حرّك وتذوّق — يجب أن يكون للشوربة طعم حامض لطيف؛ أضف المزيد حسب الحاجة. اضبط التوابل بالملح والفلفل الأبيض، أضف اللوفيج أو البقدونس وقدّم فوراً.","en":"Place the chicken in a large pot, cover with 2 litres of cold water, and bring to a boil over medium-high heat; skim the foam that rises for the first 5-10 minutes until the broth runs clear. Add the carrots, onion, and celery, reduce heat to medium-low, partially cover, and simmer for 45-50 minutes until the chicken is cooked through and falling from the bone. Lift out the chicken and vegetables; discard the onion, slice the carrots into rounds, and shred the chicken into bite-sized pieces, discarding skin and bones. Return the shredded chicken and carrot rounds to the pot and bring back to a simmer over medium heat. Add the noodles and cook for 5-7 minutes (or per packet) until just tender. Pour in the borș or lemon juice, stir, and taste — the soup should have a pleasant sour edge; add more as needed. Season with salt and white pepper, stir in the lovage or parsley, and serve immediately."}},{"id":82,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ar":"أستراليا","en":"Australia","ro":"Australia"},"name":{"ar":"فطيرة اللحم","en":"Meat Pie","ro":"Meat Pie"},"category":{"ar":"وجبة خفيفة","en":"Snack","ro":"Gustare"},"ingredients":{"ar":["375 غ من عجينة البسكويت الجاهزة","250 غ من عجينة الفيلو الجاهزة","500 غ من اللحم البقري المفروم (خالي الدهن)","1 بصلة متوسطة (نحو 150 غ)، مقطّعة ناعماً","2 فص ثوم، مفروم","250 مل مرق لحم بقري","2 ملعقة كبيرة معجون طماطم","1 ملعقة كبيرة صلصة ورسيستر","2 ملعقة كبيرة دقيق","1 بيضة، مخفوقة قليلاً، للدهن","1 ملعقة صغيرة ملح ناعم","نصف ملعقة صغيرة فلفل أسود مطحون"],"en":["375 g ready-made shortcrust pastry","250 g ready-made puff pastry","500 g lean beef mince","1 medium onion (about 150 g), finely diced","2 garlic cloves, minced","250 ml beef stock","2 tbsp tomato paste","1 tbsp Worcestershire sauce","2 tbsp plain flour","1 egg, lightly beaten, for brushing","1 tsp fine salt","1/2 tsp ground black pepper"],"ro":["375 g aluat fraged gata preparat","250 g aluat foietaj gata preparat","500 g carne de vită tocată (slabă)","1 ceapă medie (circa 150 g), tăiată mărunt","2 căței de usturoi, pisați","250 ml supă de vită","2 linguri pastă de roșii","1 lingură sos Worcestershire","2 linguri făină albă","1 ou, bătut ușor, pentru uns","1 linguriță sare fină","1/2 linguriță piper negru măcinat"]},"howIsMade":{"ar":"سخّن الفرن إلى 200 درجة مئوية (180 مع مروحة). سخّن قليلاً من الزيت في مقلاة كبيرة على نار متوسطة عالية، أضف البصل والثوم واطبخ 3-4 دقائق حتى يلينا. أضف اللحم المفروم واطبخ مع تفتيته بملعقة 6-8 دقائق حتى يصبح بنياً. أضف الدقيق واطبخ دقيقة، ثم أضف مرق اللحم ومعجون الطماطم وصلصة ورسيستر والملح والفلفل؛ اخلط جيداً. اطبخ على نار متوسطة 12-15 دقيقة مع التحريك حتى يتكاثف الصلصة ويلتصق بظهر الملعقة — يجب أن يكون الحشو رطباً لكن غير سائل؛ ارفع من النار واترك يبرد 15 دقيقة. افردي العجينة الهشة واقطعي 4 دوائر لتبطين 4 قوالب فردية (نحو 12 سم)؛ اضغطيها في القوالب وخزّي القواعد بشوكة. وزّع الحشو بالتساوي، غطِّ بدوائر العجين المورق واضغط الحواف للإغلاق وادهن ببيض مخفوق. اخبز 25-30 دقيقة حتى يصبح ذهبياً عميقاً وتنتفخ الأغطية وتصبح مقرمشة؛ ارح 5 دقائق ثم قدّم مع صلصة الطماطم.","en":"Preheat the oven to 200°C (180°C fan). Heat a drizzle of oil in a large frying pan over medium-high heat, add the onion and garlic and cook for 3-4 minutes until softened. Add the beef mince and cook, breaking it up with a spoon, for 6-8 minutes until browned all over. Stir in the flour, cook for 1 minute, then add the stock, tomato paste, Worcestershire sauce, salt, and pepper; stir to combine. Simmer over medium heat for 12-15 minutes, stirring occasionally, until the gravy thickens to coat the back of a spoon — the filling should be moist but not runny; remove from heat and cool for 15 minutes. Roll out the shortcrust pastry and cut 4 circles to line 4 individual pie tins (about 12 cm diameter); press into the tins and prick the bases with a fork. Divide the filling evenly between the tins, top with puff pastry lids, press the edges to seal, and brush with beaten egg. Bake for 25-30 minutes until deep golden and the lids are puffed and crisp; rest for 5 minutes then serve with tomato sauce."}},{"id":83,"servings":4,"tipType":"def","pairingsType":"middle-eastern","origin":{"ar":"سوريا","en":"Syria","ro":"Siria"},"name":{"ar":"فتة","en":"Fatteh","ro":"Fatteh"},"category":{"ar":"فطور","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"ar":["رغيفان كبيران من الخبز العربي (نحو 200 غ)، ممزّقان إلى قطع","400 غ من الحمص المعلّب (1 علبة 400 غ)، مصفّى ومغسول","500 غ لبن زبادي كامل الدسم","3 فصوص ثوم، مفروم","2 ملعقة كبيرة طحينة","2 ملعقة كبيرة عصير ليمون طازج","3 ملاعق كبيرة زبدة غير مملّحة","50 غ صنوبر","1 ملعقة صغيرة كمون مطحون","1 ملعقة صغيرة بابريكا حلوة","نصف ملعقة صغيرة ملح ناعم","2 ملعقة كبيرة بقدونس طازج، مفروم ناعماً"],"en":["2 large pita breads (about 200 g), torn into bite-sized pieces","400 g canned chickpeas (1 x 400 g can), drained and rinsed","500 g full-fat plain yogurt","3 garlic cloves, minced","2 tbsp tahini","2 tbsp fresh lemon juice","3 tbsp unsalted butter","50 g pine nuts","1 tsp ground cumin","1 tsp sweet paprika","1/2 tsp fine salt","2 tbsp fresh parsley, finely chopped"],"ro":["2 pâini pita mari (circa 200 g), rupte în bucăți","400 g năut din conservă (1 x 400 g), scurs și clătit","500 g iaurt integral simplu","3 căței de usturoi, pisați","2 linguri tahini","2 linguri suc proaspăt de lămâie","3 linguri unt nesărat","50 g semințe de pin","1 linguriță chimion măcinat","1 linguriță boia dulce","1/2 linguriță sare fină","2 linguri pătrunjel proaspăt, tocat fin"]},"howIsMade":{"ar":"سخّن الفرن إلى 200 درجة مئوية. اخلط قطع الخبز العربي مع قليل من الزيت، وزّعها على صينية واخبزها 8-10 دقائق حتى تصبح ذهبية ومقرمشة. صفّي الحمص؛ سخّنه في قدر صغير مع رشة ملح وكمون على نار متوسطة 3-4 دقائق حتى يدفأ. اخفق اللبن مع الثوم والطحينة وعصير الليمون والملح حتى تحصل على صلصة ناعمة؛ اضبط التوابل. افرد قطع الخبز المحمص في طبقة متساوية في طبق تقديم كبير. ضع الحمص الدافئ بالتساوي فوق طبقة الخبز. صبّ صلصة اللبن فوق الحمص بسخاء مغطياً كل شيء. أذب الزبدة في مقلاة صغيرة على نار متوسطة؛ أضف الصنوبر واطبخ 2-3 دقائق مع التحريك حتى يتحول للذهبي؛ أضف البابريكا وصبّ فوراً الزبدة الساخنة على اللبن. رشّ البقدونس المفروم وقدّم فوراً قبل أن يتشرب الخبز.","en":"Preheat the oven to 200°C. Toss the pita pieces with a drizzle of oil, spread on a baking tray and bake for 8-10 minutes until golden and crisp. Drain the chickpeas; heat in a small saucepan with a pinch of salt and cumin over medium heat for 3-4 minutes until warmed through. Whisk the yogurt, garlic, tahini, lemon juice, and salt until smooth; taste and adjust seasoning. Spread the toasted pita pieces in an even layer on a large serving platter. Spoon the warm chickpeas evenly over the pita. Pour the yogurt sauce over the chickpeas, covering everything generously. Melt the butter in a small pan over medium heat; add the pine nuts and cook for 2-3 minutes, stirring, until golden; stir in the paprika and immediately drizzle the hot butter and pine nuts over the yogurt. Scatter the chopped parsley on top and serve immediately before the pita softens."}},{"id":84,"servings":4,"tipType":"def","pairingsType":"def","origin":{"ar":"الدنمارك","en":"Denmark","ro":"Danemarca"},"name":{"ar":"سموربرود","en":"Smørrebrød","ro":"Smørrebrød"},"category":{"ar":"فطور","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"ar":["8 شرائح من خبز الجاودار الداكن الدانماركي (روغبرود)، نحو 400 غ","100 غ من الزبدة غير المملّحة، طرية","400 غ من فيليه الرنجة المخللة (8 فيليهات)، مصفّاة","4 بيضات مسلوقة (10 دقائق)، مقشّرة ومقطّعة دوائر","1 بصلة حمراء صغيرة (نحو 80 غ)، مقطّعة حلقات رفيعة جداً","4 فجلات، مقطّعة دوائر رفيعة","2 ملعقة كبيرة كبر، مصفّى","4 ملاعق كبيرة قشدة حامضة أو كريم فريش","1 ملعقة صغيرة خردل ديجون","حزمة صغيرة من الشبت الطازج (نحو 15 غ)","نصف ملعقة صغيرة ملح ناعم"],"en":["8 slices dark rye bread (rugbrød), about 400 g","100 g unsalted butter, softened","400 g pickled herring fillets (8 fillets), drained","4 eggs, hard-boiled (10 minutes), peeled and sliced into rounds","1 small red onion (about 80 g), very finely sliced into rings","4 radishes, thinly sliced into rounds","2 tbsp capers, drained","4 tbsp soured cream or crème fraîche","1 tsp Dijon mustard","1 small bunch fresh dill (about 15 g)","1/2 tsp fine salt"],"ro":["8 felii de pâine daneză de secară (rugbrød), circa 400 g","100 g unt nesărat, înmuiat","400 g hering murat (8 fileuri), scurs","4 ouă fierte tari (10 minute), decojite și feliate în rondele","1 ceapă roșie mică (circa 80 g), feliată subțire în inele","4 ridichi, feliate subțire în rondele","2 linguri capere, scurse","4 linguri smântână sau crème fraîche","1 linguriță muștar Dijon","1 legătură mică de mărar proaspăt (circa 15 g)","1/2 linguriță sare fină"]},"howIsMade":{"ar":"اسلق البيض: ضعه في ماء مغلٍ واطبخه 10 دقائق، ثم انقله إلى ماء بارد لمدة 5 دقائق؛ اقشره وقطّعه دوائر. اخلط القشدة الحامضة مع خردل ديجون وقليل من الملح في وعاء صغير. ادهن كل شريحة من خبز الجاودار بسخاء بالزبدة الطرية حتى الحواف — نحو ملعقة كبيرة لكل شريحة. ضع 1-2 فيليه رنجة مخللة على كل شريحة مدهونة، اتركها تنحني بشكل طبيعي. ضع ملعقة صغيرة من كريمة الخردل فوق الرنجة، ثم رتّب 2-3 دوائر بيض بجانبها. رشّ حلقات البصل الأحمر وشرائح الفجل والكبر فوقها. أنهِ بأغصان الشبت الطازج وقدّم فوراً مع بيرة باردة أو أكوافيت.","en":"Hard-boil the eggs: lower into boiling water and cook for 10 minutes, then transfer to cold water for 5 minutes before peeling and slicing into rounds. Mix the soured cream with the Dijon mustard and a pinch of salt in a small bowl. Spread each slice of rye bread generously with softened butter right to the edges — about 1 tablespoon per slice. Lay 1-2 pickled herring fillets on each buttered slice, letting them curve naturally over the surface. Spoon a small dollop of mustard cream onto the herring, then arrange 2-3 egg rounds alongside. Scatter red onion rings, radish slices, and capers over the top. Finish with fresh dill sprigs and serve immediately with a cold beer or aquavit."}},{"id":85,"origin":{"ar":"كوريا الشمالية","en":"North Korea","ro":"Coreea de Nord"},"name":{"ar":"نِينغميون","en":"Naengmyeon","ro":"Naengmyeon"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","timeMins":{"total":600,"active":60},"pairingsType":"korean","ingredients":{"ar":["400غ نودلز الحنطة السوداء الجافة (ميميل-غوكسو)","300غ صدر لحم بقري مسلوق حتى الطراوة، مبرّد ومقطّع رفيعاً","1.5 لتر مرق صدر اللحم البقري، مبرّد تماماً ومزال دهنه","كمثرى كورية واحدة (ناشي)، مقشّرة ومقطّعة رفيعاً","خيارة متوسطة مقطّعة شرائح دقيقة","4 بيضات مسلوقة منصّفة","2 ملعقة كبيرة خل الأرز","1 ملعقة صغيرة خردل كوري (غيوجا) أو خردل إنجليزي","1 ملعقة كبيرة غوتشوغارو (اختياري كتوابل مائدة)","ملح وسكر حسب الذوق للمرق","مكعبات ثلج حسب الحاجة"],"en":["400g dried buckwheat noodles (memil-guksu)","300g beef brisket, simmered until tender, chilled, thinly sliced","1.5L beef brisket broth, fully chilled and defatted","1 Korean pear (nashi), peeled, thinly sliced","1 medium cucumber, julienned","4 hard-boiled eggs, halved","2 tbsp rice vinegar","1 tsp Korean mustard (gyeoja) or English mustard","1 tbsp gochugaru (optional, as table condiment)","salt and sugar to taste for the broth","ice cubes as needed"],"ro":["400g tăiței de hrișcă uscați (memil-guksu)","300g piept de vită, fiert și refrigerat, feliat subțire","1.5L supă de piept de vită (răcită complet la frigider, degresată)","1 pară coreeană (nashi), curățată, feliată subțire","1 castravete mediu, feliat julien","4 ouă fierte tari, înjumătățite","2 linguri oțet de orez","1 linguriță muștar coreean (gyeoja) sau muștar englez","1 lingură gochugaru (opțional, pentru condiment la masă)","sare și zahăr după gust pentru supa de bază","cuburi de gheață — câte este necesar"]},"howIsMade":{"ar":"في اليوم السابق: اسلق صدر اللحم البقري في 2 لتر ماء مع ملعقة صغيرة ملح وقطعة زنجبيل 2 سم و3 بصل أخضر على نار هادئة 1.5–2 ساعة. دع اللحم يبرد في المرق ثم ضعه بالثلاجة طوال الليل. في اليوم التالي أزل طبقة الدهن المتجمّد. تبّل المرق البارد بخل الأرز والسكر والملح — يجب أن يكون خفيف الحموضة وخفيف الحلاوة. أضف ثلجاً إضافياً إذا لزم. اسلق النودلز حسب التعليمات (3–4 دقائق)، صفّها واشطفها فوراً تحت ماء بارد جارٍ 30 ثانية مع الفرك باليدين. ضعها في أطباق عميقة، أضف المرق البارد، وضع فوقها اللحم والكمثرى والخيار والبيض. قدّمها فوراً مع خل وخردل على الجانب.","en":"Day before: simmer beef brisket in 2L water with 1 tsp salt, a 2 cm piece of ginger, and 3 spring onions over low heat for 1.5–2 hours. Let meat cool in the broth, then refrigerate overnight. Next day, lift off the solidified fat layer. Season the cold broth with rice vinegar, sugar, and salt — it should be lightly tart and subtly sweet. Chill further with ice if needed. Cook noodles per packet (usually 3–4 minutes), drain and immediately rinse under cold running water for 30 seconds, rubbing with hands to remove starch and chill completely. Nest noodles in deep bowls. Ladle cold broth to cover. Top with sliced brisket, pear, julienned cucumber, and halved egg. Serve at once with vinegar and mustard on the side."}},{"id":86,"origin":{"ar":"باكستان","en":"Pakistan","ro":"Pakistan"},"name":{"ar":"نهاري","en":"Nihari","ro":"Nihari"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"indian","ingredients":{"ar":["1 كيلو كراع بقر بالعظم، مقطّع إلى قطع 5 سم","2 عظمة نخاع، كل منها نحو 5 سم","4 ملاعق كبيرة سمن مُوضَّح (غي) أو زيت","2 بصلة كبيرة (~300 غ)، مقطّعة شرائح رفيعة","2 ملعقة كبيرة معجون الزنجبيل والثوم","1.5 ملعقة صغيرة بهار فلفل أحمر حار","1 ملعقة صغيرة كزبرة مطحونة","نصف ملعقة صغيرة كركم مطحون","1.5 ملعقة صغيرة ملح","1 ملعقة صغيرة مسالا نهاري أو غارام مسالا","3 ملاعق كبيرة دقيق ممزوجة بـ 100 مل ماء بارد","5 سم زنجبيل طازج مقشور ومقطّع جوليان، للتقديم","ليمونة مقطّعة أرباعاً وحفنة أوراق كزبرة طازجة، للتقديم"],"en":["1 kg bone-in beef shanks, cut into 5 cm pieces","2 marrow bones, each about 5 cm long","4 tbsp ghee or clarified butter","2 large onions (~300 g), thinly sliced","2 tbsp ginger-garlic paste","1.5 tsp red chilli powder","1 tsp ground coriander","1/2 tsp ground turmeric","1.5 tsp salt","1 tsp nihari masala or garam masala","3 tbsp plain flour mixed with 100 ml cold water","5 cm piece of fresh ginger, peeled and julienned, to serve","1 lemon cut into wedges and a handful of fresh coriander leaves, to serve"],"ro":["1 kg rasol de vită cu os, tăiat în bucăți de 5 cm","2 oase cu măduvă, fiecare de aproximativ 5 cm","4 linguri unt clarificat (ghee) sau ulei","2 cepe mari (~300 g), feliate subțire","2 linguri pastă de ghimbir și usturoi","1,5 linguriță praf de ardei iute roșu","1 linguriță coriandru măcinat","1/2 linguriță turmeric măcinat","1,5 linguriță sare","1 linguriță masala nihari sau garam masala","3 linguri făină albă amestecate cu 100 ml apă rece","5 cm ghimbir proaspăt, curățat și juliennat, pentru servire","1 lămâie tăiată în felii și un mănunchi de frunze de coriandru, pentru servire"]},"howIsMade":{"ar":"سخّن 3 ملاعق كبيرة من الغي في قدر كبير على نار متوسطة إلى عالية، واقلِ البصل 12–15 دقيقة مع التقليب المستمر حتى يصبح ذهبي داكن، ثم أخرجه بالمِغرفة المثقّبة وضعه جانباً. أضف الغي المتبقي، ارفع الحرارة وحمّر قطع الكراع والعظام على دفعات، 3–4 دقائق لكل جانب، ثم ضعها جانباً. خفّض الحرارة للمتوسط، أضف معجون الزنجبيل والثوم واقلِ دقيقتين حتى يفوح الأريج، ثم أضف الفلفل الحار والكزبرة والكركم وقلّب 30 ثانية. أعد اللحم والبصل المقلي إلى القدر، أضف الملح والماء حتى يعلو اللحم بـ 5 سم (نحو 1.2 لتر)، وأزل الرغوة عند الغليان. اخفض الحرارة لأدنى درجة، غطِّ القدر جيداً واطبخ 3–4 ساعات حتى ينفصل اللحم عن العظم بسهولة. أضف مسالا النهاري، صبّ عجينة الدقيق في تيار رفيع مع التحريك، واطبخ مكشوفاً 10–15 دقيقة حتى يتكثّف المرق ويغطي ظهر الملعقة. اسكب في أطباق وزيّن بالزنجبيل الجوليان وأوراق الكزبرة وعصير الليمون، وقدّم مع خبز النان أو خبز مقرمش.","en":"Heat 3 tbsp ghee in a large heavy pot over medium-high heat and fry the onions for 12–15 minutes, stirring often, until deep golden brown, then remove with a slotted spoon and set aside. Add the remaining ghee, raise the heat to high, and sear the beef shanks and marrow bones in batches for 3–4 minutes per side until browned, then set aside. Reduce heat to medium, add the ginger-garlic paste and fry for 1–2 minutes until fragrant, then add the chilli powder, coriander, and turmeric and stir for 30 seconds. Return the meat and fried onions to the pot, add the salt and enough water to cover by 5 cm (about 1.2 litres), bring to a boil and skim any foam. Reduce heat to the lowest setting, cover tightly, and simmer for 3–4 hours until the beef is completely tender and falling from the bone. Stir in the nihari masala, pour in the flour slurry in a thin stream while stirring, and simmer uncovered for 10–15 minutes until the broth thickens to a glossy consistency that coats the back of a spoon. Ladle into bowls, top with julienned ginger, coriander leaves, and a squeeze of lemon, and serve with naan or crusty bread."}},{"id":87,"origin":{"ar":"فيتنام","en":"Vietnam","ro":"Vietnam"},"name":{"ar":"بون بو هوي","en":"Bún bò Huế","ro":"Bún bò Huế"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","timeMins":{"total":195,"active":75},"pairingsType":"vietnamese","ingredients":{"ar":["600 غ كراع خنزير بالعظم، مقطّع إلى قطع 4 سم","500 غ عظام بقر، مسلوقة مسبقاً","400 غ ساق بقر، مقطّعة شرائح رفيعة","400 غ شعيرية أرز دائرية جافة (بون)","3 سيقان حشيشة الليمون، مطحونة ومقطّعة إلى قطع 5 سم","3 كراث صغير، مقسومة إلى النصف ومحروقة قليلاً","4 فصوص ثوم، مهروسة","2 ملعقة كبيرة معجون روبيان مخمّر (مام روك)","3 ملاعق كبيرة صلصة السمك","2 ملعقة كبيرة زيت الفلفل الحار أو 1 ملعقة صغيرة رقائق فلفل جاف","1 ملعقة صغيرة سكر","1 ملعقة صغيرة ملح","للتقديم: 200 غ فول الصويا المنبت، أعشاب طازجة (نعناع أو كزبرة فيتنامية)، 2 ليمون أخضر مقطّع وشرائح فلفل أحمر حار"],"en":["600 g bone-in pork hock, cut into 4 cm pieces","500 g beef bones, blanched","400 g beef shank, thinly sliced","400 g dried round rice vermicelli (bún)","3 lemongrass stalks, bruised and cut into 5 cm pieces","3 shallots, halved and charred","4 garlic cloves, bruised","2 tbsp fermented shrimp paste (mắm ruốc)","3 tbsp fish sauce","2 tbsp chilli oil or 1 tsp dried chilli flakes","1 tsp sugar","1 tsp salt","to serve: 200 g bean sprouts, fresh herbs (mint, perilla or Vietnamese coriander), 2 limes cut into wedges, and 2 red chillies sliced"],"ro":["600 g picior de porc cu os, tăiat în bucăți de 4 cm","500 g oase de vită, opărite","400 g rasol de vită, feliat subțire","400 g tăiței rotunzi de orez uscați (bún)","3 tulpini de lemongrass, zdrobite și tăiate în bucăți de 5 cm","3 șalote, tăiate pe jumătate și pârlite","4 căței de usturoi, zdrobiți","2 linguri pastă de creveți fermentați (mắm ruốc)","3 linguri sos de pește","2 linguri ulei de ardei iute sau 1 linguriță fulgi de ardei iute","1 linguriță zahăr","1 linguriță sare","pentru servit: 200 g muguri de fasole, ierburi proaspete (mentă sau coriandru vietnamez), 2 lămâi verzi în sferturi și 2 ardei iuți roșii felieți"]},"howIsMade":{"ar":"اسلق كراع الخنزير وعظام البقر في الماء المغلي 5 دقائق، ثم صفّ وشطف بالماء البارد. احرق الكراث والثوم في مقلاة جافة على نار عالية 3–4 دقائق حتى يسودّ قليلاً. ضع الكراع والعظام وحشيشة الليمون والكراث والثوم المحروق في قدر كبير، أضف 2.5 لتر ماء بارد، اغلِ وأزل الرغوة، ثم خفّض النار واطبخ ساعة كاملة. أذِب معجون الروبيان في 100 مل من المرق الساخن وصبّه في القدر، ثم أضف صلصة السمك والسكر والملح وزيت الفلفل وعدّل التوابل حتى يصبح المرق لذيذاً وخفيف الحدة وعطراً. أضف شرائح ساق البقر واطبخها على نار هادئة 15–20 دقيقة حتى تنضج وتطرأ، ثم اخرجها وقطّعها رقيقة. اطبخ الشعيرية حسب التعليمات (عادةً 3–5 دقائق)، صفّها ووزّعها في 4 أطباق عميقة. اسكب المرق الساخن فوق الشعيرية وضع شرائح الكراع وساق البقر، وقدّم فوراً مع فول الصويا المنبت والأعشاب الطازجة وشرائح الليمون والفلفل الحار.","en":"Blanch the pork hock and beef bones in boiling water for 5 minutes, drain and rinse under cold water. Char the shallots and garlic cut-side down in a dry pan over high heat for 3–4 minutes until lightly blackened. Place the pork hock, bones, lemongrass, charred shallots, and garlic in a large pot, add 2.5 litres of cold water, bring to a boil, skim well, then simmer over low heat for 1 hour. Dissolve the shrimp paste in 100 ml of hot broth, stir into the pot, then add fish sauce, sugar, salt, and chilli oil, adjusting until the broth is savoury, lightly spicy, and fragrant. Add the beef shank slices and poach over gentle heat for 15–20 minutes until just cooked through and tender, then remove and slice thinly. Cook the rice vermicelli according to packet instructions (usually 3–5 minutes), drain, and divide among 4 deep bowls. Ladle the hot broth over the noodles, top with slices of pork hock and beef shank, and serve immediately with bean sprouts, fresh herbs, lime wedges, and sliced chilli on the side."}},{"id":88,"origin":{"ar":"البرازيل","en":"Brazil","ro":"Brazilia"},"name":{"ar":"موكيكا","en":"Moqueca","ro":"Moqueca"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"fish","pairingsType":"latin","ingredients":{"ar":["800 غ شرائح سمك أبيض طري (قاروص، باكاليار أو لوت)، مقطّعة إلى قطع 5 سم","2 ليمون أخضر (لايم)، عصيرها فقط","1 ملعقة صغيرة ملح","1 بصلة كبيرة (~180 غ)، مقطّعة شرائح رفيعة","4 فصوص ثوم، مفرومة ناعماً","1 فلفل أحمر (~150 غ)، منزوع البذور ومقطّع شرائح","1 فلفل أخضر (~150 غ)، منزوع البذور ومقطّع شرائح","2 حبة طماطم كبيرة ناضجة (~300 غ)، مقطّعة مكعبات","400 مل حليب جوز الهند كامل الدسم","2 ملعقة كبيرة زيت النخيل الأحمر (دندي)","20 غ كزبرة طازجة، مفرومة خشناً، والمزيد للتقديم","نصف ملعقة صغيرة فلفل أسود مطحون"],"en":["800 g firm white fish fillets (sea bass, cod, or monkfish), cut into 5 cm chunks","2 limes, juice only","1 tsp salt","1 large onion (~180 g), thinly sliced","4 garlic cloves, finely minced","1 red bell pepper (~150 g), deseeded and sliced","1 green bell pepper (~150 g), deseeded and sliced","2 large ripe tomatoes (~300 g), diced","400 ml full-fat coconut milk","2 tbsp dendê (red palm oil)","20 g fresh coriander, roughly chopped, plus extra to serve","1/2 tsp ground black pepper"],"ro":["800 g fileuri de pește alb ferm (biban de mare, cod sau merluciu), tăiate în bucăți de 5 cm","2 lămâi verzi (lime), sucul","1 linguriță sare","1 ceapă mare (~180 g), feliată subțire","4 căței de usturoi, tocați mărunt","1 ardei gras roșu (~150 g), curat și feliat","1 ardei gras verde (~150 g), curat și feliat","2 roșii coapte mari (~300 g), tocate cuburi","400 ml lapte de cocos integral","2 linguri ulei de palmier roșu (dendê)","20 g coriandru proaspăt, tocat grosier, plus extra pentru garnit","1/2 linguriță piper negru măcinat"]},"howIsMade":{"ar":"تبّل قطع السمك بعصير الليمون الأخضر ونصف ملعقة صغيرة ملح والفلفل الأسود واتركها لتتبّل 15–20 دقيقة أثناء تحضير الخضار. سخّن ملعقة كبيرة زيت دندي في مقلاة واسعة على نار متوسطة، أضف البصل واطبخه 6–8 دقائق حتى يصبح طرياً وذهبي اللون خفيفاً. أضف الثوم والفلفل والطماطم وقلّب جيداً واطبخ 5 دقائق حتى تبدأ الطماطم بالتفكك. ضع السمك المتبّل فوق الخضار في طبقة واحدة، صبّ حليب جوز الهند من فوق وادفع السمك برفق داخل السائل دون التحريك. أحضر لغليان خفيف، غطِّ واطبخ 12–15 دقيقة حتى يصبح السمك معتماً ويتفتت بسهولة. صبّ الملعقة الكبيرة المتبقية من زيت الدندي على السطح، رشّ الكزبرة وعدّل الملح. قدّم مباشرةً من المقلاة مع أرز أبيض أو خبز، وشرائح الليمون الأخضر جانباً.","en":"Toss the fish chunks with the lime juice, 1/2 tsp salt, and the black pepper and leave to marinate for 15–20 minutes while you prepare the vegetables. Heat 1 tbsp dendê oil in a large wide pan over medium heat, add the onion slices, and cook for 6–8 minutes until softened and lightly golden. Add the garlic, bell peppers, and tomatoes, stir well, and cook for 5 minutes until the tomatoes begin to break down. Lay the marinated fish over the vegetables in a single layer, pour the coconut milk over the top, and gently push the fish down into the liquid without stirring. Bring to a gentle simmer, cover, and cook for 12–15 minutes until the fish is opaque and flakes easily when pressed. Drizzle the remaining 1 tbsp dendê oil over the surface, scatter the coriander on top, and taste for salt. Serve directly from the pan with white rice or crusty bread, with lime wedges on the side."}},{"id":89,"origin":{"ar":"إسرائيل","en":"Israel","ro":"Israel"},"name":{"ar":"سبيخ","en":"Sabich","ro":"Sabich"},"category":{"ar":"فطور","en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"def","pairingsType":"middle-eastern","ingredients":{"ar":["4 خبز بيتا كبير","1 باذنجانة كبيرة (~400 غ)، مقطّعة شرائح سمكها 1 سم","4 ملاعق كبيرة زيت للقلي","4 بيضات","300 غ بطاطس شمعية، مسلوقة حتى تطرأ ومقطّعة شرائح 1 سم","4 ملاعق كبيرة طحينة","1 حبة ليمون، عصيرها فقط","فص ثوم واحد، مهروس","4 ملاعق كبيرة صوص عمبة (صوص المانغو المخلّل)","2 حبة طماطم (~200 غ)، مفرومة ناعماً","1 خيارة (~150 غ)، مفرومة ناعماً","1 ملعقة صغيرة ملح","4 شرائح خيار مخلّل وبقدونس طازج للتقديم"],"en":["4 large pita breads","1 large aubergine (~400 g), cut into 1 cm rounds","4 tbsp oil for frying","4 eggs","300 g waxy potatoes, boiled until tender and sliced 1 cm thick","4 tbsp tahini paste","1 lemon, juice only","1 garlic clove, crushed","4 tbsp amba sauce (fermented mango pickle sauce)","2 tomatoes (~200 g), finely diced","1 cucumber (~150 g), finely diced","1 tsp salt","4 slices pickled cucumber and fresh parsley, to serve"],"ro":["4 lipii pita mari","1 vânătă mare (~400 g), tăiată în felii de 1 cm","4 linguri ulei pentru prăjit","4 ouă","300 g cartofi galbeni, fierți până sunt moi și feliați la 1 cm grosime","4 linguri pastă de tahini","1 lămâie, sucul","1 cățel de usturoi, zdrobit","4 linguri sos amba (sos din mango murat)","2 roșii (~200 g), tăiate mărunt","1 castravete (~150 g), tăiat mărunt","1 linguriță sare","4 felii castraveți murați și pătrunjel proaspăt, pentru servire"]},"howIsMade":{"ar":"اسلق البيض: ضعه في الماء المغلي واطبخه 10 دقائق، ثم انقله إلى ماء بارد 5 دقائق، قشّره وقطّعه شرائح. رشّ شرائح الباذنجان بنصف ملعقة صغيرة ملح على الوجهين واتركه 10 دقائق، ثم جفّفه بمناديل المطبخ. سخّن الزيت في مقلاة كبيرة على نار متوسطة وقلي الباذنجان على دفعات، 3–4 دقائق لكل وجه حتى يصبح ذهبي داكن وطرياً، ثم صفّه على ورق المطبخ. اخفق الطحينة مع عصير الليمون والثوم و3–4 ملاعق كبيرة ماء بارد حتى تصبح كريمية وسائلة. اخلط الطماطم والخيار المفروم مع نصف ملعقة صغيرة ملح وقليل من زيت الزيتون. سخّن كل رغيف بيتا دقيقة واحدة على كل وجه في مقلاة جافة، ثم افتح الجيب بحذر. احشُ كل خبزة بالباذنجان المقلي وشرائح البطاطس والبيض والسلطة وطحينة وافرة وملعقة عمبة وخيار مخلّل وبقدونس طازج، وقدّمها فوراً.","en":"Hard-boil the eggs: lower into boiling water, cook for 10 minutes, then transfer to cold water for 5 minutes, peel, and slice into rounds. Sprinkle the aubergine slices on both sides with 1/2 tsp salt and leave for 10 minutes, then pat dry with kitchen paper. Heat the oil in a large non-stick pan over medium-high heat and fry the aubergine in batches for 3–4 minutes per side until deep golden and tender throughout, then drain on kitchen paper. Whisk the tahini with the lemon juice, crushed garlic, and 3–4 tbsp cold water until creamy and pourable. Combine the diced tomatoes and cucumber with the remaining 1/2 tsp salt and a drizzle of olive oil. Warm each pita for 1 minute per side in a dry pan, then carefully open the pocket without tearing. Layer each pita with fried aubergine, sliced potato and egg, the tomato-cucumber salad, a generous drizzle of tahini sauce, a spoonful of amba sauce, pickled cucumber, and fresh parsley, and serve immediately."}},{"id":90,"origin":{"ar":"كوبا","en":"Cuba","ro":"Cuba"},"name":{"ar":"روبا فييخا","en":"Ropa Vieja","ro":"Ropa Vieja"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"latin","ingredients":{"ar":["700 غ شريحة لحم بقري (فلانك أو صدر بقر)","2 ملعقة كبيرة زيت زيتون","1 بصلة كبيرة (~200 غ)، مقطّعة شرائح رفيعة","1 فلفل أحمر و1 فلفل أخضر (~150 غ لكل منهما)، منزوعا البذور ومقطّعان شرائح","4 فصوص ثوم، مفرومة ناعماً","400 غ طماطم مهروسة معلّبة","2 ملعقة كبيرة معجون طماطم","100 مل نبيذ أبيض جاف","1 ملعقة صغيرة كمون مطحون","1 ملعقة صغيرة زعتر مجفّف","ورقتا غار","1 ملعقة صغيرة ملح ونصف ملعقة صغيرة فلفل أسود"],"en":["700 g beef flank steak or brisket","2 tbsp olive oil","1 large onion (~200 g), thinly sliced","1 red bell pepper and 1 green bell pepper (~150 g each), deseeded and sliced","4 garlic cloves, finely minced","400 g canned crushed tomatoes","2 tbsp tomato paste","100 ml dry white wine","1 tsp ground cumin","1 tsp dried oregano","2 bay leaves","1 tsp salt and 1/2 tsp ground black pepper"],"ro":["700 g antricot sau piept de vită","2 linguri ulei de măsline","1 ceapă mare (~200 g), feliată subțire","1 ardei gras roșu și 1 ardei gras verde (~150 g fiecare), curățați și feliați","4 căței de usturoi, tocați mărunt","400 g roșii zdrobite la conservă","2 linguri pastă de roșii","100 ml vin alb sec","1 linguriță chimion măcinat","1 linguriță oregano uscat","2 foi de dafin","1 linguriță sare și 1/2 linguriță piper negru măcinat"]},"howIsMade":{"ar":"ضع اللحم في قدر وغطّه بالماء البارد المُملّح، اغلِ وأزل الرغوة، ثم خفّض النار وارتبخ مغطّى 1.5–2 ساعة حتى ينفصل اللحم بسهولة. أخرج اللحم واحتفظ بـ 200 مل من ماء الطهي، ثم مزّق اللحم إلى خيوط طويلة. سخّن الزيت في مقلاة واسعة على نار متوسطة، أضف البصل والفلفلين واطبخ 8–10 دقائق حتى يلينا ويتلوّنا خفيفاً. أضف الثوم والكمون والزعتر وقلّب دقيقة، ثم اسكب النبيذ واطبخه 2 دقيقة حتى ينصف. أضف الطماطم المهروسة ومعجون الطماطم وماء الطهي وأوراق الغار، تبّل بالملح والفلفل وارتبخ 10 دقائق حتى يتكثّف الصوص قليلاً. أضف اللحم الممزّق وامزج جيداً وارتبخ 10–15 دقيقة حتى يمتص اللحم الصوص ويصبح الطبق عصيراً. أزل أوراق الغار وقدّم مع الأرز الأبيض والموز المقلي.","en":"Place the beef in a pot, cover with cold salted water, bring to a boil, skim, reduce heat, and simmer covered for 1.5–2 hours until the meat pulls apart easily. Remove the beef, reserve 200 ml of the cooking liquid, and shred the meat into long strips. Heat the oil in a wide heavy pan over medium heat, add the onion and both bell peppers, and cook for 8–10 minutes until softened and beginning to colour. Add the garlic, cumin, and oregano and stir for 1 minute, then pour in the white wine and cook for 2 minutes until reduced by half. Stir in the crushed tomatoes, tomato paste, reserved cooking liquid, and bay leaves, season with salt and pepper, and simmer for 10 minutes until the sauce thickens slightly. Add the shredded beef, stir to combine, and simmer for 10–15 minutes more until the beef absorbs the sauce and the mixture is juicy but not soupy. Remove the bay leaves and serve with white rice and fried plantains."}},{"id":91,"origin":{"ar":"اسكتلندا","en":"Scotland","ro":"Scoția"},"name":{"ar":"كالين سكينك","en":"Cullen Skink","ro":"Cullen Skink"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"fish","pairingsType":"fish","ingredients":{"ar":["600 غ شرائح سمك الحدّاق المدخّن (يُفضَّل غير ملوّن)","700 مل حليب كامل الدسم","500 غ بطاطس دقيقية الملمس، مقشورة ومقطّعة مكعبات 2 سم","1 بصلة كبيرة (~200 غ)، مفرومة ناعماً","2 ملعقة كبيرة زبدة غير مملّحة","ورقتا غار","100 مل كريمة للطهي","10 غ بقدونس طازج، مفروم ناعماً","نصف ملعقة صغيرة فلفل أبيض","نصف ملعقة صغيرة ملح"],"en":["600 g undyed smoked haddock fillets","700 ml whole milk","500 g floury potatoes (such as Maris Piper), peeled and cut into 2 cm cubes","1 large onion (~200 g), finely diced","2 tbsp unsalted butter","2 bay leaves","100 ml double cream","10 g fresh parsley, finely chopped","1/2 tsp white pepper","1/2 tsp salt"],"ro":["600 g fileuri de eglefin afumat (de preferință necolorat)","700 ml lapte integral","500 g cartofi făinoși, curățați și tăiați cuburi de 2 cm","1 ceapă mare (~200 g), tăiată mărunt","2 linguri unt fără sare","2 foi de dafin","100 ml frișcă grasă","10 g pătrunjel proaspăt, tocat mărunt","1/2 linguriță piper alb","1/2 linguriță sare"]},"howIsMade":{"ar":"ضع شرائح الحدّاق جانب الجلد للأسفل في مقلاة واسعة، صبّ عليها الحليب وأضف أوراق الغار وأحضر لغليان خفيف على نار متوسطة؛ اتركها تُطهى 8–10 دقائق حتى يصبح السمك معتماً وينفصل عند أسمك جزء. أخرج السمك بالمِغرفة المثقّبة وأزل الجلد والعظام، فتّت اللحم إلى قطع كبيرة وصفّ الحليب بمصفاة. أذِب الزبدة في نفس المقلاة على نار متوسطة وأضف البصل واطبخه 8–10 دقائق مع التقليب حتى يطرأ تماماً دون أن يتلوّن. أضف مكعبات البطاطس والحليب المصفّى وأحضر لغليان خفيف، غطِّ جزئياً واطبخ 15–18 دقيقة حتى تنضج البطاطس تماماً. اهرس ثلث البطاطس بلطف بظهر الملعقة على جدار القدر لتكثيف الشوربة. أضف الكريمة وأعد قطع الحدّاق وسخّن بلطف 2–3 دقائق؛ تبّل بالفلفل الأبيض والملح بحذر إذ السمك مالح بطبيعته. اسكب في أطباق دافئة، رشّ البقدونس وقدّم مع خبز مقرمش.","en":"Place the smoked haddock skin-side down in a wide pan, pour over the milk, add the bay leaves, and bring to a gentle simmer over medium heat; poach for 8–10 minutes until the fish is just opaque and flakes at the thickest part. Lift the fish out with a slotted spoon, remove the skin and any bones, break the flesh into large flakes, and strain the poaching milk through a sieve into a jug. Melt the butter in the same pan over medium heat, add the diced onion, and cook for 8–10 minutes, stirring occasionally, until completely soft but not coloured. Add the potato cubes and the strained milk, bring to a simmer, cover loosely, and cook for 15–18 minutes until the potatoes are completely tender when pierced with a knife. Lightly mash about one-third of the potatoes against the side of the pan with the back of a spoon to thicken the soup, leaving the rest in chunks. Stir in the double cream, return the flaked haddock to the pan, and simmer gently for 2–3 minutes until just heated through; season with white pepper and salt, tasting carefully as the haddock is already salty. Ladle into warmed bowls, scatter with chopped parsley, and serve with crusty bread."}},{"id":92,"origin":{"ar":"إندونيسيا","en":"Indonesia","ro":"Indonezia"},"name":{"ar":"غادو غادو","en":"Gado-Gado","ro":"Gado-Gado"},"category":{"ar":"سلطة","en":"Salad","ro":"Salată"},"servings":4,"tipType":"veg","pairingsType":"veg","ingredients":{"ar":["400 جرام توفو صلب، مضغوط ومقطع إلى مكعبات 2 سم","150 جرام تيمبيه، مقطع إلى مكعبات 2 سم","4 بيضات كبيرة","300 جرام بطاطس شمعية، مقشرة ومقطعة إلى أرباع","200 جرام فاصوليا خضراء، منظفة","200 جرام ملفوف أبيض، مقطع بشكل رفيع","150 جرام براعم الفول السوداني","خيارة واحدة (~200 جرام)، مقطعة إلى أنصاف أقراص","3 ملاعق كبيرة زيت نباتي","200 جرام زبدة فول سوداني ناعمة","200 مل حليب جوز الهند","2 ملعقة كبيرة كيجاب مانيس (صلصة الصويا الحلوة)","2 ملعقة كبيرة معجون التمر الهندي مذاب في 4 ملاعق كبيرة ماء دافئ","1 ملعقة صغيرة سكر النخيل أو السكر البني","فصان من الثوم، مبشوران ناعماً","نصف ملعقة صغيرة رقائق الفلفل الحار","نصف ملعقة صغيرة ملح","رقائق الروبيان (كروبوك) وشرائح الليمون الأخضر للتقديم"],"en":["400 g firm tofu, pressed and cut into 2 cm cubes","150 g tempeh, cut into 2 cm cubes","4 large eggs","300 g waxy potatoes, peeled and quartered","200 g green beans, trimmed","200 g white cabbage, thinly shredded","150 g bean sprouts","1 cucumber (~200 g), sliced into half-moons","3 tbsp vegetable oil","200 g smooth peanut butter","200 ml coconut milk","2 tbsp kecap manis (sweet soy sauce)","2 tbsp tamarind paste dissolved in 4 tbsp warm water","1 tsp palm sugar or soft brown sugar","2 garlic cloves, finely grated","1/2 tsp chilli flakes","1/2 tsp salt","prawn crackers (krupuk) and lime wedges to serve"],"ro":["400 g tofu ferm, presat și tăiat în cuburi de 2 cm","150 g tempeh, tăiat în cuburi de 2 cm","4 ouă mari","300 g cartofi cu coajă crocantă, curățați și tăiați în sferturi","200 g fasole verde, curățată de capete","200 g varză albă, feliată subțire","150 g germeni de soia","1 castravete (~200 g), tăiat în felii semilună","3 linguri ulei vegetal","200 g unt de arahide cremos","200 ml lapte de cocos","2 linguri kecap manis (sos de soia dulce)","2 linguri pastă de tamarind dizolvată în 4 linguri apă caldă","1 linguriță zahăr de palmier sau zahăr brun","2 căței de usturoi, rași fin","1/2 linguriță fulgi de ardei iute","1/2 linguriță sare","chipsuri de creveți (krupuk) și felii de lămâie verde pentru servit"]},"howIsMade":{"ar":"اسلقي البيض في ماء يغلي على نار هادئة لمدة 9 دقائق، انقليه إلى وعاء من الماء المثلج، ثم قشريه وقطعيه نصفين بعد أن يبرد. اطهي البطاطس في ماء مملح جيداً 12–15 دقيقة حتى تنضج عند ثقبها؛ أخرجيها بملعقة مثقبة، ثم ابيضي الفاصوليا الخضراء في نفس الماء 3 دقائق حتى تصبح خضراء زاهية وما زالت مقرمشة، واصفيها. ابيضي الملفوف المقطع بسكب الماء المغلي عليه في مصفاة، عدي 30 ثانية، ثم اعصري الماء الزائد. سخني الزيت في مقلاة غير لاصقة على نار متوسطة عالية واقلي مكعبات التوفو 3–4 دقائق من كل جانب حتى تصبح ذهبية ومقرمشة؛ أخرجيها، ثم اقلي التيمبيه في نفس المقلاة 2–3 دقائق من كل جانب حتى يصبح ذهبياً غامقاً. اخلطي زبدة الفول السوداني وحليب جوز الهند والكيجاب مانيس وماء التمر الهندي وسكر النخيل والثوم المبشور ورقائق الفلفل في قدر صغيرة؛ اطهي على نار هادئة مع التحريك المستمر 5–7 دقائق حتى تصبح ناعمة وثخينة بما يكفي لتغطية ظهر الملعقة. رتبي الملفوف والبطاطس والفاصوليا والبراعم والخيار في طبق كبير؛ ضعي فوقها التوفو والتيمبيه ونصفي البيض. صبي صلصة الفول السوداني الدافئة فوق الكل وقدمي مع رقائق الروبيان وشرائح الليمون.","en":"Hard-boil the eggs in simmering water for 9 minutes, transfer to a bowl of ice water, then peel and halve when cool. Cook the potatoes in well-salted boiling water for 12–15 minutes until just tender when pierced; lift out with a slotted spoon and drain, then blanch the green beans in the same water for 3 minutes until bright green and still with some bite, and drain. Blanch the shredded cabbage by pouring boiling water over it in a colander, count 30 seconds, then press out excess water. Heat the oil in a non-stick frying pan over medium-high heat and fry the tofu cubes for 3–4 minutes per side until golden and crisp; remove, then fry the tempeh in the same pan for 2–3 minutes per side until deep golden. Combine the peanut butter, coconut milk, kecap manis, tamarind water, palm sugar, grated garlic, and chilli flakes in a small saucepan; cook over low heat, stirring constantly, for 5–7 minutes until smooth and thick enough to coat the back of a spoon — thin with a splash of water if needed. Arrange the cabbage, potatoes, green beans, bean sprouts, and cucumber slices on a large platter or individual plates; place the tofu, tempeh, and egg halves on top. Pour the warm peanut sauce over everything, and serve with prawn crackers and lime wedges on the side."}},{"id":93,"origin":{"ar":"السويد","en":"Sweden","ro":"Suedia"},"name":{"ar":"لفائف القرفة","en":"Cinnamon Bun","ro":"Kanelbulle"},"category":{"ar":"حلوى","en":"Dessert","ro":"Desert"},"servings":12,"tipType":"dessert","pairingsType":"dessert","ingredients":{"ar":["500 جرام دقيق أبيض، زائد كمية للتغليف","250 مل حليب كامل الدسم","7 جرام خميرة جافة فورية (كيس واحد)","10 جرام سكر (للعجينة)","بيضة كبيرة واحدة","100 جرام زبدة غير مملحة، مُليّنة","ملعقة صغيرة هيل مطحون","نصف ملعقة صغيرة ملح","75 جرام زبدة غير مملحة، مُليّنة (للحشو)","75 جرام سكر (للحشو)","ملعقة كبيرة قرفة مطحونة","ملعقة صغيرة هيل مطحون (للحشو)","بيضة مخفوقة (للدهن)","ملعقتان كبيرتان سكر لؤلؤي"],"en":["500 g plain flour, plus extra for dusting","250 ml whole milk","7 g fast-action dried yeast (1 sachet)","10 g caster sugar (for dough)","1 large egg","100 g unsalted butter, softened","1 tsp ground cardamom","1/2 tsp salt","75 g unsalted butter, softened (filling)","75 g caster sugar (filling)","1 tbsp ground cinnamon","1 tsp ground cardamom (filling)","1 egg, beaten (for egg wash)","2 tbsp pearl sugar"],"ro":["500 g făină albă, plus extra pentru presărat","250 ml lapte integral","7 g drojdie uscată instant (1 plic)","10 g zahăr tos (pentru aluat)","1 ou mare","100 g unt nesărat, la temperatura camerei","1 linguriță cardamom măcinat","1/2 linguriță sare","75 g unt nesărat, la temperatura camerei (umplutură)","75 g zahăr tos (umplutură)","1 lingură scorțișoară măcinată","1 linguriță cardamom măcinat (umplutură)","1 ou bătut (pentru uns)","2 linguri zahăr perle"]},"howIsMade":{"ar":"سخني الحليب إلى 37 درجة مئوية، وأضيفي الخميرة والـ10 جرام من السكر واتركيها 5–10 دقائق حتى تفقع. اخلطي الدقيق والهيل والملح في وعاء كبير؛ أضيفي مزيج الخميرة والبيضة واعجني حتى تتشكل عجينة خشنة. أضيفي الـ100 جرام من الزبدة المُليّنة قطعة قطعة واعجني على سطح مرشوش طحيناً 8–10 دقائق حتى تصبح العجينة ناعمة ومرنة وغير لاصقة؛ غطيها واتركيها في مكان دافئ 60–90 دقيقة حتى تتضاعف. اخلطي الـ75 جرام من الزبدة مع 75 جرام سكر والقرفة وملعقة الهيل الثانية للحشو. افردي العجينة المخمرة على سطح مرشوش طحيناً بشكل مستطيل 40×50 سم؛ وزعي الحشو بالتساوي، اطوي العجينة ثلاثاً في الطول، افرديها مجدداً وقطعيها إلى 12 شريطاً. التفي كل شريط ولفيه على شكل عقدة وضعي الطرف تحتها؛ ضعيها على صواني مبطنة بمسافات، غطيها ودعيها تتخمر 30–45 دقيقة حتى تنتفخ وسخني الفرن على 200 درجة (180 درجة بالمروحة). ادهني بالبيض المخفوق ورشي السكر اللؤلؤي واخبزي 12–15 دقيقة حتى تصبح ذهبية داكنة؛ انقليها على رف وغطيها بمنشفة.","en":"Warm the milk to 37°C, stir in the yeast and the 10 g of caster sugar, and leave for 5–10 minutes until frothy. Combine the flour, cardamom, and salt in a large bowl; make a well, pour in the yeast mixture and beaten egg, then bring together into a rough dough. Add the 100 g of softened butter a piece at a time and knead on a lightly floured surface for 8–10 minutes until the dough is smooth, elastic, and no longer sticks to your hands; cover and leave in a warm place for 60–90 minutes until doubled in size. Beat together the 75 g of butter, 75 g of caster sugar, cinnamon, and the second teaspoon of cardamom until smooth for the filling. Turn the risen dough onto a lightly floured surface and roll into a 40×50 cm rectangle; spread the filling evenly, fold the dough lengthways into thirds, roll again, and cut into 12 strips. Twist each strip and coil into a knot, tucking the end underneath, then space on lined baking trays; cover loosely and prove 30–45 minutes until noticeably puffed, while preheating the oven to 200°C (fan 180°C). Brush with beaten egg, scatter with pearl sugar, and bake for 12–15 minutes until deep golden brown; transfer to a wire rack and cover with a tea towel to keep them soft."}},{"id":94,"origin":{"ar":"المكسيك","en":"Mexico","ro":"Mexic"},"name":{"ar":"شيليز إن نوجادا","en":"Chiles en nogada","ro":"Chiles en nogada"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"mexican","ingredients":{"ar":["4 فلفل بوبلانو كبيرة (~700 جرام إجمالاً)","400 جرام لحم خنزير مفروم","2 ملعقة كبيرة زيت زيتون أو شحم","بصلة متوسطة واحدة (~150 جرام)، مقطعة ناعماً","3 فصوص ثوم، مفرومة","2 طماطم ناضجة (~300 جرام)، مقشرة ومقطعة","50 جرام زبيب","50 جرام لوز مقشر، مفروم خشناً","خوخة أو كمثرى ناضجة (~150 جرام)، مقشرة مقطعة مكعبات","ملعقة صغيرة قرفة مطحونة، نصف ملعقة صغيرة قرنفل مطحون، ملعقة صغيرة ملح، نصف ملعقة صغيرة فلفل أسود","150 جرام أنصاف جوز، منقوعة 30 دقيقة في حليب دافئ ومصفاة","150 جرام جبن كريمي، مُليّن","100 مل قشطة حامضة","بذور رمانة واحدة (~100 جرام)","حفنة من أوراق البقدونس الطازج"],"en":["4 large poblano chiles (~700 g total)","400 g ground pork","2 tbsp olive oil or lard","1 medium onion (~150 g), finely diced","3 garlic cloves, minced","2 ripe tomatoes (~300 g), peeled and diced","50 g raisins","50 g blanched almonds, roughly chopped","1 ripe peach or pear (~150 g), peeled and diced","1 tsp ground cinnamon, 1/2 tsp ground cloves, 1 tsp salt, 1/2 tsp black pepper","150 g walnut halves, soaked in warm milk 30 minutes then drained","150 g cream cheese, softened","100 ml soured cream","seeds of 1 pomegranate (~100 g)","small handful of fresh flat-leaf parsley leaves"],"ro":["4 ardei poblano mari (~700 g total)","400 g carne de porc tocată","2 linguri ulei de măsline sau untură","1 ceapă medie (~150 g), tăiată mărunt","3 căței de usturoi, tocați","2 roșii coapte (~300 g), curățate de coajă și tocate","50 g stafide","50 g migdale decojite, tocate grosier","1 piersică sau pară coaptă (~150 g), curățată și tăiată cubulețe","1 linguriță scorțișoară, 1/2 linguriță cuișoare, 1 linguriță sare, 1/2 linguriță piper negru","150 g miez de nucă, înmuiat 30 minute în lapte cald și scurs","150 g cremă de brânză, la temperatura camerei","100 ml smântână fermentată","semințele unui rodiu (~100 g)","o mână de frunze de pătrunjel plat proaspăt"]},"howIsMade":{"ar":"احرقي فلفل البوبلانو مباشرة فوق لهب موقد الغاز أو تحت الشواية الساخنة لمدة 8–10 دقائق، مع التقليب بالملقط حتى تسود القشرة تماماً من جميع الجوانب؛ ضعيه في وعاء مغطى لمدة 10 دقائق، ثم احتكي القشرة وأزيليها، واشقي كل فلفلة شقاً طولياً وأخرجي البذور والخيوط بملعقة صغيرة مع المحافظة على شكلها. سخني الزيت في مقلاة واسعة على نار متوسطة، أضيفي البصل وقلبي 5–6 دقائق حتى يطرأ؛ أضيفي الثوم وقلبي دقيقة أخرى. أضيفي اللحم المفروم وقلبي 8 دقائق حتى لا يبقى لون وردي؛ أضيفي الطماطم وقلبي 5 دقائق حتى تتهرى. أضيفي الزبيب واللوز والخوخ والقرفة والقرنفل والملح والفلفل؛ قلبي 5 دقائق حتى تطرأ الفاكهة ويصبح الخليط جافاً، ثم أزيلي عن النار واتركيه يبرد. صفّي الجوز المنقوع واخلطيه مع الجبن الكريمي والقشطة في الخلاط حتى يصبح ناعماً تماماً؛ اضبطي الملح. احشي كل فلفلة بإحكام بالحشوة الباردة مع الضغط برفق؛ رتبيها في أطباق. اسكبي صلصة الجوز بسخاء فوق كل فلفلة، ورشي بذور الرمان وأوراق البقدونس وقدمي في درجة حرارة الغرفة.","en":"Char the poblano chiles over an open gas flame or under a hot grill for 8–10 minutes, turning with tongs until the skin is completely blackened on all sides; place in a covered bowl for 10 minutes, then rub off the skin, make a single lengthways slit, and remove the seeds and veins with a small spoon while keeping each chile intact. Heat the oil in a wide frying pan over medium heat, add the onion, and cook for 5–6 minutes until completely soft; add the garlic and cook 1 minute more until fragrant. Add the ground pork and cook, breaking it up with a wooden spoon, for 8 minutes until no pink remains; add the diced tomatoes and cook for 5 minutes until they collapse and the liquid reduces. Stir in the raisins, almonds, peach, cinnamon, cloves, salt, and pepper; cook for 5 minutes until the fruit softens and the mixture is fairly dry, then remove from heat and cool to room temperature. Drain the soaked walnuts and blend with the cream cheese and soured cream until completely smooth; season with a pinch of salt — the nogada should be thick enough to coat a spoon. Stuff each poblano firmly with the cooled meat filling, pressing gently to close the slit; arrange on individual plates or a large serving dish. Spoon the walnut sauce generously over each chile, scatter pomegranate seeds and parsley leaves on top, and serve at room temperature."}},{"id":95,"origin":{"ar":"لبنان","en":"Lebanon","ro":"Liban"},"name":{"ar":"حساء العدس","en":"Lentil Soup","ro":"Supă de linte"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"soup","ingredients":{"ar":["300 جرام عدس أحمر، مغسول حتى يصبح الماء صافياً","2 ملعقة كبيرة زيت زيتون","بصلة كبيرة واحدة (~200 جرام)، مقطعة ناعماً","2 جزرة متوسطة (~200 جرام)، مقشرتان ومقطعتان","3 فصوص ثوم، مفرومة","2 ملعقة صغيرة كمون مطحون","1 ملعقة صغيرة كزبرة مطحونة","نصف ملعقة صغيرة كركم","ربع ملعقة صغيرة فلفل كايان","1.2 لتر مرق خضار أو دجاج","عصير ليمونة واحدة","2 ملعقة كبيرة زبدة (للتزيين)","1 ملعقة صغيرة بابريكا حلوة (للتزيين)","ملح وفلفل أسود حسب الذوق","كزبرة طازجة أو بقدونس وشرائح ليمون للتقديم"],"en":["300 g red lentils, rinsed until water runs clear","2 tbsp olive oil","1 large onion (~200 g), finely diced","2 medium carrots (~200 g), peeled and diced","3 garlic cloves, minced","2 tsp ground cumin","1 tsp ground coriander","1/2 tsp ground turmeric","1/4 tsp cayenne pepper","1.2 litres vegetable or chicken stock","juice of 1 lemon","2 tbsp unsalted butter (for topping)","1 tsp sweet paprika (for topping)","salt and black pepper to taste","fresh coriander or parsley and lemon wedges to serve"],"ro":["300 g linte roșie, clătită până apa devine limpede","2 linguri ulei de măsline","1 ceapă mare (~200 g), tăiată mărunt","2 morcovi medii (~200 g), curățați și tăiați cubulețe","3 căței de usturoi, tocați","2 lingurițe chimen măcinat","1 linguriță coriandru măcinat","1/2 linguriță turmeric","1/4 linguriță ardei cayenne","1,2 litri supă de legume sau pui","sucul de la 1 lămâie","2 linguri unt nesărat (pentru topping)","1 linguriță paprika dulce (pentru topping)","sare și piper negru după gust","coriandru proaspăt sau pătrunjel, felii de lămâie pentru servit"]},"howIsMade":{"ar":"سخني زيت الزيتون في قدر كبيرة على نار متوسطة، أضيفي البصل والجزر وقلبي 8–10 دقائق مع التحريك أحياناً حتى يطروا ويصبح البصل شفافاً. أضيفي الثوم والكمون والكزبرة والكركم والفلفل الحار؛ حركي 1–2 دقيقة حتى تفوح رائحة البهارات. أضيفي العدس المغسول والمرق، أوصلي إلى الغليان، خففي الحرارة، غطي جزئياً واتركي يغلي على نار هادئة 20–25 دقيقة حتى ينضج العدس تماماً ويبدأ بالتفتت. اخلطي نصف الشوربة تقريباً بالخلاط الغاطس للحصول على قوام كريمي مع بعض القطع — أو كلها للحصول على شوربة ناعمة تماماً؛ خففي بالمرق إن لزم. أضيفي عصير الليمون وتبلي بسخاء بالملح والفلفل الأسود. أذيبي الزبدة في مقلاة صغيرة على نار متوسطة، أضيفي البابريكا ودعيها تفقع 30 ثانية حتى تفوح رائحتها. اسكبي الشوربة الساخنة في أطباق مسخنة، رشي زبدة البابريكا فوق كل طبق، أضيفي الكزبرة الطازجة وقدمي مع شرائح الليمون والخبز المقرمش.","en":"Heat the olive oil in a large saucepan over medium heat, add the onion and carrots, and cook for 8–10 minutes, stirring occasionally, until softened and the onion is translucent. Add the garlic, cumin, coriander, turmeric, and cayenne; stir for 1–2 minutes until the spices are fragrant and toasted. Add the rinsed lentils and stock, bring to a boil, then reduce the heat, partially cover, and simmer for 20–25 minutes until the lentils are completely tender and beginning to dissolve into the liquid. Use an immersion blender to puree about half the soup directly in the pot for a creamy yet textured finish — or blend it all smooth if you prefer; thin with a splash of extra stock or water if needed. Stir in the lemon juice and season generously with salt and black pepper. Melt the butter in a small pan over medium heat, add the sweet paprika, and let it sizzle for 30 seconds until fragrant and deep red. Ladle the hot soup into warmed bowls, drizzle the paprika butter over each portion, scatter fresh coriander on top, and serve with lemon wedges and crusty bread."}},{"id":96,"origin":{"ar":"اليونان","en":"Greece","ro":"Grecia"},"name":{"ar":"سباناكوبيتا","en":"Spanakopita","ro":"Spanakopita"},"category":{"ar":"وجبة خفيفة","en":"Snack","ro":"Gustare"},"servings":6,"tipType":"veg","pairingsType":"veg","ingredients":{"ar":["500غ عجينة فيلو، مذابة إن كانت مجمدة","1كغ سبانخ طازجة، مغسولة (أو 600غ سبانخ مجمدة، مذابة ومعصورة جيداً)","300غ جبنة فيتا، مفتتة","بصلتان متوسطتان، مفرومتان ناعماً","4 أعواد بصل أخضر، مقطعة ناعماً","3 بيضات كبيرة، مخفوقة","30غ شبت طازج، مفروم","20غ بقدونس طازج، مفروم","150مل زيت زيتون بكر ممتاز","100غ جبنة كيفالوتيري أو بيكورينو مبشورة (اختياري)","1/2 ملعقة صغيرة جوزة طيب مبشورة طازجة","ملح وفلفل أسود مطحون طازجاً حسب الذوق"],"en":["500g phyllo pastry, thawed if frozen","1kg fresh spinach, washed (or 600g frozen spinach, thawed and squeezed dry)","300g feta cheese, crumbled","2 medium onions, finely chopped","4 spring onions, finely sliced","3 large eggs, beaten","30g fresh dill, chopped","20g fresh parsley, chopped","150ml extra virgin olive oil","100g grated kefalotyri or pecorino (optional)","1/2 tsp freshly grated nutmeg","salt and freshly ground black pepper to taste"],"ro":["500g foi de plăcintă (phyllo), decongelate dacă sunt din congelator","1kg spanac proaspăt, spălat (sau 600g spanac congelat, decongelat și stors bine)","300g brânză feta, sfărâmată","2 cepe medii, tocate fin","4 cepe verzi, tăiate fin","3 ouă mari, bătute","30g mărar proaspăt, tocat","20g pătrunjel proaspăt, tocat","150ml ulei de măsline extravirgin","100g kefalotyri sau pecorino, ras (opțional)","1/2 linguriță nucșoară proaspăt rasă","sare și piper negru proaspăt măcinat după gust"]},"howIsMade":{"ar":"سخّن الفرن إلى 180°م (مروحة 160°م); اغسل 1كغ من السبانخ وذبّلها في قدر كبير على نار متوسطة لمدة 4–5 دقائق حتى تنكمش; اسكبها في مصفاة واضغط عليها لإخراج أكبر قدر من الماء، ثم اعصرها بكميات صغيرة بين مناشف ورقية. سخّن 3 ملاعق كبيرة من زيت الزيتون في مقلاة وقلّب البصل المفروم على نار متوسطة لمدة 8 دقائق حتى يلين ويصبح شفافاً; أضف البصل الأخضر واطبخ دقيقتين إضافيتين. في وعاء كبير، اخلط السبانخ المعصورة، خليط البصل، 300غ من جبنة الفيتا المفتتة، الكيفالوتيري إن وُجد، 3 بيضات مخفوقة، الشبت، البقدونس، جوزة الطيب، الملح والفلفل; اخلط بلطف — فالتقليب المفرط يجعل السبانخ تطلق ماءً إضافياً. ادهن صينية 25×35 سم بزيت الزيتون; ضع ورقة فيلو، ادهنها بالزيت، ثم ضع فوقها ورقة ثانية; تابع حتى تحصل على 8 طبقات كقاعدة; احفظ الأوراق غير المستخدمة مغطّاة بقطعة قماش رطبة قليلاً. وزّع الحشوة بالتساوي فوق قاعدة الفيلو; غطّها بـ 8 أوراق فيلو إضافية، مع دهن كل طبقة بسخاء بزيت الزيتون. اطوِ الحواف نحو الداخل; باستخدام سكين حادة، ارسم خطوطاً على السطح لتقسيمه إلى 6–8 حصص، قاطعاً الطبقات العلوية فقط — هذا يمنع تشظّي الفطيرة عند التقديم; رشّ بضع قطرات ماء فوقها كي لا تتقوّس العجينة. اخبزها لمدة 40–45 دقيقة حتى يصبح السطح ذهبياً عميقاً وتُصدر العجينة صوتاً مقرمشاً عند النقر عليها; اتركها ترتاح 15 دقيقة، ثم قطّعها على طول الخطوط المرسومة.","en":"Preheat the oven to 180°C (fan 160°C); wash 1kg of spinach and wilt it in a large pot over medium heat for 4–5 minutes, until just collapsed; tip into a colander and press out as much water as possible, then squeeze handfuls dry between paper towels. Warm 3 tablespoons of olive oil in a pan and cook the chopped onions over medium heat for 8 minutes, until soft and translucent; add the spring onions and cook 2 more minutes. In a large bowl, combine the squeezed spinach, the onion mixture, 300g crumbled feta, the kefalotyri if using, 3 beaten eggs, dill, parsley, nutmeg, salt and pepper; mix gently — do not overwork or the spinach will release more water. Brush a 25×35 cm baking dish with olive oil; lay one sheet of phyllo, brush with olive oil, and top with another sheet; continue until you have 8 layers as the base; keep unused phyllo covered with a slightly damp cloth. Spread the filling evenly over the phyllo base; top with 8 more sheets of phyllo, brushing each layer generously with olive oil. Tuck the edges in; with a sharp knife, score the top into 6–8 portions, cutting only through the top layers — this prevents shattering when serving; sprinkle a few drops of water on top to stop the pastry curling. Bake for 40–45 minutes, until the top is deep golden brown and the pastry sounds crisp when tapped; rest 15 minutes before cutting along the scored lines."},"timeMins":{"total":90,"active":40}},{"id":97,"origin":{"ar":"نيجيريا","en":"Nigeria","ro":"Nigeria"},"name":{"ar":"أرز جولوف","en":"Jollof Rice","ro":"Jollof Rice"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"def","ingredients":{"ar":["400غ أرز طويل الحبة مسلوق مسبقاً (أو بسمتي)، مغسول حتى يصفو الماء","6 حبات طماطم روما ناضجة، مفرومة خشناً (أو 400غ طماطم مفرومة معلبة)","2 حبة فلفل رومي أحمر كبيرة، منزوعة البذور ومفرومة خشناً","1 فلفل سكوتش بونيه أو فلفل أحمر حار، منزوع البذور","2 بصلة كبيرة (واحدة للخلط، الأخرى مقطعة شرائح)","4 فصوص ثوم، مقشّرة","30غ زنجبيل طازج، مقشّر","3 ملاعق كبيرة معجون طماطم","120مل زيت نباتي (تقليدياً زيت الفول السوداني)","750مل مرق دجاج أو خضار ساخن","ورقتا غار","1 ملعقة صغيرة كاري بودرة","1 ملعقة صغيرة زعتر يابس","1 ملعقة صغيرة بابريكا مدخنة","ملح وفلفل أسود مطحون طازجاً حسب الذوق"],"en":["400g long-grain parboiled rice (or basmati), rinsed until water runs clear","6 ripe Roma tomatoes, roughly chopped (or 400g canned chopped tomatoes)","2 large red bell peppers, deseeded and roughly chopped","1 scotch bonnet or red chilli, deseeded","2 large onions (1 blended, 1 sliced)","4 garlic cloves, peeled","30g fresh ginger, peeled","3 tbsp tomato paste","120ml vegetable oil (groundnut oil is traditional)","750ml hot chicken or vegetable stock","2 bay leaves","1 tsp curry powder","1 tsp dried thyme","1 tsp smoked paprika","salt and freshly ground black pepper to taste"],"ro":["400g orez cu bob lung parboiled (sau basmati), spălat până apa rămâne limpede","6 roșii Roma coapte, tăiate grosier (sau 400g roșii din conservă)","2 ardei kapia roșii mari, fără semințe și tăiați grosier","1 ardei scotch bonnet sau ardei iute roșu, fără semințe","2 cepe mari (una mixată, una feliată)","4 căței de usturoi, curățați","30g ghimbir proaspăt, curățat","3 linguri pastă de roșii","120ml ulei vegetal (tradițional, ulei de arahide)","750ml supă fierbinte de pui sau legume","2 foi de dafin","1 linguriță pudră de curry","1 linguriță cimbru uscat","1 linguriță boia afumată","sare și piper negru proaspăt măcinat după gust"]},"howIsMade":{"ar":"اشطف 400غ من الأرز بالماء البارد حتى يصفو الماء، ثم صفّه — هذه الخطوة تزيل النشاء الزائد وتحافظ على انفصال الحبوب. اخلط الطماطم والفلفل الرومي الأحمر والفلفل الحار وبصلة واحدة والثوم والزنجبيل في الخلاط حتى تصبح عجينة ناعمة. سخّن 120مل من الزيت في قدر سميك القاع على نار متوسطة; أضف البصل المقطّع شرائح وقلّبه 5–6 دقائق حتى يصبح ذهبياً خفيفاً. أضف 3 ملاعق كبيرة من معجون الطماطم واطبخها 3 دقائق حتى يتعمّق لونها وتختفي رائحتها النيئة. اسكب خليط الفلفل المخلوط، وأضف ورق الغار، الكاري، الزعتر، والبابريكا المدخنة; اطبخ مكشوفاً على نار متوسطة لمدة 18–20 دقيقة، مع التحريك المتكرر، حتى تتقلّص الصلصة وتصبح حمراء داكنة ويطفو الزيت على السطح — هذه هي الخطوة الحاسمة. أضف الأرز المغسول وحرّكه حتى يتغلّف كل حبة بالصلصة; اسكب 750مل من المرق الساخن، تبّل بالملح والفلفل وأعد المزيج إلى الغليان. خفّض الحرارة إلى أدنى درجة، أغلق القدر بإحكام (اختم الحافة بورق ألمنيوم قبل وضع الغطاء للحصول على لمسة أصيلة)، واطبخ دون تحريك لمدة 25–30 دقيقة حتى ينضج الأرز ويُمتص السائل بالكامل. أطفئ النار واترك القدر مغطّى 10 دقائق إضافية; فرّش الأرز بشوكة برفق — يجب أن تظهر في القاع قشرة مدخّنة خفيفة; قدّمه مع موز الجنة المقلي، الدجاج المشوي، أو سلطة بسيطة.","en":"Rinse 400g of rice in cold water until the water runs clear, then drain — this removes excess starch and keeps the grains separate. Blend the tomatoes, red bell peppers, chilli, one onion, garlic and ginger to a smooth paste in a blender. Heat 120ml oil in a heavy-bottomed pot over medium heat; add the sliced onion and fry for 5–6 minutes, until lightly golden. Stir in 3 tablespoons of tomato paste and cook for 3 minutes, until darkened and the raw aroma is gone. Pour in the blended pepper mixture, add the bay leaves, curry powder, thyme and smoked paprika; cook uncovered over medium heat for 18–20 minutes, stirring often, until the sauce reduces, deepens to a dark red and the oil rises to the surface — this is the critical step. Add the rinsed rice and stir until every grain is coated in sauce; pour in 750ml hot stock, season with salt and pepper, and bring back to a boil. Reduce the heat to the lowest setting, cover the pot tightly (seal the rim with foil before placing the lid for an authentic finish), and cook undisturbed for 25–30 minutes, until the rice is tender and the liquid is absorbed. Turn off the heat and leave covered for 10 more minutes; fluff gently with a fork — the bottom layer should have a slight smoky crust; serve with fried plantain, grilled chicken, or a simple salad."}},{"id":98,"origin":{"ar":"ساموا","en":"Samoa","ro":"Samoa"},"name":{"ar":"أوكا إيا","en":"Oka i'a","ro":"Oka i'a"},"category":{"ar":"وجبة خفيفة","en":"Snack","ro":"Gustare"},"servings":4,"tipType":"fish","pairingsType":"fish","ingredients":{"ar":["500غ تونة أو ماهي ماهي بجودة الساشيمي، منزوعة الجلد والعظام، مقطعة مكعبات بحجم 1,5 سم","120مل عصير ليمون أخضر طازج (نحو 6 ليمونات)","200مل حليب جوز الهند كامل الدسم (طازج الفتح أو معلّب)","1 خيارة متوسطة، مقشّرة منزوعة البذور ومقطعة مكعبات صغيرة","1 بصلة حمراء صغيرة، مقطعة مكعبات صغيرة","2 حبة طماطم ناضجة، منزوعة البذور ومقطعة مكعبات","1 فلفل أحمر حار صغير، مفروم ناعماً (اختياري)","1 عود بصل أخضر، مقطع ناعماً","1 ملعقة صغيرة ملح بحر ناعم","فلفل أسود مطحون طازجاً","أوراق كزبرة طازجة، للتزيين"],"en":["500g sashimi-grade tuna or mahi-mahi, skinned and boned, cut into 1.5 cm cubes","120ml fresh lime juice (about 6 limes)","200ml full-fat coconut milk (freshly opened or canned)","1 medium cucumber, peeled, deseeded, and finely diced","1 small red onion, finely diced","2 ripe tomatoes, deseeded and diced","1 small red chilli, finely chopped (optional)","1 spring onion, finely sliced","1 tsp fine sea salt","freshly ground black pepper","fresh coriander leaves, to garnish"],"ro":["500g ton sau mahi-mahi de calitate sashimi, fără piele și oase, tăiat cuburi de 1,5 cm","120ml suc proaspăt de lime (aproximativ 6 lime)","200ml lapte de cocos integral (proaspăt deschis sau din conservă)","1 castravete mediu, curățat, fără semințe, tăiat cuburi mici","1 ceapă roșie mică, tăiată cuburi mici","2 roșii coapte, fără semințe, tăiate cuburi","1 ardei iute roșu mic, tocat fin (opțional)","1 ceapă verde, tăiată fin","1 linguriță sare fină de mare","piper negru proaspăt măcinat","frunze de coriandru proaspăt, pentru ornat"]},"howIsMade":{"ar":"ضع مكعبات السمك في وعاء غير تفاعلي (زجاج أو سيراميك); اسكب فوقها 120مل من عصير الليمون الأخضر الطازج وقلّب حتى تتغلّف كل قطعة; أدخلها الثلاجة لمدة 15–20 دقيقة — يجب أن يصبح السطح معتماً بينما يبقى القلب شفافاً. خلال تتبيل السمك، انقع البصل الأحمر المقطع مكعبات في ماء بارد لمدة 10 دقائق ثم صفّه; هذه الخطوة تخفف من حدته دون أن تفقده القرمشة. صفّ السمك جيداً في مصفاة دقيقة; تخلّص من معظم عصير الليمون مع الاحتفاظ بـ 2 ملعقة كبيرة منه. أعد السمك إلى وعاء نظيف; أضف الخيار والبصل الأحمر المصفّى والطماطم والفلفل الحار والبصل الأخضر; قلّب بلطف ليبقى السمك متماسكاً. اسكب 200مل من حليب جوز الهند مع 2 ملعقة كبيرة من عصير الليمون المحتفظ به; أضف الملح وعدة لفّات من الفلفل; اطوِ الخليط برفق — يجب أن يغلّف حليب جوز الهند السمك دون أن يفتته. تذوّق واضبط الملح أو الليمون; قدّمه فوراً، بارداً جداً، في أوعية ضحلة; زيّنه بأوراق كزبرة طازجة.","en":"Place the cubed fish in a non-reactive (glass or ceramic) bowl; pour over 120ml fresh lime juice and toss until every piece is coated; refrigerate for 15–20 minutes — the surface should turn opaque while the centre stays translucent. While the fish marinates, soak the diced red onion in cold water for 10 minutes, then drain; this softens its raw bite without losing the crunch. Drain the fish thoroughly through a fine sieve; discard most of the lime juice but reserve 2 tablespoons. Return the fish to a clean bowl; add the cucumber, drained red onion, tomatoes, chilli and spring onion; toss gently so the fish stays intact. Pour in 200ml coconut milk and the reserved 2 tbsp lime juice; add the salt and a few grinds of pepper; fold everything together gently — the coconut milk should coat without breaking the fish. Taste and adjust salt or lime; serve immediately, very cold, in shallow bowls; scatter fresh coriander leaves on top."}},{"id":99,"origin":{"ar":"أرمينيا","en":"Armenia","ro":"Armenia"},"name":{"ar":"خوروفاتس","en":"Khorovats","ro":"Khorovats"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ar":["800غ من كتف الخنزير أو فيليه البقر، مقطعة مكعبات بحجم 4 سم","2 بصلة حمراء كبيرة (واحدة شرائح للتتبيلة، واحدة أرباع للأسياخ)","1 فلفل رومي أحمر، مقطع قطعاً بحجم 4 سم","1 فلفل رومي أخضر، مقطع قطعاً بحجم 4 سم","1 باذنجان متوسط، مقطع شرائح بسماكة 3 سم","4 حبات طماطم ناضجة (تُشوى كاملة جانباً)","3 ملاعق كبيرة زيت دوار الشمس","1 ملعقة صغيرة فلفل أسود مطحون طازجاً","2 ملعقة صغيرة ملح خشن","حفنة صغيرة من الريحان والبقدونس الطازج، للتقديم","خبز اللواش أو أي خبز مسطح آخر، للتقديم"],"en":["800g pork shoulder or beef tenderloin, cut into 4 cm cubes","2 large red onions (1 sliced for the marinade, 1 cut into wedges for skewering)","1 red bell pepper, cut into 4 cm pieces","1 green bell pepper, cut into 4 cm pieces","1 medium aubergine, cut into 3 cm rounds","4 ripe tomatoes (to be grilled whole alongside)","3 tbsp sunflower oil","1 tsp freshly ground black pepper","2 tsp coarse salt","a small handful of fresh basil and parsley, to serve","lavash or another flatbread, to serve"],"ro":["800g pulpă de porc sau mușchi de vită, tăiat cuburi de 4 cm","2 cepe roșii mari (una feliată pentru marinadă, una tăiată felii pentru frigărui)","1 ardei gras roșu, tăiat bucăți de 4 cm","1 ardei gras verde, tăiat bucăți de 4 cm","1 vânătă medie, tăiată rondele de 3 cm","4 roșii coapte (pentru grătar întregi)","3 linguri ulei de floarea-soarelui","1 linguriță piper negru proaspăt măcinat","2 lingurițe sare grunjoasă","un mănunchi de busuioc și pătrunjel proaspăt, pentru servit","lavaș sau alt tip de pâine plată"]},"howIsMade":{"ar":"قطّع بصلة واحدة شرائح رفيعة; في وعاء كبير، اخلط 800غ من اللحم المكعّب، البصل المقطع، 2 ملعقة صغيرة من الملح، 1 ملعقة صغيرة من الفلفل الأسود، و3 ملاعق كبيرة من زيت دوار الشمس; دلّك جيداً باليد وضعه في الثلاجة 4–8 ساعات أو طوال الليل. أشعل ناراً من الفحم واتركها تحترق حتى يصبح الجمر أحمر متوهجاً مع حواف بيضاء — نحو 30–40 دقيقة; ضع الشبك على بعد 15 سم فوق الجمر. ثبّت اللحم المتبّل على أسياخ معدنية، بالتناوب مع أرباع البصل، تاركاً فجوات صغيرة بين القطع ليمر الهواء الساخن. ضع الفلفل كاملاً وشرائح الباذنجان والطماطم مباشرة فوق الشبك بعيداً عن اللحم; أدِرها باستمرار حتى تسودّ القشرة من كل الجوانب — حوالي 12–15 دقيقة إجمالاً. ضع أسياخ اللحم فوق أسخن جزء من الجمر; اشوها 10–14 دقيقة، مع تقليبها كل دقيقتين، حتى يصبح اللحم متكرملاً بعمق من الخارج وما زال وردياً في المنتصف — درجة حرارة داخلية 60°م لمنتجات الخنزير. انقل الخضروات المشوية إلى طبق وغطّها بورق ألمنيوم لمدة 5 دقائق ثم انزع القشور المحروقة; قطّعها خشناً واخلطها بعصارتها والملح والبقدونس المفروم لتكوّن صلصة ريفية. قدّم الأسياخ ساخنة مع صلصة الخضروات والريحان الطازج وشرائح الليمون وخبز اللواش الدافئ لللف.","en":"Thinly slice one onion; in a large bowl, combine 800g cubed meat, the sliced onion, 2 tsp salt, 1 tsp black pepper, and 3 tbsp sunflower oil; massage well by hand and refrigerate 4–8 hours, or overnight. Light a charcoal fire and let it burn down to glowing red embers with white edges — about 30–40 minutes; position the grill 15 cm above the coals. Thread the marinated meat onto metal skewers, alternating with wedges of onion and leaving small gaps between pieces so the hot air can circulate. Lay the whole peppers, aubergine slices and tomatoes directly on the grill, away from the meat; char them rotating frequently, until the skins blacken on every side — about 12–15 minutes total. Place the meat skewers over the hottest part of the embers; grill 10–14 minutes, turning every 2 minutes, until the meat is deeply caramelised outside but still pink in the centre — internal temperature 60°C for pork. Transfer the grilled vegetables to a plate, cover with foil for 5 minutes, then strip off the blackened skins; roughly chop and mix with the resting juices, salt, and chopped parsley to make a rustic relish. Serve the skewers hot with the vegetable relish, fresh basil, lemon wedges, and warm lavash for wrapping."}},{"id":100,"origin":{"ar":"إستونيا","en":"Estonia","ro":"Estonia"},"name":{"ar":"فيريفورست","en":"Verivorst","ro":"Verivorst"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ar":["500غ من دم الخنزير (طازج أو مذاب)","200غ من دهن الخنزير أو لحم خنزير دهني، مقطع مكعبات صغيرة","200غ شعير لؤلؤي، مطبوخ ومبرّد","2 بصلة كبيرة، مفرومة ناعماً","1 ملعقة صغيرة بردقوش يابس","1 ملعقة صغيرة فلفل أفرنجي مطحون","1 ملعقة صغيرة فلفل أسود مطحون","2 ملعقة صغيرة ملح خشن","1,5م من غلاف نقانق طبيعي منظف","2 ملعقة كبيرة شحم خنزير للطهي","مربى عنب الثعلب وخيار مخلّل، للتقديم"],"en":["500g pig's blood (fresh or thawed)","200g pork fat or fatty pork belly, finely diced","200g pearl barley, cooked and cooled","2 large onions, finely chopped","1 tsp dried marjoram","1 tsp ground allspice","1 tsp ground black pepper","2 tsp coarse salt","1.5m cleaned natural sausage casing","2 tbsp pork lard, for cooking","lingonberry jam and pickled cucumbers, to serve"],"ro":["500g sânge de porc (proaspăt sau decongelat)","200g slănină sau piept de porc gras, tăiat cuburi mici","200g orz perlat, fiert și răcit","2 cepe mari, tocate fin","1 linguriță maghiran uscat","1 linguriță ienibahar măcinat","1 linguriță piper negru măcinat","2 lingurițe sare grunjoasă","1,5m maț natural curățat","2 linguri untură de porc, pentru gătit","gem de lingonberry și castraveți murați, pentru servit"]},"howIsMade":{"ar":"في مقلاة كبيرة، اقلِ مكعبات دهن الخنزير على نار هادئة لمدة 8–10 دقائق حتى يذوب معظم الدهن وتصبح المكعبات ذهبية; أضف البصل المفروم واطبخه 6–8 دقائق إضافية حتى يلين ويصبح شفافاً; اتركه ليبرد تماماً. في وعاء كبير، اخلط الشعير المطبوخ، البصل ومكعبات الدهن المقلية (مع كل دهنها)، البردقوش، الفلفل الأفرنجي، الملح والفلفل الأسود; اخلط جيداً. اخفق الدم بسرعة بالمضرب لتفكيك أي تجلطات، ثم أضفه تدريجياً إلى خليط الشعير; يجب أن تكون الحشوة لامعة وسائلة بقوام يمكن سكبه، لكن ليست شديدة السيولة. اشطف غلاف النقانق تحت الماء البارد الجاري لمدة 5 دقائق; اربط أحد طرفيه بخيط مطبخ. أدخل الطرف المفتوح للغلاف على قمع واسع أو أداة حشو النقانق; أدخل الخليط تدريجياً، تاركاً ثلثَي الغلاف ممتلئين فقط لتسمح بالتمدد أثناء الطهي; اربط على شكل نقانق بطول 12–15 سم وانخز كل واحدة بإبرة في عدة مواضع. أحضر قدراً كبيراً من الماء بدرجة 80°م — دون أن يغلي; ضع النقانق برفق واسلقها هادئاً لمدة 30–40 دقيقة، حتى تصبح متماسكة بالملمس ويخرج عصيرها صافياً عند الوخز. أخرج النقانق ودعها ترتاح 10 دقائق; سخّن الفرن إلى 200°م. ادهن النقانق بالشحم المذاب واشوها في صينية لمدة 12–15 دقيقة، مع تقليبها مرة واحدة، حتى يصبح غلافها مقرمشاً ولامعاً; قدّمها ساخنة مع مربى عنب الثعلب والخيار المخلل.","en":"In a large pan, fry the diced pork fat over low heat for 8–10 minutes, until most of its fat has rendered and the cubes are golden; add the chopped onions and cook 6–8 minutes more, until soft and translucent; set aside to cool completely. In a large bowl, combine the cooked pearl barley, the fried onions and pork fat (with all their fat), the marjoram, allspice, salt and pepper; mix well. Whisk the blood briefly to break up any clots, then stir it gradually into the barley mixture; the filling should look glossy and pourable, but not too liquid. Rinse the sausage casing under cold running water for 5 minutes; tie off one end with kitchen twine. Slide the open end of the casing onto a wide funnel or sausage stuffer; pipe the mixture in gradually, leaving the casing two-thirds full to allow expansion during cooking; tie off into 12–15 cm sausages and prick each with a needle in several places. Bring a large pot of water to 80°C — not boiling; slip the sausages in and poach gently for 30–40 minutes, until they feel firm to the touch and the juices run clear when pricked. Lift the sausages out and let them rest 10 minutes; preheat the oven to 200°C. Brush the sausages with melted lard and roast on a tray for 12–15 minutes, turning once, until the skins are crisp and burnished; serve hot with lingonberry jam and pickled cucumbers."}},{"id":102,"origin":{"ar":"كوريا الجنوبية","en":"South Korea","ro":"Coreea de Sud"},"name":{"ar":"تيوكبوكي","en":"Tteokbokki","ro":"Tteokbokki"},"category":{"ar":"وجبة خفيفة","en":"Snack","ro":"Gustare"},"servings":4,"tipType":"def","pairingsType":"korean","ingredients":{"ar":["500غ توك أسطواني (غاراي-توك) طازج أو مذاب","150غ إيومُك (كعكة السمك الكورية) مقطّعة مثلثات","3 ملاعق كبيرة غوتشوجانغ (معجون الفلفل الأحمر المخمّر)","1 ملعقة كبيرة غوتشوغارو (رقائق الفلفل الأحمر الكوري)","1 ملعقة كبيرة سكر","1 ملعقة صغيرة صلصة الصويا","500مل مرق الأنشوجة (أو ماء مع كيس داشي)","2 بصل أخضر مقطّع 5 سم","2 بيضة مسلوقة مقشّرة","1 ملعقة صغيرة زيت السمسم","1 ملعقة صغيرة سمسم محمص"],"en":["500g cylindrical rice cakes (garae-tteok), fresh or thawed","150g eomuk (Korean fish cake), cut into triangles","3 tbsp gochujang (fermented red chili paste)","1 tbsp gochugaru (Korean red pepper flakes)","1 tbsp sugar","1 tsp soy sauce","500ml anchovy stock (or water with a dashi packet)","2 spring onions, cut into 5 cm pieces","2 hard-boiled eggs, peeled","1 tsp sesame oil","1 tsp toasted sesame seeds"],"ro":["500g tteok cilindric (garae-tteok) proaspăt sau dezghețat","150g eomuk (prăjitură de pește coreeană), tăiat în triunghiuri","3 linguri gochujang (pastă de ardei iute fermentat)","1 lingură gochugaru (fulgi de ardei iute coreean)","1 lingură zahăr","1 linguriță sos de soia","500ml supă de hamsii (sau apă cu dashi)","2 cepe verzi, tăiate în bucăți de 5 cm","2 ouă fierte tari, decojite","1 linguriță ulei de susan","1 linguriță semințe de susan prăjite"]},"howIsMade":{"ar":"إذا كان التوك صلباً أو مبرّداً، انقعه في ماء دافئ لمدة 20–30 دقيقة حتى يصبح طريّاً; صفّه. في مقلاة واسعة، اغلِ 500مل من مرق الأنشوجة على نار متوسطة عالية. أضف 3 ملاعق كبيرة غوتشوجانغ، 1 ملعقة كبيرة غوتشوغارو، 1 ملعقة كبيرة سكر و1 ملعقة صغيرة صلصة صويا; اخفقه حتى تذوب العجينة كلياً ويصبح الصوص لامعاً أحمر اللون. أضف التوك المصفّى; قلّب برفق ليتغلّف كل قطعة، ثم اطبخ على نار متوسطة 8–10 دقائق مع التحريك المتكرر، حتى يصبح التوك طريّاً والصوص قِواماً شُربياً يغطّي ظهر الملعقة. أضف قطع الإيومُك واطبخ 3–4 دقائق إضافية حتى تمتص الصوص وتصبح حمراء زاهية. ضع البيضتين المسلوقتين لتسخنا; تذوّق واضبط بقليل من السكر أو رشة صلصة صويا إذا لزم. اسكب عليه زيت السمسم، رشّ البصل الأخضر وبذور السمسم; قدّم فوراً ساخناً جداً مباشرة من المقلاة.","en":"If the rice cakes are hard or refrigerated, soak them in warm water for 20–30 minutes until pliable; drain. In a wide shallow pan, bring 500ml of anchovy stock to a boil over medium-high heat. Stir in 3 tbsp gochujang, 1 tbsp gochugaru, 1 tbsp sugar and 1 tsp soy sauce; whisk until the paste fully dissolves and the sauce turns glossy red. Add the drained rice cakes; stir gently to coat every piece, then simmer over medium heat for 8–10 minutes, stirring often, until the rice cakes are tender and the sauce has thickened to a syrupy consistency that coats the back of a spoon. Add the eomuk pieces and cook for another 3–4 minutes, until they have absorbed the sauce and turned bright red. Slip in the 2 hard-boiled eggs to warm through; taste and adjust with a pinch of sugar or a splash of soy if needed. Drizzle with sesame oil, sprinkle with the spring onions and sesame seeds; serve immediately, very hot, straight from the pan."}},{"id":103,"origin":{"ar":"الإكوادور","en":"Ecuador","ro":"Ecuador"},"name":{"ar":"سيفيتشي الروبيان","en":"Shrimp Ceviche","ro":"Ceviche de camarón"},"category":{"ar":"وجبة خفيفة","en":"Snack","ro":"Gustare"},"servings":4,"tipType":"fish","pairingsType":"fish","ingredients":{"ar":["600غ من الروبيان المتوسط، مقشّر ومنزوع العصب","180مل عصير ليمون أخضر طازج (نحو 8 ليمونات)","120مل عصير برتقال طازج","1 بصلة حمراء كبيرة، مقطعة مكعبات صغيرة","3 حبات طماطم ناضجة، منزوعة البذور ومقطعة مكعبات","1 فلفل أحمر حار (آخي)، مفروم ناعماً (اختياري)","30غ كزبرة طازجة، مفرومة","3 ملاعق كبيرة زيت زيتون","1 ملعقة صغيرة ملح بحر ناعم","فلفل أسود مطحون طازجاً","تشيفليس (شيبس الموز) أو ذرة محمصة، للتقديم"],"en":["600g medium shrimp, peeled and deveined","180ml fresh lime juice (about 8 limes)","120ml fresh orange juice","1 large red onion, finely diced","3 ripe tomatoes, deseeded and diced","1 red chili (ají), finely chopped (optional)","30g fresh coriander leaves, chopped","3 tbsp olive oil","1 tsp fine sea salt","freshly ground black pepper","chifles (plantain chips) or toasted corn, to serve"],"ro":["600g creveți medii, decojiți și fără vene","180ml suc proaspăt de lime (aproximativ 8 lime)","120ml suc proaspăt de portocale","1 ceapă roșie mare, tăiată cuburi mici","3 roșii coapte, fără semințe și tăiate cuburi","1 ardei iute roșu (ají), tocat fin (opțional)","30g frunze de coriandru proaspăt, tocate","3 linguri ulei de măsline","1 linguriță sare fină de mare","piper negru proaspăt măcinat","chifles (chipsuri de plantain) sau porumb prăjit, pentru servit"]},"howIsMade":{"ar":"أحضر قدراً كبيراً من الماء المملّح إلى الغليان; أضف الروبيان واطبخه 60–90 ثانية حتى يصبح وردياً ومعتماً; صفّه فوراً واغمسه في وعاء ماء مثلّج. صفّ الروبيان، اقطعه نصفين أو دعه كاملاً حسب الذوق، ثم ضعه في وعاء غير تفاعلي (زجاج أو سيراميك). اسكب 180مل من عصير الليمون الأخضر و120مل من عصير البرتقال فوق الروبيان; قلّب وغطِّ ثم أدخله الثلاجة 15–20 دقيقة. خلال تتبيل الروبيان، انقع البصل الأحمر المقطع في ماء بارد مملّح لمدة 10 دقائق ثم صفّه — هذه الخطوة تخفف الحدة وتحافظ على القرمشة. أضف إلى وعاء الروبيان البصل المصفّى والطماطم والفلفل الحار والكزبرة و3 ملاعق كبيرة زيت زيتون و1 ملعقة صغيرة ملح; قلّب بلطف. تذوّق واضبط الملح أو الليمون أو الفلفل; اتركه يرتاح 5 دقائق حتى تستقر النكهات. قدّمه بارداً جداً في أوعية ضحلة مع تشيفليس أو ذرة محمصة لتباين مقرمش.","en":"Bring a large pot of salted water to a boil; add the shrimp and boil for 60–90 seconds, until pink and opaque; drain immediately and shock in a bowl of ice water. Drain the shrimp, halve them or leave them whole as you prefer, and place in a non-reactive (glass or ceramic) bowl. Pour 180ml lime juice and 120ml orange juice over the shrimp; toss, cover, and refrigerate for 15–20 minutes. While the shrimp marinates, soak the diced red onion in salted ice water for 10 minutes, then drain — this softens the harsh bite without losing crunch. Add the drained onion, tomatoes, chili, coriander, 3 tbsp olive oil and 1 tsp salt to the shrimp bowl; toss gently. Taste and adjust salt, lime, or chili; let rest for 5 minutes so the flavours settle. Serve very cold in shallow bowls, with chifles or toasted corn alongside for crisp contrast."}},{"id":104,"origin":{"ar":"جمهورية الدومينيكان","en":"Dominican Republic","ro":"Republica Dominicană"},"name":{"ar":"لا باندييرا","en":"La Bandera","ro":"La Bandera"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"latin","ingredients":{"ar":["400غ من الأرز الأبيض طويل الحبة","250غ فاصولياء حمراء جافة (أو 800غ مطبوخة/معلبة، مصفّاة)","600غ من فخذ الدجاج بالعظم أو لحم بقري للطهي، مقطّع مكعبات بحجم 4 سم","2 موزة جنة خضراء كبيرة، مقشّرة ومقطّعة شرائح بسماكة 1 سم","1 فلفل رومي أخضر متوسط، مقطّع مكعبات صغيرة","1 فلفل رومي أحمر صغير، مقطّع مكعبات صغيرة","1 بصلة كبيرة، مفرومة ناعماً","4 فصوص ثوم، مفرومة","30غ كزبرة طازجة، مفرومة (أو كولانترو)","2 حبة طماطم ناضجة، مقطعة مكعبات (أو 200غ طماطم مفرومة معلّبة)","2 ملعقة كبيرة معجون طماطم","60مل زيت نباتي (وإضافي لقلي موز الجنة)","1 ملعقة صغيرة زعتر يابس","عصير ليمونة خضراء واحدة","ملح وفلفل أسود مطحون طازجاً"],"en":["400g long-grain white rice","250g dried red kidney beans (or 800g cooked/canned, drained)","600g bone-in chicken thighs or beef chuck, cut into 4 cm cubes","2 large green plantains, peeled and sliced 1 cm thick","1 medium green bell pepper, finely diced","1 small red bell pepper, finely diced","1 large onion, finely chopped","4 garlic cloves, minced","30g fresh coriander, chopped (or culantro if available)","2 ripe tomatoes, diced (or 200g canned chopped tomatoes)","2 tbsp tomato paste","60ml vegetable oil (plus more for frying plantains)","1 tsp dried oregano","juice of 1 lime","salt and freshly ground black pepper"],"ro":["400g orez cu bob lung alb","250g fasole roșie uscată (sau 800g fasole gătită)","600g pulpe de pui cu os sau pulpă de vită, tăiată cuburi de 4 cm","2 banane plantain verzi mari, decojite, tăiate rondele de 1 cm","1 ardei gras verde mediu, tăiat cuburi mici","1 ardei gras roșu mic, tăiat cuburi mici","1 ceapă mare, tocată fin","4 căței de usturoi, tocați","30g coriandru proaspăt, tocat (sau culantro)","2 roșii coapte, tăiate cuburi (sau 200g roșii din conservă)","2 linguri pastă de roșii","60ml ulei vegetal (plus mai mult pentru prăjit)","1 linguriță oregano uscat","zeamă de la 1 lime","sare și piper negru proaspăt măcinat"]},"howIsMade":{"ar":"انقع الفاصولياء الجافة طوال الليل إن استخدمتها; صفّها وغطِّها بـ1ل من الماء النظيف ورشة ملح، واطبخها على نار هادئة 60–75 دقيقة حتى تطرى تماماً; احتفظ بـ250مل من ماء الطبخ. تبّل اللحم بالملح والفلفل والزعتر وعصير الليمون; اتركه يرتاح 15 دقيقة ريثما تجهّز الصوفريتو. سخّن 2 ملعقة كبيرة من الزيت في قدر سميك; حضّر الصوفريتو: قلّب البصل 5 دقائق ثم أضف الثوم والفلفلين ونصف الكزبرة; اطبخ 4 دقائق حتى يلين. ادفع الصوفريتو إلى جانب; ضع اللحم في الفراغ وحمّره 3–4 دقائق لكل وجه; أضف 2 ملعقة كبيرة معجون طماطم والطماطم المقطعة، اطبخ 3 دقائق; اسكب 500مل ماء، غطِّ القدر، واطبخ على نار هادئة 35–40 دقيقة حتى يصبح اللحم طرياً وتثخن الصلصة. في هذه الأثناء اطبخ الأرز: اشطف 400غ أرز حتى يصفو الماء; في قدر واسع، سخّن 1 ملعقة كبيرة زيت و1 ملعقة صغيرة ملح، أضف الأرز، وغطِّه بـ700مل ماء، اغلِه ثم خفّض النار إلى أدنى درجة واطبخ مغطّى 18–20 دقيقة; اتركه يرتاح 10 دقائق بعيداً عن النار. أكمل الفاصولياء: في قدر صغير، سخّن 1 ملعقة كبيرة زيت وملعقة من الصوفريتو المحفوظ في الخطوة 3; أضف الفاصولياء المصفّاة و250مل من ماء الطبخ المحفوظ و1 ملعقة صغيرة ملح; اطبخ 12–15 دقيقة، مع هرس حفنة من الفاصولياء على جانب القدر لتثخّن الصلصة. سخّن 5 سم من الزيت إلى 175°م; اقلِ شرائح موز الجنة 3–4 دقائق حتى تصبح ذهبية; صفّها على ورق، اضغطها بمكبس أو بقاع كأس، ثم أعد قليها 1–2 دقيقة حتى تصبح مقرمشة; ملّحها وهي ساخنة. في الطبق: الأرز كقاعدة، مغرفة فاصولياء جانباً، حصة وافرة من اللحم المطهو بصلصته، و4–5 شرائح موز جنة; اختم بالكزبرة المتبقية، شرائح الليمون، وسلطة خضراء بسيطة.","en":"Soak the dried beans overnight if using; drain, cover with 1L fresh water and a pinch of salt, and simmer for 60–75 minutes, until fully tender; reserve 250ml of the cooking liquid. Season the meat with salt, pepper, oregano, and lime juice; rest for 15 minutes while you prepare the sofrito. Heat 2 tbsp oil in a heavy pot; make a sofrito: sauté the onion for 5 minutes, then add the garlic, both peppers, and half the coriander; cook 4 minutes until soft. Push the sofrito to one side; add the meat to the empty space and brown for 3–4 minutes per side; stir in 2 tbsp tomato paste and the diced tomatoes, cook for 3 minutes; pour in 500ml water, cover, and simmer for 35–40 minutes, until the meat is fork-tender and the sauce has thickened. Meanwhile cook the rice: rinse 400g of rice until the water runs clear; in a wide pot, heat 1 tbsp oil and 1 tsp salt, add the rice, cover with 700ml water, bring to a boil, then reduce to the lowest heat and steam, covered, for 18–20 minutes; rest 10 minutes off heat. Finish the beans: in a small pot, heat 1 tbsp oil and a spoonful of the sofrito set aside in step 3; add the drained beans plus 250ml reserved cooking liquid and 1 tsp salt; simmer for 12–15 minutes, mashing a handful against the side of the pot to thicken to a saucy consistency. Heat 5 cm of oil in a frying pan to 175°C; fry the plantain slices for 3–4 minutes until golden; drain on paper, flatten with a press or the back of a cup, and refry for 1–2 minutes until crisp; salt while hot. Plate each portion with rice as the base, a ladle of beans alongside, a generous portion of braised meat with its sauce, and 4–5 plantain rounds; finish with the remaining coriander, lime wedges, and a simple green salad."}},{"id":105,"origin":{"ar":"إيران","en":"Iran","ro":"Iran"},"name":{"ar":"فسنجان","en":"Fesenjan","ro":"Fesenjan"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"middle-eastern","ingredients":{"ar":["800غ من فخذ الدجاج منزوع العظم، أو بطة صغيرة (1,5كغ) مقطّعة","300غ من جوز مقشّر، محمّص ومطحون ناعماً","120مل دبس الرمان","2 بصلة كبيرة، مفرومة ناعماً","3 ملاعق كبيرة زيت نباتي","1 ملعقة صغيرة كركم مطحون","1 ملعقة صغيرة قرفة مطحونة","1/2 ملعقة صغيرة جوزة طيب مبشورة طازجة","1 ملعقة كبيرة سكر أسمر (أو حسب الذوق)","1 لتر مرق دجاج ساخن أو ماء","بذور رمان طازجة، للتزيين","ملح وفلفل أسود مطحون طازجاً","أرز بسمتي، للتقديم"],"en":["800g boneless chicken thighs, or 1 small duck (1.5kg) jointed","300g shelled walnuts, toasted and finely ground","120ml pomegranate molasses","2 large onions, finely chopped","3 tbsp vegetable oil","1 tsp ground turmeric","1 tsp ground cinnamon","1/2 tsp freshly grated nutmeg","1 tbsp brown sugar (or to taste)","1 litre hot chicken stock or water","fresh pomegranate seeds, to garnish","salt and freshly ground black pepper","basmati rice, to serve"],"ro":["800g pulpe de pui dezosate, sau 1 rață mică (1,5kg) tăiată","300g miez de nucă, prăjit și măcinat fin","120ml melasă de rodie","2 cepe mari, tocate fin","3 linguri ulei vegetal","1 linguriță turmeric măcinat","1 linguriță scorțișoară măcinată","1/2 linguriță nucșoară proaspăt rasă","1 lingură zahăr brun (sau după gust)","1 litru supă de pui sau apă fierbinte","semințe de rodie proaspete, pentru ornat","sare și piper negru proaspăt măcinat","orez basmati pentru servit"]},"howIsMade":{"ar":"حمّر 300غ من الجوز في مقلاة جافة على نار متوسطة لمدة 4–5 دقائق مع التحريك المستمر حتى يفوح عطره ويصبح أغمق قليلاً; اتركه يبرد ثم اطحنه في الخلاط إلى عجينة ناعمة قدر الإمكان. في قدر سميك، سخّن 3 ملاعق كبيرة من الزيت على نار متوسطة; أضف البصل المفروم واطبخه 12–15 دقيقة حتى يصبح ذهبياً عميقاً وحلواً; أضف الكركم والقرفة وجوزة الطيب واطبخ 1 دقيقة. تبّل اللحم بالملح والفلفل; ضعه في القدر وحمّره 4–5 دقائق لكل وجه، فقط ليكتسب اللون; ارفعه إلى طبق. أضف عجينة الجوز إلى القدر وقلّبها بملعقة خشبية 3 دقائق حتى تبدأ بإطلاق زيتها وتفوح رائحتها المحمّصة — هذه الخطوة تبني عمق الصلصة. اسكب 1 لتر من المرق الساخن، أعد اللحم مع عصارته، واطبخ بدون غطاء على نار هادئة 30–40 دقيقة مع التحريك المتكرر كي لا تحترق عجينة الجوز. أضف دبس الرمان والسكر الأسمر; تذوّق: يجب أن تكون الصلصة حامضةً حلوة وعميقة النكهة; تابع الطهي على نار هادئة 30–40 دقيقة أخرى حتى ينضج اللحم تماماً ويصبح لون الصلصة شبه أسود ويطفو زيت الجوز على السطح. اضبط الملح، أضف مزيداً من الدبس (للحموضة) أو السكر (للتوازن); قدّمه فوق أرز بسمتي دافئ مع رشة من بذور الرمان الطازجة.","en":"Toast 300g of walnuts in a dry pan over medium heat for 4–5 minutes, tossing constantly, until fragrant and slightly darker; cool, then grind to as fine a paste as possible in a food processor. In a heavy pot, heat 3 tbsp oil over medium heat; add the chopped onions and cook for 12–15 minutes, until deeply golden and sweet; stir in the turmeric, cinnamon, and nutmeg and cook for 1 minute. Season the meat with salt and pepper; add to the pot and brown for 4–5 minutes per side, just for colour; lift onto a plate. Add the walnut paste to the pot and stir with a wooden spoon for 3 minutes, until it starts releasing oil and smells toasted — this is the step that builds the sauce's depth. Pour in 1 litre of hot stock, return the meat with its juices, and simmer uncovered over low heat for 30–40 minutes, stirring often so the nut paste does not scorch. Add the pomegranate molasses and brown sugar; taste: the sauce should be tart-sweet and deeply savoury; continue to simmer over low heat for another 30–40 minutes, until the meat is fully tender, the sauce has darkened to almost black, and walnut oil rises to the surface. Adjust with salt, more molasses (for tartness) or sugar (to round it); serve over warm basmati rice, scattered with fresh pomegranate seeds."}},{"id":106,"origin":{"ar":"الفلبين","en":"Philippines","ro":"Filipine"},"name":{"ar":"كاري كاري","en":"Kare-Kare","ro":"Kare-Kare"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ar":["1,2كغ من ذيل الثور، مقطّع عند المفاصل (أو ساق بقري بالعظم)","200غ من زبدة الفول السوداني غير المحلّاة (أو 250غ فول سوداني محمّص ومطحون)","2 ملعقة كبيرة من بذور الأناتو (أتشويتي) — أو 1 ملعقة كبيرة من مسحوق الأناتو","4 ملاعق كبيرة أرز نيء، محمّص في مقلاة جافة ومطحون","1 بصلة كبيرة، مفرومة ناعماً","6 فصوص ثوم، مفرومة","1 باذنجانة كبيرة، مقطعة أرباعاً","200غ فاصولياء خضراء طويلة (سيتاو)، مقطعة قطعاً بطول 7 سم","1 بوك تشوي كبيرة أو 200غ بيتشاي، مقطعة طولياً نصفين","1,5ل ماء (أو مرق بقري)","60مل زيت نباتي","ملح حسب الذوق","باغونغ (معجون الروبيان الفلبيني)، للتقديم","أرز مطهو بالبخار، للتقديم"],"en":["1.2kg oxtail, cut at the joints (or bone-in beef shank)","200g unsweetened peanut butter (or 250g roasted peanuts, ground)","2 tbsp annatto (achuete) seeds — or 1 tbsp annatto powder","4 tbsp raw rice, toasted in a dry pan and ground","1 large onion, finely chopped","6 garlic cloves, minced","1 large eggplant, cut into quarters","200g long green beans (sitaw), cut into 7 cm lengths","1 large bok choy or 200g pechay, halved lengthwise","1.5L water (or beef stock)","60ml vegetable oil","salt to taste","bagoong (Filipino shrimp paste), to serve","steamed rice, to serve"],"ro":["1,2kg coadă de vită, tăiată în bucăți la articulație (sau pulpă de vită cu os)","200g pastă de arahide neîndulcită (sau 250g arahide prăjite, măcinate)","2 linguri semințe de annatto (achiote) — sau 1 lingură pudră de annatto","4 linguri orez crud, prăjit într-o tigaie uscată și măcinat","1 ceapă mare, tocată fin","6 căței de usturoi, tocați","1 vânătă mare, tăiată sferturi","200g fasole verde lungă, tăiată în bucăți de 7 cm","1 bok choy mare sau 200g pak choi, tăiat pe lungime","1,5L apă (sau supă de vită)","60ml ulei vegetal","sare după gust","bagoong (pastă de creveți filipineză) pentru servit","orez fiert, pentru servit"]},"howIsMade":{"ar":"ضع ذيل الثور في قدر كبير مع 1,5ل ماء; أوصله إلى الغليان، أزل الرغوة، واطبخ 5 دقائق; صفّه واغسل اللحم للحصول على مرق صافٍ. أعد اللحم إلى القدر مع 1,5ل ماء طازج (أو مرق بقري) واطبخه على نار هادئة 2,5–3 ساعات حتى يكاد ينفصل عن العظم; ارفع اللحم واحتفظ بـ1ل من المرق. انقع بذور الأناتو في 3 ملاعق كبيرة ماء ساخن لمدة 10 دقائق ثم صفِّه إلى سائل أحمر-برتقالي عميق (أو أذِب مسحوق الأناتو مباشرة). في قدر نظيف، سخّن 60مل من الزيت; قلّب البصل 5 دقائق ثم أضف الثوم واطبخ دقيقة أخرى. أضف زبدة الفول السوداني وسائل الأناتو و1ل من المرق المحفوظ; اخفقه ليبقى ناعماً; اطبخ 5 دقائق ثم أضف الأرز المحمّص المطحون — ستبدأ الصلصة بالتكثّف بشكل ملحوظ. أعد اللحم إلى الصلصة واطبخ على نار هادئة 10–15 دقيقة، خفّفه بمزيد من المرق إذا صار سميكاً جداً; تبّل بالملح باعتدال — الباغونغ على المائدة شديد الملوحة. أضف أرباع الباذنجان والفاصولياء الخضراء، اطبخ 5 دقائق; ضع البوك تشوي فوقها، غطِّ القدر، واطبخ 3 دقائق إضافية حتى تطرى الخضار مع بقاء ألوانها زاهية. قدّمه في أوعية عميقة فوق أرز مطهو بالبخار، مع الباغونغ في وعاء صغير جانباً — يضيف كل ضيف القدر الذي يحبه.","en":"Put the oxtail in a large pot with 1.5L water; bring to a boil, skim the foam, and boil for 5 minutes; drain and rinse the meat for a clear broth. Return the meat to the pot with 1.5L fresh water (or beef stock) and simmer gently for 2.5–3 hours, until the meat falls almost off the bone; lift out the meat and reserve 1L of the broth. Steep the annatto seeds in 3 tbsp hot water for 10 minutes, then strain to a deep red-orange liquid (or dissolve the annatto powder directly). In a clean pot, heat 60ml oil; sauté the onion for 5 minutes, add the garlic and cook 1 minute more. Stir in the peanut butter, annatto liquid, and 1L of the reserved broth; whisk to keep it smooth; simmer 5 minutes, then add the toasted ground rice — the sauce will begin to thicken visibly. Return the meat to the sauce and simmer over low heat for 10–15 minutes, loosening with more broth if it becomes too thick; season with salt (sparingly — the bagoong at the table is very salty). Add the eggplant quarters and long beans, simmer 5 minutes; lay the bok choy on top, cover, and cook for another 3 minutes, until the vegetables are tender but still vibrant. Serve in deep bowls over steamed rice, with bagoong in a small bowl alongside — each diner stirs in as much as they like."}},{"id":107,"origin":{"ar":"البرتغال","en":"Portugal","ro":"Portugalia"},"name":{"ar":"فرانسزينها","en":"Francesinha","ro":"Francesinha"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ar":["8 شرائح سميكة من خبز التوست الأبيض","400غ من ستيك الريب آي أو السيرلوين، مقطّع 4 شرائح رفيعة","4 نقانق لينكيسا أو نقانق مدخّنة، مقطّعة طولياً نصفين","8 شرائح لحم خنزير مطهي (هام)","8 شرائح سلامي حار أو شوريسو","12 شريحة جبنة شيدر أو غودا قابلة للذوبان","4 بيضات للأعلى","30غ زبدة","زيت لقلي البيض","للصلصة:","400مل بيرة فاتحة","200مل مرق بقري","200غ معجون طماطم","60مل ويسكي أو براندي","1 بصلة صغيرة، مفرومة ناعماً","2 فص ثوم، مفروم","1 ورقة غار","1/2 ملعقة صغيرة فلفل حار في رقائق (أو بيري بيري)","1 ملعقة كبيرة دقيق","ملح وفلفل وسكر حسب الذوق","بطاطس مقلية، للتقديم"],"en":["8 thick slices white bread (sandwich loaf)","400g rib-eye or sirloin steak, cut into 4 thin slices","4 linguiça or smoked sausage links, halved lengthwise","8 slices cooked ham","8 slices spicy salami or chouriço","12 slices Cheddar or Gouda, melting type","4 eggs, for topping","30g butter","oil for frying eggs","For the sauce:","400ml lager beer","200ml beef stock","200g tomato paste","60ml whisky or brandy","1 small onion, finely chopped","2 garlic cloves, minced","1 bay leaf","1/2 tsp chili flakes (or piri-piri)","1 tbsp flour","salt, pepper, sugar to taste","fries, to serve"],"ro":["8 felii groase de pâine albă (tip toast)","400g antricot sau mușchi de vită, în 4 felii subțiri","4 cârnați linguiça (sau cabanos afumat), tăiați pe lungime","8 felii de șuncă (presunto) fiartă","8 felii salami picant (chouriço)","12 felii brânză cheddar sau Gouda topit","4 ouă (pentru deasupra)","30g unt","ulei pentru prăjit ouăle","Pentru sos:","400ml bere blondă","200ml bulion de vită","200g pastă de roșii","60ml whisky sau brandy","1 ceapă mică, tocată","2 căței de usturoi, tocați","1 frunză de dafin","1/2 linguriță fulgi de chili (sau piri-piri)","1 lingură făină","sare, piper, zahăr după gust","cartofi prăjiți, pentru servit"]},"howIsMade":{"ar":"ابدأ بالصلصة: أذِب ملعقة كبيرة من الزبدة في قدر، قلّب البصل 5 دقائق، أضف الثوم وملعقة كبيرة من الدقيق، اطبخه دقيقة; أضف معجون الطماطم واطبخ دقيقتين. اسكب البيرة والويسكي، اتركهما يغليان دقيقتين لتطاير الكحول; أضف المرق وورق الغار ورقائق الفلفل ورشة ملح وسكر; اطبخه على نار هادئة 25–30 دقيقة حتى تصبح الصلصة كثيفة ولامعة; صفّها للحصول على قوام أملس. تبّل شرائح اللحم بالملح والفلفل; أذِب بقية الزبدة في مقلاة واشوِ اللحم 1,5 دقيقة لكل وجه حتى يحمر; ارفعه. في نفس المقلاة، حمّر أنصاف اللينكيسا 2–3 دقائق لكل وجه. لكل ساندويتش، حمّر شريحتي خبز في الزبدة أو الزيت من الوجهين (1 دقيقة لكل وجه); رتّب: شريحة خبز، 2 شريحة هام، 1 شريحة لحم، 2 شريحة سلامي، نصفان من اللينكيسا، ثم شريحة الخبز الثانية; اضغط برفق. ضع الساندويتشات في صينية مدهونة; غطّ كلّ واحدة بـ 3 شرائح جبن وأدخلها تحت الشواية على 220°م لمدة 3–4 دقائق حتى يذوب الجبن ويتفقع ويحمرّ في أماكن. اقلِ بيضة لكل ساندويتش في الزيت، تاركاً الصفار سائلاً. ضع كل ساندويتش في طبق عميق، ضع البيضة المقلية فوق الجبن، واسكب الصلصة الساخنة بسخاء حول الساندويتش حتى تتجمع في قاع الطبق; قدّمها فوراً مع البطاطس المقلية.","en":"Make the sauce first: heat 1 tbsp of the butter in a saucepan, sauté the onion for 5 minutes, add the garlic and 1 tbsp flour, cook for 1 minute; stir in the tomato paste and cook for 2 minutes. Pour in the beer and whisky, simmer 2 minutes to burn off the alcohol; add the beef stock, bay leaf, chili flakes, a pinch each of salt and sugar; simmer over low heat for 25–30 minutes, until the sauce is thick and glossy; strain for a smooth finish. Season the steak slices with salt and pepper; melt the remaining butter in a frying pan and sear the steak for 1.5 minutes per side, until browned; lift out. In the same pan, fry the linguiça halves for 2–3 minutes per side, until coloured. For each sandwich, toast 2 slices of bread in butter or oil on both sides (1 minute per side); layer: 1 slice bread, 2 slices ham, 1 slice steak, 2 slices salami, 2 linguiça halves, top with second slice of bread; press gently. Place the sandwiches in a greased baking dish; cover each with 3 slices of cheese and slide under a grill at 220°C for 3–4 minutes, until the cheese melts, bubbles and browns in spots. Fry 1 egg per sandwich in oil, leaving the yolk runny. Set each sandwich in a deep plate, place a fried egg on top of the cheese, and pour the hot sauce generously around the sandwich — it should pool at the base of the plate; serve immediately with fries on the side."}},{"id":109,"origin":{"ar":"بيرو","en":"Peru","ro":"Peru"},"name":{"ar":"أرز تشوفا","en":"Arroz Chaufa","ro":"Arroz Chaufa"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"latin","ingredients":{"ar":["500غ من الأرز طويل الحبة، مطبوخ ومُبرَّد (ويُفضَّل أن يكون من اليوم السابق)","300غ من صدر الدجاج أو لحم خاصرة الخنزير، مقطّعاً مكعبات بحجم 1,5 سم","3 بيضات كبيرة، مخفوقة","1 فلفل رومي أحمر، مقطّع مكعبات صغيرة","6 أعواد بصل أخضر، الأبيض مقطّع ناعماً والأخضر محفوظ جانباً","3 فصوص ثوم، مفرومة","20غ زنجبيل طازج، مفروم ناعماً","60مل صلصة الصويا","1 ملعقة كبيرة صلصة المحار","1 ملعقة كبيرة زيت سمسم محمّص","60مل زيت نباتي محايد","1 ملعقة صغيرة معجون أحي أماريو (أو 1/2 ملعقة صغيرة فلفل أحمر مطحون)","ملح وفلفل أبيض حسب الذوق"],"en":["500g long-grain rice, cooked and cooled (preferably day-old)","300g chicken breast or pork loin, cut into 1.5 cm cubes","3 large eggs, beaten","1 red bell pepper, finely diced","6 spring onions, white parts finely sliced, green parts reserved","3 garlic cloves, minced","20g fresh ginger, finely minced","60ml soy sauce","1 tbsp oyster sauce","1 tbsp toasted sesame oil","60ml neutral vegetable oil","1 tsp ají amarillo paste (or 1/2 tsp chili powder)","salt and white pepper to taste"],"ro":["500g orez cu bob lung fiert și răcit (preferabil de o zi)","300g piept de pui sau pulpă de porc, tăiat cuburi de 1,5 cm","3 ouă mari, bătute","1 ardei kapia roșu, tăiat cuburi mici","6 cepe verzi, partea albă tăiată fin, verdele păstrat","3 căței de usturoi, tocați","20g ghimbir proaspăt, tocat fin","60ml sos de soia","1 lingură sos de stridii","1 lingură ulei de susan","60ml ulei vegetal neutru","1 linguriță aji amarillo pastă (sau 1/2 linguriță pudră de chili)","sare și piper alb după gust"]},"howIsMade":{"ar":"اخفق البيض مع رشة ملح; سخّن ملعقة كبيرة من الزيت النباتي في ووك على نار متوسطة، اسكب البيض، وصنع عجة رقيقة بسرعة بالتحريك; ضعها في طبق وقطّعها مكعبات صغيرة; ضعها جانباً. مع الووك شديد السخونة، أضف ملعقة أخرى من الزيت; حرّك اللحم مع رشة ملح لمدة 3–4 دقائق حتى يحمر من الأطراف وينضج من الداخل; انقله إلى الطبق مع العجة. اسكب باقي الزيت النباتي في الووك وسخّنه حتى يبدأ بإطلاق دخان خفيف; أضف الثوم والزنجبيل والفلفل وقلّبه 30 ثانية حتى تفوح رائحته. أضف أبيض البصل الأخضر ومعجون الأحي أماريو; قلّب 30 ثانية ليتشرّب الزيت النكهات. أضف الأرز البارد; استخدم الملعقة لتفتيت الكتل، اضغط الأرز على قاع الووك بين التقليبات لمدة 3–4 دقائق حتى تنفصل الحبات وتسمع صوت قلي خفيف. اسكب صلصة الصويا وصلصة المحار فوق الأرز، وقلّب لمدة دقيقة ليتوزّع اللون والنكهة; أعد اللحم والبيض إلى الووك. أطفئ النار; أضف زيت السمسم وأخضر البصل الأخضر; تبّل بالفلفل الأبيض; قدّمه فوراً ساخناً، مباشرة من الووك.","en":"Beat the eggs with a pinch of salt; heat 1 tbsp of vegetable oil in a wok over medium heat, pour in the eggs, and quickly make a thin omelette by stirring; tip onto a plate and cut into small cubes; set aside. With the wok very hot, add another 1 tbsp oil; stir-fry the meat with a pinch of salt for 3–4 minutes, until browned at the edges and cooked through; move to the plate with the eggs. Pour the remaining vegetable oil into the wok and heat until it just begins to smoke; add the garlic, ginger, and bell pepper, and stir-fry for 30 seconds, until fragrant. Add the white parts of the spring onions and the ají amarillo paste; stir-fry for 30 seconds, letting the flavours infuse the oil. Add the cold rice; use a spatula to break it into small pieces, pressing it against the bottom of the wok between tosses for 3–4 minutes, until every grain is separate and you hear a slight sizzle. Pour the soy sauce and oyster sauce over the rice, tossing for 1 minute to distribute evenly and pick up colour; return the meat and egg to the wok. Turn off the heat; drizzle with the sesame oil and add the green parts of the spring onions; season with white pepper; serve immediately, hot, straight from the wok."}},{"id":110,"origin":{"ar":"سنغافورة","en":"Singapore","ro":"Singapore"},"name":{"ar":"سلطعون الفلفل الحار","en":"Chili Crab","ro":"Chili Crab"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"fish","pairingsType":"fish","ingredients":{"ar":["2 سلطعون طين حي (1,5كغ مجتمعة)، منظف ومقطّع نصفين عند المفاصل","4 ملاعق كبيرة معجون طماطم","3 ملاعق كبيرة سامبال أوليك (أو معجون فلفل حار)","2 ملعقة كبيرة صلصة فلفل حار حلوة","60مل كاتشب","30غ زنجبيل طازج، مبشور","6 فصوص ثوم، مفرومة","2 بيضة كبيرة، مخفوقة","3 أعواد بصل أخضر، مفرومة","1 ملعقة كبيرة خل أرز","2 ملعقة صغيرة سكر","1 ملعقة صغيرة ملح","500مل مرق دجاج (أو ماء)","60مل زيت نباتي","1 ملعقة كبيرة نشاء ذرة ممزوج بـ2 ملعقة كبيرة ماء","مانتو مقلي (خبيز صيني)، للتقديم"],"en":["2 live mud crabs (1.5kg total), cleaned and halved at the joints","4 tbsp tomato paste","3 tbsp sambal oelek (or chili paste)","2 tbsp sweet chili sauce","60ml ketchup","30g fresh ginger, grated","6 garlic cloves, minced","2 large eggs, beaten","3 spring onions, chopped","1 tbsp rice vinegar","2 tsp sugar","1 tsp salt","500ml chicken stock (or water)","60ml vegetable oil","1 tbsp cornstarch mixed with 2 tbsp water","fried mantou (Chinese buns), to serve"],"ro":["2 crabi de noroi vii (1,5kg în total), curățați și tăiați în jumătăți la articulații","4 linguri pastă de roșii","3 linguri sos sambal oelek (sau pastă de chili)","2 linguri sos dulce de chili","60ml ketchup","30g ghimbir proaspăt, ras","6 căței de usturoi, tocați","2 ouă mari, bătute","3 cepe verzi, tocate","1 lingură oțet de orez","2 lingurițe zahăr","1 linguriță sare","500ml supă de pui (sau apă)","60ml ulei vegetal","1 lingură amidon de porumb amestecat cu 2 linguri apă","mantou prăjit (chifle chinezești), pentru servit"]},"howIsMade":{"ar":"ضع السلطعون في المجمّد لمدة 30 دقيقة لتخديره برفق; نظّفه وارفع الصدفة العليا واستخرج الأعضاء الداخلية الطرية، ثم قسّمه نصفين عند المفاصل; اكسر الكلاّبات بظهر السكين ليتسرّب النكهة. اخفق البيض في وعاء صغير; في وعاء آخر، اخلط معجون الطماطم والسامبال وصلصة الفلفل الحار الحلوة والكاتشب والخل والسكر والملح — هذه قاعدة الصلصة. سخّن 60مل من الزيت في ووك كبير أو قدر عميق على نار قوية; أضف قطع السلطعون وقلّب 3–4 دقائق حتى تتحوّل الصدفة إلى الأحمر; ارفعها إلى طبق. في نفس الزيت، قلّب الزنجبيل المبشور والثوم 30 ثانية حتى تفوح رائحتهما بقوة. اسكب خليط الطماطم و500مل من مرق الدجاج; أوصله إلى الغليان وعدّل الحدة بإضافة المزيد من السامبال. أعد قطع السلطعون وغطّ الووك واطبخ 8–10 دقائق مع تقليبه مرة واحدة في المنتصف، حتى ينضج اللحم تماماً ويصبح طريّاً. أضف خليط النشاء بالماء في خيط رفيع وقلّب لتثخّن الصلصة وتصبح لامعة; اسكب البيض المخفوق بشكل حلزوني دون تحريك — سيتجمّد على هيئة شرائط حريرية; انتظر 30 ثانية ثم اطوِ مرة واحدة. رشّ البصل الأخضر المفروم; قدّمه فوراً في طبق كبير مع المانتو المقلي جانباً لامتصاص الصلصة.","en":"Place the crabs in the freezer for 30 minutes to humanely stun them; clean them, lift off the top shell, remove the soft inner organs, and chop the crab in half at the joints; crack the claws with the back of a knife so the flavour penetrates. Beat the eggs in a small bowl; in another bowl, stir together the tomato paste, sambal, sweet chili sauce, ketchup, vinegar, sugar and salt — this is the sauce base. Heat 60ml of oil in a large wok or deep pot over high heat; add the crab pieces and stir-fry for 3–4 minutes, turning, until the shells turn red; lift onto a plate. In the same oil, sauté the grated ginger and garlic for 30 seconds, until very fragrant. Pour in the tomato-paste mixture and 500ml chicken stock; bring to a boil, adjust with more sambal for more heat. Return the crab pieces, cover the wok and simmer for 8–10 minutes, turning once halfway, until the meat is fully cooked and tender. Stir the cornstarch slurry into the sauce in a thin stream so the sauce thickens to a glossy coat; pour the beaten eggs around the wok in a spiral without stirring — they will set as silky ribbons; wait 30 seconds, then fold once. Scatter with the chopped spring onions; serve immediately on a large platter with fried mantou alongside to soak up the sauce."}},{"id":111,"origin":{"ar":"المكسيك","en":"Mexico","ro":"Mexic"},"name":{"ar":"تامالي","en":"Tamale","ro":"Tamale"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"mexican","ingredients":{"ar":["20–24 ورقة ذرة جافة","500غ مَسا هارينا (دقيق ذرة منيكستمالي)","250غ شحم خنزير بدرجة حرارة الغرفة","500مل مرق دجاج دافئ","1 ملعقة كبيرة بيكنغ باودر","2 ملعقة صغيرة ملح","للحشوة:","500غ كتف خنزير منزوع العظم، مسلوق ومُمَزَّع","4 فلفل غواخيلو يابس، منزوع السيقان والبذور","2 فلفل أنشو يابس، منزوع السيقان والبذور","1 بصلة صغيرة، أرباعاً","3 فصوص ثوم","1 ملعقة صغيرة كمون مطحون","1 ملعقة صغيرة زعتر مكسيكي","2 ملعقة كبيرة زيت نباتي","ملح حسب الذوق","صلصة حمراء أو خضراء، للتقديم"],"en":["20–24 dried corn husks","500g masa harina (nixtamalized corn flour)","250g pork lard, at room temperature","500ml warm chicken stock","1 tbsp baking powder","2 tsp salt","For the filling:","500g boneless pork shoulder, simmered and shredded","4 dried guajillo chilies, stems and seeds removed","2 dried ancho chilies, stems and seeds removed","1 small onion, quartered","3 garlic cloves","1 tsp ground cumin","1 tsp Mexican oregano","2 tbsp vegetable oil","salt to taste","red or green salsa, to serve"],"ro":["20–24 foi de porumb uscate (chiote)","500g masa harina (făină de porumb nixtamalizată)","250g untură de porc, la temperatura camerei","500ml supă de pui caldă","1 lingură praf de copt","2 lingurițe sare","Pentru umplutură:","500g pulpă de porc dezosată, fiartă și mărunțită","4 ardei iuți guajillo uscați, fără semințe","2 ardei iuți ancho uscați, fără semințe","1 ceapă mică, tăiată sferturi","3 căței de usturoi","1 linguriță chimion măcinat","1 linguriță oregano mexican","2 linguri ulei vegetal","sare după gust","salsă roșie sau verde, pentru servit"]},"howIsMade":{"ar":"انقع أوراق الذرة في ماء دافئ لمدة 30 دقيقة حتى تصبح طيّعة; ضع طبقاً فوقها لتبقى مغمورة. حضّر الصلصة: حمّر فلفل غواخيلو وأنشو في مقلاة جافة دقيقة لكل وجه حتى تفوح روائحه; غطّه بماء ساخن 15 دقيقة; اخلط الفلفل المنقوع مع البصل والثوم والكمون والزعتر و250مل من ماء النقع; صفِّ الصلصة. سخّن 2 ملعقة كبيرة من الزيت في مقلاة، اسكب صلصة الفلفل واطبخها 8–10 دقائق حتى تتكاثف; أضف لحم الخنزير المُمزَّع، تبّله بالملح، واطبخه 5 دقائق إضافية; اتركه يبرد. اخفق الشحم بالخلاط 3 دقائق حتى يصبح رقيقاً وفاتح اللون; أضف البيكنغ باودر والملح وحرّك 30 ثانية أخرى. أضف الماسا هارينا بالتناوب مع المرق الدافئ مع الخفق المستمر; يجب أن يكون العجين خفيفاً ورقيقاً ويلتصق بالملعقة; اختبره برمي كرة صغيرة في ماء بارد — يجب أن تطفو. صفِّ أوراق الذرة; لكل تامالي، افرد 3 ملاعق كبيرة من العجين بطبقة رقيقة على ورقة مع ترك 2 سم على الجوانب و5 سم في الأعلى; ضع 2 ملعقة كبيرة من الحشوة في المنتصف. اطوِ جوانب الورقة فوق الحشوة، ثم اطوِ الطرف الضيق إلى الأعلى تاركاً الأعلى مفتوحاً; اصفّ التامالي عمودياً في سلة بخار مع توجيه الفتحة لأعلى. اطبخها على البخار 60–75 دقيقة حتى يتقشّر العجين بنظافة عن الورقة عند فتح إحداها; اتركها ترتاح 10 دقائق قبل التقديم; قدّمها دافئة مع الصلصة الحمراء أو الخضراء.","en":"Soak the corn husks in warm water for 30 minutes, until pliable; weight them down with a plate so they stay submerged. Make the sauce: toast the guajillo and ancho chilies in a dry pan for 1 minute per side, until fragrant; cover with hot water for 15 minutes; blend the rehydrated chilies with the onion, garlic, cumin, oregano and 250ml of the soaking liquid; strain the sauce. Heat 2 tbsp oil in a pan, pour in the chili sauce and simmer for 8–10 minutes, until thickened; add the shredded pork, season with salt and cook another 5 minutes; let it cool. Beat the lard with a mixer for 3 minutes, until fluffy and pale; add the baking powder and salt, mix 30 seconds more. Add the masa harina alternately with warm chicken stock, beating continuously; the dough should be light, fluffy, and cling to the spatula; test by dropping a small ball into cold water — it should float. Drain the corn husks; for each tamale, spread 3 tbsp of dough in a thin layer on a husk, leaving a 2 cm border on the sides and 5 cm at the top; place 2 tbsp filling down the centre. Fold the sides of the husk over the filling, then fold the narrow end up, leaving the top open; stand the tamales vertically in a steamer basket, open ends up. Steam for 60–75 minutes, until the dough peels cleanly away from the husk when you open one; let them rest 10 minutes before serving; serve warm with red or green salsa alongside."}},{"id":112,"origin":{"ar":"تايلاند","en":"Thailand","ro":"Thailanda"},"name":{"ar":"توم يام","en":"Tom Yum","ro":"Tom Yum"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"thai","ingredients":{"ar":["1 لتر مرق دجاج أو مأكولات بحرية","300غ جمبري نيء مقشور","2 ساق لمونغراس مقطوعة 3سم ومسحوقة","30غ غالانغال (أو زنجبيل) شرائح رقيقة","6 أوراق كافير لايم","3–4 فلفل حار أحمر تايلاندي منصف","200غ فطر محار أو فطر مقطع","3 ملاعق كبيرة صلصة سمك","2 ملعقة كبيرة عصير ليمون أخضر طازج","1 ملعقة كبيرة سكر نخيل","2 ملعقة كبيرة معجون توم يام (اختياري)","بصل أخضر للتزيين","كزبرة طازجة للتقديم"],"en":["1L chicken or seafood stock","300g raw prawns, peeled and deveined","2 stalks lemongrass, cut into 3cm pieces and bruised","30g galangal (or ginger), thinly sliced","6 kaffir lime leaves","3–4 Thai red chillies, halved","200g oyster or button mushrooms, sliced","3 tbsp fish sauce","2 tbsp fresh lime juice","1 tbsp palm sugar","2 tbsp tom yum paste (optional)","1 spring onion stalk, to garnish","Fresh coriander to serve"],"ro":["1 L supă de pui sau stoc de fructe de mare","300g creveți cruzi, curățați","2 tulpini lemongrass, secționate în bucăți de 3 cm și zdrobite","30g galangal (sau ghimbir), felii subțiri","6 frunze de kaffir lime","3–4 ardei iuți roșii thailandezi, tăiați pe jumătate","200g ciuperci pleurotus sau champignon, feliate","3 linguri sos de pește","2 linguri suc proaspăt de lime","1 lingură zahăr de palmier","2 linguri pastă tom yum (opțional)","1 tulpină ceapă verde, pentru servire","Coriandru proaspăt, pentru servire"]},"howIsMade":{"ar":"أحضر 1 لتر من المرق إلى الغليان الخفيف في قدر كبير. أضف سيقان اللمونغراس المسحوقة وشرائح الغالانغال وأوراق الكافير لايم; اطبخ على نار هادئة 10 دقائق ليتشرّب المرق العطر. أضف معجون التوم يام (إن استخدمت)، والفلفل المشقوق نصفين والفطر المقطع; اطبخ 3–4 دقائق حتى يلين الفطر قليلاً. أضف الجمبري واطبخه بالضبط 2–3 دقائق — يصبح وردياً ويلتف; لا تطبخه أكثر وإلا يصبح مطاطياً. ارفع القدر عن النار; أضف 3 ملاعق كبيرة من صلصة السمك، 2 ملعقة كبيرة من عصير الليمون الأخضر الطازج و1 ملعقة كبيرة من سكر النخيل. تذوّق واضبط التوازن: الحساء يجب أن يكون حامضاً ومالحاً وحاراً وحلواً قليلاً في آن واحد; أضف مزيداً من الليمون للحموضة أو صلصة السمك للملوحة. قدّمه فوراً في أطباق عميقة ورشّ بصلاً أخضر وكزبرة طازجة; اللمونغراس والغالانغال وأوراق الليمون مكوّنات عطرية ولا تُؤكل.","en":"Bring 1L of stock to a gentle simmer in a large pot. Add the bruised lemongrass stalks, sliced galangal, and kaffir lime leaves; simmer for 10 minutes to infuse the aromatics and turn the broth deeply fragrant. Stir in the tom yum paste (if using), halved chillies, and sliced mushrooms; cook for 3–4 minutes, until the mushrooms soften slightly. Add the prawns and cook for exactly 2–3 minutes — they should turn pink and curl; do not overcook or they will become rubbery. Take the pot off the heat; stir in 3 tbsp fish sauce, 2 tbsp fresh lime juice, and 1 tbsp palm sugar. Taste and adjust the balance: the soup should be sour, salty, spicy, and lightly sweet all at once; add more lime for sharpness or more fish sauce for salt. Serve immediately in deep bowls, scattered with spring onion and fresh coriander; the lemongrass, galangal, and lime leaves are aromatics and are not meant to be eaten."}},{"id":113,"origin":{"ar":"الأرجنتين","en":"Argentina","ro":"Argentina"},"name":{"ar":"ميلانيسا","en":"Milanesa","ro":"Milanesa"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"latin","ingredients":{"ar":["4 شرائح رقيقة من اللحم البقري (فخذ علوي أو سيرلوين)، نحو 150غ لكل شريحة","2 بيضة كبيرة","2 فص ثوم، مفروم ناعماً","20غ بقدونس طازج، مفروم","150غ بقسماط جاف (يمكن استخدام بانكو لقشرة أخفّ)","100غ دقيق سادة","1 ملعقة صغيرة ملح","1/2 ملعقة صغيرة فلفل أسود مطحون طازجاً","500مل زيت نباتي للقلي","1 ليمونة، مقطعة شرائح، للتقديم"],"en":["4 thin beef steaks (top round or sirloin), about 150g each","2 large eggs","2 garlic cloves, finely minced","20g fresh parsley, finely chopped","150g dried breadcrumbs (panko works for a lighter crust)","100g plain flour","1 tsp salt","1/2 tsp freshly ground black pepper","500ml vegetable oil, for frying","1 lemon, cut into wedges, to serve"],"ro":["4 felii subțiri de vită (vrăbioară sau pulpă), aproximativ 150g fiecare","2 ouă mari","2 căței de usturoi, tocați fin","20g pătrunjel proaspăt, tocat","150g pesmet uscat (eventual panko pentru o crustă mai aerată)","100g făină simplă","1 linguriță sare","1/2 linguriță piper negru proaspăt măcinat","500ml ulei vegetal, pentru prăjit","1 lămâie, tăiată felii, pentru servit"]},"howIsMade":{"ar":"ضع شرائح اللحم بين ورقتي نايلون مطبخ; اضربها بمطرقة اللحم حتى تصبح بسماكة 5 ملم; تبّلها بنصف الملح والفلفل من الجانبين. اخفق البيض في طبق عميق مع الثوم المفروم والبقدونس وبقية الملح والفلفل. حضّر طبقين مسطحين: واحد للدقيق وآخر للبقسماط; خط التغليف: دقيق → بيض مخفوق → بقسماط. مرّر كل شريحة بالدقيق وانفض الزائد، ثم في خليط البيض (دعها تنزّل 2 ثانية)، ثم اضغطها في البقسماط من الوجهين; يجب أن يغطّي البقسماط اللحم بالكامل. اترك الشرائح المغلفة ترتاح على شبكة 10 دقائق — التغليف يلتصق بشكل أفضل هكذا. سخّن 1 سم من الزيت في مقلاة كبيرة إلى 175°م (بميزان حرارة أو باختبار مكعب خبز — يجب أن يحمرّ خلال 30 ثانية). اقلِ الشرائح واحدة أو اثنتين في المرة، دقيقتين لكل وجه، حتى تصبح القشرة ذهبية داكنة واللحم طرياً; صفّها على شبكة فوق صينية (لا على الورق — يجعل القشرة طرية). قدّمها فوراً مع شرائح ليمون لعصرها فوق القشرة قبيل العض.","en":"Place the beef slices between two sheets of cling film; pound with a meat mallet until 5 mm thick; season with half the salt and pepper on both sides. Beat the eggs in a wide shallow bowl with the minced garlic, parsley, and the remaining salt and pepper. Set up two shallow plates: one with the flour, one with the breadcrumbs; breading line: flour → beaten egg → breadcrumbs. Dip each slice in flour, shaking off the excess, then in the egg mixture (let it drip for 2 seconds), then press into the breadcrumbs on both sides; the crumbs should fully coat the meat. Let the breaded slices rest on a wire rack for 10 minutes — the breading adheres better this way. Heat 1 cm of oil in a large frying pan to 175°C (use a thermometer or test with a bread cube — it should brown in 30 seconds). Fry the slices one or two at a time for 2 minutes per side, until the crust is deep golden and the meat is tender; drain on a rack over a tray (not on paper — it steams the crust). Serve immediately with lemon wedges to squeeze over the crust just before eating."}},{"id":114,"origin":{"ar":"كمبوديا","en":"Cambodia","ro":"Cambodgia"},"name":{"ar":"لوك لاك","en":"Lok Lak","ro":"Lok Lak"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","pairingsType":"vietnamese","ingredients":{"ar":["600غ من فيلية البقر أو السيرلوين، مقطّعة مكعبات 2,5 سم","3 ملاعق كبيرة صلصة محار","2 ملعقة كبيرة صلصة صويا","1 ملعقة كبيرة سكر نخيل (أو سكر بني)","1 ملعقة كبيرة معجون طماطم","6 فصوص ثوم، مفرومة","2 ملعقة صغيرة فلفل أسود مطحون طازجاً (بكثرة)","3 ملاعق كبيرة زيت نباتي","1 بصلة كبيرة، مقطعة شرائح رفيعة","4 بيضات (للقلي)","1 رأس خس صغير (آيسبرغ أو رومانو)، أوراق منفصلة","2 طماطم، شرائح","1 خيار، شرائح","لصلصة الغمس:","عصير ليمونتين خضراويتين","1 ملعقة صغيرة ملح خشن","1/2 ملعقة صغيرة فلفل أسود مطحون طازجاً","أرز مطهو بالبخار، للتقديم"],"en":["600g beef tenderloin or sirloin, cut into 2.5 cm cubes","3 tbsp oyster sauce","2 tbsp soy sauce","1 tbsp palm sugar (or brown sugar)","1 tbsp tomato paste","6 garlic cloves, minced","2 tsp freshly ground black pepper (generous)","3 tbsp vegetable oil","1 large onion, thinly sliced","4 eggs (for frying)","1 small head of lettuce (iceberg or romaine), leaves separated","2 tomatoes, sliced","1 cucumber, sliced","For the dipping sauce:","juice of 2 limes","1 tsp coarse salt","1/2 tsp freshly ground black pepper","steamed rice, to serve"],"ro":["600g vrăbioară sau mușchi de vită, tăiată cuburi de 2,5 cm","3 linguri sos de stridii","2 linguri sos de soia","1 lingură zahăr de palmier (sau zahăr brun)","1 lingură pastă de roșii","6 căței de usturoi, tocați","2 lingurițe piper negru proaspăt măcinat (din belșug)","3 linguri ulei vegetal","1 ceapă mare, tăiată felii subțiri","4 ouă (pentru ochiuri)","1 cap mic de salată verde (iceberg sau romană), frunzele separate","2 roșii, feliate","1 castravete, feliat","Pentru sos:","zeama de la 2 lime","1 linguriță sare grunjoasă","1/2 linguriță piper negru proaspăt măcinat","orez fiert, pentru servit"]},"howIsMade":{"ar":"في وعاء، اخلط اللحم مع صلصة المحار وصلصة الصويا وسكر النخيل ومعجون الطماطم ونصف الثوم و1 ملعقة صغيرة فلفل أسود; اتركه يتبَّل بدرجة حرارة الغرفة 30 دقيقة. حضّر صلصة الغمس: اخلط عصير الليمون والملح الخشن والفلفل المتبقي في وعاء صغير. جهّز طبق التقديم: أوراق الخس وشرائح الطماطم والخيار على طبق كبير. اقلِ 4 بيضات في مقلاة بقليل من الزيت مع إبقاء الصفار سائلاً; ضعها على طبق دافئ. سخّن 3 ملاعق كبيرة من الزيت في ووك كبير على نار شديدة جداً حتى يبدأ بإطلاق الدخان. أضف البصل وبقية الثوم وحرّكهما 30 ثانية حتى تفوح رائحتهما. أضف اللحم المتبّل في طبقة واحدة; اتركه دون تحريك دقيقة لينضج من جهة، ثم قلّبه بقوة 2 دقيقة إضافية; يجب أن يكون اللحم محمَّراً من الخارج وردياً من الداخل — لا تطبخه أكثر. ضع اللحم الساخن فوق طبق السلطة، وضع بيضة مقلية على كل حصة; قدّم فوراً مع صلصة الليمون جانباً وأرز مطهو بالبخار لكل ضيف.","en":"In a bowl, combine the beef with oyster sauce, soy sauce, palm sugar, tomato paste, half the garlic, and 1 tsp black pepper; let it marinate at room temperature for 30 minutes. Make the dipping sauce: stir lime juice, coarse salt, and the remaining pepper in a small bowl; set aside. Arrange the serving platter: lettuce leaves, tomato slices, and cucumber slices laid out on a large platter. Fry 4 eggs in a pan with a little oil, leaving the yolks runny; set them aside on a warm plate. Heat 3 tbsp oil in a large wok over very high heat until it just begins to smoke. Add the sliced onion and remaining garlic, stir-fry for 30 seconds, until fragrant. Add the marinated beef in a single layer; leave it untouched for 1 minute to sear, then stir-fry vigorously for 2 more minutes; the beef should be charred outside and pink inside — do not overcook. Spoon the hot beef over the salad platter, place a fried egg on each portion; serve immediately with the lime dipping sauce alongside and steamed rice for each diner."}},{"id":115,"origin":{"ar":"أوزبكستان","en":"Uzbekistan","ro":"Uzbekistan"},"name":{"ar":"مانتي","en":"Manti","ro":"Manti"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ar":["للعجينة:","500غ دقيق متعدد الاستخدامات","250مل ماء دافئ","1 بيضة","1 ملعقة صغيرة ملح","للحشوة:","600غ لحم بقري أو ضأن مفروم بالسكين (لا بالمفرمة)","3 بصلات كبيرة، مفرومة ناعماً (نسبة 1:1 بصل ولحم بالحجم — أمر ضروري)","1 ملعقة صغيرة كمون مطحون","1 ملعقة صغيرة فلفل أسود مطحون طازجاً","2 ملعقة صغيرة ملح","100غ من دهن ذيل الخروف أو لارد مقطّع مكعبات صغيرة جداً (اختياري، تقليدي)","للتقديم:","100غ زبدة","200غ لبن كامل الدسم (أو كريمة حامضة)","1 ملعقة كبيرة بابريكا حلوة","أوراق كزبرة أو بقدونس طازجة، مفرومة"],"en":["For the dough:","500g all-purpose flour","250ml warm water","1 egg","1 tsp salt","For the filling:","600g coarsely chopped beef or lamb (knife-cut, not ground)","3 large onions, finely chopped (use a 1:1 onion-to-meat ratio by volume — essential)","1 tsp ground cumin","1 tsp freshly ground black pepper","2 tsp salt","100g lamb-tail fat or pork lardons in tiny cubes (optional, traditional)","To serve:","100g butter","200g full-fat yogurt (or sour cream)","1 tbsp sweet paprika","fresh coriander or parsley leaves, chopped"],"ro":["Pentru aluat:","500g făină","250ml apă caldă","1 ou","1 linguriță sare","Pentru umplutură:","600g carne tocată grosier de vită sau miel","3 cepe mari, tăiate fin (foarte importantă proporția 1:1 cu carnea după volum)","1 linguriță chimion măcinat","1 linguriță piper negru proaspăt măcinat","2 lingurițe sare","100g grăsime de coadă de oaie sau slănină tăiată cuburi mici (opțional, dar tradițional)","Pentru servit:","100g unt","200g iaurt gras (sau smântână)","1 lingură boia dulce","frunze de coriandru sau pătrunjel proaspăt, tocate"]},"howIsMade":{"ar":"حضّر العجينة: في وعاء كبير، اخلط الدقيق مع الملح; اخفق البيض مع الماء الدافئ واسكبه فوق الدقيق; اعجن 10 دقائق حتى تصبح ناعمة ومرنة; غطّها بنايلون مطبخ ودعها ترتاح 30 دقيقة. حضّر الحشوة: اخلط اللحم المفروم بالسكين مع البصل والكمون والملح والفلفل ودهن الخروف (إن استخدمت); اخلطه باليد حتى يتجانس; سيُفرز البصل سائلاً — احتفظ به في الحشوة. قسّم العجينة إلى 4 قطع; افرد كل قطعة رقيقة قدر الإمكان (1–2 ملم); قطّعها مربعات 10x10 سم. ضع ملعقة كبيرة وافرة من الحشوة في وسط كل مربع; ارفع زوايا العجينة الأربع فوق الحشوة وأمسكها سويةً في الأعلى، ثم اضغط الحواف الجانبية الأربع لتشكيل كيس محكم. ادهن سلة البخار بالزيت; ضع المانتي في طبقة واحدة بدون أن تتلامس (ستكبر في الحجم). اطبخها على البخار 35–40 دقيقة على نار متوسطة مع غليان الماء باستمرار; تصبح العجينة شبه شفافة ولامعة قليلاً. أذِب الزبدة في قدر صغير، أضف البابريكا الحلوة وقلّبها; اتركها ترتاح دقيقة بعيداً عن النار. رتّب المانتي على طبق كبير، رشّ البقدونس فوقها واسكب زبدة البابريكا; قدّمها مع اللبن في وعاء صغير جانباً.","en":"Make the dough: in a large bowl, combine the flour with salt; beat the egg with warm water and pour over the flour; knead for 10 minutes until smooth and elastic; cover with cling film and rest for 30 minutes. Make the filling: combine the knife-cut meat, onions, cumin, salt, pepper, and lamb-tail fat (if using); mix by hand until uniform; the onions will release liquid — keep it in. Divide the dough into 4 pieces; roll each as thin as possible (1–2 mm); cut into 10x10 cm squares. Place a generous tablespoon of filling in the centre of each square; lift the four corners of the dough up over the filling and pinch them together at the top, then pinch the four side edges closed to form a sealed parcel. Brush a steamer basket with oil; arrange the manti in a single layer, not touching (they will swell as they cook). Steam for 35–40 minutes over medium heat with the water at a steady boil; the dough should become translucent and slightly glossy when done. Melt the butter in a small saucepan, stir in the sweet paprika; let it rest 1 minute off the heat. Arrange the manti on a large platter, scatter with chopped parsley, and spoon the paprika butter over the top; serve with yogurt in a small bowl alongside."}},{"id":116,"origin":{"ar":"جورجيا","en":"Georgia","ro":"Georgia"},"name":{"ar":"تشاخوخبيلي","en":"Chakhokhbili","ro":"Chakhokhbili"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ar":["1,2كغ من فخذ وساق الدجاج بالعظم","4 بصلات كبيرة (نحو 600غ)، شرائح رفيعة — النسبة التقليدية 1:1 بصل ودجاج بالوزن","6 حبات طماطم ناضجة (نحو 700غ)، مقشّرة ومقطعة خشناً","1 فلفل رومي أحمر، منزوع البذور ومقطع مكعبات","6 فصوص ثوم، مفرومة","2 ملعقة كبيرة معجون طماطم","1 ملعقة صغيرة خميلي-سونيلي (خلطة بهارات جورجية)","1/2 ملعقة صغيرة حلبة زرقاء مطحونة (أوتسخو-سونيلي)","1 ملعقة صغيرة سبر يابس أو بردقوش","30غ كزبرة طازجة، أوراق وسيقان منفصلة، كلاهما مفروم","20غ بقدونس طازج، مفروم","1 ملعقة صغيرة ملح","فلفل أسود مطحون طازجاً","1 ملعقة كبيرة خل نبيذ أبيض (اختياري، للإنعاش)","خبز جورجي أو خبز ريفي، للتقديم"],"en":["1.2kg bone-in chicken thighs and drumsticks","4 large onions (about 600g), thinly sliced — a 1:1 onion-to-chicken ratio by weight is traditional","6 ripe tomatoes (about 700g), peeled and roughly chopped","1 red bell pepper, deseeded and diced","6 garlic cloves, minced","2 tbsp tomato paste","1 tsp khmeli-suneli (Georgian spice blend)","1/2 tsp ground blue fenugreek (utskho suneli)","1 tsp dried savory or marjoram","30g fresh coriander, leaves and stems separated, both chopped","20g fresh parsley, chopped","1 tsp salt","freshly ground black pepper","1 tbsp white wine vinegar (optional, for brightness)","Georgian flatbread or any sturdy bread, to serve"],"ro":["1,2kg pulpe de pui cu os (pulpe superioare și ciocănele)","4 cepe mari (aproximativ 600g), feliate subțire — raportul 1:1 ceapă:pui după greutate este tradițional","6 roșii coapte (aproximativ 700g), decojite și tăiate grosier","1 ardei kapia roșu, fără semințe, tăiat cuburi","6 căței de usturoi, tocați","2 linguri pastă de roșii","1 linguriță khmeli-suneli (amestec de condimente georgian)","1/2 linguriță schinduf albastru măcinat (utskho suneli)","1 linguriță cimbru de iarnă uscat (sau maghiran)","30g coriandru proaspăt, frunze și tulpini separate, ambele tocate","20g pătrunjel proaspăt, tocat","1 linguriță sare","piper negru proaspăt măcinat","1 lingură oțet de vin alb (opțional, pentru prospețime)","pâine georgiană sau alt tip de pâine rustică, pentru servit"]},"howIsMade":{"ar":"سخّن قدراً ثقيلاً جافاً على نار متوسطة-عالية بدون زيت; ضع قطع الدجاج بالجلد إلى الأسفل واطبخها 6–8 دقائق لكل وجه حتى تصبح ذهبية عميقة; يطلق الدجاج دهنه الخاص — هذه هي خطوة التحمير الجاف التي تميّز التشاخوخبيلي. ارفع الدجاج إلى طبق; يجب أن يبقى 3–4 ملاعق كبيرة من الدهن في القدر — احتفظ به. أضف شرائح البصل إلى الدهن; اطبخها على نار متوسطة 12–15 دقيقة مع التحريك المتكرر حتى تصبح ذهبية عميقة وطرية. أضف الفلفل الرومي ونصف الثوم وسيقان الكزبرة المفرومة والخميلي-سونيلي والحلبة الزرقاء والسبر; اطبخها دقيقتين حتى تفوح روائحها. أضف معجون الطماطم واطبخه دقيقتين إضافيتين حتى يتعمّق لونه; أضف الطماطم المفرومة وأعد الدجاج بعصيره إلى القدر. خفّض النار وغطّ القدر واطبخ ببطء 35–45 دقيقة، مع تقليب الدجاج مرة في المنتصف; يجب أن يكاد ينفصل اللحم عن العظم وتتفتت الطماطم في صلصة كثيفة لامعة. ارفع الغطاء واطبخ 5 دقائق أخرى مكشوفاً إذا احتاجت الصلصة للتكثيف; أضف الثوم المتبقي والخل (إن استخدمت) ومعظم أوراق الكزبرة والبقدونس المفرومة. تذوّق واضبط الملح والفلفل; قدّمها ساخنة في أوعية ضحلة مع الخبز الجورجي (أو أي خبز ريفي) لمسح الصلصة; رشّ بقية الأعشاب فوقها.","en":"Heat a heavy dry pot over medium-high heat — no oil; lay the chicken pieces skin-side down and cook for 6–8 minutes per side, until deeply golden; the chicken renders its own fat — this is the dry-brown step that defines chakhokhbili. Lift the chicken onto a plate; the pot should hold 3–4 tbsp of rendered fat — keep it. Add the sliced onions to the rendered fat; cook over medium heat for 12–15 minutes, stirring often, until deeply golden and soft. Stir in the bell pepper, half the garlic, the chopped coriander stems, khmeli-suneli, blue fenugreek, and savory; cook 2 minutes, until fragrant. Add the tomato paste and cook 2 more minutes, until it darkens; add the chopped tomatoes and return the chicken with its juices to the pot. Reduce the heat to low, cover, and braise for 35–45 minutes, turning the chicken once halfway; the chicken should be falling off the bone and the tomatoes broken down into a thick, glossy sauce. Lift the lid and simmer uncovered 5 more minutes to thicken the sauce if needed; stir in the remaining garlic, the vinegar (if using), and most of the chopped coriander leaves and parsley. Taste, adjust salt and pepper; serve hot in shallow bowls with Georgian flatbread (or any sturdy bread) to mop up the sauce; scatter the remaining herbs on top."}},{"id":117,"origin":{"ar":"بيرو","en":"Peru","ro":"Peru"},"name":{"ar":"لومو سالتادو","en":"Lomo Saltado","ro":"Lomo Saltado"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"latin","ingredients":{"ar":["600غ من سيرلوين أو فيليه البقر، مقطّع شرائح بسماكة 1 سم","3 حبات بطاطس كبيرة (نحو 700غ)، مقطّعة بطاطس مقلية سميكة","1 بصلة حمراء كبيرة، مقطّعة شرائح هلالية بسماكة 1 سم","2 حبة طماطم روما متوسطة، مقطّعة شرائح هلالية (أو شرائح سميكة)","1 فلفل آحي أماريّو أصفر (أو 1 فلفل رومي أحمر + 1 ملعقة صغيرة معجون آحي أماريّو)","4 فصوص ثوم، مفرومة","2 ملعقة كبيرة زنجبيل طازج، مبشور","3 ملاعق كبيرة صلصة صويا","2 ملعقة كبيرة خل نبيذ أحمر","30غ كزبرة طازجة، مفرومة خشناً","3 ملاعق كبيرة زيت نباتي (و500مل للقلي)","1 ملعقة صغيرة ملح","1/2 ملعقة صغيرة فلفل أسود مطحون طازجاً","400غ أرز بسمتي أبيض، مطبوخ","1 ليمونة خضراء، مقطّعة شرائح (اختياري)"],"en":["600g beef sirloin or tenderloin, cut into 1 cm strips","3 large potatoes (about 700g), cut into thick fries","1 large red onion, cut into 1 cm-thick wedges","2 medium Roma tomatoes, cut into wedges (or thick slices)","1 yellow ají amarillo pepper (or 1 red bell pepper + 1 tsp ají amarillo paste)","4 garlic cloves, minced","2 tbsp fresh ginger, grated","3 tbsp soy sauce","2 tbsp red wine vinegar","30g fresh coriander, roughly chopped","3 tbsp vegetable oil (plus 500ml for frying potatoes)","1 tsp salt","1/2 tsp freshly ground black pepper","400g white basmati rice, cooked","1 lime, cut into wedges (optional)"],"ro":["600g vrăbioară sau mușchi de vită, tăiată fâșii de 1 cm grosime","3 cartofi mari (aproximativ 700g), tăiați cartofi prăjiți groși","1 ceapă roșie mare, feliată în pene groase de 1 cm","2 roșii Roma medii, tăiate sferturi (sau felii groase)","1 ardei aji amarillo galben (sau 1 ardei kapia + 1 linguriță pastă aji amarillo)","4 căței de usturoi, tocați","2 linguri ghimbir proaspăt, ras","3 linguri sos de soia","2 linguri oțet de vin roșu","30g coriandru proaspăt, tocat grosier","3 linguri ulei vegetal (plus 500ml pentru cartofi)","1 linguriță sare","1/2 linguriță piper negru proaspăt măcinat","400g orez basmati alb, gătit","1 lime, tăiat felii (opțional)"]},"howIsMade":{"ar":"تبّل شرائح اللحم بالملح والفلفل; اتركها ترتاح 10 دقائق بدرجة حرارة الغرفة — ستُحمّر أفضل على نار عالية. سخّن 500مل من الزيت في مقلاة عميقة إلى 175°م; اقلِ البطاطس 6–7 دقائق حتى تصبح ذهبية ومقرمشة; صفّها على شبكة ورشّ ملحاً خفيفاً وهي ساخنة. سخّن ووك كبيراً أو مقلاة حديد على نار شديدة جداً مع 2 ملعقة كبيرة من الزيت — يجب أن يبدأ الزيت بإطلاق دخان خفيف; هذه هي الخطوة الحاسمة: يجب أن يكون الووك ساخناً جداً للحصول على تأثير \"ووك هي\" البيروفي. أضف اللحم في طبقة واحدة; اتركه دون تحريك 30 ثانية ليُحمَّر، ثم قلّبه بقوة 90 ثانية — يجب أن يكون اللحم بنياً من الخارج وردياً من الداخل; ارفعه إلى طبق. في نفس الووك، أضف 1 ملعقة كبيرة أخرى من الزيت; قلّب أهلّة البصل وفلفل الآحي 90 ثانية — يجب أن يظل البصل مقرمشاً. أضف الثوم والزنجبيل وقلّبهما 30 ثانية حتى تفوح رائحتهما; أضف الطماطم واطبخها دقيقة واحدة — يجب أن تلين قليلاً لكن لا تنفصل. اسكب صلصة الصويا وخل النبيذ الأحمر على حافة المقلاة (سيتبخّران ويخلقان دخاناً عطرياً); أعد اللحم بعصيره وأضف البطاطس المقلية; قلّب بقوة 30 ثانية حتى يتغلّف كل شيء. أطفئ النار، رشّ الكزبرة المفرومة وقلّب مرة واحدة; قدّمه فوراً فوق أرز بسمتي ساخن مع شرائح الليمون جانباً.","en":"Season the beef strips with salt and pepper; let them rest for 10 minutes at room temperature — they will sear better at high heat. Heat 500ml of oil in a deep pan to 175°C; fry the potatoes for 6–7 minutes until golden and crisp; drain on a rack and salt lightly while hot. Heat a large wok or cast-iron pan over very high heat with 2 tbsp of vegetable oil — the oil should just begin to smoke; this is the critical step: the pan must be very hot for the Peruvian \"wok hei\" effect. Add the beef in a single layer; leave untouched for 30 seconds to sear, then stir-fry vigorously for 90 seconds — the beef should be browned outside but still pink in the centre; lift onto a plate. In the same wok, add 1 tbsp more oil; stir-fry the onion wedges and ají amarillo for 90 seconds — the onion should stay crisp, not soft. Add the garlic and ginger, stir-fry for 30 seconds until fragrant; add the tomatoes and cook for 1 minute — they should soften slightly but not break down. Pour the soy sauce and red wine vinegar around the edge of the pan (they will steam and create aromatic smoke); return the beef with its juices and add the fries; toss vigorously for 30 seconds, until everything is coated. Turn off the heat, scatter the chopped coriander, and toss once; serve immediately over warm basmati rice with lime wedges on the side."}},{"id":118,"origin":{"ar":"المغرب","en":"Morocco","ro":"Maroc"},"name":{"ar":"طاجين الدجاج","en":"Chicken Tagine","ro":"Chicken Tagine"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"middle-eastern","ingredients":{"ar":["1.2 كغ أفخاذ دجاج بالعظم والجلد (حوالي 8 قطع)، يُزال الجلد الزائد","2 بصلة صفراء كبيرة (~400 غ)، واحدة مبشورة ناعماً للتتبيلة وواحدة شرائح رفيعة لقاعدة الطاجين","6 فصوص ثوم، مفرومة ناعماً","4 سم زنجبيل طازج، مبشور ناعماً","1 ملعقة صغيرة كمون + 1 ملعقة صغيرة زنجبيل ناشف + 1 ملعقة صغيرة كزبرة ناشفة + 0.5 ملعقة صغيرة كركم + 0.5 ملعقة صغيرة بابريكا حلوة + 0.5 ملعقة صغيرة فلفل أبيض + رشة سخية من خيوط الزعفران (8-10 خيوط منقوعة في 2 ملعقة كبيرة ماء ساخن)","حزمة صغيرة من الكزبرة الخضراء الطازجة، ~25 غ، مفرومة ناعماً (نصف للتتبيلة ونصف للتزيين)","حزمة صغيرة من البقدونس البلدي، ~25 غ، مفروم ناعماً (نصف للتتبيلة ونصف للتزيين)","1.5 ملعقة صغيرة ملح + 0.5 ملعقة صغيرة فلفل أسود طازج","3 ملاعق كبيرة زيت زيتون + 1 ملعقة كبيرة زبدة غير مملحة (أو سمن للنكهة الأصيلة)","2 ليمونة مخللة، يُغسل ويُزال اللب وتُقطع القشرة شرائح رفيعة (حوالي 80 غ قشرة)","150 غ زيتون أخضر مغربي (أو من نوع Castelvetrano)، يُغسل ويُنزع نواه إن كان كبيراً","400 مل ماء ساخن أو مرق دجاج قليل الملح","عصير نصف ليمونة طازجة (تضاف في النهاية لإضافة نكهة منعشة)","للتقديم: خبز مغربي (خبز) دافئ لتغميس الصلصة، أو كسكسي مطهو على البخار"],"en":["1.2 kg bone-in skin-on chicken thighs (about 8 pieces), trimmed of excess skin","2 large yellow onions (~400 g), one finely grated for the marinade, one thinly sliced for the stew base","6 garlic cloves, minced","4 cm fresh ginger, finely grated","1 tsp ground cumin + 1 tsp ground ginger + 1 tsp ground coriander + 0.5 tsp ground turmeric + 0.5 tsp sweet paprika + 0.5 tsp ground white pepper + a generous pinch of saffron threads (8-10 strands, bloomed in 2 tbsp hot water)","1 small bunch fresh coriander (cilantro), about 25 g, finely chopped (half for the marinade, half for garnish)","1 small bunch flat-leaf parsley, about 25 g, finely chopped (half for the marinade, half for garnish)","1.5 tsp salt + 0.5 tsp freshly ground black pepper","3 tbsp olive oil + 1 tbsp unsalted butter (or smen for the most traditional flavour)","2 preserved lemons, rinsed, flesh discarded, peel cut into thin strips (about 80 g of peel total)","150 g green Moroccan olives (or Castelvetrano), rinsed, pitted if large","400 ml hot water or low-salt chicken stock","Juice of half a fresh lemon (added at the end, to brighten)","To serve: warm khobz flatbread to mop up the sauce, or steamed couscous"],"ro":["1.2 kg pulpe de pui cu os și piele (aproximativ 8 bucăți), curățate de pielea în exces","2 cepe galbene mari (~400 g), una rasă fin pentru marinadă, una tăiată felii subțiri pentru baza tocăniței","6 căței de usturoi, tocați","4 cm ghimbir proaspăt, ras fin","1 linguriță chimion măcinat + 1 linguriță ghimbir măcinat + 1 linguriță coriandru măcinat + 0.5 linguriță turmeric + 0.5 linguriță boia dulce + 0.5 linguriță piper alb măcinat + un vârf generos de șofran (8-10 fire, înflorite în 2 linguri apă fierbinte)","1 legătură mică de coriandru proaspăt (cilantro), ~25 g, tocat fin (jumătate pentru marinadă, jumătate pentru garnitură)","1 legătură mică de pătrunjel cu frunza lată, ~25 g, tocat fin (jumătate pentru marinadă, jumătate pentru garnitură)","1.5 linguriță sare + 0.5 linguriță piper negru proaspăt măcinat","3 linguri ulei de măsline + 1 lingură unt nesărat (sau smen pentru aroma cea mai tradițională)","2 lămâi conservate, clătite, pulpa îndepărtată, coaja tăiată fâșii subțiri (aproximativ 80 g de coajă)","150 g măsline verzi marocane (sau Castelvetrano), clătite, fără sâmburi dacă sunt mari","400 ml apă fierbinte sau supă de pui cu puțină sare","Zeama de la jumătate de lămâie proaspătă (adăugată la final, pentru prospețime)","Pentru servit: pâine plată khobz caldă pentru a culege sosul, sau couscous aburit"]},"howIsMade":{"ar":"تتبيل الدجاج: في وعاء كبير اخلطي البصل المبشور، الثوم، الزنجبيل، جميع البهارات الناشفة، الزعفران المنقوع مع مائه، نصف الكزبرة المفرومة، نصف البقدونس، 1.5 ملعقة صغيرة ملح، 0.5 ملعقة صغيرة فلفل أسود و1.5 ملعقة كبيرة زيت زيتون. أضيفي أفخاذ الدجاج ودلّكي التتبيلة جيداً تحت الجلد وفوقه. غطّي وضعي في الثلاجة ساعة على الأقل؛ 4 ساعات أفضل بوضوح، طوال الليل مثالي.\n\nالتحمير وبناء القاعدة: سخّني الكمية المتبقية من الزيت (1.5 ملعقة كبيرة) والزبدة في طاجين أو قدر ثقيل القاع على نار متوسطة. أضيفي البصل المقطّع شرائح وحمّريه 8 دقائق مع التحريك حتى يلين ويصبح ذهبياً خفيفاً. ادفعي البصل جانباً، ضعي الدجاج بالجلد إلى الأسفل وحمّريه 3-4 دقائق حتى يصبح الجلد ذهبياً داكناً، ثم اقلبيه.\n\nالطهي على نار هادئة: اكشطي كل قطرة من التتبيلة من الوعاء إلى القدر. اسكبي 400 مل من الماء الساخن أو المرق. اتركيه يغلي بهدوء، غطّيه وخفّضي النار إلى أدنى درجة. اطبخي 30 دقيقة — الغطاء المخروطي يحبس البخار الذي يميّز الطاجين.\n\nأضيفي الليمون المخلل والزيتون: ارفعي الغطاء، ضعي شرائح قشر الليمون المخلل والزيتون الأخضر حول الدجاج (وليس فوقه) — كلاهما يطلق محلولاً مالحاً لذا تجنّبي التحريك العنيف. غطّي مجدداً واطبخي 10-15 دقيقة إضافية، حتى يصل الدجاج إلى 75 °م في أسمك جزء وتتركّز الصلصة إلى قوام لامع وخفيف يغلف ظهر الملعقة.\n\nالإنهاء والتقديم: اكشفي القدر، اعصري عصير نصف ليمونة طازجة فوق الطبق وانثري الكزبرة والبقدونس المتبقيتين. تذوّقي قبل التمليح — الليمون المخلل والزيتون يقدّمان ملحاً بحد ذاتهما. قدّمي مباشرة من الطاجين مع خبز مغربي دافئ لتغميس الصلصة، أو مع كسكسي مطبوخ على البخار.","en":"MARINATE THE CHICKEN: in a large bowl combine the grated onion, garlic, ginger, all the dry spices, the bloomed saffron with its water, half the chopped coriander, half the parsley, 1.5 tsp salt, 0.5 tsp black pepper and 1.5 tbsp olive oil. Add the chicken thighs and massage the marinade thoroughly into and under the skin. Cover and refrigerate at least 1 hour; 4 hours is markedly better, overnight is best.\n\nSEAR AND BUILD THE BASE: heat the remaining 1.5 tbsp olive oil and the butter in a tagine vessel or wide heavy-bottomed pot over medium heat. Add the sliced onion and cook 8 minutes, stirring, until soft and lightly golden. Push the onions to one side, lay the marinated chicken skin-side down and sear 3-4 minutes until the skin is deep golden, then flip.\n\nSIMMER: scrape every drop of marinade from the bowl into the pot. Pour in the 400 ml hot water or stock. Bring to a gentle simmer, then cover and reduce the heat to its lowest setting. Cook 30 minutes — the conical lid traps the steam that defines a tagine.\n\nADD PRESERVED LEMON AND OLIVES: lift the lid, tuck the preserved-lemon strips and green olives around (not on top of) the chicken — both release brine, so resist the urge to stir vigorously. Re-cover and cook 10-15 minutes more, until the chicken reads 75 °C / 170 °F at the thickest part and the sauce has reduced to a glossy, brothy consistency that coats the back of a spoon.\n\nFINISH AND SERVE: uncover, squeeze the half-lemon juice over the dish, and scatter the reserved coriander and parsley on top. Taste before salting — preserved lemons and olives both contribute salt, so the dish often needs nothing more. Serve straight from the tagine with warm khobz flatbread to mop up the sauce, or alongside steamed couscous."}},{"id":120,"origin":{"ar":"فنزويلا","en":"Venezuela","ro":"Venezuela"},"name":{"ar":"أريبا","en":"Arepa","ro":"Arepa"},"category":{"ar":"فطور","en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"veg","pairingsType":"latin","ingredients":{"ar":["للعجينة:","400غ هارينا P.A.N. (دقيق ذرة بيضاء مطهو مسبقاً)","500مل ماء دافئ","1 ملعقة صغيرة ملح","2 ملعقة كبيرة زيت نباتي","لرينا بيبيادا (الحشوة الكلاسيكية بالدجاج والأفوكادو):","2 صدر دجاج (نحو 500غ)، مسلوقة ومفتتة","1 أفوكادو ناضج، مقطع مكعبات","3 ملاعق كبيرة مايونيز","1 ملعقة كبيرة عصير ليمون أخضر","1 عود بصل أخضر، شرائح رفيعة","10غ كزبرة طازجة، مفرومة","ملح وفلفل","حشوات شائعة أخرى:","200غ جبنة بيضاء طازجة (queso fresco)، شرائح","100غ لحم بقري مفتت (carne mechada)","زيت نباتي للصاج"],"en":["For the dough:","400g harina P.A.N. (pre-cooked white corn flour)","500ml warm water","1 tsp salt","2 tbsp vegetable oil","For reina pepiada (classic chicken-avocado filling):","2 chicken breasts (about 500g), poached and shredded","1 ripe avocado, diced","3 tbsp mayonnaise","1 tbsp lime juice","1 spring onion, finely sliced","10g fresh coriander, chopped","salt and pepper","Other popular fillings:","200g fresh white cheese (queso fresco), sliced","100g shredded beef (carne mechada)","vegetable oil for griddle"],"ro":["Pentru aluat:","400g harina P.A.N. (făină de porumb pre-fiartă)","500ml apă caldă","1 linguriță sare","2 linguri ulei vegetal","Pentru reina pepiada (umplutura clasică):","2 piepți de pui (aproximativ 500g), fierți și mărunțiți","1 avocado copt, tăiat cuburi","3 linguri maioneză","1 lingură zeamă de lime","1 ceapă verde, tăiată fin","10g coriandru proaspăt, tocat","sare și piper","Alte umpluturi populare:","200g brânză albă proaspătă (queso fresco), feliată","100g carne de vită mărunțită (carne mechada)","ulei vegetal pentru prăjit pe plită"]},"howIsMade":{"ar":"في وعاء كبير، اخلط 500مل من الماء الدافئ مع الملح والزيت; أضف 400غ من هارينا P.A.N; تدريجياً مع التحريك باليد أو بملعقة. اعجن 3–4 دقائق حتى تصبح العجينة ناعمة ومرنة; غطّها بمنشفة واتركها ترتاح 5 دقائق — يمتص الدقيق الماء وتصبح العجينة سهلة التشكيل. اختبر العجينة: يجب أن تكون لزجة قليلاً لكن غير نيئة; إذا تشققت أثناء التشكيل، أضف ملعقة كبيرة من الماء. قسّم العجينة إلى 8 كرات متساوية (نحو 100غ لكل منها); افرد كل كرة بين راحتيك إلى قرص بقطر 8 سم وسماكة 1,5 سم، مع تنعيم الحواف بأصابع مبللة. سخّن مقلاة ثقيلة أو صاجاً على نار متوسطة مع قليل من الزيت; ضع الأريبا واطبخها 4–5 دقائق لكل وجه حتى يتشكّل قشر ذهبي مع بقع أغمق. انقلها إلى صينية فرن واستكمل في فرن مسخّن مسبقاً عند 180°م لمدة 10–15 دقيقة، حتى تُصدر صوتاً أجوف عند النقر الخفيف; هذه هي علامة النضج. خلال راحة الأريبا، حضّر الرينا بيبيادا: اخلط الدجاج المفتت مع الأفوكادو والمايونيز وعصير الليمون والبصل الأخضر والكزبرة والملح والفلفل. قطّع كل أريبا أفقياً بسكين حادة (مثل جيب البيتا)، دون فصلها كلياً; احشها بالرينا بيبيادا (أو أي حشوة أخرى); قدّمها فوراً وهي دافئة ومقرمشة من الخارج.","en":"In a large bowl, combine 500ml warm water with salt and oil; gradually add 400g harina P.A.N., mixing with your hand or a spatula. Knead for 3–4 minutes until the dough is smooth and pliable; cover with a cloth and let it rest for 5 minutes — the flour absorbs the water and the dough becomes easier to shape. Test the dough: it should be slightly sticky but not raw; if it cracks while shaping, add a tablespoon more water. Divide into 8 equal balls (about 100g each); flatten each between your palms into a 8 cm wide, 1.5 cm thick disc, smoothing the edges with damp fingers. Heat a heavy pan or griddle over medium heat with a little oil; add the arepas and cook for 4–5 minutes per side, until a golden crust with darker spots forms. Transfer to a baking tray and finish in a preheated 180°C oven for 10–15 minutes, until they sound hollow when tapped lightly; this is the doneness test. While the arepas rest, make the reina pepiada: mix the shredded chicken with avocado, mayonnaise, lime juice, spring onion, coriander, salt, and pepper. Slice each arepa horizontally with a sharp knife (like a pita pocket), without cutting all the way through; stuff with reina pepiada (or your chosen filling); serve immediately while the arepa is warm and crisp on the outside."}},{"id":121,"origin":{"ar":"فنلندا","en":"Finland","ro":"Finlanda"},"name":{"ar":"فطيرة كاريليا","en":"Karelian Pie","ro":"Karjalanpiirakka"},"category":{"ar":"فطور","en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"veg","pairingsType":"veg","ingredients":{"ar":["للعجينة:","150غ دقيق جاودار","100غ دقيق أبيض","150مل ماء بارد","1/2 ملعقة صغيرة ملح","1 ملعقة كبيرة زيت نباتي","لحشوة الأرز:","200غ أرز قصير الحبة (أرز بودينغ)","1 لتر حليب كامل الدسم","1/2 ملعقة صغيرة ملح","20غ زبدة","لمونا فوي (زبدة البيض، التزيين الكلاسيكي):","100غ زبدة طرية غير مملحة","2 بيضة مسلوقة، مقشّرة ومفرومة ناعماً","1/4 ملعقة صغيرة ملح","1/4 ملعقة صغيرة فلفل أبيض"],"en":["For the dough:","150g rye flour","100g plain white flour","150ml cold water","1/2 tsp salt","1 tbsp vegetable oil","For the rice porridge filling:","200g short-grain rice (pudding rice)","1 litre whole milk","1/2 tsp salt","20g butter","For muna voi (egg butter, classic topping):","100g soft unsalted butter","2 hard-boiled eggs, peeled and finely chopped","1/4 tsp salt","1/4 tsp white pepper"],"ro":["Pentru aluat:","150g făină de secară","100g făină albă","150ml apă rece","1/2 linguriță sare","1 lingură ulei vegetal","Pentru umplutura de orez:","200g orez cu bob rotund (orez pudding)","1 litru lapte integral","1/2 linguriță sare","20g unt","Pentru muna voi (untul de ouă pentru servire):","100g unt moale","2 ouă fierte tari, decojite și tocate fin","1/4 linguriță sare","1/4 linguriță piper alb"]},"howIsMade":{"ar":"حضّر عصيدة الأرز (يمكن أن تُحضَّر قبل يوم): اخلط 200غ من الأرز مع 250مل ماء ساخن في قدر; اطبخه 8 دقائق على نار متوسطة حتى يُمتص الماء. أضف 1 لتر من الحليب و1/2 ملعقة صغيرة من الملح; اطبخه على نار هادئة مع التحريك المستمر 35–45 دقيقة حتى تصبح العصيدة كريمية كثيفة جداً; أضف 20غ من الزبدة وبرّده تماماً. للعجينة: اخلط دقيق الجاودار والدقيق الأبيض والملح في وعاء; أضف الماء البارد والزيت، اعجن 5 دقائق حتى تصبح متماسكة لكن مرنة. قسّم العجينة إلى 16 قطعة متساوية وشكّلها كرات; على سطح مرشوش بدقيق الجاودار، افرد كل كرة إلى بيضاوي رقيق جداً (سماكة 1 ملم، طول 12 سم). ضع 1–2 ملعقة كبيرة من عصيدة الأرز الباردة في وسط كل بيضاوي، تاركاً 2 سم من الحافة. ارفع العجينة من الجانبين الطويلين فوق الحشوة، تاركاً الوسط مكشوفاً; اعصر العجينة بأصابعك لتشكيل ثنيات متعرجة مميزة — هذه هي السدة الكاريلية التقليدية. رتّب الفطائر على صينية مغطاة بورق خبز; اخبزها في فرن مسخّن مسبقاً عند 250°م لمدة 15–20 دقيقة حتى تصبح الحواف ذهبية. أثناء الخبز، حضّر المونا فوي: اهرس الزبدة الطرية مع البيض المفروم والملح والفلفل الأبيض; قدّم الفطائر دافئة، مدهونة بسخاء بالمونا فوي فوق سطح الأرز المكشوف.","en":"Make the rice porridge (can be made a day ahead): combine 200g rice with 250ml hot water in a pot; cook 8 minutes over medium heat, until the water is absorbed. Add 1 litre milk and 1/2 tsp salt; simmer over low heat, stirring often, for 35–45 minutes, until the porridge is very creamy and thick; stir in 20g butter and cool completely. For the dough: combine rye flour, white flour, and salt in a bowl; add cold water and oil, knead for 5 minutes until firm but elastic. Divide the dough into 16 equal pieces and roll into balls; on a rye-floured surface, roll each ball into a very thin oval (1 mm thick, 12 cm long). Spoon 1–2 tbsp cold rice porridge into the centre of each oval, leaving a 2 cm border. Lift the dough over the filling on both long sides, leaving the centre exposed; pinch the dough with your fingers to create the characteristic zigzag pleats — this is the traditional Karelian seal. Arrange the pies on a lined baking tray; bake in a preheated 250°C oven for 15–20 minutes, until the edges are golden brown. While the pies bake, make muna voi: mash the soft butter with the chopped eggs, salt, and white pepper; serve the pies warm, generously spread with muna voi over the exposed rice surface."}},{"id":123,"origin":{"ar":"إيطاليا","en":"Italy","ro":"Italia"},"name":{"ar":"باستا إي فاجيولي","en":"Pasta e fagioli","ro":"Pasta e fagioli"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"pasta","pairingsType":"italian","ingredients":{"ar":["200غ معكرونة قصيرة (ديتاليني، توبيتي، أو أوريكيتي)","400غ من فاصولياء بورلوتي أو كانيلليني المعلبة، مصفّاة (أو 200غ يابسة منقوعة طوال الليل ومطبوخة)","1 بصلة كبيرة، مفرومة ناعماً","2 جزرة، مقطعة مكعبات صغيرة","2 ساق كرفس، مقطعة مكعبات صغيرة","3 فصوص ثوم، مفرومة","100غ بانشيتا أو لحم مقدّد، مقطع مكعبات (اختياري)","400غ طماطم مقطعة معلّبة","2 ملعقة كبيرة معجون طماطم","1 ورقة غار","1 غصن إكليل الجبل الطازج","1 غصن زعتر طازج","1.2 لتر مرق دجاج أو خضار ساخن","4 ملاعق كبيرة زيت زيتون بكر ممتاز","1 قطعة قشرة بارميجيانو (اختياري للنكهة)","ملح وفلفل أسود مطحون طازجاً","بارميجيانو مبشور وزيت زيتون بكر ممتاز للتقديم"],"en":["200g short pasta (ditalini, tubetti, or orecchiette)","400g canned borlotti or cannellini beans, drained (or 200g dried, soaked overnight and cooked)","1 large onion, finely chopped","2 carrots, finely diced","2 celery stalks, finely diced","3 garlic cloves, minced","100g pancetta or bacon, diced (optional)","400g canned chopped tomatoes","2 tbsp tomato paste","1 bay leaf","1 sprig fresh rosemary","1 sprig fresh thyme","1.2L hot chicken or vegetable stock","4 tbsp extra-virgin olive oil","1 piece Parmigiano rind (optional, for flavour)","salt and freshly ground black pepper","grated Parmigiano and extra-virgin olive oil, to serve"],"ro":["200g paste scurte (ditalini, tubetti sau orecchiette)","400g fasole borlotti sau cannellini din conservă, scurse (sau 200g fasole uscată înmuiată peste noapte și fiartă)","1 ceapă mare, tocată fin","2 morcovi, tăiați cuburi mici","2 tulpini de țelină, tăiate cuburi mici","3 căței de usturoi, tocați","100g pancetta sau bacon, tăiat cuburi (opțional)","400g roșii sfărâmate din conservă","2 linguri pastă de roșii","1 frunză de dafin","1 crenguță de rozmarin proaspăt","1 crenguță de cimbru proaspăt","1,2 litri supă de pui sau legume fierbinte","4 linguri ulei de măsline extravirgin","1 bucată coajă de Parmigiano (opțional, pentru aromă)","sare și piper negru proaspăt măcinat","Parmigiano ras și ulei de măsline extravirgin, pentru servit"]},"howIsMade":{"ar":"في قدر كبير ثقيل القاع، سخّن 3 ملاعق كبيرة من زيت الزيتون على نار متوسطة; أضف مكعبات البانشيتا (إن استخدمتها) واطبخها 5 دقائق حتى تتحمّر ويُفرز الدهن. أضف البصل والجزر والكرفس ورشة ملح; قلّب 10–12 دقيقة حتى تلين وتتكرمل قليلاً — هذا هو السوفريتو، القاعدة العطرية. أضف الثوم ومعجون الطماطم وإكليل الجبل والزعتر; اطبخ دقيقتين حتى يتعمّق لون المعجون. أضف الطماطم المقطعة وورقة الغار وقشرة البارميجيانو (إن استخدمتها); اطبخ 5 دقائق على نار متوسطة. أضف نصف الفاصولياء كاملة والنصف الآخر مهروسة بالشوكة أو المضرب اليدوي (القوام التقليدي يتطلب الاثنين); اسكب 1,2 لتر من المرق الساخن; أوصله إلى الغليان. أضف المعكرونة واطبخها 8–10 دقائق على نار متوسطة مع التحريك المتكرر حتى تصل إلى ال دنتي; يتكاثف السائل بانطلاق نشاء المعكرونة. تذوّق واضبط الملح; أزل قشرة البارميجيانو وإكليل الجبل والزعتر; اترك الشوربة ترتاح 5 دقائق — ستزداد كثافة لتتحوّل إلى يخنة سميكة كريمية. قدّمها ساخنة في أوعية عميقة; توّجها بالفلفل الأسود المطحون طازجاً بسخاء، وكومة من البارميجيانو المبشور، ورشة أخيرة من زيت الزيتون البكر الممتاز.","en":"In a large heavy-bottomed pot, heat 3 tbsp olive oil over medium heat; add the diced pancetta (if using) and cook for 5 minutes, until browned and the fat has rendered. Add the onion, carrots, celery and a pinch of salt; sauté for 10–12 minutes, until soft and lightly caramelised — this is the soffritto, the aromatic foundation. Stir in the garlic, tomato paste, rosemary, and thyme; cook for 2 minutes, until the paste darkens. Add the chopped tomatoes, bay leaf, and Parmigiano rind (if using); simmer for 5 minutes over medium heat. Add half the beans whole and the other half mashed with a fork or hand whisk (the traditional texture calls for both); pour in 1.2L hot stock; bring to a boil. Add the pasta and cook for 8–10 minutes over medium heat, stirring often, until al dente; the liquid will thicken as the pasta releases starch. Taste and adjust salt; remove the Parmigiano rind, rosemary, and thyme stems; let the soup rest 5 minutes — it will thicken further into a dense, creamy stew. Serve hot in deep bowls; crown with generous fresh black pepper, a heavy drift of grated Parmigiano, and a final drizzle of extra-virgin olive oil."}},{"id":124,"origin":{"ar":"سريلانكا","en":"Sri Lanka","ro":"Sri Lanka"},"name":{"ar":"كوتو","en":"Kottu","ro":"Kottu"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"indian","ingredients":{"ar":["8 خبزات روتي غودهامبا أو باراتا (نحو 640 غ في المجموع)، مقطّعة شرائح رفيعة بعرض 1 سم","600 غ من فخذ الدجاج منزوع العظم والجلد، مقطّع قطعاً بحجم 1,5 سم","5 بيضات كبيرة، مخفوقة قليلاً مع رشّة ملح","2 بصلة حمراء متوسطة (نحو 240 غ)، مفرومة شرائح رفيعة","1 كرّاث كبير (نحو 200 غ)، منظّف ومقطّع شرائح رفيعة ومغسول","2 جزرة صغيرة (نحو 140 غ)، مقطّعة جوليان","3 فلفلات خضراء حارّة طازجة، مقطّعة شرائح رفيعة (بدون بذور لمذاق ألطف)","2 ملعقة كبيرة زنجبيل طازج مبشور ناعماً","5 فصوص ثوم، مفرومة ناعماً","2 ملعقة صغيرة مسحوق كاري سريلانكي","1 ملعقة صغيرة كركم مطحون","2 ملعقة صغيرة فلفل كشميري مطحون أو فلفل أحمر حلو","15 ورقة كاري طازجة","400 مل صلصة كاري دجاج أو جوز هند، دافئة","3 ملاعق كبيرة صلصة صويا","4 ملاعق كبيرة زيت جوز هند أو زيت نباتي","1,5 ملعقة صغيرة ملح، ويُضاف حسب الذوق","2 ملعقة كبيرة عصير ليمون أخضر، للتقديم النهائي"],"en":["8 godhamba roti or paratha (about 640 g total), thinly sliced into 1 cm-wide strips","600 g boneless, skinless chicken thigh, cut into 1.5 cm pieces","5 large eggs, lightly beaten with a pinch of salt","2 medium red onions (about 240 g), thinly sliced","1 large leek (about 200 g), trimmed, thinly sliced, and washed","2 small carrots (about 140 g), julienned","3 fresh green chillies, finely sliced (seeded for a milder finish)","2 tbsp finely grated fresh ginger","5 garlic cloves, finely chopped","2 tsp Sri Lankan curry powder","1 tsp ground turmeric","2 tsp Kashmiri chilli powder or sweet paprika","15 fresh curry leaves","400 ml warm chicken or coconut curry sauce","3 tbsp soy sauce","4 tbsp coconut or vegetable oil","1.5 tsp salt, plus more to taste","2 tbsp lime juice, to finish"],"ro":["8 lipii godhamba sau paratha (aproximativ 640 g în total), tăiate în fâșii subțiri de 1 cm lățime","600 g pulpă de pui dezosată, fără piele, tăiată în bucăți de 1,5 cm","5 ouă mari, bătute ușor cu un praf de sare","2 cepe roșii medii (aproximativ 240 g), feliate subțire","1 praz mare (aproximativ 200 g), curățat, feliat subțire și spălat","2 morcovi mici (aproximativ 140 g), tăiați julienne","3 ardei iuți verzi proaspeți, feliați subțire (fără semințe pentru un gust mai blând)","2 linguri ghimbir proaspăt, ras fin","5 căței de usturoi, tocați fin","2 lingurițe pudră de curry srilankez","1 linguriță turmeric măcinat","2 lingurițe pudră de ardei iute Kashmiri sau boia dulce","15 frunze de curry proaspete","400 ml sos de curry de pui sau de cocos, cald","3 linguri sos de soia","4 linguri ulei de cocos sau vegetal","1,5 lingurițe sare, plus după gust","2 linguri suc de lime, pentru finisare"]},"howIsMade":{"ar":"سخّن 1 ملعقة كبيرة من الزيت في مقلاة كبيرة أو ووك على نار متوسطة إلى عالية; تبّل الدجاج بـ 0,5 ملعقة صغيرة من الملح ورشّة من مسحوق الكاري; اطبخه 7–8 دقائق مع التقليب من حين لآخر حتى يأخذ لوناً ذهبياً خفيفاً ويصبح ناضجاً تماماً (دون أثر وردي في المنتصف); انقله إلى طبق. أضف 3 ملاعق كبيرة من الزيت المتبقية إلى المقلاة ذاتها; حين يبدأ بإطلاق وميض، أضف أوراق الكاري — ستفرقع 5–10 ثوانٍ; أضف البصل الأحمر المشرّح واطبخه 3–4 دقائق حتى يلين ويصبح شفافاً عند الحواف لكنه يبقى متماسكاً. أضف الكرّاث والجزر والفلفل الأخضر وقلّب 2–3 دقائق — يجب أن تظل الخضار مقرمشة-طريّة، لا طريّة تماماً. ادفع الخضار إلى جانب من المقلاة; أضف الزنجبيل والثوم إلى المساحة الفارغة واطبخهما 30 ثانية حتى تفوح رائحتهما دون أن يحمرّا; اخلط ما تبقّى من مسحوق الكاري والكركم وفلفل كشمير ثم حمّصها 20–30 ثانية حتى تفوح روائحها. اسكب البيض المخفوق في وسط المقلاة وقلّبه برفق 60–90 ثانية حتى يتجمّد لكن يظلّ لامعاً — اكسر الكتلة إلى قطع صغيرة بالملعقة. أعد الدجاج إلى المقلاة مع شرائح الروتي; قلّب كل شيء 1–2 دقيقة ليمتص الروتي لون التوابل وعصير الدجاج. اسكب صلصة الصويا وصلصة الكاري الدافئة على حواف المقلاة; باستخدام ملعقتين معدنيتين (أو ظهر ملعقة خشبية ثقيلة)، قطّع-وقلّب الخليط بقوة 3–4 دقائق — استمرّ بالقطع داخل الكومة حتى تتفتت شرائح الروتي إلى قطع صغيرة غير منتظمة وتمتص الصلصة; يجب أن يبدو الخليط لامعاً ومتجانساً، لا حسائياً. تذوّق وأضف ملحاً إذا لزم; اعصر عصير الليمون الأخضر وقلّب مرة أخيرة ثم قدّمه فوراً وهو لا يزال يتصاعد منه البخار، إلى جانبه مغرفة إضافية من صلصة الكاري.","en":"Heat 1 tbsp of the oil in a large skillet or wok over medium-high heat; season the chicken with 0.5 tsp of the salt and a pinch of the curry powder; cook for 7–8 minutes, stirring occasionally, until lightly golden and just cooked through (no pink in the centre); transfer to a plate. Add the remaining 3 tbsp of oil to the same pan; when shimmering, add the curry leaves — they will crackle for 5–10 seconds; add the sliced red onions and cook for 3–4 minutes until softened and translucent at the edges but still firm. Add the leek, carrots, and green chillies and stir-fry for 2–3 minutes — the vegetables should remain crisp-tender, not soft. Push the vegetables to one side of the pan; add the ginger and garlic to the open space and cook for 30 seconds, until fragrant but not browned; stir in the remaining curry powder, the turmeric, and the Kashmiri chilli powder; toast for 20–30 seconds until aromatic. Pour the beaten eggs into the centre of the pan and gently scramble for 60–90 seconds until set but still glossy — break the curd into small pieces with the spatula. Return the chicken to the pan along with the sliced roti; toss everything together for 1–2 minutes so the roti picks up colour from the spices and chicken juices. Pour the soy sauce and warm curry sauce around the edge of the pan; use two metal spatulas (or the back of a heavy wooden spoon) and chop-and-toss the mixture vigorously for 3–4 minutes — keep cutting through the pile so the roti strips break down into small irregular pieces and soak up the sauce; the mixture should look glossy and unified, not soupy. Taste and add more salt if needed; squeeze over the lime juice, toss once more, and serve immediately while the kottu still steams, with an extra ladle of curry sauce on the side."}},{"id":125,"origin":{"ar":"لاتفيا","en":"Latvia","ro":"Letonia"},"name":{"ar":"بيراجي","en":"Piragi","ro":"Piragi"},"category":{"ar":"وجبة خفيفة","en":"Snack","ro":"Gustare"},"servings":8,"tipType":"meat","pairingsType":"meat","ingredients":{"ar":["500 غ من دقيق الخبز الأبيض القوي، مع كمية إضافية للرش","250 مل من الحليب كامل الدسم، مدفّأً لطفياً إلى 38 درجة مئوية","كيس 7 غ (2 ملعقة صغيرة) من الخميرة الفورية الجافة","50 غ من السكر الناعم","1 ملعقة صغيرة من ملح البحر الناعم","70 غ من الزبدة غير المملحة، مذابة ومبردة قليلاً","1 بيضة كبيرة، مخفوقة قليلاً","350 غ من اللحم المقدد المدخن (أو الشبيك المدخن)، مقطّع مكعبات صغيرة 5 ملم","1 بصلة كبيرة (نحو 180 غ)، مفرومة فرماً ناعماً جداً","1 ملعقة كبيرة من زيت محايد (فقط إذا كان البيكون قليل الدسم)","0,5 ملعقة صغيرة من الفلفل الأسود المطحون الطازج","رشّة من بذور الكراويا، مهروسة قليلاً (اختياري)","1 صفار بيضة كبيرة مخفوق مع 1 ملعقة كبيرة من الحليب، للتلميع","رقائق ملح البحر، للرش (اختياري)"],"en":["500 g strong white bread flour, plus extra for dusting","250 ml whole milk, gently warmed to 38°C","7 g sachet (2 tsp) instant dry yeast","50 g caster sugar","1 tsp fine sea salt","70 g unsalted butter, melted and slightly cooled","1 large egg, lightly beaten","350 g smoked streaky bacon (or smoked speck), in small 5 mm dice","1 large onion (about 180 g), very finely diced","1 tbsp neutral oil (only if the bacon is very lean)","0.5 tsp freshly ground black pepper","Pinch of caraway seeds, lightly crushed (optional)","1 large egg yolk beaten with 1 tbsp milk, for glazing","Flaky sea salt, for sprinkling (optional)"],"ro":["500 g făină albă de pâine, plus pentru tăvălit","250 ml lapte integral, încălzit ușor la 38°C","1 plic de 7 g (2 lingurițe) drojdie instant uscată","50 g zahăr tos","1 linguriță sare fină de mare","70 g unt nesărat, topit și ușor răcit","1 ou mare, bătut ușor","350 g bacon afumat (sau speck afumat), tăiat cuburi mici de 5 mm","1 ceapă mare (aproximativ 180 g), tocată foarte fin","1 lingură ulei neutru (doar dacă baconul este foarte slab)","0,5 linguriță piper negru proaspăt măcinat","Un vârf de semințe de chimen, ușor zdrobite (opțional)","1 gălbenuș mare bătut cu 1 lingură de lapte, pentru glazură","Fulgi de sare de mare, pentru presărat (opțional)"]},"howIsMade":{"ar":"اسكب الحليب الدافئ في وعاء كبير، رشّ فوقه الخميرة والسكر، وقلّب برفق; اتركه 5–10 دقائق حتى تتكوّن رغوة على السطح — هذا يؤكد أن الخميرة حيّة. أضف الزبدة المذابة والبيض المخفوق والملح إلى الحليب; اسكب الدقيق وقلّب بملعقة خشبية حتى تتشكّل عجينة خشنة; اقلبها على سطح مرشوش بالدقيق واعجنها 8–10 دقائق حتى تصبح ناعمة ومرنة ولزجة قليلاً فقط. شكّل العجينة كرةً، ضعها في وعاء مدهون قليلاً بالزيت، غطّها بقطعة قماش رطبة، واتركها ترتاح في مكان دافئ ساعة إلى ساعة وربع، حتى تتضاعف. في هذه الأثناء، حضّر الحشوة; اطبخ مكعبات اللحم المقدد في مقلاة جافة على نار متوسطة 5–6 دقائق مع التحريك المتكرر، حتى تتحرّر الدهون وتبدأ الأطراف بالاحمرار قليلاً دون أن يصبح اللحم مقرمشاً; أضف البصل (والزيت عند اللزوم) واطبخ 4–5 دقائق إضافية حتى يصبح البصل شفافاً دون أن يحمرّ; تبّل بالفلفل والكراويا; اتركه يبرد تماماً. اطرد الهواء من العجينة المختمرة وقسّمها إلى 24 قطعة متساوية (نحو 35 غ لكل قطعة); شكّل كل قطعة كرة ناعمة ثم فردها بنشّابة إلى شكل بيضاوي بطول 8 سم وسماكة 4 ملم تقريباً. ضع 1 ملعقة صغيرة من الحشوة الباردة على نصف كل قرص بيضاوي، اطوِ العجينة فوقها لإغلاقها، واضغط الحواف بقوة لإحكام الإغلاق; اسحب الأطراف المغلقة بلطف نحو بعضها لتشكيل الهلال الكلاسيكي، مع توجيه الخط المغلق نحو الأسفل على الصينية. وزّع البيراجي على صينيتين مبطّنتين بورق الخبز، مع ترك 3 سم بينهما; غطّها برفق واتركها ترتاح لمدة 20–25 دقيقة إضافية حتى تنتفخ بوضوح; في هذه الأثناء سخّن الفرن إلى 220°م (425°ف / مروحة 200°م). ادهن الأسطح بصفار البيض، ورشّ ملح الرقائق إن أردت، واخبزها 12–15 دقيقة — تكون جاهزة عندما تكون الأسطح ذهبية غامقة، والحواف محكمة الإغلاق، والقواعد تُصدر صوتاً أجوف عند النقر; اتركها على شبكة 5 دقائق وقدّمها دافئة.","en":"Pour the warm milk into a large bowl, scatter the yeast and sugar over it, and stir lightly; let stand 5–10 minutes until foamy on the surface — this confirms the yeast is alive. Add the melted butter, beaten egg, and salt to the milk; pour in the flour and stir with a wooden spoon until a shaggy dough forms; tip onto a lightly floured surface and knead for 8–10 minutes, until smooth, elastic, and only slightly tacky to the touch. Shape the dough into a ball, place it in a lightly oiled bowl, cover with a damp cloth, and leave to rise in a warm spot for 1 hour to 1 hour 15 minutes, until doubled. Meanwhile, prepare the filling; cook the diced bacon in a dry frying pan over medium heat for 5–6 minutes, stirring often, until the fat has rendered and the edges just begin to colour but the bacon is not crisp; add the onion (and the oil if needed) and cook for another 4–5 minutes, until the onion is translucent but not browned; season with the pepper and caraway; cool completely. Knock back the risen dough and divide it into 24 equal pieces (about 35 g each); roll each piece into a smooth ball, then flatten with a rolling pin into an 8 cm oval, about 4 mm thick. Spoon 1 tsp of cold filling onto one half of each oval, fold the dough over to enclose, and pinch the edges firmly to seal; pull the sealed ends gently toward each other to form the classic crescent shape, with the seam facing down on the tray. Arrange the piragi on two parchment-lined trays, leaving 3 cm between them; cover lightly and let rise for another 20–25 minutes, until visibly puffy; meanwhile heat the oven to 220°C (425°F / fan 200°C). Brush the tops with the egg-yolk glaze, sprinkle with flaky salt if using, and bake for 12–15 minutes — they are ready when the tops are deep golden brown, the seams hold tight, and the bottoms sound hollow when tapped; cool on a rack for 5 minutes and serve warm."}},{"id":126,"origin":{"ar":"فيتنام","en":"Vietnam","ro":"Vietnam"},"name":{"ar":"بان سيو","en":"Banh Xeo","ro":"Bánh xèo"},"category":{"ar":"فطور","en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"fish","pairingsType":"vietnamese","ingredients":{"ar":["250 غ من دقيق الأرز","30 غ من نشا الذرة","1 ملعقة صغيرة من الكركم المطحون","0,5 ملعقة صغيرة من ملح البحر الناعم، مع إضافة للحم الخنزير","1 ملعقة صغيرة من السكر الناعم","400 مل من حليب جوز الهند كامل الدسم","350 مل من الماء الفوّار البارد (أو الماء العادي البارد)","4 بصلات أخضر، الأجزاء الخضراء مقطّعة شرائح رفيعة (نحو 30 غ)","300 غ من بطن أو كتف الخنزير، مقطّع شرائح بسماكة 5 ملم","300 غ من الجمبري الني المقشّر (نحو 24 حبة متوسطة)، منزوع العرق الأسود","200 غ من براعم الفول المنغ الطازجة","1 بصلة متوسطة (نحو 120 غ)، مفرومة شرائح رفيعة","60 مل من زيت محايد (زيت الفول السوداني أو زيت نباتي)، للقلي","1 ملعقة كبيرة من صلصة السمك، مع 3 ملاعق كبيرة لصلصة النوك تشام","3 ملاعق كبيرة من عصير الليمون الأخضر الطازج","2 ملعقة كبيرة من السكر الناعم (لصلصة النوك تشام)","1 فص ثوم مفروم ناعماً و1 فلفل أحمر صغير مقطّع شرائح رفيعة (لصلصة النوك تشام)","1 رأس خس الزبدة أو الروماني، أوراقه مفصولة، مع باقة كبيرة من الأعشاب الطازجة (نعناع، بريلا، كزبرة، ريحان تايلندي) وخيارة واحدة مقطّعة جوليان، للتقديم"],"en":["250 g rice flour","30 g cornflour (cornstarch)","1 tsp ground turmeric","0.5 tsp fine sea salt, plus more for the pork","1 tsp caster sugar","400 ml full-fat coconut milk","350 ml cold sparkling water (or cold still water)","4 spring onions, green tops finely sliced (about 30 g)","300 g pork belly or shoulder, cut into 5 mm-thick strips","300 g raw peeled prawns (about 24 medium), deveined","200 g fresh mung bean sprouts","1 medium onion (about 120 g), thinly sliced","60 ml neutral oil (peanut or vegetable), for frying","1 tbsp fish sauce, plus 3 tbsp for the nuoc cham","3 tbsp fresh lime juice","2 tbsp caster sugar (for the nuoc cham)","1 garlic clove, finely minced, and 1 small red chilli, finely sliced (for the nuoc cham)","1 head butter lettuce or romaine, leaves separated, plus a large bunch of fresh herbs (mint, perilla, coriander, Thai basil) and 1 cucumber, julienned, to serve"],"ro":["250 g făină de orez","30 g amidon de porumb","1 linguriță turmeric măcinat","0,5 linguriță sare fină de mare, plus în plus pentru carnea de porc","1 linguriță zahăr tos","400 ml lapte de cocos integral","350 ml apă minerală rece (sau apă plată rece)","4 cepe verzi, părțile verzi feliate subțire (aproximativ 30 g)","300 g piept sau pulpă de porc, tăiat fâșii de 5 mm grosime","300 g creveți cruzi decojiți (aproximativ 24 medii), curățați de venă","200 g germeni proaspeți de fasole mung","1 ceapă medie (aproximativ 120 g), feliată subțire","60 ml ulei neutru (de arahide sau vegetal), pentru prăjit","1 lingură sos de pește, plus 3 linguri pentru nuoc cham","3 linguri suc de lime proaspăt","2 linguri zahăr tos (pentru nuoc cham)","1 cățel de usturoi tocat fin și 1 ardei iute roșu mic feliat subțire (pentru nuoc cham)","1 căpățână de salată verde de unt sau romană, frunze separate, plus o legătură mare de ierburi proaspete (mentă, perilla, coriandru, busuioc thailandez) și 1 castravete tăiat julienne, pentru servit"]},"howIsMade":{"ar":"حضّر العجين قبل 30 دقيقة على الأقل; اخفق في وعاء كبير دقيق الأرز ونشا الذرة والكركم و0,5 ملعقة صغيرة من الملح و1 ملعقة صغيرة من السكر; اسكب حليب جوز الهند والماء الفوّار واخفق حتى تصبح العجينة ناعمة; أضف الجزء الأخضر من البصل المقطّع; غطّ العجين واتركه يرتاح في الثلاجة 30 دقيقة على الأقل (حتى 4 ساعات) — الراحة ترطّب الدقيق وتعطي بانه شيو أكثر قرمشة. خلال راحة العجين، حضّر صلصة النوك تشام; اخلط في وعاء 3 ملاعق كبيرة من صلصة السمك و3 ملاعق كبيرة من عصير الليمون و2 ملعقة كبيرة من السكر و4 ملاعق كبيرة من الماء الدافئ حتى يذوب السكر; أضف الثوم المفروم والفلفل الحار المقطّع; اتركها جانباً. قلّب شرائح لحم الخنزير مع 1 ملعقة كبيرة من صلصة السمك و0,5 ملعقة صغيرة من الفلفل; اشطف الجمبري وجفّفه; اغسل البراعم وانفض الماء عنها; رتّب الخس والأعشاب والخيار على طبق التقديم. سخّن مقلاة غير لاصقة قطرها 24 سم على نار متوسطة إلى عالية; أضف 1 ملعقة صغيرة من الزيت ودوّر لتغطية القاع، ثم أضف 2–3 حبات جمبري وحفنة من شرائح اللحم; قلّب 60–90 ثانية حتى يتقوّس الجمبري ويصبح وردياً وتأخذ أطراف اللحم لوناً ذهبياً دون أن ينضج بالكامل. قلّب العجين ثم اسكب نحو 100 مل في المقلاة مع تدوير سريع كي يغطي العجين القاع طبقة رقيقة ويصعد إلى منتصف الجوانب; وزّع حفنة صغيرة من البصل المقطّع على نصف الفطيرة. غطّ المقلاة لمدة 60 ثانية — البخار يساعد على نضج الوجه; اكشف الغطاء، رشّ 1 ملعقة صغيرة من الزيت حول الحافة، واطبخ 2–3 دقائق إضافية حتى تصبح الحواف ذهبية غامقة وترتفع نظيفة بواسطة ملعقة رقيقة. كوّم حفنة من براعم الفاصوليا على النصف الذي عليه لحم وجمبري; اطوِ النصف الفارغ فوقها لتشكيل نصف هلال، ثم اسحبها على طبق دافئ; كرّر العملية مع باقي العجين والجمبري واللحم والبراعم؛ ينبغي أن تحصل على 4–5 فطائر. قدّمها فوراً وهي ما زالت مقرمشة بصوت مسموع; طريقة الأكل: قطّع جزءاً ولفّه في ورقة خس مع الأعشاب والخيار، ثم اغمسه في النوك تشام; يجب أن تُصدر الفطيرة فرقعة مسموعة عند ثنيها — إذا صارت طريّة، فالمقلاة بحاجة لأن تكون أسخن في المرة التالية، والسكب أرقّ قليلاً.","en":"Make the batter at least 30 minutes ahead; whisk together the rice flour, cornflour, turmeric, 0.5 tsp salt, and 1 tsp sugar in a large bowl; pour in the coconut milk and sparkling water and whisk until smooth; stir in the sliced spring-onion greens; cover and rest in the fridge for at least 30 minutes (up to 4 hours) — the resting hydrates the flour for a crisper crepe. While the batter rests, mix the nuoc cham; stir 3 tbsp fish sauce, 3 tbsp lime juice, 2 tbsp sugar, and 4 tbsp warm water in a bowl until the sugar dissolves; add the minced garlic and sliced chilli; set aside. Toss the pork strips with 1 tbsp fish sauce and 0.5 tsp pepper; rinse and pat dry the prawns; wash the bean sprouts and shake dry; arrange the lettuce, herbs, and cucumber on a serving platter. Heat a 24 cm non-stick pan over medium-high heat; add 1 tsp oil, swirl to coat, then add 2–3 prawns and a handful of pork strips; stir-fry for 60–90 seconds until the prawns curl pink and the pork edges are golden but not fully cooked through. Stir the batter, then ladle about 100 ml into the pan, immediately swirling so the batter coats the base in a thin layer and reaches halfway up the sides; drop a small handful of sliced onion over one half of the crepe. Cover with a lid for 60 seconds — the steam helps cook the top; then uncover, drizzle 1 tsp oil around the edge, and cook for a further 2–3 minutes, until the edges turn deep golden and lift cleanly from the pan with a thin spatula. Pile a handful of bean sprouts onto the half topped with pork and prawns; fold the empty half over to form a half-moon, then slide onto a warmed plate; repeat with the remaining batter, prawns, pork, and bean sprouts; you should get 4–5 crepes. Serve immediately, while the crepes are still loud-crispy; to eat: tear a piece, wrap it in lettuce with herbs and cucumber, and dip into the nuoc cham; the crepe should crackle audibly as it bends — if it goes soft, the next one needs a hotter pan and a slightly thinner pour."}},{"id":127,"origin":{"ar":"بيرو","en":"Peru","ro":"Peru"},"name":{"ar":"كاوسا ليمنيا","en":"Causa Limeña","ro":"Causa Limeña"},"category":{"ar":"مقبلات","en":"Appetizer","ro":"Aperitiv"},"servings":4,"tipType":"fish","pairingsType":"latin","ingredients":{"ar":["1 كغ من البطاطس الصفراء البيروفية (أو Yukon Gold أو غيرها من البطاطس الصفراء الشمعية)، مقشّرة ومقطّعة قطعاً","60 مل من عصير الليمون الأخضر الطازج (نحو 2 ليمونة)","60 مل من زيت محايد (زيت دوار الشمس أو زيت الزيتون)","2 ملعقة كبيرة من معجون آحي أماريّو (أو 1 ملعقة كبيرة من آحي أماريّو + 1 ملعقة صغيرة من الغوتشوجانغ الكوري كبديل)","1,5 ملعقة صغيرة من ملح البحر الناعم، ويُضاف حسب الذوق","0,5 ملعقة صغيرة من الفلفل الأبيض المطحون الطازج","علبتان 160 غ من تونة عالية الجودة في زيت الزيتون، مصفّاة (أو 320 غ من صدر الدجاج المسلوق المُقطّع)","120 غ من مايونيز جيد","2 بصلتان أخضر، مقطّعتان شرائح رفيعة جداً (نحو 20 غ)","1 ساق كرفس صغيرة، مفرومة ناعماً (نحو 30 غ، اختياري)","0,5 ملعقة صغيرة من ملح البحر الناعم","1 ثمرة أفوكادو كبيرة ناضجة (نحو 200 غ)، مقطّعة شرائح 5 ملم ومخلوطة بـ 1 ملعقة صغيرة من عصير الليمون","12 حبة زيتون أسود (بوتيخا أو كالاماتا)، مشطورة ومنزوعة النواة","2 بيضتان مسلوقتان جيداً، مقطّعتان أنصافاً أو أرباعاً","أغصان كزبرة أو بقدونس طازجة"],"en":["1 kg yellow Peruvian potatoes (or Yukon Gold or other waxy yellow potatoes), peeled and cut into chunks","60 ml fresh lime juice (about 2 limes)","60 ml neutral oil (sunflower or olive)","2 tbsp ají amarillo paste (or 1 tbsp ají amarillo + 1 tsp Korean gochujang as substitute)","1.5 tsp fine sea salt, plus more to taste","0.5 tsp freshly ground white pepper","2 × 160 g tins of high-quality tuna in olive oil, drained (or 320 g cooked shredded chicken breast)","120 g good mayonnaise","2 spring onions, very finely sliced (about 20 g)","1 small celery stalk, finely diced (about 30 g, optional)","0.5 tsp fine sea salt","1 large ripe avocado (about 200 g), sliced 5 mm thick and tossed with 1 tsp lime juice","12 black olives (botija or kalamata), halved and pitted","2 hard-boiled eggs, halved or quartered","Sprigs of fresh coriander or parsley"],"ro":["1 kg cartofi galbeni peruvieni (sau Yukon Gold ori alți cartofi galbeni cu pastă fermă), curățați și tăiați în bucăți","60 ml suc proaspăt de lime (aproximativ 2 lime)","60 ml ulei neutru (de floarea-soarelui sau de măsline)","2 linguri pastă de ají amarillo (sau 1 lingură ají amarillo + 1 linguriță gochujang ca substitut)","1,5 lingurițe sare fină de mare, plus după gust","0,5 linguriță piper alb proaspăt măcinat","2 conserve de 160 g de ton de calitate în ulei de măsline, scurse (sau 320 g piept de pui fiert și mărunțit)","120 g maioneză bună","2 cepe verzi, feliate foarte fin (aproximativ 20 g)","1 tulpină mică de țelină, tocată fin (aproximativ 30 g, opțional)","0,5 linguriță sare fină de mare","1 avocado mare copt (aproximativ 200 g), feliat la 5 mm și amestecat cu 1 linguriță suc de lime","12 măsline negre (botija sau Kalamata), tăiate în două și fără sâmburi","2 ouă fierte tare, tăiate în jumătăți sau sferturi","Crenguțe de coriandru sau pătrunjel proaspăt"]},"howIsMade":{"ar":"اسلق البطاطس في ماء مالح جيداً (نحو 1 ملعقة كبيرة من الملح للتر) لمدة 18–20 دقيقة، حتى تنزلق السكين دون مقاومة من غير أن تتفتّت البطاطس; صفّها واتركها تجف بالبخار على شبكة لمدة 5 دقائق. وهي ما زالت دافئة، مرّر البطاطس عبر مهروسة أو منخل ناعم إلى وعاء واسع; أضف معجون آحي أماريّو، عصير الليمون، الزيت، 1,5 ملعقة صغيرة من الملح، والفلفل الأبيض; اعجن برفق باليدين 2–3 دقائق — يجب أن يكون البوريه أملس وحريرياً ومرناً قليلاً، يحتفظ بشكله عند الضغط. تذوّق وعدّل بمزيد من الملح أو الليمون; غطّ واترك ليبرد إلى درجة حرارة الغرفة، ثم أدخله الثلاجة 20 دقيقة ليتماسك قليلاً. حضّر الحشوة; فتّت التونة المصفّاة (أو قطّع الدجاج) في وعاء; أضف المايونيز، البصل الأخضر، الكرفس (إن وُجد)، و0,5 ملعقة صغيرة من الملح; اقلبه برفق — احرص على الإبقاء على رقائق السمك ظاهرة بدلاً من تحويلها إلى بوريه ناعم; أبقه بارداً حتى الاستعمال. غلّف قالب كيك 22 × 12 سم (أو حلقة كيك دائرية قطرها 18 سم) بغشاء بلاستيكي مع ترك زيادة سخية; اضغط ثلث بوريه البطاطس في القاع طبقة متساوية بسماكة 1,5 سم، وسوّ السطح بظهر ملعقة مبلّلة. وزّع نصف حشوة التونة أو الدجاج فوق البطاطس طبقة بسماكة 1 سم، مع ترك حافة 5 ملم; رتّب شرائح الأفوكادو فوقها طبقة واحدة متراصة; اضغط ثلثاً ثانياً من بوريه البطاطس فوق الأفوكادو، ثم غطّه بباقي الحشوة وطبقة أخيرة من البوريه. اطوِ الغشاء البلاستيكي فوق السطح واضغط بقوة براحة يدك أو لوح صغير لإحكام التماسك; ضع في الثلاجة لمدة ساعة على الأقل (وحتى 6 ساعات) لتثبيت الطبقات. ارفع التيرين بمساعدة الغشاء، اكشفه، وقطّعه إلى 8 شرائح سخية بسكين ساخن مبلل (اشطف النصل بين القطعات); زيّن كل شريحة بنصف زيتونة وقطعة من البيض المسلوق وغصن من الكزبرة; قدّمه بارداً خلال ساعتين من تقطيعه.","en":"Boil the potatoes in well-salted water (about 1 tbsp salt per litre) for 18–20 minutes, until a knife slides in with no resistance but the potatoes are not falling apart; drain and leave to steam-dry on a rack for 5 minutes. While still warm, pass the potatoes through a ricer or fine sieve into a wide bowl; add the ají amarillo paste, lime juice, oil, 1.5 tsp salt, and white pepper; knead gently with your hands for 2–3 minutes — the mash should be smooth, silky, and slightly elastic, holding its shape when pinched. Taste and adjust with more salt or lime; cover and let cool to room temperature, then chill for 20 minutes to firm slightly. Make the filling; flake the drained tuna (or shred the chicken) into a bowl; add the mayonnaise, spring onions, celery (if using), and 0.5 tsp salt; fold gently — keep visible flakes of fish rather than a smooth purée; chill until needed. Line a 22 × 12 cm loaf tin (or a round 18 cm cake ring) with cling film, leaving a generous overhang; press one-third of the potato mash into the base in an even 1.5 cm layer, using the back of a damp spoon to smooth. Spread half the tuna or chicken filling over the potato in a 1 cm layer, leaving a 5 mm border; arrange the avocado slices on top in a tight overlapping single layer; press a second third of potato over the avocado, then top with the remaining filling and a final layer of potato. Fold the cling film over the top and press firmly with the flat of your hand or a small board to compact the terrine; refrigerate for at least 1 hour (or up to 6 hours) to set the layers. Lift the terrine out using the cling film, peel back, and slice into 8 generous portions with a hot wet knife (rinse the blade between cuts); top each slice with an olive half, a wedge of hard-boiled egg, and a sprig of coriander; serve cold, within 2 hours of slicing."}},{"id":129,"origin":{"ar":"قيرغيزستان","en":"Kyrgyzstan","ro":"Kârgâzstan"},"name":{"ar":"بيشبمارك","en":"Beshbarmak","ro":"Beshbarmak"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ar":["1,2 كغ من كتف الضأن بالعظم أو صدر البقر (أو خليط منهما)، مقطّع 4 قطع كبيرة","3 لترات من الماء البارد","1 ملعقة كبيرة من ملح البحر الناعم، ويُضاف حسب الذوق","1 بصلة، مشطورة (للمرق)","1 جزرة، مشطورة (للمرق)","2 ورقة غار","10 حبات فلفل أسود كاملة","400 غ من الدقيق العادي، مع كمية إضافية للرش","2 بيضة كبيرة","150 مل من الماء الدافئ","1 ملعقة صغيرة من ملح البحر الناعم","2 بصلتان كبيرتان (نحو 350 غ)، مشطورتان ومقطّعتان شرائح رفيعة بشكل نصف هلال","0,5 ملعقة صغيرة من الفلفل الأسود المطحون الطازج","رشّة من السكر","شبت أو بقدونس طازج، مفروم خشناً"],"en":["1.2 kg bone-in lamb shoulder or beef brisket (or a mix), cut into 4 large pieces","3 litres cold water","1 tbsp fine sea salt, plus more to taste","1 onion, halved (for the broth)","1 carrot, halved (for the broth)","2 bay leaves","10 whole black peppercorns","400 g plain (all-purpose) flour, plus extra for dusting","2 large eggs","150 ml warm water","1 tsp fine sea salt","2 large onions (about 350 g), halved and thinly sliced into half-moons","0.5 tsp freshly ground black pepper","Pinch of sugar","Fresh dill or parsley, roughly chopped"],"ro":["1,2 kg umăr de miel sau piept de vită cu os (sau un amestec), tăiat în 4 bucăți mari","3 litri apă rece","1 lingură sare fină de mare, plus după gust","1 ceapă, tăiată în două (pentru bulion)","1 morcov, tăiat în două (pentru bulion)","2 frunze de dafin","10 boabe de piper negru întregi","400 g făină albă obișnuită, plus pentru tăvălit","2 ouă mari","150 ml apă caldă","1 linguriță sare fină de mare","2 cepe mari (aproximativ 350 g), tăiate în două și feliate subțire în semilune","0,5 linguriță piper negru proaspăt măcinat","Un vârf de zahăr","Mărar sau pătrunjel proaspăt, tocat grosier"]},"howIsMade":{"ar":"ضع اللحم في قدر كبير، غمره بالماء البارد، وارفعه ببطء إلى الغليان على نار متوسطة — التسخين البطيء يستخلص أقصى نكهة في المرق; ارفع الرغوة الرمادية بعناية خلال أول 10 دقائق حتى يصفو السطح. أضف 1 ملعقة كبيرة من الملح، البصلة المشطورة، الجزرة، أوراق الغار، وحبات الفلفل; خفّض النار إلى أدنى درجة غليان (الكاد تتحرك السطح) واتركه بدون غطاء 2–2,5 ساعة حتى يتفكّك اللحم عن العظم. خلال طهي اللحم، حضّر العجين; اخلط في وعاء واسع الدقيق و1 ملعقة صغيرة من الملح، اصنع حفرة في الوسط وأضف البيض والماء الدافئ; قلّب بشوكة، ثم اعجن على سطح مرشوش بالدقيق 8–10 دقائق حتى يصبح متماسكاً وأملس ومرناً; غطّ بغشاء بلاستيكي واتركه يرتاح في درجة حرارة الغرفة 30 دقيقة. قسّم العجين المرتاح إلى 4 قطع; اعمل قطعة واحدة في كل مرة مع تغطية الباقي، وافرد العجين على سطح مرشوش بالدقيق إلى أرقّ ما يمكن — حوالي 1 ملم; قطّعه إلى مربعات تقريبية 8 × 8 سم (أو معينات 10 × 5 سم); رشّ الدقيق بسخاء ورتّبها مسطّحة على صينية حتى لا تلتصق. ارفع اللحم من المرق إلى لوح، غطّه بورق ألمنيوم برخاوة ودعه يرتاح; صفِّ المرق إلى قدر نظيف عبر مصفاة ناعمة وتخلّص من الخضار التي طُبخت; اترك المرق على غليان خفيف. اسكب 500 مل من المرق الساخن في قدر صغير منفصل; أضف البصل المشرّح ورشّة سكر واتركه يغلي 5–6 دقائق — يجب أن يظل البصل شفافاً وطرياً للتو، دون أن ينهار; أضف 0,5 ملعقة صغيرة من الفلفل الأسود. اعد المرق المصفّى إلى غليان قوي; أنزل مربعات العجين على دفعات، قلّبها بلطف لتجنّب الالتصاق، واطبخها 3–4 دقائق لكل دفعة حتى تطفو وتصبح متماسكة; ارفعها بمصفاة شقّ وضعها على طبق تقديم دافئ. قطّع اللحم شرائح سميكة عكس اتجاه الأنسجة ووزّعه فوق العجين; اسكب البصل ومرقه بسخاء فوق اللحم; رشّ الشبت المفروم، ثم قدّم لكل ضيف كوباً من المرق الصافي الساخن إلى الجانب ليرتشفه بين اللقمات; قدّمه فوراً وهو يتصاعد منه البخار.","en":"Place the meat in a large stockpot, cover with the cold water, and bring slowly to the boil over medium heat — slow heating draws maximum flavour into the broth; skim the grey foam carefully for the first 10 minutes until the surface runs clear. Add the 1 tbsp salt, halved onion, carrot, bay leaves, and peppercorns; reduce the heat to a bare simmer (the surface should barely move) and cook uncovered for 2–2.5 hours, until the meat is fork-tender and falling from the bone. While the meat simmers, make the dough; whisk the flour and 1 tsp salt in a wide bowl, make a well, and add the eggs and warm water; stir with a fork, then knead on a floured surface for 8–10 minutes until firm, smooth, and elastic; cover with cling film and rest at room temperature for 30 minutes. Divide the rested dough into 4 pieces; working with one piece at a time and keeping the rest covered, roll out as thinly as possible on a floured surface — about 1 mm thick; cut into rough 8 × 8 cm squares (or 10 × 5 cm diamonds); dust generously with flour and lay flat on a tray so they do not stick. Lift the meat out of the broth onto a board, cover loosely with foil, and rest; strain the broth into a clean pot through a fine sieve and discard the boiling vegetables; keep the broth at a gentle simmer. Ladle 500 ml of the hot broth into a separate small pot; add the thinly sliced onions and a pinch of sugar and simmer for 5–6 minutes — the onions should stay translucent and just tender, not collapsed; stir in 0.5 tsp black pepper. Bring the strained broth back to a vigorous boil; drop the dough squares in batches, stir gently to prevent sticking, and cook 3–4 minutes per batch until they float and are al dente; lift out with a slotted spoon onto a warmed serving platter. Slice the meat thickly against the grain and arrange over the noodles; spoon the onions and their broth liberally over the meat; scatter with chopped dill, then ladle a cup of the hot clear broth on the side for each diner to sip between bites; serve immediately while everything is steaming hot."}},{"id":130,"origin":{"ar":"تايلاند","en":"Thailand","ro":"Thailanda"},"name":{"ar":"أرز بجوز الهند","en":"Coconut Rice","ro":"Orez cu lapte de cocos"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"veg","pairingsType":"veg","ingredients":{"ar":["400 غ من الأرز طويل الحبة (الياسمين التايلندي أو البسمتي)","400 مل من حليب جوز الهند كامل الدسم (علبة قياسية واحدة)","250 مل من الماء البارد","1 ملعقة صغيرة من ملح البحر الناعم","1 ملعقة صغيرة من السكر الناعم","2 ورقة باندان طازجة، معقودة (أو 1 ملعقة صغيرة من خلاصة الباندان — اختياري لكنه تقليدي)","1 كراث صغير (نحو 30 غ)، مفروم شرائح رفيعة","1 ساق من عشب الليمون، مهروسة قليلاً (اختياري، لإكساب رائحة جنوب شرق آسيا)","شريط قشر ليمون أخضر بطول 3 سم (اختياري، لإضفاء انتعاش)","1 ملعقة كبيرة من زيت جوز الهند أو زيت محايد","30 غ من جوز الهند المبشور غير المُحلَّى، محمّص قليلاً (للتزيين)","حفنة صغيرة من أوراق الكزبرة الطازجة (للتزيين)"],"en":["400 g long-grain rice (Thai jasmine or basmati)","400 ml full-fat coconut milk (1 standard tin)","250 ml cold water","1 tsp fine sea salt","1 tsp caster sugar","2 fresh pandan leaves, tied into a knot (or 1 tsp pandan extract — optional but traditional)","1 small shallot (about 30 g), finely sliced","1 stalk lemongrass, lightly bruised (optional, for Southeast Asian aroma)","3 cm strip lime zest (optional, for brightness)","1 tbsp coconut oil or neutral oil","30 g unsweetened desiccated coconut, lightly toasted (for garnish)","Small handful fresh coriander leaves (for garnish)"],"ro":["400 g orez cu bob lung (jasmine thailandez sau basmati)","400 ml lapte de cocos integral (1 conservă standard)","250 ml apă rece","1 linguriță sare fină de mare","1 linguriță zahăr tos","2 frunze de pandan proaspete, legate în nod (sau 1 linguriță extract de pandan — opțional, dar tradițional)","1 eșalotă mică (aproximativ 30 g), feliată fin","1 tulpină de lemongrass, ușor zdrobită (opțional, pentru aroma sud-est asiatică)","Coajă de lime de 3 cm, fâșie subțire (opțional, pentru prospețime)","1 lingură ulei de cocos sau ulei neutru","30 g cocos rasă neîndulcită, ușor prăjită (pentru garnitură)","Un pumn mic de frunze de coriandru proaspete (pentru garnitură)"]},"howIsMade":{"ar":"اشطف الأرز جيداً في مصفاة تحت ماء بارد جارٍ لنحو دقيقة، مع تحريكه باليد، حتى يصبح الماء صافياً تقريباً; صفّه جيداً; هذه الخطوة تزيل النشا السطحي وتُبقي الحبوب منفصلة في النهاية. سخّن زيت جوز الهند في قدر بقاع سميك سعة 2 لتر على نار متوسطة; أضف الكراث المشرّح وقلّبه 90 ثانية–2 دقيقة حتى يلين ويأخذ لوناً ذهبياً خفيفاً عند الحواف من دون أن يحمرّ. أضف الأرز المصفّى إلى القدر وقلّبه 30 ثانية ليتغلّف كل حبة بالزيت; اسكب حليب جوز الهند والماء، ثم أضف الملح والسكر وأوراق الباندان المعقودة وعشب الليمون المهروس وقشر الليمون الأخضر. قلّب مرّة واحدة لتذويب الملح وارفعه إلى غليان خفيف على نار متوسطة-عالية — استمر بالتحريك برفق نحو دقيقتين كي لا يلتصق حليب جوز الهند بالقاع. خفّض النار إلى أدنى درجة ممكنة، غطّ بإحكام، واطبخ من دون فتح لمدة 12 دقيقة; لا ترفع الغطاء — البخار المحبوس هو ما يطهو الأرز بانتظام. أطفئ النار (مع إبقاء الغطاء) واترك الأرز يرتاح 10 دقائق — هذا البخار النهائي يجفّف الحبوب ويمنعها من التلاصق. ارفع الغطاء، وتخلّص من الباندان وعشب الليمون وقشر الليمون; فكّ حبيبات الأرز برفق بشوكة، وزّع جوز الهند المحمّص وأوراق الكزبرة فوقه وقدّمه فوراً بجانب كاري أو سامبول أو سمك مشوي.","en":"Rinse the rice thoroughly in a sieve under cold running water for about 1 minute, swirling with your hand, until the water runs almost clear; drain well; this removes surface starch and keeps the grains separate at the end. Heat the coconut oil in a heavy-based 2-litre pan over medium heat; add the sliced shallot and stir-fry for 90 seconds–2 minutes, until softened and lightly golden at the edges but not browned. Add the drained rice to the pan and stir for 30 seconds to coat each grain in oil; pour in the coconut milk and water, then add the salt, sugar, knotted pandan leaves, bruised lemongrass, and lime zest. Stir once to dissolve the salt and bring to a gentle boil over medium-high heat — keep stirring gently for about 2 minutes so the coconut milk does not catch on the base. Lower the heat to the lowest possible setting, cover with a tight-fitting lid, and cook undisturbed for 12 minutes; do not lift the lid — the trapped steam is what cooks the rice evenly. Turn off the heat (leave the pan covered) and rest the rice for 10 minutes — this finishing steam dries the grains and stops them clumping. Lift the lid, remove and discard the pandan, lemongrass, and lime zest; fluff the rice gently with a fork, scatter the toasted desiccated coconut and coriander leaves over the top, and serve immediately alongside curry, sambols, or grilled fish."}},{"id":131,"origin":{"ar":"ماليزيا","en":"Malaysia","ro":"Malaezia"},"name":{"ar":"ناسي لماك","en":"Nasi lemak","ro":"Nasi lemak"},"category":{"ar":"فطور","en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"fish","pairingsType":"fish","ingredients":{"ar":["400 غ من أرز الياسمين طويل الحبة","400 مل من حليب جوز الهند كامل الدسم","200 مل من الماء البارد","1 ملعقة صغيرة من ملح البحر الناعم","2 ورقة باندان طازجة معقودة، مع 1 ساق من عشب الليمون مهروسة و3 شرائح رفيعة من الزنجبيل الطازج (للأرز)","60 غ من الفول السوداني الني المقشّر","60 غ من إيكان بيليس (أنشوجة ماليزية مجففة)","4 بيضات كبيرة","1 خيارة متوسطة (نحو 200 غ)، مقطّعة شرائح بسماكة 5 ملم","10 فلفلات حمراء مجففة، منقوعة في ماء ساخن 15 دقيقة ومصفّاة","4 فلفلات حمراء طازجة (لطيفة)","2 كراث كبير (نحو 120 غ)، مقشّر، مع 3 فصوص ثوم وقطعة زنجبيل طازج بحجم الإبهام (15 غ)","1 ملعقة كبيرة من البلاتشان (معجون الجمبري المحمّص) أو 1,5 ملعقة صغيرة من صلصة السمك كبديل","2 ملعقة كبيرة من معجون التمر الهندي مذابة في 4 ملاعق كبيرة من الماء الدافئ (أو 3 ملاعق كبيرة من عصير الليمون الأخضر)","2 ملعقة كبيرة من سكر النخيل أو السكر البني الداكن","1 بصلة حمراء متوسطة (نحو 120 غ)، مقطّعة حلقات رفيعة","60 مل و250 مل من زيت محايد (60 مل للسامبال؛ الباقي لقلي الأنشوجة والفول السوداني)","0,5 ملعقة صغيرة من ملح البحر الناعم للسامبال"],"en":["400 g long-grain jasmine rice","400 ml full-fat coconut milk","200 ml cold water","1 tsp fine sea salt","2 fresh pandan leaves tied into a knot, plus 1 bruised stalk of lemongrass and 3 thin slices of fresh ginger (for the rice)","60 g raw skinless peanuts","60 g ikan bilis (dried Malaysian anchovies)","4 large eggs","1 medium cucumber (about 200 g), sliced into 5 mm rounds","10 dried red chillies, soaked in hot water for 15 minutes and drained","4 fresh red chillies (mild)","2 large shallots (about 120 g), peeled, plus 3 garlic cloves and 1 thumb-sized piece of fresh ginger (15 g)","1 tbsp belacan (toasted shrimp paste), or 1.5 tsp fish sauce as a substitute","2 tbsp tamarind paste mixed with 4 tbsp warm water (or 3 tbsp lime juice)","2 tbsp palm sugar or dark brown sugar","1 medium red onion (about 120 g), sliced into thin rings","60 ml plus 250 ml neutral oil (split: 60 ml for the sambal, the rest for frying anchovies and peanuts)","0.5 tsp fine sea salt for the sambal"],"ro":["400 g orez jasmine cu bob lung","400 ml lapte de cocos integral","200 ml apă rece","1 linguriță sare fină de mare","2 frunze de pandan proaspete, legate în nod, plus 1 tulpină de lemongrass zdrobită și 3 felii subțiri de ghimbir proaspăt (pentru orez)","60 g arahide crude fără pieliță","60 g ikan bilis (anșoa malaezieni uscați)","4 ouă mari","1 castravete mediu (aproximativ 200 g), tăiat rondele de 5 mm","10 ardei iuți roșii uscați, înmuiați în apă fierbinte 15 minute și scurși","4 ardei iuți roșii proaspeți (blânzi)","2 eșalote mari (aproximativ 120 g), decojite, plus 3 căței de usturoi și o bucată de ghimbir cât degetul mare (15 g)","1 lingură belacan (pastă de creveți prăjită) sau 1,5 linguriță sos de pește ca substitut","2 linguri pastă de tamarin amestecată cu 4 linguri apă caldă (sau 3 linguri suc de lime)","2 linguri zahăr de palmier sau zahăr brun închis","1 ceapă roșie medie (aproximativ 120 g), feliată inele subțiri","60 ml plus 250 ml ulei neutru (împărțit: 60 ml pentru sambal, restul pentru prăjit anșoa și arahide)","0,5 linguriță sare fină de mare pentru sambal"]},"howIsMade":{"ar":"اشطف الأرز في مصفاة تحت ماء بارد جارٍ لدقيقة حتى يصفو الماء تقريباً، ثم صفِّه جيداً; ضعه في قدر بقاع سميك سعة 2 لتر مع حليب جوز الهند والماء وملعقة الملح الصغيرة والباندان وعشب الليمون والزنجبيل; ارفعه إلى غليان خفيف على نار متوسطة-عالية مع تقليبة واحدة; خفّض النار إلى أدنى درجة، غطِّ بإحكام، واطبخ من دون فتح 12 دقيقة; أطفئ النار واتركه يرتاح تحت الغطاء 10 دقائق إضافية — البخار المحبوس يكمل الطهي ويُجفّف الحبوب; أزل الباندان وعشب الليمون والزنجبيل قبل التقديم. خلال طهي الأرز، اقلِ الفول السوداني; سخّن الـ 250 مل من الزيت في مقلاة صغيرة إلى 160 درجة مئوية; اقلِ الفول السوداني 3–4 دقائق حتى يأخذ لوناً ذهبياً فاتحاً (سيتعمّق لونه عند التبريد)، ثم ارفعه بمصفاة شقّ إلى ورق ماص; رشّ ملحاً خفيفاً. جفّف إيكان بيليس بمنديل ورقي; في الزيت نفسه، اقلِه على دفعتين 60–90 ثانية لكل دفعة، مع تقليبة واحدة، حتى يصبح مقرمشاً وذهبياً غامقاً; ارفعه على ورق ماص آخر; احتفظ بالزيت. اسلق البيض: أنزله في ماء يغلي بهدوء واطبخه 8 دقائق بالضبط لصفار متماسك (أو 7 دقائق لصفار شبه طري); انقله فوراً إلى ماء بارد بالثلج 3 دقائق، ثم قشّره واقطعه أنصافاً. حضّر معجون السامبال; ضع الفلفل المجفف المنقوع والفلفل الطازج والكراث والثوم وقطعة الزنجبيل 15 غ والبلاتشان في خلاط أو هاون مع 2 ملعقة كبيرة من الزيت المُحتفظ به، واطحن حتى تحصل على معجون خشن. سخّن 60 مل من الزيت الطازج في ووك أو مقلاة واسعة على نار متوسطة; أضف معجون السامبال واقليه مع تقليب مستمر 12–15 دقيقة حتى ينفصل الزيت على الحواف ويأخذ المعجون لون الطوب الأحمر الداكن; هذا القلي الطويل يُزيل الطعم النيء للمكونات. أضف حلقات البصل الأحمر وماء التمر الهندي وسكر النخيل و0,5 ملعقة صغيرة من الملح; اطبخ بهدوء 6–8 دقائق إضافية حتى يلين البصل ويصبح للسامبال ملمس لامع شبيه بالمربى، يحفظ خطاً نظيفاً عند تمرير الملعقة في وسط المقلاة; تذوّق وعدّل — يجب أن يكون حاراً وحلواً وحامضاً وملحياً بنسب متقاربة. التقديم: ضع حصة من الأرز على كل طبق; أحطها بنصف بيضة مسلوقة وملعقة سخية من السامبال وكومة صغيرة من الفول السوداني وأخرى من الأنشوجة المقرمشة ومروحة من شرائح الخيار; يُؤكل بمزج قليل من كل كومة في كل لقمة.","en":"Rinse the rice in a sieve under cold running water for 1 minute, until the water runs almost clear, then drain well; put it in a heavy 2-litre pan with the coconut milk, water, 1 tsp salt, pandan, lemongrass, and ginger; bring to a gentle boil over medium-high heat, stirring once; lower the heat to the lowest setting, cover with a tight lid, and cook undisturbed for 12 minutes; turn off the heat and rest, covered, for another 10 minutes — the trapped steam finishes cooking and dries the grains; discard the aromatics before serving. While the rice cooks, fry the peanuts; heat the 250 ml oil in a small pan to 160°C; fry the peanuts for 3–4 minutes until pale gold (they will darken as they cool), then lift onto paper towels with a slotted spoon; salt lightly. Pat the ikan bilis dry; in the same oil, fry them in two batches for 60–90 seconds per batch, stirring once, until crisp and deep gold; lift onto a separate sheet of paper; reserve the oil. Hard-boil the eggs: lower them into gently simmering water and cook for exactly 8 minutes for set yolks (or 7 minutes for slightly jammy); transfer immediately to iced water for 3 minutes, then peel and halve. Make the sambal paste; combine the drained dried chillies, fresh chillies, shallots, garlic, the 15 g ginger piece, and belacan in a blender or mortar with 2 tbsp of the reserved oil and process to a coarse paste. Heat 60 ml fresh oil in a wok or wide pan over medium heat; add the sambal paste and fry, stirring continuously, for 12–15 minutes, until the oil splits out around the edges and the paste turns deep brick-red; this long fry is what kills the raw bite of the aromatics. Stir in the red onion rings, tamarind water, palm sugar, and 0.5 tsp salt; simmer for 6–8 minutes more, until the onions are softened and the sambal has a glossy, jammy texture that holds a clean line when you drag a spoon across the pan; taste and balance — it should be hot, sweet, sour, and savoury in roughly equal measure. To serve: mound a portion of rice on each plate; surround with a hard-boiled egg half, a generous spoonful of sambal, a small heap of peanuts, a small heap of crispy anchovies, and a fan of cucumber slices; eat by mixing small amounts from each pile into each bite."}},{"id":132,"origin":{"ar":"سويسرا","en":"Switzerland","ro":"Elveția"},"name":{"ar":"روستي","en":"Rösti","ro":"Rösti"},"category":{"ar":"فطور","en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"veg","pairingsType":"veg","ingredients":{"ar":["1 كغ من البطاطس الشمعية (Yukon Gold أو Charlotte أو ما يشابهها)، غير مقشّرة","60 غ من الزبدة غير المملحة، مقسّمة إلى حصتين 30 غ","2 ملعقة كبيرة من زيت محايد (دوار الشمس أو بذور العنب)، مقسّم إلى حصتين 1 ملعقة كبيرة","1 ملعقة صغيرة من ملح البحر الناعم، ويُضاف حسب الذوق","0,5 ملعقة صغيرة من الفلفل الأسود المطحون الطازج","رشّة من جوزة الطيب المبشورة (اختياري، تقليدي في الإصدار البرني)","1 بصلة صغيرة (نحو 80 غ)، مفرومة فرماً ناعماً جداً (اختياري، تنويعة شائعة)","60 غ من جبن غرويير عتيق، مبشور خشناً (اختياري، لنكهة أغنى)","1 ملعقة كبيرة من ثوم معمر طازج مفروم ناعماً، للتزيين"],"en":["1 kg waxy potatoes (Yukon Gold, Charlotte, or similar), unpeeled","60 g unsalted butter, in two 30 g portions","2 tbsp neutral oil (sunflower or grapeseed), in two 1 tbsp portions","1 tsp fine sea salt, plus more to taste","0.5 tsp freshly ground black pepper","Pinch of grated nutmeg (optional, traditional in Bernese versions)","1 small onion (about 80 g), very finely diced (optional, common variation)","60 g aged gruyère, coarsely grated (optional, for a richer finish)","1 tbsp finely chopped fresh chives, to garnish"],"ro":["1 kg cartofi cu pastă fermă (Yukon Gold, Charlotte sau similari), necurățați","60 g unt nesărat, împărțit în două porții de 30 g","2 linguri ulei neutru (de floarea-soarelui sau de struguri), împărțit în două porții de 1 lingură","1 linguriță sare fină de mare, plus după gust","0,5 linguriță piper negru proaspăt măcinat","Un vârf de nucșoară rasă (opțional, tradițional în versiunea berneză)","1 ceapă mică (aproximativ 80 g), tăiată foarte fin (opțional, variantă obișnuită)","60 g gruyère maturat, ras grosier (opțional, pentru finisare mai bogată)","1 lingură arpagic proaspăt tocat fin, pentru garnitură"]},"howIsMade":{"ar":"في اليوم السابق، اسلق البطاطس بقشرها كاملةً في ماء مالح جيداً (1 ملعقة كبيرة من الملح للتر) لمدة 8–10 دقائق — يجب أن تلقى السكين بعض المقاومة وأن يبقى المركز نيئاً; صفّها واتركها تبرد تماماً; ضعها مكشوفة في الثلاجة طوال الليل ليجف السطح ويتماسك النشا. في اليوم التالي، قشّر البطاطس الباردة — يجب أن تنزلق القشور بسهولة; ابشرها على الفتحات الكبيرة لمبشرة الصندوق إلى خيوط طويلة منتظمة، واعمل بسرعة كي لا تسخن. في وعاء، تبّل البطاطس المبشورة بالملح والفلفل وجوزة الطيب وقلّبها برفق بأطراف الأصابع، دون ضغط، لتبقى الخيوط طويلة. سخّن 1 ملعقة كبيرة من الزيت و30 غ من الزبدة في مقلاة بقطر 24 سم غير لاصقة أو حديدية مُعتّقة على نار متوسطة حتى تتكوّن رغوة الزبدة وتأخذ لون البندق; أضف البصل المفروم (إن وُجد) واطبخه 90 ثانية–2 دقيقة حتى يلين ويأخذ لوناً ذهبياً خفيفاً. أضف البطاطس المتبّلة إلى المقلاة في طبقة واحدة متساوية، اضغطها برفق بظهر الملعقة لتشكيل قرص بسماكة 1,5 سم وقطر نحو 22 سم — لا تضغطها بشدة، فالفجوات الهوائية هي ما تمنح المركز قرمشة; اطبخ من دون تحريك 8–10 دقائق حتى تصبح القاعدة ذهبية غامقة وتنفصل نظيفة عند تمرير الملعقة تحتها. ضع طبقاً مسطحاً فوق المقلاة واقلب الروستي عليه، ثم أعِده إلى المقلاة مع توجيه الجانب المطهو للأعلى; أضف 30 غ المتبقية من الزبدة و1 ملعقة كبيرة من الزيت حول الحواف لتنزلق أسفل القرص; اطبخ 7–9 دقائق إضافية حتى يصبح الوجه الثاني ذهبياً غامقاً بالقدر نفسه ويكون المركز ساخناً وطرياً (سكين رفيع غُرز في المنتصف يجب ألّا يلقى مقاومة). انقل الروستي إلى لوح خشبي، ورشّه بجبن الغرويير المبشور إن أردت (الحرارة المتبقية تذيبه قليلاً)، وزيّنه بثوم معمر مفروم وقطّعه إلى 4 شرائح; قدّمه فوراً مع بيضة مقلية فوقه أو لحم خنزير مدخن أو سجق براتفورست.","en":"The day before, parboil the potatoes whole and unpeeled in well-salted water (1 tbsp salt per litre) for 8–10 minutes — a knife should meet some resistance, the centre should still be raw; drain and cool completely; refrigerate uncovered overnight so the surface dries and the starches firm up. The next day, peel the cold potatoes — the skins should slip off easily; grate them on the large holes of a box grater into long, even shreds, working briskly so they do not warm. In a bowl, season the grated potatoes with the salt, pepper, and nutmeg, and toss gently to distribute — use your fingertips, not a heavy hand, so the strands stay long. Heat 1 tbsp oil and 30 g of the butter in a 24 cm non-stick or well-seasoned cast-iron pan over medium heat until the butter foams and just turns nut-brown; add the diced onion (if using) and cook for 90 seconds–2 minutes, until soft and lightly golden. Add the seasoned potato to the pan in one even layer, lightly pressing with the back of a spatula to form a 1.5 cm cake about 22 cm across — do not pack it down hard, the air gaps are what crisp the inside; cook undisturbed for 8–10 minutes, until the underside is deep golden brown and pulls cleanly from the pan when you slide a spatula under it. Hold a flat plate over the pan, invert the rösti onto it, then slide it back into the pan with the cooked side up; add the remaining 30 g butter and 1 tbsp oil around the edges so they run under the cake; cook for a further 7–9 minutes, until the second side is equally deep golden and the centre is hot and tender (a paring knife pushed into the middle should meet no resistance). Slide the rösti onto a board, scatter with the grated gruyère if using (the residual heat will melt it lightly), top with chopped chives, and cut into 4 wedges; serve immediately with a fried egg on top, smoked ham, or Bratwurst."}},{"id":133,"origin":{"ar":"رومانيا","en":"Romania","ro":"România"},"name":{"ar":"فاصوليا مع النقانق","en":"Beans with Sausages","ro":"Fasole cu cârnați"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ar":["500 غ من الفاصوليا البيضاء الجافة (كانيليني، نيفي، أو الفاصوليا اليونانية العملاقة)، منقوعة طوال الليل في ماء بارد","4 نقانق لحم خنزير مدخنة (نحو 500 غ؛ مثل كرنا تسي بليشكوي أو نقانق بولندية مدخنة)","150 غ من اللحم المقدد المدخن (كايزر) أو ضلوع خنزير مدخنة، مقطّعة قطعاً 2 سم (اختياري، لإضفاء عمق)","2 بصلتان كبيرتان (نحو 350 غ)، مفرومتان ناعماً","2 جزرة متوسطة (نحو 200 غ)، مفرومتان ناعماً","1 فلفل رومي أحمر متوسط، مفروم ناعماً","4 فصوص ثوم، مفرومة ناعماً","3 ملاعق كبيرة من معجون الطماطم","200 غ من الطماطم المهروسة المعلّبة (أو حبتا طماطم طازجة مبشورتان)","3 ورقات غار","1 ملعقة صغيرة من الفلفل الأحمر الحلو","0,5 ملعقة صغيرة من الزعتر المجفف (أو 1 غصن طازج)","0,5 ملعقة صغيرة من الفلفل الأسود المطحون الطازج","1,5 ملعقة صغيرة من ملح البحر الناعم، ويُضاف حسب الذوق","60 مل من زيت دوار الشمس (أو 30 غ من الشحم)","1,5–2 لتر من الماء (أو مرق دجاج بلا ملح لنكهة أغنى)","2 ملعقة كبيرة من الشبت أو البقدونس الطازج المفروم، للتقديم النهائي","1 ملعقة كبيرة من خل النبيذ الأبيض (اختياري، لموازنة المذاق في النهاية)"],"en":["500 g dried white beans (cannellini, navy, or Greek elephant), soaked overnight in cold water","4 smoked pork sausages (about 500 g; e.g. cârnați Pleșcoi or smoked Polish sausage)","150 g smoked bacon (kaiser) or smoked pork ribs, cut into 2 cm pieces (optional, for extra depth)","2 large onions (about 350 g), finely diced","2 medium carrots (about 200 g), finely diced","1 medium red bell pepper, finely diced","4 garlic cloves, finely chopped","3 tbsp tomato paste","200 g canned crushed tomatoes (or 2 fresh tomatoes, grated)","3 bay leaves","1 tsp sweet paprika","0.5 tsp dried thyme (or 1 sprig fresh)","0.5 tsp freshly ground black pepper","1.5 tsp fine sea salt, plus more to taste","60 ml sunflower oil (or 30 g lard)","1.5–2 litres water (or unsalted chicken stock for richer flavour)","2 tbsp finely chopped fresh dill or parsley, to finish","1 tbsp white wine vinegar (optional, to balance at the end)"],"ro":["500 g fasole albă uscată (cannellini, navy sau fasole gigant grecească), înmuiată peste noapte în apă rece","4 cârnați afumați de porc (aproximativ 500 g, ex. cârnați Pleșcoi sau cârnați polonezi afumați)","150 g kaiser afumat sau coaste de porc afumate, tăiate bucăți de 2 cm (opțional, pentru profunzime)","2 cepe mari (aproximativ 350 g), tocate fin","2 morcovi medii (aproximativ 200 g), tocați mărunt","1 ardei kapia roșu mediu, tocat fin","4 căței de usturoi, tocați fin","3 linguri bulion (pastă de roșii)","200 g roșii sfărâmate din conservă (sau 2 roșii proaspete, date pe răzătoare)","3 foi de dafin","1 linguriță boia dulce","0,5 linguriță cimbru uscat (sau 1 crenguță proaspătă)","0,5 linguriță piper negru proaspăt măcinat","1,5 lingurițe sare fină de mare, plus după gust","60 ml ulei de floarea-soarelui (sau 30 g untură)","1,5–2 litri apă (sau supă neagră de pui pentru o aromă mai bogată)","2 linguri mărar sau pătrunjel proaspăt tocat fin, pentru finisare","1 lingură oțet de vin alb (opțional, pentru echilibru la final)"]},"howIsMade":{"ar":"في الليلة السابقة، ضع الفاصوليا الجافة في وعاء كبير، غمرها بـ 2 لتر على الأقل من الماء البارد، واتركها تنقع 8–12 ساعة; سيتضاعف حجمها تقريباً وتفقد كثيراً من السكريات المسببة للغازات. في اليوم التالي، صفِّ الفاصوليا واشطفها; ضعها في قدر سميك مع ماء طازج يغطّيها بـ 5 سم، ارفعها إلى الغليان واتركها مكشوفة 10 دقائق; صفِّها مرة أخرى — هذا الغليان السريع الأول يخفّف من حدّتها ويُقصّر زمن الطهي النهائي. أعد الفاصوليا إلى القدر مع 1,5 لتر ماء طازج (أو مرق)، قطع اللحم المقدد المدخن (إن وُجدت)، و2 ورقة غار; ارفعها إلى غليان خفيف واطبخها مغطّاة جزئياً 50–60 دقيقة — يجب أن تكون طريّة بالكاد دون أن تتفتت; لا تضف الملح بعد (الملح في هذه المرحلة يجعل القشرة قاسية). خلال طهي الفاصوليا، سخّن الزيت في مقلاة عميقة واسعة على نار متوسطة; أضف البصل المفروم ورشّة سخيّة من الملح وقلِّه 8–10 دقائق مع التحريك المتكرر حتى يلين ويتحول إلى ذهبي عند الحواف; أضف الجزر والفلفل الأحمر واطبخهما 5–6 دقائق أخرى حتى يلينا. ادفع الخضار إلى جانب من المقلاة، أضف الثوم في المساحة الفارغة واطبخه 30 ثانية، ثم أدرج الفلفل الأحمر الحلو والزعتر — حمّصها 20–30 ثانية حتى تفوح رائحتها; أضف معجون الطماطم والطماطم المهروسة واطبخها مع التحريك 3–4 دقائق حتى يصبح لون الطماطم أعمق ويتجمّع الزيت على الحواف. قطّع 2 من النقانق إلى حلقات بسماكة 2 سم؛ واحتفظ بالنقانق الأخرى كاملةً للأعلى; أضف النقانق المقطعة إلى قاعدة الطماطم واطبخها 2–3 دقائق لاستخراج بعض الدهن. اسكب قدر الفاصوليا مع سائلها في قاعدة الطماطم، أضف ورقة الغار المتبقية و1,5 ملعقة صغيرة من الملح والفلفل الأسود; اغرس النقانق الكاملة في الطبخة; اطبخها مكشوفة 35–45 دقيقة مع التحريك من حين لآخر، حتى تنضج الفاصوليا ويصبح السائل صلصة خفيفة تغلّف ظهر الملعقة; أضف رشّة ماء إذا غلظت كثيراً. تذوّق وعدّل بالملح، وأضف خل النبيذ الأبيض إن استخدمته (لمسة حموضة تُلمّع نكهة التدخين); أخرج النقانق الكاملة وقطّعها بشكل قطري; اسكب الفاصوليا في أوعية عميقة، ضع فوق كل وعاء مروحة من شرائح النقانق، ورشّ الشبت المفروم، وقدّمها مع مخللات وخبز ريفي أو بولينتا.","en":"The night before, place the dried beans in a large bowl, cover with at least 2 litres of cold water, and leave to soak for 8–12 hours; they will roughly double in size and lose much of the gas-producing sugars. The next day, drain and rinse the beans; put them in a heavy pot with fresh water to cover by 5 cm, bring to a boil, and cook uncovered for 10 minutes; drain again — this first quick boil mellows the beans and shortens the final cooking time. Return the beans to the pot with 1.5 litres of fresh water (or stock), the smoked bacon (if using), and 2 of the bay leaves; bring to a gentle simmer and cook partially covered for 50–60 minutes — the beans should be just tender but not falling apart; do not salt yet (salt at this stage toughens the skins). While the beans simmer, heat the oil in a wide deep pan over medium heat; add the diced onions and a generous pinch of salt and cook for 8–10 minutes, stirring often, until soft and golden brown at the edges; add the carrots and red bell pepper and cook for another 5–6 minutes, until softened. Push the vegetables to one side, add the garlic to the empty space and cook for 30 seconds, then stir in the paprika and thyme — toast for 20–30 seconds until fragrant; add the tomato paste and crushed tomatoes and cook, stirring, for 3–4 minutes, until the tomato is deeper red and the oil splits out around the edges. Slice 2 of the smoked sausages into 2 cm rounds; keep the other 2 whole for the top; add the sliced sausage to the tomato base and cook for 2–3 minutes to render some fat. Tip the bean pot and its liquid into the tomato base, add the remaining bay leaf, the 1.5 tsp salt, and the black pepper; bury the whole sausages in the stew; simmer uncovered for 35–45 minutes, stirring occasionally, until the beans are soft and the liquid has thickened to a thin gravy that coats the back of a spoon; add a splash of water if it tightens too much. Taste, adjust with salt, and add the white wine vinegar if using (a touch of acid brightens the smoke); lift out the whole sausages and slice on the diagonal; ladle the beans into deep bowls, top each with a fan of sausage slices, scatter with chopped dill, and serve with pickles and crusty bread or polenta."}},{"id":134,"origin":{"ar":"المجر","en":"Hungary","ro":"Ungaria"},"name":{"ar":"دجاج بابريكا","en":"Chicken Paprikash","ro":"Chicken Paprikash"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ar":["1,5 كغ من أفخاذ وأوراك الدجاج بالعظم والجلد (نحو 8 قطع)","2 بصلتان كبيرتان (نحو 400 غ)، مفرومتان ناعماً","3 ملاعق كبيرة من بابريكا مجرية حلوة (Édesnemes، ويُفضّل من كالوكشا أو سيكيد)، مع 0,5 ملعقة صغيرة من بابريكا مجرية حارة (اختياري)","3 فصوص ثوم، مفرومة ناعماً","1 فلفل رومي أحمر متوسط، مفروم ناعماً","1 طماطمة متوسطة (نحو 100 غ)، مقشّرة ومفرومة ناعماً (أو 2 ملعقة كبيرة من معجون الطماطم)","60 غ من الشحم (أو 4 ملاعق كبيرة من زيت محايد)","500 مل من مرق دجاج ساخن بلا ملح أو ماء","200 غ من كريمة حامضة كاملة الدسم (بنسبة دسم لا تقل عن 20% — لا تستخدم النوع خفيف الدسم لأنه ينفصل)","1 ملعقة كبيرة من الدقيق العادي","1,5 ملعقة صغيرة من ملح البحر الناعم، ويُضاف حسب الذوق","0,5 ملعقة صغيرة من الفلفل الأسود المطحون الطازج","1 ملعقة صغيرة من بذور الكراويا (اختياري، تقليدي في بعض المناطق)","شبت أو بقدونس طازج مفروم، للتزيين"],"en":["1.5 kg bone-in, skin-on chicken thighs and drumsticks (about 8 pieces)","2 large onions (about 400 g), finely diced","3 tbsp sweet Hungarian paprika (Édesnemes, preferably from Kalocsa or Szeged), plus 0.5 tsp hot Hungarian paprika (optional)","3 garlic cloves, finely chopped","1 medium red bell pepper, finely diced","1 medium tomato (about 100 g), peeled and finely diced (or 2 tbsp tomato paste)","60 g lard (or 4 tbsp neutral oil)","500 ml hot unsalted chicken stock or water","200 g full-fat sour cream (at least 20% fat — do NOT use light sour cream, it will split)","1 tbsp plain (all-purpose) flour","1.5 tsp fine sea salt, plus more to taste","0.5 tsp freshly ground black pepper","1 tsp caraway seeds (optional, traditional in some regions)","Fresh dill or parsley, chopped, to garnish"],"ro":["1,5 kg pulpe și copane de pui cu os și piele (aproximativ 8 bucăți)","2 cepe mari (aproximativ 400 g), tocate fin","3 linguri paprika dulce maghiară (Édesnemes, de preferință din Kalocsa sau Szeged), plus 0,5 linguriță paprika iute maghiară (opțional)","3 căței de usturoi, tocați fin","1 ardei gras roșu mediu, tăiat cuburi mici","1 roșie medie (aproximativ 100 g), curățată și tăiată cuburi mici (sau 2 linguri pastă de roșii)","60 g untură (sau 4 linguri ulei neutru)","500 ml supă de pui fierbinte nesărată sau apă","200 g smântână grasă (cel puțin 20% grăsime — NU smântână ușoară, se taie)","1 lingură făină albă","1,5 lingurițe sare fină de mare, plus după gust","0,5 linguriță piper negru proaspăt măcinat","1 linguriță semințe de chimen (opțional, tradițional în unele regiuni)","Mărar sau pătrunjel proaspăt tocat, pentru garnitură"]},"howIsMade":{"ar":"جفّف الدجاج بمناديل ورقية وتبّل الجانبين بـ 1 ملعقة صغيرة من الملح والفلفل الأسود; اتركه يستريح 15 دقيقة في درجة حرارة الغرفة. اذب الشحم في قدر ثقيل بقطر 28 سم أو مقلاة عميقة واسعة على نار متوسطة-عالية; بدفعتين، اقلِ الدجاج بالجلد لأسفل 4–5 دقائق، ثم 3 دقائق على الجهة الأخرى، حتى يصبح الجلد ذهبياً غامقاً — لا تكدّس المقلاة; ارفعه على طبق. خفّض النار إلى متوسطة وتخلص من الدهن المذاب مع الإبقاء على نحو 3 ملاعق كبيرة; أضف البصل ورشّة ملح واطبخه 12–15 دقيقة مع التحريك المتكرر، حتى يلين ويصبح لامعاً وذهبياً تماماً — هذا الطهي البطيء هو أساس نكهة الباباريكاش. أضف الثوم والفلفل الأحمر وبذور الكراويا (إن استخدمت) واطبخها 2–3 دقائق إضافية حتى يلين الفلفل قليلاً. ارفع المقلاة عن النار تماماً; أدرج البابريكا الحلوة (والحارة إن استخدمت) — البابريكا تحترق وتصبح مرّة على النار المباشرة، لذا يجب أن تكون المقلاة بعيدة عن النار عند إضافتها; قلّب 30 ثانية حتى يتلوّن البصل بلون قرميدي عميق وتفوح رائحة التوابل دافئة وحلوة. أعد المقلاة إلى نار متوسطة; أضف الطماطم المفرومة (أو معجون الطماطم) وقلّب لدقيقة; اسكب المرق الساخن و0,5 ملعقة صغيرة الملح المتبقية، ثم ضع الدجاج في الصلصة بالجلد لأعلى; ارفعها إلى غليان خفيف. غطّ القدر واطبخه على أدنى نار 35–45 دقيقة حتى ينفصل اللحم بسهولة عن العظم وتبلغ درجة حرارته الداخلية 75 درجة مئوية; انقل الدجاج إلى طبق دافئ وغطّه بورق ألمنيوم بينما تنهي الصلصة. اخفق الدقيق مع الكريمة الحامضة حتى ينعم، ثم أضف مغرفة من الصلصة الساخنة لتعديل درجة الحرارة; مع رفع القدر عن النار، اسكب الكريمة المعدّلة في الصلصة وقلّب حتى تصبح حريرية; أعد الدجاج إلى الصلصة لتسخينه فقط، تذوّق وعدّل الملح، ثم قدّمه فوق نوكيدلي أو معكرونة طازجة أو شعيرية بالزبدة، مع رش الشبت المفروم فوقه.","en":"Pat the chicken dry with paper towels and season both sides with 1 tsp of the salt and the black pepper; rest at room temperature for 15 minutes. Melt the lard in a heavy 28 cm Dutch oven or wide deep pan over medium-high heat; working in two batches, sear the chicken skin-side down for 4–5 minutes, then 3 minutes on the other side, until the skin is deep golden — do not crowd the pan; lift onto a plate. Reduce the heat to medium and pour off all but about 3 tbsp of the rendered fat; add the onions and a pinch of salt and cook for 12–15 minutes, stirring often, until soft, glossy, and fully golden — this slow sweat is the foundation of paprikash flavour. Add the garlic, red bell pepper, and caraway seeds (if using) and cook for another 2–3 minutes, until the pepper is just softened. Take the pan off the heat completely; stir in the sweet paprika (and hot paprika if using) — paprika scorches and turns bitter on direct heat, so the pan must be off when it goes in; stir for 30 seconds until the onions are stained a deep brick red and the spice smells warm and sweet. Return the pan to medium heat; add the diced tomato (or tomato paste) and stir for 1 minute; pour in the hot stock and the remaining 0.5 tsp salt, then nestle the chicken back into the sauce, skin-side up; bring to a gentle simmer. Cover and braise on the lowest heat for 35–45 minutes, until the chicken pulls easily from the bone and the internal temperature reads 75°C; lift the chicken onto a warm plate and tent with foil while you finish the sauce. Whisk the flour into the sour cream until smooth, then whisk in a ladle of the hot pan sauce to temper; off the heat, pour the tempered cream back into the pan and stir until silky; return the chicken to the sauce just to warm through, taste and adjust salt, then serve over nokedli, fresh pasta, or buttered noodles with chopped dill on top."}},{"id":135,"origin":{"ar":"إيطاليا","en":"Italy","ro":"Italia"},"name":{"ar":"باستا ألا نورما","en":"Pasta alla Norma","ro":"Pasta alla Norma"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"pasta","pairingsType":"italian","ingredients":{"ar":["2 حبتا باذنجان متوسطتان (نحو 700 غ في المجموع)، بقشرهما، مقطّعتان مكعبات بحجم 2 سم","1,5 ملعقة صغيرة من ملح البحر الناعم لتمليح الباذنجان، مع إضافة لماء سلق المعكرونة","300 مل من زيت الزيتون البكر الممتاز لقلي الباذنجان","400 غ من معكرونة الريغاتوني أو البيني ريغاتي أو الماكاروني","3 ملاعق كبيرة من زيت الزيتون البكر الممتاز للصلصة","3 فصوص ثوم، مقطّعة شرائح رفيعة","0,5 ملعقة صغيرة من رقائق الفلفل الحار الجاف (اختياري)","800 غ من الطماطم الكاملة المقشّرة (سان مارزانو إن وُجد)، مهروسة باليد، أو 700 غ من الباساتا","1 ملعقة صغيرة من السكر الناعم (فقط إذا كانت الطماطم حامضة)","0,5 ملعقة صغيرة من الفلفل الأسود المطحون الطازج","حزمة كبيرة من الريحان الطازج (نحو 30 غ)، أوراقه ممزقة باليد","120 غ من جبن الريكوتا سالاتا، مبشور ناعماً، مع المزيد للتقديم","1 ملعقة كبيرة من ملح البحر الخشن لماء المعكرونة"],"en":["2 medium aubergines (about 700 g total), unpeeled, cut into 2 cm cubes","1.5 tsp fine sea salt for salting the aubergine, plus more for the pasta water","300 ml extra-virgin olive oil for shallow-frying the aubergine","400 g rigatoni, penne rigate, or maccheroni","3 tbsp extra-virgin olive oil for the sauce","3 garlic cloves, sliced thin","0.5 tsp dried chilli flakes (optional)","800 g whole peeled tomatoes (San Marzano if available), crushed by hand, or 700 g passata","1 tsp caster sugar (only if the tomatoes are sharp)","0.5 tsp freshly ground black pepper","1 large bunch fresh basil (about 30 g), leaves picked and torn","120 g ricotta salata, finely grated, plus more to serve","1 tbsp coarse sea salt for the pasta water"],"ro":["2 vinete medii (aproximativ 700 g în total), necurățate, tăiate cuburi de 2 cm","1,5 lingurițe sare fină de mare pentru asezonarea vinetelor, plus mai multă pentru apa pastelor","300 ml ulei de măsline extravirgin pentru prăjit vinetele","400 g rigatoni, penne rigate sau maccheroni","3 linguri ulei de măsline extravirgin pentru sos","3 căței de usturoi, feliați subțire","0,5 linguriță fulgi de ardei iute uscat (opțional)","800 g roșii întregi, decojite (San Marzano dacă e posibil), zdrobite cu mâna, sau 700 g pasată","1 linguriță zahăr tos (doar dacă roșiile sunt acrișoare)","0,5 linguriță piper negru proaspăt măcinat","1 legătură mare de busuioc proaspăt (aproximativ 30 g), frunzele rupte","120 g ricotta salata, rasă fin, plus în plus pentru servit","1 lingură sare grunjoasă de mare pentru apa pastelor"]},"howIsMade":{"ar":"قلّب مكعبات الباذنجان مع 1,5 ملعقة صغيرة من الملح الناعم في مصفاة واتركها تنزّ فوق وعاء لمدة 30 دقيقة — هذا يستخرج الماء المرّ ويمنع الباذنجان من امتصاص كمية كبيرة من الزيت أثناء القلي; اضغطها قليلاً بمنشفة ورقية وجفّفها. سخّن 300 مل من زيت الزيتون في مقلاة عميقة واسعة إلى 170 درجة مئوية; جرّب بقطعة باذنجان واحدة — يجب أن تفور بقوة; اقلِ الباذنجان على ثلاث دفعات لمدة 3–4 دقائق لكل دفعة، مع التقليب المتكرر، حتى يصبح ذهبياً غامقاً من جميع الجوانب وطرياً من الداخل (السكين تخترقه بسهولة); ارفعه بمصفاة شقّ إلى ورق ماص; خصّصه جانباً. خلال قلي الباذنجان، ارفع قدراً كبيراً فيه 4 لترات من الماء و1 ملعقة كبيرة من الملح الخشن إلى غليان قوي. في مقلاة سوتيه واسعة، سخّن 3 ملاعق كبيرة من زيت الزيتون على نار متوسطة; أضف شرائح الثوم ورقائق الفلفل الحار (إن وُجدت) واطبخه 60–90 ثانية — يجب أن يصبح الثوم ذهبياً فاتحاً عند الحواف فقط، دون أن يحمرّ. أضف الطماطم المهروسة والسكر (إن وُجد) و0,5 ملعقة صغيرة من الملح والفلفل; قلّب وارفعه إلى غليان خفيف; اطبخه 12–15 دقيقة مع التحريك من حين لآخر، حتى تتكاثف الصلصة قليلاً ويصعد الزيت إلى السطح; في الدقيقة الأخيرة، أضف نصف الريحان الممزّق. ضع المعكرونة في الماء المغلي واطبخها دقيقة أقل من تعليمات العبوة لتكون al dente; احتفظ بـ 250 مل من ماء السلق النشوي ثم صفِّها. أدمج الباذنجان المقلي مع صلصة الطماطم، ثم أضف المعكرونة المصفّاة; قلّبها بقوة على نار متوسطة 1–2 دقيقة مع إضافة رشّات من ماء السلق حسب الحاجة، حتى تتعلق الصلصة لامعة بكل قطعة — يجب أن تسيل عند إمالة المقلاة دون أن تكون مائية. ارفع المقلاة عن النار، رشّ نصف الريكوتا سالاتا المبشورة ومعظم الريحان المتبقي وقلّب مرة واحدة; وزّع المعكرونة بين أربعة أوعية دافئة، وأنهِ كلاً منها بمزيد من الريكوتا سالاتا وأوراق الريحان الأخيرة وخيط من زيت الزيتون النيء; قدّم فوراً.","en":"Toss the aubergine cubes with the 1.5 tsp fine salt in a colander and leave to drain over a bowl for 30 minutes — this draws out bitter water and stops the aubergine from drinking too much oil during frying; press lightly with a paper towel and pat dry. Heat the 300 ml olive oil in a wide deep frying pan to 170°C; test with a single aubergine cube — it should sizzle briskly; fry the aubergine in three batches for 3–4 minutes per batch, turning often, until deeply golden on all sides and tender inside (a knife should pass through easily); lift onto paper towels with a slotted spoon to drain; reserve. While the aubergine fries, bring a large pot with 4 litres of water and 1 tbsp coarse salt to a rolling boil. In a wide sauté pan, heat the 3 tbsp olive oil over medium heat; add the sliced garlic and chilli flakes (if using) and cook for 60–90 seconds — the garlic should just turn pale gold around the edges, never brown. Add the crushed tomatoes, the sugar (if using), 0.5 tsp salt, and the black pepper; stir and bring to a simmer; cook for 12–15 minutes, stirring occasionally, until the sauce has thickened slightly and the oil rises to the surface; tear in half of the basil for the last minute. Drop the pasta into the boiling water and cook 1 minute less than the package says for al dente; reserve 250 ml of starchy pasta water, then drain. Fold the fried aubergine into the tomato sauce, then add the drained pasta; toss vigorously over medium heat for 1–2 minutes, adding splashes of pasta water as needed, until the sauce clings glossy to every piece — it should be loose enough to flow when you tilt the pan but not watery. Off the heat, scatter half the grated ricotta salata and most of the remaining basil and toss once; divide between four warmed bowls, finish each with more ricotta salata, the last basil leaves, and a drizzle of raw olive oil; serve immediately."}},{"id":137,"origin":{"ar":"تركمانستان","en":"Turkmenistan","ro":"Turkmenistan"},"name":{"ar":"إيشلكلي","en":"Ichlekli","ro":"Ichlekli"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ar":["500 غ من الدقيق العادي، مع كمية إضافية للفرد","1 ملعقة صغيرة من ملح البحر الناعم","240 مل من الماء الدافئ","1 ملعقة كبيرة من زيت محايد (دوار الشمس أو بذور العنب)","500 غ من كتف الضأن أو لحم البقر، مفروم ناعماً (أو مقطع مكعبات صغيرة ومدقوق نبضياً في الكبّاش)","100 غ من شحم ذيل الخروف أو شحم البقر، مقطع مكعبات صغيرة (أو 30 غ من الزبدة غير المملحة كبديل)","2 بصلتان كبيرتان (نحو 350 غ)، مفرومتان ناعماً","200 غ من البطاطس الشمعية، مقشّرة ومقطّعة مكعبات 5 ملم (اختياري لكنه تقليدي)","1,5 ملعقة صغيرة من ملح البحر الناعم","1 ملعقة صغيرة من الفلفل الأسود المطحون الطازج","1 ملعقة صغيرة من الكمون المطحون","0,5 ملعقة صغيرة من الكزبرة المطحونة","0,5 ملعقة صغيرة من رقائق الفلفل الحار الجاف (اختياري)","1 صفار بيضة كبيرة مخفوق مع 1 ملعقة كبيرة من الحليب، للدهن"],"en":["500 g plain (all-purpose) flour, plus extra for rolling","1 tsp fine sea salt","240 ml warm water","1 tbsp neutral oil (sunflower or grapeseed)","500 g lamb shoulder or beef chuck, finely minced (or coarsely diced and pulsed in a processor)","100 g lamb-tail fat or beef suet, finely diced (or 30 g unsalted butter as substitute)","2 large onions (about 350 g), finely diced","200 g waxy potatoes, peeled and diced into 5 mm cubes (optional but traditional)","1.5 tsp fine sea salt","1 tsp freshly ground black pepper","1 tsp ground cumin","0.5 tsp ground coriander","0.5 tsp dried red pepper flakes (optional)","1 large egg yolk, beaten with 1 tbsp milk, for brushing"],"ro":["500 g făină albă obișnuită, plus pentru întins","1 linguriță sare fină de mare","240 ml apă caldă","1 lingură ulei neutru (de floarea-soarelui sau de struguri)","500 g umăr de miel sau pulpă de vită, tocate fin (sau cuburi mărunte pulsate într-un robot)","100 g grăsime de coadă de miel sau seu de vită, tăiate fin (sau 30 g unt nesărat ca substitut)","2 cepe mari (aproximativ 350 g), tocate fin","200 g cartofi cu pastă fermă, curățați și tăiați cuburi de 5 mm (opțional, dar tradițional)","1,5 lingurițe sare fină de mare","1 linguriță piper negru proaspăt măcinat","1 linguriță chimion măcinat","0,5 linguriță coriandru măcinat","0,5 linguriță fulgi de ardei iute uscat (opțional)","1 gălbenuș mare bătut cu 1 lingură de lapte, pentru uns"]},"howIsMade":{"ar":"حضّر العجين; اخفق في وعاء واسع الدقيق والملح; اصنع حفرة في الوسط، اسكب الماء الدافئ والزيت وقلّب بملعقة خشبية حتى تتكون عجينة خشنة; اعجن على سطح مرشوش بالدقيق 6–8 دقائق حتى تصبح ناعمة ومتماسكة ومرنة — أصلب قليلاً من عجينة الخبز; لفّها بغشاء بلاستيكي واتركها ترتاح 30 دقيقة في درجة حرارة الغرفة بينما تحضّر الحشوة. في وعاء كبير، اخلط اللحم المفروم والشحم والبصل ومكعبات البطاطس (إن وُجدت) والملح والفلفل والكمون والكزبرة ورقائق الفلفل الحار; اعجن باليدين دقيقة واحدة حتى يصبح المزيج لزجاً ومتماسكاً جيداً; لا تطهوه مسبقاً — الحشوة تنضج داخل العجين. سخّن الفرن إلى 220 درجة مئوية (425 درجة فهرنهايت / مروحة 200 درجة مئوية) وضع صينية ثقيلة مقلوبة أو حجر بيتزا على الرف الأوسط ليسخن مدة 20 دقيقة على الأقل; السطح الساخن هو ما يجعل القاع مقرمشاً. قسّم العجين المرتاح إلى قطعتين متساويتين; على سطح مرشوش بالدقيق، افرد قطعة إلى قرص قطره 32 سم وسماكته نحو 2 ملم — اجعل الحواف أرق من الوسط حتى لا يكون الإغلاق سميكاً. انقل القرص إلى ورقة خبز; وزّع الحشوة بالتساوي فوق القرص مع ترك حافة 2 سم، واضغطها برفق إلى طبقة بسماكة 1,5 سم. افرد القطعة الثانية إلى قرص 32 سم وضعه فوقها; اضغط الطبقتين معاً بإحكام عند الحافة، ثم لفّ الحافة واقرصها للداخل بشكل حبل ضيق حتى لا يفلت العصير. ادهن الوجه بصفار البيض واغرز الوسط في 6–8 مواضع بشوكة لتفريغ البخار; انقل الفطيرة مع ورق الخبز إلى الصينية الساخنة داخل الفرن; اخبزها 30–35 دقيقة حتى يصبح الوجه ذهبياً غامقاً ويُصدر القاع صوتاً أجوف عند النقر. اترك الفطيرة على لوح 5 دقائق ليستقر البخار وتتماسك الحشوة، ثم قطّعها بسكين حادة إلى 8 شرائح; قدّمها ساخنة مع شاي أخضر أو زبادي ساده أو حليب متخمر.","en":"Make the dough; whisk the flour and salt in a wide bowl; make a well, pour in the warm water and oil, and stir with a wooden spoon until a shaggy dough forms; knead on a lightly floured surface for 6–8 minutes until smooth, firm, and elastic — slightly stiffer than bread dough; wrap in cling film and rest at room temperature for 30 minutes while you prepare the filling. In a large bowl, combine the minced lamb, fat, onions, potato cubes (if using), salt, pepper, cumin, coriander, and pepper flakes; mix with your hands for 1 minute until the mixture is sticky and well bound; do not pre-cook — the filling cooks inside the dough. Heat the oven to 220°C (425°F / fan 200°C) and place an upturned heavy baking tray or pizza stone on the middle rack to heat through for at least 20 minutes; the hot surface is what crisps the bottom. Divide the rested dough into two equal pieces; on a lightly floured surface, roll one piece into a 32 cm round, about 2 mm thick — work the edges thinner than the centre so the seal will not be too thick. Slide the round onto a sheet of baking parchment; spread the filling evenly over the disc, leaving a 2 cm border, and press it down lightly into a 1.5 cm layer. Roll out the second piece of dough to the same 32 cm round and lay it on top; press the two layers together firmly around the edge, then roll and pinch the rim inward into a tight rope-like border so no juice can escape. Brush the top with the egg-yolk glaze and prick the centre in 6–8 places with a fork to let steam vent; slide the pie, on its parchment, onto the hot tray in the oven; bake for 30–35 minutes, until the top is deep golden brown and the bottom sounds hollow when you tap it. Rest the pie on a board for 5 minutes (the steam settles and the filling firms up), then cut into 8 wedges with a sharp knife; serve hot with green tea, plain yoghurt, or soured milk."}},{"id":138,"origin":{"ar":"أوكرانيا","en":"Ukraine","ro":"Ucraina"},"name":{"ar":"دجاج كييف","en":"Chicken Kiev","ro":"Pui Kiev"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ar":["100 غ من الزبدة غير المملحة، طرية بدرجة حرارة الغرفة","3 فصوص ثوم، مفرومة ناعمة جداً (أو 1 ملعقة كبيرة من معجون الثوم)","30 غ من البقدونس مسطح الأوراق، مفروم ناعماً جداً","1 ملعقة كبيرة من عصير الليمون","0,5 ملعقة صغيرة من ملح البحر الناعم","0,25 ملعقة صغيرة من الفلفل الأسود المطحون الطازج","4 صدور دجاج كبيرة منزوعة العظم والجلد (نحو 200 غ لكل صدر)","1 ملعقة صغيرة من ملح البحر الناعم لصدور الدجاج","0,5 ملعقة صغيرة من الفلفل الأسود المطحون الطازج لصدور الدجاج","80 غ من الدقيق العادي","2 بيضتان كبيرتان، مخفوقتان مع 1 ملعقة كبيرة من الماء البارد","150 غ من البقسماط البانكو أو بقسماط جاف ناعم","750 مل من زيت محايد (دوار الشمس أو الكانولا)، للقلي العميق","1 ملعقة كبيرة من الزبدة غير المملحة لتعطير الزيت (اختياري، لقشرة أعمق نكهة)","شرائح ليمون وحزمة صغيرة من البقدونس، للتقديم"],"en":["100 g unsalted butter, softened to room temperature","3 garlic cloves, very finely minced (or 1 tbsp garlic paste)","30 g flat-leaf parsley, very finely chopped","1 tbsp lemon juice","0.5 tsp fine sea salt","0.25 tsp freshly ground black pepper","4 large skinless chicken breasts (about 200 g each)","1 tsp fine sea salt for the breasts","0.5 tsp freshly ground black pepper for the breasts","80 g plain (all-purpose) flour","2 large eggs, beaten with 1 tbsp cold water","150 g panko or fine dry breadcrumbs","750 ml neutral oil (sunflower or rapeseed), for deep-frying","1 tbsp unsalted butter, for finishing the oil (optional, for a nuttier crust)","Lemon wedges and a small bunch of parsley, to serve"],"ro":["100 g unt nesărat, înmuiat la temperatura camerei","3 căței de usturoi, tocați foarte fin (sau 1 lingură pastă de usturoi)","30 g pătrunjel cu frunze plate, tocat foarte fin","1 lingură suc de lămâie","0,5 linguriță sare fină de mare","0,25 linguriță piper negru proaspăt măcinat","4 piepți mari de pui dezosați și fără piele (aproximativ 200 g fiecare)","1 linguriță sare fină de mare pentru piepți","0,5 linguriță piper negru proaspăt măcinat pentru piepți","80 g făină albă obișnuită","2 ouă mari, bătute cu 1 lingură apă rece","150 g panko sau pesmet fin uscat","750 ml ulei neutru (de floarea-soarelui sau de rapiță), pentru prăjire adâncă","1 lingură unt nesărat, pentru aromatizarea uleiului (opțional, pentru o crustă cu unt prăjit)","Felii de lămâie și o legătură mică de pătrunjel, pentru servit"]},"howIsMade":{"ar":"حضّر زبدة الأعشاب; اخفق الزبدة الطرية في وعاء مع الثوم المفروم والبقدونس وعصير الليمون و0,5 ملعقة صغيرة من الملح و0,25 ملعقة صغيرة من الفلفل حتى تتجانس; اسكبها على غشاء بلاستيكي، شكّلها أسطوانة بطول 12 سم وسماكة 2 سم، ولفّها بإحكام واتركها في الفريزر ساعة على الأقل حتى تتجمد بما يكفي للتقطيع. قطّع أسطوانة الزبدة الباردة إلى 4 أسطوانات متساوية; أعدها إلى الفريزر بينما تحضّر الدجاج — يجب أن تكون الزبدة شديدة البرودة وإلا تسربت أثناء القلي. بسكين حادة، اقطع جيباً أفقياً عميقاً في الجانب السميك من كل صدر دجاج، وتوقّف على بُعد 1 سم من الحافة المقابلة — لا تقطعه بالكامل; افتح الصدر كالكتاب، ضعه بين ورقتين من الغشاء البلاستيكي ودقّه برفق بمطرقة لحم إلى سماكة موحدة 5 ملم من المركز نحو الأطراف; تبّل الداخل بـ 1 ملعقة صغيرة من الملح و0,5 ملعقة صغيرة من الفلفل. ضع أسطوانة زبدة باردة في وسط كل صدر مدقوق; اطوِ الجانبين الطويلين فوق الزبدة ثم لُفّ الصدر بإحكام إلى أسطوانة مغلقة، اضغط لإخراج الهواء; أدخل الأطراف الفضفاضة تحته; لفّ كل صرّة بغشاء بلاستيكي وضعها في الثلاجة 30 دقيقة. جهّز ثلاثة أوعية ضحلة: واحد بالدقيق وواحد بالبيض المخفوق والماء وواحد بالبقسماط; خذ صرّة، غمّسها بالدقيق ثم انفض الزائد، ثم البيض (مع تصفية جيدة)، ثم البقسماط — اضغط بقوة على جميع الجوانب; غمّسها بالبيض ثم البقسماط مرة ثانية: هذه الطبقة المزدوجة هي التي تمنع انفجار الزبدة أثناء القلي; كرّر العملية مع الباقي. سخّن الزيت في قدر عميق إلى 170 درجة مئوية; اختبر بقطعة بقسماط — يجب أن تطقطق وتصبح ذهبية فاتحة خلال 20 ثانية; أنزل اثنتين من قطع كييف بحذر واقلهما 6–7 دقائق مع قلب واحد، حتى تصبح القشرة ذهبية غامقة في جميع الجوانب; ارفعهما إلى شبكة فوق صينية; كرّر مع الأخريين. أكمل الطهي في الفرن عند الحاجة; ضع قطع كييف على شبكة فوق صينية واخبزها في 180 درجة مئوية (350 درجة فهرنهايت) لمدة 8–10 دقائق، حتى يقرأ مقياس الحرارة المغمور في اللحم (لا في الزبدة) 70 درجة مئوية; هكذا ينضج الدجاج تماماً دون أن تحرق القشرة. اتركها ترتاح دقيقتين على الشبكة، ثم قدّمها; اخترق وجه كل قطعة كييف على المائدة — ستندفع زبدة الأعشاب المذابة في تدفق ذهبي; قدّمها فوراً مع شرائح ليمون وبقدونس، بجانب بطاطس مهروسة أو أرز بالزبدة.","en":"Make the herb butter; beat the softened butter in a bowl with the minced garlic, chopped parsley, lemon juice, 0.5 tsp salt, and 0.25 tsp pepper until evenly combined; scrape onto cling film, shape into a 12 cm long, 2 cm thick log, wrap tightly, and freeze for at least 1 hour, until firm enough to slice. Slice the chilled butter log into 4 equal cylinders; return them to the freezer while you prepare the chicken — the butter must be very cold or it will leak out during frying. With a sharp knife, cut a deep horizontal pocket into the thick side of each chicken breast, stopping about 1 cm before the opposite edge — do not cut through; open the breast like a book, lay it between two sheets of cling film, and pound gently with a meat mallet to an even 5 mm thickness, working from the centre outwards; season the inside with 1 tsp salt and 0.5 tsp pepper. Place one cold butter cylinder along the centre of each pounded breast; fold the two long sides over the butter, then roll the breast tightly into a sealed cylinder, pressing to expel air; tuck any loose flaps underneath; wrap each parcel in cling film and refrigerate for 30 minutes. Set up three shallow bowls: one with the flour, one with the beaten eggs and water, one with the breadcrumbs; take a parcel, dip in flour and pat off excess, then egg, draining well, then breadcrumbs — press firmly on all sides; dip the egg and breadcrumbs again for a second coat: this double coat is what stops the butter from blowing out during frying; repeat with the other three. Heat the oil in a deep pan to 170°C; test with a breadcrumb — it should sizzle and turn pale gold in 20 seconds; lower two Kievs in carefully and fry for 6–7 minutes, turning once, until the crust is deeply golden brown all over; lift onto a wire rack set over a tray; repeat with the other two. Finish in the oven if needed; place the fried Kievs on a rack over a baking tray and bake at 180°C (350°F) for 8–10 minutes, until a temperature probe pushed into the chicken (not the butter) reads 70°C; this ensures the chicken is cooked through without overcooking the crust. Rest for 2 minutes on the rack, then plate; pierce the top of each Kiev at the table — the molten herb butter will spill out in a golden stream; serve immediately with lemon wedges and parsley, alongside mashed potatoes or buttered rice."}},{"id":139,"origin":{"ar":"ليتوانيا","en":"Lithuania","ro":"Lituania"},"name":{"ar":"سيبيليناي","en":"Cepelinai","ro":"Cepelinai"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ar":["1,5 كغ من البطاطس الشمعية النيئة (Yukon Gold أو ما يشابهها)، مقشّرة ومزنّة بعد التقشير","500 غ من البطاطس النشوية (Russet أو King Edward)، مقشّرة ومزنّة بعد التقشير","1 ملعقة كبيرة من عصير الليمون أو 1 ملعقة صغيرة من حمض الستريك (لمنع البطاطس المبشورة النيئة من الاسوداد)","1 ملعقة صغيرة من ملح البحر الناعم للعجين","2 ملعقة كبيرة من نشا الذرة — فقط إذا كانت البطاطس النيئة شديدة الرطوبة","500 غ من كتف الخنزير مفروم خشناً (أو 50% خنزير + 50% بقر)","1 بصلة متوسطة (نحو 150 غ)، مفرومة فرماً ناعماً جداً","1 ملعقة صغيرة من ملح البحر الناعم للحشوة","0,5 ملعقة صغيرة من الفلفل الأسود المطحون الطازج","1 ملعقة صغيرة من البردقوش المجفف أو الزعتر البري المجفف","60 مل من الماء البارد للحشوة","200 غ من اللحم المقدد المدخن، مكعبات","1 بصلة كبيرة (نحو 200 غ)، شرائح رفيعة","200 غ من القشدة الحامضة كاملة الدسم","شبت أو بقدونس مفروم ناعماً، للتزيين","1 ملعقة كبيرة من ملح البحر الخشن لماء السلق"],"en":["1.5 kg raw waxy potatoes (Yukon Gold or similar), peeled and weighed","500 g floury potatoes (Russet or King Edward), peeled and weighed","1 tbsp lemon juice or 1 tsp citric acid (to prevent the raw grated potato from greying)","1 tsp fine sea salt for the dough","2 tbsp cornflour (cornstarch) — only if the raw potato is very wet","500 g coarsely minced pork shoulder (or 50% pork + 50% beef)","1 medium onion (about 150 g), very finely diced","1 tsp fine sea salt for the filling","0.5 tsp freshly ground black pepper","1 tsp dried marjoram or dried savory","60 ml cold water for the filling","200 g smoked streaky bacon, cubed","1 large onion (about 200 g), finely sliced","200 g full-fat sour cream","Dill or parsley, finely chopped, to garnish","1 tbsp coarse sea salt for the cooking water"],"ro":["1,5 kg cartofi cu pastă fermă (Yukon Gold sau similari), curățați și cântăriți după curățare","500 g cartofi făinoși (Russet sau King Edward), curățați și cântăriți după curățare","1 lingură suc de lămâie sau 1 linguriță acid citric (pentru a împiedica înnegrirea cartofului ras crud)","1 linguriță sare fină de mare pentru aluat","2 linguri amidon de porumb — doar dacă aluatul rămâne prea umed","500 g carne de porc tocată grosier (sau 50% porc + 50% vită)","1 ceapă medie (aproximativ 150 g), tocată foarte fin","1 linguriță sare fină de mare pentru umplutură","0,5 linguriță piper negru proaspăt măcinat","1 linguriță maghiran uscat sau cimbru de munte uscat","60 ml apă rece pentru umplutură","200 g bacon afumat striat, tăiat cuburi","1 ceapă mare (aproximativ 200 g), feliată fin","200 g smântână grasă","Mărar sau pătrunjel, tocat fin, pentru garnitură","1 lingură sare grunjoasă de mare pentru apa de fierbere"]},"howIsMade":{"ar":"حضّر الحشوة أولاً لتتزاوج النكهات; اخلط في وعاء لحم الخنزير المفروم والبصل المفروم ناعماً و1 ملعقة صغيرة من الملح والفلفل والبردقوش و60 مل من الماء البارد; اعجن باليد 1–2 دقيقة حتى يصبح المزيج لزجاً ومتماسكاً جيداً; غطّه وضعه في الثلاجة بينما تحضّر عجين البطاطس. اسلق 500 غ من البطاطس النشوية كاملةً بقشرها في ماء مالح لمدة 25–30 دقيقة حتى تنضج تماماً; صفِّها، قشّرها وهي ساخنة ومرّرها عبر مهروسة أو اهرسها بنعومة; وزّعها على صينية لتبرد إلى درجة حرارة الغرفة — البطاطس المهروسة الساخنة ستطبخ البطاطس النيئة في الخطوة التالية. ابشر 1,5 كغ من البطاطس النيئة على الجانب الناعم لمبشرة الصندوق في وعاء كبير مبطّن بفوطة مطبخ نظيفة; اجمع الفوطة واعصرها بقوة فوق وعاء ثانٍ لاستخراج أكبر قدر ممكن من السائل; ستحصل على نحو 250 مل من السائل؛ اتركه يستقر 5 دقائق. اسكب بحذر الماء الصافي من وعاء السائل المعصور، تاركاً النشا الأبيض في القاع; اكشط هذا النشا وأعده إلى البطاطس المبشورة المعصورة — فهو الرابط الطبيعي الذي يحفظ تماسك الكرات; أضف البطاطس المهروسة المبرّدة وعصير الليمون و1 ملعقة صغيرة من الملح; اعجن بقوة باليد 2–3 دقائق حتى تحصل على عجينة لزجة ومرنة; لا تُضِف نشا الذرة إلا إذا بقيت العجينة رطبة جداً. بأيدٍ مبلّلة، قسّم العجين إلى 8 قطع متساوية (نحو 220 غ لكل قطعة); افرد قطعة على راحة يدك المبلّلة بشكل بيضاوي 12 × 8 سم، ضع نحو 60 غ من الحشوة الباردة في المنتصف، ثم لفّ العجين فوق الحشوة وحوله، اضغط لإغلاقه تماماً; شكّله بهيئة منطاد بطول 12 سم، بدون شقوق قد يدخل منها البخار أو الماء. ارفع 4 لترات من الماء و1 ملعقة كبيرة من الملح الخشن في قدر واسع عميق إلى غليان خفيف (لا إلى غليان شديد — الماء العنيف يُكسّر الكرات); أنزل الكرات على دفعتين، قلّبها برفق مرة واحدة لئلا تلتصق بالقاع، واطبخها 25–30 دقيقة على أهدأ غليان حتى يتحوّل سطحها من المطفي إلى الشفاف وتطفو إلى الأعلى. خلال طهي الكرات، حضّر الصلصة; اطبخ مكعبات اللحم المقدد في مقلاة جافة على نار متوسطة 6–8 دقائق حتى يتحرّر الدهن وتصبح المكعبات مقرمشة; أضف البصل المشرّح واطبخه 5–6 دقائق إضافية حتى يلين ويأخذ لوناً ذهبياً خفيفاً; قلّب وارفع عن النار وأبقها دافئة. ارفع الكرات المطبوخة بمصفاة شقّ إلى أطباق دافئة — 2 لكل شخص; وزّع بسخاء خليط اللحم المقدد والبصل بدهنه فوقها، ضع ملعقة كبيرة من القشدة الحامضة الباردة وأنهِ برشّ شبت مفروم; قدّمها فوراً وكل شيء ساخن والقلب طري وعصاري.","en":"Make the filling first so the flavours marry; mix the minced pork, finely diced onion, 1 tsp salt, pepper, marjoram, and 60 ml cold water in a bowl with your hand for 1–2 minutes, until the mixture is sticky and well bound; cover and chill while you prepare the potato dough. Boil the 500 g floury potatoes whole and unpeeled in salted water for 25–30 minutes, until very tender; drain, peel while hot, and pass through a ricer or mash smoothly; spread out on a tray to cool to room temperature — hot mash would cook the raw potato in the next step. Grate the 1.5 kg waxy potatoes on the fine side of a box grater into a large bowl lined with a clean kitchen towel; gather the towel and squeeze hard over a second bowl to extract as much liquid as possible; you should end up with about 250 ml of liquid; leave it to settle for 5 minutes. Carefully pour off the clear water from the bowl of squeezed liquid, leaving the white starch settled at the bottom; scrape this starch back into the squeezed grated potato — it is the natural binder that holds the dumplings together; add the cooled mashed potato, the lemon juice, and 1 tsp salt; mix vigorously by hand for 2–3 minutes, until you have a sticky, elastic dough; add the cornflour only if the dough still feels wet. With wet hands, divide the dough into 8 equal pieces (about 220 g each); flatten one piece on a wet palm into a 12 × 8 cm oval, place about 60 g of the chilled filling in the centre, then wrap the dough up and around the filling, pinching to seal completely; smooth into a 12 cm zeppelin shape, with no cracks where steam or water could enter. Bring a wide deep pan with 4 litres of water and 1 tbsp coarse salt to a gentle simmer (not a rolling boil — vigorous water can break the dumplings); lower the cepelinai in 2 batches, stir gently once to keep them off the base, and cook for 25–30 minutes at the gentlest simmer, until the surface goes from matte to translucent and the dumplings float high. While they cook, make the sauce; cook the cubed bacon in a dry frying pan over medium heat for 6–8 minutes until the fat renders and the cubes are crisp; add the sliced onion and cook for another 5–6 minutes until soft and lightly golden; stir off the heat and keep warm. Lift the cooked cepelinai out with a slotted spoon onto warmed plates — 2 per person; scatter generously with the bacon-onion mixture and its fat, top with a heap of cold sour cream, and finish with chopped dill; serve immediately while everything is hot and the centres are juicy."}},{"id":140,"origin":{"ar":"فرنسا","en":"France","ro":"Franța"},"name":{"ar":"دجاج فريكاسيه","en":"Chicken Fricassée","ro":"Fricassée de Poulet"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"french","ingredients":{"ar":["1,5 كغ من أفخاذ وأوراك الدجاج بالعظم والجلد (نحو 8 قطع)، أو دجاجة كاملة 1,5 كغ مقسّمة إلى 8 قطع","1 ملعقة صغيرة من ملح البحر الناعم + 0,5 ملعقة صغيرة من الفلفل الأبيض المطحون الطازج (الفلفل الأسود يصلح لكنه يبقي بقع في الصلصة)","60 غ من الزبدة غير المملحة، مقسّمة 30 غ + 30 غ","2 ملعقة كبيرة من زيت محايد","250 غ من بصل اللؤلؤ أو كراث صغير، مقشّر (أو 1 بصلة متوسطة مفرومة فرماً ناعماً)","200 غ من فطر شامبينيون أبيض أو بني، مشطور أو إلى أرباع إذا كان كبيراً","2 جزرة متوسطة (نحو 200 غ)، مقشّرة ومقطّعة أصابع 5 سم","2 فصوص ثوم، مفرومة ناعماً","30 غ من الدقيق العادي","150 مل من نبيذ أبيض جاف (Riesling أو Sauvignon Blanc)","500 مل من مرق دجاج ساخن بلا ملح","1 باقة أعشاب صغيرة (1 ورقة غار + 4 أغصان زعتر + 4 سيقان بقدونس مربوطة بخيط)","200 مل من كريمة كاملة الدسم (35% دهن أو أكثر)، مع 2 صفار بيض اختيارية لرابطة أغنى","1 ملعقة كبيرة من عصير الليمون الطازج","2 ملعقة كبيرة من البقدونس مسطح الأوراق مفروم ناعماً، للتزيين"],"en":["1.5 kg bone-in skin-on chicken thighs and drumsticks (about 8 pieces), or a 1.5 kg whole chicken jointed into 8","1 tsp fine sea salt + 0.5 tsp freshly ground white pepper (black pepper works but speckles the sauce)","60 g unsalted butter, divided into 30 g + 30 g","2 tbsp neutral oil","250 g pearl onions or small shallots, peeled (or 1 medium onion finely diced)","200 g chestnut or button mushrooms, halved or quartered if large","2 medium carrots (about 200 g), peeled and cut into 5 cm batons","2 garlic cloves, finely minced","30 g plain (all-purpose) flour","150 ml dry white wine (Riesling or Sauvignon Blanc)","500 ml hot unsalted chicken stock","1 small bouquet garni (1 bay leaf + 4 thyme sprigs + 4 parsley stalks tied with string)","200 ml double cream (heavy cream, 35% fat or higher), plus 2 optional egg yolks for a richer liaison","1 tbsp fresh lemon juice","2 tbsp finely chopped fresh flat-leaf parsley, to garnish"],"ro":["1,5 kg pulpe și copane de pui cu os și piele (aproximativ 8 bucăți) sau 1,5 kg pui întreg dezasamblat în 8 bucăți","1 linguriță sare fină de mare + 0,5 linguriță piper alb proaspăt măcinat (piperul negru funcționează dar pătează sosul)","60 g unt nesărat, împărțit în două porții de 30 g","2 linguri ulei neutru","250 g cepe de primăvară sau eșalote mici, decojite (sau 1 ceapă medie tocată fin)","200 g ciuperci champignon (albe sau brune), tăiate în jumătăți sau sferturi dacă sunt mari","2 morcovi medii (aproximativ 200 g), curățați și tăiați bastonașe de 5 cm","2 căței de usturoi, tocați fin","30 g făină albă obișnuită","150 ml vin alb sec (Riesling sau Sauvignon Blanc)","500 ml supă de pui fierbinte nesărată","1 bouquet garni mic (1 foaie de dafin + 4 crenguțe de cimbru + 4 cozi de pătrunjel legate cu sfoară)","200 ml smântână grasă (cel puțin 35% grăsime), plus 2 gălbenușuri opționale pentru o legătură mai bogată","1 lingură suc de lămâie proaspăt","2 linguri pătrunjel proaspăt cu frunze plate, tocat fin, pentru garnitură"]},"howIsMade":{"ar":"جفّف قطع الدجاج بمناديل ورقية وتبّل الجانبين بـ 1 ملعقة صغيرة من الملح والفلفل الأبيض; اتركها ترتاح 15 دقيقة في درجة حرارة الغرفة. سخّن 30 غ من الزبدة و2 ملعقة كبيرة من الزيت في مقلاة عريضة 28 سم أو قدر فرنسي على نار متوسطة; عندما تتكوّن رغوة الزبدة، رتّب الدجاج بالجلد للأسفل في طبقة واحدة (دفعات إن لزم) واطبخه 5–6 دقائق لكل جانب — يجب أن يأخذ السطح لوناً ذهبياً فاتحاً، لا بنيّاً; القشرة البنية ستعكّر الصلصة; ارفعه إلى طبق. خفّض النار إلى متوسطة-منخفضة; أضف بصل اللؤلؤ إلى المقلاة نفسها واطبخه 5–6 دقائق مع التحريك حتى يصبح ذهبياً خفيفاً لكنه لا يزال شاحباً; ارفعه إلى طبق الدجاج. أضف الجزر والفطر إلى المقلاة واطبخه 4–5 دقائق — سيُطلق الفطر ماءه ويستعيده; أضف الثوم وقلّب 30 ثانية. رشّ الدقيق فوق الخضار وقلّب باستمرار 2 دقيقة لإنضاج الطعم الني — ستتشكّل حول الخضار رو فاتح اللون; اسكب النبيذ وارفعه إلى غليان قوي مع كشط أي رواسب عن القاع، حتى يقلّ النصف (1–2 دقيقة). أعد الدجاج وبصل اللؤلؤ إلى المقلاة في طبقة واحدة; اسكب المرق الساخن لتغطيتها تقريباً، ضع باقة الأعشاب واخفض النار إلى أهدأ غليان; غطّ القدر واطبخه 30–35 دقيقة للأفخاذ (أو 25 دقيقة لصدور الدجاج التي أخرجتها مسبقاً) حتى ينفصل اللحم بسهولة عن العظم وتبلغ الحرارة الداخلية 75 درجة مئوية. انقل الدجاج والخضار إلى طبق دافئ وغطّه بورق ألمنيوم; تخلّص من باقة الأعشاب; ارفع الصلصة على نار متوسطة إلى غليان قوي وقلّلها 3–5 دقائق حتى تغلّف ظهر الملعقة (نحو 350 مل). حضّر اللية; اخفق الكريمة وصفار البيض في وعاء صغير; أضف مغرفة من الصلصة الساخنة للمعادلة الحرارية، ثم اسكب الخليط المُعدّل عائداً إلى المقلاة بعد إطفاء النار; قلّب برفق — لا تتركها تغلي، فالصفار سيتجمّع; أضف عصير الليمون، تذوّق وعدّل الملح; اسكبها فوق الدجاج، رشّ البقدونس المفروم وقدّمها فوراً مع الأرز أو الشعيرية بالزبدة أو البطاطس المسلوقة على البخار.","en":"Pat the chicken pieces dry with paper towels and season both sides with 1 tsp salt and the white pepper; rest at room temperature for 15 minutes. Heat 30 g of the butter and 2 tbsp oil in a wide 28 cm heavy-based sauté pan or Dutch oven over medium heat; when the butter foams, add the chicken skin-side down in one layer (work in batches if needed) and cook 5–6 minutes per side — the surface should turn pale gold and gilded, NOT brown; a brown crust would muddy the sauce; lift onto a plate. Reduce the heat to medium-low; add the pearl onions to the same pan and cook for 5–6 minutes, stirring, until lightly gilded but still pale; lift onto the plate with the chicken. Add the carrots and mushrooms to the pan and cook for 4–5 minutes — the mushrooms will release their water and reabsorb it; add the garlic and stir for 30 seconds. Sprinkle the flour over the vegetables and stir constantly for 2 minutes to cook out the raw taste — a pale roux will form around the vegetables; pour in the wine and bring to a brisk simmer, scraping up any sediment from the pan base, until reduced by half (1–2 minutes). Return the chicken and pearl onions to the pan in a single layer; pour in the hot stock to nearly cover, tuck in the bouquet garni, and bring to the gentlest simmer; cover and cook for 30–35 minutes for thighs (or 25 minutes for breasts removed earlier), until the meat pulls easily from the bone and the internal temperature reads 75°C. Lift the chicken and vegetables to a warmed dish and cover with foil; discard the bouquet garni; bring the sauce to a brisk simmer over medium heat and reduce for 3–5 minutes, until it coats the back of a spoon (about 350 ml). Make the liaison; whisk the cream and egg yolks together in a small bowl; whisk in a ladle of hot sauce to temper, then pour the tempered mixture back into the pan off the heat; stir gently — DO NOT BOIL, or the yolks will scramble; add the lemon juice, taste and adjust the salt; pour over the chicken, scatter with chopped parsley, and serve immediately with rice, buttered noodles, or steamed potatoes."}},{"id":141,"origin":{"ar":"الكويت","en":"Kuwait","ro":"Kuweit"},"name":{"ar":"مجبوس","en":"Machboos","ro":"Machboos"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"middle-eastern","ingredients":{"ar":["1,5 كغ من أفخاذ وأوراك الدجاج بالعظم والجلد (أو 1,2 كغ من كتف الضأن بالعظم مقطعاً قطعاً 6 سم)","400 غ من أرز بسمتي، مغسول ومنقوع في ماء بارد 30 دقيقة ثم مصفّى","60 مل من زيت محايد (أو 30 غ من السمن + 2 ملعقة كبيرة من الزيت لنكهة أغنى)","3 بصلات كبيرة (نحو 600 غ)، مفرومة شرائح رفيعة — احتفظ بقليل منها نيئة للتقديم","6 فصوص ثوم، مفرومة ناعماً","قطعة زنجبيل طازج بحجم الإبهام (نحو 30 غ)، مبشورة ناعماً","3 طماطمات متوسطة (نحو 300 غ)، مبشورة (أو 200 غ من الطماطم المقطعة المعلبة)","2 ملعقة كبيرة من معجون الطماطم","2 لومي (ليمون أسود مجفف)، مثقوب بالسكين في 3 مواضع (أو 2 ملعقة كبيرة من عصير الليمون الأخضر الطازج كبديل أقل تقليدية)","1 ملعقة كبيرة من البهارات (أو 1 ملعقة صغيرة قرفة مطحونة + 1 ملعقة صغيرة كمون مطحون + 1 ملعقة صغيرة كزبرة مطحونة + 0,5 ملعقة صغيرة هيل مطحون + 0,5 ملعقة صغيرة فلفل أسود مطحون)","0,5 ملعقة صغيرة من الكركم المطحون","4 حبات هيل أخضر كاملة، مفتوحة قليلاً + 1 عود قرفة (5 سم) + 4 حبات قرنفل كاملة + 2 ورقة غار","حزمة صغيرة من الكزبرة الطازجة (نحو 30 غ)، السيقان مفرومة ناعماً للقدر، الأوراق محفوظة للتزيين","2 فلفلتان خضراوان طازجتان، مشقوقتان طولياً","1,2 لتر من الماء الساخن (أو مرق دجاج بلا ملح لمزيد من العمق)","1,5 ملعقة صغيرة من ملح البحر الناعم، ويُضاف حسب الذوق","60 غ من شرائح اللوز و40 غ من الزبيب الذهبي، محمصة قليلاً في 1 ملعقة صغيرة من السمن (للنثر فوقه)","0,5 ملعقة صغيرة من خيوط الزعفران منقوعة في 2 ملعقة كبيرة من الماء الدافئ (اختياري، لتزيين الأرز)"],"en":["1.5 kg bone-in skin-on chicken thighs and drumsticks (or 1.2 kg bone-in lamb shoulder cut into 6 cm chunks)","400 g basmati rice, rinsed and soaked in cold water for 30 minutes, then drained","60 ml neutral oil (or 30 g ghee + 2 tbsp oil for a richer flavour)","3 large onions (about 600 g), finely sliced — reserve a small handful raw for serving","6 garlic cloves, finely chopped","1 thumb-sized piece of fresh ginger (about 30 g), finely grated","3 medium tomatoes (about 300 g), grated (or 200 g canned chopped tomatoes)","2 tbsp tomato paste","2 dried limes (loomi), pierced with a knife in 3 places (or 2 tbsp fresh lime juice as a less-traditional substitute)","1 tbsp baharat (or 1 tsp ground cinnamon + 1 tsp ground cumin + 1 tsp ground coriander + 0.5 tsp ground cardamom + 0.5 tsp ground black pepper)","0.5 tsp ground turmeric","4 whole green cardamom pods, lightly cracked + 1 cinnamon stick (5 cm) + 4 whole cloves + 2 bay leaves","1 small bunch fresh coriander (about 30 g), stems chopped fine for the pot, leaves reserved for garnish","2 fresh green chillies, slit lengthwise","1.2 litres hot water (or unsalted chicken stock for more depth)","1.5 tsp fine sea salt, plus more to taste","60 g flaked almonds and 40 g sultanas, lightly toasted in 1 tsp ghee (to scatter on top)","0.5 tsp saffron threads soaked in 2 tbsp warm water (optional, for finishing the rice)"],"ro":["1,5 kg pulpe și copane de pui cu os și piele (sau 1,2 kg umăr de miel cu os tăiat bucăți de 6 cm)","400 g orez basmati, clătit și înmuiat în apă rece 30 de minute, apoi scurs","60 ml ulei neutru (sau 30 g ghee + 2 linguri ulei pentru aromă mai bogată)","3 cepe mari (aproximativ 600 g), feliate fin — păstrează o mică parte crudă pentru servit","6 căței de usturoi, tocați fin","O bucată de ghimbir proaspăt cât degetul mare (aproximativ 30 g), ras fin","3 roșii medii (aproximativ 300 g), date pe răzătoare (sau 200 g roșii sfărâmate din conservă)","2 linguri pastă de roșii","2 lămâi uscate (loomi), înțepate cu cuțitul în 3 locuri (sau 2 linguri suc proaspăt de lime ca substitut mai puțin tradițional)","1 lingură baharat (sau 1 linguriță scorțișoară măcinată + 1 linguriță chimion măcinat + 1 linguriță coriandru măcinat + 0,5 linguriță cardamom măcinat + 0,5 linguriță piper negru măcinat)","0,5 linguriță turmeric măcinat","4 capsule întregi de cardamom verde, ușor crăpate + 1 baton de scorțișoară (5 cm) + 4 cuișoare + 2 foi de dafin","1 legătură mică de coriandru proaspăt (aproximativ 30 g), tijele tocate fin pentru oală, frunzele păstrate pentru garnitură","2 ardei iuți verzi proaspeți, crestați pe lungime","1,2 litri apă fierbinte (sau supă de pui nesărată pentru profunzime)","1,5 lingurițe sare fină de mare, plus după gust","60 g migdale feliate și 40 g stafide blonde, ușor prăjite în 1 linguriță ghee (pentru deasupra)","0,5 linguriță fire de șofran înmuiate în 2 linguri apă caldă (opțional, pentru finisarea orezului)"]},"howIsMade":{"ar":"اشطف أرز البسمتي تحت الماء البارد الجاري حتى يصفو الماء تقريباً، ثم انقعه في ماء بارد نظيف 30 دقيقة; هذا يُزيل النشا الفائض ويُقصّر زمن الطهي النهائي; صفِّه قبل الاستخدام مباشرة. جفّف قطع الدجاج وتبّلها بـ 0,5 ملعقة صغيرة من الملح; سخّن الزيت (أو السمن + الزيت) في قدر سميك بقطر 28 سم على نار متوسطة-عالية; حين يبدأ بإطلاق وميض، ضع الدجاج بالجلد للأسفل وحمّره 4–5 دقائق لكل جانب حتى يصبح ذهبياً غامقاً; ارفعه إلى طبق. خفّض النار إلى متوسطة; أضف البصل المشرّح ورشّة ملح إلى القدر نفسه واطبخه 12–15 دقيقة مع التحريك المتكرر حتى يصبح ذهبياً عميقاً وطرياً جداً; أضف الثوم والزنجبيل واطبخهما 1 دقيقة حتى تفوح رائحتهما. أضف حبات الهيل وعود القرفة والقرنفل وأوراق الغار والبهارات والكركم; حمّصها 30 ثانية — يجب أن تفوح رائحة التوابل ويتعمّق لونها; أضف معجون الطماطم والطماطم المبشورة واطبخها مع التحريك 4–5 دقائق حتى يكتسب المزيج لوناً أحمر غنياً ويتجمّع الزيت على الحواف. أعد الدجاج إلى القدر في طبقة واحدة; اسكب الماء الساخن (أو المرق)، أضف اللومي وثقّبه، الفلفل المشقوق، سيقان الكزبرة المفرومة والملح المتبقي; ارفعه إلى غليان خفيف، غطّه وخفّض النار إلى أهدأ غليان واطبخه 35–40 دقيقة (دجاج) أو ساعة و30 دقيقة (ضأن) حتى يتفكّك اللحم بسهولة ويصبح المرق عميق النكهة. ارفع الدجاج إلى طبق وغطّه برخاوة بورق ألمنيوم لإبقائه دافئاً; اكشط الدهن الفائض من سطح المرق. أضف الأرز المصفّى إلى القدر مع دفعه برفق ليكون مغموراً بالكاد بالمرق (أكمل بالماء الساخن عند الحاجة — يجب أن يبقى نحو 2,5 سم من السائل فوق الأرز); أعِده إلى غليان خفيف، غطّ القدر بإحكام، خفّض النار إلى أقصى حد ممكن واطبخه دون فتح 18 دقيقة. أطفئ النار; رشّ ماء الزعفران (إن استخدمته) فوق الأرز، ضع قطع الدجاج فوقه، أعد الغطاء واتركه يرتاح 10 دقائق — البخار يكمل طهي الدجاج وتتفكّك حبات الأرز; فكّك الأرز بشوكة، انقله إلى طبق واسع مع الدجاج فوقه، ووزّع اللوز المحمّص والزبيب وشرائح البصل النيء وأوراق الكزبرة; قدّمه مع الدِيبَّة (صلصة التمر الهندي) أو اللبن جانباً.","en":"Rinse the basmati rice under cold running water until the water runs almost clear, then soak in fresh cold water for 30 minutes; this removes excess starch and shortens the final cooking step; drain just before use. Pat the chicken pieces dry and season with 0.5 tsp of the salt; heat the oil (or ghee + oil) in a heavy 28 cm pot over medium-high heat; when shimmering, add the chicken skin-side down and sear for 4–5 minutes per side until deep golden; lift onto a plate. Reduce the heat to medium; add the sliced onions and a pinch of salt to the same pot and cook for 12–15 minutes, stirring often, until deeply golden and very soft; add the garlic and ginger and cook for 1 minute until fragrant. Stir in the cardamom pods, cinnamon stick, cloves, bay leaves, baharat, and turmeric; toast for 30 seconds — the spices should turn aromatic and deepen in colour; add the tomato paste and grated tomatoes and cook, stirring, for 4–5 minutes, until the mixture darkens to a rich red and the oil splits out around the edges. Return the chicken to the pot in a single layer; pour in the hot water (or stock), add the dried limes, slit chillies, chopped coriander stems, and remaining salt; bring to a gentle boil, then cover, reduce to the lowest simmer, and cook for 35–40 minutes (chicken) or 1 h 30 min (lamb), until the meat is fork-tender and the broth is deeply flavoured. Lift the chicken onto a plate and cover loosely with foil to keep warm; skim any excess fat from the broth. Add the drained rice to the pot, gently pushing it down so it is just covered by the broth (top up with hot water if needed — you want about 2.5 cm of liquid above the rice); bring back to a gentle boil, then cover with a tight lid, reduce to the lowest possible heat, and cook undisturbed for 18 minutes. Turn off the heat; drizzle the saffron water (if using) over the rice, place the chicken pieces on top, replace the lid, and rest for 10 minutes — the steam finishes cooking the chicken and the rice grains separate; fluff the rice with a fork, transfer to a wide platter with the chicken on top, and scatter with toasted almonds, sultanas, raw onion slices, and fresh coriander leaves; serve with deeba (tamarind sauce) or yoghurt on the side."}},{"id":142,"origin":{"ar":"جمهورية الكونغو","en":"Republic of the Congo","ro":"Republica Congo"},"name":{"ar":"دجاج موامبي","en":"Moambe chicken","ro":"Pui Moambe"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ar":["1,5 كغ من أفخاذ وأوراك الدجاج بالعظم والجلد (نحو 8 قطع)","1 ملعقة صغيرة من ملح البحر الناعم + 0,5 ملعقة صغيرة من الفلفل الأسود المطحون الطازج للدجاج","60 مل من زيت النخيل الأحمر (أو 30 مل من زيت النخيل + 2 ملعقة كبيرة من زيت محايد إذا كانت النكهة قوية جداً)","2 بصلتان كبيرتان (نحو 400 غ)، مفرومتان ناعماً","6 فصوص ثوم، مفرومة ناعماً","قطعة زنجبيل طازج بحجم الإبهام (نحو 20 غ)، مبشورة ناعماً","400 غ من الطماطم الناضجة، مبشورة، أو 1 × 400 غ من الطماطم المقطّعة المعلّبة","2 ملعقة كبيرة من معجون الطماطم","100 غ من زبدة الفول السوداني الناعمة غير المُحلّاة (أو 200 غ من معجون الموامبه المعلّب عند توفّره)","2 فلفلتان حارّتان طازجتان من نوع سكوتش بونيت أو هابانيرو، مشقوقتان طولياً (أو 1 ملعقة صغيرة من رقائق الفلفل الحار المجفف؛ تُعدَّل حسب الذوق — الموامبه حارّة)","2 ورقتان غار","500 مل من مرق دجاج ساخن بلا ملح أو ماء","1,5 ملعقة صغيرة من ملح البحر الناعم، ويُضاف حسب الذوق","2 ملعقة كبيرة من البقدونس مسطح الأوراق المفروم ناعماً (أو 2 ملعقة كبيرة من ريحان الليمون)، للتزيين","أرز أبيض مطبوخ بالبخار أو فوفو أو موز بلانتين مسلوق، للتقديم"],"en":["1.5 kg bone-in skin-on chicken thighs and drumsticks (about 8 pieces)","1 tsp fine sea salt + 0.5 tsp freshly ground black pepper for the chicken","60 ml red palm oil (or 30 ml palm + 2 tbsp neutral oil if the flavour is too strong)","2 large onions (about 400 g), finely diced","6 garlic cloves, finely chopped","1 thumb-sized piece of fresh ginger (about 20 g), finely grated","400 g ripe tomatoes, grated, or 1 × 400 g can chopped tomatoes","2 tbsp tomato paste","100 g unsweetened smooth peanut butter (or 200 g canned moambe palm paste when available)","2 fresh scotch bonnet or habanero chillies, slit lengthwise (or 1 tsp dried chilli flakes; adjust to taste — moambe is hot)","2 bay leaves","500 ml hot unsalted chicken stock or water","1.5 tsp fine sea salt, plus more to taste","2 tbsp finely chopped flat-leaf parsley (or 2 tbsp lemon basil), to garnish","Steamed white rice, fufu, or boiled plantains, to serve"],"ro":["1,5 kg pulpe și copane de pui cu os și piele (aproximativ 8 bucăți)","1 linguriță sare fină de mare + 0,5 linguriță piper negru proaspăt măcinat pentru pui","60 ml ulei de palmier roșu (sau 30 ml palmier + 2 linguri ulei neutru dacă aroma e prea puternică)","2 cepe mari (aproximativ 400 g), tocate fin","6 căței de usturoi, tocați fin","O bucată de ghimbir proaspăt cât degetul mare (aproximativ 20 g), ras fin","400 g roșii coapte, date pe răzătoare (sau 1 × 400 g conservă de roșii tocate)","2 linguri pastă de roșii","100 g unt de arahide neîndulcit, fin (sau 200 g pastă de moambe la conservă, când e disponibilă)","2 ardei iuți proaspeți scotch bonnet sau habanero, crestați pe lungime (sau 1 linguriță fulgi de ardei iute; ajustează după gust — muambe este picant)","2 foi de dafin","500 ml supă de pui fierbinte nesărată sau apă","1,5 lingurițe sare fină de mare, plus după gust","2 linguri pătrunjel cu frunze plate tocat fin (sau 2 linguri busuioc de lămâie), pentru garnitură","Orez alb fiert, fufu sau banane plantain fierte, pentru servit"]},"howIsMade":{"ar":"جفّف قطع الدجاج وتبّل الجانبين بـ 1 ملعقة صغيرة من الملح و0,5 ملعقة صغيرة من الفلفل; اتركها ترتاح 15 دقيقة في درجة حرارة الغرفة. سخّن زيت النخيل في قدر سميك بقطر 28 سم على نار متوسطة-عالية — يذوب زيت النخيل إلى سائل برتقالي-أحمر داكن; حين يبدأ بإطلاق وميض، ضع قطع الدجاج بالجلد للأسفل في طبقة واحدة (دفعتين عند اللزوم) وحمّرها 4–5 دقائق لكل جانب حتى يصبح الجلد ذهبياً غامقاً; ارفعها إلى طبق. خفّض النار إلى متوسطة; أضف البصل المفروم ورشّة من الملح إلى القدر نفسه واطبخه 8–10 دقائق مع التحريك المتكرر حتى يلين ويصبح لامعاً وذهبياً خفيفاً دون أن يحمرّ. أضف الثوم والزنجبيل واطبخهما 1 دقيقة حتى تفوح رائحتهما; أدرج معجون الطماطم والطماطم المبشورة واطبخه 5–6 دقائق مع التحريك حتى يصبح المزيج بلون قرميدي عميق ويبدأ زيت النخيل بالانفصال على الحواف — هذا الانفصال هو السمة البصرية للموامبه. اخفق زبدة الفول السوداني مع 200 مل من المرق الساخن في وعاء صغير حتى تنعم، ثم اسكبها في القدر وقلّب; أضف 300 مل المتبقية من المرق وأوراق الغار والفلفل الحار المشقوق والـ 0,5 ملعقة صغيرة من الملح المتبقية. أعد الدجاج إلى القدر في طبقة واحدة، اغرس القطع في الصلصة بالجلد للأعلى ليظل الجلد فوق السائل; ارفعه إلى غليان خفيف. غطّه بالغطاء مع تركه مفتوحاً قليلاً واطبخه على أدنى نار 35–40 دقيقة مع تقليبة واحدة في المنتصف، حتى يتفكّك الدجاج بسهولة عن العظم وتصل الحرارة الداخلية إلى 75 درجة مئوية; يجب أن تكون الصلصة برتقالية-مرجانية وكثيفة بما يكفي لتغليف ظهر الملعقة — وإذا غلظت كثيراً، خفّفها برشّة ماء ساخن. تذوّق وعدّل بالملح أو بمزيد من الفلفل الحار; انقل الدجاج إلى طبق دافئ، اسكب الصلصة بسخاء فوقه، ورشّ البقدونس المفروم، ثم قدّمه فوراً مع الأرز المطهو على البخار أو الفوفو أو البلانتين المسلوق ليُغمَس في الصلصة.","en":"Pat the chicken pieces dry and season both sides with 1 tsp salt and 0.5 tsp pepper; rest at room temperature for 15 minutes. Heat the palm oil in a heavy 28 cm pot over medium-high heat — palm oil melts into a deep orange-red liquid; when shimmering, add the chicken pieces skin-side down in one layer (work in two batches if needed) and sear for 4–5 minutes per side until the skin is deep golden; lift onto a plate. Reduce the heat to medium; add the diced onions and a pinch of salt to the same pot and cook for 8–10 minutes, stirring often, until soft, glossy, and lightly golden but not browned. Add the garlic and ginger and cook for 1 minute until fragrant; stir in the tomato paste and grated tomatoes and cook for 5–6 minutes, stirring, until the mixture darkens to a rich brick-red and the palm oil starts to separate around the edges — this oil split is the signature look of moambe. Whisk the peanut butter with 200 ml of the hot stock in a small bowl until smooth, then pour into the pot and stir to combine; add the remaining 300 ml stock, the bay leaves, slit chillies, and the remaining 0.5 tsp salt. Return the chicken to the pot in a single layer, nestling the pieces into the sauce skin-side up so the skin stays above the liquid; bring to a gentle simmer. Cover with a lid set slightly ajar and cook on the lowest heat for 35–40 minutes, stirring once at the halfway mark, until the chicken pulls easily from the bone and the internal temperature reads 75°C; the sauce should be coral-orange and thick enough to coat the back of a spoon — if it tightens too much, loosen with a splash of hot water. Taste and adjust with salt or extra chilli; lift the chicken into a warmed serving dish, spoon the sauce generously over the top, scatter with chopped parsley, and serve immediately with steamed rice, fufu, or boiled plantain to soak up the sauce."}},{"id":143,"origin":{"ar":"فرنسا","en":"France","ro":"Franța"},"name":{"ar":"كاسوليه","en":"Cassoulet","ro":"Cassoulet"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":6,"tipType":"meat","pairingsType":"meat","ingredients":{"ar":["500 غ من الفاصوليا البيضاء الجافة (haricot tarbais أو cannellini)، منقوعة في ماء بارد طوال الليل","4 أفخاذ بط كونفي (cuisses de canard confites)، بدرجة حرارة الغرفة، مع الاحتفاظ بالدهن","400 غ من كتف الخنزير، مقطّع قطعاً 4 سم","300 غ من بطن الخنزير بقشره، مقطّع قطعاً 3 سم","4 نقانق تولوز (نحو 500 غ) — أو نقانق خنزير مدخنة كبديل","1 جزرة كبيرة (نحو 150 غ)، مقشّرة ومقطعة قطعاً 2 سم","1 بصلة كبيرة (نحو 200 غ)، مقشّرة ومغروزة بـ 4 حبات قرنفل كاملة","1 رأس ثوم (نحو 60 غ)، مشطور أفقياً","1 باقة أعشاب (1 ورقة غار + 4 أغصان زعتر + 4 سيقان بقدونس + قطعة قشر برتقال مجفف، مربوطة)","1 عظمة كاحل خنزير أو موزة (نحو 400 غ، اختياري لكنه تقليدي)","200 غ من الطماطم المقطّعة المعلبة (أو حبتا طماطم ناضجة، مقشّرتان ومقطّعتان)","2 ملعقة كبيرة من معجون الطماطم","1,5 لتر من مرق دجاج أو خنزير بلا ملح (أو ماء)","60 غ من البقسماط الأبيض الخشن","1,5 ملعقة صغيرة من ملح البحر الناعم، ويُضاف حسب الذوق","1 ملعقة صغيرة من الفلفل الأسود المطحون الطازج","2 ملعقة كبيرة من البقدونس مسطح الأوراق المفروم ناعماً، للتزيين","2 ملعقة كبيرة من دهن البط (من الكونفي)، لتحمير اللحوم"],"en":["500 g dried white beans (haricot tarbais or cannellini), soaked in cold water overnight","4 confit duck legs (cuisses de canard confites), at room temperature, fat reserved","400 g pork shoulder, cut into 4 cm pieces","300 g pork belly with rind, cut into 3 cm pieces","4 Toulouse sausages (about 500 g) — or smoked pork sausages as a substitute","1 large carrot (about 150 g), peeled and cut into 2 cm chunks","1 large onion (about 200 g), peeled and studded with 4 whole cloves","1 head of garlic (about 60 g), halved horizontally","1 bouquet garni (1 bay leaf + 4 thyme sprigs + 4 parsley stalks + a piece of dried orange peel, tied)","1 pork knuckle bone or ham hock (about 400 g, optional but traditional)","200 g canned chopped tomatoes (or 2 ripe tomatoes, peeled and chopped)","2 tbsp tomato paste","1.5 litres unsalted chicken or pork stock (or water)","60 g coarse white breadcrumbs","1.5 tsp fine sea salt, plus more to taste","1 tsp freshly ground black pepper","2 tbsp finely chopped fresh flat-leaf parsley, to garnish","2 tbsp duck fat (from the confit), for browning the meats"],"ro":["500 g fasole albă uscată (haricot tarbais sau cannellini), înmuiată în apă rece peste noapte","4 pulpe de rață confit (cuisses de canard confites), la temperatura camerei, grăsimea păstrată","400 g umăr de porc, tăiat bucăți de 4 cm","300 g piept de porc cu șorici, tăiat bucăți de 3 cm","4 cârnați de Toulouse (aproximativ 500 g) — sau cârnați afumați de porc ca substitut","1 morcov mare (aproximativ 150 g), curățat și tăiat bucăți de 2 cm","1 ceapă mare (aproximativ 200 g), curățată și înfiptă cu 4 cuișoare întregi","1 căpățână de usturoi (aproximativ 60 g), tăiată orizontal","1 bouquet garni (1 foaie de dafin + 4 crenguțe de cimbru + 4 cozi de pătrunjel + o bucată de coajă uscată de portocală, legate)","1 os de jambon afumat sau o ciolan de porc (aproximativ 400 g, opțional dar tradițional)","200 g roșii sfărâmate din conservă (sau 2 roșii coapte, decojite și tocate)","2 linguri pastă de roșii","1,5 litri supă de pui sau de porc nesărată (sau apă)","60 g pesmet alb grosier","1,5 lingurițe sare fină de mare, plus după gust","1 linguriță piper negru proaspăt măcinat","2 linguri pătrunjel proaspăt cu frunze plate, tocat fin, pentru garnitură","2 linguri grăsime de rață (din confit), pentru rumenirea cărnurilor"]},"howIsMade":{"ar":"في الليلة السابقة، ضع الفاصوليا في وعاء كبير، غمرها بـ 2 لتر على الأقل من الماء البارد، واتركها تنقع 10–12 ساعة; سيتضاعف حجمها تقريباً; في اليوم التالي صفِّها واشطفها. حضّر مرق الفاصوليا; ضع الفاصوليا المصفّاة في قدر سميك بسعة 5 لترات مع ساق الخنزير (إن وُجد)، البصلة المغروزة بالقرنفل، رأس الثوم المشطور، الجزر، باقة الأعشاب، و1,5 لتر من المرق البارد; ارفعه إلى غليان خفيف واطبخه مكشوفاً 50–60 دقيقة حتى تصبح الفاصوليا طريّة بالكاد دون أن تتفتت; لا تضف الملح بعد. في الأثناء، حمّر اللحوم; سخّن 2 ملعقة كبيرة من دهن البط في مقلاة واسعة على نار متوسطة-عالية; جفّف كتف الخنزير وبطنه وحمّرهما على دفعات 4–5 دقائق لكل جانب حتى يصبحا ذهبيين غامقين; ارفعهما إلى طبق; في الدهن نفسه، حمّر نقانق تولوز 2–3 دقائق لكل جانب فقط لتلوين الغلاف; أضفها إلى الطبق. سخّن الفرن إلى 160 درجة مئوية (320 درجة فهرنهايت / مروحة 140 درجة مئوية); أخرج ساق الخنزير، البصلة، الثوم، الجزر وباقة الأعشاب من قدر الفاصوليا وتخلّص من المنكّهات; انزع اللحم عن العظم، قطّعه خشناً واحتفظ به; أدرج معجون الطماطم والطماطم المقطّعة في سائل الفاصوليا، ثم تذوّق وأضف 1,5 ملعقة صغيرة من الملح والفلفل. ركّب الكاسوليه في كاسول واسع قطره 26 سم (أو أي قدر واسع يصلح للفرن); افرد ثلث الفاصوليا في القاع، ثم رتّب كتف الخنزير المحمَّر، بطن الخنزير، لحم الساق وأفخاذ البط الكونفي الباردة فوقها; غطّ بثلث آخر من الفاصوليا، ضع النقانق المحمَّرة فوقها، ثم أنهِ بالثلث الأخير; اسكب من سائل الفاصوليا حتى يكاد يغطي الطبقة العلوية — احتفظ بالباقي دافئاً لإضافته لاحقاً. رشّ البقسماط بالتساوي فوقه; ضع الكاسول في الفرن مكشوفاً واطبخه ساعة واحدة; سيتلوّن البقسماط ويتشكّل قشرة بنيّة. بعد ساعة، اكسر القشرة بضغطها داخل الكاسوليه بظهر ملعقة خشبية — لا تقلّبه; أضف مغرفة من سائل الفاصوليا المحفوظ إن بدا جافاً; أعده إلى الفرن واطبخه ساعة إضافية مع كسر القشرة مرة أخرى بعد 30 دقيقة، حتى تتشكّل قشرة جديدة وتغلي الفاصوليا بعمق على الحواف. كرّر مرة أخرى: اكسر القشرة، أعد إضافة السائل واخبزه 30–40 دقيقة أخيرة; زمن الفرن الإجمالي نحو 2 ساعة و30 دقيقة — ثلاث قشور في المجموع; اترك الكاسوليه يرتاح 10 دقائق خارج الفرن لتعيد الفاصوليا امتصاص السائل; رشّ البقدونس المفروم وقدّمه مباشرة من الكاسول مع خبز مقرمش وسلطة خضراء.","en":"The night before, place the beans in a large bowl, cover with at least 2 litres of cold water, and soak for 10–12 hours; they will roughly double in size; drain and rinse the next day. Make the bean stock; put the drained beans in a heavy 5-litre pot with the pork knuckle (if using), the studded onion, the halved garlic head, the carrot chunks, the bouquet garni, and 1.5 litres of cold stock; bring to a gentle simmer and cook uncovered for 50–60 minutes, until the beans are just tender but not falling apart; do not salt yet. Meanwhile, brown the meats; heat 2 tbsp duck fat in a wide skillet over medium-high heat; pat the pork shoulder and pork belly dry and brown in batches for 4–5 minutes per side until deep golden; lift onto a plate; in the same fat, brown the Toulouse sausages for 2–3 minutes per side just to colour the casings; add to the plate. Heat the oven to 160°C (320°F / fan 140°C); lift the cooked knuckle, onion, garlic, carrot, and bouquet garni out of the bean pot and discard the aromatics; pull any meat from the knuckle bone, shred coarsely, and reserve; stir the tomato paste and chopped tomatoes into the bean liquid, then taste and add 1.5 tsp salt and the pepper. Assemble the cassoulet in a wide 26 cm cassole (or any wide oven-safe pot); spread one-third of the beans on the bottom, then arrange the browned pork shoulder, pork belly, knuckle meat, and the cold confit duck legs on top; cover with another third of the beans, lay the browned sausages on top, then finish with the remaining beans; pour over enough bean liquid to just cover the top layer of beans — keep the rest warm for topping up. Sprinkle the breadcrumbs evenly over the top; place the cassole in the oven, uncovered, and cook for 1 hour; the breadcrumbs will gild and form a brown crust. After 1 hour, break the crust by pressing it down into the cassoulet with the back of a wooden spoon — do not stir; top up with a ladle of reserved bean liquid if it looks dry; return to the oven and cook for another hour, breaking the crust again after 30 minutes, until a fresh crust has formed and the cassoulet is bubbling deeply around the edges. Repeat once more: break the crust, top up the liquid, and bake a final 30–40 minutes; the total oven time is about 2 h 30 m — three crusts in all; rest the cassoulet for 10 minutes out of the oven so the beans drink back the liquid; scatter with chopped parsley and serve straight from the pot, with crusty bread and a green salad."},"timeMins":{"total":240,"active":45}},{"id":144,"origin":{"ar":"كرواتيا","en":"Croatia","ro":"Croația"},"name":{"ar":"باستيكادا","en":"Pasticada","ro":"Pašticada"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ar":["1,2 كغ من لحم الردف البقري أو الفخذ العلوي، قطعة واحدة","100 غ من شحم ظهر الخنزير أو البانشيتا، مقطّع شرائح 5 ملم × 5 سم للتلحيم","2 جزرة متوسطة (نحو 200 غ): 1 مقطّعة عيدان للتلحيم، 1 مقطّعة مكعبات صغيرة للصلصة","10 حبات قرنفل كاملة (5 للتلحيم، 5 للنقع) + 0,5 ملعقة صغيرة من القرنفل المطحون للصلصة","6 فصوص ثوم مقشّرة — 3 مهروسة للنقع، 3 مفرومة ناعماً للصلصة","200 مل من خل النبيذ الأبيض + 200 مل من الماء البارد + 3 ورقات غار + 1 ملعقة صغيرة من حبات الفلفل الأسود + 4 حبات عرعر (للنقع)","2 بصلتان كبيرتان (نحو 400 غ)، مفرومتان ناعماً","200 غ من البرقوق المجفف منزوع النوى","100 مل من نبيذ بروشيك الحلو (أو مارسالا حلو أو 1 ملعقة كبيرة سكر بني + 80 مل بورت)","500 مل من نبيذ أحمر جاف (Plavac Mali، Merlot أو أي نبيذ أحمر جاف قوي)","300 مل من مرق لحم بقري بلا ملح","2 ملعقة كبيرة من معجون الطماطم + 200 غ من الطماطم المقطّعة المعلّبة","1 ملعقة صغيرة من القرفة المطحونة + 0,5 ملعقة صغيرة من جوزة الطيب المبشورة الطازجة","50 غ من الشحم (أو 3 ملاعق كبيرة من زيت الزيتون)، للتحمير","1,5 ملعقة صغيرة من ملح البحر الناعم، ويُضاف حسب الذوق","0,5 ملعقة صغيرة من الفلفل الأسود المطحون الطازج، للإنهاء","بقدونس طازج مفروم ناعماً، للتزيين","نيوكي أو معكرونة طازجة (نحو 500 غ)، للتقديم"],"en":["1.2 kg beef rump or topside, in one piece","100 g pork fat back or pancetta, cut into 5 mm × 5 cm strips for larding","2 medium carrots (about 200 g): 1 cut into matchsticks for larding, 1 finely diced for the sauce","10 whole cloves (5 for larding, 5 for the marinade) + 0.5 tsp ground cloves for the sauce","6 garlic cloves, peeled — 3 crushed for the marinade, 3 finely chopped for the sauce","200 ml white wine vinegar + 200 ml cold water + 3 bay leaves + 1 tsp black peppercorns + 4 juniper berries (for the marinade)","2 large onions (about 400 g), finely diced","200 g pitted prunes (dried plums)","100 ml prošek dessert wine (or sweet Marsala or 1 tbsp brown sugar + 80 ml port)","500 ml dry red wine (Plavac Mali, Merlot, or any robust dry red)","300 ml unsalted beef stock","2 tbsp tomato paste + 200 g canned chopped tomatoes","1 tsp ground cinnamon + 0.5 tsp freshly grated nutmeg","50 g lard (or 3 tbsp olive oil), for browning","1.5 tsp fine sea salt, plus more to taste","0.5 tsp freshly ground black pepper, for finishing","Fresh parsley, finely chopped, to garnish","Gnocchi or fresh pasta (about 500 g), to serve"],"ro":["1,2 kg vrăbioară sau pulpă de vită, într-o singură bucată","100 g slană de porc sau pancetta, tăiată fâșii de 5 mm × 5 cm pentru împănat","2 morcovi medii (aproximativ 200 g): 1 tăiat fâșii subțiri pentru împănat, 1 tăiat cuburi mici pentru sos","10 cuișoare întregi (5 pentru împănat, 5 pentru marinadă) + 0,5 linguriță cuișoare măcinate pentru sos","6 căței de usturoi decojiți — 3 zdrobiți pentru marinadă, 3 tocați fin pentru sos","200 ml oțet de vin alb + 200 ml apă rece + 3 foi de dafin + 1 linguriță boabe de piper negru + 4 boabe de ienupăr (pentru marinadă)","2 cepe mari (aproximativ 400 g), tocate fin","200 g prune uscate fără sâmburi","100 ml vin dulce prošek (sau Marsala dulce, sau 1 lingură zahăr brun + 80 ml porto)","500 ml vin roșu sec (Plavac Mali, Merlot sau orice vin sec robust)","300 ml supă de vită nesărată","2 linguri pastă de roșii + 200 g roșii sfărâmate din conservă","1 linguriță scorțișoară măcinată + 0,5 linguriță nucșoară proaspăt rasă","50 g untură (sau 3 linguri ulei de măsline), pentru rumenire","1,5 lingurițe sare fină de mare, plus după gust","0,5 linguriță piper negru proaspăt măcinat, pentru finisare","Pătrunjel proaspăt tocat fin, pentru garnitură","Gnocchi sau paste proaspete (aproximativ 500 g), pentru servit"]},"howIsMade":{"ar":"اليوم الأول، لحّم اللحم; بسكين حادة، اعمل 16 شقاً عميقاً على سطح قطعة اللحم; أدخل في كل شق شريطاً من شحم الخنزير، عوداً من الجزر، و(في الشقوق المتناوبة) نصف قرنفلة كاملة; الدهن يروي اللحم من الداخل، والجزر يحلّي الصلصة، والقرنفل يعطّر اللحم. حضّر النقع; في وعاء غير تفاعلي بحجم يكفي اللحم بالكاد، اخلط 200 مل من خل النبيذ، 200 مل من الماء البارد، 3 فصوص الثوم المهروسة للنقع، 3 ورقات غار، حبات الفلفل، حبات العرعر، والـ 5 قرنفلات الكاملة المتبقية; اغمر اللحم، غطّه وضعه في الثلاجة 24 ساعة (حتى 48)، مع تقليبه مرّتين. اليوم الثاني، أخرج اللحم، اكشط التوابل العالقة وجفّفه جيداً — اللحم الرطب لا يتحمّر; تخلّص من النقيع; تبّل اللحم بـ 1 ملعقة صغيرة من الملح و0,5 ملعقة صغيرة من الفلفل. سخّن الشحم في قدر ثقيل أو حلّة (28 سم) على نار متوسطة-عالية; حمّر اللحم من جميع الجوانب 3–4 دقائق لكل جانب، ما مجموعه 12–15 دقيقة، حتى يكتسب لوناً بنياً مهاغونياً موحداً; ارفعه إلى طبق. خفّض النار إلى متوسطة; أضف البصل المفروم ورشّة ملح إلى الدهن المذاب واطبخه 10–12 دقيقة مع التحريك المتكرر حتى يكتسب لوناً بنياً ذهبياً عميقاً — هذه الكاراميلية البطيئة هي أساس الصلصة; أضف الجزر المكعّب والثوم المفروم واطبخهما 3–4 دقائق إضافية; أدرج معجون الطماطم والقرنفل المطحون والقرفة وجوزة الطيب وحمّصهم 1 دقيقة. اسكب البروشيك وحرّك دقيقة واحدة مع كشط القاع; أضف النبيذ الأحمر، ارفع النار وقلّله إلى النصف (نحو 6–8 دقائق); أضف الطماطم المقطّعة، مرق اللحم، البرقوق المجفف، وما تبقّى 0,5 ملعقة صغيرة من الملح; أعد اللحم إلى القدر مغموساً في السائل — يجب أن تصل الصلصة إلى ثلاثة أرباع ارتفاع اللحم تقريباً. غطّ القدر بإحكام وحضّره على أقل نار (أو في الفرن على 150 درجة مئوية) 2 ساعة و30 دقيقة – 3 ساعات، مع تقليب اللحم كل 45 دقيقة، حتى تدخل السكين في المنتصف بدون مقاومة; انقل اللحم إلى لوح واتركه يرتاح مغطّى بورق ألمنيوم 15 دقيقة. أنهِ الصلصة; أخرج البرقوق واحتفظ بحفنة للتزيين؛ اخلط الباقي مع الصلصة بخلاط يدوي حتى تصبح كثيفة لامعة (أو مرّرها عبر مصفاة لتشطيب أنعم); قلّلها مكشوفة 5–8 دقائق إن احتاجت إلى تكثيف — يجب أن تغلّف ظهر الملعقة وأن يكون مذاقها حلواً-حامضاً-متبّلاً بعمق; قطّع اللحم المرتاح عكس الألياف إلى شرائح 1 سم، رتّبها فوق نيوكي دافئ أو معكرونة طازجة، اسكب الصلصة بسخاء، رشّ البرقوق المحفوظ والبقدونس المفروم وقدّمها فوراً.","en":"Day 1, lard the beef; using a sharp paring knife, make 16 deep slits across the surface of the beef joint; slide a strip of pork fat, a carrot matchstick, and (in alternate slits) half of a whole clove into each slit; the fat will baste the meat from the inside, the carrot will sweeten the sauce, and the cloves perfume the meat. Make the marinade; in a non-reactive bowl just large enough to hold the beef, combine 200 ml wine vinegar, 200 ml cold water, the 3 crushed marinade garlic cloves, 3 bay leaves, peppercorns, juniper berries, and the remaining 5 whole cloves; submerge the beef, cover, and refrigerate 24 hours (up to 48 hours), turning twice. Day 2, lift the beef out, scrape off any clinging spices, and pat thoroughly dry — wet meat will not brown; discard the marinade; season the meat with 1 tsp salt and 0.5 tsp pepper. Heat the lard in a heavy Dutch oven or braiser (28 cm) over medium-high heat; sear the beef on all sides for 3–4 minutes per side, about 12–15 minutes total, until evenly mahogany brown all over; lift onto a plate. Reduce the heat to medium; add the diced onion and a pinch of salt to the rendered fat and cook for 10–12 minutes, stirring often, until deeply golden brown — this slow caramelisation builds the sauce; add the diced carrot and chopped garlic and cook for another 3–4 minutes; stir in the tomato paste, ground cloves, cinnamon, and nutmeg and toast for 1 minute. Pour in the prošek and stir for 1 minute, scraping the base; add the red wine, raise the heat, and reduce by half (about 6–8 minutes); add the chopped tomatoes, beef stock, prunes, and the remaining 0.5 tsp salt; return the beef to the pot, settling it into the liquid — the sauce should come about three-quarters of the way up the meat. Cover with a tight lid and braise on the lowest hob heat (or in a 150°C oven) for 2 h 30 m – 3 h, turning the beef every 45 minutes, until a knife slides into the centre with no resistance; lift the beef onto a board and rest, tented with foil, for 15 minutes. Finish the sauce; lift out the prunes and reserve a handful for garnish; blend the rest with the sauce using a stick blender to a thick, glossy gravy (or push through a sieve for a finer finish); reduce uncovered for 5–8 minutes if it needs thickening — it should coat the back of a spoon and taste deeply sweet-sour-spiced; slice the rested beef across the grain into 1 cm slices, fan over warm gnocchi or fresh pasta, spoon the sauce generously, scatter with reserved prunes and chopped parsley, and serve immediately."}},{"id":145,"origin":{"ar":"قبرص","en":"Cyprus","ro":"Cipru"},"name":{"ar":"شيفتاليا","en":"Sheftalia","ro":"Sheftalia"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"mediterranean","ingredients":{"ar":["400 غ من كتف الخنزير مفروم خشناً (15–20% دهن)","300 غ من كتف الضأن مفروم خشناً (أو 700 غ من الخنزير فقط إذا لم يتوفّر الضأن)","300 غ من غشاء الشحم (لحم خنزير أو ضأن)، منقوع في ماء بارد مالح قليلاً 30 دقيقة ثم مصفّى — ورقة بحجم نحو 30 × 30 سم","1 بصلة كبيرة (نحو 200 غ)، مبشورة ومعصورة من السوائل الزائدة","30 غ من البقدونس مسطح الأوراق، مفروم ناعماً","20 غ من النعناع الطازج (دياسموس قبرصي)، مفروم ناعماً (اختياري لكنه تقليدي)","4 فصوص ثوم، مفرومة ناعماً","1,5 ملعقة صغيرة من ملح البحر الناعم","1 ملعقة صغيرة من الفلفل الأسود المطحون الطازج","1 ملعقة صغيرة من الكمون المطحون","0,5 ملعقة صغيرة من القرفة المطحونة","60 مل من نبيذ أبيض جاف أو 2 ملعقة كبيرة من خل النبيذ الأحمر (للربط والترقيق)","1 ملعقة كبيرة من زيت الزيتون لخلطة اللحم","1 ملعقة كبيرة من زيت الزيتون لدهن الشواية","شرائح ليمون، بصل أحمر مشرّح، طماطم مشرّحة، وخبز بيتا دافئ أو خبز ليموني القبرصي، للتقديم","تزاتزيكي أو حمص، للتقديم"],"en":["400 g coarsely minced pork shoulder (15–20% fat)","300 g coarsely minced lamb shoulder (or 700 g all pork if lamb is unavailable)","300 g caul fat (lamb or pork), soaked in cold lightly-salted water for 30 minutes then drained — about a 30 × 30 cm sheet","1 large onion (about 200 g), grated and squeezed of excess liquid","30 g flat-leaf parsley, finely chopped","20 g fresh mint (Cypriot dyosmos), finely chopped (optional but traditional)","4 garlic cloves, finely minced","1.5 tsp fine sea salt","1 tsp freshly ground black pepper","1 tsp ground cumin","0.5 tsp ground cinnamon","60 ml dry white wine or 2 tbsp red wine vinegar (to bind and tenderise)","1 tbsp olive oil for the meat mixture","1 tbsp olive oil for brushing the grill","Lemon wedges, sliced red onion, sliced tomato, and warm pitta or Cypriot lemoni-bread, to serve","Tzatziki or hummus, to serve"],"ro":["400 g umăr de porc tocat grosier (15–20% grăsime)","300 g umăr de miel tocat grosier (sau 700 g doar porc, dacă mielul nu este disponibil)","300 g prapure (de porc sau miel), înmuiat în apă rece ușor sărată 30 de minute, apoi scurs — o foaie de aproximativ 30 × 30 cm","1 ceapă mare (aproximativ 200 g), dată pe răzătoare și stoarsă de lichidul în exces","30 g pătrunjel cu frunze plate, tocat fin","20 g mentă proaspătă (dyosmos cipriot), tocată fin (opțional, dar tradițional)","4 căței de usturoi, tocați fin","1,5 lingurițe sare fină de mare","1 linguriță piper negru proaspăt măcinat","1 linguriță chimion măcinat","0,5 linguriță scorțișoară măcinată","60 ml vin alb sec sau 2 linguri oțet de vin roșu (pentru a lega și a frăgezi)","1 lingură ulei de măsline pentru compoziție","1 lingură ulei de măsline pentru uns grătarul","Felii de lămâie, ceapă roșie feliată, roșii feliate și pita caldă sau pâine cipriotă de lămâie (lemoni), pentru servit","Tzatziki sau hummus, pentru servit"]},"howIsMade":{"ar":"حضّر خليط اللحم; في وعاء واسع، اخلط لحم الخنزير المفروم ولحم الضأن المفروم والبصل المبشور والبقدونس والنعناع (إن استخدمته) والثوم والملح والفلفل والكمون والقرفة والنبيذ (أو الخل) و1 ملعقة كبيرة من زيت الزيتون; اعجن باليد 2–3 دقائق حتى يصبح المزيج لزجاً ومتجانساً; غطّه وضعه في الثلاجة ساعة على الأقل (حتى 12 ساعة) لتنضج التوابل. حضّر غشاء الشحم; افرد الغشاء المنقوع والمصفّى بحذر على لوح نظيف — يتمزّق بسهولة; باستخدام مقص، قطّعه إلى 12 مربّعاً بأبعاد نحو 12 × 12 سم; أصلح أي ثقوب بتراكب القطع. شكّل قطع الشفتاليا; خذ مقدار ملعقة كبيرة من اللحم (نحو 50–60 غ) وشكّله أسطوانة دقيقة قليلاً بطول 7–8 سم; ضعها عند حافة أحد المربعات; اطوِ الجانبين فوق اللحم ثم لُفّه بإحكام إلى شكل سجق مع جعل الخط المغلق للأسفل; مرّر سيخاً معدنياً عبره إن وُجد — وإلا فالخط المغلق سيكفي; كرّر العملية مع البقية: ستحصل على 12 شفتاليا، 3 لكل شخص. ضع السجق الملفوف على صينية وبرّده في الثلاجة 15 دقيقة على الأقل (حتى 4 ساعات) لتتماسك الطبقة — يثبت أفضل على الشواية. سخّن شواية الفحم أو مقلاة مضلّعة ثقيلة على نار متوسطة-عالية (سطحها بنحو 200 درجة مئوية); ادهنها بـ 1 ملعقة كبيرة من زيت الزيتون; يجب أن تطقطق الشفتاليا عند ملامستها الشواية لكن دون اشتعال شديد — حرارة مفرطة ستحرق الغشاء قبل نضوج اللحم. اشوِ الشفتاليا 12–15 دقيقة في المجموع، مع تقليبها كل 3–4 دقائق على كل جانب من جوانبها الأربعة، حتى يذوب الغشاء إلى قشرة رفيعة دانتيلية وتصل حرارة المركز إلى 70 درجة مئوية; يجب أن تكون ذهبية غامقة ومتماسكة دون أن تكون قاسية. انقل الشفتاليا إلى لوح وغطِّها برخاوة بورق ألمنيوم 5 دقائق; تستقر العصارة ويُكمل اللحم نضجه بالحرارة المتبقية. سخّن البيتا أو خبز الليموني على الشواية 30 ثانية لكل جانب; ضع 3 شفتاليا لكل شخص على الطبق مع الخبز الدافئ وشرائح الليمون والبصل الأحمر والطماطم; قدّم التزاتزيكي أو الحمص جانباً; تُؤكل بتمزيق قطع الشفتاليا داخل البيتا مع السلطة والصلصة.","en":"Make the meat mixture; in a wide bowl combine the minced pork, minced lamb, grated onion, parsley, mint (if using), garlic, salt, pepper, cumin, cinnamon, wine (or vinegar), and 1 tbsp olive oil; knead with your hand for 2–3 minutes until sticky and homogeneous; cover and chill in the fridge for at least 1 hour (up to 12 hours) so the seasoning matures. Prepare the caul fat; spread the soaked and drained caul fat carefully on a clean board — it tears very easily; use scissors to cut it into 12 squares of about 12 × 12 cm; patch holes by overlapping pieces. Shape the sheftalia; take a tablespoon-sized portion of meat (about 50–60 g) and shape into a slightly tapered cylinder 7–8 cm long; place at the edge of one caul-fat square; fold the sides over the meat, then roll up tightly into a sausage shape, finishing with the seam underneath; pierce onto a metal skewer if you have one — otherwise the wrapped seam will hold; repeat with the remaining meat and caul fat: you should get 12 sheftalia, 3 per person. Rest the wrapped sausages on a tray and chill for at least 15 minutes (up to 4 hours) so the caul fat firms — they hold together better on the grill. Heat a charcoal grill or a heavy ridged griddle pan to medium-high (about 200°C / 390°F surface); brush lightly with 1 tbsp olive oil; the sheftalia should hiss when they touch the grill but not flare aggressively — too high and the caul fat will burn before the meat cooks through. Grill the sheftalia for 12–15 minutes total, turning every 3–4 minutes onto each of their four sides, until the caul fat has rendered down into a thin lacy crust and the meat reaches 70°C in the centre; they should be deep golden brown and feel firm but not hard. Lift the sheftalia onto a board and rest, loosely tented with foil, for 5 minutes; the juices settle and the meat finishes cooking from residual heat. Warm the pitta or Cypriot lemoni-bread on the grill for 30 seconds per side; pile 3 sheftalia per person on each plate with the warm bread, lemon wedges, sliced red onion, and tomato; spoon tzatziki or hummus to the side; eat by tearing pieces of sheftalia into the pitta with the salad and dip."}},{"id":146,"origin":{"ar":"البوسنة والهرسك","en":"Bosnia and Herzegovina","ro":"Bosnia și Herțegovina"},"name":{"ar":"تشيفابي","en":"Cevapi","ro":"Cevapi"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ar":["500 غ من لحم البقر المفروم خشناً (نحو 15% دهن)","300 غ من كتف الضأن المفروم خشناً (أو 800 غ من البقر فقط إذا لم يتوفّر الضأن)","4 فصوص ثوم، مهروسة مع 0,5 ملعقة صغيرة من الملح إلى عجينة ناعمة","60 مل من ماء فوّار بارد","1 ملعقة صغيرة من بيكربونات الصوديوم — سرّ القوام النابض","1,5 ملعقة صغيرة من ملح البحر الناعم","1 ملعقة صغيرة من الفلفل الأسود المطحون الطازج","1 ملعقة صغيرة من البابريكا المجرية الحلوة","0,5 ملعقة صغيرة من البردقوش أو الأوريغانو المجفف (اختياري لكنه تقليدي)","1 ملعقة كبيرة من زيت محايد للدهن","4 أرغفة سومون (أو 4 أرغفة بيتا)، قطر كل منها نحو 18 سم، للتقديم","1 بصلة حمراء كبيرة (نحو 200 غ)، مفرومة فرماً ناعماً جداً","200 غ من الأجڤار (معجون الفلفل الأحمر المشوي)","100 غ من الكايماك (قشدة بلقانية كثيفة) أو كريم فريش سميك كبديل","حزمة صغيرة من البقدونس مسطح الأوراق، تُقطف أوراقه، للنثر"],"en":["500 g coarsely minced beef chuck (about 15% fat)","300 g coarsely minced lamb shoulder (or 800 g all beef if lamb is unavailable)","4 garlic cloves, crushed with 0.5 tsp salt to a fine paste","60 ml chilled sparkling water","1 tsp baking soda (sodium bicarbonate) — the key to the springy texture","1.5 tsp fine sea salt","1 tsp freshly ground black pepper","1 tsp sweet Hungarian paprika","0.5 tsp dried marjoram or oregano (optional but traditional)","1 tbsp neutral oil for brushing","4 somun flatbreads (or 4 pittas), about 18 cm across each, to serve","1 large red onion (about 200 g), very finely diced","200 g ajvar (roasted red-pepper relish)","100 g kajmak (Balkan clotted cream) or thick crème fraîche, as a substitute","1 small bunch flat-leaf parsley, leaves picked, to scatter"],"ro":["500 g pulpă de vită tocată grosier (15% grăsime)","300 g umăr de miel tocat grosier (sau 800 g doar vită, dacă nu există miel)","4 căței de usturoi, zdrobiți cu 0,5 linguriță sare într-o pastă fină","60 ml apă minerală rece (carbogazoasă)","1 linguriță bicarbonat de sodiu — cheia texturii elastice","1,5 lingurițe sare fină de mare","1 linguriță piper negru proaspăt măcinat","1 linguriță boia dulce maghiară","0,5 linguriță maghiran sau oregano uscat (opțional, dar tradițional)","1 lingură ulei neutru pentru uns","4 lipii somun (sau 4 pita) de aproximativ 18 cm fiecare, pentru servit","1 ceapă roșie mare (aproximativ 200 g), tocată foarte fin","200 g ajvar (pastă de ardei copți)","100 g kajmak (smântână groasă balcanică) sau crème fraîche groasă ca substitut","1 legătură mică de pătrunjel cu frunze plate, frunzele păstrate, pentru servit"]},"howIsMade":{"ar":"حضّر خليط اللحم; في وعاء واسع، اخلط لحم البقر المفروم ولحم الضأن المفروم وعجينة الثوم والملح والماء الفوّار البارد وبيكربونات الصوديوم والملح والفلفل والبابريكا والبردقوش; اعجن بقوة باليد 4–5 دقائق — يجب أن يصبح المزيج لزجاً بشكل واضح ويتماسك جيداً; هذا العجن الطويل والبيكربونات هما ما يمنحان الـشيفابي قواماً ناعماً مرناً. غطّ الوعاء بغشاء بلاستيكي واترك الخليط يرتاح في الثلاجة 4 ساعات على الأقل، ويُفضّل 12–24 ساعة; تنضج النكهات وترتاح البروتينات. بلّل يديك بماء بارد; خذ مقدار ملعقة كبيرة من اللحم (نحو 35–40 غ) ولفّه بين راحتيك أسطوانة بشكل إصبع بطول 7–8 سم وسماكة 2 سم; كرّر مع باقي اللحم لتحصل على نحو 24 قطعة شيفابي (6 لكل شخص); رتّبها على صينية مع التقدّم. برّد الشيفابي المشكّل 20 دقيقة على الأقل (حتى 4 ساعات) لتتماسك — تحتفظ بشكلها أفضل على الشواية. سخّن شواية الفحم أو مقلاة ثقيلة مضلّعة على نار متوسطة-عالية (سطحها نحو 220 درجة مئوية); ادهن الشيفابي بطبقة خفيفة جداً من الزيت — مجرد لمسة; يجب أن تطقطق الشواية عند ملامستها، دون دخان شديد. اشوِ الشيفابي 8–10 دقائق إجمالاً، مع تقليبها كل دقيقتين على جوانبها الأربعة، حتى يصبح السطح بنياً ماهوغانياً بحواف مقرمشة ويصل المركز إلى 65 درجة مئوية (سيواصل النضوج على الطبق); لا تضغطها؛ الهدف هو داخل عصاري نابض. خلال راحة الشيفابي دقيقتين، سخّن خبز السومون (أو البيتا) على الشواية 30 ثانية لكل جانب حتى ينتفخ قليلاً ويأخذ بعض السواد الخفيف; اشقّ كلًا منها على طول الخط لتشكّل جيباً. ضع 6 قطع شيفابي داخل كل رغيف دافئ (أو رتّب 6 بجانب الخبز في كل طبق); ضع 1–2 ملعقة كبيرة من الأجڤار على جانب، وأضف ملعقة سخية من الكايماك (أو الكريم فريش) وكومة صغيرة من البصل الأحمر النيء المفروم; رشّ أوراق البقدونس وقدّم فوراً — يجب أن تتشرّب عصارات الشيفابي بخبز السومون.","en":"Make the meat mixture; in a wide bowl combine the minced beef, minced lamb, garlic-salt paste, chilled sparkling water, baking soda, salt, pepper, paprika, and marjoram; knead vigorously with your hand for 4–5 minutes — the mixture should become noticeably sticky and start to pull together; this long knead and the bicarbonate are what give cevapi their characteristic springy bounce. Cover the bowl with cling film and rest the mixture in the fridge for at least 4 hours, ideally 12–24 hours; the flavour matures and the proteins relax. Wet your hands with cold water; take a tablespoon-sized portion of meat (about 35–40 g) and roll it between your palms into a finger-shaped cylinder about 7–8 cm long and 2 cm thick; repeat with the remaining meat to make about 24 cevapi (6 per person); arrange on a tray as you go. Chill the shaped cevapi for at least 20 minutes (up to 4 hours) to firm — they hold their shape better on the grill. Heat a charcoal grill or a heavy ridged griddle pan to medium-high (about 220°C surface); brush the cevapi very lightly with oil — barely a glaze; the grill should hiss but not smoke aggressively. Grill the cevapi for 8–10 minutes total, turning every 2 minutes onto all four sides, until the surface is mahogany brown with crisp edges and the centre reaches 65°C (they continue cooking on the plate); do not press them down; the goal is juicy, springy interiors. While the cevapi rest for 2 minutes, warm the somun (or pittas) on the grill 30 seconds per side until just puffed and lightly charred; split each one open along the seam to make a pocket. Pile 6 cevapi inside each warm flatbread (or arrange 6 on each plate beside the bread); spoon 1–2 tablespoons of ajvar to one side, add a generous knob of kajmak (or crème fraîche), and a small mound of diced raw red onion; scatter parsley leaves and serve immediately — the cevapi juices should soak into the somun."}},{"id":147,"origin":{"ar":"غانا","en":"Ghana","ro":"Ghana"},"name":{"ar":"فوفو","en":"Fufu","ro":"Fufu"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"veg","pairingsType":"veg","ingredients":{"ar":["700 غ من جذر الكسافا الطازج، مقشّر ومقطّع قطعاً 5 سم (أو 500 غ من الكسافا المجمّدة المقشّرة مسبقاً، مذابة)","500 غ من موز الجنة نصف الناضج، حوالي 3 حبات كبيرة، مقشّرة ومقطّعة قطعاً 5 سم (القشرة الصفراء المنقّطة بالأسود تعطي توازناً مناسباً بين الحلاوة والنشا)","1 ملعقة كبيرة من ملح البحر الناعم لماء السلق","2 لتر من الماء البارد للسلق","نحو 150 مل من ماء السلق الساخن، يُحتفظ به دافئاً في إبريق","1 ملعقة كبيرة من زيت محايد (نخيل أو دوار شمس)، لدهن اليدين ووعاء التقديم","قدر كبير من الحساء الغرب أفريقي الساخن (600 مل–1 لتر من light soup أو حساء جوز النخيل أو الفول السوداني أو الإيغوسي)، للتقديم","فلفل سكوتش بونيت طازج مقطّع شرائح، لمن يرغب بمزيد من الحرارة","فول سوداني محمص أو مهروس، للنثر على الحساء (اختياري)"],"en":["700 g fresh cassava root, peeled and cut into 5 cm chunks (or 500 g pre-peeled frozen cassava chunks, thawed)","500 g semi-ripe plantains, about 3 large, peeled and cut into 5 cm chunks (yellow skin streaked with black gives the right balance of sweet and starchy)","1 tbsp fine sea salt for the cooking water","2 litres cold water for boiling","About 150 ml hot cooking water reserved from the pot, kept warm in a jug","1 tbsp neutral oil (palm or sunflower), for oiling hands and the serving bowl","1 large pot of hot West African soup (600 ml–1 L of light soup, palmnut, groundnut, or egusi), for serving","Sliced fresh scotch bonnet chilli, for those who want extra heat","Roasted peanuts or crushed groundnuts, to scatter over the soup (optional)"],"ro":["700 g manioc proaspăt, curățat și tăiat bucăți de 5 cm (sau 500 g cassava decongelată, deja curățată)","500 g banane plantain semi-coapte, aproximativ 3 mari, decojite și tăiate bucăți de 5 cm (coaja galbenă cu pete negre dă echilibrul potrivit între dulce și amidonos)","1 lingură sare fină de mare pentru apa de fierbere","2 litri apă rece pentru fierbere","Aproximativ 150 ml apă fierbinte de fierbere păstrată separat, ținută caldă într-un vas","1 lingură ulei neutru (palmier sau floarea-soarelui), pentru a unge mâinile și bolul de servit","O cratiță mare cu supă vest-africană caldă (600 ml–1 L de light soup, palmnut, groundnut sau egusi), pentru servit","Ardei iute scotch bonnet feliat, pentru cei care vor mai mult picant","Arahide prăjite sau pisate, pentru presărat peste supă (opțional)"]},"howIsMade":{"ar":"حضّر الكسافا; اغسل القطع تحت ماء بارد لإزالة الأوساخ; بسكين حادة، اشقّ القشرة البنية السميكة طولياً وانزعها (مع الطبقة الوردية الداخلية) لكشف اللب الأبيض; أزل الخيط الليفي المركزي من كل قطعة وتخلّص منه. في قدر سميك بسعة 5 لترات، ضع قطع الكسافا المقشّرة، قطع موز الجنة، 1 ملعقة كبيرة من الملح، و2 لتر من الماء البارد; ارفعه إلى غليان خفيف على نار متوسطة-عالية، خفّض إلى متوسطة-منخفضة واطبخ 30–40 دقيقة حتى تنضج كل من الكسافا وموز الجنة بحيث تخترقهما الشوكة بسهولة — يجب أن تكون الكسافا بقوام البطاطس المسلوقة. صفِّ في مصفاة لكن احتفظ بـ 250 مل على الأقل من سائل السلق الساخن في إبريق; التقط وتخلّص من أي ألياف ظاهرة. اهرس الفوفو; الطريقة التقليدية: انقل خليط الكسافا والموز الساخن دفعات إلى مهراس خشبي ثقيل مدهون بقطرات زيت; بمدقّة خشبية طويلة، اهرس بإيقاع منتظم بينما يقوم شخص ثانٍ (بأيدٍ مدهونة قليلاً) بتدوير العجينة وجمعها بين الضربات; اعمل 8–10 دقائق لكل دفعة حتى تصبح العجينة كثيفة وملساء ومرنة بوضوح — دون كتل. الطريقة بدون مهراس: ضع الكسافا والموز الساخنين في خلاط واقف متين مزوّد بخطّاف العجين; شغّله على سرعة منخفضة دقيقة لتفتيت القطع، ثم ارفع السرعة إلى المتوسطة واخفق 6–8 دقائق مع كشط الوعاء كل دقيقتين حتى تتشكّل كتلة عجين مرنة حول الخطّاف; أضف ملعقة كبيرة من ماء السلق الساخن في كل مرة إن كانت جافة — الهدف لمعان ومرونة دون رطوبة. اختبر القوام; اقتطع قطعة صغيرة (نحو 50 غ) ودحرجها بين راحتيك المدهونتين قليلاً إلى كرة ملساء; يجب أن يكون السطح لامعاً وبلا تشققات، وأن تحتفظ الكرة بشكلها دون أن تترهل أو تتشقق; إن تشقّقت، أضف ملعقة ماء ساخن إضافية؛ وإن ترهّلت اعجن دقيقتين إضافيتين. شكّل حصص التقديم بأيدٍ مدهونة قليلاً: 4 كرات كبيرة بحجم نحو 250 غ لكل واحدة (أو 8 أصغر لحصص فردية تقليدية); ضع كل كرة في وعاء واسع مدهون قليلاً حتى لا تلتصق; غطّها بقطعة قماش رطبة حتى التقديم — يتصلّب الفوفو بسرعة عند تعرضه للهواء. قدّم فوراً; اسكب حساء غرب أفريقي ساخن (light soup أو حساء جوز النخيل أو الفول السوداني أو إيغوسي) في وعاء واسع حول كل كرة فوفو; يُؤكل بقرص قطعة صغيرة من الفوفو باليد اليمنى، الضغط بالإبهام لتشكيل كأس صغير، واستخدامها لغرف الحساء — لا يُمضغ الفوفو، بل يُبتلع كاملاً ليأخذه مذاق الحساء; رشّ الفلفل الأخضر السكوتش بونيت المقطّع والفول السوداني المحمّص حسب الرغبة.","en":"Prepare the cassava; wash the cassava chunks under cold water to remove any clinging grit; with a paring knife slit the thick brown skin lengthwise, then peel it away (along with the pink underlayer) to expose the white core; cut out the fibrous central string from each piece and discard. In a heavy 5-litre pot, combine the peeled cassava chunks, the plantain chunks, the 1 tbsp salt, and the 2 litres cold water; bring to a gentle boil over medium-high heat, then reduce to medium-low and cook for 30–40 minutes, until both cassava and plantain are fork-tender — the cassava should feel like a cooked potato when pierced. Drain into a colander but reserve at least 250 ml of the hot cooking liquid in a jug for later; pick out and discard any visible fibres or strings. Pound the fufu; traditional method: transfer the hot cassava-plantain mixture in batches to a heavy wooden mortar lubricated with a few drops of oil; with a long wooden pestle, pound rhythmically while a second person (lightly oiled hands) turns and gathers the mass between strokes; work for 8–10 minutes per batch until the paste is dense, perfectly smooth, and noticeably elastic — no lumps remain. Mortar-free method: place the hot cassava and plantain together in a sturdy stand mixer with the dough-hook attachment; run at low speed for 1 minute to break down the chunks, then increase to medium and beat for 6–8 minutes, scraping the bowl every 2 minutes, until the mass forms a single elastic dough around the hook; add a tablespoon of reserved hot cooking water at a time if it is too dry — the goal is glossy and elastic without being wet. Test the texture; pinch off a small piece (about 50 g) and roll it in lightly oiled palms into a smooth ball; the surface should be glossy and seamless, and the ball should hold its shape on a plate without sagging or cracking; if it cracks, work in another spoonful of hot water; if it slumps, knead for another 2 minutes. Shape the serving portions with lightly oiled hands: form 4 large balls of about 250 g each (or 8 smaller balls for traditional individual servings); place each ball in a slightly oiled wide bowl so it does not stick; cover with a damp cloth until ready to serve — fufu hardens quickly when exposed to air. Serve immediately; ladle hot West African soup (light soup, palmnut, groundnut, or egusi) into a wide soup bowl around each fufu ball; eat by pinching off a small piece of fufu with the right hand, pressing a depression into it with the thumb to form a cup, and using it to scoop up the soup — do not chew the fufu, swallow it whole so the flavour of the soup carries it down; scatter chopped scotch bonnet and roasted peanuts to taste."}},{"id":148,"origin":{"ar":"جورجيا","en":"Georgia","ro":"Georgia"},"name":{"ar":"خينكالي","en":"Khinkali","ro":"Khinkali"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ar":["500 غ من الدقيق العادي، مع كمية إضافية للفرد","250 مل من الماء البارد","1 بيضة كبيرة، مخفوقة قليلاً (اختياري — بعض العائلات الجورجية تستخدم بيضة لعجين أنعم)","1 ملعقة صغيرة من ملح البحر الناعم للعجين","1 ملعقة كبيرة من زيت محايد للعجين","500 غ من لحم البقر مفروم خشناً (نحو 15% دهن)","200 غ من كتف الخنزير مفروم خشناً (أو 700 غ من البقر فقط لنتيجة أقل دهنية)","1 بصلة كبيرة (نحو 200 غ)، مفرومة فرماً ناعماً جداً — لا تبشرها، القوام مهم","3 فصوص ثوم، مفرومة ناعماً","20 غ من الكزبرة الطازجة، مفرومة ناعماً — السيقان والأوراق","1 ملعقة صغيرة كمون مطحون + 1 ملعقة صغيرة فلفل أسود مطحون طازج + 0,5 ملعقة صغيرة خميلي سونيلي (أو 0,25 ملعقة صغيرة كراويا + 0,25 ملعقة صغيرة حلبة مطحونة كبديل)","1,5 ملعقة صغيرة من ملح البحر الناعم للحشوة","200 مل من مرق بقر مثلج أو ماء بارد (يطلق البخار ببطء أثناء السلق — هذا سرّ كيس المرق الشهير)","1 ملعقة كبيرة من ملح البحر الخشن لماء السلق","وفير من الفلفل الأسود المطحون الطازج، للنثر على المائدة"],"en":["500 g plain (all-purpose) flour, plus extra for rolling","250 ml cold water","1 large egg, lightly beaten (optional — some Georgian families use an egg for a softer dough)","1 tsp fine sea salt for the dough","1 tbsp neutral oil for the dough","500 g coarsely minced beef (around 15% fat)","200 g coarsely minced pork shoulder (or 700 g all beef for a leaner result)","1 large onion (about 200 g), very finely diced — do NOT grate, the texture matters","3 garlic cloves, finely minced","20 g fresh coriander, finely chopped — stems and leaves","1 tsp ground cumin + 1 tsp freshly ground black pepper + 0.5 tsp khmeli suneli (or 0.25 tsp caraway + 0.25 tsp ground fenugreek as substitute)","1.5 tsp fine sea salt for the filling","200 ml ice-cold beef stock or cold water (releases steam slowly during boiling — this is what creates the famous broth pocket)","1 tbsp coarse sea salt for the cooking water","Plenty of freshly cracked black pepper, to scatter at the table"],"ro":["500 g făină albă obișnuită, plus pentru întins","250 ml apă rece","1 ou mare, bătut ușor (opțional — unele familii georgiene folosesc un ou pentru un aluat mai moale)","1 linguriță sare fină de mare pentru aluat","1 lingură ulei neutru pentru aluat","500 g vită tocată grosier (în jur de 15% grăsime)","200 g umăr de porc tocat grosier (sau 700 g doar vită pentru un rezultat mai slab)","1 ceapă mare (aproximativ 200 g), tocată foarte fin — NU rasă, textura contează","3 căței de usturoi, tocați fin","20 g coriandru proaspăt, tocat fin — tulpini și frunze","1 linguriță chimion măcinat + 1 linguriță piper negru proaspăt măcinat + 0,5 linguriță khmeli suneli (sau 0,25 linguriță chimion negru + 0,25 linguriță schinduf măcinat ca substitut)","1,5 lingurițe sare fină de mare pentru umplutură","200 ml supă de vită rece ca gheața sau apă rece (eliberează aburi încet în timpul fierberii — acesta este secretul pungii de bulion)","1 lingură sare grunjoasă de mare pentru apa de fierbere","Mult piper negru proaspăt măcinat, pentru presărat la masă"]},"howIsMade":{"ar":"العجين: امزج 500 غ من الدقيق مع 1 ملعقة صغيرة ملح في وعاء كبير; اسكب تدريجياً 250 مل من الماء البارد (واختيارياً 1 بيضة مخفوقة + 1 ملعقة كبيرة زيت)، مع التحريك بشوكة، ثم اعجن على الطاولة 8–10 دقائق حتى يصبح العجين أملس وقوياً ومرناً — يجب أن يكون متيناً بما يكفي ليُفرد رقيقاً دون أن يتمزق; غطّ بغشاء واتركه يستريح 30 دقيقة في حرارة الغرفة. الحشوة: في وعاء، اخلط باليد 500 غ بقر + 200 غ خنزير مفروم خشناً مع 200 غ بصل مفروم ناعماً جداً، 3 فصوص ثوم، 20 غ كزبرة مفرومة، 1 ملعقة صغيرة كمون، 1 ملعقة صغيرة فلفل، 0,5 ملعقة صغيرة خميلي سونيلي و1,5 ملعقة صغيرة ملح; اسكب ببطء 200 مل من المرق المثلج، 50 مل في كل مرة، مع التحريك بعد كل إضافة — يجب أن تكون الحشوة فضفاضة ورطبة لكن غير سائلة; غطّ وبرّد 30 دقيقة. الفرد: قسّم العجين إلى 4 قطع; اعمل قطعة واحدة في كل مرة (واترك الباقي مغطى); افرد بسماكة 2 مم على سطح مرشوش بالدقيق; قطّع دوائر بقطر 12–14 سم بصحن صغير أو كأس كبير; اجمع البقايا، اعجنها قليلاً ثم افرد من جديد. التشكيل: ضع دائرة في راحة يدك، ضع نحو 30 مل (2 ملعقة كبيرة) من الحشوة في الوسط; باليد الأخرى، شكّل 18–20 طية حول الحشوة، اقرص كل طية بين الإبهام والسبابة ولفّها برفق نحو المركز; في النهاية اجمع كل الطيات في الأعلى ولفّ الطرف — الذيل — للإغلاق; ضع الخينكالي على سطح مرشوش بالدقيق. ماء السلق: اغلِ 4 لترات من الماء في قدر كبير على غليان قوي وأضف 1 ملعقة كبيرة من الملح الخشن. السلق: أنزل 5–6 قطع خينكالي في الماء المغلي (دون ازدحام); فور أن تطفو على السطح (بعد 2–3 دقائق)، شغّل المؤقت: اسلق 8–10 دقائق إضافية; المجموع 12–14 دقيقة; تكون جاهزة عندما تصبح الطيات شفافة ويُرى المرق يتحرك في الداخل. الإخراج: ارفعها بمصفاة كبيرة، دعها تتصفى قليلاً ورتّبها في صحن دافئ; انثر فوراً وفيراً من الفلفل الأسود المطحون الطازج; بدون أي صلصة — الخينكالي تُؤكل عارية. كيفية الأكل: امسك الخينكالي من الذيل بأصابعك، أمِلها قليلاً وعضّ ثقباً صغيراً قرب الخياطة، ثم ارشف المرق الساخن من الداخل أولاً قبل أن ينسكب; كُل الباقي تاركاً الذيل الملتوي في الصحن; عدد الذيول المتبقية = كم أكلت.","en":"DOUGH: mix 500 g flour with 1 tsp salt in a large bowl; gradually pour in 250 ml cold water (and optionally 1 beaten egg + 1 tbsp oil), stirring with a fork, then knead on the bench 8–10 minutes until the dough is smooth, firm and elastic — it needs to be tough enough to roll thin without tearing; cover with film and rest 30 minutes at room temperature. FILLING: in a bowl, mix by hand 500 g beef + 200 g pork coarse-mince with 200 g very finely diced onion, 3 garlic cloves, 20 g chopped coriander, 1 tsp cumin, 1 tsp black pepper, 0.5 tsp khmeli suneli and 1.5 tsp salt; slowly pour in 200 ml ice-cold stock, 50 ml at a time, mixing after each addition — the filling should be loose and wet but not soupy; cover and chill 30 minutes. ROLLING: divide the dough into 4 pieces; work one piece at a time (keep the rest covered); roll out to a 2 mm thin sheet on a lightly floured surface; cut 12–14 cm diameter circles with a saucer or large glass; gather scraps, knead briefly and roll again. SHAPING: place a circle in your palm, put about 30 ml (2 tbsp) of filling in the centre; with the other hand, form 18–20 pleats around the filling, pinching each pleat between thumb and forefinger and twisting it gently toward the centre; at the end, gather all pleats at the top and twist the tip — the tail — to seal; set the khinkali on a floured surface. COOKING WATER: bring 4 litres of water to a vigorous rolling boil in a large pot and add 1 tbsp coarse salt. BOILING: drop 5–6 khinkali at a time into the boiling water (do not crowd); the moment they float to the surface (after 2–3 minutes), start your timer: boil another 8–10 minutes; total 12–14 minutes; they are done when the pleats turn translucent and you can see the broth moving inside. REMOVING: lift them out with a slotted spoon, let drain briefly and arrange on a warm plate; immediately scatter plenty of freshly cracked black pepper over the top; no sauce — khinkali are eaten plain. HOW TO EAT: hold the khinkali by the tail with your fingers, tilt slightly and bite a small hole near the seam, then sip the hot broth from inside first before it spills; then eat the rest of the dumpling, leaving the twisted tail on the plate; the number of tails left = how many you ate."}},{"id":149,"origin":{"ar":"المكسيك","en":"Mexico","ro":"Mexic"},"name":{"ar":"بوزولي","en":"Pozole","ro":"Pozole"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"servings":6,"tipType":"meat","pairingsType":"mexican","ingredients":{"ar":["1,2 كغ من كتف الخنزير منزوع العظم، مقطع إلى مكعبات 4 سم","500 غ من عظام رقبة أو ذيل الخنزير (لمرق أغنى)","1 بصلة بيضاء كبيرة مشقوقة نصفين بقشرتها (للون) + 1 بصلة صغيرة مفرومة ناعماً للتقديم","8 فصوص ثوم (6 للمرق، 2 لصلصة الفلفل)","3 ورقات غار","1 ملعقة كبيرة ملح خشن للمرق + ملح حسب الذوق","4 لترات ماء بارد للمرق","800 غ ذرة هوميني معلبة، مصفاة ومغسولة (أو 250 غ مجففة منقوعة طوال الليل ومسلوقة على حدة)","6 فلفل غواخيو مجفف، منزوع العنق والبذور","4 فلفل أنشو مجفف، منزوع العنق والبذور","2 فلفل دي أربول مجفف (اختياري، لمزيد من الحرارة)","1 ملعقة صغيرة كمون مطحون","1 ملعقة صغيرة أوريجانو مكسيكي مجفف","200 غ ملفوف أخضر مقطع ناعماً للتقديم","150 غ فجل أحمر مقطع شرائح رقيقة","4–6 ليم مقطع إلى أرباع","12 توستادا (خبز تورتيا الذرة المقرمش)","أوريجانو طازج أو مجفف للنثر على المائدة"],"en":["1.2 kg boneless pork shoulder, cut into 4 cm cubes","500 g pork neck bones or pork tail (for a richer broth)","1 large white onion halved, skin on (for color) + 1 small onion finely diced for serving","8 garlic cloves (6 for the broth, 2 for the chili sauce)","3 bay leaves","1 tbsp coarse salt for the broth + salt to taste","4 litres cold water for the broth","800 g canned hominy, drained and rinsed (or 250 g dried hominy soaked overnight and boiled separately)","6 dried guajillo chilies, stemmed and deseeded","4 dried ancho chilies, stemmed and deseeded","2 dried árbol chilies (optional, for heat)","1 tsp ground cumin","1 tsp dried Mexican oregano","200 g green cabbage, finely shredded for serving","150 g red radishes, thinly sliced","4–6 limes cut into wedges","12 tostadas (crisp corn tortillas)","Fresh or dried oregano to scatter at the table"],"ro":["1,2 kg umăr de porc dezosat, tăiat în cuburi de 4 cm","500 g oase de porc cu carne (gât sau coadă) pentru un bulion mai bogat","1 ceapă albă mare tăiată în jumătăți (cu coajă, pentru culoare) + 1 ceapă mică tocată fin pentru servire","8 căței de usturoi (6 pentru bulion, 2 pentru sosul de ardei)","3 frunze de dafin","1 lingură sare grunjoasă pentru bulion + sare după gust","4 litri apă rece pentru bulion","800 g hominy din conservă, scurs și clătit (sau 250 g hominy uscat înmuiat peste noapte și fiert separat)","6 ardei guajillo uscați, decotorați și fără semințe","4 ardei ancho uscați, decotorați și fără semințe","2 ardei de árbol uscați (opțional, pentru iuțeală)","1 linguriță chimion măcinat","1 linguriță oregano mexican uscat","200 g varză verde tocată mărunt, pentru servire","150 g ridichi roșii feliate subțire","4–6 lime tăiate în sferturi","12 tostadas (lipii de porumb crocante)","Oregano proaspăt sau uscat de presărat la masă"]},"howIsMade":{"ar":"أساس المرق: في قدر كبير ضع 1,2 كغ من لحم الخنزير المقطع مكعبات + 500 غ من عظام الخنزير، 1 بصلة مشقوقة نصفين (بقشرتها)، 6 فصوص ثوم، 3 ورقات غار و1 ملعقة كبيرة ملح; غطّ بـ4 لترات من الماء البارد; اتركه يغلي، أزل الرغوة في أول 5 دقائق، ثم خفف الحرارة لغليان هادئ. سلق اللحم: اتركه يغلي بهدوء مكشوفاً 1,5–2 ساعة حتى يتفكك اللحم بالشوكة; أخرج اللحم والعظام، فكّك اللحم خشناً بشوكتين، ضعه جانباً; صفِّ المرق (~3,5 لتر) واتخلص من المتبقي. تحميص الفلفل: سخّن مقلاة جافة على نار متوسطة; حمّص 6 فلفل غواخيو + 4 أنشو + 2 دي أربول (اختياري) بالضغط عليها بملعقة، 30 ثانية لكل جانب حتى تصبح عطرية ومنتفخة قليلاً — لا تحرقها وإلا أصبح المرق مرّاً; انقلها إلى وعاء، غطها بماء مغلي، وانقعها 15 دقيقة حتى تطرى. صلصة الفلفل: انقل الفلفل المنقوع إلى خلاط مع 2 فص ثوم، 1 ملعقة صغيرة كمون، 1 ملعقة صغيرة أوريجانو و500 مل من المرق الدافئ; اخلط بأقصى سرعة 2–3 دقائق حتى تصبح ناعمة تماماً; مرّر الصلصة عبر مصفاة دقيقة فوق وعاء، اضغط اللب من خلال المصفاة — تخلص من قطع القشرة. الجمع: أعد الصلصة المصفاة إلى قدر المرق; أضف اللحم المفكك و800 غ من الهوميني المصفّى; اتركها على نار هادئة بدون غطاء 30–40 دقيقة، مع التحريك من حين لآخر، حتى يثخن المرق قليلاً وتتمازج النكهات; تذوّق وعدّل الملح — يجب أن يكون نكهة عميقة. تجهيز المرفقات: أثناء غليان البوزولي، قطّع 200 غ ملفوف ناعماً، شرّح 150 غ فجل، قطّع 1 بصلة ناعماً، قطّع 4–6 ليم إلى أرباع، وحضّر الأوريجانو; ضع كلاً منها في صحون صغيرة على المائدة. التوستاداس: سخّن 12 توستادا في مقلاة جافة 30 ثانية لكل جانب حتى تصبح مقرمشة وذهبية قليلاً; ضعها في سلة على المائدة. التقديم: اغرف البوزولي في صحون عميقة; كل ضيف يخصص صحنه: حفنة ملفوف، رش فجل، رشة بصل وأوريجانو، عصرة ليم; التوستاداس تؤكل إلى جانب الصحن — تكسر في المرق أو تستخدم للغرف; تُؤكل فوراً وهي ساخنة جداً.","en":"BROTH BASE: place 1.2 kg cubed pork shoulder + 500 g pork bones, 1 halved onion (skin on), 6 garlic cloves, 3 bay leaves and 1 tbsp salt in a large stockpot; cover with 4 litres of cold water; bring to a boil, skim the foam for the first 5 minutes, then reduce to a gentle simmer. SIMMER THE PORK: simmer uncovered 1.5–2 hours until the pork is fork-tender; lift out meat and bones, shred the meat coarsely with two forks, set aside; strain the broth (~3.5 L) and discard the solids. TOAST THE CHILIES: heat a dry skillet over medium heat; toast 6 guajillo + 4 ancho + 2 árbol chilies (optional), pressing them down with a spatula, 30 seconds per side until fragrant and lightly blistered — do not burn or the broth will turn bitter; transfer to a bowl, cover with boiling water, and soak 15 minutes until softened. CHILI SAUCE: transfer the soaked chilies to a blender with 2 garlic cloves, 1 tsp cumin, 1 tsp oregano and 500 ml of the warm broth; blend on high 2–3 minutes until completely smooth; strain the puree through a fine sieve into a bowl, pressing the pulp through — discard the skin bits left behind. COMBINE: pour the strained chili sauce back into the broth pot; add the shredded pork and 800 g drained hominy; bring to a simmer and cook uncovered 30–40 minutes, stirring occasionally, until the broth thickens slightly and the flavours meld; taste and adjust salt — it should be deeply savoury. PREP THE GARNISHES: while the pozole simmers, finely shred 200 g cabbage, thinly slice 150 g radishes, finely dice 1 onion, cut 4–6 limes into wedges, prepare oregano; arrange each in small bowls on the table. TOSTADAS: warm 12 tostadas in a dry skillet 30 seconds per side until crisp and lightly toasted; place in a basket for the table. SERVE: ladle the pozole into deep bowls; each guest customises their bowl: a handful of cabbage, scattering of radish, pinch of onion and oregano, squeeze of lime; tostadas eaten alongside — broken into the broth or used to scoop; eaten immediately while piping hot."}},{"id":150,"origin":{"ar":"غواتيمالا","en":"Guatemala","ro":"Guatemala"},"name":{"ar":"بيبيان","en":"Pepian","ro":"Pepian"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"mexican","ingredients":{"ar":["1,2 كغ من أفخاذ الدجاج وأرجله السفلية بالعظم (نحو 8 قطع)","1,5 لتر ماء بارد + 1 ملعقة صغيرة ملح لسلق الدجاج","100 غ بذور قرع نيئة مقشّرة (بيبيتاس)","50 غ بذور سمسم","4 فلفل غواخيو مجفف، منزوع العنق والبذور","2 فلفل أنشو أو باسيا مجفف، منزوع العنق والبذور","1 فلفل شيبوتلي مجفف (اختياري للنكهة الدخانية)","4 طماطم متوسطة (~500 غ)، مشقوقة نصفين","4 توماتيو (~200 غ)، منزوع القشرة ومشقوق نصفين","1 بصلة متوسطة (~150 غ)، مقطعة إلى أرباع","5 فصوص ثوم بقشرتها","1 عود قرفة سيلانية (~5 سم)","2 قرنفل كامل","1 ملعقة صغيرة فلفل أسود مطحون + 0,5 ملعقة صغيرة بهار حلو مطحون","1 خبز تورتيا الذرة، ممزقة (للتثخين)","200 غ تشايوت أو كوسة بديلة، مقشّرة ومقطعة مكعبات 2 سم","300 غ بطاطس، مقشّرة ومقطعة مكعبات 2 سم","2 ملعقة كبيرة زيت نباتي لقلي العجينة","2 ملعقة كبيرة كزبرة طازجة، مفرومة ناعماً، للتزيين","ملح حسب الذوق","500 غ أرز أبيض مطبوخ + خبز تورتيا دافئ للتقديم"],"en":["1.2 kg bone-in chicken thighs and drumsticks (about 8 pieces)","1.5 L cold water + 1 tsp salt for poaching","100 g raw hulled pumpkin seeds (pepitas)","50 g sesame seeds","4 dried guajillo chilies, stemmed and deseeded","2 dried ancho or pasilla chilies, stemmed and deseeded","1 dried chipotle chili (optional, for smokiness)","4 medium tomatoes (~500 g), halved","4 tomatillos (~200 g), husked and halved","1 medium onion (~150 g), quartered","5 unpeeled garlic cloves","1 Ceylon cinnamon stick (~5 cm)","2 whole cloves","1 tsp ground black pepper + 0.5 tsp ground allspice","1 corn tortilla, torn into pieces (for thickening)","200 g güisquil (chayote squash) or zucchini, peeled and cubed 2 cm","300 g potatoes, peeled and cubed 2 cm","2 tbsp vegetable oil for cooking the paste","2 tbsp fresh cilantro, finely chopped, to garnish","Salt to taste","500 g cooked white rice + warm tortillas to serve"],"ro":["1,2 kg pulpe și pulpe inferioare de pui cu os (aproximativ 8 bucăți)","1,5 L apă rece + 1 linguriță sare pentru fierberea puiului","100 g semințe crude de dovleac decojite (pepitas)","50 g semințe de susan","4 ardei guajillo uscați, decotorați și fără semințe","2 ardei ancho sau pasilla uscați, decotorați și fără semințe","1 ardei chipotle (opțional, pentru afumare)","4 roșii medii (~500 g), tăiate în jumătăți","4 tomatillos (~200 g), curățați de coajă și tăiați în jumătăți","1 ceapă medie (~150 g), tăiată în sferturi","5 căței de usturoi, necurățați","1 batjoc de scorțișoară Ceylon (~5 cm)","2 cuișoare întregi","1 linguriță piper negru măcinat + 0,5 linguriță ienibahar măcinat","1 tortilla de porumb, ruptă în bucăți (pentru îngroșare)","200 g chayote (sau dovlecel ca substitut), curățat și tăiat cuburi de 2 cm","300 g cartofi, curățați și tăiați cuburi de 2 cm","2 linguri ulei vegetal pentru sotare","2 linguri coriandru proaspăt, tocat fin, pentru ornare","Sare după gust","500 g orez alb gătit + tortillas calde pentru servire"]},"howIsMade":{"ar":"سلق الدجاج: ضع 1,2 كغ من الدجاج في 1,5 لتر ماء بارد مع 1 ملعقة صغيرة ملح في قدر كبير; اتركه يغلي، أزل الرغوة، خفف الحرارة لغليان هادئ; اطبخ 25–30 دقيقة حتى يكون الدجاج مطهواً للتو (تخرج العصارة صافية); أخرج الدجاج إلى صحن واحتفظ بالمرق (~1,2 لتر). تحميص البذور: في مقلاة جافة على نار متوسطة، حمّص 100 غ بذور قرع، مع التحريك المستمر، 3–4 دقائق حتى تنتفخ وتذهب — لا تحرقها; انقلها إلى وعاء; في نفس المقلاة، حمّص 50 غ سمسم 1–2 دقيقة حتى يذهب ويفوح، مع التحريك; أضفه إلى نفس الوعاء. حرق الخضار: في مقلاة جافة أو كومال على نار متوسطة-عالية، احرق 4 أنصاف طماطم (الوجه المقطع لأسفل أولاً)، 4 أنصاف توماتيو، 1 بصلة بأرباع و5 فصوص ثوم بقشرتها; اقلبها بين الحين والآخر 8–10 دقائق حتى يسود القشر في أماكن ويلين الخضار; قشّر الثوم بعد أن يبرد. تحميص الفلفل والتوابل: في نفس المقلاة، حمّص بسرعة 4 غواخيو + 2 أنشو + 1 شيبوتلي (اختياري) بالضغط بملعقة، 20–30 ثانية لكل جانب حتى تفوح — لا تحرقها; انقلها إلى وعاء وغطها بماء مغلي؛ انقعها 15 دقيقة; في نفس المقلاة، حمّص بسرعة 1 عود قرفة، 2 قرنفل، 1 ملعقة صغيرة فلفل و0,5 ملعقة صغيرة بهار حلو 30 ثانية; حمّص قطع التورتيا 30 ثانية لكل جانب حتى تكون مقرمشة. خلط العجينة: في خلاط، ادمج الفلفل المصفى، الخضار المحروقة، الثوم المقشّر، البذور المحمصة، قطع التورتيا و500 مل من مرق الدجاج; اخلط بأقصى سرعة 3–4 دقائق حتى تصبح العجينة ناعمة تماماً — مرّر عبر مصفاة دقيقة إذا أردتها حريرية. طهي الصلصة: سخّن 2 ملعقة كبيرة من الزيت في القدر على نار متوسطة; اسكب العجينة — كن حذراً، ستنفجر; اطبخها 10 دقائق، مع التحريك المتكرر بملعقة خشبية، حتى تغمق الصلصة ويختفي الطعم النيء; يجب أن تغطي الصلصة ظهر الملعقة. طهي الدجاج: أعد قطع الدجاج إلى القدر، ثم اسكب الـ700 مل المتبقية من المرق + 200 غ تشايوت + 300 غ مكعبات بطاطس; اطبخها بهدوء، مغطاة جزئياً، 25–30 دقيقة حتى تنضج البطاطس والتشايوت ويتشرّب الدجاج بالصلصة; حرّك بين الحين والآخر; عدّل الملح. التقديم: اغرف البيبيان في صحون عميقة فوق طبقة من الأرز الأبيض المطهو بالبخار; زيّن كل حصة بكزبرة طازجة وعصرة ليم (اختياري); قدّم مع التورتيا الدافئة على الجانب لجمع الصلصة.","en":"POACH THE CHICKEN: place 1.2 kg chicken pieces in 1.5 L cold water with 1 tsp salt in a large pot; bring to a boil, skim the foam, then reduce to a gentle simmer; cook 25–30 minutes until the chicken is just cooked through (juices run clear); remove the chicken to a plate and reserve the broth (~1.2 L). TOAST THE SEEDS: in a dry skillet over medium heat, toast 100 g pumpkin seeds, stirring constantly, 3–4 minutes until they puff up and turn golden brown — do not burn; transfer to a bowl; in the same skillet, toast 50 g sesame seeds 1–2 minutes until golden and fragrant, stirring constantly; add to the same bowl. CHAR THE VEGETABLES: in a dry skillet or comal over medium-high heat, char 4 halved tomatoes (cut side down first), 4 halved tomatillos, 1 quartered onion, and 5 unpeeled garlic cloves; turn occasionally for 8–10 minutes until the skins are blackened in spots and the vegetables soften; peel the garlic after they cool. TOAST THE CHILIES AND SPICES: in the same skillet, briefly toast 4 guajillo + 2 ancho + 1 chipotle (optional) chilies, pressing them flat with a spatula, 20–30 seconds per side until fragrant — do not burn; transfer to a bowl and cover with boiling water; soak 15 minutes; in the same skillet, briefly toast 1 cinnamon stick, 2 cloves, 1 tsp pepper, and 0.5 tsp allspice for 30 seconds; toast the torn tortilla pieces 30 seconds per side until crisp. BLEND THE PASTE: in a blender, combine the drained chilies, the charred vegetables, peeled garlic, toasted seeds, toasted tortilla pieces, and 500 ml of the chicken broth; blend on high 3–4 minutes until the paste is completely smooth — strain through a fine sieve if you want it silky. COOK THE SAUCE: heat 2 tablespoons of oil in the pot over medium heat; pour in the blended paste — be careful, it will splutter; simmer 10 minutes, stirring frequently with a wooden spoon, until the sauce darkens and the rawness cooks off; the sauce should coat the back of the spoon. STEW THE CHICKEN: return the chicken pieces to the pot, then pour in the remaining 700 ml broth + 200 g chayote + 300 g potato cubes; simmer gently, partially covered, 25–30 minutes until the potatoes and chayote are fork-tender and the chicken is fully infused with the sauce; stir occasionally to prevent sticking; adjust salt to taste — the sauce should taste deeply spiced and slightly sweet. SERVE: spoon the pepian into deep plates over a bed of steamed white rice; top each serving with a sprinkle of fresh cilantro and a squeeze of lime (optional); serve with warm corn tortillas on the side for scooping up the sauce."}},{"id":151,"origin":{"ar":"روسيا","en":"Russia","ro":"Rusia"},"name":{"ar":"أوكروشكا","en":"Okroshka","ro":"Okroshka"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"soup","ingredients":{"ar":["1 لتر كفير سادة 3,2% دسم، مبرّد جيداً","500 مل ماء معدني غير غازي بارد (أو ماء مغلي بارد)، مبرّد","500 غ بطاطس متوسطة الحجم نشوية (4 حبات)، مسلوقة بقشرها ثم مقشرة ومقطعة مكعبات 1 سم","4 بيضات كبيرة مسلوقة بصلابة، مقشرة ومقطعة مكعبات 1 سم","400 غ خيار (3 متوسطة)، مقشّر، إزالة البذور الكبيرة وتقطيع مكعبات 0,5 سم","300 غ نقانق دكتورسكايا مطبوخة أو لحم خنزير مسلوق، مقطعة مكعبات 0,5 سم","150 غ فجل أحمر، مقشّر ومقطع مكعبات 0,5 سم","6 بصل أخضر (الأجزاء البيضاء والخضراء منفصلة)، مقطع شرائح رقيقة","30 غ شبت طازج، مفروم ناعماً (مع 1 ملعقة كبيرة للتزيين)","1 ملعقة كبيرة من خردل ديجون (اختياري لكنه تقليدي)","1,5 ملعقة صغيرة ملح ناعم + 0,5 ملعقة صغيرة فلفل أسود مطحون","1 ملعقة صغيرة سكر (يوازن حموضة الكفير)","1 ملعقة صغيرة عصير ليمون أو خل النبيذ الأبيض","كريمة حامضة (سمتانا) للتقديم","مكعبات ثلج وخبز جاودار طازج للتقديم"],"en":["1 L plain kefir (3.2% fat), well chilled","500 ml cold still mineral water (or cold boiled water), chilled","500 g medium starchy potatoes (4 pieces), boiled in skins then peeled and diced 1 cm","4 large hard-boiled eggs, peeled and diced 1 cm","400 g cucumbers (3 medium), peeled, large seeds scooped out, diced 0.5 cm","300 g cooked doktorskaya sausage or boiled ham, diced 0.5 cm","150 g red radishes, trimmed and diced 0.5 cm","6 spring onions (whites and greens kept separate), thinly sliced","30 g fresh dill, finely chopped (plus 1 tbsp to garnish)","1 tbsp Dijon-style mustard (optional but traditional)","1.5 tsp fine salt + 0.5 tsp freshly ground black pepper","1 tsp sugar (balances the kefir tang)","1 tsp lemon juice or white-wine vinegar","Sour cream (smetana) to drizzle when serving","Ice cubes and fresh dark rye bread for serving"],"ro":["1 L chefir simplu 3,2% grăsime, bine răcit","500 ml apă minerală plată rece sau apă fiartă rece, răcită","500 g cartofi medii (4 bucăți) fierți în coajă, decojiți și tăiați cuburi de 1 cm","4 ouă mari fierte tari, decojite și tăiate cuburi de 1 cm","400 g castraveți (3 bucăți medii), decojiți, fără sâmburi mari și tăiați cuburi de 0,5 cm","300 g cârnați doktorskaya sau șuncă fiartă, tăiată cuburi de 0,5 cm","150 g ridichi roșii, tăiate cuburi de 0,5 cm","6 cepe verzi (cu părți albe și verzi separate), feliate subțire","30 g mărar proaspăt, tocat fin (plus 1 lingură pentru ornare)","1 lingură muștar Dijon (opțional, dar tradițional)","1,5 lingurițe sare fină + 0,5 linguriță piper negru proaspăt măcinat","1 linguriță zahăr (echilibrează aciditatea chefirului)","1 linguriță suc de lămâie sau oțet de vin alb","Smântână (smetana) pentru servire","Cuburi de gheață și pâine neagră proaspătă pentru servire"]},"howIsMade":{"ar":"سلق البطاطس والبيض: في قدر بماء بارد مملح، اسلق 500 غ من البطاطس كاملة (بقشرها مفروكة) 20–25 دقيقة حتى تنضج تماماً; في قدر ثانٍ، ضع 4 بيضات في ماء بارد، اتركها تغلي ثم اسلقها 9 دقائق لتصبح بصلابة; صفِّ كليهما، غطّ البطاطس بماء بارد لتسهيل التقشير، اغمر البيض في ماء بثلج 5 دقائق; قشّر وقطّع كليهما مكعبات 1 سم؛ افردها على صينية وبرّدها 30 دقيقة في الثلاجة — يجب أن يكون كل شيء بارداً قبل الخلط. الخيار: قشّر 400 غ خيار، شقّه طولياً، أفرغ البذور المائية الكبيرة بملعقة، ثم قطّعه مكعبات 0,5 سم — المكعب الصغير المتساوي ضروري، القطع الكبيرة تغرق وتفسد الحساء; جفّفه بمنشفة ورقية. البروتين: قطّع 300 غ نقانق مطبوخة أو لحم خنزير مسلوق إلى مكعبات 0,5 سم — بنفس حجم الخيار حتى تكون كل ملعقة متوازنة. الفجل والبصل: قطّع 150 غ فجل إلى مكعبات 0,5 سم; شرّح 6 بصلات خضراء (مع فصل الأبيض عن الأخضر); افرم 30 غ شبت ناعماً، احتفظ بـ1 ملعقة كبيرة للتزيين; في وعاء صغير، اهرس 2 ملعقة كبيرة من البصل الأبيض مع رشة ملح بظهر الملعقة — يطلق العطر في الحساء. الصلصة: في وعاء كبير، اخفق 1 لتر كفير بارد + 500 مل ماء بارد + 1 ملعقة كبيرة خردل + 1 ملعقة صغيرة عصير ليمون + 1,5 ملعقة صغيرة ملح + 0,5 ملعقة صغيرة فلفل + 1 ملعقة صغيرة سكر; اخفق 30 ثانية حتى يتجانس ثم تذوّق — يجب أن يكون الأساس حامضاً قليلاً وحلواً قليلاً، متبّلاً بسخاء لأن المكونات ستخفّفه. التجميع: أضف جميع المكونات المقطعة (البطاطس، البيض، الخيار، النقانق، الفجل، البصل الأخضر، البصل الأبيض المهروس، الشبت) إلى قاعدة الكفير; اخلط برفق بمغرفة للتوزيع المتساوي دون سحق أي شيء. التبريد: غطّ الأوكروشكا وبرّدها في الثلاجة 30 دقيقة كحدّ أدنى (مثالياً ساعة واحدة) حتى تمتزج النكهات ويصبح الحساء بارداً جداً; لا تتجاوز 3 ساعات — الخيار سيبدأ بإطلاق الماء وسيصبح الحساء مخفّفاً. التقديم: حرّك برفق قبل التقديم; اغرف في صحون عميقة مبرّدة; زيّن كل وعاء بـ1 ملعقة كبيرة كريمة حامضة، بعض أعواد الشبت الإضافية، و2 مكعبي ثلج في موجات الحر الصيفية; قدّمها فوراً مع الخبز الجاودار الطازج؛ الخردل على المائدة لمن يرغب بنكهة أقوى.","en":"BOIL THE POTATOES AND EGGS: in a pot of cold salted water, boil 500 g whole potatoes (skins on, scrubbed) 20–25 min until fork-tender; in a second pot, place 4 eggs in cold water, bring to a boil, then simmer 9 min for hard-boiled; drain both, cover potatoes with cold water to peel easily, plunge eggs into ice water 5 min; peel and dice both 1 cm; spread on a tray and chill 30 min in the fridge — everything must be cold before mixing. DICE THE CUCUMBERS: peel 400 g cucumbers, halve lengthwise, scoop out any large watery seeds with a spoon, then dice 0.5 cm — the small even cube is essential, larger pieces sink and ruin the soup; pat with paper towel to remove excess water. DICE THE PROTEIN: dice 300 g cooked sausage or boiled ham into 0.5 cm cubes — the same size as the cucumbers so each spoonful balances. DICE RADISH AND ONIONS: trim and dice 150 g radishes 0.5 cm; slice 6 spring onions (whites and greens kept separate); finely chop 30 g dill, reserve 1 tbsp for garnish; in a small bowl, mash 2 tbsp of the spring-onion whites with a pinch of salt using the back of a spoon — this releases their aroma into the soup. THE DRESSING: in a large mixing bowl, whisk together 1 L cold kefir + 500 ml cold water + 1 tbsp mustard + 1 tsp lemon juice + 1.5 tsp salt + 0.5 tsp pepper + 1 tsp sugar; whisk 30 seconds until smooth, then taste — the base should be tangy and slightly sweet, generously seasoned because the diced ingredients will dilute it. ASSEMBLE: add all diced ingredients (potatoes, eggs, cucumbers, sausage, radish, spring-onion greens and mashed whites, dill) to the kefir base; stir gently with a ladle to distribute evenly without crushing anything. CHILL: cover and refrigerate the okroshka 30 minutes minimum (ideally 1 hour) so the flavours mingle and the soup becomes ice-cold; do not chill longer than 3 hours — the cucumbers will start to release water and the soup turns thin. SERVE: stir gently before serving; ladle into deep, well-chilled bowls; top each bowl with 1 tablespoon sour cream, a few extra dill fronds, and 2 ice cubes per bowl in summer heat; serve immediately with fresh dark rye bread on the side; mustard on the table for those who like it sharper."}},{"id":152,"origin":{"ar":"أوزبكستان","en":"Uzbekistan","ro":"Uzbekistan"},"name":{"ar":"بلاف","en":"Plov","ro":"Plov"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":6,"tipType":"meat","pairingsType":"meat","ingredients":{"ar":["600 غ من كتف الضأن أو رقبة البقر مع بعض الدهن، مقطعة مكعبات 3 سم","100 غ من دهن ذيل الضأن (كردياك) للنكهة الأصيلة — أو 150 مل من زيت دوار الشمس المحايد كبديل","500 غ من أرز ديفزيرا أو أرز بسمتي طويل الحبة","500 غ من الجزر الأصفر (أو 600 غ من الجزر البرتقالي)، مقطع جوليان 0,5 × 0,5 × 5 سم — لا تبشره","2 بصلة صفراء كبيرة (~300 غ)، مقطعة شرائح رفيعة","2 رأس ثوم كامل (مع إزالة القشور الخارجية مع بقاء الرؤوس كاملة)","1 ملعقة كبيرة من بذور الكمون الكاملة (غير مطحونة)","1 ملعقة كبيرة من ثمار البرباريس المجففة (زيرا/بارباريس) — اختياري لكنه تقليدي","0,5 ملعقة صغيرة كركم مطحون (للون)","1 فلفل أحمر حار مجفف كامل (اختياري)","1 ملعقة صغيرة فلفل أسود مطحون","1,5 ملعقة كبيرة ملح ناعم + ملح حسب الذوق","1,2 لتر ماء مغلي (احتياطي)","100 غ من الحمص، منقوع طوال الليل (اختياري، تقليدي طشقند)","للتقديم: بصل أحمر مقطع شرائح رفيعة مع خل، سلطة أتشيتشوك من الطماطم والخيار، خبز مسطح (نون)"],"en":["600 g lamb shoulder or beef chuck with some fat, cut into 3 cm cubes","100 g lamb-tail fat (kurdyuk) for authentic flavour — OR 150 ml neutral sunflower oil as a substitute","500 g devzira or long-grain basmati rice","500 g yellow carrots (or 600 g orange carrots), cut into julienne matchsticks 0.5 × 0.5 × 5 cm — do NOT grate","2 large yellow onions (~300 g), thinly sliced","2 whole heads of garlic (papery outer skins removed but heads intact)","1 tbsp whole cumin seeds (not ground)","1 tbsp dried barberries (zira/barbaris) — optional but traditional","0.5 tsp ground turmeric (for colour)","1 dried whole hot red chili (optional)","1 tsp ground black pepper","1.5 tbsp fine salt + extra to season","1.2 L boiling water (reserve)","100 g chickpeas, soaked overnight (optional, traditional Tashkent style)","To serve: thinly sliced red onion with vinegar, achichuk tomato-cucumber salad, flatbread (non)"],"ro":["600 g umăr de miel sau gulaș de vită cu puțină grăsime, tăiat cuburi de 3 cm","100 g grăsime de coadă de oaie (kurdyuk) — opțional pentru aromă autentică — SAU 150 ml ulei neutru de floarea-soarelui ca substitut","500 g orez devzira sau basmati cu bob lung","500 g morcovi galbeni (sau 600 g morcovi portocalii), tăiați julien în bețișoare de 0,5 × 0,5 × 5 cm — NU dați prin răzătoare","2 cepe galbene mari (~300 g), feliate subțire","2 căpățâni de usturoi întregi (cu coaja exterioară curățată, dar capul păstrat întreg)","1 lingură semințe de chimion întregi (nu măcinate)","1 lingură fructe uscate de cătină (zira/barbaris) — opțional, tradițional","0,5 linguriță turmeric măcinat (pentru culoare)","1 ardei roșu iute uscat întreg (opțional)","1 linguriță piper negru măcinat","1,5 linguri sare fină + sare după gust","1,2 L apă clocotită (rezerve)","100 g năut, înmuiat peste noapte (opțional, tradițional Tashkent)","Pentru servire: ceapă roșie feliată subțire cu oțet, salată de roșii cu castraveți (achichuk), pâine plată non"]},"howIsMade":{"ar":"نقع الأرز: اغسل 500 غ من الأرز بالماء البارد 4–5 مرات حتى يخرج الماء صافياً، ثم انقعه في ماء دافئ مملح (1 ملعقة صغيرة ملح لكل لتر) لمدة ساعة واحدة; هذه الخطوة لا غنى عنها لطبق البلاف — تبقى الحبوب منفصلة وتمتص المرق بالتساوي; صفّه قبل إضافته إلى القدر مباشرة. صهر الدهن: في كازان حديدي ثقيل أو قدر هولندي على نار متوسطة، اصهر 100 غ من دهن ذيل الضأن حتى يصبح الكسر ذهبياً (نحو 8 دقائق)، ثم أزله بمصفاة; عند استخدام الزيت: سخّن 150 مل من الزيت حتى يلمع ويدخن قليلاً (نحو 3 دقائق على نار عالية) — ضروري لتعطيل الطعم النيء. شواء اللحم: ارفع الحرارة إلى عالية وأضف 600 غ من مكعبات اللحم في طبقة واحدة في الدهن الحار; اشوِ دون تحريك 2–3 دقائق لكل جانب، إجمالي 8–10 دقائق، حتى يحمرّ بعمق من جميع الجوانب; أخرج اللحم إلى صحن. البصل + الجزر: في الدهن المتبقي، أضف 300 غ من البصل المقطع واقلِ مع التحريك 5–6 دقائق حتى يصبح ذهبياً; أعد اللحم وأضف 500 غ من الجزر بالجوليان في طبقة واحدة فوقه — لا تحرك في الدقائق الـ5 الأولى (دع الجزر يتبخر); ثم اخلط برفق واطبخ 8–10 دقائق أخرى حتى يذبل الجزر، يصبح ذهبياً، ويبدأ التكرمل. الزيرفاك (أساس المرق): اسكب 1,2 لتر من الماء المغلي (يجب أن يغطي اللحم والجزر بـ1 سم); أضف 1 ملعقة كبيرة من بذور الكمون (افركها أولاً بين راحتيك لتطلق الزيوت)، 1 ملعقة كبيرة من البرباريس، 0,5 ملعقة صغيرة كركم، 1 فلفل حار مجفف، 1 ملعقة صغيرة فلفل، 100 غ حمص، 1,5 ملعقة كبيرة ملح، و2 رأس ثوم كامل مدفوعين في المركز; اتركها تغلي، خفف الحرارة واطبخها مكشوفة 30 دقيقة — هذا هو الزيرفاك; يجب أن يبدو المرق متبّلاً قليلاً بزيادة؛ الأرز سيلطّفه. إضافة الأرز: صفِّ الأرز المنقوع بحذر وافرده بالتساوي فوق الزيرفاك (لا تحركه); يجب أن يكون الأرز مغموراً بالكاد — إذا لم يكن كذلك، أضف ماءً مغلياً بحذر; ارفع الحرارة إلى عالية واطبخها مكشوفة 10–12 دقيقة حتى ينخفض الماء الظاهر إلى سطح الأرز (تحقق بعود); افرد الأرز مسطحاً بمصفاة لكن لا تخلطه أبداً بطبقة اللحم. غطّ + بخّر: عندما يتبخر ماء السطح وتظهر فتحات صغيرة على سطح الأرز، شكّل الأرز قبة، اعمل 4–5 ثقوب عميقة حتى القاع بمقبض ملعقة خشبية (لخروج البخار)، خفف الحرارة إلى أدنى مستوى، غطّ القدر بغطاء محكم (ضع منديل مطبخ نظيف تحت الغطاء لامتصاص التكثيف) واطبخ 25 دقيقة; ثم ارفع عن النار واتركه يستريح مغطى 15 دقيقة — لا ترفع الغطاء. التقديم: ارفع الغطاء وأخرج رؤوس الثوم والفلفل; احفر برفق بملعقة، ارفع الأرز وأخرج اللحم والجزر من القاع إلى الأعلى، خالطاً أثناء النقل إلى صحن مشترك كبير; رتّب اللحم والثوم في المركز، محاطاً بالأرز; قدّمه فوراً مع البصل الأحمر المقطع المرشوش بالخل، سلطة الطماطم الطازجة، وخبز مسطح إلى الجانب.","en":"SOAK THE RICE: wash 500 g rice in cold water 4–5 times until the water runs clear, then soak it in warm salted water (1 tsp salt per litre) for 1 hour; this step is non-negotiable for plov — the grains stay separate and absorb the broth evenly; drain just before adding to the pot. RENDER THE FAT: in a heavy cast-iron kazan or Dutch oven over medium heat, melt 100 g lamb-tail fat until the cracklings are golden brown (about 8 minutes), then remove them with a slotted spoon; if using oil: heat 150 ml oil until it shimmers and faintly smokes (about 3 minutes at high heat) — essential to neutralize the raw taste. SEAR THE MEAT: raise heat to high and add 600 g cubed meat in a single layer to the hot fat; sear undisturbed 2–3 minutes per side, total 8–10 minutes, until deeply browned on all sides; lift the meat out to a plate. ONION + CARROT: in the remaining fat, add 300 g sliced onion and fry, stirring, 5–6 minutes until golden brown; return the meat and add 500 g julienned carrots in a single layer on top — do NOT stir for the first 5 minutes (this lets the carrots steam); then stir gently and cook another 8–10 minutes until the carrots are wilted, golden, and just starting to caramelize. ZIRVAK (BROTH BASE): pour in 1.2 L boiling water (it should cover the meat and carrots by 1 cm); add 1 tbsp cumin seeds (first rubbed briefly between your palms to release the oils), 1 tbsp barberries, 0.5 tsp turmeric, 1 dried chili, 1 tsp black pepper, 100 g chickpeas, 1.5 tbsp salt, and the 2 whole garlic heads pushed into the centre; bring to a boil, reduce heat to low and simmer uncovered 30 minutes — this is the zirvak; the broth must taste slightly over-seasoned; the rice will tame it. ADD THE RICE: drain the soaked rice carefully and spread it evenly over the zirvak (do not stir it in); the rice should just be submerged — if not, add boiling water carefully; raise heat to high and cook uncovered 10–12 minutes until the visible water has reduced to the surface of the rice (poke with a chopstick to check); tap the rice flat with a slotted spoon but never mix it with the meat layer below. COVER + STEAM: once the surface water has evaporated and small steam holes appear on the rice surface, mound the rice into a dome, poke 4–5 deep holes through to the bottom with the handle of a wooden spoon (for steam to escape), reduce heat to the lowest setting, cover the pot with a tight lid (place a clean kitchen towel under the lid to absorb condensation), and cook 25 minutes; then remove from heat and let rest, covered, 15 minutes — do not lift the lid. SERVE: uncover and lift out the garlic heads and chili; gently dig down with a spoon, lifting the rice and bringing the meat and carrots from the bottom to the top, mixing as you transfer to a large communal platter; arrange the meat and garlic on top in the centre, surrounded by rice; serve immediately with sliced red onion sprinkled with vinegar, fresh tomato salad, and flatbread on the side."}},{"id":153,"servings":8,"tipType":"dessert","pairingsType":"dessert","origin":{"ar":"سلوفينيا","en":"Slovenia","ro":"Slovenia"},"name":{"ar":"بوتيتسا","en":"Potica","ro":"Potica"},"category":{"ar":"حلويات","en":"Dessert","ro":"Desert"},"ingredients":{"ar":["للعجين: 500 غ من دقيق الخبز القوي، مع كمية إضافية للعجن","7 غ من الخميرة الفورية الجافة أو 21 غ من الخميرة الطازجة","50 غ من السكر الناعم (1 ملعقة صغيرة لتغذية الخميرة، الباقي في العجين)","5 غ من الملح الناعم","250 مل من الحليب كامل الدسم الدافئ (38 °م)","100 غ من الزبدة غير المملحة، مذابة ومبردة إلى فاترة","2 صفار بيض كبير + 1 بيضة كاملة للعجين","1 ملعقة كبيرة رم داكن (اختياري، تقليدي)","بشر ناعم من 1 ليمونة غير معالجة","لحشوة الجوز: 400 غ من الجوز المقشّر المطحون ناعماً (مطحون طازجاً — المطحون مسبقاً لن يصلح)","200 مل من الحليب كامل الدسم الساخن","150 غ من عسل السنط (أو عسل زهري لطيف)","100 غ من الزبدة غير المملحة المذابة للحشوة","100 غ من السكر الناعم للحشوة","2 صفار + 2 بياض بيض (مخفوقين بشكل منفصل حتى تتشكل قمم صلبة)","1 ملعقة كبيرة رم داكن، 1 ملعقة صغيرة قرفة مطحونة، 0,5 ملعقة صغيرة قرنفل مطحون، 1 ملعقة كبيرة بقسماط طازج","للتشطيب: 1 بيضة مخفوقة مع 1 ملعقة كبيرة حليب (للدهن)، سكر بودرة للنثر بعد الخبز"],"en":["For the dough: 500 g bread flour (or strong all-purpose), plus extra for kneading","7 g instant dry yeast OR 21 g fresh yeast","50 g caster sugar (1 tsp to feed the yeast, the rest in the dough)","5 g fine salt","250 ml warm whole milk (38 °C)","100 g unsalted butter, melted and cooled to lukewarm","2 large egg yolks + 1 whole egg for the dough","1 tbsp dark rum (optional, traditional)","Finely grated zest of 1 unwaxed lemon","For the walnut filling: 400 g finely ground shelled walnuts (freshly ground — pre-ground will not work)","200 ml hot whole milk","150 g acacia honey (or mild floral honey)","100 g unsalted butter, melted, for the filling","100 g caster sugar for the filling","2 large egg yolks + 2 egg whites (whipped to stiff peaks separately)","1 tbsp dark rum, 1 tsp ground cinnamon, 0.5 tsp ground cloves, 1 tbsp fresh breadcrumbs","For finishing: 1 egg beaten with 1 tbsp milk (egg wash), icing sugar to dust after baking"],"ro":["Pentru aluat: 500 g făină pentru pâine (T550), plus pentru frământare","7 g drojdie uscată instant SAU 21 g drojdie proaspătă","50 g zahăr fin (1 linguriță pentru a hrăni drojdia, restul în aluat)","5 g sare fină","250 ml lapte integral cald (38 °C)","100 g unt nesărat topit și răcit la călduț","2 gălbenușuri mari + 1 ou întreg pentru aluat","1 lingură rom întunecat (opțional, tradițional)","Coaja rasă fin de la 1 lămâie netratată","Pentru umplutură: 400 g miez de nucă măcinat fin (proaspăt măcinat, nu pre-măcinat — esențial)","200 ml lapte integral fierbinte","150 g miere de salcâm (sau miere florală blândă)","100 g unt nesărat topit pentru umplutură","100 g zahăr fin pentru umplutură","2 gălbenușuri + 2 albușuri (bătute spumă tare separat)","1 lingură rom întunecat, 1 linguriță scorțișoară măcinată, 0,5 linguriță cuișoare măcinate, 1 lingură pesmet proaspăt","Pentru finisare: 1 ou bătut cu 1 lingură lapte (spălătură), zahăr pudră pentru presărat după coacere"]},"howIsMade":{"ar":"تنشيط الخميرة: في وعاء صغير، اذب 7 غ من الخميرة الفورية (أو 21 غ طازجة) في 250 مل من الحليب الدافئ (~38 °م) مع 1 ملعقة صغيرة من السكر; اترك ليرتاح 10 دقائق حتى تظهر رغوة كريمية في الأعلى — إذا لم تترغ، فالخميرة ميتة، ابدأ من جديد. العجين: في خلاط بخطّاف عجن (أو يدوياً)، اخلط 500 غ من الدقيق مع 47 غ من السكر المتبقي و5 غ من الملح وبشر الليمون; اسكب الحليب المخمر، 2 صفار + 1 بيضة كاملة، 100 غ من الزبدة المذابة والمبردة و1 ملعقة كبيرة من الرم; اعجن على سرعة متوسطة لمدة 10 دقائق (أو 15 يدوياً) حتى يصبح العجين أملس ومرناً ويتركز من الوعاء — يجب أن يكون طرياً وغير لزج; غطّ بغشاء واتركه يخمر في مكان دافئ 1,5–2 ساعة حتى يتضاعف. حشوة الجوز: ضع 400 غ من الجوز المطحون طازجاً في وعاء كبير; اسكب فوقه 200 مل من الحليب الساخن، 100 غ من الزبدة المذابة، 150 غ من العسل و100 غ من السكر; اخلطه جيداً لسلق الجوز وإذابة السكر; اتركه يبرد 10 دقائق، ثم أضف 2 صفار، 1 ملعقة كبيرة رم، 1 ملعقة صغيرة قرفة، 0,5 ملعقة صغيرة قرنفل، 1 ملعقة كبيرة بقسماط ورشة ملح; في وعاء آخر، اخفق 2 بياض حتى تتشكل قمم صلبة وأدخلهما برفق في خليط الجوز في 3 إضافات — يجب أن تكون الحشوة هوائية وقابلة للدهن. افرد العجين: رش الدقيق على منشفة نظيفة واقلب العجين المخمر فوقها; اضغط برفق لإخراج الهواء، ثم افرد مستطيلاً رقيقاً 60 × 40 سم بسماكة 4–5 مم — اعمل من المنتصف للخارج، ارفع ودر لمنع الالتصاق; يجب أن يكون العجين رقيقاً بما يكفي لتكون اللولبية مرئية بعد الخبز، لكن سميكاً بما يكفي لحمل الحشوة. افرد الحشوة: افرد حشوة الجوز بالتساوي على العجين، مع ترك حافة 2 سم على الجوانب الطويلة; اضغطه برفق بملعقة — لا تثقل، يجب أن تكون الحشوة بسماكة 5–6 مم; انثر بعض الجوز المطحون الإضافي إذا تسربت بقعة. لفها: باستخدام المنشفة للمساعدة، لف العجين بإحكام من الجانب الطويل، مكوناً جذعاً طويلاً; لف بإحكام لكن ليس بقوة تضغط الحشوة; اقرص الخياطة لإغلاقها وأدخل الأطراف; يجب أن يكون الجذع نحو 60 سم. تشكيل في القالب + التخمير الثاني: ادهن قالب البوتيتسا الأنبوبي (أو قالب بانت 24 سم أو قالب كوغلهوف) بالزبدة جيداً ورش الدقيق; ضع الجذع في القالب بالخياطة لأسفل، وصل الأطراف لتكوين حلقة مغلقة (اقرصها معاً); غطّ بشكل فضفاض واترك ليخمر في مكان دافئ 45–60 دقيقة حتى يرتفع العجين بشكل واضح ويملأ القالب تقريباً; في هذه الأثناء، سخن الفرن إلى 175 °م. اخبز: ادهن الوجه بمزيج البيض; اخبز على الرف الأوسط من الفرن على 175 °م 45–55 دقيقة — غطّ بشكل فضفاض بالألمنيوم بعد 30 دقيقة إذا كان الوجه يتحمر بسرعة; تكون البوتيتسا جاهزة عندما يخرج سيخ نظيفاً وتصل درجة الحرارة الداخلية إلى 92–95 °م; اتركها تستريح 15 دقيقة في القالب، ثم اقلبها بحذر على شبكة لتبرد تماماً; انثر بسخاء السكر البودرة قبل التقطيع; قدّمها بحرارة الغرفة مع قهوة قوية أو شاي.","en":"ACTIVATE THE YEAST: in a small bowl, dissolve 7 g instant dry yeast (or 21 g fresh yeast) into 250 ml warm milk (~38 °C) with 1 tsp sugar; let stand 10 minutes until a creamy foam appears on top — if it doesn't foam, the yeast is dead, start over. THE DOUGH: in a stand mixer with dough hook (or by hand), combine 500 g flour with the remaining 47 g sugar, 5 g salt, and lemon zest; pour in the foamed yeast-milk, 2 egg yolks + 1 whole egg, 100 g melted-and-cooled butter, and 1 tbsp rum; knead on medium speed 10 minutes (or 15 by hand) until the dough is smooth, elastic, and pulls cleanly from the bowl — it should be soft but not sticky; cover with film and proof in a warm place 1.5–2 hours until doubled. THE WALNUT FILLING: place 400 g freshly ground walnuts in a large bowl; pour over 200 ml hot milk, 100 g melted butter, 150 g honey, and 100 g sugar; stir well to scald the walnuts and dissolve the sugars; cool 10 minutes, then mix in 2 egg yolks, 1 tbsp rum, 1 tsp cinnamon, 0.5 tsp cloves, 1 tbsp breadcrumbs, and a pinch of salt; in a separate bowl, whip 2 egg whites to stiff peaks, then fold them gently into the walnut mixture in 3 additions — the filling should be airy and spreadable. ROLL THE DOUGH: lightly flour a clean tea towel and turn the proofed dough out onto it; punch down gently, then roll out into a thin rectangle 60 × 40 cm and 4–5 mm thick — work from the centre outward, lifting and rotating to prevent sticking; the dough must be thin enough that the spiral is visible after baking, but thick enough to hold the filling. SPREAD THE FILLING: spread the walnut filling evenly over the rolled dough, leaving a 2 cm border along the long edges; pat it gently with a spatula — do not overload, the filling should be 5–6 mm thick; sprinkle a few extra ground walnuts if any spot oozes thin. ROLL UP: using the tea towel to help, roll up the dough tightly from the long side, forming a long log; roll snug but not so tight you compress the filling; pinch the seam closed and tuck in the ends; the log should be about 60 cm long. SHAPE IN MOLD + SECOND PROOF: grease a tubular potica mold (or a 24 cm Bundt pan or a kugelhopf form) thoroughly with butter and dust with flour; lay the log in the mold, seam side down, joining the ends to form a closed ring (pinch them together); cover loosely and proof again in a warm place 45–60 minutes until the dough has risen visibly to almost fill the mold; meanwhile, preheat the oven to 175 °C. BAKE: brush the top with the egg wash; bake on the middle rack of the 175 °C oven 45–55 minutes — cover loosely with foil after 30 min if the top is browning too fast; the potica is done when a skewer comes out clean and the internal temperature reaches 92–95 °C; let it rest 15 minutes in the mold, then carefully invert onto a wire rack to cool completely; dust generously with icing sugar before slicing; serve at room temperature with strong coffee or tea."}},{"id":154,"servings":4,"tipType":"def","pairingsType":"soup","origin":{"ar":"نيجيريا","en":"Nigeria","ro":"Nigeria"},"name":{"ar":"حساء إيجوسي","en":"Egusi soup","ro":"Egusi soup"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["250 غ من بذور إيجوسي النيئة، مطحونة ناعماً (أو 200 غ من إيجوسي المطحون مسبقاً)","600 غ من لحم الماعز أو لحم البقر بالعظم، مقطعة قطع 4 سم","200 غ من السمك المدخن (ماكريل أو سلور) — منظف ومنزوع العظم ومكسر قطع (اختياري، تقليدي)","100 غ من الجمبري المجفف أو سمك ستوكفيش، منقوع 30 دقيقة وممزق صغيراً (اختياري)","1 بصلة متوسطة (~150 غ)، مفرومة خشناً","2 فلفل سكوتش بونيت (أو 3 هابانيرو) — حسب تحمل الحرارة","2 فلفل أحمر حلو (~300 غ)، منزوع البذور","100 مل من زيت النخيل الأحمر","3 طماطم كبيرة طازجة (~400 غ) أو 200 غ معجون طماطم ممزوج بـ200 مل ماء","4 فصوص ثوم، مفرومة ناعماً","5 سم زنجبيل طازج، مقشّر ومبشور","2 مكعب مرق (ماجي أو مماثل، 10 غ)","1 ملعقة كبيرة من الجراد المطحون (ضروري للنكهة الأصيلة) — بديل: 1 ملعقة كبيرة جمبري مجفف مطحون","1 ورقة غار (أو 1 ملعقة صغيرة مطحونة)","200 غ من السبانخ الطازج أو أوراق أوغو، مغسولة ومفرومة خشناً","1,5 ملعقة صغيرة ملح + المزيد حسب الذوق","1 ملعقة كبيرة بذور خروب (إيرو/داوادوا) — اختياري، إضافة يوروبية تقليدية","للتقديم: يام مهروس، فوفو، إيبا (غاري)، أو أرز أبيض مطهي"],"en":["250 g raw egusi seeds, finely ground (or 200 g pre-ground egusi)","600 g goat meat or beef chuck on the bone, cut into 4 cm pieces","200 g smoked fish (mackerel or catfish) — cleaned, boned, broken into chunks (optional, traditional)","100 g dried prawns or stockfish (panla), soaked 30 min and torn small (optional)","1 medium onion (~150 g), roughly chopped","2 Scotch bonnet peppers (or 3 habaneros) — adjust to heat tolerance","2 red bell peppers (~300 g), seeded","100 ml red palm oil","3 large fresh tomatoes (~400 g) OR 200 g tomato paste blended with 200 ml water","4 garlic cloves, finely minced","5 cm fresh ginger, peeled and grated","2 stock cubes (Maggi or similar, 10 g)","1 tbsp ground crayfish (essential for authentic flavour) — substitute: 1 tbsp ground dried shrimp","1 bay leaf (or 1 tsp ground bay)","200 g fresh spinach or ugu pumpkin leaves, washed and roughly chopped","1.5 tsp salt + more to taste","1 tbsp locust beans (iru/dawadawa) — optional, traditional Yoruba addition","To serve: pounded yam, fufu, eba (gari), or boiled white rice"],"ro":["250 g semințe egusi brute, măcinate fin (sau 200 g egusi pre-măcinat)","600 g carne de capră sau gulaș de vită cu os, tăiată în bucăți de 4 cm","200 g pește afumat (macrou sau somn) — curățat, dezosat, rupt în bucăți (opțional, tradițional)","100 g creveți uscați sau stockfish, înmuiat 30 minute și rupt mic (opțional)","1 ceapă medie (~150 g), tocată grosier","2 ardei iuți Scotch bonnet (sau 3 habanero) — ajustează după toleranța la iuțeală","2 ardei roșii grași (~300 g), fără semințe","100 ml ulei roșu de palmier","3 roșii mari proaspete (~400 g) sau 200 g pastă de roșii amestecată cu 200 ml apă","4 căței de usturoi, tocați fin","5 cm rădăcină de ghimbir proaspăt, curățată și rasă","2 cuburi Maggi sau pentru condimentare (10 g)","1 lingură crayfish măcinat (esențial pentru aroma autentică) — substitut: 1 lingură creveți uscați măcinați","1 frunză de dafin (sau 1 linguriță dafin măcinat)","200 g spanac proaspăt sau frunze de ugu (pumpkin leaves), spălate și tocate","1,5 lingurițe sare + sare după gust","1 lingură semințe de locust (iru/dawadawa) — opțional, tradițional Yoruba","Pentru servire: igname pisată, fufu, eba (gari) sau orez fiert"]},"howIsMade":{"ar":"عجينة الإيجوسي: اضرب 250 غ من بذور الإيجوسي في مطحنة بهارات أو محضرة طعام 30 ثانية حتى تصبح مطحونة ناعمة لكن ليست بعد عجينة; في وعاء صغير، اخلطها مع 200 مل من الماء الدافئ إلى عجينة سميكة شبيهة بالحمص; اتركها 10 دقائق للتشبع تماماً — هذا سر القوام المميز: حبيبي من الخارج، كريمي من الداخل. اطبخ اللحم: في قدر ثقيل، اخلط 600 غ من اللحم المقطع مع 1 بصلة مفرومة، 4 فصوص ثوم، زنجبيل مبشور، 2 مكعب مرق، 1 ملعقة صغيرة ملح و1 لتر ماء; اتركه يغلي، ثم اطبخه مغطى 40–50 دقيقة (أطول للماعز) حتى يصبح اللحم طرياً دون أن يتفكك; صفِّ واحتفظ بـ800 مل من المرق; ضع اللحم جانباً. اخلط أساس الفلفل: في خلاط، اخلط 2 فلفل أحمر، 2 سكوتش بونيت و3 طماطم طازجة (أو معجون مع ماء); اخلط 1–2 دقيقة حتى يصبح ناعماً تماماً; اسكبه في مقلاة عريضة واطبخه على نار متوسطة 15 دقيقة — يجب أن يتقلص النصف ويتعمق اللون إلى أحمر آجري; هذا التركيز ضروري وإلا سيكون الحساء مائياً. اقلِ الأساس بزيت النخيل: في قدر الحساء على نار متوسطة، سخّن 100 مل من زيت النخيل 2 دقيقة حتى يلمع (لا تجعله يدخن — الإفراط في التسخين يدمر النكهة); أضف أساس الطماطم-الفلفل المركّز واقلِه مع التحريك 8–10 دقائق حتى يطفو الزيت على السطح ويغمق الخليط; هذا يسمى \"قلي الأساس\". أضف الإيجوسي: خذ عجينة الإيجوسي المرطبة بالملاعق وأنزلها على شكل كرات في الأساس الفائر — لا تحرك; اترك الكرات تطبخ دون لمس 5 دقائق، ثم أدخلها برفق; بعضها سيحتفظ بشكله (الكتل) بينما يتكسر بعضها ويثخن الصلصة — هذا هو القوام المرغوب. مرق + لحم + سمك: اسكب 800 مل من المرق المحفوظ; أضف اللحم المطبوخ، 200 غ من السمك المدخن (مكسر قطع)، 100 غ من الجمبري/ستوكفيش المنقوع (اختياري)، 1 ملعقة كبيرة من الجراد المطحون، 1 ملعقة كبيرة من بذور الخروب (اختياري) و1 ورقة غار; حرّك برفق، اتركها على نار هادئة واطبخها مكشوفة 15–20 دقيقة حتى يتقلص الحساء إلى قوام كالبودنغ — يجب أن يكوّن كومة على الملعقة، لا يتدفق كالمرق. أضف الخضار: أدخل 200 غ من السبانخ المفروم (أو أوغو/أوراق اليقطين) في الحساء الفائر; اطبخه 5–7 دقائق مكشوفاً حتى تذبل الخضار وتبقى خضراء زاهية; تذوّق وعدّل الملح والحرارة; يجب أن يكون الحساء عميق النكهة، قليلاً جوزياً (من الإيجوسي)، بنهاية نظيفة من زيت النخيل وحرارة متصاعدة. الراحة والتقديم: أطفئ النار واترك الحساء يستريح 5 دقائق — تتمازج النكهات بشكل دراماتيكي; قدّمه في صحون عميقة مع الـ\"بلعة\" المختارة (يام مهروس، فوفو، إيبا أو أمالا) إلى الجانب; كل باليد اليمنى: خذ قطعة صغيرة، اغمسها في الحساء وابلعها دون مضغ; الأرز الأبيض المسلوق خيار ألطف.","en":"EGUSI PASTE: pulse 250 g egusi seeds in a spice grinder or food processor 30 seconds until finely ground but not yet pasty; in a small bowl, mix with 200 ml warm water into a thick, hummus-like paste; let it sit 10 minutes to hydrate fully — this is the secret to the signature lumpy-creamy texture. COOK THE MEAT: in a heavy pot, combine 600 g cut meat with 1 chopped onion, 4 minced garlic, grated ginger, 2 stock cubes, 1 tsp salt and 1 L water; bring to boil, then simmer covered 40–50 minutes (longer if using goat) until the meat is tender enough to bite easily but not falling apart; strain and reserve 800 ml of the broth; set the meat aside. BLEND THE PEPPER BASE: in a blender, combine 2 red bell peppers, 2 Scotch bonnet peppers, and 3 fresh tomatoes (or paste-and-water mix); blend 1–2 minutes until completely smooth; pour into a wide pan and simmer over medium heat 15 minutes — the mix should reduce by half and the colour deepen to a rich brick-red; this concentration is essential or the soup will be watery. FRY THE PALM-OIL BASE: in your soup pot over medium heat, warm 100 ml palm oil 2 minutes until it just shimmers (do NOT smoke it — over-smoking destroys the flavour); add the reduced pepper-tomato base and fry, stirring, 8–10 minutes until the oil floats to the surface and the mixture darkens slightly; this is called \"frying the base\". ADD THE EGUSI: take the hydrated egusi paste by tablespoons and drop dumpling-style into the simmering pepper base — do NOT stir; let the dumplings cook undisturbed 5 minutes, then gently fold them in; some will hold their shape (the lumps) while others break apart and thicken the sauce — this is the desired texture. ADD STOCK + MEAT + FISH: pour in 800 ml reserved meat broth; add the cooked meat, 200 g smoked fish (broken into chunks), 100 g soaked dried prawns/stockfish (optional), 1 tbsp ground crayfish, 1 tbsp locust beans (optional), and 1 bay leaf; stir gently, bring to a simmer and cook uncovered 15–20 minutes until the soup has reduced and thickened to a pudding-like consistency — it should mound on a spoon, not pour like broth. ADD GREENS: stir in 200 g chopped spinach (or ugu/pumpkin leaves) into the simmering soup; cook 5–7 minutes uncovered until the greens are wilted but still bright green; taste and adjust salt and heat; the soup should taste deeply savoury, slightly nutty (from the egusi), with a clean palm-oil finish and a building chili heat. REST AND SERVE: turn off the heat and let the soup rest 5 minutes — the flavours meld dramatically in this short rest; serve in deep bowls with the swallow of choice (pounded yam, fufu, eba, or amala) on the side; eat with the right hand: take a small lump of swallow, dip into the soup, and swallow without chewing; boiled white rice is a milder option."}},{"id":155,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ar":"بولندا","en":"Poland","ro":"Polonia"},"name":{"ar":"كوتليت شابوفي","en":"Kotlet schabowy","ro":"Kotlet schabowy"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["4 شرائح خاصرة خنزير منزوعة العظم (~180–200 غ لكل واحدة، ~1,5–2 سم سماكة) — نحو 800 غ إجمالاً","1 ملعقة صغيرة ملح ناعم للحم الخنزير","0,5 ملعقة صغيرة فلفل أبيض مطحون طازج","200 مل حليب كامل الدسم للنقع المطرّي (الحيلة البولندية)","80 غ دقيق عادي للتغليف","3 بيضات كبيرة مخفوقة مع 1 ملعقة كبيرة حليب ورشة ملح","200 غ بقسماط ناعم طازج (محضّر منزلياً من خبز يوم سابق هو الأفضل) أو بانكو","80 غ شحم (تقليدي) أو 100 مل زيت دوار الشمس المحايد للقلي","30 غ زبدة غير مملحة للتقطير النهائي","1 ليمونة مقطعة إلى أرباع (تزيين عصري)","للبطاطس بالشبت: 800 غ بطاطس نشوية مقشّرة + 30 غ زبدة + 1 حزمة صغيرة من الشبت المفروم + ملح لماء السلق","لمخلل الملفوف المقلي: 400 غ مخلل ملفوف مصفّى + 1 بصلة صغيرة مفرومة ناعماً + 1 ملعقة كبيرة شحم + 100 مل ماء"],"en":["4 boneless pork loin chops (~180–200 g each, ~1.5–2 cm thick) — about 800 g total","1 tsp fine salt for the pork","0.5 tsp freshly ground white pepper","200 ml whole milk for the tenderizing soak (the Polish trick)","80 g all-purpose flour for breading","3 large eggs beaten with 1 tbsp milk and a pinch of salt","200 g fine fresh breadcrumbs (homemade from day-old bread is best) or panko","80 g lard (traditional) OR 100 ml neutral sunflower oil for frying","30 g unsalted butter for the finishing baste","1 lemon, cut into wedges (modern garnish)","For dill potatoes: 800 g floury potatoes peeled + 30 g butter + 1 small bunch chopped dill + salt for the cooking water","For sautéed sauerkraut: 400 g drained sauerkraut + 1 small onion finely chopped + 1 tbsp lard + 100 ml water"],"ro":["4 cotlete de porc din mușchi (~180–200 g fiecare, ~1,5–2 cm grosime) — aproximativ 800 g total","1 linguriță sare fină pentru carne","0,5 linguriță piper alb proaspăt măcinat","200 ml lapte integral pentru marinada de tendierare","80 g făină pentru panare","3 ouă mari bătute cu 1 lingură lapte și un vârf de sare","200 g pesmet fin proaspăt (de casă, din pâine de o zi) sau panko","80 g untură (tradițional) SAU 100 ml ulei neutru de floarea-soarelui pentru prăjit","30 g unt nesărat pentru finisare","1 lămâie tăiată în sferturi (garnitură modernă)","Pentru cartofi cu mărar: 800 g cartofi făinoși decojiți + 30 g unt + 1 bunch mic de mărar tocat + sare pentru apa de fierbere","Pentru varza murată: 400 g varză murată scursă + 1 ceapă mică tocată + 1 lingură untură + 100 ml apă"]},"howIsMade":{"ar":"اطرق لحم الخنزير: ضع كل شريحة بين ورقتي بلاستيك واطرقها بمطرقة لحم مسطحة من المنتصف للخارج، 30 ثانية لكل جانب، حتى تصبح الشرائح بسماكة 6–7 مم وتقريباً ضعف الحجم — يجب أن تكون بسماكة موحدة لطهي متجانس; اقطع حافة الدهن 3–4 جروح لمنع التواء. النقع بالحليب: جفّ الشرائح المطروقة وافرك كل جانب بالملح والفلفل الأبيض; ضعها في طبق ضحل، اسكب 200 مل من الحليب حتى تكون الشرائح مغمورة تقريباً، غطّ وضع في الثلاجة 30 دقيقة (حتى ساعتين) — حمض اللاكتيك سيُطرّي اللحم دون تغيير النكهة. حضّر محطة التغليف: ثلاثة أطباق مسطحة في صف: طبق 1 مع 80 غ من الدقيق؛ طبق 2 مع 3 بيضات مخفوقة + 1 ملعقة كبيرة حليب + رشة ملح؛ طبق 3 مع 200 غ من البقسماط الناعم; الترتيب مهم: كل شريحة يجب أن تمر دقيق → بيض → بقسماط دون تخطي خطوات. غلف الشرائح: ارفع شريحة من الحليب، اترك الفائض ينزل وغمّسها بالدقيق، ارجّ الفائض — يجب أن يغطي الدقيق رقيقاً ومنتظماً وإلا لن يلتصق البيض; ثم اغمسها في البيض، اتركها تنزل 2 ثانية، ثم اضغطها بقوة في البقسماط من الجانبين، بربتها لتلتصق; ضعها في طبق; كرر للأربعة جميعها; اتركها تستريح 5 دقائق — تترطب الطبقة وتترابط. اسلق البطاطس: في هذه الأثناء، قشّر 800 غ من البطاطس وقطّعها قطعاً 4 سم; ضعها في ماء بارد مملح، اتركها تغلي، واسلق 15–18 دقيقة حتى تصبح طرية مع الشوكة; صفِّ، أعدها للقدر بدون نار 2 دقيقة لتجف، ثم اخلطها مع 30 غ من الزبدة والشبت المفروم. اقلِ المخلل: في مقلاة منفصلة، اذب 1 ملعقة كبيرة من الشحم على نار متوسطة; أضف 1 بصلة مفرومة ناعماً، اقلِ 5 دقائق حتى تذهب; أضف 400 غ من مخلل الملفوف المصفّى و100 مل من الماء؛ اطبخ مغطى 15 دقيقة، ثم اكشف واطبخ 5 دقائق إضافية حتى يتبخر معظم السائل; تبّل بلفة فلفل. اقلِ الشنيتسلز: سخّن 80 غ من الشحم (أو 100 مل من الزيت) في مقلاة كبيرة ثقيلة على نار متوسطة-عالية حتى يلمع (175 °م، أو فتاتة بقسماط تطقطق فوراً عند الاتصال); اقلِ الشرائح اثنتين في المرة حتى لا تكون المقلاة مزدحمة، 3–4 دقائق لكل جانب دون لمس حتى تكون ذهبية عميقة ومقرمشة؛ يجب أن تصل درجة الحرارة الداخلية 70 °م; في آخر 30 ثانية، أضف 15 غ من الزبدة للمقلاة ومل للسقاية على الشنيتسلز — الزبدة تنفخ بنياً وتعطي الطبقة عبق الأحد البولندي الأيقوني; انقلها إلى رف مفروش بمناديل ورقية للتصفية (ليس إلى صحن، الذي سيخفف القاع). قدّمها فوراً: ضع كل شنيتسل إلى جانب كومة من البطاطس بالشبت وكومة من مخلل الملفوف; زيّن بربع ليمونة إن أحببت (العصرة تنير الدهن); كل بسكين وشوكة — أبداً بشوكة فقط، هذا طبق يحترم الكلاسيكيات; يجب أكل الشنيتسل في غضون 5 دقائق من القلي للحصول على أقصى قرمشة.","en":"POUND THE PORK: place each pork chop between two sheets of cling film and pound with a flat meat mallet from the centre outward, 30 seconds per side, until the chops are 6–7 mm thick and almost doubled in size — they must be even thickness for uniform cooking; score the fatty rim 3–4 times to prevent curling. MILK SOAK: pat the pounded chops dry and rub each side with salt and white pepper; place in a shallow dish, pour over 200 ml milk so the chops are mostly submerged, cover and refrigerate 30 minutes (up to 2 hours) — the lactic acid tenderizes the meat without altering the flavour. SET UP THE BREADING STATION: three shallow plates in a row: plate 1 with 80 g flour; plate 2 with 3 beaten eggs + 1 tbsp milk + a pinch of salt; plate 3 with 200 g fine breadcrumbs; the line-up matters: every chop must travel flour → egg → breadcrumbs without skipping. BREAD THE CHOPS: lift one chop from the milk, let the excess drip off, and dredge in flour, shaking off the excess — the flour must coat thinly and evenly or the egg won't stick; then dip into the egg, letting it drip 2 seconds, then press firmly into the breadcrumbs on both sides, patting them on so they adhere; set on a plate; repeat for all 4 chops; let them rest 5 minutes — the breading hydrates and binds. BOIL THE POTATOES: meanwhile, peel 800 g potatoes and cut into 4 cm chunks; place in cold salted water, bring to boil, and simmer 15–18 minutes until fork-tender; drain, return to the pot off heat for 2 minutes to dry, then toss with 30 g butter and chopped dill. SAUTÉ THE SAUERKRAUT: in a separate pan, melt 1 tbsp lard over medium heat; add 1 finely chopped onion, fry 5 minutes until golden; add 400 g drained sauerkraut and 100 ml water; simmer covered 15 minutes, then uncover and cook 5 minutes more until most of the liquid has evaporated and the kraut is tender; season with a twist of pepper. FRY THE SCHNITZELS: heat 80 g lard (or 100 ml oil) in a large heavy skillet over medium-high heat until shimmering (175 °C, or a breadcrumb sizzles immediately on contact); fry the chops 2 at a time so the pan isn't crowded, 3–4 minutes per side undisturbed until deeply golden brown and crisp; the internal temperature should reach 70 °C; in the last 30 seconds, add 15 g butter to the pan and tilt to baste the schnitzels — the butter foams brown and gives the breading its iconic Polish-Sunday aroma; transfer to a rack lined with paper towels to drain (NOT a plate, which would steam the bottom soggy). SERVE IMMEDIATELY: plate each schnitzel alongside a mound of dill potatoes and a heap of sauerkraut; garnish with a lemon wedge if you like (the squeeze brightens the fat); eat with a knife and fork — never just a fork, this is a respect-the-classics dish; the schnitzel should be eaten within 5 minutes of frying for maximum crunch."}},{"id":156,"origin":{"ar":"كوريا الجنوبية","en":"South Korea","ro":"Coreea de Sud"},"name":{"ar":"كيمباب","en":"Kimbap","ro":"Kimbap"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"korean","ingredients":{"ar":["360 غ (2 كوب) أرز قصير الحبة، غير مطبوخ — لـ~4 رولات","540 مل (2¼ كوب) ماء بارد لطهي الأرز","4 أوراق نوري محمص (غيم، 20 × 18 سم)","4 شرائح دانموجي (فجل أصفر مخلل)، بطول النوري وسماكة ~1 سم","100 غ سبانخ صغير (أو حزمة صغيرة من السبانخ العادي)","جزرتان متوسطتان (~150 غ)، مقطعتان جوليان 0,5 × 0,5 × 8 سم","3 بيضات كبيرة","200 غ عصي سرطان بحر اصطناعية (أو لحم خنزير مطبوخ، أو تونة معلبة ممزوجة بالمايونيز)","100 غ خيار (1 كوري صغير أو 1/3 إنكليزي)، منزوع البذور ومقطع شرائح طويلة","3 ملاعق كبيرة زيت سمسم محمص (1,5 ملعقة كبيرة للأرز، 0,5 ملعقة صغيرة للسبانخ، الباقي للدهان الخارجي)","1,5 ملعقة صغيرة ملح ناعم (1 ملعقة صغيرة للأرز، رشات للخضار والبيض)","2 ملعقة صغيرة سمسم محمص","1 ملعقة كبيرة زيت محايد لطهي البيض والجزر","0,5 ملعقة صغيرة فلفل أبيض مطحون","حصيرة بامبو (غيمبال) + غلاف بلاستيكي"],"en":["360 g (2 cups) short-grain white rice, uncooked — makes ~4 rolls","540 ml (2¼ cups) cold water for cooking the rice","4 sheets toasted nori (gim, 20 × 18 cm)","4 strips danmuji (yellow pickled radish), cut to nori length, ~1 cm thick","100 g baby spinach (or 1 small bunch regular spinach)","2 medium carrots (~150 g), julienned 0.5 × 0.5 × 8 cm matchsticks","3 large eggs","200 g imitation crab sticks (or cooked ham, or tuna mixed with mayo)","100 g cucumber (1 small Korean cucumber or 1/3 English cucumber), seeded and cut into long batons","3 tbsp toasted sesame oil (1.5 tbsp for the rice, 0.5 tsp for spinach, the rest for the outer rub)","1.5 tsp fine salt (1 tsp for the rice, pinches for veg and eggs)","2 tsp toasted sesame seeds","1 tbsp neutral oil for cooking the eggs and carrots","0.5 tsp ground white pepper","Bamboo rolling mat (gimbal) + plastic wrap"],"ro":["360 g (2 căni) orez cu bob scurt necopt, pentru ~4 rulouri","540 ml (2¼ căni) apă rece pentru fierberea orezului","4 foi de nori prăjit (gim, 20 × 18 cm)","4 fâșii de danmuji (ridiche galbenă murată), tăiate la lungimea norii, grosime ~1 cm","100 g spanac baby (sau 1 mănunchi mic de spanac obișnuit)","2 morcovi medii (~150 g), tăiați julien 0,5 × 0,5 × 8 cm","3 ouă mari, bătute","200 g bețe de crab imitație (sau șuncă fiartă sau ton conservat amestecat cu maioneză)","100 g castraveți (1 mic castravete coreean sau 1/3 castravete englezesc), fără sâmburi, tăiat fâșii lungi","3 linguri ulei de susan prăjit (1,5 lingură pentru orez, 0,5 linguriță pentru spanac, restul pentru exterior)","1,5 linguriță sare fină (1 linguriță pentru orez, restul pentru legume)","2 lingurițe semințe de susan prăjite","1 lingură ulei neutru pentru gătit ouăle și sotat morcovii","0,5 linguriță piper alb măcinat","Covoraș de bambus (kimbal) + folie alimentară"]},"howIsMade":{"ar":"الأرز: اغسل 360 غ من الأرز بماء بارد 3–4 مرات حتى يخرج الماء صافياً, صفِّه جيداً، ثم ضعه في قدر ثقيل مع 540 مل من الماء البارد, اتركه يغلي مكشوفاً على نار متوسطة-عالية (3–4 دقائق)، ثم غطِّه، خفف الحرارة لأدنى مستوى واطبخ 12 دقيقة — لا ترفع الغطاء, ارفعه عن النار واتركه يستريح مغطى 10 دقائق, يجب أن يكون الأرز طرياً، لزجاً قليلاً، وحبيباته منفصلة. تتبيل الأرز: وهو ساخن، انقله إلى وعاء واسع, اسكب 1,5 ملعقة كبيرة زيت سمسم، 1 ملعقة صغيرة ملح و2 ملعقة صغيرة سمسم محمص, اطوِه برفق بمجرفة الأرز بحركات قطع — لا تحركه بشدة، ستنكسر الحبيبات, غطِّه بقماش رطب واتركه يبرد حتى يصبح فاتراً (10–15 دقيقة). السبانخ: اغلِ قدراً صغيراً من الماء المملح, اسلق 100 غ من السبانخ 30 ثانية حتى يذبل قليلاً, صفِّه وارشّ ماء بارداً فوراً لإيقاف الطهي والحفاظ على الأخضر الزاهي, اعصره بقبضتك بأقصى ما تستطيع لإزالة كل الماء — السبانخ المبلل يفسد الرول, تبّله بـ0,5 ملعقة صغيرة زيت سمسم ورشة ملح. الجزر: سخّن 1 ملعقة صغيرة من الزيت المحايد في مقلاة صغيرة على نار متوسطة, أضف 150 غ من الجزر المقطع شرائح ورشة ملح، اقلِه 2 دقيقة حتى يلين قليلاً لكن يبقى مقرمشاً, اقلبه على صحن ليبرد — الجزر اللين الدهني سيكسر الرول. البيض: اخفق 3 بيضات مع رشة ملح و0,5 ملعقة صغيرة فلفل أبيض, سخّن 1 ملعقة صغيرة من الزيت المحايد في مقلاة غير لاصقة على نار متوسطة-منخفضة، اسكب البيض وأمل المقلاة لتشكيل طبقة رقيقة منتظمة 25 × 20 سم, اطبخ 2 دقيقة حتى يثبت من الأعلى، دون قلب, اسحبه على لوح، اتركه يبرد 2 دقيقة، ثم قطّعه إلى 4 شرائح طويلة بعرض النوري. تجهيز الحشوات: قطّع 100 غ من الخيار طولياً إلى 8 أصابع طويلة، أزل اللب المبذور بملعقة صغيرة, شطر 200 غ من عصي السرطان نصفين طولياً, قطّع 4 شرائح من الدانموجي بطول النوري, رتّب كل شيء على صينية بترتيب الوضع: سبانخ → جزر → خيار → سرطان → بيض → دانموجي. لف كل كيمباب: ضع حصيرة البامبو والقضبان أفقياً؛ ضع ورقة نوري بالجانب اللامع للأسفل, بأصابع مبللة، وزّع ~150 غ أرز في طبقة رقيقة منتظمة على 3/4 من النوري، اترك 4 سم فارغة عند الحافة البعيدة, على بُعد 3 سم من الحافة القريبة، رتّب في حزمة مضغوطة: سبانخ، جزر، خيار، سرطان، بيض ودانموجي, ارفع الحافة القريبة من الحصيرة ولفّ بإحكام للأمام، خبئ الحشوات تحت الأرز في اللفة الأولى، ثم استمر بلف محكم إلى الحافة البعيدة, اضغط على الخياطة للإغلاق. التقطيع والتقديم: ادهن الخارج لكل رول بـ0,5 ملعقة صغيرة من زيت السمسم ليلمع النوري ويمنع التصاقه بالسكين, امسح سكيناً حاداً بقماش رطب بين كل قطعة, قطّع كل رول إلى 8 قطع متساوية بدفعة واحدة حاسمة (دون نشر) — 32 قطعة إجمالاً, رتّبها على صحن وانثر السمسم, كلها في غضون 4 ساعات من اللف؛ لا تبرّد الكيمباب أبداً (الأرز يقسو والنوري يلين عند إعادة التسخين).","en":"Rinse 360 g rice in cold water 3–4 times until the water runs clear, drain well, then put in a heavy pot with 540 ml fresh cold water, bring to a boil uncovered over medium-high heat (3–4 min), cover, reduce to the lowest possible heat and cook 12 minutes without lifting the lid, then remove from heat and rest covered 10 minutes until the rice is tender, slightly sticky, with separate grains. While the rice is still hot, transfer it to a wide bowl, drizzle 1.5 tbsp sesame oil, 1 tsp salt and 2 tsp toasted sesame seeds over the top and fold gently with a rice paddle in cutting motions — never stir aggressively or the grains break and turn mushy — then cover with a damp cloth and let cool to lukewarm (10–15 min). Bring a small pot of salted water to a boil and blanch 100 g spinach for 30 seconds until just wilted, then drain and rinse under cold water immediately to stop the cooking and preserve the bright green colour, squeeze in your fist as hard as possible to remove all water (wet spinach ruins the roll) and season with 0.5 tsp sesame oil and a pinch of salt. Heat 1 tsp neutral oil in a small pan over medium heat, add 150 g julienned carrot and a pinch of salt and stir-fry 2 minutes until just softened but still crisp, then tip onto a plate to cool — limp, oily carrots will break the roll. Beat 3 eggs with a pinch of salt and 0.5 tsp white pepper, heat 1 tsp neutral oil in a non-stick pan over medium-low heat, pour in the eggs and tilt the pan to form a thin even sheet 25 × 20 cm, cook 2 minutes until set on top without flipping, then slide onto a board, let cool 2 minutes and cut into 4 long strips the width of the nori. Cut 100 g cucumber lengthwise into 8 long batons and scrape the seedy core out with a teaspoon, split 200 g crab sticks in half lengthwise and cut 4 strips of danmuji to nori length, then arrange everything on a tray in the order you'll lay them: spinach, carrot, cucumber, crab, egg, danmuji. Place the bamboo mat with the slats running horizontally and lay a sheet of nori shiny-side down, then with wet fingers spread ~150 g rice in a thin even layer over the bottom 3/4 of the nori while leaving a clean 4 cm strip at the far edge, and about 3 cm in from the near edge line up one strip each of spinach, carrot, cucumber, crab, egg and danmuji in a tight bundle, then lift the near edge of the mat and roll firmly forward, tucking the fillings under the rice with the first roll and continuing to roll tightly to the far edge, then press along the seam to seal. Brush the outside of each roll lightly with 0.5 tsp sesame oil to make the nori glossy and prevent it from sticking to the knife, wipe a sharp knife with a damp cloth between cuts, then slice each roll into 8 even rounds with one decisive push (no sawing) for 32 pieces total, arrange on a plate and sprinkle with sesame seeds — eat within 4 hours of rolling and never refrigerate kimbap."},"timeMins":{"total":60,"active":50}},{"id":157,"servings":6,"tipType":"meat","pairingsType":"latin","origin":{"ar":"تشيلي","en":"Chile","ro":"Chile"},"name":{"ar":"باستيل دي تشوكو","en":"Pastel de Choclo","ro":"Pastel de Choclo"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["للحشوة (بينو): 600 غ من اللحم البقري المفروم (كتف أو لومو، 20% دهن)","2 بصلة كبيرة (~400 غ)، مفرومتان ناعماً","4 فصوص ثوم، مفرومة ناعماً","2 ملعقة كبيرة من الزيت المحايد للتسخين","1,5 ملعقة صغيرة ملح + 1 ملعقة صغيرة فلفل أسود مطحون طازج للبينو","1 ملعقة صغيرة كمون مطحون + 1 ملعقة صغيرة بابريكا حلوة + 1 ملعقة صغيرة أوريغانو مجفف + 1 ملعقة صغيرة آخي كولور (أو بيمنتون مدخن كبديل)","60 مل مرق بقر أو ماء","80 غ زبيب أسود، منقوع 15 دقيقة في 100 مل ماء دافئ ومصفّى","4 أفخاذ دجاج بالعظم والجلد (~600 غ) — مسلوقة ومفككة (إضافة تقليدية)","1 ورقة غار + 800 مل ماء لسلق الدجاج","6 بيضات مسلوقة ومقشّرة ومقطعة نصفين (1 لكل حصة)","18–24 زيتونة سوداء منزوعة النوى (نمط كالاماتا)","لعجينة الذرة (تشوكلو): 1,2 كغ من حبوب الذرة البيضاء الطازجة (~6–8 أكواز) أو 1 كغ من الذرة المجمدة المذابة","80 مل حليب كامل الدسم","60 غ زبدة غير مملحة","1 ملعقة كبيرة من أوراق الريحان الطازج، مفرومة ناعماً (التوقيع التشيلي)","1 ملعقة صغيرة ملح ناعم + 1 ملعقة كبيرة سكر محبب لعجينة الذرة","2 ملعقة كبيرة سكر محبب للنثر على الوجه قبل الخبز (للقشرة المكرملة الأيقونية)"],"en":["For the pino (meat filling): 600 g ground beef (chuck or sirloin, 20% fat)","2 large onions (~400 g), finely diced","4 garlic cloves, finely minced","2 tbsp neutral oil for sautéing","1.5 tsp salt + 1 tsp freshly ground black pepper for the pino","1 tsp ground cumin + 1 tsp sweet paprika + 1 tsp dried oregano + 1 tsp aji color (or pimentón as substitute)","60 ml beef stock or water","80 g dark raisins, soaked 15 min in 100 ml warm water, then drained","4 bone-in skin-on chicken thighs (~600 g) — poached and pulled (traditional addition)","1 bay leaf + 800 ml water to poach the chicken","6 hard-boiled eggs, peeled and halved (1 per portion)","18–24 pitted black olives (kalamata-style)","For the corn paste (choclo): 1.2 kg fresh white corn kernels (~6–8 ears) OR 1 kg thawed frozen corn","80 ml whole milk","60 g unsalted butter","1 tbsp fresh basil leaves, finely chopped (the Chilean signature)","1 tsp fine salt + 1 tbsp granulated sugar for the corn paste","2 tbsp granulated sugar to sprinkle over the top before baking (for the iconic caramelized crust)"],"ro":["Pentru pino: 600 g vită tocată (gulaș sau pulpă, 20% grăsime)","2 cepe mari (~400 g), tăiate fin","4 căței de usturoi, tocați fin","2 linguri ulei neutru pentru sotat","1,5 lingurițe sare + 1 linguriță piper negru proaspăt măcinat (pentru pino)","1 linguriță chimion măcinat + 1 linguriță boia dulce + 1 linguriță oregano uscat + 1 linguriță aji color (sau pimentón pentru substitut)","60 ml supă de vită sau apă","80 g stafide negre, înmuiate 15 minute în 100 ml apă caldă, apoi scurse","4 pulpe de pui cu os și piele (~600 g) — fierte și destrămate (tradițional)","1 frunză de dafin + 800 ml apă pentru fiertul puiului","6 ouă tari, decojite și tăiate în jumătăți (1 per porție)","18–24 măsline negre cu sâmbure scos (stil kalamata)","Pentru pasta de porumb: 1,2 kg boabe proaspete de porumb alb (~6–8 știuleți) SAU 1 kg porumb congelat dezghețat","80 ml lapte integral","60 g unt nesărat","1 lingură busuioc proaspăt, tocat fin (semnătura chiliană)","1 linguriță sare fină + 1 lingură zahăr granulat pentru pasta de porumb","2 linguri zahăr granulat pentru presărat pe suprafață înainte de coacere (crusta caramelizată iconică)"]},"howIsMade":{"ar":"تكرميل البصل: في مقلاة ثقيلة على نار متوسطة، سخّن 2 ملعقة كبيرة من الزيت وأضف 400 غ من البصل المفروم ناعماً مع 0,5 ملعقة صغيرة من الملح; اقلِه 12–15 دقيقة مع التحريك المتكرر حتى يصبح ذهبياً عميقاً وشفافاً — لا تتسرع في هذه الخطوة، البصل المكرمل هو أساس نكهة البينو; أضف 4 فصوص ثوم مفرومة واطبخها دقيقة أخرى حتى تفوح. تحمير اللحم: ارفع الحرارة إلى متوسطة-عالية; أضف 600 غ من اللحم المفروم إلى البصل، فتته بملعقة خشبية; اطبخه 6–8 دقائق حتى لا يعود اللحم وردياً ويتبخر السائل; أضف 1 ملعقة صغيرة كمون، 1 ملعقة صغيرة بابريكا، 1 ملعقة صغيرة أوريغانو، 1 ملعقة صغيرة آخي كولور (إذا استخدمت)، الـ1 ملعقة صغيرة المتبقية من الملح و1 ملعقة صغيرة فلفل; حرّك دقيقة لتفعيل البهارات. أنهِ البينو: اسكب 60 مل من المرق والزبيب المصفّى; اطبخه 3–4 دقائق حتى يصبح المزيج رطباً لكن غير سائل — يجب أن يكون البينو لامعاً ويحتفظ بشكله على الملعقة; ارفعه عن النار واتركه يبرد 15 دقيقة — الراحة تعمّق النكهة وتمنع انزلاق طبقة الذرة. اسلق الدجاج: بينما يستريح البينو، اسلق 4 أفخاذ دجاج في 800 مل ماء مملح قليلاً مع 1 ورقة غار لمدة 25 دقيقة حتى ينضج; صفِّه، بردّه قليلاً وافصل اللحم عن العظام بقطع كبيرة (تخلص من الجلد); احتفظ بالمرق للتقديم مع الباستيل. عجينة الذرة: في محضرة طعام أو خلاط، اضغط 1,2 كغ من حبوب الذرة مع 80 مل من الحليب و1 ملعقة صغيرة ملح 30 ثانية حتى تصبح هريسة خشنة — احتفظ بالقوام، لا تخلطه إلى كريم ناعم; انقله إلى قدر ثقيل مع 60 غ من الزبدة على نار متوسطة; اطبخه 10–15 دقيقة مع التحريك المستمر بملعقة خشبية حتى يثخن الهريس إلى قوام شبيه بالبولينتا الذي ينفصل عن جوانب القدر; أضف 1 ملعقة كبيرة من الريحان المفروم وارفعه عن النار. التركيب: سخّن الفرن إلى 200 °م مع رف في الثلث العلوي; وزّع البينو على 6 أوعية فخار فردية (paila) أو طبق خبز 28 سم; ضع فوق كل حصة قطع دجاج مسلوق، 1 نصف بيضة مسلوقة، 3–4 زيتونات وكومة صغيرة من الزبيب بشكل ديكوري; اسكب عجينة الذرة الدافئة في الأعلى بطبقة منتظمة بسماكة 2 سم، ناعمها بظهر الملعقة لختمها حتى الحواف. قشرة السكر: انثر 2 ملعقة كبيرة من السكر المحبب بشكل متساوٍ على عجينة الذرة; هذه الخطوة غير قابلة للتفاوض — يتكرمل السكر أثناء الخبز إلى القشرة الذهبية الداكنة شبه المحروقة الأيقونية التي تميز باستيل دي تشوكلو عن أي فطيرة راعٍ أخرى. الخبز: ضع الباستيلات على الرف العلوي من الفرن على 200 °م واخبزها 25–30 دقيقة حتى تصبح عجينة الذرة ذهبية بنية ويتكرمل السكر إلى بقع داكنة على السطح; قد تنفخ الزوايا — هذا صحيح; اتركه يستريح 10 دقائق قبل التقديم (تحتاج الحشوة إلى التماسك); قدّمه مباشرة من الـ paila مع صلصة بيبري وكأس من كارمنير تشيلي.","en":"CARAMELIZE THE ONIONS: in a heavy skillet over medium heat, warm 2 tbsp oil and add 400 g finely diced onion with 0.5 tsp salt; sauté 12–15 minutes, stirring often, until deeply golden and translucent — DO NOT rush this step, the caramelized onion is the foundation of pino flavour; add 4 minced garlic cloves and cook 1 minute more until fragrant. BROWN THE BEEF: raise the heat to medium-high; add 600 g ground beef to the onions, breaking it apart with a wooden spoon; cook 6–8 minutes until the meat is no longer pink and any liquid has evaporated; add 1 tsp cumin, 1 tsp paprika, 1 tsp oregano, 1 tsp aji color (if using), the remaining 1 tsp salt and 1 tsp pepper; stir 1 minute to bloom the spices. FINISH THE PINO: pour in 60 ml beef stock and the drained raisins; simmer 3–4 minutes until the mixture is moist but not soupy — the pino should be glossy and able to hold its shape on a spoon; remove from heat and let cool 15 minutes — letting it rest deepens the flavour and prevents the corn topping from sliding off. POACH THE CHICKEN: while the pino rests, simmer 4 chicken thighs in 800 ml lightly salted water with 1 bay leaf for 25 minutes until cooked through; drain, cool slightly, then pull the meat from the bones in large chunks (skin discarded); reserve the stock for serving alongside the pastel. CORN PASTE: in a food processor or blender, pulse 1.2 kg fresh corn kernels with 80 ml milk and 1 tsp salt 30 seconds until coarsely pureed — keep some texture, do not blend to a smooth cream; transfer to a heavy saucepan with 60 g butter over medium heat; cook 10–15 minutes, stirring constantly with a wooden spoon, until the puree thickens to a polenta-like consistency that pulls away from the sides of the pan; stir in 1 tbsp chopped basil and remove from heat. ASSEMBLE: preheat oven to 200 °C with a rack in the upper third; divide the pino between 6 individual earthenware pailas (or one 28 cm baking dish); top each portion with chunks of poached chicken, 1 hard-boiled egg half, 3–4 olives, and a small pile of raisins arranged decoratively; spoon the warm corn paste over the top in an even 2 cm layer, smoothing with the back of a spoon to seal all the way to the edges. SUGAR CRUST: sprinkle 2 tbsp granulated sugar evenly over the corn topping; this is non-negotiable — the sugar caramelizes during baking into the iconic dark, almost-burnt golden crust that distinguishes pastel de choclo from any other shepherd's pie. BAKE: place the pastels on the upper rack of the 200 °C oven and bake 25–30 minutes until the corn topping is golden brown and the sugar has caramelized into dark spots across the surface; the corners may bubble — that's correct; let rest 10 minutes before serving (the filling needs to set); serve straight from the paila with a side of pebre salsa and a glass of Chilean Carmenère."}},{"id":158,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ar":"صربيا","en":"Serbia","ro":"Serbia"},"name":{"ar":"بلييسكافيكا","en":"Pljeskavica","ro":"Pljeskavica"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["500 غ من رقبة البقر المفرومة خشناً (~20% دهن)","300 غ من كتف الضأن المفروم خشناً (أو كتف الخنزير لنسخة أخف)","1 بصلة كبيرة (~200 غ)، مبشورة ناعماً ومعصورة (سر العصارة)","4 فصوص ثوم، مهروسة مع 0,5 ملعقة صغيرة ملح إلى عجينة","1 ملعقة كبيرة من البابريكا المجرية الحلوة","1 ملعقة صغيرة من البابريكا الحارة (مدخنة أو كشميرية، اختياري)","1,5 ملعقة صغيرة ملح ناعم","1 ملعقة صغيرة فلفل أسود مطحون طازج","1 ملعقة صغيرة بيكربونات الصودا (الحيلة البلقانية — تحافظ على عصارة وطراوة البرغر)","100 مل ماء معدني فوار مثلج (للقوام الهوائي المرن)","0,5 ملعقة صغيرة بردقوش مجفف أو أوريغانو","1 ملعقة كبيرة زيت نباتي للشواية أو المقلاة","للتقديم: 4 خبزات سومون أو خبز بيتا (~18 سم)، 1 بصلة حمراء متوسطة (~150 غ) مقطعة شرائح رفيعة، 200 غ من الأجفار، 100 غ كايماك أو كريمة حامضة، بقدونس طازج، شرائح ليمون (اختياري)"],"en":["500 g coarsely ground beef chuck (~20% fat)","300 g coarsely ground lamb shoulder (or pork shoulder for a milder version)","1 large onion (~200 g), finely grated and water squeezed out (the secret to juicy patties)","4 garlic cloves, crushed with 0.5 tsp salt into a paste","1 tbsp sweet Hungarian paprika","1 tsp hot paprika (smoked or Kashmiri, optional)","1.5 tsp fine salt","1 tsp freshly ground black pepper","1 tsp baking soda (the Balkan trick — helps keep them juicy and tender)","100 ml ice-cold sparkling water (for the fluffy springy texture)","0.5 tsp dried marjoram or oregano","1 tbsp vegetable oil for the grill or pan","To serve: 4 somun or pita breads (~18 cm rounds), 1 medium red onion (~150 g) thinly sliced, 200 g ajvar red-pepper relish, 100 g kajmak or sour cream, fresh parsley, lemon wedges (optional)"],"ro":["500 g vită tocată grosier (ceafă, ~20% grăsime)","300 g umăr de miel tocat grosier (sau umăr de porc pentru o versiune mai blândă)","1 ceapă mare (~200 g), rasă fin și stoarsă bine (secretul cărnurilor suculente)","4 căței de usturoi, zdrobiți cu 0,5 linguriță sare într-o pastă","1 lingură boia ungurească dulce","1 linguriță boia iute (afumată sau Kashmir, opțional)","1,5 lingurițe sare fină","1 linguriță piper negru proaspăt măcinat","1 linguriță bicarbonat de sodiu (trucul balcanic — păstrează carnea suculentă și frageda)","100 ml apă minerală carbogazoasă rece ca gheața (pentru textura pufoasă)","0,5 linguriță maghiran uscat sau oregano","1 lingură ulei vegetal pentru grătar sau tigaie","Pentru servire: 4 chifle somun sau pita (~18 cm), 1 ceapă roșie medie (~150 g) tăiată subțire, 200 g ajvar, 100 g kajmak sau smântână, pătrunjel proaspăt, lămâie (opțional)"]},"howIsMade":{"ar":"تحضير البصل: ابشر 200 غ من البصل على الجانب الناعم من المبشرة; انقله إلى منديل نظيف واعصره بقوة فوق المغسلة لإزالة أكبر قدر ممكن من السائل — يجب أن يخرج 80 مل من العصير على الأقل; البصل المبلل يجعل البرغر يتفكك على الشواية; احتفظ بـ2 ملعقة كبيرة من اللب المعصور للحم. اخلط اللحم: في وعاء كبير، اجمع 500 غ بقر + 300 غ ضأن (أو خنزير); أضف 2 ملعقة كبيرة من لب البصل المعصور، 4 فصوص ثوم مهروسة مع 0,5 ملعقة صغيرة ملح، 1 ملعقة كبيرة بابريكا حلوة، 1 ملعقة صغيرة بابريكا حارة (إن استخدمت)، 1 ملعقة صغيرة ملح، 1 ملعقة صغيرة فلفل، 0,5 ملعقة صغيرة بردقوش و1 ملعقة صغيرة بيكربونات; اعجن بقوة باليد 4–5 دقائق — يجب أن يصبح المزيج لزجاً ومشدوداً بشكل ملحوظ، مما يعطي البلييسكافيكا قفزتها المميزة. أضف الماء الفوار: اسكب ببطء 100 مل من الماء الفوار المثلج بينما تواصل العجن، في 4 إضافات بمعدل 25 مل لكل منها; الماء يهوي اللحم ويتحد مع البيكربونات للحفاظ على عصارة وطراوة البرغر; غطّ بغشاء وبرّد على الأقل 4 ساعات، ومثالياً طوال الليل — الراحة غير قابلة للتفاوض لتطور النكهة والتماسك. تشكيل البرغر: قسّم اللحم المستريح إلى 4 حصص متساوية بـ~225 غ لكل منها; بأيدٍ مبللة (لمنع الالتصاق)، لف كل حصة إلى كرة، ثم سطّحها إلى قرص مسطح بقطر 18–20 سم وسماكة 8 مم; يجب أن يكون القرص بنفس قطر الخبز الذي سيقدم فيه; اضغط الوسط قليلاً بإبهامك لإنشاء غمازة — هذا يمنع البرغر من الانتفاخ على الشواية. التبريد الثاني: ضع البرغر المشكل على صينية مبطنة بورق الزبدة; غطّ بشكل فضفاض وبرّد 20 دقيقة ليتماسك; في هذه الأثناء، أشعل شواية فحم على نار متوسطة-عالية (200 °م) أو سخّن مقلاة شواية ثقيلة مع 1 ملعقة كبيرة زيت حتى تبدأ بإطلاق الدخان. الشواء: ادهن البرغر برفق بالزيت; اشوِ 4–5 دقائق لكل جانب دون تحريك — اقلب مرة واحدة فقط; يكون البرغر جاهزاً عندما تصل درجة الحرارة الداخلية 65 °م (متوسط) وتتكون قشرة محمرة عميقة على الجانبين مع علامات شواء مرئية; لا تضغط عليه — ستفقد كل العصارة وتلغي عمل الخطوة 3. سخّن الخبز: في الدقيقة الأخيرة من الشواء، ضع 4 خبزات سومون أو بيتا على الشواية 30 ثانية لكل جانب حتى تسخن وتحمص قليلاً; اشطر كل خبزة بيتا من حافة واحدة لعمل جيب كبير بما يكفي للبرغر. التقديم: ضع برغراً واحداً في كل جيب بيتا دافئ; ضع فوقه 1 ملعقة كبيرة من الأجفار، قطعة من الكايماك، كومة سخية من البصل الأحمر النيء المقطع، رشة بقدونس وعصرة ليمون إن أحببت; كله فوراً باليدين والخبز دافئ — تباين اللحم الساخن العصير، الكايماك البارد، والأجفار المدخن هو روح طعام الشوارع البلقاني.","en":"ONION PREP: grate 200 g onion on the fine side of a box grater; transfer to a clean tea towel and squeeze HARD over the sink to remove as much liquid as possible — at least 80 ml of juice should come out; wet onion makes the patties fall apart on the grill; reserve 2 tbsp of the squeezed pulp for the meat. MIX THE MEAT: in a large bowl, combine 500 g beef + 300 g lamb (or pork); add 2 tbsp squeezed onion pulp, 4 garlic cloves crushed with 0.5 tsp salt, 1 tbsp sweet paprika, 1 tsp hot paprika (if using), 1 tsp salt, 1 tsp pepper, 0.5 tsp marjoram and 1 tsp baking soda; knead vigorously by hand 4–5 minutes — the mixture should become sticky and noticeably tightened, which gives pljeskavica its signature springy bounce. ADD SPARKLING WATER: slowly drizzle in 100 ml ice-cold sparkling water while continuing to knead, in 4 additions of 25 ml each; the water aerates the mince and combines with the baking soda to keep the patties juicy and tender; cover with film and refrigerate at least 4 hours, ideally overnight — the rest is non-negotiable for flavour development and binding. SHAPE THE PATTIES: divide the rested meat into 4 equal portions of ~225 g each; with wet hands (to prevent sticking), roll each portion into a ball, then flatten into a flat disc 18–20 cm in diameter and 8 mm thick; the disc must be the same diameter as the bread it will be served in; press the centre slightly with your thumb to create a dimple — this prevents the patty from doming up on the grill. SECOND CHILL: place the shaped patties on a parchment-lined tray; cover loosely and refrigerate 20 minutes to firm up; meanwhile, fire up a charcoal grill to medium-high (200 °C) or heat a heavy ridged griddle pan with 1 tbsp oil until just smoking. GRILL: brush the patties lightly with oil; grill 4–5 minutes per side without moving — turn ONCE only; the patties are done when the internal temperature reaches 65 °C (medium) and a deep mahogany crust has formed on both sides with visible grill marks; resist pressing them — you'll lose all the juice and undo the work you did in step 3. WARM THE BREAD: during the last minute of grilling, place 4 somun or pita on the grill for 30 seconds per side until warmed and lightly toasted; split each pita open at one edge to make a pocket large enough for the patty. SERVE: slip one patty into each warm pita pocket; top with 1 tbsp ajvar, a knob of kajmak, a generous mound of sliced raw red onion, a sprinkle of parsley, and a squeeze of lemon if you like; eat immediately with your hands while the bread is warm — the contrast of hot juicy meat, cool kajmak, and smoky ajvar is the soul of Balkan street food."}},{"id":159,"servings":4,"tipType":"dessert","pairingsType":"dessert","origin":{"ar":"هولندا","en":"Netherlands","ro":"Olanda"},"name":{"ar":"بوفيرتيس","en":"Poffertjes","ro":"Poffertjes"},"category":{"ar":"حلوى","en":"Dessert","ro":"Desert"},"ingredients":{"ar":["250 غ من دقيق الحنطة السوداء (تقليدي، يعطي النكهة المميزة) — أو 100 غ حنطة سوداء + 150 غ دقيق عادي كبديل أخف","7 غ خميرة فورية جافة (أو 21 غ خميرة طازجة)","1 ملعقة كبيرة سكر محبب (1 ملعقة صغيرة لتغذية الخميرة، الباقي في الخليط)","0,5 ملعقة صغيرة ملح ناعم","350 مل من الحليب كامل الدسم الدافئ (38 °م)","2 بيضات كبيرة","30 غ زبدة غير مملحة، مذابة وفاترة، للخليط","50 غ زبدة غير مملحة إضافية للمقلاة والتزيين النهائي","1 ملعقة كبيرة من الرم الداكن أو خلاصة الفانيليا (اختياري، تقليدي)","للتقديم: 30 غ من مكعبات الزبدة الباردة للتقديم فوقها، 60 غ من السكر البودرة للنثر، شراب ستروبوافل أو القيقب (اختياري)، توت طازج (اختياري)","المعدات: مقلاة بوفيرتيس من الحديد الزهر مع 24–30 حفرة (أو مقلاة آبلسكيفر); أعواد خشبية صغيرة للتقليب"],"en":["250 g buckwheat flour (traditional, gives the signature flavour) — OR 100 g buckwheat + 150 g all-purpose flour as a milder substitute","7 g instant dry yeast (or 21 g fresh yeast)","1 tbsp granulated sugar (1 tsp to feed the yeast, the rest in the batter)","0.5 tsp fine salt","350 ml warm whole milk (38 °C)","2 large eggs","30 g unsalted butter, melted and cooled to lukewarm for the batter","50 g additional unsalted butter for the pan + finishing","1 tbsp dark rum or vanilla extract (optional, traditional)","To serve: 30 g cold unsalted butter cubes for topping, 60 g icing sugar to dust, stroopwafel syrup or maple syrup (optional), fresh berries (optional)","Equipment: poffertjespan cast-iron pan with 24–30 dimples (or aebleskiver pan); small wooden skewer or chopstick for flipping"],"ro":["250 g făină de hrișcă (tradițional, dă aroma signature) — SAU 100 g hrișcă + 150 g făină albă ca substitut mai blând","7 g drojdie uscată instant (sau 21 g drojdie proaspătă)","1 lingură zahăr (1 linguriță pentru drojdie, restul în aluat)","0,5 linguriță sare fină","350 ml lapte integral cald (38 °C)","2 ouă mari","30 g unt nesărat topit și răcit la călduț pentru aluat","50 g unt nesărat suplimentar pentru tigaie și finisare","1 lingură rom întunecat sau extract de vanilie (opțional, tradițional)","Pentru servire: 30 g unt rece în cuburi pentru a pune deasupra, 60 g zahăr pudră pentru presărat, sirop stroopwafel sau de arțar (opțional), fructe de pădure proaspete (opțional)","Echipament: tigaie poffertjespan din fontă cu 24–30 adâncituri (sau tigaie aebleskiver); bețișoară de lemn pentru întors"]},"howIsMade":{"ar":"تنشيط الخميرة: سخّن 350 مل من الحليب في قدر إلى نحو 38 °م (فاتر — مريح على الرسغ); اسكبه في وعاء كبير، انثر 7 غ من الخميرة الفورية و1 ملعقة صغيرة سكر فوق السطح، واتركه يستريح 10 دقائق حتى تظهر رغوة كريمية في الأعلى; إن لم تكن هناك رغوة، فالخميرة ميتة — ابدأ من جديد بخميرة طازجة. حضّر الخليط: اخفق 2 بيضات في الحليب المخمر حتى يصبح أملس; في وعاء آخر، انخل 250 غ من دقيق الحنطة السوداء (أو خلطة حنطة سوداء+دقيق عادي)، 2 ملعقة صغيرة من السكر المتبقي و0,5 ملعقة صغيرة ملح; أضف الجاف إلى الرطب على دفعتين، اخفق بعد كل إضافة حتى الأملس — بدون كتل; اخفق 30 غ من الزبدة المذابة والمبردة و1 ملعقة كبيرة من الرم (إن استخدمت); يجب أن يكون الخليط بقوام كريمة رقيقة تتدفق على شكل أشرطة من المخفقة. التخمير الأول: غطّ الوعاء بقماش نظيف واتركه يتخمر في مكان دافئ 60 دقيقة حتى يصبح السطح مغطى بالفقاعات ويرتفع الخليط بشكل واضح (~1,5× الحجم); الخميرة تطور النكهة الهوائية والحامضة قليلاً المميزة للبوفيرتيس الحقيقي. حرّكه ودعه يستريح: حرّك الخليط المرتفع بلطف لإخراج الفقاعات الكبيرة; انقله إلى زجاجة عاصرة أو إبريق أو كيس حلواني — أسهل طريقة للجرعة بدقة في الحفر الصغيرة; اتركه يستريح 10 دقائق بينما تسخن المقلاة. سخّن البوفيرتيسبان: ضع مقلاة بوفيرتيسبان من الحديد الزهر بـ24 أو 30 حفرة على نار متوسطة-منخفضة لمدة 3 دقائق حتى تسخن بشكل متساوٍ (اختبر بقطرة ماء — يجب أن تطقطق وتتبخر في 2 ثانية); استخدم منديل ورقي مطوي مغموس في الزبدة المذابة لدهن كل حفرة بسخاء — يجب أن تكون كل حفرة مغطاة وإلا سيلتصق البوفيرتيس. املأ الحفر: اعمل بسرعة، اعصر أو اسكب الخليط في كل حفرة حتى 3/4 (نحو 1 ملعقة كبيرة لكل حفرة); انتظر 60–90 ثانية حتى تثبت الحواف ويتشكل حلقة ذهبية حول كل واحدة، مع ظهور فقاعات على السطح. اقلب كل واحدة: باستخدام عود خشبي، اسحب كل بوفيرتيس نصف ناضج على جانب حفرته واقلبه رأساً على عقب — سيتدفق الخليط الخام من الأعلى إلى الحفرة، ليملأ كرة مستديرة; اطبخ 60–90 ثانية أخرى حتى يصبح الجانب الثاني ذهبياً بنياً عميقاً; يجب أن يكون كل بوفيرتيس كرة مستديرة هوائية، ذهبية من كلا الجانبين، بعرض نحو 3 سم. قدّمه فوراً: انقل 8–10 بوفيرتيس إلى كل صحن دافئ; ضع فوقه قطعة صغيرة من الزبدة الباردة (ستذوب وتتشبع) ورشة سخية من السكر البودرة عبر منخل ناعم; قدّمه فوراً — يصبح البوفيرتيس مطاطياً في غضون 5 دقائق من تحضيره; اختياري: اسكب شراب الستروبوافل أو انثر التوت الطازج.","en":"ACTIVATE THE YEAST: warm 350 ml milk in a saucepan to about 38 °C (lukewarm — comfortable on your wrist); pour into a large bowl, sprinkle 7 g instant dry yeast and 1 tsp sugar over the surface, and let stand 10 minutes until a creamy foam appears on top; if no foam, the yeast is dead — start over with fresh yeast. MAKE THE BATTER: whisk 2 eggs into the foamed yeast-milk until smooth; in a separate bowl, sift together 250 g buckwheat flour (or the buckwheat+all-purpose mix), the remaining 2 tsp sugar and 0.5 tsp salt; add the dry to the wet in two additions, whisking each time until smooth — no lumps; whisk in 30 g melted cooled butter and 1 tbsp rum (if using); the batter should be the consistency of thin cream that ribbons off the whisk. FIRST PROOF: cover the bowl with a clean cloth and let rise in a warm spot for 60 minutes, until the surface is covered with bubbles and the batter has risen noticeably (about 1.5× volume); the yeast develops the signature airy, slightly sour flavour of true poffertjes. STIR DOWN AND REST: gently stir the risen batter to deflate large bubbles; transfer to a squeeze bottle, jug or piping bag — the easiest way to portion accurately into the small dimples; let rest 10 minutes while the pan heats. HEAT THE POFFERTJESPAN: place a 24- or 30-dimple cast-iron poffertjespan over medium-low heat for 3 minutes until evenly hot (test with a drop of water — it should sizzle and evaporate in 2 seconds); use a folded paper towel dipped in melted butter to grease each dimple generously — every dimple must be coated or the poffertjes will stick. FILL THE DIMPLES: working fast, squeeze or pour batter into each dimple until 3/4 full (about 1 tbsp per dimple); wait 60–90 seconds until the edges are set and a golden ring forms around each one, with bubbles forming on the surface. FLIP EACH ONE: using a wooden skewer, pull each half-set poffertje up the side of its dimple and flip it upside down — the uncooked top batter will flow into the dimple, filling out a round ball; cook another 60–90 seconds until the second side is deep golden brown; each poffertje should be a fluffy round ball, golden on both sides, about 3 cm wide. SERVE IMMEDIATELY: slide 8–10 poffertjes onto each warm plate; top with a small knob of cold butter (it will melt and soak in) and a generous dust of icing sugar through a fine sieve; serve immediately — poffertjes turn rubbery within 5 minutes of being made; optional: drizzle stroopwafel syrup or scatter fresh berries."}},{"id":160,"origin":{"ar":"اليابان","en":"Japan","ro":"Japonia"},"name":{"ar":"كاري ياباني","en":"Japanese Curry Rice","ro":"Curry japonez"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"japanese","ingredients":{"ar":["كوبان أرز بحبة قصيرة (غير مطبوخ)","400غ أفخاذ دجاج منزوعة العظم والجلد (أو لحم بقري)، مقطّعة مكعبات 3 سم","بصلتان كبيرتان مقطّعتان مكعبات متوسطة","2 بطاطا متوسطة مقطّعة مكعبات 3 سم","2 جزرة متوسطة مقطّعة دوائر 1.5 سم","1 ملعقة كبيرة زيت نباتي","800مل ماء","علبة مكعبات روكس كاري ياباني (مثل S&B Golden Curry متوسط، نحو 100غ)","1 ملعقة صغيرة صوص ورشستر","1 ملعقة صغيرة كاتشب (اختياري)","ملح وفلفل أسود حسب الذوق"],"en":["2 cups short-grain rice (uncooked)","400g boneless skinless chicken thighs (or beef chuck), cut into 3 cm pieces","2 large onions, cut into medium dice","2 medium potatoes, cut into 3 cm cubes","2 medium carrots, cut into 1.5 cm rounds","1 tbsp vegetable oil","800ml water","1 pack Japanese curry roux blocks (e.g. S&B Golden Curry, medium, approx. 100g)","1 tsp Worcestershire sauce","1 tsp ketchup (optional, for depth)","salt and black pepper to taste"],"ro":["2 căni orez cu bob scurt (nepreparare)","400g pulpe de pui dezosate fără piele (sau vită pentru friptură), tăiate cuburi de 3 cm","2 cepe mari, tăiate cuburi medii","2 cartofi medii, tăiați cuburi de 3 cm","2 morcovi medii, tăiați rondele de 1,5 cm","1 lingură ulei vegetal","800ml apă","1 pachet blocuri de roux curry japonez (ex. S&B Golden Curry, mediu picant, aprox. 100g)","1 linguriță sos Worcestershire","1 linguriță ketchup (opțional, pentru rotunjimea gustului)","sare și piper negru după gust"]},"howIsMade":{"ar":"الأرز: اشطف 360 غ (2 كوب) من الأرز قصير الحبة بالماء البارد 3–4 مرات حتى يخرج الماء صافياً; ضعه في قدر مع 540 مل (2½ كوب) من الماء البارد; اتركه يغلي مكشوفاً، غطّه، خفف الحرارة لأدنى مستوى واطبخ 13 دقيقة; ارفعه عن النار واتركه يستريح مغطى 10 دقائق; لا ترفع الغطاء. تكرميل البصل: في قدر كبير، سخّن 1 ملعقة كبيرة من الزيت على نار متوسطة; أضف 2 بصلة مقطعة قطعاً متوسطة وحرّك بانتظام 15–20 دقيقة حتى يصبح طرياً وذهبياً — لا تتجاهل هذه الخطوة؛ البصل المكرمل هو العمود الفقري للنكهة. تحمير اللحم: أضف 400 غ من أفخاذ الدجاج أو لحم البقر مقطع قطعاً 3 سم، تبّله بالملح والفلفل، حمّره من جميع الجوانب 3–4 دقائق; يجب أن يكون للحم قشرة ذهبية عميقة — نكهة إضافية. الخضار: أضف 2 جزرة بشرائح 1,5 سم و2 بطاطس بمكعبات 3 سم; حرّك 1 دقيقة لتغليف الخضار بالزيت. اطبخ الأساس: أضف 800 مل من الماء، اتركه يغلي، خفف الحرارة واطبخه مكشوفاً 15 دقيقة، أو حتى تكون البطاطا طرية تقريباً (اختبر بسيخ). أضف الروكس: ارفع القدر عن النار; كسر 100 غ من قوالب روكس الكاري الياباني إلى قطع صغيرة وحرّكها حتى تذوب تماماً — الإضافة خارج النار تمنع التكتل. كثّف الصلصة: أعد القدر إلى نار هادئة واطبخ مع التحريك المتكرر 10 دقائق حتى تصبح الصلصة كثيفة ولامعة — يجب أن تغطي ظهر الملعقة; أضف 1 ملعقة صغيرة ورشستر و1 ملعقة صغيرة كاتشب للعمق، تذوّق وعدّل الملح. التقديم: قدّم حصة سخية من الكاري فوق الأرز الساخن في صحون عميقة; المرفقات التقليدية: شريحة كاتسو، ملفوف مفروم، فجل أحمر مخلل (فوكوجينزوكي); صحن واحد يحوي الأرز والكاري دون خلطهما — يجمعهما الناس بالملعقة على المائدة.","en":"THE RICE: rinse 360 g (2 cups) short-grain rice in cold water 3–4 times until the water runs clear; place in a pot with 540 ml (2½ cups) cold water; bring to a boil uncovered, cover, reduce to lowest heat and cook 13 minutes; remove from heat and rest covered 10 minutes; do not lift the lid. CARAMELIZE THE ONIONS: in a large pot, heat 1 tbsp oil over medium heat; add 2 medium-diced onions and cook, stirring often, for 15–20 minutes until soft and golden — DO NOT skip this step; the caramelized onions are the backbone of flavour. BROWN THE MEAT: add 400 g boneless chicken thighs or beef chuck cut in 3 cm pieces, season with salt and pepper, sear on all sides 3–4 minutes; the meat must have a deep golden crust — extra flavour. VEGETABLES: add 2 carrots cut in 1.5 cm rounds and 2 potatoes cut in 3 cm cubes; stir 1 minute to coat the vegetables in the oil. SIMMER THE BASE: pour in 800 ml water, bring to a boil, reduce to a gentle simmer uncovered for 15 minutes, or until the potato is just tender (check with a skewer). ADD THE ROUX: remove the pot from the heat; break 100 g Japanese curry roux blocks into small pieces and stir into the pot until fully dissolved — adding off heat prevents lumps. THICKEN THE SAUCE: return the pot to low heat and simmer, stirring frequently, for 10 minutes until the sauce is thick and glossy — it should coat the back of a spoon; stir in 1 tsp Worcestershire sauce and 1 tsp ketchup for depth, taste and adjust salt. SERVE: spoon a generous portion of curry over hot rice in deep plates; traditional accompaniments: katsu schnitzel, shredded cabbage, pickled red radishes (fukujinzuke); a single plate holds both rice and curry without mixing them — you spoon them together at the table."}},{"id":161,"servings":4,"tipType":"def","pairingsType":"mediterranean","origin":{"ar":"اليونان","en":"Greece","ro":"Grecia"},"name":{"ar":"فاسولادا","en":"Fasolada","ro":"Fasolada"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"ingredients":{"ar":["400 غ من الفاصوليا البيضاء الجافة (كانيليني، نيفي، أو الفاصوليا اليونانية الكبيرة الجايغانتس)، منقوعة طوال الليل في الماء البارد","2 جزرة متوسطة (~200 غ)، مقشّرة ومقطعة مكعبات 1 سم","2 سيقان كرفس (~150 غ)، مقطعة مكعبات 1 سم + 30 غ من أوراق الكرفس المفرومة (اختياري، تقليدي)","1 بصلة كبيرة (~200 غ)، مفرومة ناعماً","4 فصوص ثوم، مفرومة ناعماً","400 غ من الطماطم الناضجة (4 متوسطة) — مقشّرة ومبشورة أو 1 علبة × 400 غ طماطم مهروسة","1 ملعقة كبيرة معجون طماطم","100 مل زيت زيتون بكر ممتاز للسوفريتو + 60 مل إضافية للتشطيب","2 ورقة غار","1 ملعقة صغيرة أوريغانو مجفف","1,5 ملعقة صغيرة ملح + المزيد حسب الذوق","0,5 ملعقة صغيرة فلفل أسود مطحون طازج","1 ملعقة كبيرة خل النبيذ الأحمر (اختياري، ينير في النهاية)","1,5 لتر ماء (أو مرق خضار)","للتقديم: خبز ريفي مقرمش، زيتون كالاماتا، جبنة فيتا مفتتة، بقدونس طازج"],"en":["400 g dried white beans (cannellini, navy, or large Greek gigantes), soaked overnight in cold water","2 medium carrots (~200 g), peeled and diced 1 cm","2 celery stalks (~150 g), diced 1 cm + 30 g celery leaves chopped (optional, traditional)","1 large onion (~200 g), finely diced","4 garlic cloves, finely minced","400 g ripe tomatoes (4 medium) — peeled and grated OR 1 × 400 g can crushed tomatoes","1 tbsp tomato paste","100 ml extra-virgin olive oil for the soffritto + 60 ml more for finishing","2 bay leaves","1 tsp dried oregano","1.5 tsp salt + more to taste","0.5 tsp freshly ground black pepper","1 tbsp red wine vinegar (optional, brightens at the end)","1.5 L water (or vegetable stock)","To serve: crusty country bread, Kalamata olives, crumbled feta cheese, fresh parsley"],"ro":["400 g fasole albă uscată (cannellini, navy sau gigantes grecești), înmuiate peste noapte în apă rece","2 morcovi medii (~200 g), curățați și tăiați cuburi de 1 cm","2 tulpini de țelină (~150 g), tăiate cuburi de 1 cm + 30 g frunze de țelină tocate (opțional, tradițional)","1 ceapă mare (~200 g), tăiată fin","4 căței de usturoi, tocați fin","400 g roșii coapte (4 medii) — decojite și rase SAU 1 conservă × 400 g de roșii zdrobite","1 lingură pastă de roșii","100 ml ulei de măsline extravirgin pentru sotat + 60 ml suplimentar pentru finisare","2 frunze de dafin","1 linguriță oregano uscat","1,5 lingurițe sare + sare după gust","0,5 linguriță piper negru proaspăt măcinat","1 lingură oțet de vin roșu (opțional, dă luminozitate la final)","1,5 L apă (sau supă de legume)","Pentru servire: pâine de țară crocantă, măsline Kalamata, brânză feta sfărâmată, pătrunjel proaspăt"]},"howIsMade":{"ar":"انقع الفاصوليا: ضع 400 غ من الفاصوليا البيضاء الجافة في وعاء كبير، غطّها بالماء البارد بـ5 سم وانقعها 8 ساعات أو طوال الليل; صفِّها واغسلها — النقع يقصر وقت الطهي ويساعد على طهي متجانس مع بقاء الفاصوليا سليمة. اسلق الفاصوليا تمهيدياً: ضع الفاصوليا المصفّاة في قدر كبير، غطّها بالماء البارد بـ3 سم وأحضرها للغليان; اسلقها بقوة 10 دقائق ثم صفِّها — هذه الخطوة تزيل المركبات غير القابلة للهضم التي تسبب الغازات وتعطي مرقاً أنظف. السوفريتو: في قدر ثقيل 5 لتر، سخّن 100 مل من زيت الزيتون على نار متوسطة; أضف 200 غ بصل + 200 غ جزر + 150 غ كرفس مكعبات وحرّكها بانتظام 12–15 دقيقة حتى تصبح طرية جداً وتبدأ بالاحمرار — هذه القاعدة البطيئة هي أساس عمق الفاسولادا; أضف 4 فصوص ثوم مفرومة واطبخها دقيقة أخرى حتى تفوح. تفتيح الطماطم: أضف 1 ملعقة كبيرة من معجون الطماطم واطبخه مع التحريك 2 دقيقة حتى يغمق; أضف 400 غ من الطماطم المبشورة (أو المهروسة من العلبة) واطبخها 5 دقائق حتى تختفي الحموضة الخام ويصبح المزيج أحمر عميقاً. أضف الفاصوليا والماء: أعد الفاصوليا المسلوقة سابقاً إلى القدر; أضف 1,5 لتر ماء (أو مرق خضار)، 2 ورقة غار، 1 ملعقة صغيرة أوريغانو، 1,5 ملعقة صغيرة ملح و0,5 ملعقة صغيرة فلفل; أحضرها للغليان وخفف الحرارة لغليان هادئ. اطبخها ببطء: اطبخها مكشوفة 60–90 دقيقة مع التحريك من حين لآخر حتى تصبح الفاصوليا طرية تماماً وكريمية في المركز لكن تحتفظ بشكلها — تذوّق فاصوليا كل 15 دقيقة بعد ساعة الطهي الأولى; يجب أن يتقلص المرق إلى النصف ويثخن إلى قوام الحساء; أضف المزيد من الماء إذا جف بسرعة. التشطيب: تخلص من أوراق الغار; أدخل 30 غ من أوراق الكرفس المفرومة (إذا استخدمت) و1 ملعقة كبيرة من خل النبيذ الأحمر للإنارة; تذوّق وعدّل الملح; ارفعها عن النار ورش 60 مل من زيت الزيتون البكر الممتاز الطازج على السطح — هذا هو زيت التشطيب الذي يجعل الحساء لامعاً وعطرياً; اتركها تستريح 10 دقائق. التقديم: اغرف في صحون عميقة، ارش كل حصة بـ1 ملعقة صغيرة أخرى من زيت الزيتون واطحن الفلفل الأسود الطازج فوقها; قدّمها مع خبز ريفي مقرمش، صحن صغير من زيتون كالاماتا، فيتا مفتتة وبقدونس طازج مفروم على المائدة; أفضل في اليوم التالي.","en":"SOAK THE BEANS: place 400 g dried white beans in a large bowl, cover with cold water by 5 cm, and soak 8 hours or overnight; drain and rinse — the soak shortens the cooking time and helps even, intact beans. PARBOIL THE BEANS: place the drained beans in a large pot, cover with cold water by 3 cm, and bring to a boil; boil hard 10 minutes, then drain — this removes the indigestible compounds that cause gas and gives a cleaner-tasting broth. SOFFRITTO: in a heavy 5 L pot, heat 100 ml olive oil over medium heat; add 200 g diced onion + 200 g diced carrot + 150 g diced celery and cook, stirring often, 12–15 minutes until very soft and starting to gold — this slow vegetable base is the foundation of fasolada's depth; add 4 minced garlic cloves and cook 1 more minute until fragrant. BLOOM THE TOMATO: add 1 tbsp tomato paste and cook stirring 2 minutes until darkened; add 400 g grated tomato (or canned crushed) and simmer 5 minutes until the raw acidity cooks off and the mixture turns deep red. ADD BEANS AND WATER: return the parboiled beans to the pot; add 1.5 L water (or vegetable stock), 2 bay leaves, 1 tsp oregano, 1.5 tsp salt and 0.5 tsp pepper; bring to a boil, reduce to a gentle simmer. SLOW SIMMER: cook uncovered 60–90 minutes, stirring occasionally, until the beans are completely tender and creamy at the centre but still hold their shape — taste a bean every 15 minutes after the 1 hour mark; the broth should reduce by about half and thicken to a soupy consistency; add more water if it dries out too fast. FINISH: discard the bay leaves; stir in 30 g chopped celery leaves (if using) and 1 tbsp red wine vinegar for brightness; taste and adjust salt; off the heat, drizzle 60 ml fresh extra-virgin olive oil over the surface — this is the finishing oil that makes the soup glossy and aromatic; let rest 10 minutes for flavours to settle. SERVE: ladle into deep bowls, drizzle each portion with another teaspoon of olive oil, and grind fresh black pepper over the top; serve with crusty country bread, a small bowl of Kalamata olives, crumbled feta, and chopped fresh parsley on the table; even better the next day."}},{"id":162,"servings":4,"tipType":"meat","pairingsType":"mexican","origin":{"ar":"المكسيك","en":"Mexico","ro":"Mexic"},"name":{"ar":"تلايوداس","en":"Tlayudas","ro":"Tlayudas"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["4 خبزات تورتيلا تلايودا (~30 سم، شبه مجففة) أو 4 خبزات تورتيلا قمح كبيرة كبديل","250 غ من الفاصوليا السوداء الجافة منقوعة طوال الليل (أو 1 علبة × 400 غ)","100 غ شحم أو 100 مل زيت نباتي للقلي والطهي","1 بصلة كبيرة (~200 غ): النصف بأرباع للفاصوليا، النصف الآخر مفروم ناعماً للتقديم","4 فصوص ثوم (2 للفاصوليا، 2 للحم)","1 ملعقة صغيرة كمون مطحون + 1 ملعقة صغيرة أوريغانو مجفف + 1 ملعقة صغيرة ملح للفاصوليا","500 غ من ستيك الفلانك أو سكيرت، مقطع رقيقاً ضد الحبيبات (نمط تاساجو)","200 غ من تشوريزو مكسيكي طازج (أو إسباني)، منزوع من المعى","300 غ من كيسيو (جبنة واهاكا) أو موزاريلا منخفضة الرطوبة، مبشورة","200 غ من خس الآيسبرغ المقطع","2 أفوكادو ناضج (~300 غ)، مقطع شرائح","4 طماطم ناضجة (~400 غ)، مقطعة شرائح","200 غ من صلصة روخا أو فيردي (منزلية أو جاهزة)","1 ليمونة مقطعة أرباعاً + كزبرة طازجة للتقديم"],"en":["4 tlayuda tortillas (~30 cm, semi-dried) or 4 large flour tortillas as substitute","250 g dried black beans soaked overnight (or 1 × 400 g can)","100 g lard or 100 ml vegetable oil for frying beans + cooking","1 large onion (~200 g): half quartered for the beans, the other half finely diced for serving","4 garlic cloves (2 for beans, 2 for meat)","1 tsp ground cumin + 1 tsp dried oregano + 1 tsp salt for the beans","500 g flank or skirt steak, sliced very thinly across the grain (tasajo-style)","200 g fresh Mexican chorizo (or Spanish), removed from casing","300 g quesillo (Oaxaca string cheese) or low-moisture mozzarella, shredded","200 g shredded iceberg lettuce","2 ripe avocados (~300 g), sliced","4 ripe tomatoes (~400 g), sliced","200 g salsa roja or salsa verde (homemade or store-bought)","1 lime cut into wedges + fresh cilantro for serving"],"ro":["4 tortillas tlayuda (~30 cm, semi-uscate) sau 4 tortillas mari de făină","250 g fasole neagră uscată înmuiată peste noapte (sau 1 conservă × 400 g)","100 g untură sau 100 ml ulei vegetal pentru prăjit fasolea + sotat","1 ceapă mare (~200 g): jumătate tăiată sferturi pentru fasole, cealaltă jumătate tocată fin pentru servire","4 căței de usturoi (2 pentru fasole, 2 pentru carne)","1 linguriță chimion măcinat + 1 linguriță oregano uscat + 1 linguriță sare pentru fasole","500 g flank steak sau skirt steak, feliat foarte subțire în diagonală (stil tasajo)","200 g chorizo proaspăt mexican (sau spaniol), scos din maț","300 g quesillo (brânză Oaxaca) sau mozzarella low-moisture, rasă","200 g salată iceberg, tocată","2 avocado coapte (~300 g), feliate","4 roșii coapte (~400 g), feliate","200 g salsa roja sau verde (de casă sau de la magazin)","1 lime tăiată sferturi + coriandru proaspăt pentru servire"]},"howIsMade":{"ar":"الفاصوليا: صفِّ 250 غ من الفاصوليا السوداء المنقوعة; اسلقها في 1,5 لتر ماء مع نصف بصلة بأرباع، 2 فص ثوم كاملين، 1 ملعقة صغيرة كمون، 1 ملعقة صغيرة أوريغانو و1 ملعقة صغيرة ملح لمدة 60–90 دقيقة حتى تصبح طرية جداً; صفِّها مع الاحتفاظ بـ200 مل من سائل الطهي. اقلِ الفاصوليا (فريخوليس ريفريتوس): في مقلاة سخّن 50 غ شحم على نار متوسطة; أضف الفاصوليا المسلوقة واهرسها بمطحنة البطاطس أو ملعقة، مضيفاً السائل المحفوظ تدريجياً حتى تحصل على عجينة سميكة كريمية; اطبخها 5–7 دقائق مع التحريك حتى تغمق قليلاً وتكتسب نكهة دخانية. حمّر اللحم: سخّن 1 ملعقة كبيرة زيت في مقلاة كبيرة على نار متوسطة-عالية; تبّل 500 غ من اللحم بالملح والفلفل، حمّر 2 دقيقة لكل جانب في طبقة واحدة (لا تزدحم المقلاة، اعمل على دفعات); ضعه في صحن مغطى بالألمنيوم. اقلِ التشوريزو: في نفس المقلاة أضف 200 غ تشوريزو منزوع المعى، فتته بملعقة خشبية واقلِه 5–7 دقائق على نار متوسطة حتى يطلق الزيت الأحمر وينضج; اتركه في المقلاة مع زيته. حضّر الإضافات: قطّع 2 أفوكادو، 4 طماطم ونصف البصل المتبقي (مفروم ناعماً); قطّع 200 غ خس; ضع كل واحد في وعاء منفصل للتجميع السريع. تجميع التلايودا: سخّن صفيحة بلانتشا أو مقلاة كبيرة على نار متوسطة-عالية; ضع تورتيلا تلايودا على السطح الجاف وافردها بطبقة سخية من الفاصوليا المقلية حتى 1 سم من الحواف; انثر 75 غ من الجبن المبشور فوق الفاصوليا; أضف حصة من اللحم والتشوريزو. التقرمش: اطبخها على البلانتشا 5–7 دقائق دون قلب — يجب أن يصبح قاع التورتيلا ذهبياً ومقرمشاً ويظهر آثار حروق خفيفة; يجب أن تذوب الجبن تماماً; غطّها في الدقيقتين الأخيرتين لتسريع الذوبان. التقديم: انقل التلايودا إلى صحن بملعقة عريضة; ضع فوقها الخس وشرائح الطماطم والأفوكادو والبصل المفروم والصلصة; اعصر الليم وانثر الكزبرة; اطوها للنصف أو كلها مفتوحة باليد; كرر للثلاث المتبقية; قدّمها فوراً — تصبح مطاطية إذا تركتها.","en":"THE BEANS: drain 250 g soaked black beans; boil in 1.5 L water with half an onion in quarters, 2 whole garlic cloves, 1 tsp cumin, 1 tsp oregano and 1 tsp salt for 60–90 minutes until very tender; drain, reserving 200 ml of the cooking liquid. REFRY THE BEANS (frijoles refritos): in a skillet, heat 50 g lard over medium heat; add the cooked beans and mash with a potato masher or spatula, adding the reserved liquid gradually until you have a thick creamy paste; cook 5–7 minutes, stirring, until slightly blackened and smoky. SEAR THE STEAK: heat 1 tbsp oil in a large skillet over medium-high; season 500 g beef with salt and pepper, sear 2 minutes per side in a single layer (do not crowd the pan, work in batches); rest the meat on a foil-tented plate. FRY THE CHORIZO: in the same skillet, add 200 g chorizo from its casing, break it up with a wooden spoon, and fry 5–7 minutes over medium heat until the red oil is released and the meat is fully cooked; leave it in the pan with its oil. PREP THE TOPPINGS: slice 2 avocados, 4 tomatoes and the remaining onion half (finely diced); shred 200 g lettuce; place each in a separate bowl for fast assembly. ASSEMBLE THE TLAYUDA: preheat a plancha or large griddle over medium-high heat; place a tlayuda tortilla on the dry surface and spread it with a generous layer of refried beans to within 1 cm of the edges; scatter 75 g shredded cheese over the beans; add a portion of seared steak and chorizo. CRISP IT UP: cook on the plancha over medium heat 5–7 minutes without flipping — the bottom of the tortilla must turn golden brown, crunchy, and show light scorch marks; the cheese must melt completely; cover with a lid for the last 2 minutes to speed melting. SERVE: slide the tlayuda onto a plate with a wide spatula; top with lettuce, tomato slices, avocado, diced onion, salsa; squeeze lime and scatter cilantro; fold in half or eat open with your hands; repeat for the remaining 3 tlayudas; serve immediately — it gets chewy if it sits."}},{"id":163,"servings":4,"tipType":"meat","pairingsType":"latin","origin":{"ar":"كولومبيا","en":"Colombia","ro":"Columbia"},"name":{"ar":"بانديخا بايسا","en":"Bandeja Paisa","ro":"Bandeja Paisa"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"ingredients":{"ar":["لفاسوليس أنطيوكينيوس: 400 غ من الفاصوليا الحمراء الجافة (كارغامانتو أو كيدني)، منقوعة طوال الليل","جزرة متوسطة (~100 غ) مبشورة + 2 طماطم متوسطة (~250 غ) مبشورة + 1 بصلة (~150 غ) مفرومة ناعماً + 4 فصوص ثوم لإعداد الهوغاو","2 ملعقة كبيرة زيت + 1 ملعقة كبيرة معجون طماطم + 1 ملعقة صغيرة كمون + 1 ملعقة صغيرة ملح للفاصوليا","1 موزة بلانتاين ناضجة (~150 غ) مكعبات للفاصوليا","للأرز الأبيض: 360 غ (2 كوب) أرز متوسط الحبة + 540 مل ماء + 0,5 ملعقة صغيرة ملح","للحم المفروم: 500 غ لحم بقر مفروم + 1 بصلة مفرومة ناعماً + 4 فصوص ثوم + 2 طماطم مبشورة + 2 ملعقة كبيرة زيت + 1 ملعقة صغيرة كمون + 1 ملعقة صغيرة ملح + 0,5 ملعقة صغيرة فلفل + 50 مل مرق بقر","للتشيتشارون: 800 غ بطن خنزير بقشره مقطع 8 شرائح ~10 سم + 1 ملعقة صغيرة ملح","4 تشوريزو كولومبي خام (~80 غ لكل واحد)","4 موسيا (نقانق دم، ~80 غ لكل واحدة)","لـ4 أريباس صغيرة: 200 غ من دقيق الذرة الأبيض المسبق الطبخ (Harina P.A.N.) + 240 مل ماء دافئ + 0,5 ملعقة صغيرة ملح + 1 ملعقة كبيرة زيت للصينية","للمادورو: 2 موزة بلانتاين ناضجة جداً (قشرة سوداء داكنة) + 2 ملعقة كبيرة زيت","4 بيضات كبيرة للقلي + 1 ملعقة كبيرة زيت + ملح وفلفل","2 أفوكادو ناضج، مشقوقان نصفين ومنزوع النوى","4 شرائح خبز أبيض مقرمش + 4 شرائح ليم + ملح للتقديم"],"en":["For frijoles antioqueños: 400 g dried red kidney or cargamanto beans, soaked overnight","1 medium carrot (~100 g) grated + 2 medium tomatoes (~250 g) grated + 1 onion (~150 g) finely diced + 4 garlic cloves for the hogao","2 tbsp oil + 1 tbsp tomato paste + 1 tsp ground cumin + 1 tsp salt for the beans","1 ripe plantain (~150 g) diced for the beans","For arroz blanco: 360 g (2 cups) medium-grain white rice + 540 ml water + 0.5 tsp salt","For carne molida: 500 g ground beef + 1 onion finely diced + 4 garlic cloves + 2 grated tomatoes + 2 tbsp oil + 1 tsp cumin + 1 tsp salt + 0.5 tsp pepper + 50 ml beef stock","For chicharrón: 800 g pork belly skin-on cut into 8 strips of ~10 cm + 1 tsp salt","4 raw Colombian chorizos (~80 g each)","4 morcillas (blood sausages, ~80 g each)","For 4 small arepas: 200 g precooked white corn flour (Harina P.A.N.) + 240 ml warm water + 0.5 tsp salt + 1 tbsp oil for the griddle","For maduro: 2 very ripe plantains (deep black skin) + 2 tbsp oil","4 large eggs for sunny-side up + 1 tbsp oil + salt and pepper","2 ripe avocados, halved and pitted","4 slices of crusty white bread + 4 lime wedges + salt to serve"],"ro":["Pentru frijoles antioqueños: 400 g fasole roșie uscată (cargamanto sau kidney) înmuiată peste noapte","1 morcov mediu (~100 g) ras + 2 roșii medii (~250 g) rase + 1 ceapă (~150 g) tocată fin + 4 căței usturoi pentru hogao","2 linguri ulei + 1 lingură pastă de roșii + 1 linguriță chimion + 1 linguriță sare pentru fasole","1 banană plantain coaptă (~150 g) tocată în cuburi pentru fasole","Pentru arroz blanco: 360 g (2 căni) orez cu bob mediu + 540 ml apă + 0,5 linguriță sare","Pentru carne molida: 500 g vită tocată + 1 ceapă tocată + 4 căței usturoi + 2 roșii rase + 2 linguri ulei + 1 linguriță chimion + 1 linguriță sare + 0,5 linguriță piper + 50 ml supă de vită","Pentru chicharrón: 800 g costiță de porc cu coajă tăiată în 8 fâșii lungi de 10 cm + 1 linguriță sare","4 chorizos columbieni cruzi (~80 g fiecare)","4 morcillas (cârnați de sânge, ~80 g fiecare)","Pentru arepas (4 mici): 200 g făină de porumb precoaptă (Harina P.A.N.) + 240 ml apă caldă + 0,5 linguriță sare + 1 lingură ulei pentru tigaie","Pentru maduro: 2 banane plantain foarte coapte (coaja neagră) + 2 linguri ulei","4 ouă mari pentru ochiuri + 1 lingură ulei + sare și piper","2 avocado coapte, jumătățite și fără sâmbure","4 felii pâine albă crocantă + 4 felii de lime + sare pentru servire"]},"howIsMade":{"ar":"النقع والتخطيط: انقع 400 غ من الفاصوليا الحمراء طوال الليل; تتطلب بانديخا بايسا 6 مكونات متوازية — اجمع كل المكونات والأدوات قبل البدء، بالإضافة إلى 3 قدور و2 مقلاة. الفاصوليا: صفِّ الفاصوليا، اطبخها في 1,5 لتر ماء مع جزر مبشور + 1 طماطم مبشورة + بصل + 2 فص ثوم + 1 ملعقة صغيرة كمون + 1 ملعقة صغيرة ملح 60–90 دقيقة حتى تنضج; في آخر 15 دقيقة حضّر الهوغاو: قلِّ في 2 ملعقة كبيرة زيت باقي البصل + 2 ثوم + 1 طماطم مبشورة + 1 ملعقة كبيرة معجون طماطم 5 دقائق; أضفه إلى الفاصوليا مع البلانتاين المقطع واطبخ 10 دقائق إضافية. الأرز: اشطف 360 غ من الأرز بالماء البارد 3 مرات; ضعه مع 540 مل ماء و0,5 ملعقة صغيرة ملح; أحضره للغليان، غطِّه، خفف الحرارة لأدنى مستوى 12 دقيقة، اتركه يستريح مغطى 10 دقائق. كارني موليدا: سخّن 2 ملعقة كبيرة زيت في مقلاة على نار متوسطة-عالية; قلِّ البصل والثوم 5 دقائق حتى يلين; أضف 500 غ لحم بقر مفروم، فتته بالملعقة وحمّره 8 دقائق; أضف 2 طماطم مبشورة، 1 ملعقة صغيرة كمون، 1 ملعقة صغيرة ملح و0,5 ملعقة صغيرة فلفل، اطبخها 5 دقائق; أفك التحجر بـ50 مل من المرق. تشيتشارون: ضع 8 شرائح بطن خنزير بقشره في قدر مع 200 مل ماء بارد و1 ملعقة صغيرة ملح; أحضره للغليان، غطِّه واطبخه 30 دقيقة; صفِّه تماماً; في نفس القدر اقلِ لحم الخنزير في دهنه على نار متوسطة-عالية 8–10 دقائق مع التقليب المتكرر حتى تصبح القشرة ذهبية ومقرمشة; (بديل: فرن 200 °م 40 دقيقة على شبكة.). الأريباس: امزج 200 غ من دقيق الذرة مع 240 مل ماء دافئ و0,5 ملعقة صغيرة ملح في وعاء حتى يتكون عجين رطب; اتركه يستريح 5 دقائق; شكّل 4 أقراص بقطر 10 سم وسماكة 1 سم; اطبخ في مقلاة ساخنة مع 1 ملعقة كبيرة زيت على نار متوسطة 4–5 دقائق لكل جانب حتى تصبح ذهبية مع بقع داكنة. المادورو + البيض + النقانق: قطّع 2 موزة بلانتاين سوداء إلى حلقات 1 سم; اقلِ في 2 ملعقة كبيرة زيت على نار متوسطة 2 دقيقة لكل جانب حتى يتكرمل; في مقلاة أخرى اقلِ 4 تشوريزو خام 5 دقائق لكل جانب و4 موسيا 3 دقائق لكل جانب; ثم اقلِ 4 بيضات في 1 ملعقة صغيرة زيت 2 دقيقة حتى يثبت البياض لكن يبقى الصفار سائلاً. التجميع: في 4 صحون كبيرة رتّب بهذا الترتيب: كومة من الأرز، ملعقة سخية من الفاصوليا، حصة من كارني موليدا، 2 قطعة تشيتشارون، 1 تشوريزو، 1 موسيا، 1 بيضة مقلية فوق اللحم، 2 شريحة مادورو، 1/2 أفوكادو، 1 أريبا، 1 شريحة خبز، 1 شريحة ليم; قدّم فوراً — بانديخا بايسا تؤكل بسكين وشوكة، كل لقمة بمزج عدة مكونات.","en":"SOAK & PLAN: soak 400 g red beans overnight; bandeja paisa runs 6 parallel components — gather all ingredients and tools before starting, plus 3 pots and 2 skillets. THE BEANS: drain the beans, simmer in 1.5 L water with grated carrot + 1 grated tomato + onion + 2 garlic cloves + 1 tsp cumin + 1 tsp salt 60–90 minutes until tender; in the final 15 minutes make the hogao: sauté in 2 tbsp oil the remaining onion + 2 garlic + 1 grated tomato + 1 tbsp tomato paste 5 minutes; stir into the beans with the diced plantain and cook 10 more minutes. THE RICE: rinse 360 g rice in cold water 3 times; place with 540 ml water and 0.5 tsp salt; bring to a boil, cover, reduce to lowest heat 12 minutes, rest covered 10 minutes. CARNE MOLIDA: heat 2 tbsp oil in a skillet over medium-high; sauté onion and garlic 5 minutes until soft; add 500 g ground beef, break up with the spoon and brown 8 minutes; add 2 grated tomatoes, 1 tsp cumin, 1 tsp salt and 0.5 tsp pepper, cook 5 minutes; deglaze with 50 ml stock. CHICHARRÓN: place 8 strips of pork belly skin-on in a pot with 200 ml cold water and 1 tsp salt; bring to a boil, cover and simmer 30 minutes; drain completely; in the same pot, fry the pork in its own fat over medium-high heat 8–10 minutes turning often until the skin is golden and crackling; (Alternative: 200 °C oven 40 minutes on a rack.). AREPAS: mix 200 g corn flour with 240 ml warm water and 0.5 tsp salt in a bowl until a damp dough forms; rest 5 minutes; shape into 4 patties of 10 cm diameter and 1 cm thick; griddle in a hot pan with 1 tbsp oil over medium heat 4–5 minutes per side until golden with dark spots. MADURO + EGGS + SAUSAGES: slice 2 black plantains into 1 cm rounds; fry in 2 tbsp oil over medium heat 2 minutes per side until caramelized; in another skillet, fry 4 raw chorizos 5 minutes per side and 4 morcillas 3 minutes per side; then fry 4 eggs in 1 tsp oil 2 minutes until whites set but yolks runny. ASSEMBLY: on 4 large platters arrange in this order: a mound of rice, a generous ladle of beans, a portion of carne molida, 2 chicharrón pieces, 1 chorizo, 1 morcilla, 1 fried egg on top of the meat, 2 maduro slices, 1/2 avocado, 1 arepa, 1 bread slice, 1 lime wedge; serve immediately — bandeja paisa is eaten with knife and fork, each bite in combination with others."}},{"id":164,"servings":4,"tipType":"def","pairingsType":"def","origin":{"ar":"المجر","en":"Hungary","ro":"Ungaria"},"name":{"ar":"لانغوش","en":"Lángos","ro":"Lángos"},"category":{"ar":"وجبة خفيفة","en":"Snack","ro":"Gustare"},"ingredients":{"ar":["500 غ من الطحين متعدد الأغراض أو طحين الخبز T550","7 غ من الخميرة الجافة الفورية (أو 21 غ خميرة طازجة)","1 ملعقة صغيرة سكر حبيبي (لتغذية الخميرة)","1,5 ملعقة صغيرة ملح ناعم للعجين","300 مل حليب كامل الدسم دافئ (أو ماء، تقليدي) عند 38 °م","100 غ بطاطس مسلوقة ومهروسة (سر القوام الهش)","2 ملعقة كبيرة زيت محايد للعجين","1 لتر زيت دوار الشمس أو محايد للقلي العميق","لدهن الثوم: 4 فصوص ثوم مهروسة مع 1 ملعقة صغيرة ملح + 1 ملعقة كبيرة ماء إلى عجينة","200 غ من القشدة الحامضة المجرية (tejföl)","200 غ من الجبن الحاد المبشور (تشيدر/غودا/إيدام)","1 حزمة صغيرة من الثوم المعمر الطازج، مفروم ناعماً (اختياري)","ملح للتشطيب","معدات: قدر عريض وثقيل للقلي + ملعقة مثقوبة + شبكة سلكية"],"en":["500 g all-purpose or T550 bread flour","7 g instant dry yeast (or 21 g fresh yeast)","1 tsp granulated sugar (to feed yeast)","1.5 tsp fine salt for the dough","300 ml warm whole milk (or water, traditional) at 38 °C","100 g boiled mashed potato (the secret to the fluffy texture)","2 tbsp neutral oil for the dough","1 L sunflower or neutral oil for deep-frying","For garlic rub: 4 garlic cloves crushed with 1 tsp salt + 1 tbsp water into a paste","200 g Hungarian sour cream (tejföl)","200 g sharp grated cheese (cheddar/gouda/edam-style)","1 small bunch fresh chives, finely chopped (optional)","Salt for finishing","Equipment: wide heavy pot for frying + slotted spoon + wire rack"],"ro":["500 g făină universală sau de pâine T550","7 g drojdie uscată instant (sau 21 g drojdie proaspătă)","1 linguriță zahăr granulat (pentru hrănirea drojdiei)","1,5 lingurițe sare fină pentru aluat","300 ml lapte integral cald (sau apă, tradițional) la 38 °C","100 g cartof fiert și pasat (secretul texturii pufoase)","2 linguri ulei neutru pentru aluat","1 L ulei de floarea-soarelui sau neutru pentru prăjit","Pentru ungerea cu usturoi: 4 căței de usturoi zdrobiți cu 1 linguriță sare + 1 lingură apă în pastă","200 g smântână ungurească (tejföl)","200 g brânză tare rasă (cheddar/gouda/edam)","1 legăturică mică de ceapă verde proaspătă (arpagic), tocată fin (opțional)","Sare pentru finisare","Echipament: oală grea și lată pentru prăjit + lingură cu fante + grătar de sârmă"]},"howIsMade":{"ar":"نشّط الخميرة: سخّن 100 مل من الحليب إلى 38 °م، أضف 7 غ خميرة و1 ملعقة صغيرة سكر، حرّك واتركها 10 دقائق حتى تتكون رغوة; لا رغوة = خميرة ميتة، ابدأ من جديد. حضّر العجين: في وعاء كبير امزج 500 غ طحين مع 1,5 ملعقة صغيرة ملح; اصنع حفرة، أضف الحليب بالخميرة المرغية، الـ200 مل المتبقية من الحليب الدافئ، 100 غ بطاطس مهروسة ناعمة (بلا كتل) و2 ملعقة كبيرة زيت; اعجن باليد أو بالعجانة 10 دقائق حتى يصبح أملس وناعم ولزجاً قليلاً — أنعم من عجين الخبز. التخمير الأول: غطّ بمنشفة نظيفة واتركه يرتفع في مكان دافئ 1,5–2 ساعة حتى يتضاعف. التشكيل: ادهن اليدين وسطح العمل بقليل من الزيت; قسّم العجين إلى 4 حصص متساوية (~225 غ لكل); كور إلى كرات، اتركها مغطاة 10 دقائق; باليدين المدهونتين امدد كل كرة إلى قرص 25 سم بسماكة حوالي 1 سم، أرفع قليلاً عند الحواف. التخمير الثاني: ضع الأقراص المشكلة على صينية مدهونة، غطّها بلطف واتركها ترتفع 20 دقيقة حتى تصبح منتفخة. سخّن الزيت: اسكب 1 لتر زيت في قدر عريض وثقيل بعمق 5 سم; سخّنه إلى 175 °م (نار متوسطة-عالية) — يجب أن تطقطق قطعة صغيرة من العجين وترتفع خلال 5 ثوانٍ. اقلِ اللانغوش: أنزل لانغوش واحد بحذر في الزيت الساخن; بعد 30 ثانية، اضغطه برفق تحت الزيت بملعقة مثقوبة — ينتفخ بشكل دراماتيكي; اقله 60–90 ثانية لكل جانب حتى يصبح ذهبياً عميقاً; صفِّه على شبكة سلكية (وليس على مناديل ورقية تجعل القاع طرياً بالبخار). الإضافات والتقديم: ادهن الوجه الساخن بمعجون الثوم (4 فصوص مهروسة مع 1 ملعقة صغيرة ملح + 1 ملعقة كبيرة ماء); افرد 50 غ من القشدة الحامضة، انثر 50 غ من الجبن المبشور، رش الثوم المعمر المقطع ورشة ملح; قدّمه في اليد أو في صحن، يُؤكل خلال 5 دقائق بينما الخبز مقرمش من الخارج وناعم من الداخل.","en":"PROOF THE YEAST: warm 100 ml of the milk to 38 °C, add 7 g yeast and 1 tsp sugar, stir and let stand 10 minutes until foamy; no foam = dead yeast, start over. MAKE THE DOUGH: in a large bowl combine 500 g flour with 1.5 tsp salt; make a well, add the foamed yeast-milk, the remaining 200 ml warm milk, 100 g smooth mashed potato (no lumps), and 2 tbsp oil; knead by hand or stand mixer 10 minutes until smooth, soft and slightly sticky — softer than bread dough. FIRST PROOF: cover with a clean towel and rise in a warm place 1.5–2 hours until doubled. SHAPE: lightly oil hands and work surface; divide into 4 equal portions (~225 g each); roll into balls, rest 10 minutes covered; with oiled hands stretch each ball into a 25 cm disc about 1 cm thick, slightly thinner at the edges. SECOND PROOF: place shaped discs on an oiled tray, cover loosely and let rise 20 minutes until puffy. HEAT THE OIL: pour 1 L oil into a wide heavy pot to a 5 cm depth; heat to 175 °C (medium-high) — a small piece of dough should sizzle and rise within 5 seconds. FRY THE LÁNGOS: carefully slide one lángos into the hot oil; after 30 seconds, gently push under with a slotted spoon — it puffs dramatically; fry 60–90 seconds per side until deeply golden brown; drain on a wire rack (NOT paper towels which steam the base soft). TOPPING & SERVE: brush the still-hot top with garlic paste (4 garlic crushed with 1 tsp salt + 1 tbsp water); smear with 50 g sour cream, scatter 50 g grated cheese, sprinkle chopped chives and a pinch of salt; serve in hand or on a plate, eaten within 5 minutes while bread is crisp outside and pillowy inside."}},{"id":165,"servings":4,"tipType":"veg","pairingsType":"indian","origin":{"ar":"الهند","en":"India","ro":"India"},"name":{"ar":"راجما","en":"Rajma","ro":"Rajma"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["350 غ من فاصوليا الكلى الحمراء المجففة (راجما) منقوعة 8–12 ساعة في ماء بارد (أو 2 × 400 غ علب فاصوليا حمراء مصفاة كاختصار)","1,2 لتر ماء طهي للفاصوليا + 1 ملعقة صغيرة ملح + 2 ورقة غار + 4 حبات هيل أسود (للطهي تحت الضغط)","3 ملاعق كبيرة سمن أو زيت محايد للماسالا","1 ملعقة صغيرة بذور كمون كاملة (جيرا)","2 بصلة صفراء متوسطة (~300 غ) مفرومة ناعماً جداً","6 فصوص ثوم + 4 سم زنجبيل طازج — مبشورة في عجينة مع 1 ملعقة كبيرة ماء","1 فلفل أخضر حار (أو حسب الذوق)، مفروم ناعماً","4 طماطم متوسطة ناضجة (~400 غ)، مهروسة في الخلاط إلى لب ناعم","1 ملعقة كبيرة معجون طماطم (للقوام)","1 ملعقة صغيرة كزبرة مطحونة (دانيا) + 1 ملعقة صغيرة كمون مطحون (جيرا) + 0,5 ملعقة صغيرة كركم (هالدي) + 1 ملعقة صغيرة فلفل كشميري مطحون + 1 ملعقة صغيرة ملح للماسالا","1 ملعقة صغيرة غارام ماسالا (تضاف في النهاية، لا تُغلى)","1 ملعقة صغيرة كاسوري ميثي (أوراق حلبة مجففة)، مهروسة في راحة اليد (تضاف في النهاية)","30 غ زبدة مكعبات (تشطيب على طريقة المطاعم)","1 ملعقة كبيرة قشدة سائلة أو 2 ملعقة كبيرة لبن زبادي كامل الدسم (اختياري، للقوام الكريمي)","أوراق كزبرة طازجة للتزيين + 1 ليمون أخضر مقطع شرائح؛ للتقديم: 360 غ (2 كوب) أرز بسمتي مطبوخ في 540 مل ماء مع 0,5 ملعقة صغيرة ملح، ونان أو جيرا رايس إذا فُضّل"],"en":["350 g dried red kidney beans (rajma) soaked 8–12 h in cold water (OR 2 × 400 g cans drained as a shortcut)","1.2 L cooking water for the beans + 1 tsp salt + 2 bay leaves + 4 black cardamom pods (for pressure-cooking the beans)","3 tbsp ghee or neutral oil for the masala","1 tsp whole cumin seeds (jeera)","2 medium yellow onions (~300 g) very finely diced","6 garlic cloves + 4 cm fresh ginger — grated into a paste with 1 tbsp water","1 green chili (or to taste), finely chopped","4 medium ripe tomatoes (~400 g), pureed in a blender to a smooth pulp","1 tbsp tomato paste (for body)","1 tsp ground coriander (dhania) + 1 tsp ground cumin (jeera) + 0.5 tsp turmeric (haldi) + 1 tsp Kashmiri red chili powder + 1 tsp salt for the masala","1 tsp garam masala (added at end, not boiled)","1 tsp kasuri methi (dried fenugreek leaves), crushed in palm (added at end)","30 g butter cubed (the restaurant-style finish)","1 tbsp single cream or 2 tbsp full-fat yogurt (optional, for creaminess)","Fresh coriander (cilantro) leaves to garnish + 1 lime in wedges; to serve: 360 g (2 cups) basmati rice cooked in 540 ml water with 0.5 tsp salt, and naan or jeera rice if preferred"],"ro":["350 g fasole roșie uscată (rajma) înmuiată 8–12 h în apă rece (SAU 2 × 400 g cutii de fasole roșie scursă ca scurtătură)","1,2 L apă de fierbere pentru fasole + 1 linguriță sare + 2 foi de dafin + 4 păstăi de cardamom negru (pentru fierberea sub presiune)","3 linguri ghee sau ulei neutru pentru masala","1 linguriță semințe întregi de chimion (jeera)","2 cepe galbene medii (~300 g) tocate foarte fin","6 căței de usturoi + 4 cm de ghimbir proaspăt — răzuite în pastă cu 1 lingură de apă","1 ardei iute verde (sau după gust), tocat fin","4 roșii medii coapte (~400 g), pasate la blender până la o pulpă fină","1 lingură pastă de roșii (pentru corp)","1 linguriță coriandru măcinat (dhania) + 1 linguriță chimion măcinat (jeera) + 0,5 linguriță turmeric (haldi) + 1 linguriță Kashmiri chili pudră + 1 linguriță sare pentru masala","1 linguriță garam masala (adăugat la final, nu fiert)","1 linguriță kasuri methi (frunze uscate de schinduf), zdrobite în palmă (adăugat la final)","30 g unt cubulețe (finisajul în stil restaurant)","1 lingură smântână dulce single sau 2 linguri iaurt gras (opțional, pentru cremozitate)","Frunze proaspete de coriandru (cilantro) pentru garnitură + 1 lămâie verde feliată; pentru servire: 360 g (2 căni) orez basmati fiert în 540 ml apă cu 0,5 linguriță sare, plus naan sau jeera rice dacă preferi"]},"howIsMade":{"ar":"انقع الفاصوليا: اشطف 350 غ راجما في ماء بارد 2–3 مرات; غطّها بماء بارد بـ 5 سم وانقعها 8–12 ساعة (أو طوال الليل); صفّها واشطفها; تخطّي النقع يعطي مراكز غير مطبوخة وقواماً منتجاً للغازات. اطبخ الفاصوليا تحت الضغط: ضع الراجما المنقوعة في طنجرة الضغط مع 1,2 لتر ماء + 1 ملعقة صغيرة ملح + 2 ورقة غار + 4 حبات هيل أسود; اطبخ تحت الضغط على نار عالية 4–5 صفارات، ثم خفّض النار وأطهِ 25 دقيقة; اترك الضغط ينفك طبيعياً; يجب أن تكون الفاصوليا طرية تماماً — اضغط واحدة بين الإبهام والسبابة؛ يجب أن تُهرس بضغط خفيف; (بديل: قدر مفتوح 1,5–2 ساعة من الغليان.) صفّها مع الاحتفاظ بـ 500 مل من ماء الطهي. بهوناو — التشطيب: في قدر كادهاي ثقيل أو مقلاة عميقة على نار متوسطة، أذب 3 ملاعق كبيرة سمن; عندما يلمع، أضف 1 ملعقة صغيرة بذور كمون — ستطقطق وتنفجر خلال 5 ثوانٍ; لا تتركها تسود. البصل: أضف 300 غ من البصل المقطع ناعماً جداً; اطبخ مع التحريك المتكرر 12–15 دقيقة حتى يصبح بنياً ذهبياً عميقاً — مكرملاً تقريباً; هذا البهوناو الطويل والبطيء للبصل هو ما يفصل راجما المطعم عن المحاولات الهاوية; لا تستعجل. الزنجبيل-الثوم-الفلفل: أضف عجينة الزنجبيل-الثوم والفلفل الأخضر; حرّك 1–2 دقيقة حتى تختفي الرائحة النيئة. قاعدة الطماطم: أضف لب الطماطم المهروس + 1 ملعقة كبيرة معجون طماطم + 1 ملعقة صغيرة كزبرة مطحونة + 1 ملعقة صغيرة كمون مطحون + 0,5 ملعقة صغيرة كركم + 1 ملعقة صغيرة فلفل كشميري + 1 ملعقة صغيرة ملح; اطبخ مع التحريك المتكرر 8–10 دقائق حتى ينفصل الزيت عن الماسالا على حواف المقلاة — هذه هي العلامة البصرية على اكتمال البهوناو ونضج الطماطم النيئة. اطهِ مع الفاصوليا: أضف الراجما المصفاة و500 مل من السائل المحتفظ به; حرّك بلطف; اجعلها تغلي على نار هادئة واطبخ مكشوفة 20–25 دقيقة، مع هرس بعض الفاصوليا جزئياً على جانب المقلاة بملعقة لتكثيف الصلصة; يجب أن تنخفض الصلصة وتغطي الفاصوليا — لا حساء ولا جافة، مثل حساء كثيف يبقى على ملعقة. التشطيب والتقديم: حرّك 1 ملعقة صغيرة غارام ماسالا + 1 ملعقة صغيرة كاسوري ميثي مهروسة + 30 غ زبدة مكعبات + 1 ملعقة كبيرة قشدة (اختياري); حرّك حتى تذوب الزبدة; غطّ ودع يستريح 5 دقائق بعيداً عن النار لتستقر النكهات; قدّمه ساخناً فوق أرز بسمتي مبخّر (أو جيرا رايس أو نان)، مع رش الكزبرة الطازجة المفرومة وعصرة من اللايم; أفضل في اليوم التالي.","en":"SOAK THE BEANS: rinse 350 g rajma in cold water 2–3 times; cover with cold water by 5 cm and soak 8–12 hours (or overnight); drain and rinse; skipping the soak gives undercooked centers and gassy texture. PRESSURE-COOK THE BEANS: place soaked rajma in a pressure cooker with 1.2 L water + 1 tsp salt + 2 bay leaves + 4 black cardamom pods; pressure-cook on high heat 4–5 whistles, then reduce to low and cook 25 minutes; let the pressure release naturally; beans should be completely tender — press one between thumb and forefinger; it should mash with light pressure; (Alternative: open pot 1.5–2 h simmer.) Drain reserving 500 ml bean cooking liquid. BHUNAO — TEMPER: in a heavy kadhai or deep pan over medium heat, melt 3 tbsp ghee; when shimmering, add 1 tsp cumin seeds — they will sizzle and pop within 5 seconds; do not let them blacken. ONIONS: add 300 g very finely diced onion; cook stirring often 12–15 minutes until deeply golden brown — almost caramelized; this long, slow onion bhunao is what separates restaurant rajma from amateur attempts; do not rush. GINGER-GARLIC-CHILI: add the ginger-garlic paste and green chili; stir 1–2 minutes until the raw smell disappears. TOMATO BASE: add the pureed tomato pulp + 1 tbsp tomato paste + 1 tsp ground coriander + 1 tsp ground cumin + 0.5 tsp turmeric + 1 tsp Kashmiri chili powder + 1 tsp salt; cook stirring frequently 8–10 minutes until the oil separates from the masala on the edges of the pan — this is the visual sign the bhunao is complete and the raw tomato has cooked off. SIMMER WITH BEANS: tip in the drained rajma and 500 ml of reserved bean liquid; stir gently; bring to a simmer and cook uncovered 20–25 minutes, partially mashing some beans against the side of the pan with a spoon to thicken the gravy; the gravy should reduce and coat the beans — neither soupy nor dry, like a thick stew that holds on a spoon. FINISH AND SERVE: stir in 1 tsp garam masala + 1 tsp crushed kasuri methi + 30 g butter cubed + 1 tbsp cream (optional); stir until butter melts; cover and let rest off heat 5 minutes for flavors to settle; serve hot over steamed basmati rice (or jeera rice or naan), topped with chopped fresh coriander and a squeeze of lime; better the next day."}},{"id":166,"servings":4,"tipType":"meat","pairingsType":"latin","origin":{"ar":"كوبا","en":"Cuba","ro":"Cuba"},"name":{"ar":"بيكاديلو","en":"Picadillo","ro":"Picadillo"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["600 غ لحم بقري مفروم (كتف، ~20% دهن)","2 ملعقة كبيرة زيت زيتون للسوفريتو","1 بصلة صفراء كبيرة (~200 غ)، مقطعة مكعبات صغيرة","1 فلفل أخضر حلو كبير (~200 غ)، مقطع مكعبات صغيرة","6 فصوص ثوم، مفرومة","1 ملعقة صغيرة كمون مطحون (كومينو) + 1 ملعقة صغيرة أوريغانو مجفف + 0,5 ملعقة صغيرة بابريكا حلوة مدخنة (بيمنتون) + 1 ورقة غار","400 غ طماطم مهروسة معلبة (أو 4 طماطم طازجة مقشرة ومبشورة) + 2 ملعقة كبيرة معجون طماطم","100 مل نبيذ أبيض جاف أو 50 مل شيري جاف (تقليدي كوبي — يحرق رائحة اللحم النيء)","100 غ زيتون أخضر منزوع النوى (مانزانيلا)، مقطع نصفين","60 غ زبيب ذهبي أو داكن، منقوع 10 دقائق في 100 مل ماء ساخن ثم مصفى","100 غ بازلاء خضراء مجمدة، مذابة","1 ملعقة كبيرة كبر، مصفى (اختياري، تقليدي)","1,5 ملعقة صغيرة ملح + 0,5 ملعقة صغيرة فلفل أسود مطحون طازج","بقدونس طازج عريض الورق للتزيين","للتقديم: 360 غ (2 كوب) أرز أبيض مطبوخ في 540 مل ماء مع 0,5 ملعقة صغيرة ملح + 240 غ فاصوليا سوداء مطبوخة + 2 موز بلاتانو ناضج مقطع شرائح ومقلي + شرائح لايم"],"en":["600 g ground beef (chuck, ~20% fat)","2 tbsp olive oil for the sofrito","1 large yellow onion (~200 g), finely diced","1 large green bell pepper (~200 g), finely diced","6 garlic cloves, minced","1 tsp ground cumin (comino) + 1 tsp dried oregano + 0.5 tsp sweet smoked paprika (pimentón) + 1 bay leaf","400 g can crushed tomatoes (or 4 fresh tomatoes peeled and grated) + 2 tbsp tomato paste","100 ml dry white wine OR 50 ml dry sherry (Cuban traditional — burns off raw-meat smell)","100 g pitted green olives (manzanilla), halved","60 g golden or dark raisins, soaked 10 min in 100 ml hot water then drained","100 g frozen green peas, thawed","1 tbsp capers, drained (optional, traditional)","1.5 tsp salt + 0.5 tsp freshly ground black pepper","Fresh flat-leaf parsley to garnish","To serve: 360 g (2 cups) white rice cooked in 540 ml water with 0.5 tsp salt + 240 g cooked black beans + 2 ripe plantains sliced and fried + lime wedges"],"ro":["600 g carne tocată de vită (gât/cap de piept, ~20% grăsime)","2 linguri ulei de măsline pentru sofrito","1 ceapă galbenă mare (~200 g), tăiată cubulețe fine","1 ardei gras verde mare (~200 g), tăiat cubulețe fine","6 căței de usturoi, tocați mărunt","1 linguriță chimion măcinat (comino) + 1 linguriță oregano uscat + 0,5 linguriță boia dulce afumată (pimentón) + 1 foaie de dafin","400 g roșii zdrobite la conservă (sau 4 roșii proaspete decojite și răzuite) + 2 linguri pastă de roșii","100 ml vin alb sec SAU 50 ml sherry sec (tradițional cubanez — arde mirosul de carne crudă)","100 g măsline verzi fără sâmburi (manzanilla), tăiate în jumătăți","60 g stafide aurii sau negre, înmuiate 10 minute în 100 ml apă caldă, apoi scurse","100 g mazăre verde congelată, dezghețată","1 lingură capere, scurse (opțional, tradițional)","1,5 linguriță sare + 0,5 linguriță piper negru proaspăt măcinat","Pătrunjel verde proaspăt cu frunza lată pentru garnitură","Pentru servire: 360 g (2 căni) orez alb fiert în 540 ml apă cu 0,5 linguriță sare + 240 g fasole neagră fiartă + 2 banane plantain coapte feliate și prăjite + felii de lămâie verde"]},"howIsMade":{"ar":"قاعدة السوفريتو: في قدر ثقيل 5 لتر، سخّن 2 ملعقة كبيرة زيت زيتون على نار متوسطة; أضف 200 غ بصل مكعبات + 200 غ فلفل أخضر مكعبات مع رشة ملح; اطبخ مع التحريك المتكرر 8–10 دقائق حتى يلين ويبدأ بالاصفرار — السوفريتو هو روح المطبخ الكوبي; أضف 6 فصوص ثوم مفرومة واطبخ دقيقة أخرى حتى يفوح العطر. أزهر التوابل: أضف 1 ملعقة صغيرة كمون، 1 ملعقة صغيرة أوريغانو، 0,5 ملعقة صغيرة بابريكا مدخنة و1 ورقة غار إلى قاعدة الزيت والخضار الساخنة; حرّك 30 ثانية حتى تطلق التوابل عطرها — لا تحرقها. حمّر اللحم: ارفع النار إلى متوسطة-عالية; أضف 600 غ لحم بقري مفروم في طبقة واحدة واتركه دون تحريك 2–3 دقائق لتشكيل قشرة; ثم فتته بملعقة خشبية وحمّره 6–8 دقائق أخرى حتى لا يبقى وردي وأي سائل صادر تبخر. التغطية: اسكب 100 مل نبيذ أبيض جاف (أو 50 مل شيري) واكشط أي قطع محمصة عالقة في قاع القدر; اغلِ 2–3 دقائق حتى تختفي رائحة الكحول. الطماطم + البناء: أضف علبة الطماطم المهروسة + 2 ملعقة كبيرة معجون طماطم; اطبخ 5 دقائق حتى يدكن الخليط ويبدأ الزيت بالظهور على السطح — الطماطم مطبوخة تماماً، بلا حموضة نيئة. أضف الزيتون والزبيب والتوابل: أضف 100 غ زيتون أخضر مقطع نصفين + 60 غ زبيب مصفى + 1 ملعقة كبيرة كبر (إذا استخدمتها) + 1,5 ملعقة صغيرة ملح + 0,5 ملعقة صغيرة فلفل; التباين الحلو-المالح هو توقيع كوبا الفريد. اطهِ على نار هادئة: خفّض النار إلى منخفضة، غطِّ جزئياً واطهِ 20–25 دقيقة، مع التحريك كل بضع دقائق; يجب أن يتكاثف الخليط إلى هاش بالصلصة — ليس جافاً ولا حساء، يتماسك على الملعقة; أضف 60 مل ماء إذا أصبح جافاً جداً. البازلاء والتقديم: في آخر 3 دقائق، أضف 100 غ بازلاء مذابة — فقط لتسخينها، مع الحفاظ على لونها الأخضر الزاهي; أزل ورقة الغار; بعيداً عن النار، رشّ البقدونس المفروم; قدّم فوق أرز أبيض مبخّر مع فاصوليا سوداء بجانبه، موز بلاتانو مقلي وشرائح لايم — طبق كوبا الكلاسيكي comida criolla.","en":"SOFRITO BASE: in a heavy 5 L pot, heat 2 tbsp olive oil over medium heat; add 200 g diced onion + 200 g diced green pepper with a pinch of salt; cook stirring often 8–10 minutes until soft and beginning to gold — the sofrito is the soul of Cuban cooking; add 6 minced garlic cloves and cook 1 minute more until fragrant. BLOOM THE SPICES: add 1 tsp cumin, 1 tsp oregano, 0.5 tsp smoked paprika and 1 bay leaf to the hot oil-and-vegetable base; stir 30 seconds until the spices release their aroma — do not burn. BROWN THE BEEF: raise heat to medium-high; add 600 g ground beef in a single layer and let it sit undisturbed 2–3 minutes to develop a crust; then break it up with a wooden spoon and brown another 6–8 minutes until no pink remains and any released liquid has evaporated. DEGLAZE: pour in 100 ml dry white wine (or 50 ml sherry) and scrape any browned bits stuck to the bottom of the pot; simmer 2–3 minutes until the alcohol smell disappears. TOMATO + BUILD: stir in the can of crushed tomatoes + 2 tbsp tomato paste; cook 5 minutes until the mixture darkens and oil starts to appear on the surface — tomato fully cooked, no raw acidity. ADD OLIVES, RAISINS & SEASON: stir in 100 g halved green olives + 60 g drained raisins + 1 tbsp capers (if using) + 1.5 tsp salt + 0.5 tsp pepper; the sweet-salty contrast is the unique Cuban signature. SIMMER: reduce heat to low, cover partially, and simmer 20–25 minutes, stirring every few minutes; the mixture should thicken into a saucy hash — neither dry nor soupy, holding together on a spoon; add 60 ml water if it gets too dry. PEAS & SERVE: in the last 3 minutes, stir in 100 g thawed peas — just to warm through, keeping them bright green; remove the bay leaf; off the heat, scatter chopped parsley; serve over steamed white rice with black beans on the side, fried plantains, and lime wedges — the classic Cuban comida criolla plate."}},{"id":167,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ar":"المغرب","en":"Morocco","ro":"Maroc"},"name":{"ar":"طاجين لحم الضأن","en":"Lamb Tagine","ro":"Tagine cu miel"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["1 كغ كتف خروف منزوع العظم، مقطع مكعبات 4 سم (مع بعض الدهن للغنى)","2 بصلة صفراء كبيرة (~400 غ)، واحدة مقطعة مكعبات صغيرة للقاعدة والأخرى مقطعة شرائح سميكة للطاجين","6 فصوص ثوم، مفرومة","4 سم زنجبيل طازج، مبشور","3 ملاعق كبيرة زيت زيتون (أو 2 ملعقة كبيرة زيت + 1 ملعقة كبيرة زبدة للغنى التقليدي)","1 ملعقة صغيرة كمون مطحون + 1 ملعقة صغيرة كزبرة مطحونة + 1 ملعقة صغيرة قرفة مطحونة + 0,5 ملعقة صغيرة كركم مطحون + 0,5 ملعقة صغيرة بابريكا حلوة + 0,5 ملعقة صغيرة زنجبيل مطحون + رشة خيوط زعفران (5–6 خيوط، منقوعة في 2 ملعقة كبيرة ماء ساخن)","1,5 ملعقة صغيرة رأس الحانوت (خلطة بهارات مغربية)","1,5 ملعقة صغيرة ملح + 0,5 ملعقة صغيرة فلفل أسود مطحون طازج","2 ملعقة كبيرة معجون طماطم","400 غ طماطم ناضجة (4 متوسطة)، مقشرة ومبشورة، أو 1 علبة × 400 غ","200 غ مشمش مجفف، مقطع نصفين (تركي أو كاليفورني — ليس حلواً جداً)","60 غ برقوق مجفف منزوع النوى أو زبيب (اختياري، للعمق)","600 مل ماء ساخن أو مرق دجاج قليل الملح","1 عود قرفة + 1 ورقة غار","80 غ لوز كامل مقشر (أو بقشره، محمص)","1 ملعقة كبيرة عسل (تضاف في النهاية لموازنة الحلاوة)","كزبرة طازجة + بقدونس عريض الورق + 1 ملعقة كبيرة سمسم محمص قليلاً للتزيين","للتقديم: 400 غ كسكس مطهي بالبخار مع 400 مل ماء + 1 ملعقة كبيرة زبدة + 0,5 ملعقة صغيرة ملح، أو خبز خبز مسطح دافئ"],"en":["1 kg boneless lamb shoulder, cut into 4 cm cubes (with some fat on for richness)","2 large yellow onions (~400 g), one finely diced for the base and one cut into thick wedges for the stew","6 garlic cloves, minced","4 cm fresh ginger, grated","3 tbsp olive oil (or 2 tbsp oil + 1 tbsp butter for traditional richness)","1 tsp ground cumin + 1 tsp ground coriander + 1 tsp ground cinnamon + 0.5 tsp ground turmeric + 0.5 tsp sweet paprika + 0.5 tsp ground ginger + a pinch of saffron threads (5–6 strands, bloomed in 2 tbsp hot water)","1.5 tsp ras el hanout (Moroccan spice blend)","1.5 tsp salt + 0.5 tsp freshly ground black pepper","2 tbsp tomato paste","400 g ripe tomatoes (4 medium), peeled and grated, or 1 × 400 g can","200 g dried apricots, halved (use Turkish or California — not too sweet)","60 g pitted dried prunes or raisins (optional, for depth)","600 ml hot water or low-salt chicken stock","1 cinnamon stick + 1 bay leaf","80 g whole blanched almonds (or skin-on, toasted)","1 tbsp honey (added at the end to balance sweetness)","Fresh coriander + flat-leaf parsley + 1 tbsp lightly toasted sesame seeds to garnish","To serve: 400 g couscous steamed with 400 ml water + 1 tbsp butter + 0.5 tsp salt, OR warm khobz flatbread"],"ro":["1 kg pulpă de miel dezosată (spată), tăiată cuburi de 4 cm (cu puțină grăsime pentru bogăție)","2 cepe galbene mari (~400 g), una tăiată cubulețe fine pentru bază și una tăiată în felii groase pentru tocăniță","6 căței de usturoi, tocați mărunt","4 cm ghimbir proaspăt, ras","3 linguri ulei de măsline (sau 2 linguri ulei + 1 lingură unt pentru bogăție tradițională)","1 linguriță chimion măcinat + 1 linguriță coriandru măcinat + 1 linguriță scorțișoară măcinată + 0,5 linguriță turmeric măcinat + 0,5 linguriță boia dulce + 0,5 linguriță ghimbir măcinat + un vârf de șofran (5–6 fire, înflorit în 2 linguri apă caldă)","1,5 linguriță ras el hanout (amestec marocan de condimente)","1,5 linguriță sare + 0,5 linguriță piper negru proaspăt măcinat","2 linguri pastă de roșii","400 g roșii coapte (4 medii), decojite și răzuite, sau 1 cutie × 400 g","200 g caise uscate, tăiate în jumătăți (turcești sau californiene — nu prea dulci)","60 g prune uscate fără sâmburi sau stafide (opțional, pentru profunzime)","600 ml apă fierbinte sau supă de pui cu puțină sare","1 baton de scorțișoară + 1 foaie de dafin","80 g migdale întregi blanșate (sau cu coajă, prăjite)","1 lingură miere (adăugată la final pentru a echilibra dulceața)","Coriandru proaspăt + pătrunjel cu frunza lată + 1 lingură semințe de susan ușor prăjite pentru garnitură","Pentru servire: 400 g couscous aburit cu 400 ml apă + 1 lingură unt + 0,5 linguriță sare, SAU pâine plată khobz caldă"]},"howIsMade":{"ar":"تتبيل لحم الضأن: في وعاء كبير امزج 1 كغ مكعبات ضأن مع 1 ملعقة صغيرة كمون + 1 ملعقة صغيرة كزبرة + 1 ملعقة صغيرة قرفة + 0,5 ملعقة صغيرة كركم + 0,5 ملعقة صغيرة بابريكا + 0,5 ملعقة صغيرة زنجبيل + 1,5 ملعقة صغيرة رأس الحانوت + 1,5 ملعقة صغيرة ملح + 0,5 ملعقة صغيرة فلفل + 3 من فصوص الثوم المفرومة و1 ملعقة كبيرة زيت زيتون; افرك التوابل في اللحم بيديك; غطِّ واترك 30 دقيقة في درجة حرارة الغرفة (أو حتى 24 ساعة في الثلاجة) ليتغلغل التوابل. تخمير الزعفران: ضع 5–6 خيوط زعفران في 2 ملعقة كبيرة ماء ساخن واتركها تنقع 10 دقائق — هذا يطلق النكهة واللون; ضع جانباً. بناء القاعدة: سخّن باقي 2 ملعقة كبيرة زيت (و1 ملعقة كبيرة زبدة إذا استخدمت) في طاجين ثقيل القاع أو قدر هولندي على نار متوسطة; أضف 200 غ بصل مقطع مكعبات صغيرة واطبخ مع التحريك المتكرر 8–10 دقائق حتى يلين ويصبح شفافاً; أضف باقي 3 فصوص ثوم مفرومة + الزنجبيل المبشور وحرّك دقيقة. تحمير الضأن: ارفع النار إلى متوسطة-عالية; ادفع البصل إلى جوانب القدر وأضف الضأن المتبل في طبقة واحدة (اعمل في دفعتين إذا لزم الأمر); حمّر 3–4 دقائق على كل جانب دون تحريك حتى يتحمر بعمق من جميع الجوانب — القشرة ضرورية لنكهة الطاجين الغنية; اخلط كل شيء معاً بمجرد تحمير الضأن. الطماطم + السائل: أضف 2 ملعقة كبيرة معجون طماطم واطبخ دقيقة حتى يدكن; أضف 400 غ طماطم مبشورة وماء الزعفران و1 عود قرفة و1 ورقة غار; اسكب 600 مل ماء ساخن (أو مرق) — يجب أن يصل السائل إلى منتصف اللحم تقريباً، لا يغطيه; اتركه يغلي برفق. الطهي البطيء: خفّض النار إلى منخفضة، غطِّ بغطاء الطاجين (أو غطاء محكم للقدر الهولندي) واطهِ 1,5–2 ساعة، مع الفحص كل 30 دقيقة والتحريك بلطف; الضأن جاهز عندما تدخل الشوكة بسهولة; أضف رشة ماء ساخن إذا تقلّص المرق بسرعة كبيرة. أضف المشمش + البصل: أضف 200 غ مشمش مجفف مقطع نصفين + 60 غ برقوق (إذا استخدمت) + 200 غ شرائح البصل; غطِّ واطهِ 25–30 دقيقة أخرى حتى ينتفخ الفاكهة وتلين شرائح البصل لكن تحتفظ بشكلها; يجب أن تكون الصلصة لامعة، تغطي ظهر الملعقة; أنهِ بـ 1 ملعقة كبيرة عسل، تذوّق، اضبط الملح. الإنهاء والتقديم: بينما يرتاح الطاجين بعيداً عن النار 5 دقائق، حمّص 80 غ لوز كامل في مقلاة جافة على نار متوسطة 3–4 دقائق حتى يصبح ذهبياً — راقب بحرص، يحترق بسرعة; اسكب طاجين الضأن فوق الكسكس الدافئ (أو قدّم مع الخبز)، رشّ اللوز المحمص والسمسم وكزبرة وبقدونس طازج; كل مع الخبز لجمع الصلصة.","en":"MARINATE THE LAMB: in a large bowl combine 1 kg lamb cubes with 1 tsp cumin + 1 tsp coriander + 1 tsp cinnamon + 0.5 tsp turmeric + 0.5 tsp paprika + 0.5 tsp ginger + 1.5 tsp ras el hanout + 1.5 tsp salt + 0.5 tsp pepper + 3 of the minced garlic cloves and 1 tbsp olive oil; rub the spices into the meat with your hands; cover and rest 30 minutes at room temperature (or up to 24 h in the fridge) so the spices penetrate. BLOOM SAFFRON: place 5–6 saffron threads in 2 tbsp hot water and let steep 10 minutes — this releases the flavour and colour; set aside. BUILD THE BASE: heat the remaining 2 tbsp oil (and 1 tbsp butter if using) in a heavy-bottomed tagine or Dutch oven over medium heat; add 200 g finely diced onion and cook stirring often 8–10 minutes until soft and translucent; add the remaining 3 minced garlic + grated ginger and stir 1 minute. SEAR THE LAMB: raise heat to medium-high; push the onions to the sides of the pot and add the marinated lamb in a single layer (work in 2 batches if needed); sear 3–4 minutes per side without moving until deeply browned on all sides — the crust is essential for the rich stew flavour; stir everything together once the lamb is browned. TOMATO + LIQUID: stir in 2 tbsp tomato paste and cook 1 minute until darkened; add the 400 g grated tomatoes, the saffron-water, 1 cinnamon stick and 1 bay leaf; pour in 600 ml hot water (or stock) — the liquid should come about halfway up the meat, not cover it; bring to a gentle simmer. SLOW COOK: reduce heat to low, cover with the tagine lid (or a tight Dutch-oven lid), and simmer 1.5–2 hours, checking every 30 minutes and stirring gently; the lamb is ready when a fork sinks in easily; add a splash of hot water if the sauce reduces too quickly. ADD APRICOTS + ONIONS: stir in 200 g halved dried apricots + 60 g prunes (if using) + the 200 g onion wedges; cover and simmer 25–30 minutes more until the fruit is plump and the onion wedges are tender but still holding shape; the sauce should be glossy, coating the back of a spoon; finish with 1 tbsp honey, taste, adjust salt. FINISH AND SERVE: while the tagine rests off the heat for 5 minutes, toast 80 g whole almonds in a dry pan over medium heat 3–4 minutes until golden — watch carefully, they burn fast; spoon the lamb tagine over warm couscous (or serve with khobz), top with toasted almonds, sesame seeds, and a scatter of fresh coriander and parsley; eat with bread to mop up the sauce."}},{"id":168,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ar":"المملكة المتحدة","en":"United Kingdom","ro":"Marea Britanie"},"name":{"ar":"فطيرة الراعي","en":"Shepherd's Pie","ro":"Plăcintă a ciobanului"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"ingredients":{"ar":["600 غ لحم ضأن مفروم (~15% دهن — أقل دهناً من اللحم البقري المفروم المعتاد ولكن مع ما يكفي من الدهن للرطوبة)","1 بصلة كبيرة (~200 غ)، مقطعة مكعبات صغيرة","2 جزرة متوسطة (~200 غ)، مقطعة مكعبات صغيرة 0,5 سم (مكعبات صغيرة — يجب أن تذوب في الحشوة)","4 فصوص ثوم، مفرومة","1 ملعقة كبيرة معجون طماطم","1 ملعقة كبيرة صلصة وورستيرشاير (العمق السري — لا يمكن التفاوض عليه)","1 ملعقة صغيرة زعتر مجفف (أو 2 غصن طازج)","1 ملعقة صغيرة إكليل الجبل المجفف، مفروم ناعماً","2 ملعقة كبيرة طحين عادي (لتثخين الصلصة)","300 مل مرق ضأن أو بقر ساخن (منزلي أو قليل الملح)","150 غ بازلاء مجمدة","1 ملعقة كبيرة زيت محايد","1 ملعقة صغيرة ملح + 0,5 ملعقة صغيرة فلفل أسود مطحون طازج للحشوة","لتغطية البطاطس المهروسة: 1 كغ بطاطس نشوية (Maris Piper أو King Edward أو Yukon Gold)، مقشرة ومقطعة قطع 4 سم","60 غ زبدة غير مملحة + 100 مل حليب كامل دافئ + 2 صفار بيض كبير (الصفار يعطي القشرة الذهبية المقرمشة الشهيرة) + 30 غ جبن شيدر ناضج مبشور (اختياري ولكن تقليدي)","0,5 ملعقة صغيرة فلفل أبيض + 0,5 ملعقة صغيرة ملح للبطاطس المهروسة"],"en":["600 g minced lamb (~15% fat — leaner than usual ground beef but with enough fat for moisture)","1 large onion (~200 g), finely diced","2 medium carrots (~200 g), finely diced 0.5 cm (small dice — they should disappear into the filling)","4 garlic cloves, minced","1 tbsp tomato paste","1 tbsp Worcestershire sauce (the secret depth — non-negotiable)","1 tsp dried thyme (or 2 sprigs fresh)","1 tsp dried rosemary, finely chopped","2 tbsp plain flour (to thicken the gravy)","300 ml hot lamb or beef stock (homemade or low-salt)","150 g frozen peas","1 tbsp neutral oil","1 tsp salt + 0.5 tsp freshly ground black pepper for the filling","For the mash topping: 1 kg floury potatoes (Maris Piper, King Edward, or Yukon Gold), peeled and cut into 4 cm chunks","60 g unsalted butter + 100 ml warm whole milk + 2 large egg yolks (the yolks give the iconic golden crisp top) + 30 g grated mature cheddar (optional but traditional)","0.5 tsp white pepper + 0.5 tsp salt for the mash"],"ro":["600 g carne tocată de miel (~15% grăsime — mai slabă decât vita tocată obișnuită, dar cu suficientă grăsime pentru umiditate)","1 ceapă mare (~200 g), tăiată cubulețe fine","2 morcovi medii (~200 g), tăiați cubulețe fine de 0,5 cm (cubulețe mici — trebuie să dispară în umplutură)","4 căței de usturoi, tocați","1 lingură pastă de roșii","1 lingură sos Worcestershire (profunzimea secretă — nenegociabil)","1 linguriță cimbru uscat (sau 2 crenguțe proaspete)","1 linguriță rozmarin uscat, tocat fin","2 linguri făină albă (pentru a îngroșa sosul)","300 ml supă fierbinte de miel sau vită (de casă sau cu sare redusă)","150 g mazăre congelată","1 lingură ulei neutru","1 linguriță sare + 0,5 linguriță piper negru proaspăt măcinat pentru umplutură","Pentru piureul de deasupra: 1 kg cartofi făinoși (Maris Piper, King Edward sau Yukon Gold), curățați și tăiați bucăți de 4 cm","60 g unt nesărat + 100 ml lapte integral cald + 2 gălbenușuri mari (gălbenușurile dau crusta aurie iconică) + 30 g cheddar maturat ras (opțional dar tradițional)","0,5 linguriță piper alb + 0,5 linguriță sare pentru piure"]},"howIsMade":{"ar":"اسلق البطاطس: ضع 1 كغ بطاطس مقشرة ومقطعة مكعبات في قدر كبير من الماء البارد المملح (1 ملعقة كبيرة ملح لكل 2 لتر); أحضره ليغلي، خفف الحرارة لغليان ثابت، واطبخ 15–18 دقيقة حتى ينزلق السكين دون مقاومة; صفِّ وأعد إلى القدر بعيداً عن النار لمدة دقيقتين لتبخير الرطوبة — البطاطس الرطبة تصنع هريساً رطباً; اصنع الهريس: مرر البطاطس الجافة عبر مهراس (الأفضل للهريس الناعم) أو اهرسها بمهراس يدوي. اخفق 60 غ زبدة وهي ساخنة، ثم 100 مل حليب دافئ على 3 دفعات، مع الخفق بين كل دفعة; بعيداً عن النار، اخفق 2 صفار، 0,5 ملعقة صغيرة فلفل أبيض، 0,5 ملعقة صغيرة ملح; يجب أن يكون الهريس لامعاً، ناعماً، وصلباً بما يكفي للاحتفاظ بالأخاديد — إذا كان رخواً جداً، ستغرق التغطية; غطِّ بالقصدير للحفاظ على الدفء. عرق الخضروات: سخّن 1 ملعقة كبيرة زيت في مقلاة كبيرة ثقيلة على نار متوسطة; أضف 200 غ بصل مكعبات + 200 غ جزر مكعبات مع رشة ملح; اطبخ مع التحريك المتكرر 8–10 دقائق حتى يصبح طرياً جداً ويفقد الجزر قرمشته — لن يلين أكثر بمجرد خلطه باللحم; أضف 4 فصوص ثوم مفرومة + زعتر + إكليل الجبل، اطبخ دقيقة إضافية. حمّر الضأن: ارفع الحرارة إلى متوسطة-عالية; أضف 600 غ ضأن مفروم وفتته بملعقة خشبية; اطبخ 8–10 دقائق حتى لا يصبح الضأن وردياً ويبدأ الدهن المفرز بإنشاء قطع صغيرة مقرمشة في قاع المقلاة — هذا التحمير من Maillard هو أساس الصلصة; ارفع بالملعقة أي دهن متجمع فوق 1 ملعقة كبيرة (يفرز الضأن الكثير — الكثير يجعل الفطيرة دهنية). ابنِ الصلصة: حرّك 1 ملعقة كبيرة معجون طماطم في الضأن واطبخ دقيقة حتى يدكن; رش 2 ملعقة كبيرة طحين فوقه وحرّك 1–2 دقيقة لطهي الطعم النيء; اسكب 300 مل مرق ساخن + 1 ملعقة كبيرة صلصة وورستيرشاير + 1 ملعقة صغيرة ملح + 0,5 ملعقة صغيرة فلفل، مع كشط قاع المقلاة لرفع القطع المحمرة; اغلِ ببطء + بازلاء: خفّض النار إلى منخفضة واغلِ مكشوفاً 15 دقيقة، مع التحريك من حين لآخر، حتى تثخن الصلصة إلى قوام سميك ولامع يغلف اللحم — يجب ألا يكون سائلاً، وإلا ستغرق البطاطس المهروسة. حرّك 150 غ بازلاء مجمدة (ستدفأ في الفرن); تذوّق واضبط التتبيل; ركّب: سخّن الفرن مسبقاً إلى 200 °م; انقل حشوة الضأن إلى طبق خبز 23 × 30 سم (سعة حوالي 2 لتر). ضع البطاطس المهروسة فوقها بكتل، ثم وزّعها بعناية بملعقة مع الإغلاق حتى الحواف; اسحب أسنان شوكة في خطوط طويلة على السطح — هذه الأخاديد تصبح مقرمشة بشكل جميل في الفرن; انثر 30 غ شيدر مبشور فوقها إذا كنت تستخدمها; اخبز واسترح: ضع الطبق على صينية خبز (تلتقط أي قطرات فقاعية). اخبز على الرف الأوسط 25–30 دقيقة حتى يصبح السطح ذهبياً عميقاً، تكون الأخاديد مقرمشة، والصلصة تفور بوضوح حول الحواف; ارح 10 دقائق قبل التقديم — تستقر الحشوة ويكون التقطيع أنظف; قدّم مباشرة من الطبق مع سلطة خضراء أو ملفوف بالزبدة على الجانب; أفضل في اليوم التالي، يُعاد تسخينه حتى يصبح ساخناً جداً.","en":"1. BOIL THE POTATOES: place 1 kg peeled and cubed potatoes in a large pot of cold salted water (1 tbsp salt per 2 L), bring to a boil, then reduce to a steady simmer and cook 15–18 minutes until a knife slides through with no resistance; drain and return to the pot off the heat for 2 minutes to steam off, since wet potatoes make wet mash. 2. MAKE THE MASH: pass the dry potatoes through a ricer (best for fluffy mash) or mash with a hand masher, then beat in 60 g butter while still hot followed by 100 ml warm milk added in 3 stages, beating between each, and off the heat beat in 2 yolks, 0.5 tsp white pepper and 0.5 tsp salt until the mash is glossy, smooth and stiff enough to hold ridges (if it's too loose the topping will sink); cover with foil to keep warm. 3. SWEAT THE VEGETABLES: heat 1 tbsp oil in a large heavy skillet over medium heat, add 200 g diced onion and 200 g diced carrot with a pinch of salt, and cook, stirring often, 8–10 minutes until very soft and the carrots have lost their crunch (they will not soften further once mixed with meat), then stir in 4 minced garlic cloves, thyme and rosemary and cook 1 minute more. 4. BROWN THE LAMB: raise the heat to medium-high, add 600 g minced lamb and break it apart with a wooden spoon, then cook 8–10 minutes until the lamb is no longer pink and the released fat has begun to crisp small bits at the bottom of the pan (this Maillard browning is the foundation of the gravy), and spoon off any pooled fat over 1 tbsp, since lamb sheds a lot and too much makes the pie greasy. 5. BUILD THE GRAVY: stir 1 tbsp tomato paste into the lamb and cook 1 minute until darkened, sprinkle 2 tbsp flour over and stir 1–2 minutes to cook the raw taste out, then pour in 300 ml hot stock, 1 tbsp Worcestershire sauce, 1 tsp salt and 0.5 tsp pepper, scraping the bottom of the pan to lift the browned bits. 6. SIMMER + PEAS: reduce heat to low and simmer uncovered 15 minutes, stirring occasionally, until the gravy has thickened to a thick, glossy consistency that coats the meat (it should not be runny, or the mash will sink), then stir in 150 g frozen peas (they will warm through in the oven) and taste and adjust seasoning. 7. ASSEMBLE: preheat the oven to 200 °C and transfer the lamb filling to a 23 × 30 cm baking dish (about 2 L capacity), spoon the mash on top in dollops and spread carefully with a spatula sealing all the way to the edges, then drag the tines of a fork in long lines across the surface (these ridges crisp up beautifully in the oven) and scatter 30 g grated cheddar over the top if using. 8. BAKE & REST: place the dish on a baking sheet to catch any bubbling drips and bake on the middle rack 25–30 minutes until the top is deeply golden, the ridges are crisp, and the gravy is visibly bubbling around the edges, then rest 10 minutes before serving so the filling sets and slicing is cleaner, and serve straight from the dish with a green salad or buttered cabbage on the side (even better the next day, reheated until piping hot)."}},{"id":169,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ar":"الصين","en":"China","ro":"China"},"name":{"ar":"مابو توفو","en":"Mapo Tofu","ro":"Mapo Tofu"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["600 غ توفو طري (حريري أو متوسط الطراوة)، مقطع مكعبات 2 سم — القوام جزء من الطبق، لا تستخدم التوفو الصلب","200 غ لحم خنزير مفروم (~20% دهن — الكمية الصغيرة تضيف الأومامي دون أن تهيمن)","3 ملاعق كبيرة زيت محايد (كانولا أو فول سوداني)","3 ملاعق كبيرة دوبانجيانج بيكسيان (معجون الفول والفلفل الحار السيتشواني) — روح الطبق، لا تتجاهلها أو تستبدلها","1 ملعقة كبيرة دوتشي (فاصوليا سوداء مخمرة)، مغسولة ومفرومة بشكل خشن","2 ملعقة صغيرة معجون فاصوليا-فلفل سيتشواني (la doubanjiang) أو 1 ملعقة صغيرة جوتشوجانج كوري كبديل","4 فصوص ثوم، مفرومة ناعماً","4 سم زنجبيل طازج، مقشر ومبشور","6 بصل أخضر: الأجزاء البيضاء مفرومة ناعماً للطهي + القمم الخضراء مقطعة قطرياً للتزيين (احفظها منفصلة)","1,5 ملعقة كبيرة صلصة صويا داكنة (laochou)","1 ملعقة صغيرة سكر حبيبي","300 مل مرق دجاج ساخن غير مملح أو ماء","2 ملعقة صغيرة فلفل سيتشوان (huajiao)، محمص في مقلاة جافة 60 ثانية ومسحوق في هاون","1,5 ملعقة كبيرة نشا الذرة (cornflour) ممزوج مع 3 ملاعق كبيرة ماء بارد للخلطة النهائية","2 ملعقة صغيرة زيت الفلفل الحار (la yu) للتقديم","1 ملعقة صغيرة زيت السمسم المحمص للرشة الأخيرة","للتقديم: 320 غ (1,6 كوب جاف) أرز ياسمين مطبوخ أو أرز قصير الحبة"],"en":["600 g soft (silken or medium-soft) tofu, cut into 2 cm cubes — the texture is part of the dish, do not use firm tofu","200 g ground pork (~20% fat — the small amount adds umami without dominating)","3 tbsp neutral oil (rapeseed or peanut)","3 tbsp Pixian doubanjiang (Sichuan broad-bean chili paste) — the SOUL of the dish, do not skip or substitute","1 tbsp douchi (fermented black beans), rinsed and roughly chopped","2 tsp Sichuan chili bean paste (la doubanjiang) OR 1 tsp Korean gochujang as substitute","4 garlic cloves, finely minced","4 cm fresh ginger, peeled and grated","6 spring onions: the white parts finely chopped for cooking + the green tops cut diagonally for garnish (keep separate)","1.5 tbsp dark soy sauce (laochou)","1 tsp granulated sugar","300 ml hot unsalted chicken stock or water","2 tsp Sichuan peppercorns (huajiao), toasted in a dry pan 60 sec and crushed in a mortar","1.5 tbsp cornstarch (cornflour) mixed with 3 tbsp cold water for the final slurry","2 tsp chili oil (la yu) for finishing","1 tsp toasted sesame oil for the last drizzle","To serve: 320 g (1.6 cups dry) cooked jasmine rice or short-grain rice"],"ro":["600 g tofu moale (mătăsos sau mediu-moale), tăiat în cuburi de 2 cm — textura face parte din preparat, nu folosi tofu ferm","200 g carne tocată de porc (~20% grăsime — cantitatea mică adaugă umami fără a domina)","3 linguri ulei neutru (rapiță sau arahide)","3 linguri doubanjiang Pixian (pastă de fasole-chili din Sichuan) — SUFLETUL preparatului, nu omite și nu substitui","1 lingură douchi (fasole neagră fermentată), clătită și tocată grosier","2 lingurițe pastă de fasole-chili Sichuan (la doubanjiang) SAU 1 linguriță gochujang coreean ca substitut","4 căței de usturoi, tocați fin","4 cm ghimbir proaspăt, curățat și ras","6 cepe verzi: părțile albe tocate fin pentru gătit + vârfurile verzi tăiate oblic pentru ornament (păstrează separat)","1,5 linguri sos de soia închis (laochou)","1 linguriță zahăr granulat","300 ml supă fierbinte de pui nesărată sau apă","2 lingurițe boabe de piper sichuan (huajiao), prăjite într-o tigaie uscată 60 sec și zdrobite în mojar","1,5 linguri amidon de porumb (cornflour) amestecat cu 3 linguri apă rece pentru slurry-ul final","2 lingurițe ulei de chili (la yu) pentru finisare","1 linguriță ulei de susan prăjit pentru ultima stropire","Pentru servire: 320 g (1,6 căni uscat) orez jasmine fiert sau orez cu bob scurt"]},"howIsMade":{"ar":"حضّر التوفو: أحضر قدراً صغيراً من الماء مع 1 ملعقة صغيرة ملح إلى غليان خفيف (ليس فوران); أنزل مكعبات التوفو 2 سم بحذر ودعها تدفأ دقيقتين — هذا يُقوّي السطح حتى تحافظ على شكلها في الصلصة; صفِّ بلطف وضع جانباً في القدر الدافئ بعيداً عن النار. حمّص فلفل سيتشوان: في مقلاة جافة على نار متوسطة، حمّص 2 ملعقة صغيرة فلفل سيتشوان 60 ثانية حتى تصبح عطرة بشدة; اقلبها في هاون واسحقها خشناً; ضع جانباً. حمّر لحم الخنزير: سخّن 2 ملعقة كبيرة زيت محايد في ووك أو مقلاة ثقيلة على نار متوسطة-عالية; أضف 200 غ لحم خنزير مفروم وفتته بملعقة; اقلِ مع التحريك 4–5 دقائق حتى لا يصبح اللحم وردياً والقطع الصغيرة مقرمشة وذهبية اللون — فرق القوام بين اللحم المقرمش والتوفو الطري أساسي. أزهر الدوبانجيانج: ادفع اللحم إلى جانب المقلاة وأضف 1 ملعقة كبيرة زيت إضافية في المساحة الفارغة; أضف 3 ملاعق كبيرة دوبانجيانج إلى الزيت وحرّك 60–90 ثانية حتى يصبح الزيت أحمر عميقاً — هذا القلي بالزيت يطلق اللون والأومامي من المعجون; حرّك مع اللحم; أضف الدوتشي المفروم + الثوم المفروم + الزنجبيل المبشور + 2 ملعقة صغيرة la doubanjiang (أو الجوتشوجانج) واقلِ مع التحريك 60 ثانية حتى يصبح عطراً بشدة. سائل: اسكب 300 مل مرق ساخن + 1,5 ملعقة كبيرة صلصة صويا داكنة + 1 ملعقة صغيرة سكر; أحضره إلى غليان خفيف. أضف التوفو: ادفع مكعبات التوفو الدافئة بلطف إلى الصلصة المغلية; لا تحرّك — استخدم ظهر مغرفة لدفعها تحت، ثم رجّ المقلاة بلطف لتستقر; اطبخ على نار خفيفة 4–5 دقائق، مع رشّ أعلى التوفو بالصلصة من حين لآخر، لتمتص المكعبات النكهة دون أن تتكسر. كثّف: حرّك خليط النشا مرة أخرى واسكب النصف في الصلصة، ثم رجّ المقلاة ودعها تغلي 30 ثانية; ستصبح الصلصة لامعة وستبدأ في تغطية التوفو; إذا كانت لا تزال خفيفة، أضف بقية الخليط; الصلصة النهائية يجب أن تلتصق بخفة بالتوفو، وليس أن تكون كالحساء. اختم وقدّم: بعيداً عن النار، رشّ 2 ملعقة صغيرة زيت فلفل حار + 1 ملعقة صغيرة زيت سمسم محمص فوق السطح وانثر قمم البصل الأخضر + فلفل سيتشوان المسحوق; لا تحرّك — يجب أن يصل الفلفل إلى لسانك غير مخفف للحصول على إحساس ما (الخدر); قدّم فوراً مع أرز ياسمين ساخن; كل قضمة: أرز + توفو + صلصة + فلفل = تجربة ما-لا الكاملة.","en":"PREP THE TOFU: bring a small pot of water with 1 tsp salt to a gentle simmer (not boil); slip the 2 cm tofu cubes in carefully and let them warm 2 minutes — this firms the surface so they hold their shape in the sauce; drain gently and set aside in the warm pot off the heat. TOAST SICHUAN PEPPERCORNS: in a dry pan over medium heat, toast 2 tsp Sichuan peppercorns 60 seconds until intensely fragrant; tip into a mortar and crush coarsely; set aside. RENDER THE PORK: heat 2 tbsp neutral oil in a wok or heavy skillet over medium-high heat; add 200 g ground pork and break it apart with a spatula; stir-fry 4–5 minutes until the pork is no longer pink and the small bits are crispy and golden brown — the texture difference between crisp pork and soft tofu is essential. BLOOM THE DOUBANJIANG: push the pork to the side of the pan and add 1 tbsp more oil to the empty space; add 3 tbsp doubanjiang to the oil and stir 60–90 seconds until the oil turns deep red — this oil-frying releases the colour and umami of the paste; stir into the pork; add chopped douchi + minced garlic + grated ginger + 2 tsp la doubanjiang (or gochujang) and stir-fry 60 seconds until intensely aromatic. LIQUID: pour in 300 ml hot stock + 1.5 tbsp dark soy sauce + 1 tsp sugar; bring to a simmer. ADD THE TOFU: slide the warm tofu cubes gently into the simmering sauce; do NOT stir — use the back of a ladle to push them under, then shake the pan gently to settle; simmer 4–5 minutes, basting the tops of the tofu with sauce occasionally, so the cubes absorb flavour without breaking. THICKEN: stir the cornstarch slurry one more time and pour HALF into the sauce, then shake the pan and let it simmer 30 seconds; the sauce will turn glossy and start to coat the tofu; if still thin, add the rest of the slurry; the finished sauce should cling lightly to the tofu, not be soupy. FINISH AND SERVE: off the heat, drizzle 2 tsp chili oil + 1 tsp toasted sesame oil over the surface and scatter the green spring-onion tops + crushed Sichuan peppercorns; do NOT stir — the peppercorns must hit your tongue undiluted for the ma (numbing) sensation; serve immediately with hot jasmine rice; each bite: rice + tofu + sauce + peppercorn = the full ma-la experience."}},{"id":170,"servings":2,"tipType":"veg","pairingsType":"veg","origin":{"ar":"تركيا","en":"Turkey","ro":"Turcia"},"name":{"ar":"مينمن","en":"Menemen","ro":"Menemen"},"category":{"ar":"فطور","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"ar":["6 بيضات كبيرة، بدرجة حرارة الغرفة","3 ملاعق كبيرة زيت زيتون تركي أو بكر ممتاز","2 سيفري بيبر (فلفل أخضر طويل تركي، حار قليلاً) أو 1 فلفل أخضر رومي + 1 جالابينيو كبديل (~150 غ في المجموع)، منزوع البذور ومقطع ناعماً","4 طماطم ناضجة (~500 غ)، مقشرة ومبشورة خشناً على مبشرة الصندوق (القشرة تبقى، فقط اللب يمر عبر المبشرة — هذه هي التقنية التركية)","1 ملعقة كبيرة معجون طماطم (salça) — اختياري، يعمق اللون الأحمر","1 ملعقة صغيرة بول بيبر (رقائق فلفل أحمر تركي، نمط حلب أو مرعش) — يضيف دفئاً دون حرارة قاسية","0,5 ملعقة صغيرة أوريغانو مجفف","0,5 ملعقة صغيرة ملح + فلفل أسود مطحون طازج","30 غ بياز بينير على طريقة الفيتا، مفتت (اختياري، إضافة إقليمية إيجية)","حفنة صغيرة من البقدونس ذو الورق العريض، مفروم ناعماً، للتزيين","حزمة صغيرة من الثوم المعمر أو الجزء الأخضر من البصل الأخضر، مفروم ناعماً (اختياري)","للتقديم: 4 شرائح سميكة من الإكمك الطازج (خبز ريفي) أو 2 سيميت (كعك تركي بالسمسم)، شاي أسود تركي (çay) مخمر قوياً","ملاحظة حول الجدل الإقليمي: هذه النسخة بدون بصل (نمط إسطنبول)؛ إذا كنت تصنع النسخة الإيجية، أضف 1 بصلة صغيرة مفرومة ناعماً واطبخها 4 دقائق قبل الفلفل"],"en":["6 large eggs, at room temperature","3 tbsp Turkish or extra-virgin olive oil","2 sivri biber (long green Turkish peppers, mildly hot) OR 1 green bell pepper + 1 jalapeño as substitute (~150 g total), seeds removed and finely diced","4 ripe tomatoes (~500 g), peeled and roughly grated on a box grater (the skin holds back, only the pulp grates through — this is the Turkish technique)","1 tbsp tomato paste (salça) — optional, deepens the red","1 tsp pul biber (Turkish red pepper flakes, Aleppo or Maraş-style) — adds warmth without harsh heat","0.5 tsp dried oregano","0.5 tsp salt + freshly ground black pepper","30 g feta-style beyaz peynir, crumbled (optional, regional Aegean addition)","1 small handful flat-leaf parsley, finely chopped, to finish","1 small bunch chives or spring onion green, finely chopped (optional)","To serve: 4 thick slices of fresh ekmek country bread OR 2 simit (Turkish sesame bagels), Turkish black tea (çay) brewed strong","Note on regional debate: this version is WITHOUT onion (Istanbul-style); if making the Aegean-style, add 1 small onion finely diced and cook 4 min before the peppers"],"ro":["6 ouă mari, la temperatura camerei","3 linguri ulei de măsline turcesc sau extravirgin","2 sivri biber (ardei lungi verzi turcești, ușor iuți) SAU 1 ardei gras verde + 1 jalapeño ca substitut (~150 g total), fără semințe și tocați fin","4 roșii coapte (~500 g), opărite și răzuite grosier pe răzătoarea cu găuri mari (coaja rămâne în mână, doar pulpa trece prin răzătoare — aceasta este tehnica turcească)","1 lingură pastă de roșii (salça) — opțional, adâncește roșul","1 linguriță pul biber (fulgi de ardei roșu turcesc, stil Aleppo sau Maraș) — adaugă căldură fără iuțeală agresivă","0,5 linguriță oregano uscat","0,5 linguriță sare + piper negru proaspăt măcinat","30 g beyaz peynir tip feta, fărâmițat (opțional, adaos regional egeean)","1 mână mică de pătrunjel cu frunza lată, tocat fin, pentru finisare","1 legătură mică de arpagic sau partea verde a cepei verzi, tocată fin (opțional)","Pentru servire: 4 felii groase de ekmek proaspăt (pâine de țară) SAU 2 simit (covrigi turcești cu susan), ceai negru turcesc (çay) preparat tare","Notă despre dezbaterea regională: această versiune este FĂRĂ ceapă (stil Istanbul); dacă faci versiunea egeeană, adaugă 1 ceapă mică tocată fin și gătește 4 minute înainte de ardei"]},"howIsMade":{"ar":"اقشر وابشر الطماطم: قم بشق سطحي على شكل صليب في قاع كل من الطماطم الأربع الناضجة; أنزلها في الماء المغلي 30 ثانية، ثم انقلها إلى ماء مثلج; تتقشر الجلود بسهولة; اقطع كل طماطمة إلى نصفين أفقياً وافرك الجانبين المقطوعين على الجانب الخشن من مبشرة الصندوق الموضوعة فوق وعاء — يمر اللب عبر المبشرة وتبقى القشرة الفارغة في يدك; هذه التقنية التركية تعطي قاعدة طماطم لبية وعصيرية بدون قطع قشر. اطبخ الفلفل: سخّن 3 ملاعق كبيرة زيت زيتون في مقلاة ثقيلة 24 سم (الحديد الزهر أو السحان الفخاري تقليدي) على نار متوسطة; أضف 150 غ فلفل أخضر مقطع ناعماً واطبخ مع التقليب المتكرر 5–6 دقائق حتى يلين ويتفقع قليلاً على الحواف لكن لا يزال أخضر زاهياً — لا تتركه يتحمر. أضف معجون الطماطم: قلّب 1 ملعقة كبيرة معجون طماطم مع الفلفل واطبخ 30 ثانية — تعمق الصلصا اللون والأومامي; (تخطَّ هذه الخطوة إذا لم تستخدم معجوناً.). أضف الطماطم المبشورة: اسكب لب الطماطم المبشور + 1 ملعقة صغيرة بول بيبر + 0,5 ملعقة صغيرة أوريغانو + 0,5 ملعقة صغيرة ملح ولفة سخية من الفلفل الأسود; أحضر إلى غليان خفيف واطبخ 6–8 دقائق، مع التحريك من حين لآخر، حتى تتقلص الطماطم إلى النصف وتبدو مثل المربى — يجب أن يسحب أسفل الملعقة خطاً واضحاً عبر الصلصة لا يمتلئ فوراً. حضّر البيض: بينما تطبخ الطماطم، اكسر 6 بيضات في وعاء واحدة تلو الأخرى — لا تخفقها; يدخل البيض إلى المقلاة كاملاً أو مكسوراً بالكاد، مع الصفار سليم في البداية. أضف البيض: عندما تصبح الطماطم مثل المربى، اخفض النار إلى متوسطة-منخفضة; أنزل البيض بلطف في المقلاة، متباعداً حول السطح; اتركه يجلس 30 ثانية دون لمس ليتماسك في الأسفل. اخلط بلطف: بملعقة خشبية، ادفع البيض بلطف عبر الطماطم بحركات بطيئة على شكل ثمانية — لا تحرك بقوة; يجب أن يتماسك البياض في أشرطة ويجب أن ينكسر الصفار ويمتد عبر الصلصة في دوامات ذهبية; اطبخ 90 ثانية–دقيقتين فقط — يجب أن يبقى المنمن لامعاً ومتماسكاً بالكاد، وليس جافاً كالبيض المخفوق; ارفعه عن النار وهو لا يزال رطباً قليلاً — يستمر في الطهي في المقلاة الساخنة. قدّم من المقلاة: انثر 30 غ فيتا مفتت + بقدونس مفروم (وثوم معمر إذا استخدمت); أحضر المقلاة مباشرة إلى الطاولة — يؤكل المنمن دائماً من المقلاة مع الخبز الممزق المغموس في الصلصة; قدّم مع شاي تركي أسود قوي; أفضل أكله خلال 5 دقائق من الطهي، بينما يكون دافئاً ولامعاً.","en":"PEEL AND GRATE THE TOMATOES: cut a shallow cross in the bottom of each of 4 ripe tomatoes; drop into boiling water 30 seconds, then transfer to ice water; the skins peel off easily; halve each tomato horizontally and rub the cut sides against the coarse side of a box grater placed over a bowl — the flesh grates through and the empty skin remains in your hand; this Turkish technique gives a pulpy, juicy tomato base with no skin pieces. COOK THE PEPPERS: heat 3 tbsp olive oil in a heavy 24 cm skillet (cast iron or earthenware sahan is traditional) over medium heat; add 150 g finely diced green peppers and cook stirring often 5–6 minutes until softened and slightly blistered at the edges but still bright green — do not let them brown. ADD TOMATO PASTE: stir 1 tbsp tomato paste into the peppers and cook 30 seconds — the salça deepens the colour and umami; (Skip this step if not using paste.). ADD GRATED TOMATOES: pour in the grated tomato pulp + 1 tsp pul biber + 0.5 tsp oregano + 0.5 tsp salt and a generous twist of black pepper; bring to a simmer and cook 6–8 minutes, stirring occasionally, until the tomato has reduced by half and looks jammy — the bottom of the spatula should drag a clear line through the sauce that does not fill in immediately. PREP THE EGGS: while the tomatoes cook, crack 6 eggs into a bowl one at a time — DO NOT beat them; the eggs go into the pan whole or barely broken, with yolks intact at first. ADD THE EGGS: when the tomato is jammy, lower the heat to medium-low; slip the eggs gently into the pan, spaced around the surface; let them sit 30 seconds undisturbed to set on the bottom. SCRAMBLE LIGHTLY: with a wooden spoon, push the eggs gently through the tomato in slow figure-eight motions — DO NOT vigorously stir; the whites should set into ribbons and the yolks should break and streak through the sauce in golden swirls; cook 90 seconds–2 minutes only — the menemen should remain glossy and barely-set, NOT scrambled-egg-dry; take off the heat while still slightly wet — it continues cooking in the hot pan. SERVE FROM THE PAN: scatter 30 g crumbled feta + chopped parsley (and chives if using); bring the pan straight to the table — menemen is always eaten from the pan with bread torn and dipped into the sauce; serve with strong Turkish black tea; best eaten within 5 minutes of cooking, while warm and glossy."}},{"id":171,"servings":4,"tipType":"meat","pairingsType":"soup","origin":{"ar":"روسيا","en":"Russia","ro":"Rusia"},"name":{"ar":"سوليانكا","en":"Solyanka","ro":"Solyanka"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"ingredients":{"ar":["500 غ صدر بقري أو ساق بالعظم (للمرق)","2 ل ماء بارد للمرق + 1 بصلة + 1 جزرة + 2 ورقة غار + 5 حبات فلفل أسود + 1 ملعقة صغيرة ملح للمرق","200 غ كيلباسا مدخنة أو كراكوفسكايا، مقطعة شرائح بسماكة 5 ملم","150 غ لحم خنزير مطبوخ، مقطع مكعبات بحجم 1 سم (أو لسان مسلوق، تقليدياً)","100 غ سلامي أو نقانق صيد، مقطع شرائح رفيعة","2 خيارات مخللة كبيرة (~250 غ، نصف حامضة أو حامضة كاملة)، مقطعة عيدان رفيعة؛ احتفظ بـ 100 مل من ماء التخليل","1 بصلة كبيرة (~200 غ)، مفرومة ناعماً","1 ملعقة كبيرة معجون طماطم","200 غ طماطم مبشورة (أو 1 علبة 200 غ، مصفاة)","2 ملعقة كبيرة زبدة أو 30 غ شحم بقري مذاب للسوفريتو","80 غ زيتون أسود منزوع النوى (نمط كالاماتا) + 80 غ زيتون أخضر منزوع النوى","2 ملعقة كبيرة كبر، مصفى","1 ليمونة، مقطعة شرائح رفيعة على شكل أنصاف أهلة","1 ورقة غار + 0,5 ملعقة صغيرة فلفل أسود مطحون + 1 ملعقة صغيرة بابريكا (اختياري، للون)","حزمة صغيرة من الشبت الطازج، مفروم ناعماً","200 غ سميتانا (قشدة حامضة) للتقديم","للتقديم: 4 شرائح سميكة من خبز الجاودار الداكن الطازج، اختياري 1 ملعقة كبيرة فجل حار (khren)"],"en":["500 g beef brisket or shin on the bone (for the broth)","2 L cold water for the broth + 1 onion + 1 carrot + 2 bay leaves + 5 black peppercorns + 1 tsp salt for the stock","200 g smoked kielbasa or krakovskaya, sliced 5 mm thick","150 g cooked ham, cut into 1 cm cubes (or boiled tongue, traditional)","100 g salami or hunting sausage, sliced thin","2 large pickled cucumbers (~250 g, half-sour or fully sour), cut into thin matchsticks; reserve 100 ml of the pickle brine","1 large onion (~200 g), finely diced","1 tbsp tomato paste","200 g grated tomatoes (or 1 × 200 g canned, drained)","2 tbsp butter or 30 g rendered beef fat for the soffritto","80 g pitted black olives (kalamata-style) + 80 g pitted green olives","2 tbsp capers, drained","1 lemon, sliced into thin half-moons","1 bay leaf + 0.5 tsp ground black pepper + 1 tsp paprika (optional, for color)","A small bunch fresh dill, finely chopped","200 g smetana (sour cream) for serving","To serve: 4 thick slices of fresh dark rye bread, optional 1 tbsp horseradish (khren)"],"ro":["500 g piept de vită sau rasol cu os (pentru supă)","2 L apă rece pentru supă + 1 ceapă + 1 morcov + 2 foi de dafin + 5 boabe de piper negru + 1 linguriță sare pentru bulion","200 g kielbasa afumată sau cracovskaya, tăiată felii de 5 mm","150 g șuncă fiartă, tăiată cuburi de 1 cm (sau limbă fiartă, tradițional)","100 g salam sau cârnați de vânătoare, tăiat felii subțiri","2 castraveți murați mari (~250 g, semi-acri sau acri complet), tăiați fâșii subțiri; păstrează 100 ml din zeama de murături","1 ceapă mare (~200 g), tocată fin","1 lingură pastă de roșii","200 g roșii răzuite (sau 1 × 200 g din conservă, scurse)","2 linguri unt sau 30 g grăsime de vită topită pentru sotă","80 g măsline negre fără sâmburi (gen kalamata) + 80 g măsline verzi fără sâmburi","2 linguri capere, scurse","1 lămâie, tăiată felii subțiri în formă de semilună","1 foaie de dafin + 0,5 linguriță piper negru măcinat + 1 linguriță boia (opțional, pentru culoare)","O legăturică mică de mărar proaspăt, tocat fin","200 g smetana (smântână) pentru servire","Pentru servire: 4 felii groase de pâine de secară neagră proaspătă, opțional 1 lingură hrean (khren)"]},"howIsMade":{"ar":"المرق: ضع 500 غ من صدر البقر في قدر كبير مع 2 ل ماء بارد; أحضر إلى الغليان وأزل الرغوة جيداً خلال أول 5 دقائق — هذا يعطي مرقاً صافياً; أضف 1 بصلة كاملة مقطعة إلى أرباع + 1 جزرة كاملة + 2 ورقة غار + 5 حبات فلفل + 1 ملعقة صغيرة ملح; اخفض إلى غليان هادئ واطبخ مغطى 1.5 ساعة حتى تصبح اللحم طرية تماماً. صفِّ واسحب: ارفع اللحم البقري ودعه يبرد قليلاً; صفِّ المرق من خلال مصفاة ناعمة إلى قدر نظيف — يجب أن يكون لديك حوالي 1.5 ل من المرق الصافي اللذيذ; اقطع اللحم عبر الألياف إلى شرائح بحجم اللقمة، تخلص من أي أوتار صلبة. السوفريتو: في مقلاة واسعة، أذب 2 ملعقة كبيرة زبدة على نار متوسطة; أضف 200 غ بصل مفروم ناعماً وحمّر 6–8 دقائق حتى يصبح طرياً وشفافاً; قلّب 1 ملعقة كبيرة معجون طماطم واطبخ دقيقة حتى يصبح داكناً; أضف 200 غ من الطماطم المبشورة واطبخ 4–5 دقائق حتى تتقلص الخلطة ويبدأ الزيت في الظهور على السطح. أضف المخللات: قلّب أصابع الخيار المخلل في السوفريتو واطبخ 3–4 دقائق; يجب أن تكون المخللات دافئة، وليست متفسخة جداً — يجب أن تحتفظ ببعض الهشاشة لتباين الملمس. اقلي النقانق: في مقلاة جافة منفصلة على نار متوسطة، اقلي شرائح الكيلباسا المدخنة، مكعبات لحم الخنزير، وشرائح السلامي 4–5 دقائق حتى تتحمر قليلاً على الحواف وتذوب الدهون; هذه الخطوة غير قابلة للتفاوض — تحمير اللحوم قبل إضافتها إلى المرق هو ما يعطي السوليانكا طابعها العميق المدخن. اجمع الحساء: اسكب السوفريتو في المرق المصفى وقلّب النقانق المحمرة، لحم الخنزير، السلامي، واللحم البقري المسحوب; أضف 100 مل من ماء المخلل المحفوظ + 1 ورقة غار + 0.5 ملعقة صغيرة فلفل مطحون + 1 ملعقة صغيرة بابريكا; أحضر إلى غليان هادئ. اطبخ على نار هادئة: اطبخ على نار منخفضة 15–20 دقيقة، مغطى جزئياً، لتمتزج النكهات; أضف الزيتون + الكبر في آخر 5 دقائق فقط — يجب أن يدفأ لكن يحتفظ بشكله; تذوق وعدّل الملح — معظم الملوحة تأتي من المخللات والكبر والزيتون وماء المخلل، لذا تصرف بحذر. قدّم: غرف السوليانكا الساخنة في أوعية عميقة; أضف إلى كل وعاء 1 شريحة ليمون رفيعة (كاملة، مع القشرة)، ملعقة كبيرة سخية من السميتانا، ورشة من الشبت المفروم; فلفل أسود حسب الذوق; قدّم على الفور مع شرائح سميكة من خبز الجاودار الداكن الطازج بجانبه — السوليانكا طبق رئيسي وليس حساء افتتاح; في التقليد الروسي، هذا هو الترميم الكلاسيكي بعد الاحتفال.","en":"THE BROTH: place 500 g beef brisket in a large pot with 2 L cold water; bring to a boil and skim the foam thoroughly for the first 5 minutes — this gives a clear broth; add 1 whole quartered onion + 1 whole carrot + 2 bay leaves + 5 peppercorns + 1 tsp salt; reduce to a gentle simmer and cook covered 1.5 hours until the meat is fully tender. STRAIN AND SHRED: lift the beef out and let it cool slightly; strain the broth through a fine sieve back into a clean pot — you should have about 1.5 L of clear, savoury broth; cut the beef across the grain into bite-sized strips, discarding any tough sinew. SOFFRITTO: in a wide skillet, melt 2 tbsp butter over medium heat; add 200 g finely diced onion and sauté 6–8 minutes until soft and translucent; stir in 1 tbsp tomato paste and cook 1 minute until darkened; add the 200 g grated tomatoes and cook 4–5 minutes until the mixture has reduced and the oil starts to appear on the surface. ADD PICKLES: stir the cucumber matchsticks into the soffritto and cook 3–4 minutes; the pickles should be warmed through, not over-softened — they need to keep some crunch for texture contrast. FRY THE SAUSAGES: in a separate dry pan over medium heat, fry the smoked kielbasa slices, ham cubes, and salami slices 4–5 minutes until lightly browned at the edges and the fat has rendered; this step is non-negotiable — searing the meats before adding them to the broth is what gives solyanka its deep, smoky character. ASSEMBLE THE SOUP: pour the soffritto into the strained broth and stir in the seared sausages, ham, salami, and shredded beef; add the reserved 100 ml pickle brine + 1 bay leaf + 0.5 tsp ground pepper + 1 tsp paprika; bring to a gentle simmer. SIMMER: cook over low heat 15–20 minutes, partially covered, for the flavours to marry; add the olives + capers in the last 5 minutes only — they should warm through but keep their shape; taste and adjust salt — most of the saltiness comes from the pickles, capers, olives, and brine, so go cautiously. SERVE: ladle the hot solyanka into deep bowls; to each bowl add 1 thin lemon slice (whole, peel on), a generous spoonful of smetana, and a scatter of chopped dill; black pepper to taste; serve immediately with thick slices of fresh dark rye bread on the side — solyanka is a main course, not a starter; in Russian tradition, this is the classic post-celebration restorative."}},{"id":172,"servings":4,"tipType":"fish","pairingsType":"fish","origin":{"ar":"الولايات المتحدة","en":"USA","ro":"SUA"},"name":{"ar":"شوربة البطلينوس","en":"Clam Chowder","ro":"Clam Chowder"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["1.5 كغ من المحار الطازج littleneck أو quahog في الصدف (أو 2 × 200 غ علب من المحار الصغير الكامل في عصارته كبديل للطهاة البعيدين عن البحر)","500 مل عصير محار طازج أو مرق سمك (احتفظ بكل سائل البخار إذا كنت تستخدم محاراً طازجاً)","150 غ من اللحم المقدد المدخن السميك، مقطع مكعبات 0.5 سم","1 بصلة صفراء كبيرة (~250 غ)، مفرومة ناعماً","2 ساق كرفس متوسط (~120 غ)، مفرومة ناعماً","4 فصوص ثوم، مفرومة (اختياري — يستنكر متشددو بوسطن لكن معظم الوصفات الحديثة تتضمن)","30 غ زبدة غير مملحة","30 غ دقيق متعدد الاستخدامات (للروكس)","750 غ بطاطس نشوية (Yukon Gold أو russet)، مقشرة ومقطعة مكعبات 1.5 سم","250 مل حليب كامل الدسم","250 مل كريمة ثقيلة (أو نصف ونصف لنسخة أخف)","2 ورقة غار + 1 ملعقة صغيرة زعتر مجفف + 0.5 ملعقة صغيرة فلفل أسود مطحون طازج","0.5 ملعقة صغيرة ملح (تذوق أولاً — عصير المحار مالح)","رشة كايين أو 1 قطرة صلصة حارة (اختياري)","حزمة صغيرة من الثوم المعمر الطازج، مفروم ناعماً، و2 ملعقة كبيرة بقدونس طازج بأوراق مسطحة للزينة","للتقديم: 4 لفائف صغيرة من خبز العجين المخمر مفرغة كأوعية صالحة للأكل أو بسكويت المحار (مرافق تقليدي لنيو إنجلاند)؛ 1 ليمونة، مقطعة شرائح"],"en":["1.5 kg fresh littleneck or quahog clams in shells (or 2 × 200 g cans whole baby clams in juice as substitute for landlocked cooks)","500 ml fresh clam juice or fish stock (reserve all the steaming liquid if using fresh clams)","150 g thick-cut smoked bacon, diced 0.5 cm","1 large yellow onion (~250 g), finely diced","2 medium celery stalks (~120 g), finely diced","4 garlic cloves, minced (optional — Boston purists frown but most modern recipes include)","30 g unsalted butter","30 g all-purpose flour (for the roux)","750 g floury potatoes (Yukon Gold or russet), peeled and cut into 1.5 cm cubes","250 ml whole milk","250 ml heavy cream (or half-and-half for a lighter version)","2 bay leaves + 1 tsp dried thyme + 0.5 tsp freshly ground black pepper","0.5 tsp salt (taste first — clam juice is salty)","A pinch of cayenne or 1 dash hot sauce (optional)","1 small bunch fresh chives, finely chopped, and 2 tbsp fresh flat-leaf parsley to garnish","To serve: 4 small hollowed-out sourdough rolls as edible bread bowls OR oyster crackers (a traditional New England side); 1 lemon, sliced into wedges"],"ro":["1,5 kg scoici proaspete (littleneck sau quahog) în cochilii (sau 2 × 200 g conserve de scoici mici întregi în suc, ca substitut pentru cei departe de mare)","500 ml suc de scoici proaspăt sau fond de pește (rezervă tot lichidul de aburire dacă folosești scoici proaspete)","150 g bacon afumat tăiat gros, cuburi de 0,5 cm","1 ceapă galbenă mare (~250 g), tăiată mărunt","2 tulpini medii de țelină (~120 g), tăiate mărunt","4 căței de usturoi, tocați (opțional — puriștii din Boston dezaprobă, dar majoritatea rețetelor moderne îi includ)","30 g unt nesărat","30 g făină universală (pentru roux)","750 g cartofi făinoși (Yukon Gold sau russet), curățați și tăiați cuburi de 1,5 cm","250 ml lapte integral","250 ml smântână grasă (sau jumătate-jumătate pentru o versiune mai ușoară)","2 foi de dafin + 1 linguriță cimbru uscat + 0,5 linguriță piper negru proaspăt măcinat","0,5 linguriță sare (gustă întâi — sucul de scoici este sărat)","Un vârf de cayenne sau 1 strop de sos iute (opțional)","O legăturică mică de arpagic proaspăt, tocat fin, și 2 linguri de pătrunjel proaspăt cu frunze plate pentru garnitură","Pentru servire: 4 chifle mici de sourdough scobite ca boluri comestibile SAU biscuiți pentru stridii (un acompaniament tradițional al Noii Anglii); 1 lămâie, tăiată felii pentru garnitură"]},"howIsMade":{"ar":"اشطف 1.5 كغ من المحار الطازج بالماء البارد 2–3 مرات لإزالة الرمل; تخلص من أي محار مفتوح لا يغلق عند النقر عليه; ضعه في قدر واسع مع 250 مل ماء، غطِّ واطبخ على البخار على نار عالية 4–5 دقائق حتى تنفتح الأصداف بالكاد; تخلص من أي محار بقي مغلقاً. ارفع المحار، تاركاً سائل البخار; صفِّ ذلك السائل من خلال مصفاة ناعمة مبطنة بقماش جبني رطب في كوب قياس — يجب أن يكون لديك ~400–500 مل من مرق محار نظيف; انتزع لحم المحار من الأصداف، اقطعه خشناً واتركه جانباً; (إذا كنت تستخدم محاراً معلباً، فقط صفّه مع الاحتفاظ بالعصارة، واستخدم 500 مل مرق سمك + عصارة العلبة.). في قدر ثقيل سعة 5 ل أو دتش أوفن على نار متوسطة، أضف 150 غ لحم مقدد مكعبات; اطبخ مع التحريك المتكرر 6–8 دقائق حتى يصبح اللحم المقدد بنياً عميقاً وتذوب معظم الدهون; ارفع اللحم المقدد المقرمش بملعقة مثقبة على ورق ماص واتركه جانباً للزينة; اترك 3 ملاعق كبيرة من دهن اللحم المقدد في القدر. أضف 250 غ بصل مفروم + 120 غ كرفس مفروم إلى دهن اللحم المقدد مع رشة ملح; اطبخ مع التحريك المتكرر 8–10 دقائق حتى يصبح طرياً وشفافاً لكن غير محمر — الشودر أبيض، لا تريد لوناً هنا; أضف 4 فصوص ثوم مفرومة واطبخ دقيقة إضافية; أضف 30 غ زبدة ودعها تذوب. رش 30 غ دقيق على الخضار وقلّب باستمرار بملعقة خشبية 2 دقيقة، طاهياً طعم الدقيق النيء دون تركه يكتسب لوناً — هذا روكس أبيض; اسكب مرق المحار المصفى في مجرى بطيء وثابت مع الخفق المستمر لمنع التكتل; أضف 750 غ مكعبات بطاطس + 2 ورقة غار + 1 ملعقة صغيرة زعتر + 0.5 ملعقة صغيرة فلفل أسود; أحضر إلى غليان هادئ. اطبخ مكشوفاً 15–18 دقيقة، مع التحريك من حين لآخر، حتى تصبح البطاطس طرية لكن تحتفظ بشكلها — اثقب واحدة بسكين ويجب أن تنزلق دون مقاومة; اخفض الحرارة إلى أدنى مستوى; قلّب 250 مل حليب كامل الدسم و250 مل كريمة ثقيلة — لا تدع الخليط يغلي بعد إضافة الألبان، وإلا ستتجبن الكريمة; سخّن لمدة 3 دقائق. قلّب لحم المحار المقطع ومعظم اللحم المقدد (احتفظ بـ 2 ملعقة كبيرة من اللحم المقدد وكل الثوم المعمر للزينة); اطبخ 3 دقائق إضافية حتى يسخن المحار للتو — الإفراط في الطهي يجعله قاسياً ومطاطياً; أزل أوراق الغار; تذوق وعدّل التتبيلة بالملح ورشة من الكايين إذا أردت. فرّغ 4 لفائف صغيرة من العجين المخمر (أو استخدم بسكويت المحار كخيار تقليدي أبسط); اغرف الشودر الساخن في أوعية الخبز أو أطباق حساء عميقة; غطِّ كل واحد باللحم المقدد المقرمش المحفوظ، رشة سخية من الثوم المعمر والبقدونس، ولفة طازجة من الفلفل الأسود; قدّم على الفور مع شرائح ليمون على الجانب; مطعم نيو إنجلاند عادة يحضر طبقاً صغيراً من بسكويت المحار وجانب صلصة حارة للطاولة.","en":"Rinse 1.5 kg fresh clams in cold water 2-3 times to remove sand and discard any that are open and do not close when tapped, then place them in a wide pot with 250 ml water, cover and steam over high heat for 4-5 minutes until the shells just open, discarding any that stayed shut. Lift the clams out and strain the steaming liquid through a fine sieve lined with damp cheesecloth into a measuring cup, aiming for ~400-500 ml of clean clam broth, then pick the clam meat from the shells, roughly chop it, and set aside (if using canned clams, drain them reserving the juice and use the 500 ml fish stock plus the canned juice). In a heavy 5 L pot or Dutch oven over medium heat, add 150 g diced bacon and cook stirring often for 6-8 minutes until the bacon is deeply browned and most of the fat has rendered, then lift the crispy bacon onto a paper towel and set aside for garnish, leaving 3 tbsp of bacon fat in the pot. Add 250 g diced onion and 120 g diced celery to the bacon fat with a pinch of salt and cook stirring often for 8-10 minutes until soft and translucent but not browned (chowder is white, so you do not want colour here), then add 4 minced garlic cloves and cook 1 minute more. Add 30 g butter and let it melt, then sprinkle 30 g flour over the vegetables and stir constantly with a wooden spoon for 2 minutes, cooking out the raw flour taste without letting it darken to keep a white roux. Pour in the strained clam broth in a slow steady stream while whisking constantly to prevent lumps, add 750 g potato cubes, 2 bay leaves, 1 tsp thyme, and 0.5 tsp black pepper, bring to a gentle simmer, then cook uncovered for 15-18 minutes stirring occasionally until the potatoes are tender but still hold their shape and a knife slides in with no resistance. Lower the heat to its lowest setting and stir in 250 ml whole milk and 250 ml heavy cream, taking care not to let it boil after adding dairy or the cream will curdle, then warm through for 3 minutes before stirring in the chopped clam meat and most of the bacon (saving 2 tbsp of bacon and all the chives for garnish), and simmer 3 more minutes until the clams are just heated through (overcooking turns them tough and rubbery), then remove the bay leaves and taste, adjusting seasoning with salt and a pinch of cayenne if you like. Hollow out 4 small sourdough rolls (or use oyster crackers as a traditional simpler option), ladle the hot chowder into the bread bowls or deep soup plates, top each with the reserved crispy bacon, a generous scatter of chives and parsley, and a fresh twist of black pepper, and serve immediately with lemon wedges on the side, just as a New England restaurant typically brings a small dish of oyster crackers and a side of hot sauce to the table."}},{"id":173,"servings":2,"tipType":"meat","pairingsType":"meat","origin":{"ar":"ألمانيا","en":"Germany","ro":"Germania"},"name":{"ar":"كاري فورست","en":"Currywurst","ro":"Currywurst"},"category":{"ar":"وجبة خفيفة","en":"Snack","ro":"Gustare"},"ingredients":{"ar":["4 سجق برلين Bratwurst من لحم الخنزير (~120 غ لكل واحدة، الإجمالي ~480 غ) — طازجة، غير مشوية مسبقاً؛ أو استبدل بـ Bockwurst ناعمة أو Frankfurter إذا لم تتوفر Bratwurst","2 ملعقة كبيرة زيت محايد (دوار الشمس) لقلي السجق","لصلصة الكاري: 200 غ كاتشب طماطم عالي الجودة (Heinz أو Hela الألماني)","100 مل باساتا أو 1 ملعقة كبيرة معجون طماطم + 80 مل ماء كبديل","2 ملعقة كبيرة مسحوق كاري متوسط الحرارة (خلطة صفراء بأسلوب مدراس) — الأصلي لـ Herta Heuwer استخدم مسحوق كاري مشابه استعماري بريطاني","1 ملعقة صغيرة بابريكا حلوة مجرية","0.5 ملعقة صغيرة بابريكا مدخنة (اختياري، تضيف عمقاً)","1 ملعقة كبيرة صلصة Worcestershire (سر أصل Heuwer — غير قابل للتفاوض)","1 ملعقة كبيرة خل سيدر التفاح أو خل النبيذ الأبيض","1 ملعقة كبيرة سكر أبيض (يساعد على موازنة الخل ويبرز الطماطم)","0.5 ملعقة صغيرة بهار حلو مطحون + 0.5 ملعقة صغيرة زنجبيل مطحون (خلطة التوابل الدافئة 'السرية' التي أضافتها Heuwer)","0.5 ملعقة صغيرة ملح + رشة كايين أو فلفل حار","للتقديم: مسحوق كاري إضافي للرش فوقه + حصتين من Pommes Frites (حوالي 400 غ بطاطس مقلية ساخنة ومقرمشة من الفرن أو القلاية)، أو 2 لفائف Brötchen صغيرة؛ 2 شوكتين خشبيتين صغيرتين (Pommespieker) للتجربة البرلينية الأصيلة"],"en":["4 Berliner-style Bratwurst pork sausages (~120 g each, total ~480 g) — fresh, not pre-grilled; or substitute fine Bockwurst or Frankfurter if Bratwurst unavailable","2 tbsp neutral oil (sunflower) for frying the sausages","For the curry sauce: 200 g good-quality tomato ketchup (Heinz or German Hela)","100 ml passata or 1 tbsp tomato paste + 80 ml water as substitute","2 tbsp medium-hot curry powder (a yellow Madras-style blend) — Herta Heuwer's original used a similar British colonial curry powder","1 tsp sweet Hungarian paprika","0.5 tsp smoked paprika (optional, adds depth)","1 tbsp Worcestershire sauce (the secret of Heuwer's original — not negotiable)","1 tbsp apple cider vinegar OR white wine vinegar","1 tbsp white sugar (helps balance the vinegar and brings out the tomato)","0.5 tsp ground allspice + 0.5 tsp ground ginger (the 'secret' warm-spice mix Heuwer added)","0.5 tsp salt + a pinch of cayenne or hot chili powder","To serve: extra curry powder for dusting on top + 2 portions of Pommes Frites (about 400 g hot crispy fries from the oven or fryer), or 2 small Brötchen rolls; 2 small wooden forks (Pommespieker) for the authentic Berlin experience"],"ro":["4 cârnați Bratwurst de Berlin din porc (~120 g fiecare, total ~480 g) — proaspeți, nu pre-grătar; sau substituție cu Bockwurst fin sau Frankfurter dacă Bratwurst nu este disponibil","2 linguri ulei neutru (floarea-soarelui) pentru prăjirea cârnaților","Pentru sosul de curry: 200 g ketchup de tomate de bună calitate (Heinz sau german Hela)","100 ml passata sau 1 lingură pastă de tomate + 80 ml apă ca substitut","2 linguri pudră de curry medie-iute (un amestec galben stil Madras) — originalul Herta Heuwer folosea o pudră de curry similară colonială britanică","1 linguriță paprika dulce maghiară","0,5 linguriță paprika afumată (opțional, adaugă profunzime)","1 lingură sos Worcestershire (secretul originalului Heuwer — nu este negociabil)","1 lingură oțet de cidru de mere SAU oțet de vin alb","1 lingură zahăr alb (ajută la echilibrarea oțetului și scoate în evidență tomatele)","0,5 linguriță piment ienibahar + 0,5 linguriță ghimbir măcinat (amestecul 'secret' de mirodenii calde pe care Heuwer le-a adăugat)","0,5 linguriță sare + un vârf de cayenne sau chili iute","Pentru servire: pudră de curry suplimentară pentru presărare deasupra + 2 porții de Pommes Frites (aproximativ 400 g cartofi prăjiți fierbinți și crocanți din cuptor sau friteuză), sau 2 Brötchen mici; 2 furculițe mici de lemn (Pommespieker) pentru experiența autentică berlineză"]},"howIsMade":{"ar":"اوخز السجق: أخرج 4 Bratwurst من الثلاجة قبل الطهي بـ 15 دقيقة لتقترب من درجة حرارة الغرفة; اوخز كل سجقة 4–5 مرات بشوكة — هذا يمنع الجلد من الانفجار في المقلاة ويسمح لبعض الدهون بالخروج. حضّر صلصة الكاري: في قدر صغير، اخلط 200 غ كاتشب + 100 مل باساتا + 2 ملعقة كبيرة مسحوق كاري + 1 ملعقة صغيرة بابريكا حلوة + 0.5 ملعقة صغيرة بابريكا مدخنة + 1 ملعقة كبيرة Worcestershire + 1 ملعقة كبيرة خل + 1 ملعقة كبيرة سكر + 0.5 ملعقة صغيرة بهار حلو + 0.5 ملعقة صغيرة زنجبيل مطحون + 0.5 ملعقة صغيرة ملح + رشة كايين; اخفق للمزج. اطبخ الصلصة على نار هادئة: ارفع صلصة الكاري إلى غليان لطيف على نار متوسطة-منخفضة; اطبخ 8–10 دقائق، مع التحريك المتكرر بملعقة خشبية، حتى تصبح الصلصة لامعة ومخفضة قليلاً — يجب أن تغلف ظهر ملعقة; تذوق وعدّل: إذا كانت حادة جداً، أضف رشة سكر أكثر؛ إذا كانت حلوة جداً، رشة خل أكثر; حافظ على الدفء على أدنى حرارة. اقلِ السجق: سخن 2 ملعقة كبيرة زيت في مقلاة ثقيلة على نار متوسطة; أضف السجق الموخوز واقلِ 8–10 دقائق، مع القلب كل دقيقتين بالملقاط، حتى يصبح ذهبياً غامقاً من جميع الجوانب والجلد مقرمشاً; يجب أن تصل درجة الحرارة الداخلية إلى 70 °C — يجب أن يكون السجق مطهواً بالكامل. ارح لمدة دقيقتين: انقل السجق إلى لوح مبطن بمنشفة ورقية; اتركه يرتاح دقيقتين — هذا ينهي الطهي ويسمح للعصارات بإعادة التوزيع، حتى لا تتدفق عند التقطيع. قطّع: بسكين حاد، قطّع كل سجقة بشكل قطري إلى 8 قطع بحجم 1.5 سم; القطع القطري يعطي سطحاً أكبر لتلتصق به الصلصة وهو التقديم البرليني الأيقوني. التجميع: قسّم السجق المقطع بين طبقين عميقين من الصواني الورقية أو أوعية ضحلة (أسلوب Berlin Imbiss); اسكب صلصة الكاري الساخنة بسخاء فوقها لتتجمع حول الشرائح; رش الطبق كاملاً برشة سخية إضافية من مسحوق الكاري — القمة الترابية هي ما تجعلها currywurst، وليس مجرد سجق في صلصة. قدّم مع Pommes: اغرز Pommespieker خشبياً (شوكة صغيرة) في الشرائح، ضع على جانب الصينية كومة من Pommes Frites الذهبية ولمسة صغيرة من المايونيز + الكاتشب (Pommes rot-weiß الألماني); كل واقفاً، يفضل في زاوية شارع برليني; اشرب مع Pilsner باردة; الأفضل الأكل خلال 5 دقائق — المتعة في تباين الجلد المقرمش، الصلصة الساخنة، الكاري الترابي، والبطاطس المالحة.","en":"PRICK THE SAUSAGES: take 4 Bratwurst out of the fridge 15 minutes before cooking to come closer to room temperature; prick each sausage 4–5 times with a fork — this prevents the skin from bursting open in the pan and lets some fat render out. MAKE THE CURRY SAUCE: in a small saucepan, combine 200 g ketchup + 100 ml passata + 2 tbsp curry powder + 1 tsp sweet paprika + 0.5 tsp smoked paprika + 1 tbsp Worcestershire + 1 tbsp vinegar + 1 tbsp sugar + 0.5 tsp allspice + 0.5 tsp ground ginger + 0.5 tsp salt + a pinch of cayenne; whisk to combine. SIMMER THE SAUCE: bring the curry sauce to a gentle simmer over medium-low heat; cook 8–10 minutes, stirring often with a wooden spoon, until the sauce is glossy and slightly reduced — it should coat the back of a spoon; taste and adjust: if too sharp, add a pinch more sugar; if too sweet, a splash more vinegar; keep warm on the lowest heat. FRY THE SAUSAGES: heat 2 tbsp oil in a heavy skillet over medium heat; add the pricked sausages and fry 8–10 minutes, turning every 2 minutes with tongs, until deeply golden brown on all sides and the skin is crisp; the internal temperature should reach 70 °C — sausages must be fully cooked through. REST 2 MINUTES: transfer the sausages onto a board lined with paper towel; let them rest 2 minutes — this finishes cooking and lets the juices redistribute, so they don't gush out when sliced. SLICE: with a sharp knife, slice each sausage diagonally into 8 pieces of 1.5 cm; the diagonal cut gives more surface for the sauce to cling to and is the iconic Berlin presentation. ASSEMBLE: divide the sliced sausages between 2 deep paper-tray plates or shallow bowls (the Berlin Imbiss style); ladle the hot curry sauce generously over the top so it pools around the slices; dust the whole plate with an extra generous pinch of curry powder — the dusty top is what makes it a currywurst, not just a sausage in sauce. SERVE WITH POMMES: stab a wooden Pommespieker (small fork) into the slices, set on the side of the tray a heap of golden Pommes Frites and a small dollop of mayonnaise + ketchup (the German Pommes rot-weiß); eat standing up, ideally on a Berlin street corner; pair with a cold Pilsner; best eaten within 5 minutes — the joy is in the contrast of crisp skin, hot sauce, dusty curry, and salty fries."}},{"id":174,"servings":4,"tipType":"meat","pairingsType":"thai","origin":{"ar":"تايلاند","en":"Thailand","ro":"Thailanda"},"name":{"ar":"توم خا غاي","en":"Tom Kha Gai","ro":"Tom Kha Gai"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"ingredients":{"ar":["500 غ أفخاذ دجاج منزوعة العظم والجلد (نكهة أفضل من الصدر في هذا المرق الرقيق)، مقطعة رفيعة عكس الألياف إلى شرائح 5 مم","400 مل حليب جوز الهند كامل الدسم غير محلى (مع طبقة الكريمة منفصلة، انظر الخطوة 2)","600 مل مرق دجاج بدون ملح (محلي الصنع أو مشترى منخفض الصوديوم)","1 يد من الجلانجال الطازج (kha) — ~50 غ، مقشر ومقطع إلى شرائح عملة 5 مم؛ لا تستبدل بالزنجبيل، النكهة مختلفة تماماً","3 سيقان عشب الليمون الطازج (takrai) — الأوراق الخارجية مزالة، 10 سم السفلية مرضوضة بظهر السكين ومقطعة إلى أقسام 5 سم","6 أوراق كافير لايم طازجة (bai makrut)، منزوعة العروق ومُمزقة (غير مقطعة — تطلق الزيوت عند تمزيقها)","4 فلفل حار تايلندي صغير عين الطائر (prik kee noo) — مرضوض قليلاً كاملاً، غير مقطع إذا أردت حرارة لطيفة (مقطع للحار)","4 فصوص ثوم، مرضوضة قليلاً","2 كراث صغير (~80 غ)، مقطع رفيعاً","200 غ فطر القش (معلب، مصفى)، مقسوم إلى نصفين — أو فطر طازج المحار/شيتاكي/زر كبديل","4 ملاعق كبيرة صلصة سمك تايلندية (nam pla) — ماركة Squid أو Tiparos لأفضل نكهة","1 ملعقة كبيرة سكر النخيل (أو سكر بني فاتح)","60 مل عصير ليمون طازج (من 2 ليمونة) — يضاف في النهاية، لا يغلى أبداً","2 ملعقة كبيرة معجون فلفل حار تايلندي في زيت الصويا (nam prik pao) — يضيف العمق المدخن المميز (اختياري ولكن تقليدي)","1 حزمة صغيرة من الكزبرة الطازجة، مفرومة خشنة، للتزيين","4 بصل أخضر، مقطع رفيع بشكل قطري، للتزيين","للتقديم: 320 غ أرز ياسمين مطبوخ (80 غ جاف لكل حصة) + 1 ليمونة مقطعة إلى شرائح"],"en":["500 g boneless skinless chicken thighs (more flavour than breast in this delicate broth), thinly sliced across the grain into 5 mm strips","400 ml unsweetened full-fat coconut milk (the cream layer separated, see step 2)","600 ml unsalted chicken stock (low-sodium homemade or store-bought)","1 hand of fresh galangal (kha) — ~50 g, peeled and cut into 5 mm coin slices; do NOT substitute ginger, the flavour is completely different","3 stalks fresh lemongrass (takrai) — outer leaves removed, lower 10 cm bruised with the back of a knife and cut into 5 cm sections","6 fresh kaffir lime leaves (bai makrut), de-veined and torn (NOT chopped — they release oils when torn)","4 small Thai bird's eye chilies (prik kee noo) — lightly bruised whole, not sliced if you want gentle heat (sliced for hot)","4 garlic cloves, lightly bruised","2 small shallots (~80 g), thinly sliced","200 g straw mushrooms (canned, drained), halved — or fresh oyster/shiitake/button mushrooms as substitute","4 tbsp Thai fish sauce (nam pla) — Squid or Tiparos brand for best flavour","1 tbsp palm sugar (or light brown sugar)","60 ml fresh lime juice (from 2 limes) — added at the END, never boiled","2 tbsp Thai chili paste in soybean oil (nam prik pao) — adds the signature smoky depth (optional but traditional)","1 small bunch fresh cilantro (coriander) leaves, roughly chopped, to garnish","4 spring onions, thinly sliced on the diagonal, to garnish","To serve: 320 g cooked jasmine rice (80 g dry per serving) + 1 lime cut into wedges"],"ro":["500 g pulpe de pui dezosate și fără piele (mai aromate decât pieptul în acest bulion delicat), feliate subțire în benzi de 5 mm contra fibrei","400 ml lapte de cocos integral neîndulcit (cu stratul de smântână separat, vezi pasul 2)","600 ml supă de pui nesărată (de casă sau cumpărată cu conținut scăzut de sodiu)","1 mână de galangal proaspăt (kha) — ~50 g, curățat și tăiat în felii de 5 mm; NU înlocui cu ghimbir, aroma este complet diferită","3 tulpini de lemongrass proaspăt (takrai) — frunzele exterioare îndepărtate, partea inferioară de 10 cm zdrobită cu dosul cuțitului și tăiată în secțiuni de 5 cm","6 frunze de kaffir lime proaspete (bai makrut), cu vinele îndepărtate și rupte (NU tăiate — eliberează uleiurile când sunt rupte)","4 ardei iuți thailandezi mici (prik kee noo) — zdrobiți ușor întregi, nu feliați dacă vrei iuțeală blândă (feliați pentru iute)","4 căței de usturoi, zdrobiți ușor","2 șalote mici (~80 g), feliate subțire","200 g ciuperci de paie (la conservă, scurse), tăiate în jumătăți — sau ciuperci proaspete oyster/shiitake/champignon ca substitut","4 linguri sos de pește thailandez (nam pla) — marca Squid sau Tiparos pentru cea mai bună aromă","1 lingură zahăr de palmier (sau zahăr brun deschis)","60 ml suc de lime proaspăt (din 2 limete) — adăugat la SFÂRȘIT, niciodată fiert","2 linguri pastă thailandeză de ardei iute în ulei de soia (nam prik pao) — adaugă profunzimea afumată caracteristică (opțional dar tradițional)","1 mănunchi mic de coriandru proaspăt (frunze de cilantro), tocat grosier, pentru garnitură","4 cepe verzi, feliate subțire pe diagonală, pentru garnitură","Pentru servire: 320 g orez jasmin fiert (80 g uscat pe porție) + 1 lime tăiat în felii"]},"howIsMade":{"ar":"حضّر الأعشاب العطرية: قشّر وقطّع 50 غ من الجلانجال إلى عملات بحجم 5 مم; أزل الأوراق الخارجية الصلبة من 3 سيقان عشب الليمون وارضض الـ 10 سم السفلية بظهر سكين ثقيلة لإطلاق الزيوت — ثم قطّعها إلى قطع 5 سم; مزّق (لا تقطع) 6 أوراق كافير لايم لإطلاق زيوتها; ارضض قليلاً 4 فلفل حار + 4 فصوص ثوم بجانب السكين; هذه الأعشاب العطرية هي روح المرق — لا تستخدم أبداً البدائل المطحونة. افصل حليب جوز الهند: افتح علبة 400 مل من حليب جوز الهند دون رجها; عادةً ما تستقر الكريمة الكثيفة في الأعلى — اغرف بالملعقة حوالي 100 مل من الكريمة الكثيفة وضعها جانباً (هذه هي hua kati، الكريمة); الباقي هو الحليب الأرق (hang kati). ازهر الكريمة: في قدر متوسط على نار متوسطة، اطبخ 100 مل من كريمة جوز الهند 3–4 دقائق حتى تنفصل ويبدأ الزيت بالانفصال بشكل مرئي — هذا يركز نكهة جوز الهند وهو الحركة الافتتاحية التايلندية التقليدية; (إذا لم ينفصل حليب جوز الهند الخاص بك بشكل نظيف، تخطَّ هذه الخطوة وابدأ بكل شيء في القدر.). انقع الأعشاب العطرية: أضف شرائح الجلانجال، قطع عشب الليمون، أوراق الليم الممزقة، الفلفل الحار المرضوض، الثوم، و80 غ من الكراث المقطع إلى كريمة جوز الهند الساخنة; حرّك دقيقة واحدة حتى يصبح عطرياً بشدة; يجب أن تنبعث من المطبخ رائحة تايلاندية مميزة — حمضيات لامعة، جلانجال فلفلي، وجوز هند حلو. ابنِ المرق: اسكب الـ 300 مل المتبقية من حليب جوز الهند + 600 مل مرق الدجاج + 2 ملعقة كبيرة nam prik pao (إذا استخدمت); ارفع إلى غليان لطيف (لا تغلِ بقوة أبداً — حليب جوز الهند ينفصل بشكل قبيح إذا غلي بقوة); اطبخ على نار هادئة 8 دقائق مكشوفاً، حتى تنقع الأعشاب العطرية تماماً ويكون طعم المرق عميقاً ومتكاملاً. أضف الدجاج: ضع 500 غ من الدجاج المقطع في المرق الذي يغلي، مع التحريك بلطف لفصل القطع; اطبخ على نار هادئة 4–5 دقائق حتى ينضج الدجاج بالكاد ويصبح أبيض — الإفراط في الطهي يجعله قاسياً; أضف 200 غ من فطر القش المقسوم إلى نصفين واطبخ على نار هادئة دقيقتين أخريين. تبّل: أطفئ النار; حرّك 4 ملاعق كبيرة من صلصة السمك + 1 ملعقة كبيرة من سكر النخيل; تذوق — يجب أن يكون المرق مالحاً، حلواً قليلاً، حاراً بشكل معتدل، ومليئاً بعطر الحمضيات; أضف رشة أخرى من صلصة السمك أو السكر إذا لزم الأمر; إطفاء النار حاسم هنا. الليمون في اللحظة الأخيرة: حرّك 60 مل من عصير الليمون الطازج فقط قبل التقديم مباشرة — غلي عصير الليمون يجعله مراً وباهتاً; اسكب في أوعية عميقة; غطِّ بالكزبرة الطازجة + البصل الأخضر المقطع + بضع شرائح إضافية من الفلفل الحار المرضوض لأولئك الذين يحبون المزيد من الحرارة; قدّم ساخناً مع أرز الياسمين المطهو على البخار جانباً وشرائح الليمون; أخبر الضيوف: الجلانجال، عشب الليمون، وأوراق الليم هي أعشاب عطرية، وليست صالحة للأكل — ادفعها إلى جانب الوعاء.","en":"PREP THE AROMATICS: peel and slice 50 g galangal into 5 mm coins; remove the tough outer leaves from 3 lemongrass stalks and bruise the lower 10 cm with the back of a heavy knife to release the oils — then cut into 5 cm pieces; tear (don't chop) 6 kaffir lime leaves to release their oils; lightly bruise 4 chilies + 4 garlic cloves with the side of the knife; these aromatics are the soul of the broth — never use ground substitutes. SEPARATE THE COCONUT MILK: open a 400 ml can of coconut milk without shaking; the thick cream usually sits on top — spoon off about 100 ml of the thick cream and set aside (this is your hua kati, the cream); the rest is the thinner milk (hang kati). BLOOM THE CREAM: in a medium pot over medium heat, simmer the 100 ml coconut cream 3–4 minutes until it splits and the oil starts to separate visibly — this concentrates the coconut flavor and is the traditional Thai opening move; (If your coconut milk doesn't separate cleanly, skip this step and just start with everything in the pot.). INFUSE THE AROMATICS: add the galangal slices, lemongrass pieces, torn lime leaves, bruised chilies, garlic, and 80 g sliced shallots to the hot coconut cream; stir 1 minute until intensely aromatic; the kitchen should smell distinctly of Thai — bright citrus, peppery galangal, and sweet coconut. BUILD THE BROTH: pour in the remaining 300 ml coconut milk + 600 ml chicken stock + 2 tbsp nam prik pao (if using); bring to a gentle simmer (NEVER a hard boil — coconut milk separates ugly if boiled hard); simmer 8 minutes uncovered, so the aromatics infuse fully and the broth tastes deep and rounded. ADD THE CHICKEN: drop the 500 g sliced chicken into the simmering broth, stirring gently to separate the pieces; simmer 4–5 minutes until the chicken is just cooked through and white — overcooking turns it tough; add 200 g halved straw mushrooms and simmer 2 minutes more. SEASON: turn off the heat; stir in 4 tbsp fish sauce + 1 tbsp palm sugar; taste — the broth should be savoury, slightly sweet, mildly hot, and full of citrus aroma; add a splash more fish sauce or sugar if needed; off heat is critical here. LIME AT THE LAST MOMENT: stir in 60 ml fresh lime juice ONLY just before serving — boiling the lime juice turns it bitter and dull; ladle into deep bowls; top with fresh cilantro + sliced spring onions + a few extra slices of bruised chili for those who like more heat; serve hot with steamed jasmine rice on the side and lime wedges; tell guests: the galangal, lemongrass, and lime leaves are aromatics, not edible — fish them to the side of the bowl."}},{"id":175,"servings":6,"tipType":"meat","pairingsType":"latin","origin":{"ar":"الرأس الأخضر","en":"Cape Verde","ro":"Capul Verde"},"name":{"ar":"كاشوبا","en":"Cachupa","ro":"Cachupa"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["400 غ milho cachupa (ذرة هوميني بيضاء، صنف رأس الأخضر المجفف المتشقق) — منقوعة طوال الليل في كمية وفيرة من الماء البارد (إلزامي)","200 غ فاصوليا حمراء جافة — منقوعة طوال الليل","200 غ فاصوليا الزبدة الجافة (ليما) أو الحمص — منقوعة طوال الليل (مزيج البقوليات هو التوقيع الرأس الأخضري)","500 غ كتف خنزير (cabidela)، مقطعة إلى مكعبات 3 سم","300 غ أضلاع خنزير مملحة أو لحم بطن (toucinho)، مقطعة إلى قطع — انقعها لمدة ساعة في ماء بارد لإزالة الملح الزائد","200 غ linguiça أو chouriço portuguesa (نقانق مدخنة برتغالية)، مقطعة إلى شرائح 1.5 سم","200 غ morcela (نقانق دم برتغالية) — اختياري، تقليدي","2 بصل أصفر كبير (~350 غ)، واحد مفروم ناعم للـ refogado والآخر مقطع إلى شرائح كبيرة","6 فصوص ثوم، مفرومة","2 طماطم متوسطة ناضجة (~250 غ)، مقشرة ومبشورة، أو 1 علبة 200 غ من الطماطم المهروسة","1 ملعقة كبيرة معجون طماطم","2 ورقة غار + 1 ملعقة صغيرة كمون مطحون + 1 ملعقة صغيرة بابريكا حلوة + 0.5 ملعقة صغيرة أوريغانو مجفف + 1 ملعقة صغيرة ملح + 0.5 ملعقة صغيرة فلفل أسود","3 ملاعق كبيرة زيت نخيل أحمر أو زيت زيتون (زيت النخيل أكثر تقليدية في بعض الجزر)","500 غ يقطين أو قرع جوزي، مقشر ومقطع إلى مكعبات 4 سم","300 غ بطاطا حلوة أو يام، مقشرة ومقطعة إلى مكعبات 4 سم","200 غ ملفوف سافوا، مقطع إلى شرائح 4 سم (يضاف في المرحلة النهائية)","2 لتر ماء (أو مرق خنزير) + 1 فلفل حار بيري-بيري أو scotch bonnet (اختياري، لحرارة الجزر الخفيفة)","للتقديم: قطع من الخبز الأبيض الطازج، بضع شرائح إضافية من linguiça المشوية، صلصة بيري-بيري الحارة، وخيار اليوم التالي 'cachupa guisada' المقلية في المقلاة مع البيض"],"en":["400 g milho cachupa (white hominy corn, the cracked dried Cape Verdean variety) — soaked overnight in plenty of cold water (mandatory)","200 g dried red kidney beans — soaked overnight","200 g dried butter beans (lima beans) or chickpeas — soaked overnight (the mixture of legumes is the Cape Verdean signature)","500 g pork shoulder (cabidela), cut into 3 cm cubes","300 g salted pork ribs or pork belly (toucinho), cut into chunks — soak 1 hour in cold water to remove excess salt","200 g linguiça or chouriço portuguesa (Portuguese smoked sausage), cut into 1.5 cm slices","200 g morcela (Portuguese blood sausage) — optional, traditional","2 large yellow onions (~350 g), one finely diced for the refogado and one cut into wedges","6 garlic cloves, minced","2 medium ripe tomatoes (~250 g), peeled and grated, or 1 × 200 g can crushed tomatoes","1 tbsp tomato paste","2 bay leaves + 1 tsp ground cumin + 1 tsp sweet paprika + 0.5 tsp dried oregano + 1 tsp salt + 0.5 tsp black pepper","3 tbsp red palm oil OR olive oil (palm oil is more traditional in some islands)","500 g pumpkin or butternut squash, peeled and cut into 4 cm cubes","300 g sweet potato or yam, peeled and cut into 4 cm cubes","200 g savoy cabbage, cut into 4 cm wedges (added in the final stage)","2 L water (or pork stock) + 1 piri-piri or scotch bonnet chili (optional, for the islands' light heat)","To serve: chunks of fresh white bread, a few extra slices of grilled linguiça, hot piri-piri sauce, and the next-day pan-fried 'cachupa guisada' with eggs option mentioned"],"ro":["400 g milho cachupa (porumb hominy alb, varietatea crăpată uscată specifică Capului Verde) — înmuiat peste noapte în multă apă rece (obligatoriu)","200 g fasole roșie uscată — înmuiată peste noapte","200 g fasole untoasă uscată (lima) sau năut — înmuiată peste noapte (amestecul de leguminoase este semnătura capverdiană)","500 g spată de porc (cabidela), tăiată în cuburi de 3 cm","300 g coaste de porc sărate sau burtă de porc (toucinho), tăiate în bucăți — înmuiate 1 oră în apă rece pentru a îndepărta excesul de sare","200 g linguiça sau chouriço portuguesa (cârnat afumat portughez), tăiat în felii de 1.5 cm","200 g morcela (cârnat de sânge portughez) — opțional, tradițional","2 cepe galbene mari (~350 g), una tăiată mărunt pentru refogado și una tăiată în felii mari","6 căței de usturoi, tocați mărunt","2 roșii medii coapte (~250 g), decojite și răzuite, sau 1 cutie de 200 g de roșii zdrobite","1 lingură pastă de roșii","2 foi de dafin + 1 linguriță chimion măcinat + 1 linguriță boia dulce + 0.5 linguriță oregano uscat + 1 linguriță sare + 0.5 linguriță piper negru","3 linguri ulei roșu de palmier SAU ulei de măsline (uleiul de palmier este mai tradițional în unele insule)","500 g dovleac sau dovleac plăcintar, curățat și tăiat în cuburi de 4 cm","300 g cartof dulce sau ignamă, curățat și tăiat în cuburi de 4 cm","200 g varză de Milano, tăiată în felii mari de 4 cm (adăugată în etapa finală)","2 L apă (sau supă de porc) + 1 ardei iute piri-piri sau scotch bonnet (opțional, pentru iuțeala ușoară a insulelor)","Pentru servire: bucăți de pâine albă proaspătă, câteva felii suplimentare de linguiça la grătar, sos iute piri-piri și opțiunea 'cachupa guisada' a doua zi (prăjită în tigaie cu ouă)"]},"howIsMade":{"ar":"انقع طوال الليل: هذه الخطوة غير قابلة للتفاوض; في الليلة السابقة للطهي، ضع 400 غ من ذرة الهوميني + 200 غ من الفاصوليا الحمراء + 200 غ من فاصوليا الزبدة/الحمص كل منها في أوعية منفصلة مغطاة بـ 5 سم من الماء البارد; انقع لمدة 12 ساعة على الأقل; في الصباح التالي، صفِّ واشطف; تخطي النقع يعطي ذرة تبقى رملية بعد ساعات من الطهي. اطبخ الهوميني مسبقاً: ضع الهوميني المصفى في قدر كبير مع 1.5 لتر من الماء البارد الطازج + 1 ورقة غار + 1 ملعقة صغيرة ملح; ارفع إلى الغليان، ثم اطبخ مغطى على نار هادئة لساعة; يجب أن تكون الذرة طرية جزئياً ولكن لا تزال صلبة في المركز — ستستمر في الطهي في اليخنة; صفِّ، مع الاحتفاظ بـ 500 مل من سائل الطهي. اطبخ الفاصوليا مسبقاً: في قدر ثانٍ، ضع الفاصوليا الحمراء المصفاة وفاصوليا الزبدة معاً مع ماء بارد طازج لتغطيتها بـ 3 سم; ارفع إلى الغليان، اكشط الرغوة لمدة 5 دقائق، ثم اطبخ على نار هادئة لمدة 45 دقيقة حتى تصبح al dente — ستنتهي في اليخنة; صفِّ. الـ refogado: في قدر كبير ثقيل بسعة 8 لتر، سخّن 3 ملاعق كبيرة من زيت النخيل أو زيت الزيتون على نار متوسطة; أضف 200 غ من البصل المفروم ناعماً + 6 فصوص ثوم مفرومة واطبخ 8–10 دقائق حتى تصبح طرية وذهبية; حرّك 1 ملعقة كبيرة من معجون الطماطم واطبخ دقيقة واحدة حتى يقتم; أضف 250 غ من الطماطم المبشورة + 1 ملعقة صغيرة بابريكا + 1 ملعقة صغيرة كمون + 0.5 ملعقة صغيرة أوريغانو واطبخ 4–5 دقائق حتى يقل الخليط وينفصل الزيت على السطح. اقلي اللحم: ادفع الـ refogado إلى الجانب; ارفع النار إلى متوسطة-عالية وأضف مكعبات 500 غ من كتف الخنزير في طبقة واحدة; اقلي 3 دقائق على كل جانب حتى تصبح ذهبية، ثم حرّك في الـ refogado; أضف أضلاع/بطن الخنزير المملحة المصفاة + 1 ملعقة صغيرة ملح + 0.5 ملعقة صغيرة فلفل + 1 ورقة غار متبقية + فلفل بيري-بيري الاختياري. ابنِ اليخنة: أضف الهوميني المطهو جزئياً + الفاصوليا المصفاة + 2 لتر ماء (أو مرق خنزير) + 500 مل من سائل طهي الذرة المحجوز; ارفع إلى غليان لطيف. طهي بطيء: اطبخ على نار هادئة مكشوفاً، مع التحريك كل 20–30 دقيقة، لمدة ساعتين; بعد ساعة، أضف مكعبات 500 غ من اليقطين + 300 غ من البطاطا الحلوة + شرائح linguiça; بعد 1.5 ساعة، أضف 200 غ من شرائح الملفوف + شرائح البصل + شرائح morcela (إذا استخدمت); يجب أن تقل اليخنة إلى قوام كثيف يشبه العصيدة، حيث تكون الذرة والفاصوليا والخضار واللحوم جميعها طرية; تذوق واضبط الملح — يضيف لحم الخنزير المملح والنقانق الكثير. الراحة والتقديم: أطفئ النار واترك الـ cachupa ترتاح لمدة 10 دقائق — هنا تكثف إلى القوام المثالي; اغرف بسخاء في أوعية عميقة مع ظهور جميع الألوان: ذرة صفراء، فاصوليا حمراء، يقطين برتقالي، ملفوف أخضر، نقانق ذهبية، ولحم خنزير غني; قدّم مع قطع من الخبز الأبيض الطازج، صلصة بيري-بيري الحارة على الطاولة، وكوب من grogue الرأس الأخضري أو البيرة; تُقلى البقايا في اليوم التالي في المقلاة مع بيضة مقلية فوقها كـ 'cachupa guisada' — تعتبر أفضل حتى من اليوم الأول.","en":"SOAK OVERNIGHT: this is non-negotiable; the night before cooking, place 400 g hominy corn + 200 g kidney beans + 200 g butter beans/chickpeas each in separate bowls covered by 5 cm of cold water; soak 12 hours minimum; the next morning, drain and rinse; skipping the soak gives a corn that stays gritty after hours of cooking. PRE-COOK THE HOMINY: place the drained hominy in a large pot with 1.5 L fresh cold water + 1 bay leaf + 1 tsp salt; bring to a boil, then simmer covered 1 hour; the corn should be partially tender but still firm at the centre — it will continue cooking in the stew; drain, reserving 500 ml of the cooking liquid. PRE-COOK THE BEANS: in a second pot, place the drained kidney beans and butter beans together with fresh cold water to cover by 3 cm; bring to a boil, skim foam for 5 min, then simmer 45 min until al dente — they will finish in the stew; drain. THE REFOGADO: in a large heavy 8 L pot, heat 3 tbsp palm or olive oil over medium heat; add 200 g finely diced onion + 6 minced garlic and cook 8–10 minutes until soft and golden; stir in 1 tbsp tomato paste and cook 1 min until darkened; add 250 g grated tomato + 1 tsp paprika + 1 tsp cumin + 0.5 tsp oregano and cook 4–5 min until the mixture reduces and the oil separates on the surface. SEAR THE PORK: push the refogado to the side; raise the heat to medium-high and add the 500 g pork shoulder cubes in a single layer; sear 3 minutes per side until golden brown, then stir into the refogado; add the drained salted pork ribs/belly + 1 tsp salt + 0.5 tsp pepper + 1 remaining bay leaf + the optional piri-piri chili. BUILD THE STEW: add the partially-cooked hominy + the drained beans + 2 L water (or pork stock) + the 500 ml reserved corn-cooking liquid; bring to a gentle simmer. SLOW SIMMER: simmer uncovered, stirring every 20–30 minutes, for 2 hours; after 1 hour, add the 500 g pumpkin cubes + 300 g sweet potato cubes + the linguiça slices; after 1.5 hours, add the 200 g cabbage wedges + the onion wedges + the morcela slices (if using); the stew should reduce to a thick, porridge-like consistency where the corn, beans, vegetables, and meats are all tender; taste and adjust salt — the saltpork and sausages add a lot. REST AND SERVE: turn off the heat and let the cachupa rest 10 minutes — this is when it thickens to the perfect consistency; ladle generously into deep bowls with all the colors visible: yellow corn, red beans, orange pumpkin, green cabbage, golden sausage, and rich pork; serve with chunks of fresh white bread, hot piri-piri sauce on the table, and a glass of Cape Verdean grogue or beer; the leftovers next day are pan-fried with a fried egg on top as 'cachupa guisada' — considered even better than the first day."}},{"id":176,"servings":4,"tipType":"veg","pairingsType":"indian","origin":{"ar":"الهند","en":"India","ro":"India"},"name":{"ar":"باف بهاجي","en":"Pav Bhaji","ro":"Pav Bhaji"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["500 غ بطاطس نشوية، مقشرة ومقطعة إلى مكعبات 3 سم","250 غ زهيرات قرنبيط (حوالي نصف رأس صغير)","100 غ بازلاء خضراء (طازجة أو مجمدة)","100 غ فاصوليا خضراء فرنسية، مقطعة إلى قطع 1 سم","1 جزرة متوسطة (~100 غ)، مقطعة مكعبات","100 غ زبدة غير مملحة (نعم — هذا الكم، هذه كميات زبدة بائعي الشارع) — مقسمة","2 بصلة حمراء كبيرة (~300 غ) — واحدة مفرومة ناعمة للبهاجي وواحدة مفرومة ناعمة نيئة للتزيين","1 فلفل أخضر كبير أو فلفل رومي (~150 غ)، مفروم ناعم","4 طماطم ناضجة (~500 غ)، مهروسة في الخلاط","1 ملعقة كبيرة معجون زنجبيل-ثوم (أو 3 سم زنجبيل + 4 فصوص ثوم، مبشورة معًا)","2 ملعقة كبيرة باف بهاجي ماسالا (ماركة Everest أو MDH) — خلطة التوابل المحددة، لا تستبدل بـ garam masala","1 ملعقة صغيرة فلفل أحمر كشميري (للون الأحمر الأيقوني، حرارة خفيفة)","0.5 ملعقة صغيرة كركم + 1.5 ملعقة صغيرة ملح + 0.5 ملعقة صغيرة فلفل أسود مطحون","1 ليمونة، مقطعة إلى 4 قطع + كزبرة طازجة مفرومة، بسخاء","8 خبزات باف صغيرة وطرية (ladi pav بطراز مومباي، أو استبدل بخبز brioche slider)","50 غ زبدة غير مملحة لتحميص الباف + فلفل أحمر إضافي للرش","للتقديم: بصل أحمر نيء إضافي، كزبرة طازجة، قطع ليمون، 1 فلفل أخضر صغير مفروم ناعم (اختياري)"],"en":["500 g floury potatoes, peeled and cut into 3 cm cubes","250 g cauliflower florets (about 1/2 small head)","100 g green peas (fresh or frozen)","100 g French beans, cut into 1 cm pieces","1 medium carrot (~100 g), diced","100 g unsalted butter (yes — that much, this is street-vendor butter quantities) — divided","2 large red onions (~300 g) — one finely diced for the bhaji, one finely diced raw for the garnish","1 large green bell pepper or capsicum (~150 g), finely diced","4 ripe tomatoes (~500 g), pureed in a blender","1 tbsp ginger-garlic paste (or 3 cm ginger + 4 garlic cloves, grated together)","2 tbsp pav bhaji masala (Everest or MDH brand) — the specific spice blend, do not substitute with garam masala","1 tsp Kashmiri red chili powder (for the iconic red color, mild heat)","0.5 tsp turmeric + 1.5 tsp salt + 0.5 tsp ground black pepper","1 lemon, cut into 4 wedges + chopped fresh coriander (cilantro), generously","8 small soft pav buns (Mumbai-style ladi pav, or substitute with brioche slider buns)","50 g unsalted butter for toasting the pav + extra red chili powder for sprinkling","To serve: extra raw red onion, fresh coriander, lemon wedges, 1 small green chili finely chopped (optional)"],"ro":["500 g cartofi făinoși, curățați și tăiați în cuburi de 3 cm","250 g buchețele de conopidă (aproximativ 1/2 căpățână mică)","100 g mazăre verde (proaspătă sau congelată)","100 g fasole verde franceză, tăiată în bucăți de 1 cm","1 morcov mediu (~100 g), tăiat cubulețe","100 g unt nesărat (da — atât de mult, acestea sunt cantitățile de unt ale vânzătorilor de stradă) — împărțit","2 cepe roșii mari (~300 g) — una tăiată mărunt pentru bhaji, una tăiată mărunt crudă pentru garnitură","1 ardei capia verde mare sau capsicum (~150 g), tăiat mărunt","4 roșii coapte (~500 g), pasate în blender","1 lingură pastă de ghimbir-usturoi (sau 3 cm ghimbir + 4 căței usturoi, răzuiți împreună)","2 linguri pav bhaji masala (marca Everest sau MDH) — amestecul specific de condimente, nu înlocuiți cu garam masala","1 linguriță pudră de chili roșu Kashmiri (pentru culoarea roșie iconică, iuțeală blândă)","0.5 linguriță turmeric + 1.5 linguriță sare + 0.5 linguriță piper negru măcinat","1 lămâie, tăiată în 4 sferturi + coriandru proaspăt (cilantro) tocat, generos","8 chifle pav mici și moi (ladi pav stil Mumbai, sau înlocuiți cu chifle brioche slider)","50 g unt nesărat pentru prăjirea pavului + suplimentar pudră de chili roșu pentru presărat","Pentru servire: ceapă roșie crudă suplimentară, coriandru proaspăt, sferturi de lămâie, 1 ardei iute verde mic tocat mărunt (opțional)"]},"howIsMade":{"ar":"اطبخ الخضار في قدر الضغط: في قدر ضغط (أو قدر كبير) اخلط 500 غ مكعبات بطاطس + 250 غ قرنبيط + 100 غ بازلاء + 100 غ فاصوليا خضراء فرنسية + 100 غ جزر مكعبات + 500 مل ماء + 1 ملعقة صغيرة ملح; اطبخ تحت الضغط 3 صفارات على نار عالية، ثم أطفئ النار واترك الضغط ينطلق طبيعياً (حوالي 15 دقيقة); إذا استخدمت قدراً عادياً، غط واترك يسبح 25–30 دقيقة حتى يصبح كل شيء طرياً بالشوكة; صفّ، مع الاحتفاظ بـ 250 مل من ماء الطهي. اهرس الخضار: بهراسة بطاطس، اهرس الخضار المسلوقة بقوة مباشرة في القدر حتى تحصل على هريسة خشنة — يجب أن تبقى بعض القوام، هذه ليست شوربة ناعمة; اتركها جانباً. أزهر الأرومات: سخّن 50 غ زبدة في مقلاة كبيرة ثقيلة أو kadhai على نار متوسطة حتى تذوب وتتفاعل; أضف 150 غ بصل أحمر مفروم ناعم واطبخ مع التحريك المتكرر 5–6 دقائق حتى يصبح طرياً ومتحولاً إلى ذهبي خفيف على الحواف. زنجبيل-ثوم + فلفل: أضف 1 ملعقة كبيرة معجون زنجبيل-ثوم وحرّك 1 دقيقة حتى تختفي رائحة النيء; أضف 150 غ فلفل أخضر مكعبات واطبخ 3–4 دقائق حتى يطرى قليلاً ولكن لا يزال أخضر زاهٍ. التوابل تزهر: أضف 2 ملعقة كبيرة باف بهاجي ماسالا + 1 ملعقة صغيرة فلفل كشميري + 0.5 ملعقة صغيرة كركم; حرّك 30 ثانية حتى تكون التوابل عطرة بشدة — لا تحرقها، اخفض الحرارة قليلاً عند الحاجة. ابنِ البهاجي: اسكب الطماطم المهروسة + 0.5 ملعقة صغيرة فلفل مطحون + 0.5 ملعقة صغيرة ملح; اطبخ مع التحريك المتكرر 6–8 دقائق حتى تنخفض الطماطم وتبدأ الزبدة بالانفصال حول حواف المقلاة — هذه هي العلامة البصرية أن الماسالا جاهزة; أضف 250 مل ماء الخضار المحفوظ + الخضار المهروسة; حرّك بقوة للدمج. سبح + اهرس أكثر: اسبح البهاجي 10–12 دقيقة، مع التحريك المتكرر والاستمرار في الهرس بهراسة البطاطس مباشرة في المقلاة; يجب أن يصبح البهاجي سميكاً وأحمر داكناً ولامعاً وعطراً بشدة; اضبط التتبيل — يحبه باعة شوارع مومباي مالحاً وحاراً; ادمج 30 غ زبدة إضافية و1 ملعقة كبيرة كزبرة مفرومة; اعصر عصير نصف ليمونة. حمّص الباف وقدّم: قطع 8 خبزات باف أفقياً دون قطعها تماماً (نمط الكتاب); سخّن مقلاة عريضة على نار متوسطة; أضف 30 غ زبدة + رشة باف بهاجي ماسالا + رشة فلفل كشميري، حرّك دائرياً; اضغط خبزات الباف المفتوحة في الزبدة الساخنة وحمّصها 30–60 ثانية لكل جانب حتى تكون ذهبية وعطرة; قدّم فوراً: كومة سخية من البهاجي الساخن مع قطعة زبدة فوقها، بصل أحمر نيء مفروم، كزبرة مفرومة، قطعة ليمون وفلفل أخضر مفروم اختياري; قدم مع 2 باف محمص لكل شخص بجانبها; مزّق الباف، اغمسه في البهاجي، اعصر الليمون فوق كل قضمة — طعام شوارع مومباي في المنزل.","en":"PRESSURE-COOK THE VEGETABLES: in a pressure cooker (or large pot) combine 500 g potato cubes + 250 g cauliflower + 100 g peas + 100 g French beans + 100 g diced carrot + 500 ml water + 1 tsp salt; pressure cook 3 whistles on high, then turn off and let the pressure release naturally (about 15 min); if using a regular pot, cover and simmer 25–30 minutes until everything is fork-tender; drain, RESERVING 250 ml of the cooking water. MASH THE VEGETABLES: with a potato masher, vigorously mash the boiled vegetables right in the pot until you have a coarse purée — some texture should remain, this is NOT a smooth soup; set aside. BLOOM THE AROMATICS: heat 50 g butter in a large heavy skillet or kadhai over medium heat until melted and foaming; add 150 g finely diced red onion and cook stirring often 5–6 minutes until soft and just turning golden at the edges. GINGER-GARLIC + BELL PEPPER: add 1 tbsp ginger-garlic paste and stir 1 minute until the raw smell disappears; add 150 g diced green bell pepper and cook 3–4 minutes until just softened but still bright green. SPICES BLOOM: add 2 tbsp pav bhaji masala + 1 tsp Kashmiri chili powder + 0.5 tsp turmeric; stir 30 seconds until the spices are intensely fragrant — do not burn, lower the heat slightly if needed. BUILD THE BHAJI: pour in the pureed tomatoes + 0.5 tsp ground pepper + 0.5 tsp salt; cook stirring often 6–8 minutes until the tomato has reduced and the butter starts to separate around the edges of the pan — this is the visual sign that the masala is ready; add the reserved 250 ml vegetable water + the mashed vegetables; stir vigorously to combine. SIMMER + MASH MORE: simmer the bhaji 10–12 minutes, stirring frequently and mashing more with a potato masher right in the pan; the bhaji should become thick, dark red, glossy, and intensely fragrant; adjust seasoning — Mumbai street vendors love it salty and spicy; stir in another 30 g butter and 1 tbsp chopped coriander; squeeze in juice of half a lemon. TOAST THE PAV AND SERVE: slice 8 pav buns horizontally without cutting all the way through (book-style); heat a wide skillet over medium heat; add 30 g butter + a pinch of pav bhaji masala + a pinch of Kashmiri chili powder, swirl; press the open pav buns into the hot butter and toast 30–60 seconds per side until golden and fragrant; plate immediately: a generous mound of hot bhaji topped with a knob of butter, chopped raw red onion, chopped coriander, a lemon wedge, and optional chopped green chili; serve with 2 toasted pav per person on the side; tear the pav, dip into the bhaji, squeeze the lemon over each bite — Mumbai street food at home."}},{"id":177,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ar":"فنلندا","en":"Finland","ro":"Finlanda"},"name":{"ar":"يخنة كاريليا","en":"Karelian stew","ro":"Karjalanpaisti"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["400 غ من لحم بقري (chuck)، مقطع إلى مكعبات 3 سم","400 غ كتف خنزير، مقطع إلى مكعبات 3 سم","400 غ كتف خروف، مقطع إلى مكعبات 3 سم (أو لحم رنة في لابلاند)","2 بصل أصفر كبير (~400 غ)، مقطع إلى شرائح سميكة","4 جزر متوسط (~400 غ)، مقطع إلى قطع 3 سم","1 ملعقة صغيرة من حبوب الفلفل الأسود الكاملة","4 ورقات غار","6 حبات عرعر كاملة (التوقيع الفنلندي، صنوبري قليلاً — غير قابل للتفاوض)","6 حبات بهار حلو كاملة","2 ملعقة صغيرة ملح","1 لتر ماء بارد (أو مرق بقري خفيف — تقليديًا الماء)","1 ملعقة كبيرة زيت محايد أو 50 غ زبدة لخطوة التحمير الاختيارية","للتقديم: 800 غ بطاطا جديدة مسلوقة مع الزبدة والشبت، خيار مخلل، مربى التوت البري لينغونبيري (puolukkahillo)، خبز الجاودار الداكن، وكوب من الحليب البارد أو البيرة"],"en":["400 g beef chuck, cubed 3 cm","400 g pork shoulder, cubed 3 cm","400 g lamb shoulder, cubed 3 cm (or reindeer in Lapland)","2 large yellow onions (~400 g), thickly sliced","4 medium carrots (~400 g), cut into 3 cm chunks","1 tsp whole black peppercorns","4 bay leaves","6 whole juniper berries (the Finnish signature, slightly piny — non-negotiable)","6 whole allspice berries","2 tsp salt","1 L cold water (or weak beef stock — traditional is water)","1 tbsp neutral oil OR 50 g butter for the optional searing step","To serve: 800 g boiled new potatoes with butter and dill, pickled cucumber, lingonberry jam (puolukkahillo), dark rye bread, and a glass of cold milk or beer"],"ro":["400 g pulpă de vită (chuck), tăiată în cuburi de 3 cm","400 g spată de porc, tăiată în cuburi de 3 cm","400 g spată de miel, tăiată în cuburi de 3 cm (sau ren în Laponia)","2 cepe galbene mari (~400 g), tăiate în felii groase","4 morcovi medii (~400 g), tăiați în bucăți de 3 cm","1 linguriță boabe întregi de piper negru","4 foi de dafin","6 boabe întregi de ienupăr (semnătura finlandeză, ușor rășinos — non-negociabil)","6 boabe întregi de ienibahar","2 lingurițe sare","1 L apă rece (sau supă slabă de vită — tradițional este apa)","1 lingură ulei neutru SAU 50 g unt pentru pasul opțional de rumenire","Pentru servire: 800 g cartofi noi fierți cu unt și mărar, castravete murat, gem de merișoare lingonberry (puolukkahillo), pâine neagră de secară și un pahar de lapte rece sau bere"]},"howIsMade":{"ar":"سخن الفرن مسبقًا إلى 125 درجة مئوية — الفرن البطيء جدًا هو توقيع Karjalanpaisti، الطبق الذي يحدد قوامه الذائب. قص وقطع إلى مكعبات: قص 400 غ من اللحم البقري + 400 غ من لحم الخنزير + 400 غ من لحم الخروف من أي عصب; قطع إلى مكعبات منتظمة بحجم 3 سم — لا تقطع أصغر; هذا طبخ لمدة 5 ساعات والمكعبات الأكبر تصمد؛ القطع الأصغر تذوب إلى خيوط. اختر أسلوبك — التقليدي: تخطى التحمير; ضع كل شيء نيئًا واترك الفرن يقوم بالعمل، كما فعلت جدات كاريليا لقرون; الحديث: سخن 1 ملعقة كبيرة من الزيت في فرن هولندي على نار عالية، حمر اللحم في 3 دفعات 2 دقيقة لكل جانب لإضافة نكهة ميلارد، ثم أخرجه; كلتا الطريقتين تنتجان نتائج ممتازة. طبق القدر: في فرن هولندي كبير أو طاجن من الحديد الزهر، ابن طبقات متناوبة بهذا الترتيب: اللحم البقري في الأسفل، البصل المقطع، لحم الخنزير، قطع الجزر، لحم الخروف في الأعلى; وزع 4 ورقات غار + 6 حبات عرعر + 6 حبات بهار حلو + 1 ملعقة صغيرة حبوب فلفل + 2 ملعقة صغيرة ملح بين الطبقات — أبدًا فقط في الأعلى. أضف السائل: اسكب 1 لتر ماء بارد (أو مرق بقري خفيف) بحيث يصل إلى منتصف اللحم — لا يغطيه; تطلق اللحوم عصائرها الخاصة أثناء الطهي الطويل وتتركز الصلصة طبيعيًا. أحكم الإغلاق واطهي ببطء: غط بغطاء محكم; انقل إلى الفرن عند 125 درجة مئوية لمدة 4-5 ساعات — نعم خمس ساعات، هذه هي النقطة; لا تفتح الغطاء إلا مرة كل 1.5 ساعة لفحص السائل؛ إذا انخفض بسرعة كبيرة، أضف رشة من الماء الساخن; اللحم جاهز عندما تغوص الشوكة فيه دون جهد. الراحة في الفرن: أطفئ الفرن واترك karjalanpaisti يرتاح في الفرن الدافئ المغلق 30 دقيقة أخرى — تتعمق النكهات ويسترخي اللحم في الصلصة. التقديم: ارفع اللحم الطري إلى أطباق عميقة دافئة; اسكب فوقها العصائر المركزة الشبيهة بالمرق; يمكن أن تبقى حبات العرعر والبهار الحلو للشجعان، أو يتم استخراجها; قدم مع بطاطا جديدة مسلوقة ممزوجة بالزبدة والشبت، خيار مخلل على الجانب، ملعقة سخية من مربى التوت البري (التضاد الحلو-الحامض)، شرائح من خبز الجاودار الداكن، وكوب من الحليب البارد أو البيرة — المرافقة الفنلندية التقليدية للعشاء.","en":"PREHEAT THE OVEN to 125 °C — the very low slow oven is the SIGNATURE of Karjalanpaisti, the dish that defines its melting texture. TRIM AND CUBE: trim 400 g beef + 400 g pork + 400 g lamb of any sinew; cut into uniform 3 cm cubes — DO NOT cut smaller; this is a 5 h cook and larger cubes hold up; smaller pieces dissolve into shreds. CHOOSE YOUR STYLE — TRADITIONAL: skip browning; layer everything raw and let the oven do the work, as Karelian grandmothers have done for centuries; mODERN: heat 1 tbsp oil in a Dutch oven over high heat, brown the meat in 3 batches 2 min per side for added Maillard flavour, then lift out; both methods produce excellent results. LAYER THE POT: in a large Dutch oven or cast-iron casserole, build alternating layers in this order: beef on the bottom, sliced onion, pork, carrot chunks, lamb on top; distribute 4 bay leaves + 6 juniper berries + 6 allspice + 1 tsp peppercorns + 2 tsp salt between the layers — never just on top. ADD LIQUID: pour in 1 L cold water (or weak beef stock) so it comes halfway up the meat — NOT covering; the meats release their own juices during the long cook and the sauce concentrates naturally. SEAL AND SLOW-COOK: cover with a tight-fitting lid; transfer to the 125 °C oven for 4–5 hours — yes, five hours, that is the point; do NOT open the lid except once every 1.5 hours to check the liquid; if reducing too fast, add a splash of hot water; the meat is ready when a fork sinks in effortlessly. REST IN THE OVEN: turn off the oven and let the karjalanpaisti rest in the closed warm oven another 30 minutes — the flavours deepen and the meat relaxes into the sauce. SERVE: lift the tender meat into warm deep plates; spoon over the brothy concentrated juices; the juniper berries and allspice can stay in for the brave, or be fished out; serve with boiled new potatoes tossed in butter and dill, pickled cucumber on the side, a generous dollop of lingonberry jam (the sweet-tart counterpoint), slices of dark rye bread, and a glass of cold milk or beer — the traditional Finnish dinner accompaniment."}},{"id":178,"servings":6,"tipType":"meat","pairingsType":"french","origin":{"ar":"فرنسا","en":"France","ro":"Franța"},"name":{"ar":"بوف بورغينيون","en":"Boeuf Bourguignon","ro":"Boeuf Bourguignon"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["1.5 كغ من لحم بقري (chuck) أو ساق، مقطع إلى مكعبات 4 سم (مع بعض التخطيط الدهني للثراء)","200 غ من اللاردون (لحم خنزير مدخن مقطع 1 سم × 3 سم) أو 200 غ من البيكون السميك مكعبات","750 مل من النبيذ الأحمر البورغندي الكامل القوام (Pinot Noir) — لا تستخدم نبيذًا رخيصًا","200 مل مرق بقري","2 ملعقة كبيرة معجون طماطم","1 بصلة كبيرة (~250 غ)، مقطعة ناعماً للتتبيلة والطبخ","2 جزرة متوسطة (~250 غ)، مقطعة إلى قطع 2 سم","4 فصوص ثوم، مفرومة","30 غ زبدة غير مملحة + 2 ملعقة كبيرة زيت زيتون للتحمير","3 ملاعق كبيرة دقيق متعدد الاستخدامات","1 بوكيه غارني: 3 أغصان زعتر + 2 ورقة غار + 6 سيقان بقدونس مربوطة بخيط مطبخ","250 غ من بصل اللؤلؤ (silverskin)، مقشر","250 غ من فطر الكريميني أو الزر، مقطع نصفين أو أرباع","30 غ زبدة إضافية لتزيين الفطر وبصل اللؤلؤ","1.5 ملعقة صغيرة ملح + 1 ملعقة صغيرة فلفل أسود مطحون طازج","2 ملعقة كبيرة كونياك أو براندي للهب الاختياري","بقدونس أخضر طازج + باغيت + بطاطا جديدة مسلوقة أو شعيرية بالبيض والزبدة للتقديم"],"en":["1.5 kg beef chuck or shin, cubed 4 cm (some marbling for richness)","200 g lardons (smoked pork belly cut 1 cm × 3 cm) OR 200 g thick-cut bacon diced","750 ml full-bodied Burgundy red wine (Pinot Noir) — DO NOT use cheap wine","200 ml beef stock","2 tbsp tomato paste","1 large onion (~250 g), finely diced for the marinade and braise","2 medium carrots (~250 g), cut into 2 cm chunks","4 garlic cloves, minced","30 g unsalted butter + 2 tbsp olive oil for searing","3 tbsp all-purpose flour","1 bouquet garni: 3 thyme sprigs + 2 bay leaves + 6 parsley stems tied with kitchen string","250 g pearl onions (silverskin), peeled","250 g cremini or button mushrooms, halved or quartered","30 g extra butter for the mushroom-and-pearl-onion garnish","1.5 tsp salt + 1 tsp freshly ground black pepper","2 tbsp Cognac OR brandy for optional flambé","Fresh flat-leaf parsley + baguette + boiled new potatoes or buttered egg noodles to serve"],"ro":["1.5 kg pulpă de vită (chuck) sau gambă, tăiată în cuburi de 4 cm (cu ceva marmurare pentru bogăție)","200 g lardoni (piept de porc afumat tăiat 1 cm × 3 cm) SAU 200 g bacon gros tăiat cubulețe","750 ml vin roșu Burgundia robust (Pinot Noir) — NU folosi vin ieftin","200 ml supă de vită","2 linguri pastă de roșii","1 ceapă mare (~250 g), tăiată mărunt pentru marinadă și pentru tocană","2 morcovi medii (~250 g), tăiați în bucăți de 2 cm","4 căței de usturoi, tocați mărunt","30 g unt nesărat + 2 linguri ulei de măsline pentru rumenire","3 linguri făină universală","1 buchet garni: 3 crenguțe cimbru + 2 foi de dafin + 6 cozi de pătrunjel legate cu sfoară de bucătărie","250 g ceapă perlată (silverskin), curățată","250 g ciuperci cremini sau champignon, tăiate în jumătăți sau sferturi","30 g unt suplimentar pentru garnitura de ciuperci și ceapă perlată","1.5 linguriță sare + 1 linguriță piper negru proaspăt măcinat","2 linguri Cognac SAU brandy pentru flambare opțională","Pătrunjel proaspăt cu frunza plată + baghetă + cartofi noi fierți sau tăiței cu unt pentru servire"]},"howIsMade":{"ar":"تتبيل اللحم البقري (قبل 12-24 ساعة، الأمر غير القابل للتفاوض لجوليا تشايلد): ضع 1.5 كغ من اللحم البقري المكعب في وعاء غير تفاعلي مع 750 مل من نبيذ البورغندي الأحمر + 1 بصلة مفرومة + 1 جزرة مفرومة + 4 فصوص ثوم + بوكيه غارني + 1 ملعقة صغيرة فلفل; غط وبرد لمدة 12-24 ساعة; صف من خلال مصفاة، مع الاحتفاظ بالنبيذ; جفف اللحم البقري جيداً بمنشفة ورقية — اللحم الرطب يطبخ بالبخار ولا يتحمر أبداً. تحمير اللاردون: في فرن هولندي ثقيل على نار متوسطة، اطبخ 200 غ من اللاردون لمدة 6-8 دقائق حتى تصبح مقرمشة وذهبية، مع ذوبان الدهن بالكامل; ارفعها بملعقة مثقبة على طبق; اترك 2 ملعقة كبيرة من الدهن في القدر; تحمير اللحم البقري: ارفع الحرارة إلى العالية. أضف 1 ملعقة كبيرة زيت زيتون + 15 غ زبدة; اعمل في 3-4 دفعات دون ازدحام، حمر مكعبات اللحم البقري الجافة لمدة 2-3 دقائق لكل جانب حتى تصبح بنية اللون بعمق من جميع الجوانب — حوالي 8 دقائق لكل دفعة; انقل كل دفعة إلى صينية; القشرة الداكنة الملتصقة بقاع القدر هي أساس النكهة — اتركها. سوفريتو + لهب: قلل الحرارة إلى متوسطة; أضف 250 غ من البصل المقطع + 250 غ من قطع الجزر إلى القدر; اطبخ 5 دقائق حتى تبدأ في الليونة; حرك 4 فصوص ثوم مفرومة + 2 ملعقة كبيرة معجون طماطم واطبخ 1 دقيقة. اسكب 2 ملعقة كبيرة كونياك وأشعل بحذر (تموت اللهب في 30 ثانية); أو تخطى اللهب وأضف الكونياك ببساطة كنزع تزجيج; بناء الطبخ: رش 3 ملاعق كبيرة من الدقيق فوق الخضار وحرك 1 دقيقة لطهي الطعم الخام; اسكب النبيذ المحفوظ ببطء أثناء التحريك، واكشط القاع لرفع القشرة. أضف 200 مل مرق بقري + بوكيه غارني + 1.5 ملعقة صغيرة ملح + 1 ملعقة صغيرة فلفل; أعد اللحم البقري + اللاردون إلى القدر — يجب أن يغطي السائل بالكاد كل شيء; الطبخ البطيء: اجعله يغلي بلطف; غطه بالغطاء المفتوح قليلاً وانقله إلى الفرن عند 160 درجة مئوية (أو اطبخه على الموقد على أدنى حرارة) لمدة 2.5-3 ساعات، مع التحريك كل 45 دقيقة، حتى يصبح اللحم البقري طريًا متفتتًا وتثخن الصلصة لتغطية الملعقة بثراء لامع. تخلص من البوكيه غارني; تزيين بصل اللؤلؤ + الفطر: في مقلاة منفصلة، أذب 15 غ زبدة على نار متوسطة; أضف 250 غ من بصل اللؤلؤ المقشر + 1 ملعقة كبيرة ماء + 1 ملعقة صغيرة سكر + رشة ملح، غط واطبخ 15 دقيقة، ثم اكشف وحمر 5 دقائق حتى تصبح لامعة وذهبية; في نفس المقلاة، أضف 15 غ زبدة أخرى و250 غ من الفطر، اطبخ 6-8 دقائق في دفعتين حتى تصبح بنية ذهبية عميقة — لا تزدحم المقلاة أبدًا. تجميع وتقديم: اطو بصل اللؤلؤ + الفطر في الطبخ; سخن معاً 5 دقائق; تذوق واضبط الملح; اترك الطبخ يرتاح 10 دقائق خارج النار — تتعمق النكهات بشكل كبير. قدم حصصاً سخية في أطباق عميقة فوق بطاطا جديدة مسلوقة (أو شعيرية بالبيض والزبدة)، مع باغيت مقرمش لمسح الصلصة، مرشوش بالبقدونس الطازج المفروم; دائمًا أفضل في اليوم التالي — تتزاوج النكهات طوال الليل; اشرب زجاجة من نفس البورغندي الذي طبخت به.","en":"Place 1.5 kg cubed beef in a non-reactive bowl with the 750 ml red Burgundy, 1 chopped onion, 1 chopped carrot, 4 garlic cloves, the bouquet garni and 1 tsp pepper, then cover and refrigerate for 12-24 hours; drain through a sieve while reserving the wine, and pat the beef very dry with paper towel so it sears rather than steams. In a heavy Dutch oven over medium heat, cook 200 g lardons for 6-8 minutes until crisp and golden and the fat is fully rendered, then lift them out with a slotted spoon and leave 2 tbsp of rendered fat behind in the pot. Raise the heat to high and add 1 tbsp olive oil plus 15 g butter, then sear the dried beef cubes in 3-4 uncrowded batches for 2-3 minutes per side (about 8 minutes per batch) until deeply browned on all sides; transfer each batch to a tray and leave the dark fond stuck to the pot as your flavour base. Reduce the heat to medium, add 250 g diced onion and 250 g carrot chunks and cook 5 minutes until starting to soften, then stir in 4 minced garlic cloves and 2 tbsp tomato paste and cook 1 minute; pour in 2 tbsp Cognac and ignite carefully (the flames die in 30 seconds), or skip the flambe and simply use the Cognac to deglaze. Sprinkle 3 tbsp flour over the vegetables and stir for 1 minute to cook out the raw taste, then pour in the reserved wine slowly while scraping the bottom to lift the fond, add 200 ml beef stock, the bouquet garni, 1.5 tsp salt and 1 tsp pepper, and return the beef and lardons to the pot so the liquid barely covers everything. Bring to a gentle simmer, cover with the lid slightly ajar and transfer to a 160 °C oven (or simmer on the lowest stovetop heat) for 2.5-3 hours, stirring every 45 minutes until the beef is fall-apart tender and the sauce has thickened to a glossy coats-the-spoon consistency; discard the bouquet garni. In a separate skillet, melt 15 g butter over medium heat, add 250 g peeled pearl onions with 1 tbsp water, 1 tsp sugar and a pinch of salt, cover and cook 15 minutes, then uncover and brown 5 minutes until glossy and golden; in the same skillet add another 15 g butter and 250 g mushrooms and saute 6-8 minutes in 2 batches until deeply golden brown, never crowding the pan. Fold the pearl onions and mushrooms into the braise and warm together 5 minutes, then taste and adjust the salt and let the braise rest 10 minutes off the heat so the flavours deepen; serve generous portions in deep plates over boiled new potatoes (or buttered egg noodles), scatter with chopped fresh flat-leaf parsley and offer crusty baguette to mop up the sauce -- it is always better the next day, and pairs perfectly with a bottle of the same Burgundy you cooked with."}},{"id":179,"servings":2,"tipType":"veg","pairingsType":"middle-eastern","origin":{"ar":"تونس","en":"Tunisia","ro":"Tunisia"},"name":{"ar":"شكشوكة","en":"Chakchouka","ro":"Chakchouka"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["4 بيضات كبيرة بدرجة حرارة الغرفة","4 ملاعق كبيرة زيت زيتون بكر ممتاز (تونسي أو متوسطي)","1 بصلة صفراء متوسطة (~150 غ)، مفرومة ناعماً","2 فلفل أحمر حلو معتدل (~300 غ)، منزوع البذور ومقطع إلى مكعبات 1 سم","1 فلفل أحمر حار صغير مفروم ناعماً أو 1 ملعقة صغيرة من معجون الهريسة التونسية (الخيار الأكثر تقليدية)","4 فصوص ثوم، مفرومة","1 ملعقة صغيرة كمون مطحون (kamoun) — قاعدة التوابل الدافئة","1 ملعقة صغيرة كراوية مطحونة (karwiya) — التابل الدافئ المميز لتونس، وليست هي نفسها الكمون رغم التشابه في المظهر؛ استبدلها بحبة الشمر إذا لم تتوفر","1 ملعقة صغيرة بابريكا حلوة","0.5 ملعقة صغيرة كزبرة مطحونة","400 غ طماطم مهروسة معلبة (أو 4 حبات طماطم ناضجة مقشرة ومبشورة)","1 ملعقة كبيرة معجون طماطم للقوام","1 ملعقة صغيرة ملح + 0.5 ملعقة صغيرة فلفل أسود طازج مطحون + رشة سكر لموازنة الحموضة","60 غ جبنة من نوع الفيتا (تونسية أو بلغارية، مفتتة، اختيارية) + بقدونس طازج بأوراق عريضة + كزبرة + شرائح ليمون + باغيت طازج أو خبز طابونة تونسي للتقديم"],"en":["4 large eggs at room temperature","4 tbsp extra-virgin olive oil (Tunisian or Mediterranean)","1 medium yellow onion (~150 g), finely diced","2 mild red bell peppers (~300 g), seeded and cut into 1 cm dice","1 small red chili finely chopped OR 1 tsp Tunisian harissa paste (the more traditional choice)","4 garlic cloves, minced","1 tsp ground cumin (kamoun) — the warm spice base","1 tsp ground caraway (karwiya) — Tunisia's DEFINING warm spice, NOT the same as cumin despite looking similar; substitute fennel seed if unavailable","1 tsp sweet paprika","0.5 tsp ground coriander","400 g can crushed tomatoes (or 4 ripe tomatoes peeled and grated)","1 tbsp tomato paste for body","1 tsp salt + 0.5 tsp freshly ground black pepper + a pinch of sugar to balance acidity","60 g feta-style cheese (Tunisian or Bulgarian-style, crumbled, optional) + fresh flat-leaf parsley + cilantro + lemon wedges + fresh baguette or Tunisian khobz tabouna to serve"],"ro":["4 ouă mari la temperatura camerei","4 linguri ulei de măsline extravirgin (tunisian sau mediteranean)","1 ceapă galbenă medie (~150 g), tăiată mărunt","2 ardei graşi roşii blânzi (~300 g), curăţaţi de seminţe şi tăiaţi în cuburi de 1 cm","1 ardei iute roşu mic tocat mărunt SAU 1 linguriţă pastă de harissa tunisiană (alegerea mai tradiţională)","4 căţei de usturoi, tocaţi mărunt","1 linguriţă chimion măcinat (kamoun) — baza de mirodenii calde","1 linguriţă chimen măcinat (karwiya) — mirodenia caldă DEFINITORIE a Tunisiei, NU acelaşi lucru cu chimionul deşi arată asemănător; înlocuieşte cu sămânţă de fenicul dacă nu este disponibil","1 linguriţă boia dulce","0.5 linguriţă coriandru măcinat","400 g roşii zdrobite la cutie (sau 4 roşii coapte decojite şi rase)","1 lingură pastă de roşii pentru corp","1 linguriţă sare + 0.5 linguriţă piper negru proaspăt măcinat + un vârf de zahăr pentru echilibrul acidităţii","60 g brânză tip feta (tunisiană sau bulgărească, sfărâmată, opţional) + pătrunjel proaspăt cu frunza lată + coriandru + felii de lămâie + baghetă proaspătă sau khobz tabouna tunisian pentru servire"]},"howIsMade":{"ar":"حضّر العناصر العطرية: الشكشوكة تطبخ بسرعة — التحضير المسبق غير قابل للتفاوض; قطّع 150 غ من البصل + 300 غ من الفلفل الأحمر الحلو + 1 فلفل أحمر حار; افرم 4 فصوص ثوم; قس رباعي التوابل — كمون + كراوية + بابريكا + كزبرة — في وعاء صغير; الكراوية هي ما يجعل هذه تونسية وليست شكشوكة إسرائيلية أو شامية. سخّن الزيت: سخّن 4 ملاعق كبيرة زيت زيتون في مقلاة ثقيلة 24 سم (الحديد الزهر مثالي — طاجين فخاري هو الأكثر تقليدية تونسياً) على نار متوسطة حتى يلمع. SOFFRITTO: أضف 150 غ من البصل المقطع مع رشة ملح واطبخ 6–8 دقائق حتى يصبح ليناً جداً وشفافاً — وليس بنياً; الشكشوكة التونسية تريد حلاوة البصل المعرق ببطء، وليس الكراميل. الفلفل + الحار + الثوم: أضف 300 غ من الفلفل الأحمر الحلو المقطع + 1 فلفل أحمر حار مفروم (أو 1 ملعقة صغيرة هريسة); اطبخ 6–8 دقائق حتى يلين الفلفل ولكن يبقى أحمر زاهياً; أضف 4 فصوص ثوم مفرومة واطبخ دقيقة واحدة حتى يصبح عطرياً. زهّر التوابل: أضف خليط التوابل (1 ملعقة صغيرة كمون + 1 ملعقة صغيرة كراوية + 1 ملعقة صغيرة بابريكا + 0.5 ملعقة صغيرة كزبرة) مباشرة في قاعدة الزيت والخضروات الساخنة; حرّك 30 ثانية حتى يصبح عطرياً بشكل مكثف — لا تحرق، أو يصبح الطبق مراً. ابنِ الصلصة: حرّك 1 ملعقة كبيرة معجون طماطم واطبخ دقيقة واحدة; صب 400 غ طماطم مهروسة + 1 ملعقة صغيرة ملح + 0.5 ملعقة صغيرة فلفل + رشة سكر; اطبخ على نار هادئة 8–10 دقائق، مع التحريك من حين لآخر، حتى تتكاثف الصلصة — يجب أن تترك ملعقة مسحوبة عبر السطح أثراً واضحاً لا يمتلئ فوراً. أضف البيض: بظهر ملعقة، اصنع 4 آبار في الصلصة المغلية; اكسر 1 بيضة في كل بئر — احتفظ بصفار البيض سليماً; رش رشة ملح على البياض ولفّة فلفل على الصفار; غطّ المقلاة بغطاء واطبخ على نار متوسطة-منخفضة 4–6 دقائق، حتى يتماسك البياض بالكاد ولكن يبقى الصفار سائلاً — ألقِ نظرة من خلال الغطاء؛ يجب أن يكون البياض معتماً والصفار لا يزال برتقالياً زاهياً ومرتعشاً. أنهِ وقدّم: انثر 60 غ من جبنة الفيتا المفتتة + حفنة كريمة من البقدونس والكزبرة المفرومة فوقها; أحضر المقلاة مباشرة إلى الطاولة — الشكشوكة دائماً جماعية، تؤكل من المقلاة; كل ضيف يمزق قطعة من باغيت طازج أو خبز طابونة ويستخدمها لمسح الصلصة وكسر صفار; اعصر شريحة ليمون فوق حصتك; الأفضل خلال 10 دقائق من الطهي، بينما لا يزال الصفار مذاباً.","en":"PREP THE AROMATICS: chakchouka cooks fast — mise-en-place is non-negotiable; dice 150 g onion + 300 g red bell peppers + 1 red chili; mince 4 garlic; measure the spice quartet — cumin + caraway + paprika + coriander — into a small bowl; the caraway is what makes this Tunisian and not Israeli or Levantine shakshuka. WARM THE OIL: heat 4 tbsp olive oil in a heavy 24 cm skillet (cast iron is ideal — earthenware tagine is the most traditional Tunisian) over medium heat until shimmering. SOFFRITTO: add 150 g diced onion with a pinch of salt and cook 6–8 min until very soft and translucent — NOT browned; tunisian chakchouka wants the sweetness of slowly-sweated onions, not caramelization. PEPPERS + CHILI + GARLIC: add 300 g diced red bell peppers + 1 chopped red chili (or 1 tsp harissa); cook 6–8 min until peppers are softened but still bright red; add 4 minced garlic and cook 1 min until fragrant. BLOOM THE SPICES: add the spice mix (1 tsp cumin + 1 tsp caraway + 1 tsp paprika + 0.5 tsp coriander) directly into the hot oil-and-vegetable base; stir 30 seconds until intensely aromatic — do not burn, or the dish turns bitter. BUILD THE SAUCE: stir in 1 tbsp tomato paste and cook 1 min; pour in 400 g crushed tomatoes + 1 tsp salt + 0.5 tsp pepper + a pinch of sugar; simmer 8–10 min, stirring occasionally, until the sauce has thickened — a spoon dragged through the surface should leave a clear trail that does not immediately fill back in. ADD EGGS: with the back of a spoon, make 4 wells in the simmering sauce; crack 1 egg into each well — keep yolks intact; sprinkle a pinch of salt over the whites and a twist of pepper over the yolks; cover the skillet with a lid and cook over medium-low heat 4–6 min, until the whites are just set but the yolks remain runny — peek through the lid; the whites should be opaque and the yolks still bright orange and trembling. FINISH AND SERVE: scatter 60 g crumbled feta + a generous handful of chopped parsley and cilantro over the top; bring the pan straight to the table — chakchouka is always communal, eaten from the skillet; each diner tears off a piece of fresh baguette or khobz tabouna and uses it to mop up the sauce and break into a yolk; squeeze a lemon wedge over your own portion; best within 10 minutes of cooking, while the yolks are still molten."}},{"id":180,"origin":{"ar":"اليابان","en":"Japan","ro":"Japonia"},"name":{"ar":"أوكونومياكي","en":"Okonomiyaki","ro":"Okonomiyaki"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"japanese","ingredients":{"ar":["200غ دقيق عادي (أو دقيق الحلويات)","240مل مرق داشي بارد (أو ماء + ملعقة صغيرة داشي مسحوق)","بيضتان كبيرتان","400غ ملفوف أبيض مقطّع ناعم","200غ كرش الخنزير مقطّع شرائح رفيعة (بوتا بارا)، قطّعه 5 سم","2 ملعقة كبيرة تينكاسو (فتات التيمبورا، اختياري)","½ ملعقة صغيرة بيكنج باودر","4 ملاعق كبيرة مايونيز ياباني (كيوبي)","4 ملاعق كبيرة صوص أوكونومياكي (ماركة أوتافوكو)","1 ملعقة صغيرة صوص ورشستر","كاتسوبوشي (نشارة التونة المجففة) للتقديم","أونوري (مسحوق الأعشاب البحرية) للتقديم"],"en":["200g plain flour (or cake flour)","240ml cold dashi stock (or water + 1 tsp dashi powder)","2 large eggs","400g white cabbage, finely shredded","200g thinly sliced pork belly (buta bara), cut into 5 cm pieces","2 tbsp tenkasu (tempura scraps, optional)","½ tsp baking powder","4 tbsp Japanese mayonnaise (Kewpie)","4 tbsp okonomiyaki sauce (e.g. Otafuku brand)","1 tsp Worcestershire sauce","katsuobushi (dried bonito flakes) to serve","aonori (powdered seaweed) to serve"],"ro":["200g făină albă simplă (sau făină pentru prăjituri)","240ml supă dashi (rece; sau apă + 1 linguriță pudră dashi)","2 ouă mari","400g varză albă, tăiată fin","200g burta de porc feliată subțire (buta bara), tăiată în bucăți de 5 cm","2 linguri tenkasu (firimituri de tempura, opțional)","½ linguriță praf de copt","4 linguri maioneză Kewpie (japoneză)","4 linguri sos okonomiyaki (ex. Otafuku)","1 linguriță sos Worcestershire","katsuobushi (fulgi de ton uscat), pentru servire","aonori (alge marine pudră), pentru servire"]},"howIsMade":{"ar":"في وعاء كبير اخلط الدقيق ومسحوق الخبز والبيض وداشي البارد حتى يتجانس دون إفراط في الخلط. أضف الملفوف والتينكاسو بحركات طي خفيفة؛ يجب أن يكون العجين كثيفاً. سخّن مقلاة لا تلتصق على نار متوسطة وادهنها بزيت خفيف. اسكب العجين ورتّبه على شكل دائرة بسماكة ~2 سم. رتّب شرائح بطن الخنزير فوق كامل السطح. اطبخ 5–6 دقائق على نار متوسطة منخفضة حتى تتماسك الحواف ويصبح القاع ذهبياً. اقلب بحذر باستخدام ملعقتين مع ضغط خفيف؛ اطبخ 5–6 دقائق أخرى حتى يصبح اللحم مقرمشاً. ادهن الجانب اللحمي بصوص الأوكونومياكي، ورّع المايونيز بشكل متعرج، ورشّ الكاتسوبوشي والأونوري. قدّم فوراً.","en":"In a large bowl whisk together flour, baking powder, eggs, and cold dashi until just combined — do not overmix. Fold in shredded cabbage and tenkasu with a spatula; the batter should be thick and mounded with cabbage. Heat a non-stick pan over medium heat, brush with a thin layer of oil. Pour batter into the pan and shape into a disc about 2 cm thick. Lay pork belly slices over the entire top surface. Cook 5–6 minutes on medium-low until the edges look set and the underside is golden-brown. Flip carefully using two spatulas, pressing lightly; cook another 5–6 minutes until pork is crisp and batter is cooked through. Brush the pork side with okonomiyaki sauce, drizzle Kewpie in a zigzag, scatter katsuobushi and aonori. Serve immediately from the pan."}},{"id":181,"servings":2,"tipType":"meat","timeMins":{"total":780,"active":120},"pairingsType":"japanese","origin":{"ar":"اليابان","en":"Japan","ro":"Japonia"},"name":{"ar":"رامن تونكوتسو","en":"Tonkotsu Ramen","ro":"Ramen Tonkotsu"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["1.2 كجم عظام نخاع الخنزير، مسلوقة","300غ نودلز رامن رفيعة طازجة","3 ملاعق كبيرة صلصة صويا داكنة (للتاري)","2 ملعقة كبيرة ميرين","200غ بطن الخنزير تشاشو، مقطعة بسماكة 1 سم","بيضتان رامن مسلوقتان ناعمتان، مقطوعتان نصفين","80غ براعم الخيزران (مينما)، مصفاة","ورقتان نوري، مقطوعتان نصفين","2 بصل أخضر مقطع رقيقاً","4 فصوص ثوم مسحوقة","30غ زنجبيل طازج مقشر ومقطع شرائح","1 ملعقة صغيرة زيت سمسم محمص"],"en":["1.2kg pork marrow bones, blanched","300g fresh thin ramen noodles","3 tbsp dark soy sauce (for tare)","2 tbsp mirin","200g chashu pork belly, sliced 1cm thick","2 soft-boiled ramen eggs, halved","80g bamboo shoots (menma), drained","2 sheets nori, halved","2 spring onions, thinly sliced","4 cloves garlic, crushed","30g fresh ginger, peeled and sliced","1 tsp toasted sesame oil"],"ro":["1,2 kg oase de porc (măduvă), opărite","300g tăiței ramen proaspeți subțiri","3 linguri sos de soia închis (pentru tare)","2 linguri mirin","200g burtă de porc chashu, feliată la 1 cm grosime","2 ouă ramen fierte moale, tăiate în jumătate","80g lăstari de bambus (menma), scurși","2 foi alge nori, tăiate în jumătate","2 cepe verzi, feliate subțire","4 căței usturoi, zdrobiți","30g ghimbir proaspăt, curățat și feliat","1 linguriță ulei de susan prăjit"]},"howIsMade":{"ar":"اسلق العظام في الماء المغلي 10 دقائق، صفّها واشطفها بالماء البارد. انقلها إلى قدر كبير مع 3 لترات ماء بارد، أحضره إلى غليان قوي وحافظ عليه 10–12 ساعة مضيفاً ماء عند الحاجة؛ الغليان القوي يبيّض المرق. الف بطن الخنزير وثبّته، احمّره من كل الجهات في مقلاة جافة، ثم اطهه على أدنى نار في 3 ملاعق صويا و2 ملعقة ميرين و1 ملعقة ساكي و100مل ماء لمدة 90 دقيقة؛ أرحه 20 دقيقة ثم قطّعه 1 سم. التاري: 4 ملاعق صويا + 2 ميرين، اغلِ 3 دقائق وبرّد. اسلق النودلز وصفّها. 2 ملعقة تاري في كل وعاء، 400مل مرق ساخن، ثم التشاشو والبيضة والخيزران والنوري والبصل ورذاذ زيت السمسم.","en":"Blanch pork bones in boiling water for 10 minutes, drain and rinse under cold water. Transfer to a large pot with 3L cold water, bring to a rolling boil and hold it there — not a simmer — for 10 to 12 hours, topping up with water as needed; the hard boil breaks down collagen and turns the broth white. Roll pork belly tightly, tie with kitchen string, sear all sides in a dry pan, then braise in 3 tbsp soy sauce, 2 tbsp mirin, 1 tbsp sake and 100ml water on the lowest heat for 90 minutes; rest 20 minutes, slice 1cm thick. Make tare: 4 tbsp soy sauce + 2 tbsp mirin, simmer 3 minutes, cool. Cook noodles per packet, drain. Spoon 2 tbsp tare into each bowl, ladle 400ml hot broth, then top with chashu slices, halved egg, bamboo shoots, nori and spring onion. Finish with sesame oil."}},{"id":182,"servings":2,"tipType":"meat","timeMins":{"total":360,"active":90},"pairingsType":"japanese","origin":{"ar":"اليابان","en":"Japan","ro":"Japonia"},"name":{"ar":"رامن شويو","en":"Shoyu Ramen","ro":"Ramen Shoyu"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"ingredients":{"ar":["1.5 لتر مرق عظام الدجاج","2 ملعقة كبيرة صلصة صويا","1 ملعقة كبيرة ميرين","1 ملعقة كبيرة ساكي","400غ بطن الخنزير ملفوف ومربوط","4 بيضات كبيرة","300غ نودلز رامن طازجة","100غ براعم خيزران (مينما) مشطوفة","4 أوراق نوري","3 بصل أخضر مقطع رقيقاً","4 شرائح كعكة السمك ناروتوماكي","1 ملعقة صغيرة زيت سمسم"],"en":["1.5L chicken bone stock","2 tbsp soy sauce","1 tbsp mirin","1 tbsp sake","400g pork belly, rolled and tied with kitchen string","4 large eggs","300g fresh ramen noodles","100g bamboo shoots (menma), rinsed","4 sheets nori","3 spring onions, thinly sliced","4 slices narutomaki fish cake","1 tsp sesame oil"],"ro":["1,5 L supă de oase de pui","2 linguri sos de soia","1 lingură mirin","1 lingură sake","300g burtă de porc, rulată și legată","4 ouă mari","300g tăiței ramen proaspeți","100g lăstari de bambus (menma), clătiți","4 foi alge nori","3 cepe verzi, feliate subțire","4 felii pastă de pește narutomaki","1 linguriță ulei de susan"]},"howIsMade":{"ar":"اغلِ مرق العظام مع الزنجبيل والثوم والبصل الأخضر 3–4 ساعات ثم صفّه. اخلط صلصة الصويا والميرين والساكي في إناء صغير واغلِهم 5 دقائق لتبخّر الكحول — هذا هو شويو تاري. الف بطن الخنزير وثبّتها، احمرّها من كل الجهات على نار عالية، ثم اطهِها على نار خافتة مع صلصة صويا وميرين وساكي وماء لمدة 1.5 ساعة؛ أرِحها 15 دقيقة قبل التقطيع. اسلق البيض ضبط 6.5 دقيقة، بردّها وقشّرها وانقعها في سائل الطهي لمدة 4 ساعات على الأقل. اسلق النودلز وصفّها؛ صبّ المرق الساخن في الأوعية (ملعقتان كبيرتان تاري لكل وعاء)، ضع النودلز وقدّم مع التشاشو والبيضة المنصّفة وبراعم الخيزران والنوري والبصل الأخضر والناروتوماكي ورشة زيت سمسم.","en":"Simmer chicken bone stock with a 5cm piece of ginger, 3 garlic cloves and 2 spring onions for 3–4 hours, strain and discard solids. Mix soy sauce, mirin and sake in a small pan, simmer 5 minutes to cook off the alcohol — this is the shoyu tare. Roll pork belly tightly, tie with kitchen string, sear on all sides in a hot pan, then braise in 3 tbsp soy sauce, 2 tbsp mirin, 1 tbsp sake and 100ml water on low heat for 1.5 hours; rest 15 minutes before slicing into 1cm rounds. Soft-boil eggs exactly 6.5 minutes, cool in cold water, peel and submerge in the remaining chashu braising liquid for at least 4 hours. Cook noodles per packet, drain; ladle hot broth into bowls (2 tbsp shoyu tare per bowl), add noodles and top with sliced chashu, halved egg, bamboo shoots, nori, spring onions, narutomaki and a drizzle of sesame oil."}},{"id":183,"servings":2,"tipType":"def","pairingsType":"japanese","origin":{"ar":"اليابان","en":"Japan","ro":"Japonia"},"name":{"ar":"رامن ميسو","en":"Miso Ramen","ro":"Ramen Miso"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"ingredients":{"ar":["1.5 لتر مرق عظام الدجاج أو الخنزير","3 ملاعق كبيرة معجون ميسو أحمر أو أبيض","300غ نودلز رامن طازجة","150غ لحم خنزير مفروم","80غ ذرة معلبة مصفاة","1 ملعقة كبيرة زبدة غير مملحة","60غ براعم الخيزران مصفاة ومقطعة شرائح","بيضتان رامن مسلوقتان ناعمتان متبّلتان مقطوعتان نصفين","ورقتان نوري مقطوعتان نصفين","2 بصل أخضر مقطع","1 ملعقة صغيرة بذور سمسم محمصة","80غ براعم فاصوليا طازجة مسلوقة"],"en":["1.5L chicken or pork bone broth","3 tbsp red or white miso paste","300g fresh ramen noodles","150g ground pork","80g canned corn kernels, drained","1 tbsp unsalted butter","60g bamboo shoots, drained and sliced","2 soft-boiled ramen eggs, halved","2 sheets nori, halved","2 spring onions, sliced","1 tsp toasted sesame seeds","80g fresh bean sprouts, blanched"],"ro":["1,5L supă de oase de pui sau porc","3 linguri pastă miso roșu sau alb","300g tăiței ramen proaspeți","150g carne tocată de porc","80g porumb din conservă, scurs","1 lingură unt nesărat","60g lăstari de bambus, scurși și feliați","2 ouă fierte moale, marinate, tăiate în jumătate","2 foi alge nori, tăiate în jumătate","2 cepe verzi, feliate","1 linguriță semințe de susan prăjit","80g muguri de fasole proaspeți, opăriți"]},"howIsMade":{"ar":"قلي الثوم ولحم الخنزير المفروم في المقلاة الصينية على نار عالية مع تفتيت اللحم حتى لا يبقى لون وردي. أضف معجون الميسو وقلّب 60 ثانية حتى يتحمص قليلاً. صبّ المرق الساخن وأحضره إلى غليان خفيف — لا تغلِ بقوة بعد إضافة الميسو. أضف الزبدة وحرّك حتى تذوب. اطبخ النودلز منفصلاً وصفّها. وزّع النودلز على وعاءين وصبّ مرق الميسو فوقها. زيّن بالذرة وبراعم الفاصوليا والبيضة المتبلة والخيزران والنوري والبصل الأخضر. انثر السمسم في النهاية.","en":"Sauté garlic and ground pork in a wok over high heat, breaking up the meat as it cooks, until no pink remains. Add miso paste and stir-fry 60 seconds until it darkens slightly. Pour in hot broth and bring to a low simmer — do not boil hard once miso is in or it loses its fermented edge. Add butter and stir until melted. Cook noodles per packet, drain. Divide noodles between two bowls, ladle miso broth over. Top with corn, bean sprouts, halved ramen egg, bamboo shoots, nori and spring onion. Scatter sesame seeds last."}},{"id":184,"servings":4,"tipType":"def","pairingsType":"japanese","nutrition":{"cal":480,"prot":22,"carb":38,"fat":26,"fib":3},"origin":{"ar":"اليابان","en":"Japan","ro":"Japonia"},"name":{"ar":"تيمبورا","en":"Tempura","ro":"Tempura"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["400 غ قريدس كبير (8–12 برأسه، مقشّر مع الذيل)، يُزال خيطه الأسود ويُجفّف تماماً","1 بطاطا حلوة يابانية صغيرة (~200 غ)، مقشّرة ومقطّعة شرائح 5 مم","200 غ قرع كابوتشا، مقطّع أنصاف أهلّة 5 مم (مع القشرة)","1 باذنجان ياباني، مقطّع مائلاً شرائح 1 سم","6 فطر شيتاكي طازج، تُزال السيقان ويُحزّ السطح بشكل X","100 غ فلفل شيشيتو أو فلفل أخضر رفيع، تُثقَب كل قطعة بشوكة كي لا تنفجر","للخليط (يُمزج آخر شيء قبل القلي مباشرة): 1 بيضة كبيرة، 250 مل ماء غازي مثلج، 150 غ دقيق عادي منخول","30 غ دقيق إضافي لرشّ القطع قبل غمسها بالخليط","1.5 لتر زيت نباتي محايد للقلي العميق (زيت نخالة الأرز أو نباتي)","لصلصة التنتسويو: 200 مل داشي، 60 مل صلصة صويا، 60 مل ميرين","30 غ دايكون مبشور ناعماً مع عصره قليلاً","10 غ زنجبيل طازج، مبشور ناعماً","ملح بحري ناعم وشرائح ليمون للتقديم"],"en":["400 g large prawns (8–12 head-on, peeled but tails on), deveined and patted bone-dry","1 small Japanese sweet potato (~200 g), peeled and cut into 5 mm rounds","200 g kabocha squash, cut into 5 mm half-moons (skin left on)","1 Japanese eggplant, cut on the bias into 1 cm slices","6 fresh shiitake mushrooms, stems trimmed, caps scored with an X","100 g shishito or thin green peppers, each pricked with a fork so they don't burst","For the batter (mix LAST, just before frying): 1 large egg, 250 ml ice-cold sparkling water, 150 g plain (cake) flour, sifted","30 g extra plain flour for dusting the pieces before dipping","1.5 L neutral oil for deep-frying (rice bran or vegetable)","For the tentsuyu dipping sauce: 200 ml dashi, 60 ml soy sauce, 60 ml mirin","30 g daikon, finely grated and lightly squeezed","10 g fresh ginger, finely grated","Fine sea salt and lemon wedges, to serve"],"ro":["400 g creveți mari (8–12 bucăți cu cap, decojiți dar cu coadă), curățați de vinișor și șterși bine de umiditate","1 cartof dulce japonez mic (~200 g), curățat și tăiat rondele de 5 mm","200 g dovleac kabocha, tăiat semilune de 5 mm (cu coajă)","1 vânătă japoneză, tăiată oblic în felii de 1 cm","6 ciuperci shiitake proaspete, fără picioare, capul crestat în X","100 g ardei shishito sau ardei verzi subțiri, fiecare înțepat cu furculița ca să nu plesnească","Pentru aluat (se amestecă LA FINAL, chiar înainte de prăjit): 1 ou mare, 250 ml apă minerală foarte rece, 150 g făină simplă cernută","30 g făină simplă suplimentară pentru pudrat bucățile înainte de înmuierea în aluat","1.5 L ulei neutru pentru prăjit (de orez sau vegetal)","Pentru sosul tentsuyu: 200 ml dashi, 60 ml sos de soia, 60 ml mirin","30 g daikon, ras fin și stors ușor","10 g ghimbir proaspăt, ras fin","Sare fină de mare și felii de lămâie, pentru servit"]},"howIsMade":{"ar":"نشّف القريدس والخضار جيداً، ثم اعمل ثلاث شقوق سطحية تحت بطن كل قريدسة واضغط برفق على ظهرها لتُقلى مستقيمة بدل أن تنثني.\n\nللتنتسويو، اغلِ الداشي وصلصة الصويا والميرين لحظات لتطاير الكحول، ووزّعه في أوعية صغيرة، واترك الدايكون والزنجبيل المبشورين إلى جانبه.\n\nسخّن الزيت في قدر ثقيل إلى 175°م، مقاساً بمقياس حرارة.\n\nقبل القلي مباشرة، اخفق البيضة مع الماء الغازي المثلج في وعاء بارد، أضف الدقيق المنخول دفعةً واحدة وحرّك من خمس إلى ثماني حركات فقط — يجب أن يبقى في الخليط آثار دقيق جاف.\n\nمرّر كل قطعة في الدقيق الإضافي خفيفاً، اغمسها في الخليط ثم ضع أربعاً أو خمساً منها في الزيت دفعةً واحدة؛ القريدس والشيتاكي يحتاجان نحو 90 ثانية، والباذنجان والكابوتشا دقيقتين، والبطاطا الحلوة 3 دقائق، والشيشيتو دقيقة واحدة، ويجب أن تظل القشرة عاجية شاحبة.\n\nانقلها إلى شبكية فوق ورق، وقدّمها فوراً مع التنتسويو وتُحرَّك معه الدايكون والزنجبيل، أو الخضار مع رشة ملح ناعم وقطرة ليمون.","en":"Pat the prawns and vegetables completely dry, then make three shallow cuts on the underside of each prawn and press gently along the spine so they fry straight rather than curling.\n\nFor the tentsuyu, bring the dashi, soy sauce and mirin briefly to a simmer to cook off the alcohol, then divide between small dipping bowls and set the grated daikon and ginger alongside.\n\nHeat the oil in a heavy pot to 175°C, measured with a probe thermometer.\n\nJust before frying, beat the egg into the ice-cold sparkling water in a chilled bowl, tip in the sifted flour all at once and stir only five to eight strokes — the batter should still show streaks of dry flour.\n\nDust each piece lightly with the extra flour, dip into the batter, and slip into the oil four or five at a time; prawns and shiitake take about 90 seconds, eggplant and kabocha 2 minutes, sweet potato 3 minutes, shishito a minute, and the crust should stay pale ivory.\n\nLift onto a wire rack set over paper and serve straight away, with the tentsuyu, daikon and ginger to stir in, or the vegetables with a pinch of fine salt and a squeeze of lemon."}},{"id":185,"servings":4,"tipType":"def","pairingsType":"japanese","nutrition":{"cal":280,"prot":7,"carb":52,"fat":4,"fib":2},"origin":{"ar":"اليابان","en":"Japan","ro":"Japonia"},"name":{"ar":"أونيغيري","en":"Onigiri","ro":"Onigiri"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"ingredients":{"ar":["500 غ أرز ياباني قصير الحبة (Koshihikari أو أرز سوشي)","600 مل ماء بارد طازج للطهي (نسبة الأرز إلى الماء ~1:1.1)","للتزو (ماء الأصابع): 200 مل ماء دافئ + 1.5 ملعقة صغيرة ملح بحري ناعم","4 أوراق نوري محمصة، مقطّعة شرائط بعرض حوالي 3 سم × طول الورقة","الحشوة 1 — تونة بالمايونيز: 80 غ تونة معلّبة مصفّاة، 1.5 ملعقة كبيرة مايونيز ياباني، ½ ملعقة صغيرة صلصة صويا","الحشوة 2 — أوميبوشي: 60 غ خوخ مملّح منزوع النوى، مهروس قليلاً بالشوكة","الحشوة 3 — شيوزاكي (سلمون مملّح مشوي): 100 غ شريحة سلمون مشوية، تُنزع الجلد وتُفتت","الحشوة 4 — أوكاكا: 8 غ رقائق بونيتو ممزوجة مع 1 ملعقة صغيرة صلصة صويا","للأونيغيري السادة: 2 ملعقة كبيرة من فوريكاكي (توابل الأرز) لتغليف الخارج","اختياري: بعض بذور السمسم على السطح"],"en":["500 g Japanese short-grain rice (Koshihikari or sushi rice)","600 ml fresh cold water for cooking (rice to water ratio ~1:1.1)","For the tezu (finger water): 200 ml warm water + 1.5 tsp fine sea salt","4 sheets toasted nori, cut into strips about 3 cm wide × the length of the sheet","Filling option 1 — tuna mayo: 80 g canned tuna (drained), 1.5 tbsp Japanese mayonnaise, ½ tsp soy sauce","Filling option 2 — umeboshi: 60 g pitted salted plums, lightly mashed with a fork","Filling option 3 — shiozake (grilled salted salmon): 100 g salmon fillet grilled and flaked, with the skin removed","Filling option 4 — okaka: 8 g bonito flakes mixed with 1 tsp soy sauce","For plain onigiri: 2 tbsp furikake (rice seasoning), to coat the outside","Optional: a few sesame seeds for the surface of plain ones"],"ro":["500 g orez japonez cu bobul scurt (Koshihikari sau orez pentru sushi)","600 ml apă rece proaspătă pentru fiert (raport orez:apă ~1:1.1)","Pentru tezu (apa de mâini): 200 ml apă caldă + 1.5 linguriță sare fină de mare","4 foi de nori prăjit, tăiate fâșii de ~3 cm lățime × lungimea foii","Umplutură opțiunea 1 — ton cu maioneză: 80 g ton la conservă (scurs), 1.5 lingură maioneză japoneză, ½ linguriță sos de soia","Umplutură opțiunea 2 — umeboshi: 60 g prune sărate fără sâmburi, ușor strivite cu furculița","Umplutură opțiunea 3 — shiozake (somon sărat la grătar): 100 g file de somon făcut la grătar, fără piele, fărâmițat","Umplutură opțiunea 4 — okaka: 8 g fulgi de bonito amestecați cu 1 linguriță sos de soia","Pentru onigiri simplu: 2 linguri furikake (condiment pentru orez), pentru exterior","Opțional: câteva semințe de susan pentru exterior"]},"howIsMade":{"ar":"اشطف الأرز بالماء البارد أربع أو خمس مرات حتى يخرج الماء صافياً تقريباً، اتركه يصفّى في مصفاة 20 دقيقة، ثم اطبخه مع 600 مل من الماء الطازج في قدر ثقيلة أو طباخة أرز، وبعد النضج اتركه يستريح مغطّى بعيداً عن النار 10 دقائق أخرى.\n\nأثناء راحة الأرز، اهرس الأوميبوشي بشوكة، اخلط التونة مع المايونيز الياباني حتى تصبح عجينة كريمية، وفتّت السلمون المشوي — كل أونيغيري يحتاج فقط حوالي ملعقة كبيرة من الحشوة.\n\nأذب الملح في الماء الدافئ لإعداد التزو، وهو ماء الأصابع الذي يمنع التصاق الأرز بالكفين ويتبّل القشرة الخارجية بلطف.\n\nاقلب الأرز الساخن على صينية واسعة، فرّقه برفق بملعقة خشبية واتركه يبرد حتى يصبح دافئاً قابلاً للتشكيل بسهولة.\n\nبلّ كفّيك بالتزو، خذ نحو 100 غ من الأرز، اعمل تجويفاً في المنتصف، ضع ملعقة كبيرة من الحشوة واجمع الأرز حولها؛ اقبض يدك واضغطه على شكل مثلث بثلاثة وجوه مسطحة، بثبات دون سحقه.\n\nلفّ شريط نوري حول قاعدة كل مثلث قبل الأكل مباشرةً ليبقى الطحلب مقرمشاً؛ للأونيغيري السادة، لفّ الخارج بفوريكاكي. يُؤكل بدرجة حرارة الغرفة خلال 4 ساعات.","en":"Rinse the rice in cold water four or five times until the water runs almost clear, drain in a strainer for 20 minutes, then cook with the 600 ml of fresh water in a heavy pot or rice cooker; once cooked, rest off the heat with the lid on for 10 minutes.\n\nWhile the rice rests, mash the umeboshi with a fork, mix the tuna with the Japanese mayonnaise into a creamy paste, and flake the grilled salmon — each onigiri needs only about a tablespoon of filling.\n\nDissolve the salt in the warm water to make the tezu; this is the finger water that keeps the rice from sticking to your palms and lightly salts the outside.\n\nTip the hot rice onto a wide tray, fluff gently with a wooden paddle and let it cool until just warm enough to handle.\n\nWet your palms in the tezu, take about 100 g of rice in your palm, press a hollow in the centre, drop in a tablespoon of filling and gather the rice around it; cup your hand and press into a triangle with three flat faces, firm but not crushed.\n\nWrap a strip of nori around the base of each triangle just before eating so the seaweed stays crisp; for plain onigiri, roll the outside in furikake instead. Eat at room temperature within 4 hours."}},{"id":186,"servings":4,"tipType":"def","pairingsType":"japanese","nutrition":{"cal":360,"prot":36,"carb":8,"fat":18,"fib":1},"origin":{"ar":"اليابان","en":"Japan","ro":"Japonia"},"name":{"ar":"ياكيتوري","en":"Yakitori","ro":"Yakitori"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["600 غ فخذ دجاج بدون عظم مع الجلد، مقطّع مكعبات 2.5 سم","6 بصلات خضراء سميكة (أو 2 من نيغي)، الأبيض والأخضر الفاتح مقطّعاً قطعاً 3 سم (~150 غ)","16 سيخ خيزران قصير (15 سم)، منقوع في ماء بارد 30 دقيقة","للتارِه: 120 مل صلصة صويا داكنة، 120 مل ميرين، 60 مل ساكي، 30 غ سكر بني فاتح","ملح بحري ناعم لأسياخ الشيو","1 ملعقة صغيرة زيت محايد للشواية","شيتشيمي توغاراشي للتقديم","شرائح ليمون للتقديم"],"en":["600 g boneless, skin-on chicken thighs, cut into 2.5 cm cubes","6 fat spring onions (or 2 negi), white and pale green parts cut into 3 cm pieces (~150 g total)","16 short bamboo skewers (15 cm), soaked in cold water for 30 minutes","For the tare: 120 ml dark soy sauce, 120 ml mirin, 60 ml sake, 30 g light brown sugar","Fine sea salt for the shio skewers","1 tsp neutral oil for the grate","Shichimi togarashi, to serve","Lemon wedges, to serve"],"ro":["600 g pulpe de pui dezosate cu piele, tăiate cuburi de 2.5 cm","6 cepe verzi mari (sau 2 negi), partea albă și verde-deschis tăiată bucățele de 3 cm (~150 g)","16 frigărui scurte de bambus (15 cm), înmuiate în apă rece 30 de minute","Pentru tare: 120 ml sos de soia închis, 120 ml mirin, 60 ml sake, 30 g zahăr brun deschis","Sare fină de mare pentru frigăruile shio","1 linguriță ulei neutru pentru grătar","Shichimi togarashi, pentru servit","Felii de lămâie, pentru servit"]},"howIsMade":{"ar":"قطّع فخذ الدجاج مكعبات 2.5 سم وقطّع الأجزاء البيضاء من البصل الأخضر إلى قطع 3 سم، ثم انقع أسياخ الخيزران في ماء بارد لمدة 30 دقيقة كي لا تحترق على الشواية.\n\nللتارِه، اطبخ صلصة الصويا والميرين والساكي والسكر البني على نار هادئة في قدر صغير لنحو 10 دقائق حتى يصبح القوام شُربياً خفيفاً، ثم اتركه يبرد.\n\nاغرز الأسياخ بأسلوبين: النيغيما يتناوب بين دجاج وبصل أخضر ودجاج وبصل أخضر ودجاج؛ والمومو هو مكعبات دجاج فقط، متلاصقة من دون أن تنسحق.\n\nسخّن شواية الفحم أو مقلاة شواء ثقيلة على نار قوية وادهن الشبكة بقليل من الزيت.\n\nضع الأسياخ بحيث يكون الجلد أو الجانب الأكثر دهناً للأسفل واشوها 3–4 دقائق حتى تصبح ذهبية عميقة، ثم اقلبها واطبخها 2–3 دقائق إضافية.\n\nلأسياخ التارِه، اغمسها في الصلصة الباردة وأعدها إلى الشواية 30 ثانية لتُصقل، ثم اغمسها واصقلها مرة أخرى؛ ورشّ ملحاً ناعماً على أسياخ الشيو فور رفعها عن النار. قدّمها فوراً مع شيتشيمي توغاراشي وشرائح الليمون.","en":"Cut the chicken thigh into 2.5 cm cubes and the white parts of the spring onions into 3 cm pieces, then soak the bamboo skewers in cold water for 30 minutes so they don't burn on the grill.\n\nFor the tare, simmer the soy sauce, mirin, sake and brown sugar in a small pan for about 10 minutes until lightly syrupy, then let it cool to room temperature.\n\nThread the skewers in two styles: negima alternates chicken, scallion, chicken, scallion, chicken; momo is just chicken cubes packed close together but not squashed.\n\nHeat a charcoal grill or a heavy grill pan over high heat and lightly oil the grate.\n\nLay the skewers down with the skin or fattiest side first and grill for 3–4 minutes until deep golden, then flip and cook another 2–3 minutes.\n\nFor tare skewers, dip in the cooled sauce, return to the grill for 30 seconds to glaze, then dip and glaze once more; season the shio skewers with a pinch of salt straight off the heat. Serve at once with shichimi togarashi and lemon."}},{"id":187,"servings":4,"tipType":"def","pairingsType":"mexican","nutrition":{"cal":520,"prot":38,"carb":22,"fat":28,"fib":6},"origin":{"ar":"المكسيك","en":"Mexico","ro":"Mexic"},"name":{"ar":"مولي بوبلانو","en":"Mole Poblano","ro":"Mole Poblano"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["80 غ من الفلفل الحار المجفف الممزوج — 3 أنشو + 3 مولاتو + 2 باسيلا — منزوع الساق والبذور","1 فلفل تشيبوتلي في صلصة أدوبو، مع 1 ملعقة كبيرة من صلصته","100 غ من اللوز المقشّر و80 غ من الفول السوداني النيء","30 غ من بذور السمسم النيئة (مع كمية إضافية للتزيين) و60 غ من الزبيب","2 طماطم ناضجة كبيرة، مقطوعة نصفين؛ 1 بصلة بيضاء صغيرة مقطّعة أرباعاً؛ 3 فصوص ثوم بقشرها","1 عود قرفة، 2 برعم قرنفل، 1 نجمة يانسون، و6 حبات فلفل أسود","2 خبز ذرة (تورتيا)، مقطّع قطعاً صغيرة — السماكة التقليدية","60 غ من الشوكولاتة المكسيكية، مكسّرة (أو 50 غ من الشوكولاتة الداكنة + 1 ملعقة صغيرة قرفة + 1 ملعقة كبيرة سكر بني فاتح)","1.2 لتر مرق دجاج بدون ملح، مع الحفاظ عليه دافئاً","3 ملاعق كبيرة من شحم الخنزير (مانتيكا) أو زيت محايد","4 أفخاذ دجاج بالعظم، مسلوقة في ماء مملّح 25 دقيقة ثم مجفّفة","1 ملعقة صغيرة ملح بحري ناعم ورشة سكر صغيرة","للتقديم: أرز أبيض مطبوخ، خبز ذرة دافئ، أوراق كزبرة طازجة"],"en":["80 g mixed dried chiles — 3 ancho + 3 mulato + 2 pasilla — stemmed and seeded","1 chipotle chile in adobo, plus 1 tbsp of its sauce","100 g blanched almonds and 80 g raw peanuts","30 g raw sesame seeds (plus extra to garnish) and 60 g raisins","2 large ripe tomatoes, halved; 1 small white onion, quartered; 3 garlic cloves, unpeeled","1 cinnamon stick, 2 cloves, 1 star anise and 6 black peppercorns","2 corn tortillas, torn into pieces — the traditional thickener","60 g Mexican chocolate, broken up (or 50 g dark chocolate + 1 tsp cinnamon + 1 tbsp light brown sugar)","1.2 L unsalted chicken stock, kept warm","3 tbsp lard (manteca) or neutral oil","4 bone-in chicken thighs, poached in salted water for 25 minutes and patted dry","1 tsp fine sea salt and a small pinch of sugar","To serve: cooked white rice, warm corn tortillas, fresh coriander leaves"],"ro":["80 g de ardei iuți uscați amestecați — 3 ancho + 3 mulato + 2 pasilla — fără codiță și seminţe","1 ardei chipotle în sos adobo, plus 1 lingură din sosul lui","100 g de migdale blanşate și 80 g de arahide crude","30 g de seminţe de susan crude (plus în plus pentru garnitură) și 60 g de stafide","2 roșii mari coapte, tăiate jumătăți; 1 ceapă albă mică, tăiată sferturi; 3 căţei de usturoi, necurăţaţi","1 baton de scorţișoară, 2 cuișoare, 1 stea de anason și 6 boabe de piper negru","2 tortilla de porumb, rupte în bucăţi — îngroșătorul tradiţional","60 g de ciocolată mexicană, fărâmiţată (sau 50 g de ciocolată neagră + 1 linguriţă de scorţișoară + 1 lingură de zahăr brun deschis)","1.2 L de supă de pui nesărată, ţinută caldă","3 linguri de untură (manteca) sau ulei neutru","4 pulpe de pui cu os, fierte în apă sărată 25 de minute și șterse","1 linguriţă de sare fină de mare și un vârf mic de zahăr","Pentru servit: orez alb fiert, tortilla de porumb calde, frunze de coriandru proaspăt"]},"howIsMade":{"ar":"حمّر الفلفل المجفف في مقلاة ثقيلة جافة على نار متوسطة نحو 30 ثانية لكل وجه حتى تفوح رائحته، ثم انقله إلى وعاء، غطّه بماء ساخن واتركه ينتفع 20 دقيقة.\n\nفي المقلاة نفسها، حمّر اللوز والفول السوداني والسمسم والزبيب والبهارات الكاملة على دفعات صغيرة حتى يكتسبوا لوناً ذهبياً خفيفاً — نحو دقيقتين لكل دفعة — ثم ضعهم جانباً.\n\nاحرق نصف الطماطم وأرباع البصل والثوم بقشره مباشرةً على لهب أو تحت شواية ساخنة حتى تسوّد بقعاً، وقشّر الثوم حين يبرد بما يكفي للتعامل.\n\nصفِّ الفلفل (مع الاحتفاظ بماء النقع) واخلطه مع الخضار المحمّر، والتشيبوتلي وصلصته، والمكسرات والبذور المحمّصة، والزبيب والبهارات والتورتيا الممزّقة، مع إضافة نحو 500 مل من المرق الدافئ للحصول على عجينة داكنة ناعمة.\n\nسخّن الشحم في قدر ثقيلة على نار متوسطة-عالية، وأضف العجينة وقلّب باستمرار لمدة 10–15 دقيقة؛ سيغمق المولي ويثخن ويصبح لامعاً بينما تنضج النكهات معاً.\n\nأضف الـ 700 مل المتبقية من المرق والشوكولاتة المكسّرة، واتركها تطهو على نار هادئة 30–40 دقيقة مع التحريك المتكرر حتى تغلّف الصلصة ظهر الملعقة؛ تبّل بالملح ورشة صغيرة من السكر.\n\nأنزل أفخاذ الدجاج المسلوقة داخل المولي واترك 10 دقائق إضافية لتأخذ من الصلصة.\n\nقدّم الدجاج في صحون عميقة، اسكب فوقه طبقة كريمة من المولي، وزيّن ببقية السمسم وأوراق الكزبرة، مع الأرز الأبيض وخبز الذرة الدافئ إلى الجانب.","en":"Toast the dried chiles in a dry heavy pan over medium heat for about 30 seconds per side until fragrant, then transfer to a bowl, cover with hot water and soak for 20 minutes.\n\nIn the same pan, toast the almonds, peanuts, sesame seeds, raisins and whole spices in small batches until just golden — about 2 minutes each — and set aside.\n\nChar the tomato halves, onion quarters and unpeeled garlic directly over a flame or under a hot broiler until blackened in patches, then peel the garlic once cool enough to handle.\n\nDrain the chiles (keeping the soaking water) and blend them with the charred vegetables, chipotle and its sauce, toasted nuts and seeds, raisins, spices and torn tortillas, adding about 500 ml of warm chicken stock to make a smooth dark paste.\n\nHeat the lard in a heavy pot over medium-high heat, pour in the paste and stir constantly for 10–15 minutes; the mole will darken, thicken and turn glossy as the flavours fry together.\n\nStir in the remaining 700 ml of chicken stock and the broken chocolate, then simmer gently for 30–40 minutes, stirring often, until the sauce coats the back of a spoon; season with the salt and a small pinch of sugar.\n\nSlide the poached chicken thighs into the mole and simmer 10 minutes more so they take on the sauce.\n\nServe the chicken in shallow bowls, ladle generous mole over the top, and finish with the reserved sesame seeds, coriander leaves, white rice and warm corn tortillas on the side."}},{"id":188,"servings":4,"tipType":"def","pairingsType":"mexican","nutrition":{"cal":480,"prot":18,"carb":38,"fat":28,"fib":6},"origin":{"ar":"المكسيك","en":"Mexico","ro":"Mexic"},"name":{"ar":"تشيلاكيلِس","en":"Chilaquiles","ro":"Chilaquiles"},"category":{"ar":"فطور","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"ar":["200 غ من خبز الذرة (تورتيا) من اليوم السابق، مقطّع إلى ثُمن (أو توتوبوس جاهز)","500 مل زيت محايد للقلي (أو 4 ملاعق كبيرة للقلي السطحي)","لصلصة سالسا روخا: 6 طماطم ناضجة (~600 غ)، 2 فلفل غواخيو + 1 فلفل دي أربول (منزوع الساق والبذور)، 1 فص ثوم، ½ بصلة بيضاء صغيرة","1 ملعقة صغيرة ملح بحري ناعم و1 ملعقة كبيرة زيت محايد للصلصة","4 بيضات كبيرة، مقلية بالعين (اختياري لكنه تقليدي)","100 مل كريما مكسيكية (أو قشدة حامضة مخفّفة بالحليب)","80 غ من جبن كيسو فريسكو المفتت (أو فيتا خفيفة)","½ بصلة حمراء صغيرة، شرائح رفيعة جداً","حفنة صغيرة من الكزبرة الخضراء، أوراقها فقط","1 أفوكادو ناضج، يُقطّع قبل التقديم مباشرةً","هالابينو مخلل، حسب الرغبة"],"en":["200 g day-old corn tortillas, cut into eighths (or store-bought totopos)","500 ml neutral oil for frying (or 4 tbsp for shallow-frying)","For the salsa roja: 6 ripe tomatoes (~600 g), 2 guajillo chiles + 1 chile de árbol (stemmed and seeded), 1 garlic clove, ½ small white onion","1 tsp fine sea salt and 1 tbsp neutral oil for the salsa","4 large eggs, fried sunny-side-up (optional but classic)","100 ml Mexican crema (or sour cream thinned with milk)","80 g queso fresco, crumbled (or mild feta)","½ small red onion, very thinly sliced","A small handful of fresh coriander, leaves picked","1 ripe avocado, sliced just before serving","Pickled jalapeños, to taste"],"ro":["200 g tortilla de porumb de o zi, tăiate în opt (sau totopos cumpărate)","500 ml ulei neutru pentru prăjit (sau 4 linguri pentru prăjit superficial)","Pentru salsa roja: 6 roșii coapte (~600 g), 2 ardei guajillo + 1 ardei de árbol (fără codiță și semințe), 1 cățel de usturoi, ½ ceapă albă mică","1 linguriță sare fină de mare și 1 lingură ulei neutru pentru salsa","4 ouă mari, ochiuri (opțional dar tradițional)","100 ml crema mexicană (sau smântână subțiată cu lapte)","80 g queso fresco, sfărâmat (sau feta blândă)","½ ceapă roșie mică, tăiată felii foarte subțiri","Un mic mănunchi de coriandru proaspăt, doar frunzele","1 avocado copt, feliat chiar înainte de servit","Jalapeños murați, după gust"]},"howIsMade":{"ar":"قطّع التورتيا التي بقيت من اليوم السابق إلى ثُمن، ثم اقلِها إما في زيت غزير عند 175°م حتى تصبح ذهبية ومقرمشة، نحو 90 ثانية لكل دفعة، أو في 4 ملاعق كبيرة من الزيت بشكل سطحي؛ صفِّها على شبكة وتبّلها بالملح وهي لا تزال دافئة.\n\nللصلصة، حمّر فلفل غواخيو ودي أربول في مقلاة جافة 20 ثانية لكل وجه حتى تفوح رائحته، ثم انقعه في ماء ساخن 10 دقائق؛ وفي الوقت نفسه، احرق الطماطم والثوم والبصل تحت شواية حارة أو فوق اللهب مباشرةً حتى تسوّد بقعاً.\n\nصفِّ الفلفل واخلطه مع الخضار المحروق و1 ملعقة صغيرة ملح ورشة من ماء النقع حتى تصبح صلصة ناعمة.\n\nسخّن 1 ملعقة كبيرة من الزيت في مقلاة واسعة، اسكب الصلصة واتركها تطهو نحو 5 دقائق مع التحريك حتى يغمق لونها وتلمع.\n\nأضف التورتيا المقرمشة وقلّبها برفق في الصلصة على نار متوسطة لدقيقة أو دقيقتين — يجب أن تشرب الصلصة مع إبقاء بعض القرمشة.\n\nقدّم على الفور، ضع البيض المقلي إن استخدمت، اسكب الكريما من فوق، ووزّع الكيسو فريسكو والبصل الأحمر والكزبرة والأفوكادو والهالابينو المخلل.","en":"Cut the day-old tortillas into eighths and either deep-fry them at 175°C until golden and crisp, about 90 seconds per batch, or shallow-fry in 4 tablespoons of oil; drain on a rack and salt lightly while still warm.\n\nFor the salsa, toast the guajillo and árbol chiles in a dry pan for 20 seconds per side until fragrant, then soak in hot water for 10 minutes; meanwhile, char the tomatoes, garlic and onion under a hot broiler or directly over a flame until blackened in patches.\n\nDrain the chiles and blend with the charred vegetables, 1 teaspoon of salt and a splash of the chile-soaking water until smooth.\n\nHeat 1 tablespoon of oil in a wide pan, pour in the salsa and simmer for about 5 minutes, stirring, until it deepens in colour and looks glossy.\n\nTip in the crisp tortillas and gently fold them through the salsa over medium heat for a minute or two — they should soak up sauce while keeping some bite.\n\nPlate at once, top with the fried eggs if using, drizzle with crema, and scatter queso fresco, sliced red onion, coriander, avocado and pickled jalapeños over the top."}},{"id":189,"servings":8,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":530,"prot":9,"carb":70,"fat":24,"fib":1},"origin":{"ar":"المكسيك","en":"Mexico","ro":"Mexic"},"name":{"ar":"كعكة تريس ليتشيس","en":"Tres Leches Cake","ro":"Tort Tres Leches"},"category":{"ar":"تحلية","en":"Dessert","ro":"Desert"},"ingredients":{"ar":["5 بيضات كبيرة، مفصولة، في حرارة الغرفة","200 غ من السكر الناعم، و30 غ إضافية للكريمة المخفوقة","200 غ دقيق و1 ملعقة صغيرة بيكنغ باودر، منخولان معاً","1 ملعقة صغيرة خلاصة فانيليا للكيك، و½ ملعقة للكريمة","1 علبة (397 غ) من الحليب المكثّف المحلّى","1 علبة (340 غ) من الحليب المبخّر (evaporated)","200 مل حليب كامل الدسم و50 مل كريمة (خليط الأحلبة الثلاثة)","250 مل كريمة باردة للخفق، و قرفة مطحونة للتزيين"],"en":["5 large eggs, separated, at room temperature","200 g caster sugar, plus 30 g for the whipped cream","200 g plain flour and 1 tsp baking powder, sifted together","1 tsp vanilla extract for the sponge, plus ½ tsp for the cream","1 can (397 g) sweetened condensed milk","1 can (340 g) evaporated milk","200 ml whole milk and 50 ml heavy cream (the three-milk soak)","250 ml cold heavy cream for whipping, plus ground cinnamon for dusting"],"ro":["5 ouă mari, separate, la temperatura camerei","200 g zahăr tos, plus 30 g pentru frișcă","200 g făină albă și 1 linguriță praf de copt, cernute împreună","1 linguriță esență de vanilie pentru blat, plus ½ linguriță pentru frișcă","1 cutie (397 g) lapte condensat îndulcit","1 cutie (340 g) lapte evaporat","200 ml lapte integral și 50 ml smântână pentru frișcă (amestec pentru îmbibare)","250 ml smântână rece pentru frișcă (35% grăsime), plus scorțișoară măcinată pentru pudrat"]},"howIsMade":{"ar":"سخّن الفرن إلى 175°م، وادهن بالزبدة ورشّ الدقيق على صينية 23×33 سم، ثم اخفق البياض مع رشة ملح حتى قمم لينة، مضيفاً 100 غ من السكر ملعقةً ملعقة، حتى يصير لامعاً وقمماً قاسية.\n\nاخفق الصفار مع 100 غ السكر المتبقية والفانيليا من 3 إلى 4 دقائق، حتى يفتح لونه ويتضاعف حجمه ثلاث مرات، انخل الدقيق والبيكنغ باودر فوقه وقلّب بلطف بالملعقة، ثم أضف المرنغ على ثلاث دفعات مع الحفاظ على الهواء قدر الإمكان.\n\nاسكب في الصينية، سوّ السطح، واخبز 25–30 دقيقة حتى يصير ذهبياً غامقاً ويرتد عند الضغط، ثم اتركه يبرد في الصينية 30 دقيقة على الأقل.\n\nاخلط في إبريق الحليب المكثّف والحليب المبخّر وخليط الحليب الكامل مع الكريمة، اثقب الكيك البارد في كامل سطحه بسيخ رفيع حتى القاع، واسكب الخليط على كامل المساحة في ثلاث أو أربع دفعات بطيئة — سيبدو السائل كثيراً جداً، لكن الإسفنج سيشربه كله؛ غطّ وضع في الثلاجة 4 ساعات على الأقل، ويفضّل طوال الليل.\n\nقبل التقديم مباشرةً، اخفق الكريمة الباردة مع 30 غ السكر وما تبقّى من الفانيليا حتى قمم لينة، وزّعها على الكيك البارد ورشّها بسخاء بالقرفة المطحونة.","en":"Heat the oven to 175°C and butter and flour a 23×33 cm baking dish, then whisk the whites with a pinch of salt to soft peaks, beating in 100 g of the sugar a spoonful at a time until glossy and stiff.\n\nWhip the yolks with the remaining 100 g sugar and the vanilla for 3–4 minutes until pale and tripled, sift the flour and baking powder over them and fold in gently, then fold in the meringue in three additions, keeping as much air as you can.\n\nPour into the dish, level the top and bake 25–30 minutes until deep golden and springy at the centre, then cool in the dish for at least 30 minutes.\n\nWhisk the three milks together in a jug, pierce the cooled cake all over to the base with a thin skewer and pour the mixture across the surface in three or four slow passes — it looks like too much liquid, but the sponge drinks every drop; cover and refrigerate at least 4 hours, ideally overnight.\n\nJust before serving, whip the cold cream with the 30 g sugar and the remaining vanilla to soft peaks, spread it over the chilled cake and dust generously with ground cinnamon."}},{"id":190,"servings":6,"tipType":"fish","pairingsType":"french","nutrition":{"cal":480,"prot":50,"carb":30,"fat":18,"fib":4},"origin":{"ar":"فرنسا","en":"France","ro":"Franța"},"name":{"ar":"بوياباز","en":"Bouillabaisse","ro":"Bouillabaisse"},"category":{"ar":"سمك","en":"Fish","ro":"Pește"},"ingredients":{"ar":["800 غ من أسماك الصخور المتوسطية الصغيرة (راسكاس، تنين البحر، الكلب البحري — للمرق)، منزوعة الأحشاء","1.2 كغ من السمك المتوسطي المتين قطعاً (راسكاس، أبو ذقن، سان بيير، الأنقليس، الديك البحري — أربعة أنواع على الأقل)، بالقشر منزوعة الحراشف","1 بصلة كبيرة، 2 كرّاث (الجزء الأبيض فقط)، 1 شمر، 4 طماطم ناضجة، 6 فصوص ثوم","بوكيه غارني: زعتر، ورق غار، سيقان بقدونس، شريحة من قشر برتقال مجفّف، ملعقة صغيرة بذور شمر","1 غ خيوط زعفران (رشة سخية)، 2 ملعقة كبيرة باستيس (Pernod) تُضاف في النهاية","100 مل زيت زيتون، 1 ملعقة صغيرة ملح، فلفل مطحون طازجاً","2 لتر ماء (أو مرق سمك خفيف)","12–15 شريحة باغيت من اليوم السابق محمّصة، ورويّ (3 فصوص ثوم، ½ ملعقة صغيرة زعفران، ¼ ملعقة صغيرة كايين، 1 صفار بيض، 200 مل زيت زيتون، ملح، قطعة خبز صغيرة منقوعة في المرق)"],"en":["800 g small Mediterranean rockfish (rascasse, weever, wrasse — for the broth), gutted","1.2 kg firm Mediterranean fish in chunks (rascasse, monkfish, John Dory, conger, gurnard — at least four species), skin on, scaled","1 large onion, 2 leeks (white parts only), 1 fennel bulb, 4 ripe tomatoes, 6 garlic cloves","Bouquet garni: thyme, bay, parsley stalks, a strip of dried orange peel, a teaspoon of fennel seeds","1 g saffron threads (a generous pinch), 2 tbsp pastis (Pernod) stirred in at the end","100 ml olive oil, 1 tsp salt, freshly ground pepper","2 L water (or light fish fumet)","12–15 slices of toasted day-old baguette and rouille (3 garlic cloves, ½ tsp saffron, ¼ tsp cayenne, 1 egg yolk, 200 ml olive oil, salt, a small piece of bread soaked in the broth)"],"ro":["800 g pești mici mediteraneeni de stâncă (rascassa, năsărel, vrana — pentru fond), eviscerați","1,2 kg pește mediteranean ferm tăiat bucăți (rascassa, lotă, Saint-Pierre, congru, grondin — minim patru specii), cu piele, scuamat","1 ceapă mare, 2 praz (doar partea albă), 1 bulb de fenicul, 4 roșii coapte, 6 căței de usturoi","Buchet garni: cimbru, foi de dafin, codițe de pătrunjel, coajă uscată de portocală, o linguriță de semințe de fenicul","1 g șofran (un vârf bun), 2 linguri de pastis (Pernod) adăugat la final","100 ml ulei de măsline, 1 linguriță sare, piper proaspăt măcinat","2 l apă (sau fumet uşor de pește)","12–15 felii de baghetă uscată prăjită și rouille (3 căței usturoi, ½ linguriță șofran, ¼ linguriță cayenne, 1 gălbenuș, 200 ml ulei de măsline, sare, o bucată de pâine înmuiată în fond)"]},"howIsMade":{"ar":"نظّف وقشّر واغسل كل الأسماك — قطّع الكبيرة إلى مكعبات من 3 سم محتفظاً بالرؤوس والعظام للمرق، أما أسماك الصخور الصغيرة فتدخل كاملة.\n\nفي قدر كبير ثقيل، سخّن 4 ملاعق كبيرة من زيت الزيتون على نار متوسطة وقلّب البصل والكرّاث والشمر دون أن يأخذ لوناً لمدة 10 دقائق تقريباً، ثم أضف الطماطم المفرومة و5 فصوص ثوم واطبخ 5 دقائق إضافية حتى يصبح المزيج لباً.\n\nأضف الأسماك الصغيرة ورؤوس وعظام الكبيرة، غطِّ بـ 2 لتر من الماء، أضف بوكيه غارني (زعتر، غار، بقدونس، قشر برتقال، بذور شمر)، واتركها تغلي بقوة 30–40 دقيقة حتى تتفكك الأسماك الصغيرة بالكامل، ثم صفِّ الكل عبر مصفاة خشنة أو مطحنة خضار مع الضغط بقوة — تُتخلَّص العظام والأعشاب واللب — وأعد المرق المصفّى إلى الغليان القوي، عدّل الملح وقلّب الزعفران.\n\nضع قطع الأسماك المتينة أولاً (أبو ذقن، أنقليس) واطبخها 5–6 دقائق، ثم أضف الأسماك الأرقّ (راسكاس، سان بيير) واطبخها 3–4 دقائق أخرى — يجب أن تكون فقط معتمة، لا متفكّكة أبداً — ورافعاً القدر عن النار، قلّب الباستيس.\n\nللرويّ، اهرس في الهاون فصّ الثوم المتبقّي مع الملح والزعفران، أضف الخبز المغموس في المرق والمعصور، ثم صفار البيض، وأخيراً اسكب زيت الزيتون في خيط رفيع مع الخفق المستمر حتى يصبح بقوام المايونيز، ثم قدّم على مرحلتين: أولاً المرق فوق شرائح الباغيت المحمّصة مع ملعقة من الرويّ، ثم السمك في صحن منفصل مع المزيد من الرويّ على الجانب.","en":"Scale, gut and rinse all the fish — cut the larger ones into 3 cm chunks and keep the heads and bones for the broth, while the small rockfish go whole into the pot.\n\nIn a large heavy pot, heat 4 tablespoons of olive oil over medium heat and sweat the chopped onion, leeks and fennel without colour for about 10 minutes, then add the chopped tomatoes and 5 garlic cloves and cook another 5 minutes to a pulp.\n\nTip in the small fish and the heads and bones of the larger ones, cover with the 2 L of water, drop in the bouquet garni (thyme, bay, parsley, orange peel, fennel seeds) and simmer hard for 30–40 minutes until the small fish completely break down, then pass everything through a coarse sieve or food mill, pressing hard to extract every drop — bones, herbs and pulp discarded — bring the strained broth back to a rolling boil, taste for salt and stir in the saffron.\n\nSlip the firm fish (monkfish, conger) into the broth first and poach 5–6 minutes, then add the more delicate ones (rascasse, John Dory) for another 3–4 — they should be just opaque, never falling apart — and off the heat, swirl in the pastis.\n\nFor the rouille, pound the last garlic clove with the salt and saffron in a mortar, work in the bread (dipped in broth and squeezed), then the yolk, then olive oil in a thin stream, whisking constantly until thick like mayonnaise, then serve in two courses: the broth first, ladled over toasted baguette with a spoonful of rouille on top; the fish after, on a separate plate, with more rouille alongside."}},{"id":191,"servings":4,"tipType":"meat","pairingsType":"french","nutrition":{"cal":650,"prot":30,"carb":40,"fat":38,"fib":2},"origin":{"ar":"فرنسا","en":"France","ro":"Franța"},"name":{"ar":"كروك مسيو","en":"Croque Monsieur","ro":"Croque Monsieur"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"ingredients":{"ar":["8 شرائح سميكة من خبز التوست الأبيض الناعم (بان دي مي)، من اليوم السابق","80 غ زبدة غير مملّحة طريّة، و30 غ إضافية للبيشاميل","200 غ من جبن غرويير أو كومتيه مبشور ناعماً","4 شرائح من جامبون باريس (~120 غ إجمالاً)","2 ملعقة صغيرة خردل ديجون","30 غ دقيق و300 مل حليب كامل الدسم (لصلصة البيشاميل)","ملح بحري ناعم، فلفل أبيض، رشة من جوزة الطيب المبشورة"],"en":["8 thick slices of pain de mie (soft white sandwich bread), one day old","80 g unsalted butter, softened, plus 30 g for the béchamel","200 g Gruyère or Comté, finely grated","4 slices of jambon de Paris (~120 g total)","2 tsp Dijon mustard","30 g plain flour and 300 ml whole milk (for the béchamel)","Fine sea salt, white pepper, a grating of nutmeg"],"ro":["8 felii groase de pain de mie (pâine albă fină de sandviș), o zi vechi","80 g unt nesărat, înmuiat, plus 30 g pentru béchamel","200 g Gruyère sau Comté, ras fin","4 felii de jambon de Paris (~120 g în total)","2 lingurițe muștar Dijon","30 g făină albă și 300 ml lapte integral (pentru béchamel)","Sare fină, piper alb, un sfert de nucușoară rasă"]},"howIsMade":{"ar":"أذِب الـ 30 غ من الزبدة لصلصة البيشاميل في قدر صغير على نار متوسطة، أضف الدقيق وقلّبه دقيقة إلى دقيقتين دون أن يأخذ لوناً، ثم اسكب الحليب الدافئ بالتدريج مع الخفق المستمر بالمضرب واترك المزيج يغلي بهدوء 4–5 دقائق مع التحريك المتكرر حتى يثخن بما يكفي ليثبت ذروة على الملعقة — تبّل بالملح والفلفل الأبيض وجوزة الطيب واحتفظ به دافئاً.\n\nسخّن مشواية الفرن العلوية على أعلى درجة، ادهن وجهَي كل شريحة خبز بالزبدة الطريّة وضع طبقة رفيعة من خردل ديجون على الوجه الداخلي لشريحة واحدة من كل سندويش.\n\nضع 4 شرائح بالوجه المدهون لأسفل على صينية مبطّنة بورق الخبز، وزّع على كل واحدة طبقة رفيعة من الغرويير المبشور (احتفظ بـ ~60 غ للأعلى)، شريحة جامبون، ثم طبقة رفيعة أخرى من الجبن، غطِّ بالشرائح الأربع المتبقية بجهة الخردل للداخل واضغط برفق.\n\nضع ملعقتين كبيرتين ممتلئتين من البيشاميل فوق كل سندويش حتى الحواف حتى يُغطّى الخبز بالكامل وتسيل الصلصة قليلاً على الجوانب، رشّ الغرويير المحفوظ فوقها وأدخل الصينية تحت المشواية الحارة 4–6 دقائق مع المراقبة عن قرب حتى تفور البيشاميل وتحمرّ بعمق في بقع ويذوب الجبن بالكامل — يصبح الخبز مقرمشاً من الأسفل بفضل الزبدة التي أمسكت به مسبقاً.\n\nاسحب الصينية، دعها ترتاح 30 ثانية — وإلا فإن الجبن سيلتصق بأصابعك — ثم قطّع بشكل قطري؛ للكروك مدام، اقلِ بيضةً في قليل من الزبدة بينما السندويشات تحت المشواية، وضعها فوق السندويش قبل التقديم مباشرةً.","en":"Melt the 30 g béchamel butter in a small saucepan over medium heat, whisk in the flour and cook 1–2 minutes without colouring, then pour the warm milk in gradually while whisking constantly and simmer gently 4–5 minutes, stirring often, until thick enough to hold a peak on the spoon — season with salt, white pepper and nutmeg and keep warm.\n\nPreheat the broiler (top grill) to high, butter both sides of every bread slice with the softened butter, then thinly spread Dijon on the inner face of one slice per sandwich.\n\nLay 4 buttered slices on a lined tray, top each with a thin layer of grated Gruyère (hold ~60 g back for the top), a slice of ham and another thin layer of cheese, then close with the remaining 4 slices, mustard side in, and press lightly.\n\nSpoon 2 heaped tablespoons of béchamel over each sandwich right to the edges so the bread is fully covered and the sauce runs a little down the sides, scatter the reserved Gruyère on top and slide the tray under the hot broiler for 4–6 minutes, watching closely, until the béchamel is bubbling and deeply browned in patches and the cheese is molten — the bread crisps from below from the butter already gripped to its underside.\n\nLift out, rest 30 seconds — the cheese would stick to you otherwise — and cut on the diagonal; for a croque madame, fry an egg in a little butter while the sandwiches are under the broiler and slip it on top just before serving."}},{"id":192,"servings":4,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":420,"prot":13,"carb":60,"fat":14,"fib":1},"origin":{"ar":"فرنسا","en":"France","ro":"Franța"},"name":{"ar":"كريب","en":"Crêpes","ro":"Crêpes"},"category":{"ar":"تحلية","en":"Dessert","ro":"Desert"},"ingredients":{"ar":["250 غ دقيق أبيض (T45 أو T55)، منخول","4 بيضات كبيرة، في حرارة الغرفة","500 مل حليب كامل الدسم (أو 350 مل حليب + 150 مل ماء للحصول على كريب أخف)","50 غ زبدة غير مملّحة، تُذاب حتى تتحوّل إلى زبدة بنّية (beurre noisette)","30 غ سكر ورشة جيدة من الملح الناعم","ملعقة كبيرة رم داكن أو ماء زهر البرتقال (أو ملعقة صغيرة خلاصة فانيليا)","زبدة إضافية لدهن المقلاة (~30 غ، على فرشاة)","للتقديم: سكر ناعم، شرائح ليمون، اختيارياً مربى، نوتيلا، أو شرائح موز"],"en":["250 g plain flour (T45 or T55), sifted","4 large eggs, at room temperature","500 ml whole milk (or 350 ml milk + 150 ml water for lighter crêpes)","50 g unsalted butter, melted until it browns to beurre noisette","30 g sugar and a good pinch of fine salt","1 tbsp dark rum or orange-flower water (or 1 tsp vanilla extract)","Extra butter for the pan (~30 g, kept on a brush)","To serve: caster sugar, lemon wedges, optionally jam, Nutella or sliced banana"],"ro":["250 g făină albă (T45 sau T55), cernută","4 ouă mari, la temperatura camerei","500 ml lapte integral (sau 350 ml lapte + 150 ml apă pentru crêpes mai ușoare)","50 g unt nesărat, topit până devine beurre noisette (alunizat)","30 g zahăr și un vârf bun de sare fină","1 lingură de rom închis sau apă de flori de portocal (sau 1 linguriță extract de vanilie)","Unt în plus pentru ungerea tigăii (~30 g, ținut cu o pensulă)","Pentru servit: zahăr tos, felii de lămâie, opțional gem, Nutella sau banane"]},"howIsMade":{"ar":"أذِب 50 غ من الزبدة في قدر صغير على نار متوسطة، واتركها حتى تفوح برائحة المكسرات وتميل إلى لون ذهبي غامق، ثم صفِّها في وعاء واترك الرواسب الداكنة في القدر — هذه هي زبدة البندق (beurre noisette)، توقيع نكهة الكريب على طريقة الحلويات.\n\nانخل الدقيق والملح في وعاء كبير، اعمل حفرة في الوسط، اكسر فيها البيض، وأضف ثلث الحليب مع السكر، ثم اخفق بالمضرب من المركز نحو الخارج ساحباً الدقيق تدريجياً حتى يصبح لديك عجين سميك ناعم بلا تكتلات، خفّفه بباقي الحليب في خيط رفيع وأضف أخيراً الزبدة الفاترة والروم؛ يجب أن يكون قوام العجين كقشدة سائلة.\n\nغطِّ الوعاء واتركه في الثلاجة 30 دقيقة على الأقل، ويفضّل ساعة — يرتاح الغلوتين وتأتي الكريب رفيعة ومرنة بدلاً من مطّاطية.\n\nسخّن مقلاة غير لاصقة قطرها 22–24 سم أو مقلاة كريب (crêpière) على نار متوسطة-قوية، ضع بفرشاة طبقة رفيعة جداً من الزبدة واسكب ~50 مل من العجين، حرّك المقلاة فوراً ليغطي القاع بقرص رقيق، ثم اطبخ 50–60 ثانية حتى ترتفع الحواف ويصبح الوجه السفلي ذهبياً مزركشاً، اقلب بملعقة رفيعة (أو بقذفة قصيرة من المقلاة) لمدة 25–30 ثانية إضافية، مرّرها إلى صحن وغطها بمنشفة نظيفة — تابع، مع دهن المقلاة بقليل من الزبدة كل قرص أو قرصين، حتى ينتهي العجين.\n\nقدّمها دافئة، مع رشّة من السكر الناعم وعصرة ليمون، مطوية إلى أرباع — الكلاسيكيات على عربات شارع باريس: السكر، السكر-الليمون، مربى الفواكه، نوتيلا، أو الموز مع نوتيلا.","en":"Melt the 50 g of butter in a small saucepan over medium heat and keep cooking until it smells nutty and turns deep gold, then strain into a bowl leaving the dark sediment behind — that's beurre noisette, the signature flavour of bakery-grade crêpes.\n\nSift the flour and salt into a large bowl, make a well in the middle, crack in the eggs and add a third of the milk with the sugar, then whisk from the centre outwards drawing in the flour until you have a thick smooth paste with no lumps, thin with the rest of the milk in a slow stream and finally add the cooled brown butter and the rum; the batter should be the consistency of single cream.\n\nCover and rest the batter in the fridge at least 30 minutes, ideally an hour — the gluten settles and the crêpes turn out thin and flexible rather than elastic.\n\nHeat a 22–24 cm non-stick pan or crêpière over medium-high heat, brush with a very thin film of butter and pour in about 50 ml of batter, immediately swirling so it covers the base in a thin disc, then cook 50–60 seconds until the edges lift and the underside is lacy golden, flip with a thin spatula (or a quick toss of the pan) for another 25–30 seconds, slide onto a plate and cover with a clean cloth — carry on, brushing the pan with a little butter every one or two crêpes, until the batter is gone.\n\nServe warm, scattered with caster sugar and a squeeze of lemon, folded into quarters — the Parisian street-stand alternatives are sucre, sucre-citron, fruit jam, Nutella, or banana with Nutella."}},{"id":193,"servings":8,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":530,"prot":5,"carb":65,"fat":28,"fib":3},"origin":{"ar":"فرنسا","en":"France","ro":"Franța"},"name":{"ar":"تارت تاتان","en":"Tarte Tatin","ro":"Tarte Tatin"},"category":{"ar":"تحلية","en":"Dessert","ro":"Desert"},"ingredients":{"ar":["8 إلى 10 تفاحات صلبة وحامضة قليلاً (راين دو رينيت، غولدن ديليشَس، أو هاني كرسب)، مقشّرة ومنصّفة ومنزوعة القلب — نحو 1,5 كغ","150 غ زبدة غير مملّحة مكعّبات، في حرارة الغرفة","200 غ سكر أبيض ناعم (لا يُستخدم سكر بنّي في التاتان الكلاسيكية)","ملعقة كبيرة عصير ليمون طازج","قرص من العجين الفطير (pâte feuilletée)، ~250 غ، مفرود إلى قطر 26 سم وسماكة 3 مم","رشّة من فلور دو سيل (ملح بحري بلوري)","للتقديم: 200 مل كريمة طازجة (crème fraîche)، لا آيس كريم — تقليد منطقة سولونيي"],"en":["8–10 firm tart apples (reine de reinette, golden delicious or honeycrisp), peeled, halved and cored — about 1.5 kg","150 g unsalted butter, cut into cubes, at room temperature","200 g white granulated sugar (do not use brown sugar for a classic tatin)","1 tbsp fresh lemon juice","1 round of puff pastry (pâte feuilletée), ~250 g, rolled to 26 cm and 3 mm thick","A pinch of fleur de sel","To serve: 200 ml crème fraîche, not ice cream — the Sologne tradition"],"ro":["8–10 mere ferme și ușor acrișoare (reine de reinette, golden delicious sau honeycrisp), curățate, înjumătățite și fără cotor — în jur de 1,5 kg","150 g unt nesărat, tăiat cuburi, la temperatura camerei","200 g zahăr alb tos (nu se folosește zahăr brun pentru un tatin clasic)","1 lingură suc proaspăt de lămâie","Un disc de aluat de foitaj (pâte feuilletée), ~250 g, rulat la 26 cm diametru și 3 mm grosime","Un vârf de fleur de sel","Pentru servit: 200 ml smântână grasă (crème fraîche), nu înghețată — tradiția din Sologne"]},"howIsMade":{"ar":"اخلط التفاح بعصير الليمون كي لا يسوّد، أذِب 50 غ من الزبدة في مقلاة ثقيلة بمقبض يصلح للفرن (أو في قالب تاتان مخصّص) قطرها 22–24 سم، انثر السكر فوقها بطبقة متساوية، واتركه على نار متوسطة دون تحريك حتى يذوب السكر ويتكرمل إلى لون عنبري غامق — نحو 8 إلى 10 دقائق — لأن الكراميل الفاتح يفقد لونه في الفرن ويصبح طعمه بلا روح.\n\nارفع المقلاة عن النار وأضف ما تبقى من الزبدة (100 غ) مكعّبات فوق الكراميل — سوف تصدر فحيحاً قوياً — حرّك المقلاة دائرياً حتى تذوب الزبدة بانتظام في صلصة لامعة، ثم رتّب نصفي التفاح بالوجه المقطوع للأعلى مضغوطة بإحكام في حلزون من الوسط نحو الخارج (سيدخل كله)، أعد المقلاة إلى نار متوسطة واطبخ مكشوفاً 25–30 دقيقة، أمل المقلاة بين الحين والآخر لتلتقط الكراميل من الحواف، حتى يشرب أسفل التفاح الكراميل ويبدأ في الذوبان.\n\nفي الأثناء، سخّن الفرن إلى 200°م وافرد العجينة الفطيرية بشكل قرص أكبر قليلاً من المقلاة، أطفئ النار تحت التفاح واتركه يبرد دقيقة، ثم غطِّ التفاح بالعجينة، وادفع حوافها إلى داخل المقلاة بين التفاح والجدار — ستمسك القشرة الفاكهة عند القلب — واثقب العجينة بشوكة عدة مرات.\n\nاخبز 25–30 دقيقة حتى تصبح العجينة ذهبية تماماً ويفور الكراميل على الحواف، ثم دعها ترتاح بالضبط 10 دقائق — وقت يكفي لتستقر الكراميل دون أن تتصلّب.\n\nضع طبق تقديم أعرض من المقلاة فوق العجينة، أمسك المقلاة بمنشفة سميكة، واقلب بحركة واحدة حاسمة — إذا التصقت تفاحة بالمقلاة، أعدها إلى التارت بملعقة — انثر رشّة من فلور دو سيل في الأعلى وقدّمها دافئة مع ملعقة وفيرة من الـ crème fraîche على كل طبق.","en":"Toss the apples with the lemon juice so they don't brown, melt 50 g of the butter in a heavy 22–24 cm oven-safe pan with an ovenproof handle (or a proper tatin pan), scatter the sugar over it in an even layer and leave on medium heat without stirring until the sugar dissolves and caramelises to a deep amber — about 8–10 minutes — because pale caramel bleeds out in the oven and tastes flat.\n\nTake the pan off the heat and drop the remaining 100 g butter in cubes onto the caramel — it will hiss hard — swirl until the butter melts evenly into a glossy buttery sauce, then pack the apple halves cut-side-up, tight against each other in a spiral from the centre outwards (they will fit), return to medium heat and cook uncovered for 25–30 minutes, tilting the pan now and then to catch the caramel from the edges, until the underside of the apples has drunk the caramel and they just start to soften.\n\nMeanwhile heat the oven to 200°C and roll the puff pastry to a disc a little larger than the pan, cut the heat under the apples and let them settle a minute, then drape the pastry over the top and tuck the edges down inside the pan between the apples and the wall — the crust will grip the fruit when you flip — and prick the pastry a few times with a fork.\n\nBake 25–30 minutes until the pastry is fully golden and the caramel bubbles around the edges, then rest exactly 10 minutes — long enough for the caramel to settle without setting hard.\n\nPlace a serving plate wider than the pan over the pastry, hold the pan with a thick cloth and invert in one decisive motion — if any apple stays stuck to the pan, lift it back onto the tart with a spatula — scatter a pinch of fleur de sel over the top and serve warm with a generous spoonful of crème fraîche on each plate."}},{"id":194,"servings":6,"tipType":"soup","pairingsType":"soup","nutrition":{"cal":320,"prot":28,"carb":28,"fat":10,"fib":1},"origin":{"ar":"اليونان","en":"Greece","ro":"Grecia"},"name":{"ar":"أفغوليمونو","en":"Avgolemono","ro":"Avgolemono"},"category":{"ar":"حساء","en":"Soup","ro":"Supă"},"ingredients":{"ar":["1,5 كغ دجاجة كاملة (أو 1 كغ أوراك دجاج بالعظم)","2 جزر، 1 بصلة، 2 ساق كرفس (للمرق)","1 ورقة غار، حفنة من سيقان البقدونس، 8 حبات فلفل أسود","150 غ أرز طويل الحبة (أو أورزو إن فضّلت)","3 بيضات كبيرة، في حرارة الغرفة","عصير ليمونتين (نحو 80 مل)","ملح وفلفل أبيض","شبت أو بقدونس طازج للتزيين"],"en":["1.5 kg whole chicken (or 1 kg bone-in chicken thighs)","2 carrots, 1 onion, 2 celery stalks (for the broth)","1 bay leaf, a handful of parsley stems, 8 black peppercorns","150 g long-grain rice (or orzo if you prefer)","3 large eggs, at room temperature","Juice of 2 lemons (about 80 ml)","Salt and white pepper","Fresh dill or parsley to finish"],"ro":["1,5 kg pui întreg (sau 1 kg pulpe de pui cu os)","2 morcovi, 1 ceapă, 2 tulpini de țelină (pentru fond)","1 frunză de dafin, un mănunchi de codițe de pătrunjel, 8 boabe de piper negru","150 g orez cu bob lung (sau orzo, dacă preferi)","3 ouă mari, la temperatura camerei","Zeama de la 2 lămâi (aproximativ 80 ml)","Sare și piper alb","Mărar sau pătrunjel proaspăt pentru a încheia"]},"howIsMade":{"ar":"ضع الدجاجة في قدر ثقيل مع الجزر والبصل والكرفس وورقة الغار وسيقان البقدونس وحبات الفلفل، وغمرها بـ 2.5 لتر من الماء البارد وأوصلها إلى غليان هادئ. ارفع الرغوة واتركها تطهو دون غطاء نحو 90 دقيقة، حتى ينفصل اللحم عن العظم.\n\nأخرج الدجاجة، صفِّ المرق إلى قدر نظيف وتخلّص من الخضار. انزع اللحم عن العظم وقطّعه إلى قطع صغيرة، أعده إلى المرق، أوصله إلى الغليان من جديد وأضف الأرز؛ اطبخه 15–18 دقيقة حتى ينضج.\n\nاخفق البيض في وعاء حتى يصبح رغوياً وفاتح اللون، ثم اخفق فيه عصير الليمون. لطّف البيض: اسكب مغرفة من المرق الساخن عليه ببطء مع الخفق المستمر، ثم مغرفة ثانية، حتى يصبح الوعاء دافئاً عند اللمس.\n\nارفع القدر عن النار واسكب المزيج الملطّف فيه بخيط ثابت مع التحريك دون توقف — يجب ألا يغلي المرق بعد ذلك وإلا تخثّر البيض. عدّل الملح والفلفل الأبيض وقدّم فوراً، ورشّ الشبت أو البقدونس فوقها.","en":"Simmer the chicken in 2.5 L cold water with the carrots, onion, celery, bay leaf, parsley stems and peppercorns. Skim any foam and cook uncovered for about 90 minutes, until the meat falls from the bones.\n\nLift the chicken out, strain the broth into a clean pot and discard the vegetables. Shred the meat off the bones, return it to the broth, bring back to a simmer and stir in the rice; cook 15–18 minutes until tender.\n\nWhisk the eggs in a bowl until light and foamy, then whisk in the lemon juice. Temper them by slowly ladling a cup of hot broth in while whisking, then another, until the bowl is warm to the touch.\n\nOff the heat, pour the tempered eggs back into the pot in a slow steady stream, stirring continuously — never let the soup boil again. Season with salt and white pepper and serve immediately, finished with dill or parsley."}},{"id":195,"servings":4,"tipType":"meat","pairingsType":"mediterranean","nutrition":{"cal":620,"prot":38,"carb":52,"fat":28,"fib":4},"origin":{"ar":"اليونان","en":"Greece","ro":"Grecia"},"name":{"ar":"جيروس","en":"Gyros","ro":"Gyros"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"ingredients":{"ar":["1 كغ كتف خنزير، مقطّع شرائح بسماكة 1 سم عكس اتجاه الألياف (أو أوراك دجاج بدون عظم)","4 فصوص ثوم مفرومة","2 ملعقة كبيرة زيت زيتون يوناني","1 ملعقة كبيرة خل النبيذ الأحمر","1 ملعقة كبيرة زعتر مجفف (ريجاني يوناني إن أمكن)","1 ملعقة صغيرة بابريكا حلوة","1 ملعقة صغيرة ملح، ½ ملعقة صغيرة فلفل أسود","4 خبزات بيتا يونانية كبيرة وطرية (الخبز المسطّح غير المجوف)","للتقديم: 200 مل تزاتزيكي، 1 بندورة ناضجة شرائح، ½ بصلة حمراء شرائح رفيعة، زعتر، شرائح ليمون، بطاطس مقلية اختياري"],"en":["1 kg pork shoulder, sliced into 1 cm thick strips against the grain (or boneless chicken thighs)","4 garlic cloves, minced","2 tbsp Greek olive oil","1 tbsp red wine vinegar","1 tbsp dried oregano (Greek rigani if possible)","1 tsp sweet paprika","1 tsp salt, ½ tsp black pepper","4 large soft Greek pitas (the unfilled flatbread, not pocket pita)","To serve: 200 ml tzatziki, 1 ripe tomato sliced, ½ red onion thinly sliced, oregano, lemon wedges, optional French fries"],"ro":["1 kg ceafă de porc, tăiată în fâșii de 1 cm grosime contra fibrei (sau pulpe de pui dezosate)","4 căței de usturoi, tocați","2 linguri ulei de măsline grecesc","1 lingură oțet de vin roșu","1 lingură oregano uscat (rigani grecesc, dacă ai)","1 linguriță boia dulce","1 linguriță sare, ½ linguriță piper negru","4 lipii grecești mari și moi (turtă plată neumplută, nu pita cu buzunar)","Pentru servit: 200 ml tzatziki, 1 roșie coaptă feliată, ½ ceapă roșie tăiată subțire, oregano, felii de lămâie, opțional cartofi prăjiți"]},"howIsMade":{"ar":"اخفقي الثوم وزيت الزيتون والخل والأوريجانو والبابريكا والملح والفلفل في وعاء كبير، ثم أضيفي شرائح اللحم وقلّبي حتى تتغطى كل قطعة. غطّي واتركيها تتبّل ساعتين على الأقل، ويفضّل طوال الليل.\n\nسخّني مقلاة كبيرة ثقيلة أو صاج على نار عالية حتى تدخّن. ضعي شرائح اللحم بطبقة واحدة، على دفعات إن لزم الأمر، واقليها دون تحريك من 2 إلى 3 دقائق على كل وجه، حتى تتحمّر الحواف بعمق ويصبح القلب ناضجاً للتو؛ لا تكدّسي المقلاة وإلا انطبخ اللحم بالبخار بدل أن يتحمّر. ضعي كل دفعة جانباً على طبق ريثما تقلين التالية.\n\nسخّني الخبز اللبناني واحدة تلو الأخرى في المقلاة نفسها 20 ثانية لكل وجه، فقط حتى يصبح طريّاً. ضعي ملعقة كبيرة سخيّة من التزاتزيكي في الوسط، رتبي اللحم الساخن فوقها، أضيفي بعض شرائح الطماطم وحلقات البصل الأحمر — وإن أردتِ الإخلاص للنسخة الأثينية، حفنة صغيرة من البطاطس المقلية فوقها.\n\nلفّي السندويشات بإحكام في الورق مع طيّ أحد طرفيها، وقدّميها فوراً مع المزيد من الأوريجانو وشريحة ليمون وبقيّة التزاتزيكي على الجانب.","en":"Whisk the garlic, olive oil, vinegar, oregano, paprika, salt and pepper in a large bowl, add the pork strips and toss until every piece is coated. Cover and marinate at least 3 hours, ideally overnight.\n\nHeat a large heavy skillet or griddle pan over high heat until smoking. Lay the strips down in a single layer, in batches if needed, and sear without moving for 2–3 minutes per side, until the edges are deeply browned and the centre just cooked through; don't crowd the pan or the meat will steam instead of caramelise. Rest each batch on a plate while you cook the next.\n\nWarm the pitas one at a time on the same hot skillet for 20 seconds per side, just until pliable. Spread a heaped tablespoon of tzatziki down the centre of each, lay the hot pork on top, add a few tomato slices and rings of red onion, and — if you're being faithful to Athens — a small handful of French fries on top.\n\nWrap tightly in paper with one end pinched closed, and serve immediately with extra oregano, a wedge of lemon, and the rest of the tzatziki on the side."}},{"id":196,"servings":8,"tipType":"pasta","pairingsType":"mediterranean","nutrition":{"cal":680,"prot":30,"carb":62,"fat":32,"fib":4},"origin":{"ar":"اليونان","en":"Greece","ro":"Grecia"},"name":{"ar":"باستيتسيو","en":"Pastitsio","ro":"Pastitsio"},"category":{"ar":"معكرونة","en":"Pasta","ro":"Paste"},"ingredients":{"ar":["500 غ من معكرونة الباستيتسيو (طويلة وأنبوبية رقم 2؛ البوكاتيني بديل مقبول)","600 غ من اللحم البقري المفروم (أو نصف بقري ونصف ضأن)","1 بصلة كبيرة، مفرومة ناعماً","3 فصوص ثوم مفرومة","400 غ طماطم مفرومة (معلّبة)","2 ملعقة كبيرة معجون طماطم","150 مل نبيذ أحمر جاف","1 عود قرفة، 4 حبات قرنفل، 1 ورقة غار، 1 ملعقة صغيرة زعتر مجفف","100 غ من جبن الكفالوتيري أو البيكورينو مبشوراً ناعماً (الباغمزان يفي عند الضرورة)","للبيشاميل: 100 غ زبدة، 100 غ دقيق، 1 لتر حليب كامل الدسم، 4 صفار بيض، رشة جوزة الطيب المبشورة","ملح، فلفل، زيت زيتون"],"en":["500 g pastitsio noodles (long, tubular #2; bucatini is a fair substitute)","600 g beef mince (or half beef, half lamb)","1 large onion, finely chopped","3 garlic cloves, minced","400 g chopped tomatoes (canned)","2 tbsp tomato paste","150 ml dry red wine","1 cinnamon stick, 4 whole cloves, 1 bay leaf, 1 tsp dried oregano","100 g Kefalotyri or Pecorino, finely grated (Parmesan works at a pinch)","For the béchamel: 100 g butter, 100 g flour, 1 L whole milk, 4 egg yolks, a grating of nutmeg","Salt and pepper, olive oil"],"ro":["500 g paste tip pastitsio (lungi, tubulare nr. 2; bucatini este o alternativă bună)","600 g carne tocată de vită (sau jumătate vită, jumătate miel)","1 ceapă mare, tocată mărunt","3 căței de usturoi, tocați","400 g roșii tocate (la conservă)","2 linguri pastă de roșii","150 ml vin roșu sec","1 baton de scorțișoară, 4 cuișoare întregi, 1 frunză de dafin, 1 linguriță oregano uscat","100 g Kefalotyri sau Pecorino, ras fin (Parmezan se poate la nevoie)","Pentru béchamel: 100 g unt, 100 g făină, 1 l lapte integral, 4 gălbenușuri, puțină nucușoară rasă","Sare, piper, ulei de măsline"]},"howIsMade":{"ar":"سخّني 3 ملاعق كبيرة من زيت الزيتون في مقلاة ثقيلة وقومي بتشقير البصل المفروم لمدة 8–10 دقائق، أضيفي الثوم لمدة 30 ثانية، ثم فتّتي اللحم المفروم. كسّريه بملعقة خشبية واتركيه يتحمّر جيداً نحو 10 دقائق. أضيفي معجون الطماطم وقلّبيه حتى يصبح بلون الطوب، ثم أزيلي الجزء العالق بالنبيذ ودعيه يقلّ إلى النصف قبل إضافة الطماطم وعود القرفة والقرنفل وورقة الغار والأوريجانو. تبّلي بسخاء واتركيه يطهو دون غطاء على نار هادئة 45 دقيقة على الأقل؛ أخرجي البهارات الكاملة قبل التركيب.\n\nأثناء طهي اللحم، حضّري البشاميل: أذيبي الزبدة في قدر واسع، أضيفي الطحين وحرّكيه دقيقة أو دقيقتين دون أن يأخذ لوناً، اسكبي الحليب الدافئ بخيط رفيع مع الخفق المستمر، ثم اطبخيه 5–7 دقائق حتى يغطّي ظهر الملعقة. ارفعيه عن النار وأضيفي صفار البيض واحدة تلو الأخرى، ثم جوزة الطيب ونصف كمية الجبن المبشور، وتبّلي.\n\nاسلقي المعكرونة في ماء مملح جيداً لمدة دقيقتين أقل مما يشير العبوة — ستكمل النضج في الفرن — صفّيها وقلّبيها مع باقي الجبن ومغرفة من صلصة اللحم حتى لا تلتصق.\n\nفي صينية قياس 25×35 سم رتّبي نصف المعكرونة في اتجاه واحد، وزّعي صلصة اللحم بالتساوي فوقها، ثم غطّيها بباقي المعكرونة في الاتجاه ذاته. اسكبي البشاميل فوقها وسوّيها، واخبزيها على حرارة 180°م لمدة 45–50 دقيقة حتى تذهّب وتفقع.\n\nاتركيها ترتاح 20 دقيقة على الأقل قبل التقطيع، وإلا تساقطت الطبقات.","en":"Heat 3 tablespoons of olive oil in a heavy pan and brown the chopped onion for 8–10 minutes, add the garlic for 30 seconds, then crumble in the mince. Break it up with a wooden spoon and let it brown deeply, about 10 minutes. Stir in the tomato paste, fry until brick-red, deglaze with the wine and let it reduce by half before adding the tomatoes, cinnamon stick, cloves, bay leaf and oregano. Season generously and simmer uncovered on low heat for at least 45 minutes; fish out the whole spices before assembling.\n\nWhile the meat cooks, make the béchamel: melt the butter in a wide saucepan, whisk in the flour for a couple of minutes without colour, pour in the warm milk in a slow stream while whisking, then simmer 5–7 minutes until it coats the back of a spoon. Off the heat, beat in the egg yolks one at a time, add the nutmeg and half the grated cheese, and season.\n\nBoil the pasta in well-salted water 2 minutes less than the package says — it'll finish in the oven — drain and toss with the remaining cheese and a ladle of meat sauce so the noodles don't stick.\n\nIn a 25×35 cm baking dish, lay half the pasta in one direction, spread the meat sauce evenly over it, then top with the rest of the pasta aligned the same way. Pour the béchamel over, smooth it level, and bake at 180°C for 45–50 minutes until golden and bubbling.\n\nLet it rest at least 20 minutes before cutting; sliced too hot, the layers collapse."}},{"id":197,"servings":6,"tipType":"veg","pairingsType":"mediterranean","nutrition":{"cal":280,"prot":5,"carb":35,"fat":14,"fib":3},"origin":{"ar":"اليونان","en":"Greece","ro":"Grecia"},"name":{"ar":"دولمادس","en":"Dolmades","ro":"Dolmades"},"category":{"ar":"مقبلات","en":"Appetizer","ro":"Aperitiv"},"ingredients":{"ar":["1 برطمان (450 غ) من ورق العنب المخلّل، مصفّى ومغسول (أو 60 ورقة طازجة مسلوقة قليلاً)","200 غ أرز طويل الحبة (ينفع أيضاً الأربوريو)","1 بصلة كبيرة، مفرومة ناعماً","6 بصلات خضراء، شرائح رفيعة","حزمة كبيرة من الشبت الطازج، مفرومة","حزمة صغيرة من النعناع الطازج، مفرومة","حزمة صغيرة من البقدونس عريض الورقة، مفرومة","عصير ليمونتين","150 مل زيت زيتون بكر ممتاز","1 ملعقة صغيرة ملح، فلفل أسود مطحون طازجاً","اختياري لكنه تقليدي: 1 طماطم مبشورة"],"en":["1 jar (450 g) preserved grape leaves, drained and rinsed (or 60 fresh blanched leaves)","200 g long-grain rice (arborio works)","1 large onion, finely chopped","6 spring onions, thinly sliced","A large bunch of fresh dill, chopped","A small bunch of fresh mint, chopped","A small bunch of flat-leaf parsley, chopped","Juice of 2 lemons","150 ml extra-virgin olive oil","1 tsp salt, freshly ground black pepper","Optional but traditional: 1 grated tomato"],"ro":["1 borcan (450 g) de frunze de viță conservate, scurse și clătite (sau 60 de frunze proaspete opărite)","200 g orez cu bob lung (merge și arborio)","1 ceapă mare, tocată mărunt","6 fire de ceapă verde, tăiate subțire","Un mănunchi mare de mărar proaspăt, tocat","Un mănunchi mic de mentă proaspătă, tocată","Un mănunchi mic de pătrunjel cu frunza plată, tocat","Zeama de la 2 lămâi","150 ml ulei de măsline extravirgin","1 linguriță sare, piper negru proaspăt măcinat","Opțional dar tradițional: 1 roșie rasă"]},"howIsMade":{"ar":"انقعي الأرز في ماء بارد 15 دقيقة وصفّيه. سخّني 3 ملاعق كبيرة من زيت الزيتون في مقلاة واسعة وقومي بتعريق البصل المفروم 8 دقائق حتى يصبح شفافاً دون أن يأخذ لوناً. أضيفي البصل الأخضر وجميع الأعشاب والأرز المصفّى ونصف عصير الليمون ورشّة سخيّة من الملح؛ قلّبي لمدة دقيقة لإطلاق العطور، ثم انقلي الحشوة إلى صحن لتبرد إلى حرارة الغرفة.\n\nضعي ورقة عنب على سطح العمل بحيث تكون عروقها للأعلى والساق نحوك. ضعي ملعقة صغيرة مكوّمة من حشوة الأرز قرب الساق، ثم اطوي الحافة السفلى فوق الحشوة، اثني الجانبين للداخل ولفّي بإحكام على شكل سيجار صغير. لا تملئيها أكثر من اللازم — الأرز ينتفخ أثناء الطهي، والمحشي الضيق ينفجر.\n\nرصّفي قاع قدر ثقيل بأوراق ممزّقة لمنع الالتصاق. رتّبي المحشي في دوائر متراكزة، مع توجيه طرف اللفّ نحو الأسفل، متلاصقاً ليثبّت بعضه بعضاً. اسكبي ما تبقّى من زيت الزيتون وعصير الليمون فوقها، أضيفي ماءً بارداً حتى يصل إلى مستوى المحشي، ثم اضغطي طبقاً مقاوماً للحرارة فوقها مباشرة كي تبقى مغمورة.\n\nأوصليها ببطء إلى الغليان الخفيف، غطّيها واطهيها على أقل نار من 50 إلى 60 دقيقة، حتى ينضج الأرز ويُمتصّ معظم السائل. اتركيها تبرد في القدر — تُقدَّم باردة أو في حرارة الغرفة، مع شريحة ليمون ووعاء من اللبن السميك. إذا حُضِّرت قبل يوم، يصبح طعمها أفضل بكثير.","en":"Soak the rice in cold water for 15 minutes and drain. Heat 3 tablespoons of olive oil in a wide pan and sweat the chopped onion for 8 minutes until translucent, no colour. Add the spring onions, all the herbs, the drained rice, half the lemon juice and a generous pinch of salt; stir for a minute to bloom the aromas, then tip onto a plate to cool to room temperature.\n\nLay a grape leaf on the work surface vein-side up, stem at the bottom. Place a heaped teaspoon of the rice mixture near the stem, fold the bottom edge up and over, fold both sides in, and roll up tightly into a small cigar. Don't overfill — the rice swells as it cooks and packed too tightly the dolma will split.\n\nLine the bottom of a heavy pot with torn or broken leaves to prevent sticking. Pack the rolled dolmades in concentric circles, seam-side down, snug enough to hold each other in place. Pour over the remaining olive oil and lemon juice, add cold water just to the top of the dolmades, and press a heatproof plate directly on the surface to keep them submerged.\n\nBring slowly to a simmer, cover, and cook on the lowest heat for 50 minutes to an hour, until the rice is tender and the liquid mostly absorbed. Leave to cool in the pot — they're served cold or at room temperature, with a wedge of lemon and a bowl of thick yoghurt. Made the day before, they taste markedly better."}},{"id":198,"servings":12,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":380,"prot":7,"carb":48,"fat":18,"fib":1},"origin":{"ar":"اليونان","en":"Greece","ro":"Grecia"},"name":{"ar":"غالاكتوبوريكو","en":"Galaktoboureko","ro":"Galaktoboureko"},"category":{"ar":"تحلية","en":"Dessert","ro":"Desert"},"ingredients":{"ar":["500 غ من عجين الفيلو، مُذابة","200 غ زبدة غير مملحة، مذابة","1 لتر حليب كامل الدسم","200 غ سكر ناعم (للكاسترد)","150 غ سميد ناعم","4 بيضات كبيرة","1 ملعقة صغيرة خلاصة فانيليا","بشر ليمونة واحدة","للقطر: 400 غ سكر، 250 مل ماء، عصير نصف ليمونة، شريحة قشر برتقال، 1 عود قرفة"],"en":["500 g phyllo pastry, thawed","200 g unsalted butter, melted","1 L whole milk","200 g caster sugar (for the custard)","150 g fine semolina","4 large eggs","1 tsp vanilla extract","Zest of 1 lemon","For the syrup: 400 g caster sugar, 250 ml water, juice of half a lemon, a strip of orange peel, 1 stick of cinnamon"],"ro":["500 g foi de plăcintă (phyllo), dezghețate","200 g unt nesărat, topit","1 l lapte integral","200 g zahăr tos (pentru cremă)","150 g griș fin","4 ouă mari","1 linguriță extract de vanilie","Coaja rasă de la 1 lămâie","Pentru sirop: 400 g zahăr, 250 ml apă, zeama de la o jumătate de lămâie, o fâșie de coajă de portocală, 1 baton de scorțișoară"]},"howIsMade":{"ar":"ابدأ بالقطر مسبقاً — يجب أن يكون بارداً حين تخرج الفطيرة الساخنة من الفرن — اخلط السكر، الماء، عصير الليمون، قشر البرتقال والقرفة في قدر صغير، أوصلها إلى الغليان ثم اطهِها 4 دقائق، ارفعها عن النار واتركها تبرد تماماً. للكاسترد، سخّن الحليب في قدر واسع مع السكر وبشر الليمون حتى يكاد يتبخّر (لا تتركه يغلي)، انثر السميد في خيط رفيع متجانس وأنت تخفق باستمرار، ثم استمر في الخفق على نار هادئة لمدة 5–6 دقائق حتى يثخن إلى بودنغ خفيف؛ بعيداً عن النار، أدخل البيض واحدة تلو الأخرى (يجب أن يكون المزيج دافئاً ولكن ليس ساخناً بما يكفي لطهيها) والفانيلا، ثم اضغط غشاء بلاستيكي مباشرة على السطح لمنع تكوّن طبقة. ادهن صحن فرن 22×30 سم بالزبدة المذابة، ضع 7 شرائح من الفيلو في القاع وادهن كل واحدة بالزبدة بسخاء واترك الحواف معلقة على الجانبين (هذه الأطراف ستُطوى على الأعلى لاحقاً)، اسكب الكاسترد الدافئ، سوّه، اطو الأطراف المعلقة إلى الداخل وادهنها بالزبدة، ثم غطّ بـ 7 شرائح فيلو إضافية (وادهن كل واحدة بالزبدة) وقص أو ادفع الحواف بحيث تكون الفطيرة مغلقة تماماً. قطع الفيلو العلوي إلى ماسات أو مربعات بسكين حاد — اقطع حتى الأسفل ليتمكن القطر لاحقاً من الاختراق — ادهن السطح بسخاء بآخر الزبدة، واخبز على 170°م لمدة 45–55 دقيقة حتى يصبح الأعلى ذهبياً بنياً عميقاً. في اللحظة التي تخرج فيها من الفرن، اسكب القطر البارد بالتساوي على الفطيرة الساخنة — ستفور وتتبخّر — اتركها تستقر 4 ساعات على الأقل، ويفضل طوال الليل، قبل أن تقطعها عبر خطوط التقطيع وتقدمها في درجة حرارة الغرفة.","en":"Start the syrup well in advance — it must be cold when the hot pie comes out of the oven — combine the sugar, water, lemon juice, orange peel and cinnamon in a small saucepan, bring to a boil then simmer 4 minutes, take off the heat and leave to cool completely. For the custard, heat the milk in a wide saucepan with the sugar and lemon zest until just steaming (do not let it boil), sprinkle the semolina in a fine even stream while whisking constantly, then keep whisking on low heat for 5–6 minutes until it thickens to a loose pudding; off the heat, beat in the eggs one at a time (the mixture should be warm but not hot enough to scramble them) and the vanilla, then press clingfilm directly onto the surface to stop a skin forming. Brush a 22×30 cm baking dish with melted butter, lay 7 sheets of phyllo across the bottom brushing each generously with butter and letting the edges hang over the sides (those flaps will fold back over the top later), pour in the still-warm custard, smooth it level, fold the overhanging flaps inward and brush them with butter, then cover with another 7 sheets of phyllo (again buttering each) and trim or tuck the edges so the pie is fully sealed. Score the top phyllo into diamonds or squares with a sharp knife — cut all the way through so the syrup can later penetrate — brush the surface lavishly with the last of the butter, and bake at 170°C for 45–55 minutes until the top is deeply golden brown. The moment it comes out of the oven, pour the cold syrup evenly over the hot pie — it will sizzle and steam — leave to settle at least 4 hours, ideally overnight, before cutting along the score lines and serving at room temperature."}},{"id":199,"servings":4,"tipType":"def","pairingsType":"italian","nutrition":{"cal":740,"prot":28,"carb":88,"fat":30,"fib":4},"origin":{"ar":"إيطاليا","en":"Italy","ro":"Italia"},"name":{"ar":"بيتزا مارغريتا","en":"Pizza Margherita","ro":"Pizza Margherita"},"category":{"ar":"بيتزا","en":"Pizza","ro":"Pizza"},"ingredients":{"ar":["للعجين (4 بيتزات): 500 غ دقيق 00 (أو دقيق الخبز)، 325 مل ماء بارد، 10 غ ملح، 1 غ خميرة طازجة (أو ¼ ملعقة صغيرة من الجافة)","لكل بيتزا: 80 غ من طماطم سان مارزانو (معلّبة، تُهرس باليد)، رشة ملح، رشّة زيت زيتون","100 غ موزاريلا فيور دي لاتي لكل بيتزا، مفتّتة باليد (أو موزاريلا الجاموس)","بضع أوراق ريحان طازج لكل بيتزا","زيت زيتون بكر ممتاز للتزيين","سميد أو دقيق للتشكيل وللمجرفة"],"en":["For the dough (4 pizzas): 500 g 00 flour (or bread flour), 325 ml cold water, 10 g salt, 1 g fresh yeast (or ¼ tsp dried)","For each pizza: 80 g San Marzano tomatoes (canned, hand-crushed), a pinch of salt, a drizzle of olive oil","100 g fior di latte mozzarella per pizza, torn into pieces (or buffalo mozzarella)","A few fresh basil leaves per pizza","Extra-virgin olive oil to finish","Semolina or flour for shaping and the peel"],"ro":["Pentru aluat (4 pizza): 500 g făină 00 (sau pentru pâine), 325 ml apă rece, 10 g sare, 1 g drojdie proaspătă (sau ¼ linguriță uscată)","Pentru fiecare pizza: 80 g roșii San Marzano (la conservă, sfărâmate cu mâna), un praf de sare, un fir de ulei de măsline","100 g mozzarella fior di latte per pizza, ruptă în bucățele (sau mozzarella de bivoliță)","Câteva frunze de busuioc proaspăt pentru fiecare pizza","Ulei de măsline extravirgin pentru finalizare","Griș sau făină pentru modelare și pentru lopată"]},"howIsMade":{"ar":"للعجين، أذِب الخميرة في الماء البارد، ثم اخلط الدقيق والملح حتى تحصل على كتلة خشنة، اعجن باليد لمدة 10 دقائق (أو 6 دقائق بخلاط ثابت مع شفرة العجن) حتى يصبح ناعماً ومرناً، غطّ ودعه يرتاح في درجة حرارة الغرفة لمدة ساعة، ثم برّده في الثلاجة 24 ساعة على الأقل، ويفضل 48 إلى 72 — التخمير البارد الطويل هو ما يمنح العجين النابولي تلك القشرة المتفقعة المتفحمة والبنية الهوائية. قبل الخبز بساعتين، أخرج العجين، قسّمه إلى أربع كرات بوزن 210 جم، رشّ بالطحين، غطّ بقماشة مبللة، ودعها تعود إلى حرارة الغرفة، في هذه الأثناء سخّن الفرن إلى أقصى درجة (250°م أو أعلى) مع حجر بيتزا أو صفيحة فولاذية ثقيلة بالداخل لمدة 45 دقيقة على الأقل؛ بدون حرارة جدية تحت البيتزا، لن تثبت القشرة في الوقت المناسب. ابسط كرة باليد على سطح مرشوش بالطحين بوفرة — اضغط على المركز بأطراف الأصابع تاركاً حافة مرتفعة، ثم اسحب وامدد القرص بلطف إلى نحو 28 سم — لا تستخدم أبداً مرر العجين، فهو يهدم جيوب الغاز في القشرة — وادفعها على مجرفة مرشوشة بالطحين. ضع 80 جم من الطماطم المهروسة في المركز وافردها بشكل حلزوني بظهر الملعقة متوقفاً على بُعد 2 سم من الحافة، رشّ الطماطم بقليل من الملح، رشّ القليل من زيت الزيتون، وانثر الموزاريلا الممزقة فوقها (ليس كثيراً، وإلا فاضت البيتزا). ادفع البيتزا على الحجر واخبزها حتى تنتفخ القشرة وتظهر بقع متفحمة، يذوب الجبن في برك، وتصبح الحافة ذهبية داكنة — 4 إلى 6 دقائق في فرن منزلي على أقصاه، و 90 ثانية في فرن نابولي يعمل بالحطب — أخرجها، مزّق أوراق الريحان فوقها (التي ستحترق في الفرن)، رشّ خيطاً أخيراً من زيت الزيتون، وتناولها فوراً.","en":"For the dough, dissolve the yeast in the cold water then mix in the flour and salt until you have a shaggy mass, knead by hand for 10 minutes (or 6 minutes with a stand mixer and dough hook) until smooth and elastic, cover and rest at room temperature for an hour, then refrigerate for at least 24 hours and ideally 48 to 72 — the long cold proof is what gives Neapolitan dough its blistered char and airy structure. Two hours before baking, take the dough out, divide into four 210 g balls, dust with flour, cover with a damp cloth and let them come to room temperature, meanwhile heat the oven as hot as it goes (250°C or above) with a pizza stone or heavy steel sheet inside for at least 45 minutes; without serious heat under the pizza, the crust will never set in time. Hand-stretch one ball on a well-floured surface — press the centre flat with your fingertips leaving a raised lip, then gently pull and stretch the disc to about 28 cm across — never use a rolling pin, which collapses the gas pockets in the crust — and slide it onto a floured peel. Spoon 80 g of crushed tomato into the centre and spread it in a spiral with the back of the spoon stopping 2 cm from the edge, salt the tomato lightly, drizzle a little olive oil, and scatter the torn mozzarella over the top (not too much, or the pizza floods). Slide the pizza onto the stone and bake until the crust is puffed and charred in spots, the cheese has melted into pools and the rim is dark gold — 4 to 6 minutes in a domestic oven at full blast, 90 seconds in a wood-fired Neapolitan oven — pull it out, tear over the basil leaves (which would scorch in the oven), drizzle a final thread of olive oil, and eat immediately."}},{"id":200,"servings":6,"tipType":"pasta","pairingsType":"italian","nutrition":{"cal":720,"prot":36,"carb":58,"fat":36,"fib":4},"origin":{"ar":"إيطاليا","en":"Italy","ro":"Italia"},"name":{"ar":"لازانيا بالبولونيز","en":"Lasagne alla Bolognese","ro":"Lasagne alla Bolognese"},"category":{"ar":"معكرونة","en":"Pasta","ro":"Paste"},"ingredients":{"ar":["للراغو: 400 غ لحم بقري مفروم، 200 غ لحم خنزير مفروم، 80 غ بانشيتا مكعّبات صغيرة، 1 بصلة + 1 جزرة + 1 ساق كرفس مفرومة كلها ناعماً، 200 مل نبيذ أحمر جاف، 400 غ صلصة بصاطة أو طماطم مفرومة، 250 مل حليب كامل الدسم، 1 ورقة غار، ملح وفلفل، زيت زيتون","للبيشاميل: 80 غ زبدة، 80 غ دقيق، 1 لتر حليب كامل الدسم، ملح، رشة جوزة الطيب","300 غ ألواح لازانيا طازجة بالبيض (أو 250 غ جافة، مسلوقة)","150 غ بارميجانو ريجيانو مبشور ناعماً","زبدة لدهن الصينية"],"en":["For the ragù: 400 g beef mince, 200 g pork mince, 80 g pancetta finely diced, 1 onion + 1 carrot + 1 celery stalk all finely diced, 200 ml dry red wine, 400 g passata or chopped tomatoes, 250 ml whole milk, 1 bay leaf, salt and pepper, olive oil","For the béchamel: 80 g butter, 80 g flour, 1 L whole milk, salt, a grating of nutmeg","300 g fresh egg lasagne sheets (or 250 g dried, blanched)","150 g Parmigiano Reggiano, finely grated","Butter for the dish"],"ro":["Pentru ragù: 400 g vită tocată, 200 g porc tocat, 80 g pancetta tăiată cubulețe, 1 ceapă + 1 morcov + 1 țelină — toate tocate mărunt, 200 ml vin roșu sec, 400 g passata sau roșii tocate, 250 ml lapte integral, 1 frunză de dafin, sare și piper, ulei de măsline","Pentru béchamel: 80 g unt, 80 g făină, 1 l lapte integral, sare, puțină nucușoară rasă","300 g foi proaspete de lasagne cu ou (sau 250 g uscate, opărite)","150 g Parmigiano Reggiano, ras fin","Unt pentru vasul de copt"]},"howIsMade":{"ar":"أذِب البانشيتا برفق في قدر ثقيل مع رشة زيت الزيتون على نار متوسطة-منخفضة لمدة 5 دقائق حتى تخرج الدهون صافية، أضف الصوفريتو المفروم (بصل، جزر، كرفس) واطبخ 10 دقائق حتى يصبح طرياً ومذهباً عند الحواف، ثم فتت اللحمين وحمّرهما بشكل صحيح — صبر: لا تحرّك خلال أول 3 دقائق، ثم فتت واطبخ 10 دقائق إضافية حتى يصبح قعر القدر متكرملاً بعمق. اسكب النبيذ، اكشط طبقة الفوند من القعر بملعقة خشبية وقلّل إلى النصف، ثم أضف الطماطم، الحليب (توقيع بولوني — يدوّر الحمضية ويشدّ القوام)، ورقة الغار وملعقة صغيرة من الملح؛ أوصلها إلى غليان بالكاد محسوس، غطّ جزئياً، واطبخ على أهدأ نار ممكنة لمدة لا تقل عن ساعتين، ويفضل 3 ساعات، مع التقليب من حين لآخر وإضافة رشة ماء إذا هددت بالجفاف — الراغو الجاهز يجب أن يكون لامعاً، أحمر-بنياً عميقاً وشبه عجين، ليس شوربة. أثناء انتهاء الراغو، حضّر البشاميل: أذِب الزبدة، اخفق الطحين لمدة دقيقتين بدون لون، اسكب الحليب الدافئ بخيط بطيء أثناء الخفق واطهُ 5 دقائق حتى يثخن، ثم تبّل بالملح وبرشة سخية من جوزة الطيب. إذا استخدمت ألواح اللازانيا الجافة، اسلقها في ماء مغلي مملح لمدة دقيقة وضعها على مناشف مبللة — الألواح الطازجة تذهب نيئة — سخّن الفرن إلى 180°م وادهن صحن خبز 25×35 سم بالزبدة، ثم افرد طبقة رقيقة من البشاميل في القاع، ثم طبقة من الباستا، ثم راغو، ثم بشاميل، ثم رشة بيضاء من البارميجيانو، وكرّر حتى تستخدم كل شيء (ست إلى سبع طبقات هو الهدف البولوني)، منتهياً ببشاميل وبشاميل أكثر سخاء من البارميجيانو. اخبز 35–40 دقيقة حتى يصبح السطح برونزياً ويفور، ثم أرحه 20 دقيقة قبل التقطيع — اللازانيا المقطعة وهي ساخنة تنزلق، أما المرتاحة فتحافظ على طبقاتها.","en":"Render the pancetta gently in a heavy pot with a splash of olive oil over medium-low heat for 5 minutes until the fat runs clear, add the chopped soffritto (onion, carrot, celery) and cook 10 minutes until soft and just gilded at the edges, then crumble in both meats and brown them properly — patience: do not stir for the first 3 minutes, then break them up and cook 10 more minutes until the pan bottom is deeply caramelised. Pour in the wine, scrape the fond from the pan with a wooden spoon and reduce by half, then add the tomatoes, the milk (the Bolognese signature — it rounds the acid and tightens the texture), the bay leaf and a teaspoon of salt; bring to a bare simmer, partially cover, and cook on the lowest possible heat for at least 2 hours and ideally 3, stirring occasionally and adding a splash of water if it threatens to dry — the finished ragù should be glossy, deep brown-red and almost a paste, never a soup. While the ragù finishes, make the béchamel: melt the butter, whisk in the flour for 2 minutes without colour, pour in the warm milk in a slow stream while whisking and simmer 5 minutes until thick, then season with salt and a generous grating of nutmeg. If using dried lasagne sheets blanch them in salted boiling water for a minute and lay on damp tea towels — fresh sheets go in raw — heat the oven to 180°C and butter a 25×35 cm baking dish, then spread a thin layer of béchamel on the bottom, then a layer of pasta, then ragù, then béchamel, then a snowy dusting of Parmigiano, and repeat until you have used everything (six to seven layers is the Bolognese target), finishing with béchamel and a heavier shower of Parmigiano. Bake 35–40 minutes until the top is bronzed and bubbling, then rest 20 minutes before cutting — lasagne sliced hot slides apart, lasagne rested holds its layers."}},{"id":201,"servings":4,"tipType":"meat","pairingsType":"italian","nutrition":{"cal":580,"prot":42,"carb":18,"fat":32,"fib":3},"origin":{"ar":"إيطاليا","en":"Italy","ro":"Italia"},"name":{"ar":"أوسوبوكو ميلانيز","en":"Osso Buco alla Milanese","ro":"Osso Buco alla Milanese"},"category":{"ar":"طبق رئيسي","en":"Main","ro":"Fel principal"},"ingredients":{"ar":["4 شرائح سميكة من ساق العجل (3–4 سم سُمكاً، نحو 350 غ لكل واحدة)، مربوطة بخيط مطبخ حول المحيط","ملح وفلفل أسود مطحون طازجاً","دقيق أبيض للتغطية","4 ملاعق كبيرة زبدة غير مملحة، 2 ملعقة كبيرة زيت زيتون","1 بصلة + 1 جزرة + 1 ساق كرفس، جميعها مفرومة ناعماً","200 مل نبيذ أبيض جاف","400 غ طماطم مفرومة","500 مل مرق عجل أو دجاج","1 ورقة غار، بضع غصينات زعتر","للغريمولاتا: بشر ليمونة واحدة، 2 فص ثوم مفرومة جداً، حزمة صغيرة بقدونس عريض الورقة مفرومة"],"en":["4 thick-cut veal shanks (3–4 cm thick, about 350 g each), tied around the circumference with kitchen string","Salt and freshly ground black pepper","Plain flour for dusting","4 tbsp unsalted butter, 2 tbsp olive oil","1 onion + 1 carrot + 1 celery stalk, all finely diced","200 ml dry white wine","400 g chopped tomatoes","500 ml veal or chicken stock","1 bay leaf, a few sprigs of thyme","For the gremolata: zest of 1 lemon, 2 garlic cloves finely minced, a small bunch of flat-leaf parsley finely chopped"],"ro":["4 rasoluri groase de vițel (3–4 cm grosime, aproximativ 350 g fiecare), legate cu sfoară de bucătărie pe circumferință","Sare și piper negru proaspăt măcinat","Făină albă pentru tăvălit","4 linguri unt nesărat, 2 linguri ulei de măsline","1 ceapă + 1 morcov + 1 țelină, toate tocate mărunt","200 ml vin alb sec","400 g roșii tocate","500 ml fond de vițel sau pui","1 frunză de dafin, câteva fire de cimbru","Pentru gremolata: coaja rasă de la 1 lămâie, 2 căței de usturoi tocați fin, un mănunchi mic de pătrunjel cu frunza plată, tocat fin"]},"howIsMade":{"ar":"جفّف قطع الكاحل بمنشفة ورقية — اللحم الرطب يتبخّر بدلاً من أن يُحمّر — تبّلها بقوة بالملح والفلفل ورشّها بالطحين قليلاً مع نفض الفائض، ثم سخّن نصف الزبدة وكامل الزيت في قدر طهي بطيء ثقيل على نار متوسطة-عالية حتى يرغو، ضع قطع الكاحل ولا تلمسها لمدة 4 دقائق حتى يصبح القعر بنياً عميقاً، اقلبها للجانب الآخر، ثم ارفعها على طبق. اخفض النار إلى متوسطة، أضف باقي الزبدة والصوفريتو، واطبخ برفق 10 دقائق حتى يصبح طرياً وذهبياً عند الأطراف، ثم اسكب النبيذ، ارفع النار، وقلّل إلى النصف مع كشط القطع المتكرملة من قعر القدر. أضف الطماطم وورقة الغار والزعتر، أعد قطع الكاحل إلى القدر في طبقة واحدة، واسكب مرقاً بما يكفي تماماً ليصل إلى ثلثي ارتفاع اللحم — يجب أن تبقى العظام مكشوفة لتظل الفقمة فيها — وأوصلها إلى غليان بالكاد محسوس. غطّ واطبخ ببطء على أهدأ نار أو في فرن 160°م لمدة 2 إلى 2½ ساعة، مع تقليب قطع الكاحل برفق كل 30 دقيقة كي تنضج بانتظام — تكون جاهزة حين يسقط اللحم عن العظم عند الضغط بملعقة وتثخن الصلصة إلى طلاء لامع — ثم ارفعها بحذر لأن العظام والفقمة هشّة في هذه المرحلة. أثناء راحة قطع الكاحل، اخلط قشر الليمون والثوم والبقدونس لصنع الغريمولاتا، ضع قطعة كاحل في كل طبق، اسكب فوقها كمية وفيرة من الصلصة، وتوّجها برشة سخية من الغريمولاتا الخام — حدّتها تقطع الثراء وهي ما يجعله أوسو بوكو ميلاني بدلاً من مجرد لحم عجل مطهو — قدّمه مع ريزوتو ميلاني أو بولينتا أو قطعة خبز للفقمة.","en":"Pat the shanks dry — wet meat steams instead of searing — season aggressively with salt and pepper and dust lightly in flour knocking off the excess, then heat half the butter and all the oil in a heavy braising pan over medium-high heat until foaming, lay the shanks in and do not touch them for 4 minutes until the bottom is deeply browned, flip and do the second side, then lift onto a plate. Lower the heat to medium, add the rest of the butter and the soffritto, and cook gently for 10 minutes until soft and golden at the edges, then pour in the wine, raise the heat, and reduce by half while scraping up the caramelised bits from the bottom of the pan. Stir in the tomatoes, bay leaf and thyme, return the shanks to the pan in a single layer, and pour in just enough stock to come about two-thirds of the way up the meat — the bones should stay exposed so the marrow stays in — and bring to a bare simmer. Cover and braise on the lowest heat or in a 160°C oven for 2 to 2½ hours, turning the shanks gently every 30 minutes so they cook evenly — they are done when the meat slumps off the bone at the press of a spoon and the sauce has thickened to a glossy gravy — then lift them out carefully because the bones and marrow are fragile at this point. While the shanks rest, stir together the lemon zest, garlic and parsley to make the gremolata, place a shank on each plate, spoon over plenty of sauce, and crown with a generous pinch of the raw gremolata — its sharpness cuts the richness and is what makes osso buco Milanese rather than just braised veal — serve with risotto alla milanese, polenta, or a piece of bread for the marrow."}},{"id":202,"servings":8,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":540,"prot":9,"carb":42,"fat":36,"fib":1},"origin":{"ar":"إيطاليا","en":"Italy","ro":"Italia"},"name":{"ar":"تيراميسو","en":"Tiramisu","ro":"Tiramisu"},"category":{"ar":"تحلية","en":"Dessert","ro":"Desert"},"ingredients":{"ar":["500 غ مسكربوني، في حرارة الغرفة","5 بيضات كبيرة، مفصولة، في حرارة الغرفة","100 غ سكر ناعم","250 مل إسبريسو قوي بارد (نحو 5 جرعات)","2 ملعقة كبيرة مارسالا حلوة أو رم داكن (اختياري، تقليدي في تريفيزو)","300 غ سافوياردي (أصابع البسكويت الإيطالية — النوع الصلب لا الطري)","كاكاو غير محلّى للتزيين","قطعة صغيرة من الشوكولاتة الداكنة للبرش (اختياري)","رشة ملح للبياض"],"en":["500 g mascarpone, at room temperature","5 large eggs, separated, at room temperature","100 g caster sugar","250 ml strong cold espresso (about 5 shots)","2 tbsp Marsala (sweet) or dark rum (optional, traditional in Treviso)","300 g savoiardi (Italian ladyfingers — the firm kind, not the soft kind)","Unsweetened cocoa powder for dusting","A small piece of dark chocolate for shaving (optional)","Pinch of salt for the egg whites"],"ro":["500 g mascarpone, la temperatura camerei","5 ouă mari, separate, la temperatura camerei","100 g zahăr tos","250 ml espresso tare rece (aproximativ 5 ceșcuțe)","2 linguri Marsala dulce sau rom închis (opțional, tradițional la Treviso)","300 g savoiardi (pișcoturi italiene — cele ferme, nu cele moi)","Cacao amară pentru pudrare","O bucățică de ciocolată neagră pentru ras (opțional)","Un praf de sare pentru albușuri"]},"howIsMade":{"ar":"اخفق صفار البيض مع السكر في وعاء كبير لمدة 4–5 دقائق — يدوياً أو بالخفاقة الكهربائية — حتى يصبح المزيج فاتح اللون، رغوياً، ومتضاعف الحجم إلى ثلاثة أمثاله؛ يجب أن يذوب السكر تماماً حين تفرك القليل بين أصابعك، الخفق الناقص هنا يعطيك تيراميسو حبيبياً لاحقاً. أضف المسكربون على ثلاث دفعات، اخفق برفق بعد كل دفعة، حتى تصبح الكريمة ناعمة ولامعة، ثم في وعاء نظيف منفصل اخفق بياض البيض مع رشة ملح إلى قمم متماسكة ولامعة تحتفظ بشكلها عند رفع الخفاقة، وادمج البياض في المسكربون على ثلاث إضافات بملعقة كبيرة، مع الطي من المركز إلى الخارج للحفاظ على الهواء بالداخل — يجب أن تكون الكريمة النهائية خفيفة، تكاد تكون قابلة للسكب لكنها تحتفظ بقمم لينة. اخلط الإسبريسو البارد والمارسالا في طبق ضحل، ثم اغمس السافواردي قطعةً واحدة في كل مرة — لفترة قصيرة فقط، ثانيتان لكل جانب على الأكثر — فهي إسفنجات، وأصابع السيدات المنقوعة أكثر من اللازم تتحول إلى عجين وتبكي عبر الكريمة، ورتّبها في طبقة واحدة محكمة في قاع طبق 22×30 سم. افرد نصف كريمة المسكربون فوق السافواردي في طبقة متساوية، ثم كرّر — طبقة أخرى محكمة من السافواردي المغموسة، ثم بقية الكريمة فوقها، مسطّحة بالملعقة. غطّ بغشاء بلاستيكي وضع في الثلاجة لمدة 6 ساعات على الأقل، ويفضل طوال الليل — التيراميسو المأكول في نفس اليوم يكون طعمه كأجزائه المنفصلة، أما المرتاح ليلة كاملة فطعمه كحلوى واحدة — قبل التقديم مباشرة، انثر الكاكاو بسخاء عبر مصفاة ناعمة، ابشر فوقه قليلاً من الشوكولاتة الداكنة إذا أحببت، واقطعه بسكين ساخن يُمسح بين الشرائح.","en":"Whisk the egg yolks with the sugar in a large bowl for 4–5 minutes — by hand or with an electric beater — until pale, foamy and dramatically tripled in volume; the sugar should be completely dissolved when you rub a little between your fingers, undermixing here gives you a grainy tiramisu later. Add the mascarpone in three batches, whisking gently after each, until the cream is smooth and glossy, then in a separate clean bowl whisk the egg whites with a pinch of salt to firm glossy peaks that hold their shape when the whisk is lifted, and fold the whites into the mascarpone in three additions with a large spatula, folding from the centre outwards to keep the air in — the finished cream should be light, almost pourable but holding soft peaks. Mix the cold espresso and Marsala in a shallow dish, then dip the savoiardi one at a time — just briefly, 2 seconds per side at most — they are sponges, and oversoaked ladyfingers turn to mush and weep through the cream, and lay them in a tight single layer in the bottom of a 22×30 cm dish. Spread half the mascarpone cream over the ladyfingers in an even layer, then repeat — another tight layer of dipped savoiardi, then the rest of the cream on top, smoothed level with the spatula. Cover with clingfilm and refrigerate at least 6 hours, ideally overnight — tiramisu eaten the same day tastes like its parts, tiramisu rested overnight tastes like one dessert — just before serving dust the top generously with cocoa pushed through a fine sieve, shave over a little dark chocolate if you like, and cut with a hot knife wiped between slices."}},{"id":203,"servings":4,"tipType":"pasta","pairingsType":"italian","nutrition":{"cal":520,"prot":22,"carb":76,"fat":14,"fib":3},"origin":{"ar":"إيطاليا","en":"Italy","ro":"Italia"},"name":{"ar":"كاتشو إي بيبي","en":"Cacio e Pepe","ro":"Cacio e Pepe"},"category":{"ar":"معكرونة","en":"Pasta","ro":"Paste"},"ingredients":{"ar":["400 غ من توناريلي أو سباغيتي سميك","200 غ من جبن بيكورينو رومانو، مبشور ناعم على مبشرة دقيقة (لا بارميزان — لا يذوب بنفس الطريقة)","1 ملعقة كبيرة مكوّمة من حبات الفلفل الأسود الكاملة، تُسحق طازجة في الهاون (لا مطحون مسبقاً)","ملح بحري لماء المعكرونة (أقل من المعتاد، فالجبن مالح بطبعه)"],"en":["400 g tonnarelli or thick spaghetti","200 g Pecorino Romano, finely grated on a microplane (no Parmesan — it doesn't melt the same way)","1 heaped tablespoon whole black peppercorns, freshly cracked in a mortar (not pre-ground)","Sea salt for the pasta water (less than usual, since the cheese is salty)"],"ro":["400 g tonnarelli sau spaghete groase","200 g Pecorino Romano, ras fin pe microplane (fără Parmezan — nu se topește la fel)","1 lingură plină de boabe întregi de piper negru, proaspăt zdrobite în mojaru (nu măcinat în prealabil)","Sare de mare pentru apa pastelor (mai puțină decât de obicei, fiindcă brânza este sărată)"]},"howIsMade":{"ar":"حمّر الفلفل المسحوق في مقلاة واسعة جافة على نار متوسطة لمدة 30 ثانية — حتى تشمّ نفّاذيته بحدة — وأضف نصف مغرفة ماء بارد لإيقاف الطهي وتكوين مخفوق فلفلي. ضعه جانباً بعيداً عن النار.\n\nأوصل 3 لتر من الماء المملّح قليلاً إلى الغليان واطبخ المعكرونة حتى لا تصل تماماً إلى نقطة آل دينتي، أي حوالي دقيقة أقل مما تشير العلبة؛ في روما تكمل المعكرونة الطهي في الصلصة لا في القدر.\n\nخلال طهي المعكرونة، اغرف كوباً من ماء الطبخ النشوي. في وعاء واسع، اخفق البيكورينو المبشور مع نحو 4 ملاعق كبيرة من ماء المعكرونة الساخن — اتركه يبرد بضع ثوانٍ أولاً، لأن الماء المغلي على الجبن يجعله كتلاً فوراً — حتى تحصل على عجين كثيف يشبه الريكوتا؛ خفّفه بملعقة ماء أخرى إن كان متماسكاً جداً.\n\nانقل المعكرونة بالملقط مباشرة من القدر إلى المقلاة المتبّلة بالفلفل (دون تصفيتها)، أضف مغرفة من ماء الطبخ النشوي، وقلّبها بقوة على نار هادئة 30 ثانية، حتى تصبح المعكرونة لامعة ومغلّفة جيداً.\n\nارفع المقلاة عن النار — البيكورينو فوق نقطة الغليان يتجمّع في خيوط متكتّلة — اسكب فوقه عجينة الجبن وقلّب مرة أخرى بسرعة، مضيفاً ملاعق من ماء المعكرونة عند الحاجة، حتى تصبح الصلصة كريمية تتعلّق بكل خصلة. قدّمه فوراً مع لفّة أخرى من الفلفل الطازج فوقه؛ الكاتشو إي بيبي يبرد بسرعة، فالأطباق يجب أن تكون دافئة والمدعوّون على الطاولة.","en":"Toast the cracked pepper in a wide dry pan over medium heat for 30 seconds — until you can smell it sharply — and add half a ladle of cold water to stop the cooking and create a peppery slurry. Set aside off the heat.\n\nBring 3 L of lightly salted water to a boil and cook the pasta until just shy of al dente, about a minute less than the package says; in Rome the pasta finishes cooking in the sauce, not in the pot.\n\nWhile the pasta cooks, scoop out a mug of starchy water from the pot. In a wide bowl, whisk the grated Pecorino with about 4 tablespoons of the hot pasta water — let it cool a few seconds first, since boiling water on cheese clumps it instantly — until you have a thick, ricotta-like paste; loosen with another spoonful of water if it's too stiff.\n\nLift the pasta from the pot with tongs straight into the peppered pan (don't drain it), splash in a ladle of starchy water, and toss vigorously over low heat for 30 seconds, until the pasta is glossy and well coated.\n\nTake the pan off the heat — Pecorino above boiling point seizes into stringy clumps — pour over the cheese paste and toss again, fast, adding more pasta water by the spoonful if needed, until the sauce becomes a creamy emulsion that clings to every strand. Plate immediately with another crack of pepper on top; cacio e pepe cools quickly, so plates should be warm and diners at the table."}},{"id":204,"servings":4,"tipType":"meat","pairingsType":"indian","nutrition":{"cal":720,"prot":42,"carb":28,"fat":48,"fib":4},"origin":{"ar":"الهند","en":"India","ro":"India"},"name":{"ar":"دجاج بالزبدة (مرغ مكهني)","en":"Butter Chicken (Murgh Makhani)","ro":"Butter Chicken (Murgh Makhani)"},"category":{"ar":"كاري","en":"Curry","ro":"Curry"},"ingredients":{"ar":["800 غ من أوراك الدجاج منزوعة العظم، مقطّعة قطعاً بطول 4 سم","للتتبيلة: 200 غ لبن كامل الدسم، 2 ملعقة كبيرة من معجون الزنجبيل والثوم، 1 ملعقة صغيرة فلفل كشميري أحمر، 1 ملعقة صغيرة غارام ماسالا، عصير نصف ليمونة، 2 ملعقة كبيرة زيت محايد، 1 ملعقة صغيرة ملح","للصلصة: 800 غ طماطم ناضجة (أو علبة كبيرة من الطماطم المفرومة)، 60 غ من الكاجو النيء، 1 بصلة كبيرة مقسومة لأرباع، 4 فصوص ثوم، 3 سم من الزنجبيل، 4 حبات هيل أخضر، 1 عود قرفة، 4 قرنفل، 1 ورقة غار","80 غ زبدة غير مملحة، 200 مل كريمة دسمة","1 ملعقة كبيرة كاسوري ميثي (أوراق حلبة مجففة)","1 ملعقة صغيرة فلفل كشميري، 1 ملعقة صغيرة غارام ماسالا، 1 ملعقة صغيرة سكر، ملح","كزبرة طازجة للتزيين"],"en":["800 g boneless chicken thighs, cut into 4 cm pieces","For the marinade: 200 g full-fat yoghurt, 2 tbsp ginger-garlic paste, 1 tsp Kashmiri red chilli powder, 1 tsp garam masala, juice of half a lemon, 2 tbsp neutral oil, 1 tsp salt","For the gravy: 800 g ripe tomatoes (or 1 large can chopped tomatoes), 60 g raw cashews, 1 large onion quartered, 4 garlic cloves, 3 cm piece of ginger, 4 green cardamom pods, 1 cinnamon stick, 4 cloves, 1 bay leaf","80 g unsalted butter, 200 ml double cream","1 tbsp kasoori methi (dried fenugreek leaves)","1 tsp Kashmiri red chilli powder, 1 tsp garam masala, 1 tsp sugar, salt","Fresh coriander to finish"],"ro":["800 g pulpe de pui dezosate, tăiate în bucăți de 4 cm","Pentru marinadă: 200 g iaurt gras, 2 linguri pastă de ghimbir-usturoi, 1 linguriță boia Kashmiri, 1 linguriță garam masala, zeama de la o jumătate de lămâie, 2 linguri ulei neutru, 1 linguriță sare","Pentru sosul de bază: 800 g roșii coapte (sau o cutie mare de roșii tocate), 60 g caju crud, 1 ceapă mare în sferturi, 4 căței de usturoi, 3 cm bucată de ghimbir, 4 capsule de cardamom verde, 1 baton de scorțișoară, 4 cuișoare, 1 frunză de dafin","80 g unt nesărat, 200 ml smântână grasă","1 lingură kasoori methi (frunze uscate de schinduf)","1 linguriță boia Kashmiri, 1 linguriță garam masala, 1 linguriță zahăr, sare","Coriandru proaspăt pentru a încheia"]},"howIsMade":{"ar":"اخلط التتبيلة في وعاء واسع، أضف الدجاج وقلّب كل قطعة حتى تتغطى جيداً، ثم غطّ واحفظ في البراد ساعتين على الأقل، ويفضل طوال الليل. للصلصة، انقع الكاجو في 100 مل من الماء الساخن لمدة 20 دقيقة؛ ضع الطماطم والبصل والثوم والزنجبيل والبهارات الكاملة في قدر ثقيل مع 200 مل من الماء، أوصلها للغليان واطبخ مغطىً 20–25 دقيقة حتى تنهار الطماطم ويصبح البصل طرياً تماماً، ثم انتشل القرفة والهيل والقرنفل وورقة الغار، واخفق كل شيء — بما في ذلك الكاجو المنقوع وماؤه — إلى مهروس مخملي ومرّره عبر مصفاة. سخّن الشواية لأعلى درجة، بطّن صينية بورق الألمنيوم، افرد الدجاج المتبل في طبقة واحدة مع ترك مسافة بين القطع وشوِ على بعد 5–6 سم من الحرارة 6–8 دقائق لكل جانب، حتى تتفحم الحواف ويصبح اللحم ناضجاً للتو — اترك الحواف تغمق بالفعل. أذِب الزبدة في مقلاة واسعة على نار متوسطة، اسكب الصلصة المصفاة وأضف مسحوق الفلفل والسكر وملعقة صغيرة من الملح، أغلِ برفق 10 دقائق مع التحريك المتكرر حتى يغمق اللون إلى برتقالي قرميدي غني؛ اسكب الكريمة، حرّك حتى تصبح الصلصة مخملية، ثم أنزل الدجاج المتفحم مع عصاراته من الصينية واتركها تغلي معاً 4–5 دقائق أخرى. افرك الكسوري ميثي بين راحتيك فوق المقلاة، حرّك الجارام مسالا وتذوّق الملح والسكر، انثر أوراق الكزبرة فوق، وقدّمها مع خبز النان أو أرز البسمتي.","en":"Mix the marinade in a wide bowl, add the chicken and turn each piece until well coated, then cover and chill at least 4 hours, ideally overnight. For the gravy, soak the cashews in 100 ml of hot water for 20 minutes; put the tomatoes, onion, garlic, ginger and whole spices into a heavy pan with 200 ml of water, bring to a simmer and cook covered for 20–25 minutes until the tomatoes have collapsed and the onion is fully soft, then fish out the cinnamon, cardamom, cloves and bay leaf, and blend everything — including the soaked cashews and their water — to a velvety purée and pass through a sieve. Heat the broiler high, line a tray with foil, spread the marinated chicken in a single layer with space between the pieces and broil 5–6 cm from the heat for 6–8 minutes per side, until the edges are charred and the meat is just cooked through — let the edges go genuinely dark. Melt the butter in a wide pan over medium heat, pour in the strained gravy and add the chilli powder, sugar and a teaspoon of salt, simmer gently for 10 minutes stirring often until the colour deepens to a rich brick-orange; pour in the cream, stir until the gravy turns velvet, then slide in the charred chicken with any juices from the tray and let everything bubble together for 4–5 minutes more. Crush the kasoori methi between your palms over the pan, stir in the garam masala and taste for salt and sugar, scatter coriander leaves on top, and serve with naan or basmati rice."}},{"id":205,"servings":6,"tipType":"meat","pairingsType":"indian","nutrition":{"cal":780,"prot":38,"carb":78,"fat":32,"fib":3},"origin":{"ar":"الهند","en":"India","ro":"India"},"name":{"ar":"برياني الضأن الحيدر آبادي","en":"Hyderabadi Lamb Biryani","ro":"Biryani de miel din Hyderabad"},"category":{"ar":"طبق رئيسي","en":"Main","ro":"Fel principal"},"ingredients":{"ar":["800 غ من كتف أو فخذ الضأن بالعظم، مقطّعة قطعاً بطول 4 سم","500 غ أرز بسمتي، منقوع 30 دقيقة في الماء البارد ومصفّى","4 بصلات كبيرة، شرائح رفيعة جداً (نحو 600 غ)","200 غ لبن كامل الدسم","50 غ سمن + 80 مل زيت محايد","3 ملاعق كبيرة من معجون الزنجبيل والثوم","2 فلفل أخضر حار، مشقوق طولاً","2 ملعقة صغيرة فلفل كشميري، 1 ملعقة صغيرة كركم، 1 ملعقة صغيرة ملح","بهارات كاملة: 1 عود قرفة، 4 حبات هيل أخضر + 2 هيل أسود، 4 قرنفل، 1 ورقة غار، 1 ملعقة صغيرة شاهي زيرة، 1 ملعقة صغيرة فلفل أسود حب","رشّة زعفران منقوعة في 60 مل حليب كامل دافئ","عصير ليمونة واحدة","2 ملعقة كبيرة نعناع مفروم و 2 ملعقة كبيرة كزبرة مفرومة","1 ملعقة كبيرة ماء ورد (اختياري، تقليدي)","قطعة عجين طري أو ورقة ألمنيوم سميكة للإحكام"],"en":["800 g bone-in lamb shoulder or leg, cut into 4 cm pieces","500 g basmati rice, soaked 30 minutes in cold water and drained","4 large onions, very thinly sliced (about 600 g)","200 g full-fat yoghurt","50 g ghee + 80 ml neutral oil","3 tbsp ginger-garlic paste","2 green chillies, slit lengthwise","2 tsp Kashmiri red chilli powder, 1 tsp turmeric, 1 tsp salt","Whole spices: 1 cinnamon stick, 4 green cardamom + 2 black cardamom, 4 cloves, 1 bay leaf, 1 tsp shahi jeera, 1 tsp black peppercorns","A pinch of saffron infused in 60 ml warm whole milk","Juice of 1 lemon","2 tbsp chopped mint and 2 tbsp chopped coriander","1 tbsp rose water (optional, traditional)","A piece of soft dough or a sheet of heavy foil for sealing"],"ro":["800 g spată sau pulpă de miel cu os, tăiată în bucăți de 4 cm","500 g orez basmati, înmuiat 30 de minute în apă rece și scurs","4 cepe mari, tăiate foarte subțire (aproximativ 600 g)","200 g iaurt gras","50 g ghee + 80 ml ulei neutru","3 linguri pastă de ghimbir-usturoi","2 ardei iuți verzi, despicați pe lungime","2 lingurițe boia Kashmiri, 1 linguriță turmeric, 1 linguriță sare","Mirodenii întregi: 1 baton de scorțișoară, 4 capsule cardamom verde + 2 cardamom negru, 4 cuișoare, 1 frunză de dafin, 1 linguriță shahi jeera, 1 linguriță boabe de piper negru","Un vârf de șofran infuzat în 60 ml lapte cald","Sucul de la 1 lămâie","2 linguri mentă tocată și 2 linguri coriandru tocat","1 lingură apă de trandafiri (opțional, tradițional)","O bucată de aluat moale sau o folie groasă pentru sigilare"]},"howIsMade":{"ar":"سخّن السمن والزيت في مقلاة واسعة وثقيلة على نار متوسطة وحمّر شرائح البصل ببطء 25–30 دقيقة، مع التحريك المتكرر، حتى تصير ذهبية بنية عميقة (بيريستا)، ثم صفّها على ورق، احتفظ بالزيت في المقلاة، واترك نصف البصل جانباً للتطبيق. اخلط الضأن مع اللبن، عجينة الزنجبيل-الثوم، نصف البصل المقلي المهروس في اليد، مسحوق الفلفل، الكركم، الملح، عصير الليمون، وملعقة صغيرة من شاهي جيرا، اخلط جيداً ودع المزيج يرتاح ساعتين على الأقل أو طوال الليل في الثلاجة؛ أعد الضأن المتبل إلى زيت البصل المحفوظ، أضف القرفة والهيل والقرنفل وورقة الغار، واطبخ مغطىً على نار هادئة من ساعة إلى ساعة وربع، حتى يصبح الضأن طرياً وتتقلص الصلصة إلى طبقة سميكة. أوصِل قدراً عميقاً من الماء المملح جيداً إلى غليان قوي مع بقية البهارات الكاملة وملعقة كبيرة من الزيت، أضف البسمتي المنقوع واطبخه فقط 4–5 دقائق، حتى تستطيل الحبوب وتصبح نحو ثلاثة أرباع مطهوة — يكتمل النضج في البخار — ثم صفّها بسرعة وبلطف. في المقلاة نفسها فوق الضأن، افرد الأرز بشكل متساوٍ، انثر بقية البصل المقلي، النعناع والكزبرة المفرومين، والفلفل الأخضر فوق، ثم اسكب حليب الزعفران بخطوط بطيئة عبر السطح وماء الورد إذا كنت تستخدمه. اغلق الغطاء بشريط من العجين الرطب أو ورق ألمنيوم مشدود، ضعه على أهدأ نار لمدة 25–30 دقيقة، ثم أطفئ اللهب دون رفع الغطاء واتركه مغلقاً 10 دقائق أخرى — اكسر الإغلاق على المائدة واغرز ملعقة طويلة إلى القاع وارفع مباشرة، بحيث تخرج كل حصة بأرز ولحم معاً، لا ممزوجين أبداً.","en":"Heat the ghee and oil in a wide heavy pan over medium heat and fry the sliced onions slowly for 25–30 minutes, stirring often, until deeply golden brown (birista), then drain on paper, reserve the oil in the pan and keep half the onions for layering. Combine the lamb with the yoghurt, ginger-garlic paste, half of the fried onions crushed in your hand, chilli powder, turmeric, salt, lemon juice and a teaspoon of the shahi jeera, mix thoroughly and rest at least 2 hours or overnight in the fridge; tip the marinated lamb back into the reserved onion oil, add the cinnamon, cardamom, cloves and bay leaf, and cook covered over low heat for an hour to an hour and a quarter, until the lamb is tender and the gravy has reduced to a thick coating. Bring a deep pot of well-salted water to a rolling boil with the rest of the whole spices and a tablespoon of oil, add the soaked basmati and cook just 4–5 minutes until the grains have lengthened and are about three-quarters done — they finish in the steam — then drain quickly and gently. In the same pan over the lamb, spread the rice evenly, scatter the remaining fried onions, chopped mint and coriander, and the green chillies on top, then drizzle the saffron milk in slow streaks across the surface and the rose water if using. Seal the lid with a strip of wet dough or a tight wrap of foil, set on the lowest heat for 25–30 minutes, then turn off the flame without lifting the lid and rest sealed for another 10 minutes — break the seal at the table and plunge a long spoon to the bottom to lift straight up, so each portion comes out with both rice and meat, never stirred together."}},{"id":206,"servings":4,"tipType":"veg","pairingsType":"indian","nutrition":{"cal":480,"prot":22,"carb":18,"fat":36,"fib":5},"origin":{"ar":"الهند","en":"India","ro":"India"},"name":{"ar":"بالاك بانير","en":"Palak Paneer","ro":"Palak Paneer"},"category":{"ar":"كاري","en":"Curry","ro":"Curry"},"ingredients":{"ar":["500 غ سبانخ طازج (أو 250 غ مجمّد، مذاب)","250 غ بانير، مكعّبات 2 سم","1 بصلة كبيرة، مفرومة ناعماً","2 طماطم ناضجة، مفرومة (أو 200 غ طماطم مفرومة)","3 فصوص ثوم و 2 سم زنجبيل، مفرومتين معاً","2 فلفل أخضر حار","1 ملعقة صغيرة بذور كمون","1 ملعقة صغيرة كزبرة مطحونة، 1 ملعقة صغيرة فلفل كشميري، ½ ملعقة صغيرة كركم، 1 ملعقة صغيرة غارام ماسالا","1 ملعقة كبيرة كاسوري ميثي","80 مل كريمة دسمة، 3 ملاعق كبيرة سمن (ghee)","ملح حسب الذوق","قطعة صغيرة من الزنجبيل الطازج المقطع جوليان للتزيين"],"en":["500 g fresh spinach (or 250 g frozen, defrosted)","250 g paneer, cut into 2 cm cubes","1 large onion, finely chopped","2 ripe tomatoes, chopped (or 200 g chopped tomatoes)","3 garlic cloves and 2 cm piece of ginger, minced together","2 green chillies","1 tsp cumin seeds","1 tsp coriander powder, 1 tsp Kashmiri chilli powder, ½ tsp turmeric, 1 tsp garam masala","1 tbsp kasoori methi (dried fenugreek leaves)","80 ml double cream, 3 tbsp ghee","Salt to taste","A small piece of fresh ginger, julienned, to finish"],"ro":["500 g spanac proaspăt (sau 250 g congelat, dezghețat)","250 g paneer, tăiat cuburi de 2 cm","1 ceapă mare, tocată mărunt","2 roșii coapte, tocate (sau 200 g roșii tocate)","3 căței de usturoi și o bucată de 2 cm de ghimbir, tocate împreună","2 ardei iuți verzi","1 linguriță semințe de chimion","1 linguriță coriandru pudră, 1 linguriță boia Kashmiri, ½ linguriță turmeric, 1 linguriță garam masala","1 lingură kasoori methi (frunze uscate de schinduf)","80 ml smântână grasă, 3 linguri ghee","Sare după gust","O bucățică mică de ghimbir proaspăt, tăiată julien, pentru finisat"]},"howIsMade":{"ar":"أوصِل قدراً كبيراً من الماء إلى الغليان، اسلق السبانخ 90 ثانية وانقلها فوراً إلى وعاء ماء مثلج، ثم صفّها واعصرها برفق واخفقها إلى مهروس ناعم مع إحدى الفلفلتين الخضراوين وبضع ملاعق من الماء البارد. سخّن ملعقة كبيرة من السمن في مقلاة واسعة وحمّر مكعبات البانير على نار متوسطة 2–3 دقائق لكل جهة حتى تذهب إلى ذهبي خفيف، ثم انقلها على ورق أو اغمسها في وعاء ماء دافئ مالح بينما يطهى الباقي. في المقلاة نفسها أضف بقية السمن وبذور الكمون واتركها تطقطق 30 ثانية، أدخل البصل واطبخه 8–10 دقائق حتى يصبح طرياً وذهبي الحواف، ثم أضف عجينة الزنجبيل-الثوم والفلفل الأخضر الثاني المشقوق واطبخ دقيقة إضافية. حرّك الطماطم المفرومة مع الكزبرة ومسحوق الفلفل والكركم وملعقة صغيرة من الملح واطبخ 6–8 دقائق حتى يصبح المعجون كالمربى ويبدأ الزيت بالانفصال عند الأطراف، ثم اسكب مهروس السبانخ و 100 مل من الماء، حرّك جيداً واطهُ برفق 5 دقائق. أنزل مكعبات البانير في الصلصة، اسكب الكريمة، افرك الكسوري ميثي بين راحتيك فوق المقلاة ورشّ الجارام مسالا، سخّن لـ 2 دقيقة أخرى، تذوّق الملح، أنهِ بالزنجبيل المقطع جوليان فوقه، وقدّمه مع الخبز النان أو الباراثا أو الأرز البسمتي.","en":"Bring a large pot of water to a boil, blanch the spinach for 90 seconds and transfer immediately to a bowl of ice water, then drain, squeeze gently and blend to a smooth purée with one of the green chillies and a few tablespoons of cold water. Heat a tablespoon of ghee in a wide pan and fry the paneer cubes over medium heat for 2–3 minutes per side until lightly gold, then lift onto paper or slip them into a bowl of warm salted water while everything else cooks. In the same pan add the remaining ghee and the cumin seeds and let them sizzle for 30 seconds, tip in the onion and cook 8–10 minutes until soft and golden at the edges, then add the ginger-garlic paste and the second slit green chilli and cook a minute more. Stir in the chopped tomato with the coriander, chilli powder, turmeric and a teaspoon of salt and cook 6–8 minutes until the masala is jammy and the oil starts to separate at the edges, then pour in the spinach purée and 100 ml of water, stir well and simmer gently for 5 minutes. Slide the paneer cubes into the gravy, swirl in the cream, crush the kasoori methi between your palms over the pan and sprinkle the garam masala, heat through for another 2 minutes, taste for salt, finish with julienned ginger on top, and serve with naan, paratha or basmati."}},{"id":207,"servings":6,"tipType":"meat","pairingsType":"indian","nutrition":{"cal":620,"prot":40,"carb":12,"fat":44,"fib":2},"origin":{"ar":"الهند","en":"India","ro":"India"},"name":{"ar":"روغن جوش","en":"Rogan Josh","ro":"Rogan Josh"},"category":{"ar":"كاري","en":"Curry","ro":"Curry"},"ingredients":{"ar":["1 كغ من كتف أو فخذ الضأن بالعظم، مقطّعة قطعاً بطول 4 سم","4 ملاعق كبيرة زيت خردل","200 غ لبن كامل الدسم، مخفوق ناعماً","4 حبات فلفل كشميري أحمر مجفّف، منقوعة 20 دقيقة في ماء دافئ ومطحونة إلى عجين (أو 2 ملعقة كبيرة فلفل كشميري ناعم)","1 ملعقة صغيرة شمر ناعم","1 ملعقة صغيرة زنجبيل مجفف ناعم (سونث)","½ ملعقة صغيرة من الهنغ (الحلتيت)","بهارات كاملة: 8 حبات هيل أخضر + 2 هيل أسود، 1 عود قرفة، 6 قرنفل، 1 ورقة غار","1 ملعقة صغيرة ملح","رشّة زعفران منقوعة في 2 ملعقة كبيرة من الحليب الدافئ"],"en":["1 kg bone-in lamb shoulder or leg, cut into 4 cm pieces","4 tbsp mustard oil","200 g full-fat yoghurt, whisked smooth","4 dried Kashmiri red chillies, soaked in warm water 20 minutes and ground to a paste (or 2 tbsp Kashmiri chilli powder)","1 tsp fennel powder","1 tsp dried ginger powder (sonth)","½ tsp asafoetida (hing)","Whole spices: 8 green cardamom + 2 black cardamom, 1 cinnamon stick, 6 cloves, 1 bay leaf","1 tsp salt","A pinch of saffron, soaked in 2 tbsp warm milk"],"ro":["1 kg spată sau pulpă de miel cu os, tăiată în bucăți de 4 cm","4 linguri ulei de muștar","200 g iaurt gras, bătut neted","4 ardei roșii Kashmiri uscați, înmuiați 20 de minute în apă caldă și pisați pastă (sau 2 linguri boia Kashmiri)","1 linguriță pudră de fenicul","1 linguriță pudră de ghimbir uscat (sonth)","½ linguriță asafoetida (hing)","Mirodenii întregi: 8 capsule cardamom verde + 2 cardamom negru, 1 baton de scorțișoară, 6 cuișoare, 1 frunză de dafin","1 linguriță sare","Un vârf de șofran, infuzat în 2 linguri lapte cald"]},"howIsMade":{"ar":"سخّن زيت الخردل في قدر ثقيل حتى يبدأ بإصدار الدخان للتو، ثم ارفعه عن النار لحظة — الدخان يحيّد الحدّة دون أن يحرق — أعده إلى نار متوسطة، أضف البهارات الكاملة وورقة الغار، واتركها تعطّر الزيت 30 ثانية. أضف الضأن في طبقة واحدة وحمّره من كل الجهات 8–10 دقائق (هذا هو التحمير الوحيد للطبق، فاترك اللون يتطور كما يجب)، ثم أضف الهنغ ومسحوق الزنجبيل ومسحوق الشمر، واتركها تغطي اللحم في الزيت الساخن دقيقة إضافية. اخفق اللبن مع عجينة الفلفل الكشميري وملعقة كبيرة من الماء البارد، ثم أضفه إلى القدر مغرفةً مغرفة، مع التحريك المستمر بعد كل إضافة — ببطء، لا ينقطع اللبن — أضف الملح، خفّف النار، واطبخ مغطىً 10 دقائق حتى يذوب اللبن في قاعدة حمراء لامعة. اسكب 500 مل من الماء الساخن، أعد المزيج إلى الغليان، ثم اخفض النار إلى أهدأ درجة، واطبخ مغطىً ساعة و 20 دقيقة مع التحريك كل 20 دقيقة، حتى يلين الضأن أمام الملعقة ويصبح المرق رفيعاً لامعاً بلون أحمر ماهوغني عميق؛ اسكب حليب الزعفران قبل النهاية بـ 5 دقائق وحرّكه قليلاً فقط. أرحه بعيداً عن النار 10 دقائق قبل التقديم مع أرز البسمتي المطهو على البخار — الروغن جوش يجب أن يكون شبه شوربة، حاد اللون والعطر أكثر من كونه حاراً، الحرارة من اللحم، واللون من الفلفل، والعطر من كل ما تبقى.","en":"Heat the mustard oil in a heavy pan until it just begins to smoke, then pull it off the heat for a moment — letting it smoke neutralises the raw pungency without scorching — and return to medium heat, add the whole spices and bay leaf, and let them perfume the oil for 30 seconds. Add the lamb in a single layer and brown well on all sides for 8–10 minutes (this is the only browning the dish gets, so let the colour develop properly), then stir in the asafoetida, ginger powder and fennel powder and let them coat the meat in the hot oil for another minute. Whisk the yoghurt with the Kashmiri chilli paste and a tablespoon of cold water, then add it to the pan a ladleful at a time stirring continuously after each addition — going slowly keeps the yoghurt from splitting — add the salt, lower the heat and cook covered for 10 minutes until the yoghurt has melted into a glossy red base. Pour in 500 ml of hot water, bring back to a simmer, then drop the heat to its lowest and braise covered for an hour and 20 minutes, stirring every 20 minutes, until the lamb yields to a spoon and the gravy is thin, glossy and a deep mahogany red; swirl the saffron milk through 5 minutes before the end without fully stirring it out. Rest off the heat for 10 minutes before serving with steamed basmati — Rogan Josh is meant to be soup-like, brilliantly coloured and aromatic rather than spicy hot, the heat supplied by the meat, the colour by the chillies, and the perfume by everything else."}},{"id":208,"servings":8,"tipType":"veg","pairingsType":"indian","nutrition":{"cal":280,"prot":6,"carb":32,"fat":14,"fib":3},"origin":{"ar":"الهند","en":"India","ro":"India"},"name":{"ar":"سمبوسة","en":"Samosa","ro":"Samosa"},"category":{"ar":"وجبة خفيفة","en":"Snack","ro":"Gustare"},"ingredients":{"ar":["للعجين: 300 غ دقيق أبيض، 1 ملعقة صغيرة بذور أجوين (نانخواه)، ½ ملعقة صغيرة ملح، 60 مل سمن أو زيت محايد، 120 مل ماء بارد","للحشوة: 500 غ بطاطس مفتولة (نوع روست)، 100 غ بازلاء مجمدة، 2 ملعقة كبيرة زيت محايد، 1 ملعقة صغيرة بذور كمون، 1 فلفل أخضر حار مفروم، 2 سم زنجبيل مفروم","1 ملعقة صغيرة كزبرة ناعمة، 1 ملعقة صغيرة غارام ماسالا، ½ ملعقة صغيرة فلفل كشميري، ½ ملعقة صغيرة كركم، 1 ملعقة صغيرة أمشور (مسحوق المانجو المجفف)، 1 ملعقة صغيرة ملح","حفنة كزبرة طازجة مفرومة","نحو 1 لتر زيت محايد للقلي العميق","للتقديم: شطنة تمر هندي وشطنة نعناع-كزبرة"],"en":["For the pastry: 300 g plain flour, 1 tsp ajwain (carom) seeds, ½ tsp salt, 60 ml ghee or neutral oil, 120 ml cold water","For the filling: 500 g floury potatoes (Maris Piper or Russet), 100 g frozen peas, 2 tbsp neutral oil, 1 tsp cumin seeds, 1 green chilli minced, 2 cm piece of ginger minced","1 tsp coriander powder, 1 tsp garam masala, ½ tsp Kashmiri chilli powder, ½ tsp turmeric, 1 tsp amchur (dried mango powder), 1 tsp salt","A handful of fresh coriander, chopped","About 1 L neutral oil for deep-frying","To serve: tamarind chutney and mint-coriander chutney"],"ro":["Pentru aluat: 300 g făină albă, 1 linguriță semințe de ajwain (chimen-aristotel), ½ linguriță sare, 60 ml ghee sau ulei neutru, 120 ml apă rece","Pentru umplutură: 500 g cartofi făinoși (Maris Piper sau Russet), 100 g mazăre congelată, 2 linguri ulei neutru, 1 linguriță semințe de chimion, 1 ardei iute verde tocat, 2 cm bucată de ghimbir tocat","1 linguriță coriandru pudră, 1 linguriță garam masala, ½ linguriță boia Kashmiri, ½ linguriță turmeric, 1 linguriță amchur (pudră de mango uscat), 1 linguriță sare","Un mănunchi de coriandru proaspăt, tocat","Aproximativ 1 l ulei neutru pentru prăjit","Pentru servit: chutney de tamarind și chutney de mentă-coriandru"]},"howIsMade":{"ar":"افرك السمن في الدقيق والأجوين والملح بأطراف الأصابع حتى يصبح المزيج كفتات الخبز الخشن — كمية الدهن هي ما يعطي قشرة السمبوسة قرمشتها الفقاعية كالبسكويت — أضف الماء البارد ملعقةً ملعقة، واعجن حتى تصبح عجينة متماسكة وناعمة (أطرى من عجين الشاباتي وأشد من عجين الخبز)، وأرحها مغطاة 30 دقيقة. اسلق البطاطس بقشرها حتى تطرى للتو، صفّها وقشّرها واهرسها بظهر الشوكة بشكل خشن (نريد قواماً لا بوريه)؛ سخّن الزيت في مقلاة واسعة، أضف بذور الكمون واتركها تطقطق، ثم الزنجبيل والفلفل الأخضر لمدة 30 ثانية، أضف البهارات الناعمة وقلّبها لحظة، ثم ادفع البطاطس والبازلاء والملح والأمشور والكزبرة، واطبخها 4–5 دقائق مع التقليب حتى تغلف البهارات كل قطعة — برّدها إلى حرارة الغرفة قبل التشكيل. قسّم العجين إلى 8 كرات، افرد واحدة على شكل بيضاوي رفيع بطول نحو 18 سم واقطعها في الوسط لتحصل على نصفي دائرة؛ خذ نصفاً، ادهن خطاً رفيعاً من الماء على الحافة المستقيمة، وأطوه على شكل مخروط بأن تجمع زاويتي الحافة المستقيمة مع تداخل 1 سم، اضغط على اللحام بإحكام لتثبيته. أمسك المخروط بيد، املأه بالحشوة حتى ثلاثة أرباع، ثم قسّم الحافة المفتوحة بثنية صغيرة من جهة واحدة وأحكم الإغلاق بإصبع مبلل — هذه الثنية تخلق الحافة الجانبية المميّزة للسمبوسة وتساعدها على الوقوف عند القلي — كرّر مع البقية. سخّن زيت القلي إلى 150°م (أقل مما تتوقّع، لكن التسخين البطيء هو ما يمنح القشرة فقاعاتها)، أنزل السمبوسات بدفعات من 3 أو 4 واقلِها 6–7 دقائق مع التقليب اللطيف حتى تصبح ذهبية شاحبة، ارفع الحرارة إلى 180°م واقلِها 3–4 دقائق إضافية حتى تصير ذهبية غامقة ومقرمشة فعلاً، صفّها على شبكة وقدّمها ساخنة مع شطنة التمر الهندي وشطنة النعناع-الكزبرة.","en":"Rub the ghee into the flour, ajwain and salt with your fingertips until the mixture resembles coarse breadcrumbs — the amount of fat is what gives samosa pastry its blistered, biscuit-crisp shell — then add the cold water a tablespoon at a time, mixing into a stiff smooth dough (softer than chapati but firmer than bread dough) and rest it covered for 30 minutes. Boil the potatoes in their skins until just tender, drain, peel and crush coarsely with the back of a fork (you want texture, not mash); heat the oil in a wide pan, add the cumin seeds and let them sizzle, then the ginger and green chilli for 30 seconds, stir in the dry spices and fry briefly, tip in the potato, peas, salt, amchur and coriander, and cook 4–5 minutes turning everything until the spices coat every piece — cool to room temperature before shaping. Divide the dough into 8 balls, roll one into a thin oval about 18 cm long and cut across the middle to make two half-circles; take one half, brush a thin line of water along the straight edge, and fold into a cone by bringing the two corners of the straight edge together so they overlap by 1 cm, pinching the seam tightly to seal. Hold the cone in one hand, fill it three-quarters with potato, then pleat the open edge by folding a small tuck on one side and sealing the rim shut with a damp finger — the tucked pleat creates the samosa's signature side ridge and helps it sit upright while cooking — and repeat with the rest. Heat the frying oil to 150°C (lower than you might expect, but the slow climb is what gives the shell its blisters), slip in the samosas in batches of 3 or 4 and fry 6–7 minutes turning gently until pale gold, then raise the heat to 180°C and fry another 3–4 minutes until deep golden and properly crisp, draining on a rack and serving hot with tamarind and mint chutneys."}},{"id":209,"servings":4,"tipType":"meat","pairingsType":"thai","nutrition":{"cal":620,"prot":32,"carb":22,"fat":44,"fib":5},"origin":{"ar":"تايلاند","en":"Thailand","ro":"Thailanda"},"name":{"ar":"كاري أخضر (غاينغ خياو وان)","en":"Green Curry (Gaeng Khiao Wan)","ro":"Curry verde (Gaeng Khiao Wan)"},"category":{"ar":"كاري","en":"Curry","ro":"Curry"},"ingredients":{"ar":["4 ملاعق كبيرة من معجون الكاري الأخضر (محلي الصنع أو من علامة تايلاندية جيدة مثل Mae Ploy)","400 مل حليب جوز الهند كامل الدسم (Aroy-D مثالي)","200 مل كريمة جوز الهند (الطبقة السميكة من فوق العلبة، أو 100 مل مع الكريمة المقشودة)","500 غ أوراك دجاج، مقطّعة قطعاً بطول 3 سم","4 باذنجانات تايلاندية، إلى أرباع (أو باذنجانة آسيوية صغيرة مكعّبات)","حفنة صغيرة من باذنجان البازلاء (للتزيين أساساً، اختياري)","100 غ براعم خيزران، شرائح","4 ورقات ليمون كافير، ممزقة (دون الساق)","2 فلفل أحمر طويل، شرائح رفيعة مائلة","1 ملعقة كبيرة سكر النخيل (أو سكر بني فاتح)","2 ملعقة كبيرة صلصة سمك تايلاندية","حفنة صغيرة من ريحان تايلاندي (هورابا)","أرز الياسمين للتقديم"],"en":["4 tbsp green curry paste (homemade, or a good Thai brand like Mae Ploy)","400 ml full-fat coconut milk (Aroy-D is ideal)","200 ml coconut cream (the thick top layer from the can, or 100 ml plus the skimmed cream)","500 g chicken thighs, cut into 3 cm pieces","4 Thai eggplants, quartered (or 1 small Asian eggplant cubed)","A small handful of pea eggplants (mainly garnish, optional)","100 g bamboo shoots, sliced","4 kaffir lime leaves, torn (stem removed)","2 long red chillies, sliced thinly on the bias","1 tbsp palm sugar (or light brown sugar)","2 tbsp Thai fish sauce","A small handful of Thai basil leaves (horapha)","Jasmine rice to serve"],"ro":["4 linguri pastă curry verde (de casă sau o marcă thailandeză bună precum Mae Ploy)","400 ml lapte de cocos gras (ideal Aroy-D)","200 ml smântână de cocos (stratul gros de deasupra cutiei, sau 100 ml plus crema rămasă)","500 g pulpe de pui, tăiate în bucăți de 3 cm","4 vinete thailandeze, tăiate în sferturi (sau 1 vânătă asiatică mică, cuburi)","Un mic mănunchi de vinete-mazăre (în principal pentru garnitură, opțional)","100 g vârfuri de bambus, feliate","4 frunze de lămâi kaffir, rupte (codița înlăturată)","2 ardei roșii lungi, feliați subțire în diagonală","1 lingură zahăr de palmier (sau zahăr brun deschis)","2 linguri sos de pește thailandez","Un mic mănunchi de busuioc thailandez (horapha)","Orez iasomie pentru servit"]},"howIsMade":{"ar":"في مقلاة عميقة (ووك) أو قدر ثقيل على نار متوسطة، ضع كريمة جوز الهند واتركها تطهو 4–5 دقائق مع التحريك بين الحين والآخر، حتى ينفصل الزيت وتأخذ الكريمة لمعاناً زيتياً — هذه الخطوة الأساسية هي ما يفصل بين كاري المطعم التايلاندي وبين النسخة المائية المنزلية. أضف معجون الكاري الأخضر إلى الكريمة المنفصلة وقلِّبه 2–3 دقائق مع التحريك المستمر، حتى يغمق المعجون ويُطلق رائحة الجلنجال والليمون العشبي والريحان التايلاندي، ويتحول الزيت إلى أخضر زاهٍ — ستفوح من المطبخ رائحة زقاق في بانكوك. أدخل الدجاج وقلّب القطع في المعجون حتى تتغطى، اطبخ 3–4 دقائق حتى يصبح اللحم نصف ناضج، ثم اسكب حليب جوز الهند وأوصله إلى غليان هادئ؛ أضف الباذنجان وبراعم الخيزران وأوراق الليمون الكافير الممزقة، واتركها تغلي مكشوفة 10–12 دقيقة، حتى يصبح الباذنجان طرياً والدجاج ناضجاً للتو. تبّل بصلصة السمك وسكر النخيل، مع التذوق أثناء العمل — يجب أن يضرب الكاري الملوحة والحلاوة ولمسة العشب وحرارة الفلفل الأخضر النظيفة كلها في آن واحد — ثم أضف شرائح الفلفل الأحمر والريحان التايلاندي، حرّك المقلاة دورة واحدة، ثم ارفعها عن النار بعد 30 ثانية كي يبقى الريحان زاهياً في الصحن. قدّمه في صحون ضحلة مع أرز الياسمين إلى الجانب.","en":"In a wok or heavy pan over medium heat, spoon in the coconut cream and let it cook for 4–5 minutes, stirring occasionally, until the oil cracks out and the cream takes on a slick sheen — this foundation step is what separates Thai-restaurant green curry from the watery home version. Add the green curry paste to the split cream and fry for 2–3 minutes, stirring constantly, until the paste darkens, releases its perfume of galangal, lemongrass and Thai basil, and the oil turns a vivid green — the kitchen will smell like a Bangkok back street. Slide in the chicken and turn the pieces in the paste until coated, cook 3–4 minutes until the meat is half-sealed, then pour in the coconut milk and bring to a gentle simmer; add the eggplants, bamboo shoots and torn kaffir lime leaves, and simmer uncovered for 10–12 minutes until the eggplants are tender and the chicken is just cooked through. Season with the fish sauce and palm sugar, tasting as you go — the curry should hit salty, sweet, herbaceous and a clean green chilli heat all at once — then stir in the sliced red chillies and Thai basil, swirl the pan once and take it off the heat after 30 seconds so the basil stays bright in the bowl. Serve in shallow bowls with jasmine rice on the side."}},{"id":210,"servings":6,"tipType":"meat","pairingsType":"thai","nutrition":{"cal":680,"prot":36,"carb":38,"fat":42,"fib":6},"origin":{"ar":"تايلاند","en":"Thailand","ro":"Thailanda"},"name":{"ar":"كاري ماسامان","en":"Massaman Curry","ro":"Massaman"},"category":{"ar":"كاري","en":"Curry","ro":"Curry"},"ingredients":{"ar":["4 ملاعق كبيرة من معجون كاري ماسامان (Mae Ploy ماركة موثوقة)","1 كغ من لحم البقر الموزة أو الكتف، مكعّبات بطول 5 سم","800 مل حليب جوز الهند كامل الدسم","200 مل كريمة جوز الهند","500 غ بطاطس صلبة (شارلوت أو يوكون غولد)، مقشّرة ومقطّعة قطعاً بطول 4 سم","2 بصلة صغيرة، مقشّرة ومقطّعة لأرباع","100 غ فول سوداني محمّص غير مملّح (يُهرس بعضه للتزيين)","بهارات كاملة: 5 حبات هيل، 1 عود قرفة، 4 قرنفل، 1 يانسون نجمي، 1 ورقة غار","3 ملاعق كبيرة معجون تمر هندي (أو عصير ليمونة واحدة كبديل)","3 ملاعق كبيرة سكر النخيل","3 ملاعق كبيرة صلصة السمك التايلاندية","4 ورقات ليمون كافير، ممزقة","أرز الياسمين للتقديم"],"en":["4 tbsp Massaman curry paste (Mae Ploy is reliable)","1 kg beef shin or chuck, cut into 5 cm cubes","800 ml full-fat coconut milk","200 ml coconut cream","500 g waxy potatoes (Charlotte or Yukon Gold), peeled and cut into 4 cm chunks","2 small onions, peeled and quartered","100 g roasted unsalted peanuts (a few crushed for garnish)","Whole spices: 5 cardamom pods, 1 cinnamon stick, 4 cloves, 1 star anise, 1 bay leaf","3 tbsp tamarind paste (or juice of 1 lime as a back-up)","3 tbsp palm sugar","3 tbsp Thai fish sauce","4 kaffir lime leaves, torn","Jasmine rice to serve"],"ro":["4 linguri pastă Massaman (Mae Ploy este o alegere sigură)","1 kg rasol sau pulpă de vită, tăiată în cuburi de 5 cm","800 ml lapte de cocos gras","200 ml smântână de cocos","500 g cartofi cu textură fermă (Charlotte sau Yukon Gold), curățați și tăiați în bucăți de 4 cm","2 cepe mici, curățate și tăiate în sferturi","100 g arahide prăjite nesărate (câteva zdrobite pentru ornat)","Mirodenii întregi: 5 capsule cardamom, 1 baton de scorțișoară, 4 cuișoare, 1 anason stelat, 1 frunză de dafin","3 linguri pastă de tamarind (sau zeama de la 1 lime de rezervă)","3 linguri zahăr de palmier","3 linguri sos de pește thailandez","4 frunze de lămâi kaffir, rupte","Orez iasomie pentru servit"]},"howIsMade":{"ar":"ضع كريمة جوز الهند في قدر ثقيل على نار متوسطة واتركها تطهو 5 دقائق مع التحريك، حتى ينفصل الزيت وتبدو الكريمة لامعة وحبيبية قليلاً. أضف معجون الماسامان والبهارات الكاملة واقلِها 3 دقائق — سيغمق المعجون وستفوح من المطبخ رائحة القرفة والهيل والكمون المحمّص؛ هذا الإزهار المبكّر للبهارات هو ما يمنح الماسامان عمقه ذا اللمسة الفارسية. أضف لحم البقر وقلّبه في المعجون حتى تتلوّن كل قطعة بالأحمر الداكن، اسكب حليب جوز الهند ومعجون التمر الهندي وأوراق الليمون الكافير، أوصلها إلى غليان بالكاد محسوس، واطبخها برفق مع غطاء نصف مغلق ساعة ونصف مع التحريك كل 20 دقيقة — ينضج اللحم حين يستجيب بسهولة للملعقة لكنه يحتفظ بشكله. أضف البطاطس والبصل والفول السوداني واستمر في الطهي مكشوفاً 30 دقيقة إضافية، حتى تنضج البطاطس وتثخن الصلصة إلى بنيّ غامق لامع؛ حرّك صلصة السمك وسكر النخيل في النهاية، موازناً مثلث المالح-الحلو-الحامض حتى يصبح الطعم عميقاً ومستديراً، لا حلوًا أكثر من اللازم ولا حادًا. أرحه بعيداً عن النار 10 دقائق، ثم قدّمه في صحون ضحلة مع أرز الياسمين، مع نثرة من الفول السوداني المهروس فوقه — الماسامان هو الكاري التايلاندي الذي يكتسب عمقاً ليلة كاملة، وأي بقايا يكون طعمها أفضل في اليوم التالي.","en":"Spoon the coconut cream into a heavy pot over medium heat and let it cook for 5 minutes, stirring, until the oil separates and the cream looks glossy and slightly grainy. Add the Massaman paste and the whole spices and fry for 3 minutes — the paste will darken and the kitchen should smell of cinnamon, cardamom and roasted cumin; this early bloom of the spices is what gives Massaman its Persian-inflected depth. Add the beef and turn it in the paste until every piece is dark red, pour in the coconut milk, tamarind paste and kaffir lime leaves, bring to a bare simmer and braise gently with the lid ajar for an hour and a half, stirring every 20 minutes — the beef is ready when it gives easily to a spoon but still holds its shape. Slide in the potatoes, onions and peanuts and continue cooking uncovered for another 30 minutes until the potatoes are tender and the gravy has thickened to a glossy rich brown; stir in the fish sauce and palm sugar at the end, balancing the salt-sweet-sour triangle until it tastes deep and round, neither too sweet nor too sharp. Rest off the heat for 10 minutes, then serve in shallow bowls with jasmine rice, scattered with a few crushed peanuts on top — Massaman is the Thai curry that gains depth overnight, and any leftovers taste better the next day."}},{"id":211,"servings":4,"tipType":"veg","pairingsType":"thai","nutrition":{"cal":180,"prot":6,"carb":28,"fat":6,"fib":4},"origin":{"ar":"تايلاند","en":"Thailand","ro":"Thailanda"},"name":{"ar":"سوم تام","en":"Som Tam","ro":"Som Tam"},"category":{"ar":"سلطة","en":"Salad","ro":"Salată"},"ingredients":{"ar":["400 غ بابايا خضراء (غير ناضجة)، مقشّرة ومقطّعة جوليان رفيع جداً","4 طماطم كرزية، مقطّعة نصفين","2 فاصولياء طويلة (yardlong) أو 4 حبات فاصولياء خضراء، مقطّعة بطول 4 سم","2 فص ثوم، مقشّر","2 فلفل عين الطير (أو حسب الذوق)","2 ملعقة كبيرة سكر النخيل","2 ملعقة كبيرة صلصة السمك التايلاندية","عصير ليمونة لايم واحدة","1 ملعقة كبيرة مركز تمر هندي","1 ملعقة كبيرة جمبري مجفّف","2 ملعقة كبيرة فول سوداني محمّص (بعضه مهروس وبعضه كامل)","أوراق خس آيسبرغ أو كرنب للتقديم (اختياري، تقليدي)"],"en":["400 g green (unripe) papaya, peeled and finely julienned","4 cherry tomatoes, halved","2 long beans (yardlong) or 4 green beans, cut into 4 cm lengths","2 garlic cloves, peeled","2 bird's eye chillies (or to taste)","2 tbsp palm sugar","2 tbsp Thai fish sauce","Juice of 1 lime","1 tbsp tamarind concentrate","1 tbsp dried shrimp","2 tbsp roasted peanuts (some crushed, some whole)","Iceberg lettuce or cabbage leaves to serve (optional, traditional)"],"ro":["400 g papaya verde (necoaptă), curățată și tăiată julienne foarte fin","4 roșii cherry, tăiate în jumătăți","2 fasole lungă (yardlong) sau 4 fire de fasole verde, tăiate în bucăți de 4 cm","2 căței de usturoi, curățați","2 ardei iuți bird's eye (sau după gust)","2 linguri zahăr de palmier","2 linguri sos de pește thailandez","Sucul de la 1 lime","1 lingură concentrat de tamarind","1 lingură creveți uscați","2 linguri arahide prăjite (unele zdrobite, altele întregi)","Frunze de salată iceberg sau varză pentru servit (opțional, tradițional)"]},"howIsMade":{"ar":"في هاون فخاري (كروك) أو هاون حجري متين، اطحن الثوم والفلفل معاً حتى يفتح طعمهما — لا تطحنهما إلى مسحوق، فقط افتحهما — ثم أضف سكر النخيل واطحن مرات قليلة أخرى ليذوب في زيت الفلفل. اسكب صلصة السمك وعصير الليم والتمر الهندي، حرّك بالمدقّة لإذابة السكر، ثم أضف الجمبري المجفف واطرقه مرتين لتسطيحه في الصلصة. أضف الفاصولياء الطويلة وأنصاف الطماطم وادقّ برفق — خمس أو ست طرقات لكل صنف، فقط لتفتيتها وإطلاق عصاراتها في الصلصة — المدقّة هنا أداة تتبيل لا أداة تحطيم. أدخل البابايا المبشورة على دفعتين، متناوباً بين الدقّ الخفيف والتقليب بملعقة حتى يلمع كل خيط بالصلصة ويبقى مقرمشاً، ثم أضف الفول السوداني (الكامل من أجل القرمشة، والمهروس من أجل قوام) وقلّب لمرة أخيرة. تذوّق — السوم تام يجب أن يضرب أربعة نكهات في آن واحد: حامض، مالح، حلو، وحرارة فلفل شرسة — ثم كوّمه في صحون ضحلة أو على أوراق الخس وتناوله فوراً مع الأرز اللزج أو الدجاج المشوي.","en":"In a clay krok or sturdy stone mortar, pound the garlic and chillies together until bruised — not pulverised, just opened up — then add the palm sugar and pound a few more times to dissolve it into the chilli oil. Pour in the fish sauce, lime juice and tamarind, stir with the pestle until the sugar dissolves, then tip in the dried shrimp and pound a couple of times to flatten them into the dressing. Add the long beans and tomato halves and pound gently — five or six taps each, just enough to bruise them and release their juices into the dressing — the pestle here is a tool of seasoning, not destruction. Tip in the shredded papaya in two batches, alternating light pounding with turning everything with a spoon until each strand is glossy with the dressing but still crisp, then add the peanuts (whole for crunch, crushed for body) and toss one last time. Taste — Som Tam should hit four flavours at once: sour, salty, sweet and chilli-fierce — then pile into shallow bowls or onto lettuce leaves and eat immediately with sticky rice or grilled chicken."}},{"id":212,"servings":4,"tipType":"meat","pairingsType":"thai","nutrition":{"cal":720,"prot":32,"carb":60,"fat":38,"fib":4},"origin":{"ar":"تايلاند","en":"Thailand","ro":"Thailanda"},"name":{"ar":"خاو سوي","en":"Khao Soi","ro":"Khao Soi"},"category":{"ar":"شوربة نودلز","en":"Noodle soup","ro":"Tăiței în supă"},"ingredients":{"ar":["4 ملاعق كبيرة من معجون كاري الخاو سوي الشمالي التايلاندي (أو 3 ملاعق كبيرة من معجون الكاري الأحمر + 1 ملعقة صغيرة كاري بودرة + 1 ملعقة صغيرة كركم)","500 غ من أوراك الدجاج بالعظم أو أفخاذ مقطّعة قطعاً","800 مل حليب جوز الهند كامل الدسم","200 مل كريمة جوز الهند","500 مل مرق دجاج","2 ملعقة كبيرة صلصة سمك تايلاندية","1 ملعقة كبيرة سكر النخيل","400 غ من نودلز البيض الطازج (أو 300 غ جاف)","زيت محايد لقلي حفنة من النودلز","عصير ليمونتين لايم، يُضاف عند التقديم","زينة: شالوت شرائح، خضار خردل مخللة، كزبرة طازجة، شرائح ليم، زيت فلفل حار"],"en":["4 tbsp Northern Thai khao soi curry paste (or 3 tbsp red curry paste + 1 tsp curry powder + 1 tsp ground turmeric)","500 g bone-in chicken thighs or chicken legs cut into pieces","800 ml full-fat coconut milk","200 ml coconut cream","500 ml chicken stock","2 tbsp Thai fish sauce","1 tbsp palm sugar","400 g fresh egg noodles (or 300 g dried)","Neutral oil for deep-frying a handful of noodles","Juice of 2 limes, added at the table","Garnishes: sliced shallots, pickled mustard greens, fresh coriander, lime wedges, chilli oil"],"ro":["4 linguri pastă de curry Khao Soi din nordul Thailandei (sau 3 linguri pastă curry roșu + 1 linguriță curry pudră + 1 linguriță turmeric)","500 g pulpe de pui cu os sau pulpe întregi tăiate în bucăți","800 ml lapte de cocos gras","200 ml smântână de cocos","500 ml fond de pui","2 linguri sos de pește thailandez","1 lingură zahăr de palmier","400 g tăiței de ouă proaspeți (sau 300 g uscați)","Ulei neutru pentru a prăji o mână de tăiței","Sucul de la 2 lime, adăugat la masă","Garnituri: șalote feliate, frunze de muștar murate, coriandru proaspăt, felii de lime, ulei de chili"]},"howIsMade":{"ar":"سخّن كريمة جوز الهند في قدر ثقيل على نار متوسطة 4–5 دقائق، حتى ينفصل الزيت وتبدو الكريمة لامعة، ثم أضف معجون الخاو سوي وقلِّبه 2–3 دقائق، حتى يغمق وتفوح منه رائحة عميقة محمّصة — أثقل وأكثر ترابية من كاري وسط تايلاند، لأن هذا المعجون يعتمد على البهارات الجافة. أضف قطع الدجاج وقلّبها في المعجون حتى تتغطى، اسكب حليب جوز الهند والمرق، أوصلها إلى غليان هادئ واطبخها مع غطاء نصف مفتوح 30–35 دقيقة، حتى يصبح الدجاج طرياً جداً ويتراجع المرق قليلاً؛ تبّل بصلصة السمك وسكر النخيل قرب النهاية ليكون المرق غنياً، حلواً قليلاً، وحامضاً بشكل خفيف من معجون الكاري نفسه. أثناء الطهي، خذ حفنة صغيرة من النودلز الطازجة، انفض الماء الزائد، واقلِها في زيت 180°م لمدة 30–45 ثانية حتى تنتفخ وتذهب إلى الذهبي — التاج المقرمش لكل صحن — ثم صفّها على ورق. اغلِ بقية النودلز في ماء عادي حتى تطرى للتو، صفّها بسرعة، ووزّعها في صحون عميقة، اسكب فوقها الكاري الساخن مع قطعة دجاج على الأقل لكل حصة، وضع النودلز المقلية فوقها. مرّر الزينة على المائدة — شالوت شرائح، خضار الخردل المخللة، الكزبرة، شريحة ليم لعصرها أخيراً، وملعقة من زيت الفلفل — الطبق يعيش على التباين (مرق حريري، نودلز طرية تحت، نودلز مقرمشة فوق، عضّة الشالوت النيء، حموضة المخلل، إشراق الليم) وكل صحن يُبنى على المائدة.","en":"Heat the coconut cream in a heavy pot over medium heat for 4–5 minutes until the oil cracks out and the cream looks slick, then stir in the khao soi paste and fry for 2–3 minutes until it darkens and smells deeply toasted — heavier and earthier than central-Thai curries because the paste leans on dry spices. Add the chicken pieces and turn them in the paste until coated, pour in the coconut milk and stock, bring to a gentle simmer and cook with the lid ajar for 30–35 minutes until the chicken is meltingly tender and the broth has reduced a little; season with fish sauce and palm sugar towards the end so the broth is rich, gently sweet and faintly sour from the curry paste itself. While the curry simmers, take a small handful of the fresh egg noodles, shake off any excess water, and deep-fry in 180°C oil for 30–45 seconds until puffed and golden — the crispy crown for every bowl — then drain on paper. Boil the remaining noodles in plain water until just tender, drain quickly and divide between deep bowls, ladle over the hot curry with at least one piece of chicken per portion, and top with the fried noodles. Pass the garnishes round the table — sliced shallots, pickled mustard greens, coriander, a lime wedge to squeeze in last, and a spoon of chilli oil — the dish lives on contrast (silky soup, soft noodles below, crisp on top, raw shallot bite, pickle tang, lime brightness) and each bowl is built at the table."}},{"id":213,"servings":4,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":520,"prot":6,"carb":92,"fat":16,"fib":4},"origin":{"ar":"تايلاند","en":"Thailand","ro":"Thailanda"},"name":{"ar":"أرز لزج بالمانجو (خاو نياو ماموانغ)","en":"Mango Sticky Rice (Khao Niao Mamuang)","ro":"Orez glutinos cu mango (Khao Niao Mamuang)"},"category":{"ar":"تحلية","en":"Dessert","ro":"Desert"},"ingredients":{"ar":["300 غ من الأرز اللزج التايلاندي، منقوع في ماء بارد لمدة 4 ساعات على الأقل أو طوال الليل","400 مل حليب جوز الهند كامل الدسم","80 غ سكر النخيل (أو سكر بني فاتح)","½ ملعقة صغيرة ملح","1 ورقة باندان مربوطة بعقدة (اختياري، تقليدي)","2 حبة مانجو صفراء ناضجة (نام دوك ماي أو أتولفو)، مقشّرتان ومقطّعتان شرائح","2 ملعقة كبيرة بذور سمسم محمّصة أو فاصولياء مونغ مقشّرة، للتزيين","1 ملعقة صغيرة دقيق أرز (اختياري، لتثخين الصلصة المالحة)"],"en":["300 g Thai glutinous (sticky) rice, soaked in cold water at least 4 hours or overnight","400 ml full-fat coconut milk","80 g palm sugar (or light brown sugar)","½ tsp salt","1 pandan leaf, tied in a knot (optional, traditional)","2 ripe yellow mangoes (Nam Dok Mai or Ataulfo), peeled and sliced","2 tbsp toasted sesame seeds or split mung beans, for garnish","1 tsp rice flour (optional, for thickening the salty topping)"],"ro":["300 g orez glutinos thailandez (lipicios), pus la înmuiat în apă rece minim 4 ore sau peste noapte","400 ml lapte de cocos gras","80 g zahăr de palmier (sau zahăr brun deschis)","½ linguriță sare","1 frunză de pandan, legată în nod (opțional, tradițional)","2 mango galbene coapte (Nam Dok Mai sau Ataulfo), curățate și feliate","2 linguri semințe de susan prăjite sau mazăre mungo decorticată, pentru garnitură","1 linguriță făină de orez (opțional, pentru a îngroșa topping-ul sărat)"]},"howIsMade":{"ar":"صفّ الأرز المنقوع؛ غطّ سلة البخار بشاش أو ورق موز، اسكب الأرز فيها واتركها مغطاة فوق ماء يغلي معتدل لمدة 20–25 دقيقة، رافعاً القماش في منتصف الوقت لتقلب كومة الأرز كي تنضج بانتظام — جاهز حين تصبح الحبوب شفافة، لامعة، ومطّاطية-طرية حتى المنتصف. أثناء طهي الأرز، سخّن 300 مل من حليب جوز الهند في قدر صغير مع سكر النخيل والملح وورقة الباندان، حرّك بما يكفي فقط لإذابة السكر دون أن يغلي؛ احتفظ بالـ 100 مل المتبقية للصلصة المالحة. حين يخرج الأرز ساخناً من المُبخّر، انقله إلى وعاء واسع، قلّب ثلثَي حليب جوز الهند الحلو الدافئ بملعقة حتى يلمع كل حبة، ثم غطّه واتركه يرتاح 15–20 دقيقة كي يشرب الأرز الحليب وينتفخ إلى قوام بودنغ لؤلؤي ناعم. للصلصة المالحة، اطهُ الـ 100 مل المتبقية من حليب جوز الهند مع رشّة سخية من الملح وملعقة صغيرة من دقيق الأرز لدقيقتين، فقط حتى تثخن قليلاً. اكوِم الأرز الدافئ على طبق مع شرائح المانجو إلى جانبه، اسكب الكريمة المالحة فوقه، انثر بذور السمسم المحمّصة أو فاصولياء المونغ المقشّرة، وكل بالملعقة، قليلاً من الأرز وقليلاً من المانجو في كل قضمة — التباين بين دفء وحلاوة جوز الهند وحدّة وبرودة الفاكهة هو الطبق نفسه.","en":"Drain the soaked rice; line a steamer basket with cheesecloth or banana leaf, tip in the rice and steam covered over a moderate boil for 20–25 minutes, lifting the cloth halfway to flip the mound so it cooks evenly — done when the grains are translucent, glossy and chewy-tender all the way through. While the rice steams, warm 300 ml of the coconut milk in a small saucepan with the palm sugar, salt and pandan leaf, stirring just enough to dissolve the sugar without bringing it to a boil; reserve the remaining 100 ml for the salty topping. When the rice comes hot off the steamer, tip it into a wide bowl, fold through two-thirds of the warm sweet coconut milk with a spatula until each grain glistens, then cover and rest 15–20 minutes so the rice drinks the milk and swells to a soft pearl-pudding consistency. For the salty topping, simmer the remaining 100 ml coconut milk with a generous pinch of salt and the teaspoon of rice flour for 2 minutes, just until it thickens lightly. Mound the warm coconut rice on a plate with the mango slices alongside, drizzle the salty coconut cream across the top, scatter toasted sesame seeds or split mung beans, and eat with a spoon, a little rice and a little mango in every bite — warm coconut-sweet against cool fruit-sharp is the dish itself."}},{"id":214,"tipType":"meat","pairingsType":"meat","origin":{"ar":"عالمي","en":"International","ro":"Internațional"},"name":{"ar":"يخنة الضأن","en":"Lamb Stew","ro":"Tocăniță de miel"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["800 غ كتف ضأن مكعبات","2 بصلة","3 جزرات","3 حبات بطاطا","2 فصوص ثوم","2 ملعقة كبيرة معجون طماطم","500 مل مرق لحم","زعتر، ورق غار","ملح، فلفل، زيت زيتون"],"en":["800 g lamb shoulder, cubed","2 onions","3 carrots","3 potatoes","2 garlic cloves","2 tbsp tomato paste","500 ml beef stock","thyme, bay leaf","salt, pepper, olive oil"],"ro":["800 g pulpă de miel, cuburi","2 cepe","3 morcovi","3 cartofi","2 căței usturoi","2 linguri pastă de tomate","500 ml supă de carne","frunze de cimbru, dafin","sare, piper, ulei de măsline"]},"howIsMade":{"ar":"قطّعي كتف الخروف إلى مكعبات بحجم 4 سم تقريباً — كبيرة بما يكفي لتبقى طريّة بعد طهي طويل دون أن تتفتت. جفّفيها تماماً وتبّليها بسخاء بالملح والفلفل، ثم مرّريها بخفّة شديدة على الطحين ليساعد على تكثيف الصلصة. سخّني قدراً ثقيلة من الحديد الزهر بطبقة من الزيت حتى يلمع، وحمّري الخروف على ثلاث أو أربع دفعات دون ازدحام — الازدحام يجعل اللحم يطبخ بالبخار ويفقد القشرة العميقة. ضعي كل دفعة جانباً في طبق. في الدهن نفسه قلّبي البصل المفروم ناعماً والثوم حتى يصبحا شفافين، أضيفي معجون الطماطم واتركيه دقيقة حتى تصبح رائحته أكثر استدارة. أعيدي اللحم مع عصارته، اسكبي مرقاً ساخناً يكاد يغطّي، أضيفي بضع أغصان زعتر وورقة غار، ارفعي إلى غليان هادئ ثم خفّفي النار إلى أدنى مستوى. غطّي واطبخي تسعين دقيقة — لا تدعيه يفور، فقط فقاعات هادئة — مع تقليبة واحدة. أضيفي الجزر مقطعاً بشكل مائل والبطاطس الشمعية بقطع كبيرة، وأكملي الطهي ثلاثين إلى أربعين دقيقة حتى يتفكك اللحم بلمسة الشوكة وتحافظ البطاطس على شكلها. تذوّقي، عدّلي الملح، ارفعي ورقة الغار. قدّمي في صحون عميقة مع خبز مقرمش، بعد عشر دقائق من الراحة بعيداً عن النار حتى يتجمع المرق.","en":"Cut the lamb shoulder into roughly 4 cm cubes — large enough to stay tender through a long simmer without falling apart. Pat them completely dry and season generously with salt and pepper, then dust very lightly with flour to help the sauce thicken. Heat a heavy casserole or Dutch oven with a film of oil until it shimmers, and brown the lamb in three or four batches without crowding the pan — crowding steams the meat and you lose the deep crust. Set each batch aside on a plate. In the same fat, sweat finely chopped onion and garlic until translucent, then stir in tomato paste and let it cook a minute until it smells rounder. Return the lamb with any resting juices, pour in enough hot stock to just cover, add a few sprigs of thyme and a bay leaf, bring to a gentle simmer and lower the heat to the smallest possible. Cover and cook for ninety minutes — never let it boil, only bubble — stirring once. Add carrots cut on the bias and waxy potatoes in large chunks and cook another thirty to forty minutes, until the lamb pulls apart at the touch of a fork and the potatoes hold their shape. Taste, adjust salt, and lift out the bay. Serve in deep bowls with crusty bread, after letting the stew rest off the heat for ten minutes so the broth pulls together."}},{"id":215,"tipType":"salad","pairingsType":"salad","origin":{"ar":"اليونان","en":"Greece","ro":"Grecia"},"name":{"ar":"السلطة اليونانية","en":"Greek Salad","ro":"Salată grecească"},"category":{"ar":"سلطة","en":"Salad","ro":"Salate"},"ingredients":{"ar":["4 حبات طماطم ناضجة بشرائح سميكة","1 خيارة كبيرة بشرائح","1 فلفل أخضر","1 بصلة حمراء بحلقات رفيعة","200 غ جبنة فيتا قطعة","100 غ زيتون كالاماتا","2 ملعقة كبيرة زيت زيتون بكر ممتاز","1 ملعقة صغيرة زعتر يوناني مجفف","ملح خشن"],"en":["4 ripe tomatoes, thickly sliced","1 large cucumber, sliced","1 green pepper","1 red onion, thinly ringed","200 g block feta","100 g Kalamata olives","2 tbsp extra-virgin olive oil","1 tsp dried Greek oregano","coarse salt"],"ro":["4 roșii coapte, tăiate felii groase","1 castravete mare, tăiat felii","1 ardei verde","1 ceapă roșie, tăiată rondele subțiri","200 g feta în bloc","100 g măsline Kalamata","2 linguri ulei de măsline extravirgin","1 linguriță oregano grecesc uscat","sare grunjoasă"]},"howIsMade":{"ar":"قطّعي الطماطم الناضجة شرائح سميكة — بسماكة إصبع على الأقل — وجوهاً أو شرائح، حتى تحتفظ بعصيرها بدل أن تذوب إلى هريسة. الخيار أنصاف أقمار، الفلفل الأخضر حلقات رفيعة، البصلة الحمراء أرفع ما يمكن؛ إن كان البصل حاراً، انقعي الحلقات في ماء مثلج عشر دقائق لتخفيف حدته دون فقدان القرمشة. اجمعي كل شيء في وعاء عريض ضحل مع رشّة ملح خشن ولا تخلطي — اليونانيون يبنون هذه السلطة طبقات، لا تُقلَّب أبداً. انثري زيتون كالاماتا كاملاً بنواه. ضعي الفيتا فوقها قطعة واحدة كاملة، تماماً كما تُقدَّم في حانة كريتية. اسكبي بسخاء زيت زيتون بكر ممتاز، ثم انثري زعتراً يونانياً مجففاً افركيه بين راحتيك ليتحرر عبقه. قدّمي فوراً مع خبز مقرمش لتمسحي العصارة.","en":"Slice ripe tomatoes thick — at least a finger across — into wedges or rounds, so they hold their juice rather than collapse into purée. Cut the cucumber into half-moons, the green pepper into thin rings, and the red onion paper-thin; if sharp, soak the rings in iced water for ten minutes to soften the bite while keeping the crunch. Combine in a wide, shallow bowl with a pinch of coarse salt and resist tossing — Greeks build this salad in layers, never mixed. Scatter the Kalamata olives whole, with their stones. Lay the feta on top as a single uncut slab, exactly as you'd be served in a Cretan taverna. Drizzle generously with extra-virgin olive oil, then shower with dried oregano rubbed between your palms to release the aroma. Serve immediately with crusty bread for mopping the juices."}},{"id":216,"tipType":"salad","pairingsType":"italian","origin":{"ar":"إيطاليا","en":"Italy","ro":"Italia"},"name":{"ar":"سلطة كابريزي","en":"Caprese Salad","ro":"Salată Caprese"},"category":{"ar":"سلطة","en":"Salad","ro":"Salate"},"ingredients":{"ar":["3 حبات طماطم ناضجة بشرائح","250 غ موزاريلا الجاموس","أوراق ريحان طازج","زيت زيتون بكر ممتاز","ملح خشن","فلفل أسود مطحون طازج","خل بلسمي (اختياري)"],"en":["3 ripe tomatoes, sliced","250 g buffalo mozzarella","fresh basil leaves","extra-virgin olive oil","coarse salt","freshly ground black pepper","balsamic vinegar (optional)"],"ro":["3 roșii coapte, tăiate felii","250 g mozzarella di bufala","frunze de busuioc proaspăt","ulei de măsline extravirgin","sare grunjoasă","piper negru proaspăt măcinat","oțet balsamic (opțional)"]},"howIsMade":{"ar":"أخرجي الموزاريلا من الثلاجة قبل التقديم بثلاثين دقيقة على الأقل — الباردة تفقد كريميتها ويبقى الطعم باهتاً. اختاري طماطم ناضجة عطرة — من نوع Cuore di Bue إلى الكرزية — ما دامت تفوح برائحة الصيف، وقطّعيها شرائح بسماكة سنتيمتر تقريباً. قطّعي الموزاريلا شرائح بالسماكة نفسها. على طبق كبير مسطح، ضعي بالتناوب شريحة طماطم وشريحة موزاريلا في صف واحد متراكب قليلاً، وأدخلي بين كل زوج ورقة ريحان كاملة لتظهر خضرتها. اسكبي زيت الزيتون البكر الممتاز حتى يتجمع في القاع، وتبّلي برشّات من ملح البحر ولفّة من الفلفل الأسود المطحون طازجاً. قدّمي فوراً بدرجة حرارة الغرفة، مع خبز مقرمش. النخبويون يرفضون الخل البلسمي — كابريزي ولدت من دونه وتبقى أفضل كذلك.","en":"Take the mozzarella out of the fridge at least thirty minutes before serving — fridge-cold it loses its creaminess and the flavour stays flat. Choose ripe, fragrant tomatoes — anything from Cuore di Bue to cherries on the vine, as long as they smell of summer — and slice them about a centimetre thick. Cut the mozzarella into slices of the same thickness. On a large flat plate, alternate one slice of tomato with one of mozzarella in a single, slightly overlapping row, tucking a whole basil leaf between each pair so the green shows. Drizzle with extra-virgin olive oil until it pools at the base, season with a few flakes of sea salt and a turn of freshly cracked black pepper. Serve immediately at room temperature, with crusty bread. Purists refuse balsamic vinegar — Caprese was born without it and works best that way."}},{"id":217,"tipType":"pasta","pairingsType":"italian","origin":{"ar":"إيطاليا","en":"Italy","ro":"Italia"},"name":{"ar":"لازانيا","en":"Lasagna","ro":"Lasagna"},"category":{"ar":"معكرونة","en":"Pasta","ro":"Paste"},"ingredients":{"ar":["300 غ ألواح لازانيا","500 غ لحم بقري مفروم","1 بصلة","2 فصوص ثوم","400 غ صلصة طماطم","300 مل صلصة بشاميل","150 غ بارميجانو مبشور","150 غ موزاريلا","ملح، فلفل، زيت زيتون"],"en":["300 g lasagna sheets","500 g beef mince","1 onion","2 garlic cloves","400 g tomato sauce","300 ml béchamel sauce","150 g Parmigiano grated","150 g mozzarella","salt, pepper, olive oil"],"ro":["300 g foi de lasagna","500 g vită tocată","1 ceapă","2 căței usturoi","400 g sos de roșii","300 ml sos béchamel","150 g Parmigiano ras","150 g mozzarella","sare, piper, ulei de măsline"]},"howIsMade":{"ar":"ابدئي بصلصة الراغو: قلّبي البصل والجزر والكرفس المفرومين فرماً ناعماً جداً على نار هادئة في زيت الزيتون وقطعة زبدة لمدة عشر دقائق — السوفريتو هو أساس النكهة كلها. ارفعي الحرارة، أضيفي اللحم المفروم وحمّريه جيداً مفتّتةً إياه بظهر الملعقة. اسكبي كأس نبيذ أحمر ودعيه يتبخر، ثم أضيفي الباساتا، رشّة ملح وحبّة جوزة الطيب مبشورة. اطبخي مكشوفاً على أصغر لهب ساعةً على الأقل — ساعتين إن كان هناك وقت — مع التحريك من وقت لآخر. في الوقت نفسه حضّري البشاميل: ذوّبي الزبدة، أضيفي الطحين، اطبخي دقيقة، ثم اسكبي الحليب الدافئ تدريجياً مع الخفق حتى يصبح ناعماً وكثيفاً؛ تبّلي بالملح ولمسة جوزة الطيب. سخّني الفرن إلى 180°م. ضعي طبقة رقيقة من البشاميل في قاع طبق عميق لمنع الالتصاق، ثم رصّي بهذا الترتيب: شرائح المعكرونة، الراغو، البشاميل، طبقة سخية من البارميجانو المبشور. كرّري خمس طبقات على الأقل، منهيةً بالبشاميل ورشّة أخيرة من البارميجانو. اخبزي 35–40 دقيقة حتى يصبح الوجه ذهبياً والحواف تفور. اتركيها ترتاح خمس عشرة دقيقة قبل التقطيع — وإلا تنزلق الطبقات.","en":"Start with the ragù: gently soften finely chopped onion, carrot and celery in olive oil and a knob of butter for ten minutes — the soffritto is the base of all the flavour. Raise the heat, add the minced beef and brown it deeply, breaking it up with the back of a spoon. Pour in a glass of red wine and let it evaporate, then add the tomato passata, a pinch of salt and a grating of nutmeg. Cook uncovered on the lowest flame for at least one hour — two if you have time — stirring every so often. Meanwhile, make the béchamel: melt butter, whisk in flour, cook a minute, then gradually pour in warm milk while whisking until smooth and thickened; season with salt and a touch of nutmeg. Heat the oven to 180°C. Spoon a thin layer of béchamel into the base of a deep dish to prevent sticking, then layer in this order: pasta sheets, ragù, béchamel, a generous grating of Parmigiano. Repeat for at least five layers, ending with béchamel and a final shower of Parmigiano. Bake 35–40 minutes until the top is golden and the edges bubble. Rest fifteen minutes before cutting — this is non-negotiable, or the layers slide."}},{"id":218,"tipType":"salad","pairingsType":"salad","origin":{"ar":"فرنسا","en":"France","ro":"Franța"},"name":{"ar":"سلطة نيسواز","en":"Salade Niçoise","ro":"Salată Niçoise"},"category":{"ar":"سلطة","en":"Salad","ro":"Salate"},"ingredients":{"ar":["200 غ تونة معلبة بالزيت","4 بيضات مسلوقة","200 غ فاصوليا خضراء","300 غ بطاطا صغيرة","12 زيتونة نيسوازية","4 فيليه أنشوجة","2 طماطم","2 ملعقة كبيرة زيت زيتون","خل نبيذ، ملح، فلفل"],"en":["200 g tinned tuna in oil","4 hard-boiled eggs","200 g green beans","300 g new potatoes","12 Niçoise olives","4 anchovy fillets","2 tomatoes","2 tbsp olive oil","wine vinegar, salt, pepper"],"ro":["200 g ton la conservă în ulei","4 ouă fierte tari","200 g fasole verde","300 g cartofi noi","12 măsline Niçoise","4 file de hamsii","2 roșii","2 linguri ulei de măsline","oțet de vin, sare, piper"]},"howIsMade":{"ar":"اسلقي البيض ثماني دقائق من ماء بارد ثم انقليه فوراً إلى ماء مثلج لإيقاف الطهي وإبقاء الصفار متماسكاً بالكاد. اسلقي البطاطس الجديدة كاملة في ماء مملّح حتى يدخل طرف السكين دون مقاومة، نحو خمس عشرة دقيقة، وقطّعيها نصفين وهي لا تزال دافئة لتمتص التتبيلة. اسلقي الفاصوليا الخضراء سلقاً سريعاً ثلاث دقائق في ماء مغلي مملّح بسخاء ثم اغمريها في ماء مثلج لتبقى مقرمشة وزاهية الخضرة. على طبق عريض مسطح، رصّي بسرير من الورق الأخضر، ووزّعي كل شيء في مجموعات دون خلط — أرباع البيض، أنصاف البطاطس، الفاصوليا، شرائح الطماطم، التونة قطعاً، الزيتون، شرائح الأنشوجة متقاطعة فوقها. اخفقي زيت الزيتون مع رشّة خل نبيذ، تبّلي، واسكبي قبل التقديم مباشرة. تُقدَّم باردة قليلاً، لا مثلّجة.","en":"Boil the eggs eight minutes from cold, then plunge straight into iced water to stop the cooking and keep the yolk just set. Cook the new potatoes whole in salted water until a knife tip slides in cleanly, around fifteen minutes, then halve them while still warm so they soak up the dressing. Blanch the green beans for three minutes in plenty of boiling salted water, then refresh in iced water so they stay snappy and bright. On a wide, flat plate, lay a bed of greens and arrange everything in groups rather than tossing — quartered eggs, potato halves, beans, tomato wedges, the tuna broken into chunks, olives, anchovy fillets draped across the top. Whisk olive oil with a splash of wine vinegar, season, and spoon over only just before serving. Bring to the table cool, not fridge-cold."}},{"id":219,"tipType":"meat","pairingsType":"meat","origin":{"ar":"روسيا","en":"Russia","ro":"Rusia"},"name":{"ar":"بيف ستروجانوف","en":"Beef Stroganoff","ro":"Boeuf Stroganoff"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["600 غ فيليه بقري بشرائح","300 غ مشروم","1 بصلة","2 فصوص ثوم","200 مل قشدة حامضة","2 ملعقة كبيرة مسطردة","200 مل مرق لحم","2 ملعقة كبيرة زبدة","ملح، فلفل، بقدونس"],"en":["600 g beef tenderloin, sliced into strips","300 g button mushrooms","1 onion","2 garlic cloves","200 ml sour cream","2 tbsp mustard","200 ml beef stock","2 tbsp butter","salt, pepper, parsley"],"ro":["600 g mușchi de vită, tăiat fâșii","300 g ciuperci champignon","1 ceapă","2 căței usturoi","200 ml smântână","2 linguri muștar","200 ml supă de vită","2 linguri unt","sare, piper, pătrunjel"]},"howIsMade":{"ar":"قطّعي الفيليه ضد التليفات شرائح لا تزيد سماكتها على سماكة قلم رصاص — القطع الأكثر سُمكاً تبقى قاسية في زمن الطهي القصير. جفّفيها تماماً، تبّليها بالملح والفلفل، ومرّريها مرور خفيف على الطحين. سخّني مقلاة واسعة على نار قوية جداً، أضيفي قطعة زبدة مع زيت، وحمّري اللحم على دفعتين أو ثلاث دون ازدحام المقلاة، ثلاثين ثانية لكل وجه فقط، حتى تتحمّر القشرة ويبقى الداخل وردياً. ارفعيها على طبق لترتاح. في المقلاة نفسها، خفّفي النار، اطبخي البصل المقطع بدقة في الزبدة، ثم أضيفي الفطر واتركيه يتحمّر بعمق دون تحريك خلال الدقائق الثلاث الأولى. اسكبي مرق اللحم وقطرة من البراندي إن وُجد، اكشطي كل ما تحمّر في القاع، وقلّصي الكمية إلى النصف. ارفعي المقلاة بالكامل عن النار — هذه هي الخطوة الحاسمة — وأضيفي القشدة الحامضة والخردل بالتقليب حتى يصبح المزيج ناعماً؛ إن غلت الآن، تتفكك القشدة. أعيدي اللحم وعصيره إلى المقلاة، دوّري لتدفئة الكل، عدّلي الملح، ورشّي بقدونساً مفروماً. قدّمي فوراً فوق معكرونة بالزبدة أو بطاطس مهروسة أو أرز مبخّر.","en":"Cut the beef tenderloin into strips against the grain, no thicker than a pencil — thicker pieces stay tough in the short cook time. Pat them completely dry, season with salt and pepper, then dust lightly with flour. Heat a wide pan very hot, add a knob of butter and oil, and sear the beef in two or three batches without crowding the pan, just thirty seconds a side, until browned outside and still pink within. Lift onto a plate and rest. In the same pan, lower the heat and soften finely sliced onion in butter, then add the mushrooms and let them brown deeply without stirring for the first three minutes. Pour in the beef stock and a splash of brandy if you have it, scrape up every brown bit from the base, and reduce by half. Take the pan completely off the heat — the critical step — and stir in the sour cream and the mustard until smooth; if it boils now, the cream splits. Return the beef and any resting juices to the pan, swirl through to warm, taste for salt, and shower with chopped parsley. Serve immediately over buttered noodles, mash, or steamed rice."}},{"id":222,"tipType":"meat","pairingsType":"meat","origin":{"ar":"فرنسا","en":"France","ro":"Franța"},"name":{"ar":"كوك أو فان","en":"Coq au Vin","ro":"Coq au vin"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["1 دجاجة كاملة، مقطعة 8 قطع","200 غ بانشيتا أو لحم مقدد","250 غ مشروم","200 غ بصل لؤلؤي","1 زجاجة نبيذ أحمر بورغندي","2 فصوص ثوم","2 جزرة","زعتر، ورق غار","زبدة، دقيق، ملح، فلفل، بقدونس"],"en":["1 whole chicken, cut into 8 pieces","200 g pancetta or bacon","250 g button mushrooms","200 g pearl onions","1 bottle red Burgundy wine","2 garlic cloves","2 carrots","thyme, bay leaf","butter, flour, salt, pepper, parsley"],"ro":["1 pui întreg, tăiat în 8 bucăți","200 g pancetta sau bacon","250 g ciuperci champignon","200 g ceapă mică","1 sticlă vin roșu Burgundia","2 căței usturoi","2 morcovi","cimbru, dafin","unt, făină, sare, piper, pătrunjel"]},"howIsMade":{"ar":"في الليلة السابقة، قطّعي الدجاجة إلى ثماني قطع واغمريها في نبيذ بورغوندي الأحمر مع ورق الغار، الزعتر، نصف بصلة وبضع حبات فلفل أسود؛ غطّيها واتركيها في الثلاجة طوال الليل، حتى يخترق النبيذ اللحم وتمتص التتبيلة عبق الطير. في اليوم التالي، أخرجي الدجاج وجفّفي كل قطعة جيداً — الجلد الرطب لا يتحمّر، وهذه هي الخطيئة الكبرى هنا. احفظي التتبيلة. في قدر ثقيلة من الحديد الزهر، اقلي البانشيتا المكعبة حتى تصبح مقرمشة، ارفعيها وحمّري الدجاج في الدهن على دفعتين، بدءاً بالجلد إلى الأسفل، حتى تصبح كل قطعة بلون الماهوغني. ضعيها جانباً. في القدر نفسها، قلّبي البصل المفروم ناعماً والثوم والجزر، انثري ملعقة كبيرة ممتلئة من الطحين وقلّبي دقيقة، ثم اسكبي التتبيلة المحفوظة ومغرفة من مرق الدجاج الداكن، مع كشط كل أثر بنّي من القاع. أعيدي الدجاج والبانشيتا، ارفعي إلى غليان هادئ، غطّي واطبخي على أدنى نار — أو في فرن بحرارة 160°م — ستين دقيقة، حتى يصبح اللحم طريّاً لكنه لا يزال متعلقاً بالعظم. أثناء الطهي، حمّري بصل اللؤلؤ في الزبدة في مقلاة منفصلة حتى يصبح كهرماني اللون، والفطر في مقلاة أخرى حتى يتحمّر بعمق — لا تجمعيهما، وإلا يطبخ بعضهما بعضاً بالبخار. أضيفي الاثنين إلى القدر في آخر خمس عشرة دقيقة، عدّلي الملح، أنهي بقطعة زبدة باردة تذوب بعيداً عن النار ورشّة من البقدونس. قدّمي مع بطاطس مهروسة أو معكرونة بالزبدة، لتلتقطي كل قطرة من الصلصة.","en":"The night before, joint the chicken into eight pieces and submerge in red Burgundy with bay, thyme, a halved onion and a few peppercorns; cover and refrigerate overnight so the wine penetrates the flesh and the marinade takes on the bird's perfume. Next day, lift the chicken out and pat each piece bone-dry — wet skin will not brown, which is the cardinal sin here. Reserve the marinade. In a heavy cast-iron pot, render diced pancetta until crisp; lift it out and brown the chicken in the rendered fat in two batches, skin-side first, until each piece is mahogany. Set aside. In the same pot, sweat finely chopped onion, garlic and carrot, scatter a heaped spoonful of flour over and stir for a minute, then pour in the reserved marinade and a ladle of dark chicken stock, scraping every brown trace from the bottom. Return the chicken and pancetta, bring to a gentle simmer, cover and cook on the lowest flame — or in a 160°C oven — for sixty minutes, until the meat is tender but still clings to the bone. While it cooks, sauté the pearl onions in butter until amber and the mushrooms in a separate pan until deeply browned — never together, or they steam each other. Slip both into the pot for the last fifteen minutes, taste for salt, finish with a knob of cold butter swirled in off the heat and a shower of parsley. Serve with mashed potato or buttered noodles to catch every drop of sauce."}},{"id":223,"tipType":"meat","pairingsType":"meat","origin":{"ar":"بولندا","en":"Poland","ro":"Polonia"},"name":{"ar":"بيغوس","en":"Bigos","ro":"Bigos"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["500 غ مخلل ملفوف مصفّى","300 غ ملفوف طازج مقطع","400 غ كتف خنزير مكعبات","200 غ نقانق مدخنة (كيلباسا)","150 غ لحم مقدد","1 بصلة","2 فصوص ثوم","3 برقوق مجفف","فلفل البهار، ورق غار، بابريكا، ملح، فلفل"],"en":["500 g sauerkraut, drained","300 g fresh cabbage, shredded","400 g pork shoulder, cubed","200 g smoked sausage (kielbasa)","150 g bacon","1 onion","2 garlic cloves","3 dried prunes","allspice, bay leaf, paprika, salt, pepper"],"ro":["500 g varză murată, scurtă","300 g varză proaspătă, tăiată","400 g porc (umăr), cuburi","200 g cârnați afumați (kielbasa)","150 g bacon","1 ceapă","2 căței usturoi","3 prune uscate","ienibahar, dafin, boia, sare, piper"]},"howIsMade":{"ar":"البيغوس يُبنى طبقات — لكل طاهٍ بولندي ترتيبه الخاص، لكن المبدأ هو الصبر. في قدر ثقيلة، أذيبي اللحم المقدّد المقطّع مكعبات على نار متوسطة حتى تخرج الدهون وتقرمش القطع، ثم ارفعيها واحفظيها. حمّري كتف الخنزير المكعّبة في دهن اللحم المقدّد على دفعتين دون ازدحام، حتى يصبح كل وجه ذهبياً غامقاً، ثم ارفعيها. قلّبي البصل المفروم ناعماً والثوم في الدهن نفسه، ثم أعيدي اللحم مع اللحم المقدّد. صفّي مخلل الملفوف واغسليه سريعاً إن كان حامضاً جداً، وأضيفيه مع الملفوف الطازج المقطّع شرائح، الكِيلباسا المقطّعة، البرقوق المنزوع النوى، بضع أوراق غار، حبات عرعر مهروسة في الكف، بهار حلو وبابريكا حلوة. اسكبي ماءً بمقدار التغطية بالكاد، ارفعي إلى غليان هادئ، اخفضي إلى أدنى نار، غطّي وانسي القدر ساعتين أو ثلاثاً، مع التحريك كل نصف ساعة ودفع الملفوف تحت السائل. عدّلي الملح في النهاية. السر الصادق للبيغوس: بردي القدر في الثلاجة طوال الليل وسخّنيها ببطء في اليوم التالي — تتزوج النكهات، يعمق الدخان، ويتركّز المرق.","en":"Bigos is built in layers — every cook in Poland has their own order, but the principle is patience. In a heavy pot, render diced bacon over medium heat until the fat runs and the pieces crisp, then lift them out and reserve. Brown the cubed pork shoulder in the bacon fat in two batches without crowding, until each side is deeply golden, and remove. Soften finely chopped onion and garlic in the same fat, then return the meat with the bacon. Drain and rinse the sauerkraut briefly if very sour, and pile it in with the shredded fresh cabbage, the sliced kielbasa, the pitted prunes, a few bay leaves, several juniper berries crushed in the palm, allspice and sweet paprika. Pour in just enough water to barely cover, bring to a gentle simmer, then lower the heat right down, cover, and forget about it for two to three hours, stirring every half hour and pushing the cabbage down into the liquor. Taste and adjust salt at the end. The honest secret of bigos: cool it overnight in the fridge, then warm slowly the next day — the flavours marry, the smoke deepens, the broth concentrates."}},{"id":226,"tipType":"asian","pairingsType":"asian","origin":{"ar":"فيتنام","en":"Vietnam","ro":"Vietnam"},"name":{"ar":"لفائف الربيع الفيتنامية","en":"Vietnamese Spring Rolls","ro":"Rulouri vietnameze proaspete"},"category":{"ar":"غداء","en":"Lunch","ro":"Prânz"},"ingredients":{"ar":["12 ورقة أرز (bánh tráng)","200 غ روبيان مسلوق ومقشّر","200 غ بطن خنزير مسلوق بشرائح","100 غ شعيرية أرز مسلوقة","1 خيار","أوراق خس","أوراق نعناع طازجة","أوراق كزبرة طازجة","صلصة هويسن أو nước chấm للتغميس"],"en":["12 rice paper wrappers (bánh tráng)","200 g cooked prawns, peeled","200 g cooked pork belly, sliced","100 g cooked rice vermicelli","1 cucumber","lettuce leaves","fresh mint leaves","fresh coriander leaves","hoisin or nước chấm sauce for dipping"],"ro":["12 foi de orez (bánh tráng)","200 g creveți fierți, decojiți","200 g piept de porc fiert, feliat","100 g tăiței de orez fierți","1 castravete","frunze de salată","frunze de mentă proaspătă","frunze de coriandru","sos hoisin sau nước chấm pentru servit"]},"howIsMade":{"ar":"حضّري كل شيء قبل أن تبدئي باللف — ما إن تبدئي لا يمكنك التوقف. اطبخي الشعرية الأرز حسب العبوة، اغسليها تحت ماء بارد حتى تبرد تماماً وصفّيها جيداً. قطّعي صدر الخنزير المطبوخ شرائح رفيعة؛ افلقي الجمبري المطبوخ طولياً ليظهر الوجه الوردي عبر الورقة. قطّعي الخيار أعواد رفيعة. اجمعي الأعشاب، أوراق الخس بدون السيقان، الشعرية، الخيار والبروتينات في صينية على مرمى اليد. املئي وعاءً ضحلاً بماء دافئ — لا ساخن. اغمسي ورقة أرز خمس ثوانٍ فقط؛ يجب أن تبقى متماسكة حين تضعينها على فوطة مطبخ رطبة قليلاً، وستكمل ليونتها أثناء اللف. على الثلث الأقرب إليك ضعي ورقة خس صغيرة، بضع ورقات نعناع وكزبرة، رشّة شعرية، أعواد خيار وشريحة لحم. ثني الحافة السفلية فوق الحشوة، اطوي الجانبين للداخل، وعند بدء اللف الأخير ضعي نصفي جمبري بالوجه الوردي للأسفل على الورقة لتظهرا عبر اللفافة. لفّي بإحكام للإغلاق. غطّي اللفافات الجاهزة بمنشفة رطبة كي لا تجف، وقدّميها مع صلصة هويسن-فستق أو nước chấm.","en":"Prep everything before you start rolling — once you begin you can't pause. Cook the rice vermicelli per the packet, rinse under cold water until completely cool, and drain well. Slice the cooked pork belly thinly; have the cooked prawns split lengthwise so the pink side faces the wrapper for presentation. Cut the cucumber into matchsticks. Pile the herbs, lettuce leaves with their stems removed, vermicelli, cucumber and proteins on a tray within easy reach. Fill a shallow bowl with warm — not hot — water. Dip one rice paper for just five seconds; it should still feel firm when you lay it on a slightly damp tea towel, and it will finish softening as you build the roll. On the third closest to you, lay a small lettuce leaf, then a few mint and coriander leaves, a pinch of vermicelli, cucumber matchsticks and a slice of pork. Fold the bottom edge up over the filling, then fold the two sides in, and as you start the final roll lay two prawn halves pink-side-down on the wrapper so they show through the finished roll. Roll tightly to seal. Cover finished rolls with a damp cloth so they don't dry, and serve with hoisin-peanut sauce or nước chấm."}},{"id":227,"tipType":"fish","pairingsType":"seafood","origin":{"ar":"حوض المتوسط","en":"Mediterranean","ro":"Mediterana"},"name":{"ar":"دنيس مشوي","en":"Grilled Sea Bream","ro":"Dorada la grătar"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["2 سمكتي دنيس كاملتين (500 غ كل واحدة)","2 ليمونة","4 فصوص ثوم","شبت وبقدونس طازج","زعتر","زيت زيتون بكر ممتاز","ملح خشن","فلفل أسود مطحون طازج"],"en":["2 whole sea bream (about 500 g each)","2 lemons","4 garlic cloves","fresh dill and parsley","thyme","extra-virgin olive oil","coarse salt","freshly ground black pepper"],"ro":["2 dorade întregi (cca 500 g fiecare)","2 lămâi","4 căței usturoi","mărar și pătrunjel proaspăt","cimbru","ulei de măsline extravirgin","sare grunjoasă","piper negru proaspăt"]},"howIsMade":{"ar":"اشتري أطزج دوراد تجدينها — عيون صافية، خياشيم حمراء زاهية، لحم متماسك يعود إلى وضعه عند الضغط. اقشري السمكة وأفرغيها إن لم يفعل البائع، مع إبقاء الرأس والذيل. بسكين حاد، اعملي ثلاثة شقوق مائلة في الجلد على كل جانب، تكاد تصل إلى العظم — لتسمح للحرارة بالنفاذ بانتظام ولتمنع تجعّد الجلد على الشواية. ملّحي بسخاء داخل البطن وعلى الجلد قبل عشرين دقيقة من الشواء، لتأخذ الملوحة طريقها إلى اللحم ولتجف السطح فتتحمر مقرمشاً. احشي البطن بشرائح ليمون وفصوص ثوم مهروسة وشبت وبقدونس وعدة أغصان زعتر. ادهني السطح الخارجي بزيت زيتون بكر ممتاز. أشعلي جمراً حاراً واشوي 6–8 دقائق لكل جانب، واقلبي السمكة فقط حين تتحرر بنفسها عن الشبك — إن أكرهتها تمزّق الجلد. اللحم جاهز حين يرتفع عن العظم بطرف الشوكة. اتركيها دقيقتين بعيداً عن النار ثم احملي السمكة كاملة إلى المائدة على لوح خشبي، مع شرائح ليمون إضافية، رشّة من زيت جديد وسلطة يونانية إلى جانبها.","en":"Buy the freshest sea bream you can find — clear eyes, bright red gills, firm flesh that springs back when pressed. Scale and gut the fish if your fishmonger hasn't, leaving head and tail on. With a sharp knife, score three diagonal slashes through the skin on each side, almost to the bone — they let the heat penetrate evenly and stop the skin from curling on the grill. Salt generously inside the cavity and on the skin, twenty minutes before cooking, so the salt has time to season the flesh and dry the surface for crisp browning. Stuff the belly with lemon slices, smashed garlic cloves, dill, parsley and a few sprigs of thyme. Brush the outside with extra-virgin olive oil. Build a hot charcoal fire and grill 6–8 minutes per side, flipping only when the fish releases cleanly from the grate — force it and the skin tears. The flesh is ready when it lifts off the bone with the tip of a fork. Rest two minutes off the heat, then carry the whole fish to the table on a board with extra lemon wedges, a drizzle of new olive oil, and a Greek salad alongside."}},{"id":228,"tipType":"fish","pairingsType":"seafood","origin":{"ar":"فرنسا","en":"France","ro":"Franța"},"name":{"ar":"قاروص بروفنسالي","en":"Sea Bass Provençal","ro":"Lup de mare provensal"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["2 فيليه قاروص (نحو 200 غ كل واحدة)","400 غ طماطم كرزية","12 زيتونة سوداء نيسوازية","2 فصوص ثوم","1 ملعقة كبيرة كبر","1 غصن إكليل الجبل","زعتر طازج","زيت زيتون، نبيذ أبيض جاف","ملح، فلفل، ريحان"],"en":["2 sea bass fillets (about 200 g each)","400 g cherry tomatoes","12 black Niçoise olives","2 garlic cloves","1 tbsp capers","1 sprig rosemary","fresh thyme","olive oil, dry white wine","salt, pepper, basil"],"ro":["2 fileuri de lup de mare (cca 200 g fiecare)","400 g roșii cherry","12 măsline negre Niçoise","2 căței usturoi","1 lingură capere","1 ramură rozmarin","cimbru proaspăt","ulei de măsline, vin alb sec","sare, piper, busuioc"]},"howIsMade":{"ar":"ابدئي بالسمك: إن استخدمتِ شرائح بالجلد، أخرجيها من الثلاجة قبل ثلاثين دقيقة لتعتدل حرارتها، وجفّفي كل قطعة بمنشفة ورقية تماماً — السمك البارد الرطب يطهى بشكل غير متساوٍ ولا يتحمّر. ملّحي قليلاً على الوجهين واتركيها جانباً. سخّني الفرن إلى 200°م. في طبق عريض مدهون بزيت الزيتون، رصّي الطماطم الكرزية المقطّعة نصفين مع الوجه المقطّع للأعلى، حبات زيتون نيس السوداء كاملة، كبر مغسولاً، بضع فصوص ثوم بشرائح رفيعة، أغصان زعتر وغصن إكليل جبل. اسكبي مزيداً من زيت الزيتون بسخاء، وكأس نبيذ أبيض جاف، وتبّلي بالملح والفلفل المطحون طازجاً. أدخلي الطبق إلى الفرن عشر دقائق — يجب أن تنفجر الطماطم وتطلق عصارتها، ويتقلّص النبيذ إلى النصف، ويفقد الثوم حدّته؛ هكذا يُبنى الفراش العطري الذي يستقبل السمك. اسحبي الطبق، ضعي الشرائح والجلد إلى الأعلى بين الطماطم واسكبي شيئاً من عصارة الطبق فوقها. أعيديها إلى الفرن ثماني إلى عشر دقائق، حتى يصبح اللحم معتماً وينفصل عند طرف الشوكة، وتأخذ القشرة لمسات ذهبية. اختبري المنتصف بطرف سكين: إن دخل دون مقاومة، نضج. اتركي السمك يستريح دقيقتين، انثري ورق ريحان ممزّق باليد فوقه، وقدّمي الطبق إلى المائدة مع خبز مقرمش لتمسحي به الصلصة البروفنسالية — من دونه، يبقى نصف الطعام في الطبق.","en":"Start with the fish: if using skin-on fillets, take them out of the fridge thirty minutes ahead to temper, and pat each piece bone-dry with kitchen paper — cold, wet fish cooks unevenly and won't brown. Salt lightly on both sides and set aside. Heat the oven to 200°C. In a wide oiled dish, lay halved cherry tomatoes cut-side up, whole Niçoise olives, rinsed capers, a few thinly sliced garlic cloves, thyme sprigs and a single sprig of rosemary. Drizzle generously with more olive oil, pour in a glass of dry white wine, season with salt and freshly cracked pepper. Slide into the oven for ten minutes — the tomatoes need to burst and release their juices, the wine reduces by half, and the garlic loses its sharpness; this is how the aromatic bed for the fish is built. Pull the dish out, lay the fillets skin-up among the tomatoes and spoon some of the pan juices over them. Return for eight to ten minutes, until the flesh turns opaque and flakes at the tip of a fork, and the skin takes on a few golden patches. Check the centre with a knife tip: if it slides in without resistance, it is done. Rest two minutes, scatter torn basil leaves on top, and bring the dish to the table with crusty bread to mop the Provençal sauce — without it, half the meal stays in the pan."}},{"id":229,"tipType":"meat","pairingsType":"italian","origin":{"ar":"إيطاليا","en":"Italy","ro":"Italia"},"name":{"ar":"دجاج محمر ألا ديافولا","en":"Roast Chicken Diavola","ro":"Pui la cuptor alla diavola"},"category":{"ar":"عشاء","en":"Dinner","ro":"Cină"},"ingredients":{"ar":["1 دجاجة كاملة مفتوحة كالفراشة","4 فصوص ثوم مهروسة","2 ملعقة كبيرة فلفل أحمر مطحون (بيبيرونتشينو)","1 ملعقة صغيرة بابريكا مدخنة","1 ليمونة (عصير وقشر مبشور)","3 ملاعق كبيرة زيت زيتون","زعتر وإكليل الجبل","ملح خشن، فلفل أسود"],"en":["1 whole chicken, spatchcocked","4 garlic cloves, crushed","2 tbsp crushed chilli flakes (peperoncino)","1 tsp smoked paprika","1 lemon (juice and zest)","3 tbsp olive oil","thyme and rosemary","coarse salt, black pepper"],"ro":["1 pui întreg, despicat (spatchcocked)","4 căței usturoi zdrobiți","2 linguri ardei iute zdrobit (peperoncino)","1 linguriță boia afumată","1 lămâie (suc și coajă)","3 linguri ulei de măsline","cimbru și rozmarin","sare grunjoasă, piper negru"]},"howIsMade":{"ar":"افتحي الدجاجة (سباتشكوك) إن لم يفعل الجزّار: ضعيها صدراً للأسفل، وبمقصّ مطبخ متين اقطعي العمود الفقري من الجانبين، اقلبيها واضغطي بقوة على عظم الصدر حتى يفرقع ويصبح الطائر مسطّحاً. في وعاء واسع، اخفقي زيت الزيتون، الثوم المهروس، البابريكا المدخّنة، الملح الخشن، عصير وقشر الليمون، وكمية جريئة من رقائق الفلفل الحار — هي روح الطبق بأكملها. ادهني التتبيلة على الوجهين وفي كل ثنية من الجلد، واتركيها ساعة على الأقل في حرارة الغرفة، أو ليلة كاملة مغطّاة في الثلاجة لاختراق أعمق. سخّني الفرن إلى 220°م مع صينية ثقيلة بداخله، ليصطدم الدجاج بسطح يطقطق. ضعي الدجاجة بالجلد إلى الأعلى على الصينية الحامية وثقّليها بمقلاة ثانية ثقيلة أو طوبة ملفوفة بورق ألمنيوم — مكبس الديافولا الحقيقي، يلصق الجلد بالحرارة فيتقرمش إلى أقصى حد. اشوي 35–40 دقيقة حتى يصبح الجلد بلون الماهوغني ويقرأ ميزان الحرارة 75°م في الفخذ قرب العظم. اتركيها عشر دقائق مغطّاة بورق ألمنيوم تغطية خفيفة، قطّعيها عند المفاصل وقدّميها مع شرائح ليمون إضافية وعصارة الصينية مسكوبة فوقها.","en":"Spatchcock the chicken if your butcher hasn't: lay it breast-down, snip out the backbone along both sides with sturdy kitchen shears, flip and press firmly on the breastbone until it cracks and the bird lies flat. In a wide bowl whisk olive oil, crushed garlic, smoked paprika, coarse salt, lemon juice and zest, and a defiant amount of crushed chilli flakes — the dish's whole personality. Rub the marinade into both sides and into every fold of the skin, then leave the bird at least one hour at room temperature, or overnight covered in the fridge for deeper penetration. Heat the oven to 220°C with a heavy roasting tray inside, so the chicken hits a sizzling surface. Lay the chicken skin-up on the hot tray and weigh it down with a second heavy pan or a foil-wrapped brick — the authentic diavola press, which forces the skin into contact with the heat for maximum crispness. Roast 35–40 minutes until the skin is mahogany and a probe in the thigh near the bone reads 75°C. Rest ten minutes loosely tented with foil, carve through the joints, and serve with extra lemon wedges and the pan juices spooned over."}}];export default recipes;